# ═══════════════════════════════════════════════════════════════════════════════
# ATOMIC FILE WRITES
# ═══════════════════════════════════════════════════════════════════════════════
# Write content atomically using temp file + mv pattern.
# This prevents corrupted config files if the process is interrupted.
# Usage: atomic_write "destination_file" "owner" "permissions" << 'EOF'
# ... content ...
# EOF
atomic_write() {
    local dest="$1"
    local owner="${2:-root}"
    local perms="${3:-644}"
    local temp_file
    local dest_dir

    # Get directory of destination for temp file (ensures same filesystem for atomic mv)
    dest_dir=$(dirname "$dest")

    # Create temp file in same directory as destination
    temp_file=$(mktemp "${dest_dir}/.atomic_write.XXXXXX") || {
        log_error "Failed to create temp file for atomic write to $dest"
        return 1
    }

    # Write stdin to temp file
    cat > "$temp_file" || {
        log_error "Failed to write content to temp file"
        rm -f "$temp_file" 2>/dev/null
        return 1
    }

    # Set ownership and permissions on temp file
    if ! chown "$owner" "$temp_file" 2>/dev/null; then
        log_warn "atomic_write: chown $owner failed for $dest (continuing with current ownership)"
    fi
    if ! chmod "$perms" "$temp_file" 2>/dev/null; then
        log_warn "atomic_write: chmod $perms failed for $dest (continuing with current permissions)"
    fi

    # Atomic move (rename) to destination
    mv -f "$temp_file" "$dest" || {
        log_error "Failed to atomically move temp file to $dest"
        rm -f "$temp_file" 2>/dev/null
        return 1
    }

    return 0
}

# Escape string for PostgreSQL (prevents SQL injection)
# Doubles single quotes as per SQL standard
sql_escape() {
    local str="$1"
    # Replace single quotes with doubled single quotes
    echo "${str//\'/\'\'}"
}

# Validate identifier name (prevents SQL injection in identifiers)
# Only allows alphanumeric and underscore
validate_sql_identifier() {
    local name="$1"
    if [[ ! "$name" =~ ^[a-zA-Z_][a-zA-Z0-9_]*$ ]]; then
        log_error "SECURITY: Invalid SQL identifier '$name' - must be alphanumeric with underscores only"
        return 1
    fi
    return 0
}

# Atomic write as a specific user (using sudo)
atomic_write_as() {
    local user="$1"
    local dest="$2"
    local perms="${3:-644}"
    local temp_file
    local dest_dir

    dest_dir=$(dirname "$dest")
    temp_file=$(sudo -u "$user" mktemp "${dest_dir}/.atomic_write.XXXXXX") || {
        log_error "Failed to create temp file for atomic write to $dest"
        return 1
    }

    sudo -u "$user" tee "$temp_file" > /dev/null || {
        log_error "Failed to write content to temp file"
        sudo rm -f "$temp_file" 2>/dev/null
        return 1
    }

    sudo chmod "$perms" "$temp_file" 2>/dev/null || true
    sudo -u "$user" mv -f "$temp_file" "$dest" || {
        log_error "Failed to atomically move temp file to $dest"
        sudo rm -f "$temp_file" 2>/dev/null
        return 1
    }

    return 0
}

# Backup existing config file before overwriting (for re-run safety)
# Usage: backup_config_if_exists "/path/to/config.yaml"
# Creates timestamped backup in same directory: config.yaml.bak.YYYYMMDD-HHMMSS
backup_config_if_exists() {
    local config_path="$1"

    if [[ -f "$config_path" ]]; then
        local backup_path="${config_path}.bak.$(date '+%Y%m%d-%H%M%S')"
        if cp "$config_path" "$backup_path" 2>/dev/null; then
            log "Backed up existing config to: $backup_path"
            return 0
        else
            log_warn "Failed to backup existing config: $config_path"
            return 1
        fi
    fi
    return 0  # No existing file to backup
}

# Backup config with sudo (for files owned by other users)
backup_config_if_exists_sudo() {
    local config_path="$1"

    if [[ -f "$config_path" ]]; then
        local backup_path="${config_path}.bak.$(date '+%Y%m%d-%H%M%S')"
        if sudo cp "$config_path" "$backup_path" 2>/dev/null; then
            log "Backed up existing config to: $backup_path"
            return 0
        else
            log_warn "Failed to backup existing config: $config_path"
            return 1
        fi
    fi
    return 0  # No existing file to backup
}

# Load existing credentials from config file
# Sets global EXISTING_* variables if found, preserving them during re-installation
load_existing_credentials() {
    local config_file="$INSTALL_DIR/config/config.yaml"

    # Track if we found any existing credentials
    EXISTING_CREDENTIALS_FOUND="false"

    # Load from config.yaml
    if [[ -f "$config_file" ]]; then
        # Extract DB password from database section (NOT daemon section)
        # BUG FIX: Previous AWK range /^database:/,/^[^ ]/ was broken — "database:"
        # matches BOTH patterns so the range opened and closed on the same line,
        # never reaching the indented "  password:" line. Fixed to use flag-based parsing.
        local db_pass
        db_pass=$(awk '/^database:/{f=1;next} f && /^[^ #]/{f=0} f && /password:/' "$config_file" 2>/dev/null | grep -oP 'password:\s*"?\K[^"\s]+' || true)
        if [[ -n "$db_pass" && -z "$DB_PASSWORD" ]]; then
            EXISTING_DB_PASSWORD="$db_pass"
            EXISTING_CREDENTIALS_FOUND="true"
        fi

        # Extract RPC password from daemon section (V1 format)
        local rpc_pass
        rpc_pass=$(awk '/^daemon:/{f=1;next} f && /^[^ #]/{f=0} f && /password:/' "$config_file" 2>/dev/null | grep -oP 'password:\s*"?\K[^"\s]+' || true)
        if [[ -n "$rpc_pass" && -z "$RPC_PASSWORD" ]]; then
            EXISTING_RPC_PASSWORD="$rpc_pass"
            EXISTING_CREDENTIALS_FOUND="true"
        fi

        # Extract ADMIN_API_KEY from api section (V1: adminApiKey, V2: admin_api_key)
        local api_key
        api_key=$(grep -oP '(?:adminApiKey|admin_api_key):\s*"?\K[^"\s]+' "$config_file" 2>/dev/null | head -1)
        if [[ -n "$api_key" ]]; then
            EXISTING_ADMIN_API_KEY="$api_key"
            EXISTING_CREDENTIALS_FOUND="true"
        fi
    fi

    if [[ "$EXISTING_CREDENTIALS_FOUND" == "true" ]]; then
        log "Found existing credentials - will preserve during re-installation"
    fi
}

# Generate password only if one doesn't already exist
# Usage: generate_password_if_needed "VARIABLE_NAME"
# Sets the named variable to existing value or generates new
generate_password_if_needed() {
    local var_name="$1"
    local existing_var="EXISTING_${var_name}"
    local current_val="${!var_name}"
    local existing_val="${!existing_var}"

    # Use existing if available, otherwise generate
    if [[ -n "$existing_val" ]]; then
        printf -v "$var_name" '%s' "$existing_val"
        log "Preserved existing ${var_name}"
    elif [[ -z "$current_val" ]]; then
        printf -v "$var_name" '%s' "$(generate_password)"
    fi
}

log_step() {
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo -e "${CYAN}  $1${NC}"
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
}

# Clear terminal between interactive config sections for readability
screen_clear() {
    printf '\033[2J\033[H'
}

# Run command with animated progress spinner
# Usage: run_with_spinner "message" command arg1 arg2 ...
run_with_spinner() {
    local message="$1"
    shift
    local spinner="⠋⠙⠹⠸⠼⠴⠦⠧⠇⠏"
    local i=0
    local pid

    # Start the command in background
    "$@" &
    pid=$!

    # Show spinner while command runs
    printf "${GREEN}[$(date '+%H:%M:%S')]${NC} %s " "$message"
    while kill -0 $pid 2>/dev/null; do
        printf "\b${CYAN}%s${NC}" "${spinner:i++%${#spinner}:1}"
        sleep 0.1
    done

    # Get exit status
    wait $pid
    local status=$?

    # Clear spinner and show result
    printf "\b \b"
    if [[ $status -eq 0 ]]; then
        echo -e "${GREEN}✓${NC}"
    else
        echo -e "${RED}✗${NC}"
        return $status
    fi
}

# ═══════════════════════════════════════════════════════════════════════════════
# SECURITY: PATH VALIDATION
# ═══════════════════════════════════════════════════════════════════════════════

# SECURITY: Validate path to prevent path traversal attacks
# Rejects paths containing "..", starting with "/", or equal to "/"
validate_safe_path() {
    local path="$1"
    local var_name="${2:-path}"

    # Reject empty paths
    if [[ -z "$path" ]]; then
        log_error "SECURITY: Empty $var_name is not allowed"
        return 1
    fi

    # Reject path traversal attempts
    if [[ "$path" == *".."* ]]; then
        log_error "SECURITY: Path traversal detected in $var_name: $path"
        return 1
    fi

    # Reject root path
    if [[ "$path" == "/" ]]; then
        log_error "SECURITY: Root path is not allowed for $var_name"
        return 1
    fi

    return 0
}

# SECURITY: Validate username format (prevent command injection)
validate_username() {
    local username="$1"

    # Must match valid Unix username pattern
    if [[ ! "$username" =~ ^[a-z_][a-z0-9_-]{0,31}$ ]]; then
        log_error "SECURITY: Invalid username format: $username"
        return 1
    fi

    return 0
}

# ═══════════════════════════════════════════════════════════════════════════════
# INSTALLATION PROGRESS TRACKING & CHECKPOINT/RESUME
# ═══════════════════════════════════════════════════════════════════════════════

# Track what has been installed for cleanup on failure
INSTALL_PROGRESS=""
CLEANUP_IN_PROGRESS=false
# Use secure location for checkpoint - /var/lib requires root to write
# This prevents privilege escalation via malicious checkpoint in /tmp
CHECKPOINT_DIR="/var/lib/spiralpool"
CHECKPOINT_FILE="${CHECKPOINT_DIR}/install-checkpoint"
RESUME_MODE=false

# Lock file for coordinating with other Spiral Pool operations (GATE 4 compliance)
SPIRALPOOL_LOCK_FILE="/var/lock/spiralpool-operation.lock"
SPIRALPOOL_LOCK_FD=200

# Acquire exclusive lock to prevent concurrent operations
acquire_operation_lock() {
    local operation="$1"
    local timeout="${2:-5}"

    # Create lock file directory if needed
    sudo mkdir -p /var/lock 2>/dev/null || true

    # Clean up stale lock if the process that created it is no longer running
    if [[ -f "${SPIRALPOOL_LOCK_FILE}.info" ]]; then
        local lock_pid=$(grep -oP 'pid=\K[0-9]+' "${SPIRALPOOL_LOCK_FILE}.info" 2>/dev/null || echo "")
        if [[ -n "$lock_pid" ]] && ! kill -0 "$lock_pid" 2>/dev/null; then
            # Process is dead, clean up stale lock
            sudo rm -f "$SPIRALPOOL_LOCK_FILE" "${SPIRALPOOL_LOCK_FILE}.info" 2>/dev/null || true
        fi
    fi

    # Try to acquire lock
    exec 200>"$SPIRALPOOL_LOCK_FILE"
    if ! flock -w "$timeout" -x 200 2>/dev/null; then
        # Lock acquisition failed - check what's holding it
        local lock_holder=""
        if [[ -f "${SPIRALPOOL_LOCK_FILE}.info" ]]; then
            lock_holder=$(cat "${SPIRALPOOL_LOCK_FILE}.info" 2>/dev/null || echo "unknown")
        fi
        log_error "Cannot acquire operation lock. Another Spiral Pool operation is in progress."
        if [[ -n "$lock_holder" ]]; then
            log_error "Current operation: $lock_holder"
        fi
        log_error "If no other operation is running, remove: $SPIRALPOOL_LOCK_FILE"
        return 1
    fi

    # Write lock info
    echo "operation=$operation pid=$$ started=$(date -Iseconds)" | sudo tee "${SPIRALPOOL_LOCK_FILE}.info" > /dev/null
    log "Acquired operation lock for: $operation"
    return 0
}

# Release operation lock
release_operation_lock() {
    if [[ -f "${SPIRALPOOL_LOCK_FILE}.info" ]]; then
        sudo rm -f "${SPIRALPOOL_LOCK_FILE}.info" 2>/dev/null || true
    fi
    # Lock is automatically released when FD is closed or process exits
    exec 200>&- 2>/dev/null || true
}

# Checkpoint system for resumable installation
save_checkpoint() {
    local step="$1"
    local status="${2:-completed}"
    # Ensure checkpoint directory exists with secure permissions
    # Directory is root-only (700) to prevent unauthorized file creation
    # But checkpoint file itself is world-readable (644) for sourcing
    if [[ ! -d "$CHECKPOINT_DIR" ]]; then
        sudo mkdir -p "$CHECKPOINT_DIR"
        sudo chmod 700 "$CHECKPOINT_DIR"
        sudo chown root:root "$CHECKPOINT_DIR"
    fi

    # SECURITY: Generate checkpoint content and compute hash
    # This prevents tampering even if an attacker briefly gains root access
    local checkpoint_content
    checkpoint_content=$(cat << EOF
CHECKPOINT_STEP="$step"
CHECKPOINT_STATUS="$status"
CHECKPOINT_TIME="$(date -Iseconds)"
INSTALL_DIR="$INSTALL_DIR"
POOL_USER="$POOL_USER"
ENABLE_DGB="$ENABLE_DGB"
ENABLE_BTC="$ENABLE_BTC"
ENABLE_BCH="$ENABLE_BCH"
ENABLE_BC2="$ENABLE_BC2"
ENABLE_QBX="$ENABLE_QBX"
ENABLE_LTC="$ENABLE_LTC"
ENABLE_DOGE="$ENABLE_DOGE"
ENABLE_DGB_SCRYPT="$ENABLE_DGB_SCRYPT"
ENABLE_NMC="$ENABLE_NMC"
ENABLE_SYS="$ENABLE_SYS"
ENABLE_XMY="$ENABLE_XMY"
ENABLE_FBTC="$ENABLE_FBTC"
ENABLE_QBX="$ENABLE_QBX"
ENABLE_PEP="$ENABLE_PEP"
ENABLE_CAT="$ENABLE_CAT"
COIN_MODE="$COIN_MODE"
SOLO_COIN="$SOLO_COIN"
DB_PASSWORD="$DB_PASSWORD"
RPC_PASSWORD="$RPC_PASSWORD"
DGB_RPC_PASSWORD="$DGB_RPC_PASSWORD"
BTC_RPC_PASSWORD="$BTC_RPC_PASSWORD"
BCH_RPC_PASSWORD="$BCH_RPC_PASSWORD"
BC2_RPC_PASSWORD="$BC2_RPC_PASSWORD"
LTC_RPC_PASSWORD="$LTC_RPC_PASSWORD"
DOGE_RPC_PASSWORD="$DOGE_RPC_PASSWORD"
PEP_RPC_PASSWORD="$PEP_RPC_PASSWORD"
CAT_RPC_PASSWORD="$CAT_RPC_PASSWORD"
NMC_RPC_PASSWORD="$NMC_RPC_PASSWORD"
SYS_RPC_PASSWORD="$SYS_RPC_PASSWORD"
XMY_RPC_PASSWORD="$XMY_RPC_PASSWORD"
FBTC_RPC_PASSWORD="$FBTC_RPC_PASSWORD"
QBX_RPC_PASSWORD="$QBX_RPC_PASSWORD"
ADMIN_API_KEY="$ADMIN_API_KEY"
METRICS_TOKEN="$METRICS_TOKEN"
DEPLOY_METHOD="$DEPLOY_METHOD"
INSTALL_MODE="$INSTALL_MODE"
HA_MODE="$HA_MODE"
HA_ENABLED="$HA_ENABLED"
VIP_ADDRESS="$VIP_ADDRESS"
VIP_NETMASK="$VIP_NETMASK"
VIP_INTERFACE="$VIP_INTERFACE"
HA_CLUSTER_TOKEN="$HA_CLUSTER_TOKEN"
HA_PEER_IP="$HA_PEER_IP"
HA_PEER_IPS_CSV="$HA_PEER_IPS_CSV"
HA_PRIMARY_IP="$HA_PRIMARY_IP"
HA_NODE_PRIORITY="$HA_NODE_PRIORITY"
HA_SSH_READY="$HA_SSH_READY"
HA_ADDRESSES_SYNCED="$HA_ADDRESSES_SYNCED"
HA_PRIMARY_COIN_COUNT="${HA_PRIMARY_COIN_COUNT:-0}"
HA_REPLICATE_FROM_PRIMARY="$HA_REPLICATE_FROM_PRIMARY"
POSTGRES_SUPERUSER_PASSWORD="$POSTGRES_SUPERUSER_PASSWORD"
DB_REPLICATION_USER="$DB_REPLICATION_USER"
DB_REPLICATION_PASSWORD="$DB_REPLICATION_PASSWORD"
SCAN_FOR_MINERS="$SCAN_FOR_MINERS"
BLOCKCHAIN_SYNC_CHOICE="$BLOCKCHAIN_SYNC_CHOICE"
SYNC_SOURCE_NODE="$SYNC_SOURCE_NODE"
SYNC_SSH_USER="$SYNC_SSH_USER"
SOURCE_SSH_READY="$SOURCE_SSH_READY"
ENABLE_AUTO_BACKUPS="$ENABLE_AUTO_BACKUPS"
BACKUP_CHOICE_MADE="$BACKUP_CHOICE_MADE"
WATCH_SYNC_ON_EXIT="$WATCH_SYNC_ON_EXIT"
ALERT_THEME="$ALERT_THEME"
DGB_POOL_ADDRESS="$DGB_POOL_ADDRESS"
BTC_POOL_ADDRESS="$BTC_POOL_ADDRESS"
BCH_POOL_ADDRESS="$BCH_POOL_ADDRESS"
BC2_POOL_ADDRESS="$BC2_POOL_ADDRESS"
NMC_POOL_ADDRESS="$NMC_POOL_ADDRESS"
SYS_POOL_ADDRESS="$SYS_POOL_ADDRESS"
XMY_POOL_ADDRESS="$XMY_POOL_ADDRESS"
FBTC_POOL_ADDRESS="$FBTC_POOL_ADDRESS"
LTC_POOL_ADDRESS="$LTC_POOL_ADDRESS"
DOGE_POOL_ADDRESS="$DOGE_POOL_ADDRESS"
PEP_POOL_ADDRESS="$PEP_POOL_ADDRESS"
CAT_POOL_ADDRESS="$CAT_POOL_ADDRESS"
GRAFANA_ADMIN_PASSWORD="$GRAFANA_ADMIN_PASSWORD"
MULTI_DISK_CONFIGURED="$MULTI_DISK_CONFIGURED"
CHAIN_MOUNT_POINT="$CHAIN_MOUNT_POINT"
CHAIN_STORAGE_MOUNT="$CHAIN_STORAGE_MOUNT"
CHAIN_DIRECT_DEVICE="$CHAIN_DIRECT_DEVICE"
CHAIN_BIND_SOURCE="$CHAIN_BIND_SOURCE"
EOF
)

    # Compute SHA256 hash of content (excluding the hash line itself)
    local content_hash
    content_hash=$(echo "$checkpoint_content" | sha256sum | cut -d' ' -f1)

    # Write checkpoint with integrity hash at the end
    sudo tee "$CHECKPOINT_FILE" > /dev/null << EOF
$checkpoint_content
CHECKPOINT_HASH="$content_hash"
EOF
    # File is readable (444) but only root can write (directory is 700 root-only)
    # This allows non-root user to source it while preventing tampering
    sudo chmod 444 "$CHECKPOINT_FILE"
    sudo chown root:root "$CHECKPOINT_FILE"
}

load_checkpoint() {
    if [[ -f "$CHECKPOINT_FILE" ]]; then
        # Security: Validate checkpoint file ownership before sourcing
        # The file must be owned by root to ensure it wasn't tampered with
        # The directory (700 root-only) prevents unauthorized file creation
        local file_owner
        file_owner=$(stat -c '%u' "$CHECKPOINT_FILE" 2>/dev/null)

        # Must be owned by root (uid 0)
        if [[ "$file_owner" != "0" ]]; then
            log_error "SECURITY: Checkpoint file not owned by root - refusing to load"
            return 1
        fi

        # SECURITY: Verify checkpoint integrity hash before sourcing
        # This prevents execution of tampered checkpoint files
        local stored_hash
        stored_hash=$(grep '^CHECKPOINT_HASH=' "$CHECKPOINT_FILE" 2>/dev/null | cut -d'"' -f2)

        if [[ -z "$stored_hash" ]]; then
            # Legacy checkpoint without hash - warn but allow for upgrade path
            log_warn "SECURITY: Checkpoint file lacks integrity hash (legacy format)"
            log_warn "Consider running a fresh install for maximum security"
        else
            # Extract content (everything except the CHECKPOINT_HASH line)
            local content_without_hash
            content_without_hash=$(grep -v '^CHECKPOINT_HASH=' "$CHECKPOINT_FILE")

            # Compute hash of content
            local computed_hash
            computed_hash=$(echo "$content_without_hash" | sha256sum | cut -d' ' -f1)

            if [[ "$computed_hash" != "$stored_hash" ]]; then
                log_error "SECURITY: Checkpoint file integrity check FAILED"
                log_error "Expected hash: $stored_hash"
                log_error "Computed hash: $computed_hash"
                log_error "The checkpoint file may have been tampered with - refusing to load"
                return 1
            fi
        fi

        source "$CHECKPOINT_FILE"

        # Reconstruct HA_PEER_IPS array from checkpoint-safe CSV
        if [[ -n "$HA_PEER_IPS_CSV" ]]; then
            IFS=',' read -ra HA_PEER_IPS <<< "$HA_PEER_IPS_CSV"
        elif [[ -n "$HA_PEER_IP" ]]; then
            HA_PEER_IPS=("$HA_PEER_IP")  # Legacy checkpoint fallback
            HA_PEER_IPS_CSV="$HA_PEER_IP"
        fi

        return 0
    fi
    return 1
}

clear_checkpoint() {
    sudo rm -f "$CHECKPOINT_FILE" 2>/dev/null
}

check_resume() {
    if [[ -f "$CHECKPOINT_FILE" ]]; then
        # Use secure load_checkpoint instead of direct source
        if ! load_checkpoint; then
            log_error "Failed to load checkpoint securely - starting fresh"
            clear_checkpoint
            return 1
        fi

        # Non-interactive mode: auto-resume from checkpoint
        if [[ ! -t 0 ]]; then
            log "Non-interactive mode: auto-resuming from checkpoint '$CHECKPOINT_STEP'"
            RESUME_MODE=true
            return 0
        fi

        echo ""
        echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo -e "${YELLOW}  PREVIOUS INSTALLATION DETECTED${NC}"
        echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo ""
        echo -e "  A previous installation was interrupted at step: ${WHITE}$CHECKPOINT_STEP${NC}"
        echo -e "  Time: ${DIM}$CHECKPOINT_TIME${NC}"
        echo ""
        echo -e "    ${GREEN}r${NC} = Resume from last checkpoint"
        echo -e "    ${YELLOW}f${NC} = Fresh install (clears previous progress)"
        echo -e "    ${RED}q${NC} = Quit"
        echo ""
        prompt_input "Choice [r/f/q]: "; read resume_choice
        case "$resume_choice" in
            r|R)
                RESUME_MODE=true
                log "Resuming installation from checkpoint: $CHECKPOINT_STEP"
                return 0
                ;;
            f|F)
                clear_checkpoint
                log "Starting fresh installation"
                return 1
                ;;
            *)
                echo "Installation cancelled."
                exit 0
                ;;
        esac
    fi
    return 1
}

# Check if a step should be skipped (already completed in resume mode)
# NOTE: Only reads CHECKPOINT_STEP from the checkpoint file — does NOT re-source
# the entire file, which would overwrite fresh user answers (ENABLE_*, DB_PASSWORD,
# COIN_MODE, etc.) collected during this session's interactive prompts.
should_skip_step() {
    local step="$1"
    if [[ "$RESUME_MODE" == "true" ]] && [[ -n "$CHECKPOINT_STEP" ]]; then
        # List of completed steps in order
        local steps=("prerequisites" "system_setup" "blockchain_nodes" "postgresql" "redis" "go_install" "stratum_build" "stratum_config" "dashboard" "sentinel" "services" "finalize")
        local checkpoint_idx=-1
        local step_idx=-1
        for i in "${!steps[@]}"; do
            [[ "${steps[$i]}" == "$CHECKPOINT_STEP" ]] && checkpoint_idx=$i
            [[ "${steps[$i]}" == "$step" ]] && step_idx=$i
        done
        # Skip if this step was completed at or before the checkpoint
        # Checkpoint is saved AFTER a step completes, so -le (not -lt)
        if [[ $step_idx -le $checkpoint_idx ]]; then
            log "Skipping already completed step: $step"
            return 0
        fi
    fi
    return 1
}

mark_progress() {
    INSTALL_PROGRESS="$INSTALL_PROGRESS $1"
}

# ═══════════════════════════════════════════════════════════════════════════════
# CLEANUP ON FAILURE
# ═══════════════════════════════════════════════════════════════════════════════

cleanup_on_failure() {
    local exit_code=$?

    # Prevent recursive cleanup
    if [[ "$CLEANUP_IN_PROGRESS" == "true" ]]; then
        return
    fi
    CLEANUP_IN_PROGRESS=true

    # Only cleanup on actual failures (non-zero exit), not normal exit
    if [[ $exit_code -eq 0 ]]; then
        return
    fi

    # Restore terminal state FIRST — the sync watcher (tput civis, stty -echo,
    # opost/onlcr) or other subprocess may have left the terminal corrupted.
    # Without this, all error output below would be garbled/invisible.
    stty sane 2>/dev/null || true
    tput cnorm 2>/dev/null || true

    echo ""
    echo -e "${RED}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo -e "${RED}  INSTALLATION FAILED - CLEANING UP${NC}"
    echo -e "${RED}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""

    log_error "Installation failed with exit code: $exit_code"
    log "Installed components: ${INSTALL_PROGRESS:-none}"
    echo ""

    # Check if we're running in non-interactive mode (no TTY or piped input)
    local cleanup_choice="k"  # Default to keeping components (safer)
    if [[ -t 0 ]]; then
        # Interactive mode - ask user before cleanup
        echo -e "  ${WHITE}The installation failed. Would you like to clean up installed components?${NC}"
        echo ""
        echo -e "    ${GREEN}c${NC} = Clean up all installed components"
        echo -e "    ${YELLOW}k${NC} = Keep installed components (for debugging)"
        echo ""
        stty sane 2>/dev/null || true
        prompt_input "Choice [c/k]: "; read cleanup_choice < /dev/tty
    else
        # Non-interactive mode - keep components for safety and diagnostics
        log_warn "Non-interactive mode detected - keeping installed components for diagnostics"
        log "Checkpoint saved at: $CHECKPOINT_FILE"
        log "To resume: ./install.sh (will offer to resume from last checkpoint)"
        log "To manually clean up: sudo rm -rf $INSTALL_DIR"
    fi

    if [[ "$cleanup_choice" != "c" && "$cleanup_choice" != "C" ]]; then
        log_warn "Keeping installed components for debugging"
        log "To manually clean up later, run: sudo rm -rf $INSTALL_DIR"
        exit $exit_code
    fi

    log "Starting cleanup..."

    # Resolve chain data location — get_blockchain_dir may not be defined yet if
    # failure happened early, so inline the multi-disk resolution here.
    local _cmp
    if [[ "$MULTI_DISK_CONFIGURED" == "true" && -n "$CHAIN_MOUNT_POINT" ]]; then
        _cmp="$CHAIN_MOUNT_POINT"
    else
        _cmp="$INSTALL_DIR"
    fi

    # SECURITY: Validate paths before any rm -rf operations
    if ! validate_safe_path "$INSTALL_DIR" "INSTALL_DIR"; then
        log_error "Aborting cleanup due to unsafe INSTALL_DIR"
        exit $exit_code
    fi
    if [[ -n "$POOL_USER" ]] && ! validate_username "$POOL_USER"; then
        log_error "Aborting cleanup due to unsafe POOL_USER"
        exit $exit_code
    fi

    # Stop any services we may have started
    if [[ "$INSTALL_PROGRESS" == *"services"* ]]; then
        log "Stopping services..."
        sudo systemctl stop spiralstratum 2>/dev/null || true
        sudo systemctl stop spiralsentinel 2>/dev/null || true
        sudo systemctl stop spiraldash 2>/dev/null || true
        # Stop all coin daemons
        sudo systemctl stop digibyted 2>/dev/null || true
        sudo systemctl stop bitcoind 2>/dev/null || true
        sudo systemctl stop bitcoind-bch 2>/dev/null || true
        sudo systemctl stop bitcoiniid 2>/dev/null || true
        sudo systemctl stop litecoind 2>/dev/null || true
        sudo systemctl stop dogecoind 2>/dev/null || true
        sudo systemctl stop pepecoind 2>/dev/null || true
        sudo systemctl stop catcoind 2>/dev/null || true
        sudo systemctl stop namecoind 2>/dev/null || true
        sudo systemctl stop syscoind 2>/dev/null || true
        sudo systemctl stop myriadcoind 2>/dev/null || true
        sudo systemctl stop fractald 2>/dev/null || true
        # Disable all services
        sudo systemctl disable spiralstratum 2>/dev/null || true
        sudo systemctl disable spiralsentinel 2>/dev/null || true
        sudo systemctl disable spiraldash 2>/dev/null || true
        sudo systemctl disable digibyted 2>/dev/null || true
        sudo systemctl disable bitcoind 2>/dev/null || true
        sudo systemctl disable bitcoind-bch 2>/dev/null || true
        sudo systemctl disable bitcoiniid 2>/dev/null || true
        sudo systemctl disable litecoind 2>/dev/null || true
        sudo systemctl disable dogecoind 2>/dev/null || true
        sudo systemctl disable pepecoind 2>/dev/null || true
        sudo systemctl disable catcoind 2>/dev/null || true
        sudo systemctl disable namecoind 2>/dev/null || true
        sudo systemctl disable syscoind 2>/dev/null || true
        sudo systemctl disable myriadcoind 2>/dev/null || true
        sudo systemctl disable fractald 2>/dev/null || true
        # Remove service files
        sudo rm -f /etc/systemd/system/spiralstratum.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/spiralsentinel.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/spiraldash.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/digibyted.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/bitcoind.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/bitcoind-bch.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/bitcoiniid.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/litecoind.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/dogecoind.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/pepecoind.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/catcoind.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/namecoind.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/syscoind.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/myriadcoind.service 2>/dev/null || true
        sudo rm -f /etc/systemd/system/fractald.service 2>/dev/null || true
        sudo systemctl daemon-reload 2>/dev/null || true
    fi

    # Remove stratum binary and source
    if [[ "$INSTALL_PROGRESS" == *"stratum"* ]]; then
        log "Removing Spiral Stratum..."
        sudo rm -rf "$INSTALL_DIR/bin/spiralstratum" 2>/dev/null || true
        sudo rm -rf "$INSTALL_DIR/stratum-src" 2>/dev/null || true
        sudo rm -rf "$INSTALL_DIR/config" 2>/dev/null || true
