        log "Removing Sentinel..."
        sudo rm -rf "$INSTALL_DIR/sentinel" 2>/dev/null || true
    fi

    # Drop database (optional - ask user if interactive)
    if [[ "$INSTALL_PROGRESS" == *"database"* ]]; then
        local db_choice="n"  # Default to keeping database (safer)
        if [[ -t 0 ]]; then
            echo ""
            echo -e "  ${YELLOW}Database was created. Drop it?${NC}"
            echo -e "    ${GREEN}y${NC} = Drop database (data will be lost)"
            echo -e "    ${RED}n${NC} = Keep database"
            prompt_input "Choice [y/n]: "; read db_choice
        else
            log "Non-interactive mode: keeping database for safety"
        fi
        if [[ "$db_choice" == "y" || "$db_choice" == "Y" ]]; then
            log "Dropping database..."
            sudo -u postgres psql -c "DROP DATABASE IF EXISTS $DB_NAME;" 2>/dev/null || true
            sudo -u postgres psql -c "DROP USER IF EXISTS $DB_USER;" 2>/dev/null || true
        fi
    fi

    # Stop Redis if it was installed as part of HA
    if [[ "$INSTALL_PROGRESS" == *"redis"* ]]; then
        log "Stopping Redis..."
        sudo systemctl stop redis-server 2>/dev/null || true
        sudo systemctl disable redis-server 2>/dev/null || true
        # Remove the stratum systemd drop-in that enables Redis dedup
        sudo rm -f /etc/systemd/system/spiralstratum.service.d/redis-dedup.conf 2>/dev/null || true
        sudo systemctl daemon-reload 2>/dev/null || true
    fi

    # Remove helper scripts from /usr/local/bin
    log "Removing helper scripts..."
    sudo rm -f /usr/local/bin/spiralpool-* 2>/dev/null || true
    sudo rm -f /usr/local/bin/spiralctl 2>/dev/null || true

    # Remove install directory - always remove on cleanup (user chose to clean up)
    if [[ -d "$INSTALL_DIR" ]]; then
        log "Removing install directory $INSTALL_DIR..."
        sudo rm -rf "$INSTALL_DIR" 2>/dev/null || true
    fi

    # Remove pool user and group
    if id "$POOL_USER" &>/dev/null; then
        log "Removing pool user $POOL_USER..."
        # Kill any processes owned by the user first
        sudo pkill -u "$POOL_USER" 2>/dev/null || true
        sleep 1
        sudo userdel -rf "$POOL_USER" 2>/dev/null || true
    fi

    # Always try to remove the group (handles orphaned groups)
    if getent group "$POOL_USER" &>/dev/null; then
        log "Removing group $POOL_USER..."
        sudo groupdel "$POOL_USER" 2>/dev/null || true
    fi

    # Remove MOTD
    sudo rm -f /etc/update-motd.d/00-spiralpool 2>/dev/null || true

    # Remove any leftover systemd services
    sudo rm -f /etc/systemd/system/spiralpool-*.service 2>/dev/null || true
    sudo rm -f /etc/systemd/system/digibyted.service 2>/dev/null || true
    sudo rm -f /etc/systemd/system/bitcoind.service 2>/dev/null || true
    sudo rm -f /etc/systemd/system/bitcoind-bch.service 2>/dev/null || true
    sudo rm -f /etc/systemd/system/bitcoiniid.service 2>/dev/null || true
    sudo rm -f /etc/systemd/system/litecoind.service 2>/dev/null || true
    sudo rm -f /etc/systemd/system/dogecoind.service 2>/dev/null || true
    sudo rm -f /etc/systemd/system/pepecoind.service 2>/dev/null || true
    sudo rm -f /etc/systemd/system/catcoind.service 2>/dev/null || true
    sudo rm -f /etc/systemd/system/namecoind.service 2>/dev/null || true
    sudo rm -f /etc/systemd/system/syscoind.service 2>/dev/null || true
    sudo rm -f /etc/systemd/system/myriadcoind.service 2>/dev/null || true
    sudo rm -f /etc/systemd/system/fractald.service 2>/dev/null || true
    sudo systemctl daemon-reload 2>/dev/null || true

    echo ""
    log_success "Cleanup completed"
    echo ""
    echo -e "  ${WHITE}To retry installation, run:${NC}"
    echo -e "    ${CYAN}sudo bash install.sh${NC}"
    echo ""

    exit $exit_code
}

# Set trap to cleanup on script failure
trap cleanup_on_failure EXIT

# ═══════════════════════════════════════════════════════════════════════════════
# UTILITIES
# ═══════════════════════════════════════════════════════════════════════════════

generate_password() {
    # Alphanumeric only - safest for RPC configs, PostgreSQL, YAML, and shell
    # 32 chars of [A-Za-z0-9] = ~190 bits of entropy (more than sufficient)
    local pw
    pw=$(LC_ALL=C tr -dc 'A-Za-z0-9' < /dev/urandom | head -c 32)
    if [[ -z "$pw" ]] || [[ ${#pw} -lt 20 ]]; then
        # Fallback: use openssl if /dev/urandom+tr failed
        pw=$(openssl rand -base64 48 | tr -dc 'A-Za-z0-9' | head -c 32)
    fi
    if [[ -z "$pw" ]] || [[ ${#pw} -lt 20 ]]; then
        echo "FATAL: Failed to generate secure password" >&2
        exit 1
    fi
    echo "$pw"
}

check_command() {
    command -v "$1" &> /dev/null
}

# Detect if running in a virtual machine using safe, standard Linux tools
# Uses systemd-detect-virt (official), lscpu (standard), and DMI/SMBIOS (root) - no AV triggers
# Returns: "none" for bare metal, or hypervisor/platform name
#
# Detected hypervisors:
#   kvm, qemu, vmware, oracle (VirtualBox), microsoft (Hyper-V/Azure),
#   xen, parallels, bhyve, bochs, nutanix, uml, zvm, powervm, acrn, apple
#
# Detected containers:
#   docker, podman, lxc, lxc-libvirt, openvz, systemd-nspawn, wsl, rkt, proot
#
# Detected cloud platforms (via DMI sys_vendor/board_vendor):
#   amazon (AWS), google (GCP), microsoft (Azure), digitalocean, linode,
#   hetzner, vultr, oci (Oracle Cloud), ovh, scaleway, upcloud, alibaba, tencent
#
detect_virtualization() {
    local virt_type="none"

    # Method 1: systemd-detect-virt (official Linux VM detection tool)
    # On Ubuntu 24.04 (systemd 255+), this detects all major hypervisors and containers
    # including: kvm, qemu, vmware, oracle, microsoft, xen, parallels, bhyve, bochs,
    #            amazon, google, apple, zvm, powervm, uml, acrn, qnx,
    #            docker, podman, lxc, openvz, wsl, systemd-nspawn, rkt, proot
    if command -v systemd-detect-virt &>/dev/null; then
        # Note: on bare metal, systemd-detect-virt outputs "none" AND exits 1.
        # Using "$(cmd || echo none)" would concatenate both outputs → "none\nnone".
        # Capture stdout separately, then fall back if empty (e.g., crash with no output).
        virt_type=$(systemd-detect-virt 2>/dev/null) || true
        [[ -z "$virt_type" ]] && virt_type="none"
        if [[ "$virt_type" != "none" ]]; then
            echo "$virt_type"
            return 0
        fi
    fi

    # Method 2: Check lscpu for hypervisor vendor (standard sysadmin tool)
    # Reports: KVM, VMware, Microsoft, Xen (from CPUID hypervisor leaf 0x40000000)
    if command -v lscpu &>/dev/null; then
        local hypervisor=$(lscpu 2>/dev/null | grep -i "Hypervisor vendor" | awk -F: '{print $2}' | tr -d ' ' | tr '[:upper:]' '[:lower:]')
        if [[ -n "$hypervisor" ]]; then
            echo "$hypervisor"
            return 0
        fi
    fi

    # --- DMI/SMBIOS fallback methods (Methods 3-3e) ---
    # These require root (which the installer has) and catch edge cases where
    # systemd-detect-virt and lscpu are unavailable or return "none"

    # Method 3: Check DMI product_name for VM signatures
    if [[ -r /sys/class/dmi/id/product_name ]]; then
        local product=$(cat /sys/class/dmi/id/product_name 2>/dev/null | tr '[:upper:]' '[:lower:]')
        case "$product" in
            # Desktop hypervisors
            *virtualbox*)                       echo "oracle"; return 0 ;;
            *vmware*)                           echo "vmware"; return 0 ;;
            *parallels*)                        echo "parallels"; return 0 ;;
            # KVM / QEMU variants
            *kvm*|*qemu*|*standard\ pc*)        echo "kvm"; return 0 ;;
            *proxmox*)                          echo "kvm"; return 0 ;;
            *firecracker*)                      echo "kvm"; return 0 ;;
            # Microsoft
            *hyper-v*|*virtual\ machine*)       echo "microsoft"; return 0 ;;
            # Xen variants
            *xen*|*hvm\ domu*)                  echo "xen"; return 0 ;;
            # BSD hypervisors
            *bhyve*)                            echo "bhyve"; return 0 ;;
            *bochs*)                            echo "bochs"; return 0 ;;
            # Enterprise hypervisors
            *ahv*)                              echo "nutanix"; return 0 ;;
            *rhev*|*oVirt*)                     echo "kvm"; return 0 ;;
            *openstack*)                        echo "openstack"; return 0 ;;
            # Apple Silicon VMs (UTM, Tart, etc.)
            *apple\ virtualization*)            echo "apple"; return 0 ;;
        esac
    fi

    # Method 3b: Check sys_vendor for hypervisor and cloud provider identification
    if [[ -r /sys/class/dmi/id/sys_vendor ]]; then
        local vendor=$(cat /sys/class/dmi/id/sys_vendor 2>/dev/null | tr '[:upper:]' '[:lower:]')
        case "$vendor" in
            # Hypervisors
            *qemu*)                             echo "qemu"; return 0 ;;
            *bochs*)                            echo "bochs"; return 0 ;;
            *parallels*)                        echo "parallels"; return 0 ;;
            *innotek*)                          echo "oracle"; return 0 ;;  # Old VirtualBox (pre-Oracle)
            *vmware*)                           echo "vmware"; return 0 ;;
            *citrix*|*xenserver*)               echo "xen"; return 0 ;;    # Citrix Hypervisor / XenServer
            *apple*)                            echo "apple"; return 0 ;;  # Apple Virtualization Framework
            *nutanix*)                          echo "nutanix"; return 0 ;;
            # Major cloud providers
            *amazon*|*ec2*)                     echo "amazon"; return 0 ;;
            *google*)                           echo "google"; return 0 ;;
            *microsoft*)                        echo "microsoft"; return 0 ;;
            *digitalocean*)                     echo "digitalocean"; return 0 ;;
            *linode*|*akamai*)                  echo "linode"; return 0 ;;  # Linode rebranded to Akamai
            *hetzner*)                          echo "hetzner"; return 0 ;;
            *vultr*)                            echo "vultr"; return 0 ;;
            *oracle*)                           echo "oci"; return 0 ;;    # Oracle Cloud Infrastructure
            *ovh*)                              echo "ovh"; return 0 ;;
            *scaleway*)                         echo "scaleway"; return 0 ;;
            *upcloud*)                          echo "upcloud"; return 0 ;;
            *alibaba*)                          echo "alibaba"; return 0 ;;
            *tencent*)                          echo "tencent"; return 0 ;;
            *openstack*)                        echo "openstack"; return 0 ;;
            *red\ hat*)                         echo "kvm"; return 0 ;;    # RHEV / oVirt
        esac
    fi

    # Method 3c: Check BIOS vendor for QEMU/KVM detection
    if [[ -r /sys/class/dmi/id/bios_vendor ]]; then
        local bios=$(cat /sys/class/dmi/id/bios_vendor 2>/dev/null | tr '[:upper:]' '[:lower:]')
        case "$bios" in
            *seabios*|*qemu*|*bochs*)           echo "qemu"; return 0 ;;
            *edk2*|*tianocore*)                 echo "kvm"; return 0 ;;    # OVMF/UEFI firmware used by KVM
            *xen*)                              echo "xen"; return 0 ;;
            *innotek*)                          echo "oracle"; return 0 ;;
        esac
    fi

    # Method 3d: Check board_vendor for additional cloud provider detection
    # Some clouds set board_vendor but leave sys_vendor as generic "QEMU"
    if [[ -r /sys/class/dmi/id/board_vendor ]]; then
        local board=$(cat /sys/class/dmi/id/board_vendor 2>/dev/null | tr '[:upper:]' '[:lower:]')
        case "$board" in
            *amazon*)                           echo "amazon"; return 0 ;;
            *google*)                           echo "google"; return 0 ;;
            *oracle*)                           echo "oci"; return 0 ;;
            *alibaba*)                          echo "alibaba"; return 0 ;;
        esac
    fi

    # Method 3e: Check chassis_vendor for virtualization signatures
    if [[ -r /sys/class/dmi/id/chassis_vendor ]]; then
        local chassis=$(cat /sys/class/dmi/id/chassis_vendor 2>/dev/null | tr '[:upper:]' '[:lower:]')
        case "$chassis" in
            *qemu*|*bochs*)                     echo "qemu"; return 0 ;;
            *vmware*)                           echo "vmware"; return 0 ;;
            *oracle*|*virtualbox*)              echo "oracle"; return 0 ;;
            *microsoft*)                        echo "microsoft"; return 0 ;;
            *xen*)                              echo "xen"; return 0 ;;
            *amazon*)                           echo "amazon"; return 0 ;;
            *google*)                           echo "google"; return 0 ;;
            *digitalocean*)                     echo "digitalocean"; return 0 ;;
            *hetzner*)                          echo "hetzner"; return 0 ;;
        esac
    fi

    # Method 4: Check /sys/hypervisor (Xen-specific sysfs path)
    # /sys/hypervisor/type is a file containing "xen", not a directory
    if [[ -f /sys/hypervisor/type ]]; then
        echo "xen"
        return 0
    fi

    # Method 5: Check /proc/xen for Xen PV guests that lack /sys/hypervisor
    if [[ -d /proc/xen ]]; then
        echo "xen"
        return 0
    fi

    # Method 6: Check for container environments via environment markers
    # These catch containers when systemd-detect-virt is not available
    if [[ -f /.dockerenv ]]; then
        echo "docker"
        return 0
    fi
    if [[ -f /run/.containerenv ]]; then
        echo "podman"
        return 0
    fi

    # Note: /dev/kvm indicates this machine is a KVM HOST (hypervisor), not a guest.
    # We intentionally do NOT detect on /dev/kvm presence.

    echo "none"
    return 0
}

# Check if running in a VM (returns 0 if VM, 1 if bare metal)
is_virtual_machine() {
    local virt=$(detect_virtualization)
    [[ "$virt" != "none" ]]
}

# Detect if running on a cloud provider's infrastructure
# Returns: cloud provider friendly name (stdout), exit 0 if cloud, exit 1 if not
# This checks DMI/SMBIOS strings independently of systemd-detect-virt because
# systemd-detect-virt often returns generic hypervisor type (e.g., "kvm") on
# cloud VMs instead of identifying the cloud provider.
detect_cloud_provider() {
    local dmi_files=(
        /sys/class/dmi/id/sys_vendor
        /sys/class/dmi/id/board_vendor
        /sys/class/dmi/id/chassis_vendor
        /sys/class/dmi/id/product_name
        /sys/class/dmi/id/bios_vendor
    )

    for dmi_file in "${dmi_files[@]}"; do
        [[ -r "$dmi_file" ]] || continue
        local val
        val=$(cat "$dmi_file" 2>/dev/null) || continue
        val=$(echo "$val" | tr '[:upper:]' '[:lower:]')
        case "$val" in
            *amazon*|*ec2*)             echo "AWS EC2"; return 0 ;;
            *google*)                   echo "Google Cloud"; return 0 ;;
            *digitalocean*)             echo "DigitalOcean"; return 0 ;;
            *linode*|*akamai*)          echo "Linode/Akamai"; return 0 ;;
            *hetzner*)                  echo "Hetzner Cloud"; return 0 ;;
            *vultr*)                    echo "Vultr"; return 0 ;;
            *scaleway*)                 echo "Scaleway"; return 0 ;;
            *upcloud*)                  echo "UpCloud"; return 0 ;;
            *alibaba*|*aliyun*)         echo "Alibaba Cloud"; return 0 ;;
            *tencent*)                  echo "Tencent Cloud"; return 0 ;;
            *ovh*)                      echo "OVHcloud"; return 0 ;;
        esac
    done

    # Azure detection: chassis_asset_tag contains Azure-specific identifier
    # (sys_vendor "Microsoft Corporation" is shared with on-prem Hyper-V,
    # so we use this unique tag to distinguish Azure from local Hyper-V)
    if [[ -r /sys/class/dmi/id/chassis_asset_tag ]]; then
        local tag
        tag=$(cat /sys/class/dmi/id/chassis_asset_tag 2>/dev/null) || true
        if [[ "$tag" == "7783-7084-3265-9085-8269-3286-77" ]]; then
            echo "Microsoft Azure"; return 0
        fi
    fi

    # Note: Oracle Cloud (OCI) is intentionally NOT detected here.
    # OCI VMs use sys_vendor "Oracle Corporation" — the same string used by
    # physical Oracle/Sun servers (Sun Fire, SPARC, Oracle Server X-series).
    # No reliable DMI-based distinction exists between OCI and Oracle hardware.
    # OCI is still unsupported per documentation, but cannot be auto-detected.

    return 1
}

# Detect CPU architecture and check for ARM/Raspberry Pi
# Returns: architecture description (stdout), exit 0 if ARM, exit 1 if x86
detect_arm_architecture() {
    local arch
    arch=$(uname -m 2>/dev/null) || arch="unknown"

    case "$arch" in
        aarch64|arm64)
            if [[ -f /proc/device-tree/model ]]; then
                local model
                model=$(cat /proc/device-tree/model 2>/dev/null | tr -d '\0') || true
                if [[ "$model" == *"Raspberry Pi"* ]]; then
                    echo "Raspberry Pi ($model)"; return 0
                fi
                echo "ARM64 ($model)"; return 0
            fi
            echo "ARM64 (aarch64)"; return 0
            ;;
        armv7l|armv6l|armhf)
            if [[ -f /proc/device-tree/model ]]; then
                local model
                model=$(cat /proc/device-tree/model 2>/dev/null | tr -d '\0') || true
                if [[ "$model" == *"Raspberry Pi"* ]]; then
                    echo "Raspberry Pi ($model)"; return 0
                fi
                echo "ARM32 ($model)"; return 0
            fi
            echo "ARM32 ($arch)"; return 0
            ;;
    esac

    return 1
}

validate_dgb_address() {
    local addr="$1"
    [[ "$addr" =~ ^[DS][a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]
}

# Wait for APT lock to be released before proceeding
# This prevents race conditions when multiple apt operations are queued
# Uses exponential backoff: 1s → 2s → 4s → 8s → 16s (max) for faster response
wait_for_apt_lock() {
    local max_wait=300  # Maximum wait time in seconds (5 minutes)
    local wait_interval=1  # Start with 1 second
    local max_interval=16  # Cap at 16 seconds
    local waited=0
    local shown_message=0

    while true; do
        # Check all APT-related locks
        local locks_held=0

        # Check /var/lib/apt/lists/lock
        if sudo fuser /var/lib/apt/lists/lock >/dev/null 2>&1; then
            locks_held=1
        fi

        # Check /var/lib/dpkg/lock-frontend
        if sudo fuser /var/lib/dpkg/lock-frontend >/dev/null 2>&1; then
            locks_held=1
        fi

        # Check /var/lib/dpkg/lock
        if sudo fuser /var/lib/dpkg/lock >/dev/null 2>&1; then
            locks_held=1
        fi

        # Check /var/cache/apt/archives/lock
        if sudo fuser /var/cache/apt/archives/lock >/dev/null 2>&1; then
            locks_held=1
        fi

        if [[ $locks_held -eq 0 ]]; then
            # All locks are free
            return 0
        fi

        if [[ $waited -ge $max_wait ]]; then
            log_error "Timed out waiting for APT locks after ${max_wait}s"
            return 1
        fi

        # Show message immediately on first detection of lock
        if [[ $shown_message -eq 0 ]]; then
            log "Waiting for APT lock to be released..."
            shown_message=1
        fi

        sleep $wait_interval
        waited=$((waited + wait_interval))

        # Exponential backoff: double interval up to max
        if [[ $wait_interval -lt $max_interval ]]; then
            wait_interval=$((wait_interval * 2))
        fi
    done
}

# ═══════════════════════════════════════════════════════════════════════════════
# Copy coin binaries from another node instead of downloading
# ═══════════════════════════════════════════════════════════════════════════════
# Copies already-installed coin binaries from a source node via SSH/rsync.
# Works in two modes:
#   1. HA backup: copy from primary node (HA_MODE=ha-backup, HA_REPLICATE_FROM_PRIMARY=true)
#   2. Non-HA option 2: copy from user-specified source node (BLOCKCHAIN_SYNC_CHOICE=2)
# This avoids redundant internet downloads and works even when upstream
# mirrors are unreachable (e.g., GitHub 502 errors).
#
# Usage: copy_binaries_from_primary <coin_name> <remote_bin_dir> <local_bin_dir>
#   coin_name      - Display name (e.g., "Bitcoin II Core")
#   remote_bin_dir - Full path to bin/ directory on source (e.g., /spiralpool/bc2/bin)
#   local_bin_dir  - Full path to bin/ directory on this node (e.g., /spiralpool/bc2/bin)
#
# Returns: 0 if binaries were copied successfully, 1 otherwise
# ═══════════════════════════════════════════════════════════════════════════════
copy_binaries_from_primary() {
    local coin_name="$1"
    local remote_bin_dir="$2"
    local local_bin_dir="$3"

    # Determine source node and SSH credentials based on install mode.
    # Supports two modes:
    #   1. HA backup: copy from primary node (HA_MODE=ha-backup)
    #   2. Non-HA option 2: copy from user-specified source node (BLOCKCHAIN_SYNC_CHOICE=2)
    local source_ip=""
    local ssh_user=""
    local ssh_home=""
    local ssh_ready=""
    local source_label=""

    if [[ "$HA_MODE" == "ha-backup" ]] && [[ -n "${HA_PRIMARY_IP:-}" ]]; then
        # HA backup mode: replicate from primary
        if [[ "${HA_REPLICATE_FROM_PRIMARY:-}" == "false" ]]; then
            return 1
        fi
        source_ip="$HA_PRIMARY_IP"
        ssh_user="$POOL_USER"
        ssh_home="/home/${POOL_USER}"
        ssh_ready="${HA_SSH_READY:-}"
        source_label="primary"
    elif [[ "${BLOCKCHAIN_SYNC_CHOICE:-}" == "2" ]] && [[ "${SOURCE_SSH_READY:-}" == "true" ]] && [[ -n "${SYNC_SOURCE_NODE:-}" ]]; then
        # Non-HA: copy from user-specified source node
        source_ip="$SYNC_SOURCE_NODE"
        ssh_user="${SYNC_SSH_USER:-$POOL_USER}"
        ssh_home="/home/${ssh_user}"
        ssh_ready="true"
        source_label="source node"
    else
        return 1
    fi

    local remote_user="${ssh_user}@${source_ip}"

    # Explicit SSH identity + known_hosts — matches ha-replicate.sh pattern.
    local ssh_key="${ssh_home}/.ssh/id_ed25519"
    local ssh_known_hosts="${ssh_home}/.ssh/known_hosts"
    local ssh_base_opts="-o StrictHostKeyChecking=accept-new -o ConnectTimeout=10 -o BatchMode=yes"
    if [[ -f "$ssh_key" ]]; then
        ssh_base_opts="$ssh_base_opts -i $ssh_key"
    fi
    if [[ -f "$ssh_known_hosts" ]]; then
        ssh_base_opts="$ssh_base_opts -o UserKnownHostsFile=$ssh_known_hosts"
    fi

    # Do NOT trust stale SSH readiness variables — verify SSH directly if needed.
    if [[ "$ssh_ready" != "true" ]]; then
        local ssh_test_output=""
        if ssh_test_output=$(sudo -u "$ssh_user" ssh $ssh_base_opts "$remote_user" "echo 'SSH_OK'" 2>&1); then
            log "SSH connectivity to ${source_label} (${source_ip}) verified (recovering from stale state)"
            if [[ "$HA_MODE" == "ha-backup" ]]; then
                HA_SSH_READY=true
            fi
        else
            log_warn "Cannot SSH to ${source_label} (${source_ip})"
            log_warn "SSH diagnostic: ${ssh_test_output}"
            log_warn "Skipping binary copy for ${coin_name} — will download from network instead"
            return 1
        fi
    fi

    # Check if the source node has the binaries installed
    log "Checking if ${coin_name} binaries exist on ${source_label} (${source_ip})..."
    local remote_file_count=0
    local ssh_result=""
    local ssh_exit_code=0
    # Remote check: test if directory exists, then count files. Returns structured output
    # so we can distinguish "SSH failed" vs "dir missing" vs "dir empty" vs "files found".
    local remote_check_cmd="if [ ! -d '${remote_bin_dir}' ]; then echo 'DIR_MISSING'; elif [ -z \"\$(ls -A '${remote_bin_dir}/' 2>/dev/null)\" ]; then echo 'DIR_EMPTY'; else ls -1 '${remote_bin_dir}/' 2>/dev/null | wc -l; fi"
    # Use if-context so set -e doesn't kill script on SSH failure
    if ssh_result=$(sudo -u "$ssh_user" ssh $ssh_base_opts "$remote_user" "$remote_check_cmd" 2>&1); then
        local check_output
        check_output=$(echo "$ssh_result" | tail -1 | tr -d '[:space:]')
        if [[ "$check_output" == "DIR_MISSING" ]]; then
            log_warn "Directory ${remote_bin_dir} does not exist on ${source_label} (${source_ip})"
            log_warn "${coin_name} not installed on ${source_label} — will download from network instead"
            return 1
        elif [[ "$check_output" == "DIR_EMPTY" ]]; then
            log_warn "Directory ${remote_bin_dir} exists on ${source_label} but is empty"
            log_warn "${coin_name} binaries not found — will download from network instead"
            return 1
        fi
        remote_file_count=$(echo "$check_output" | tr -dc '0-9')
        remote_file_count="${remote_file_count:-0}"
    else
        ssh_exit_code=$?
        log_warn "SSH to ${source_label} failed (exit code ${ssh_exit_code}): ${ssh_result}"
        log_warn "Skipping binary copy for ${coin_name} — will download from network instead"
        return 1
    fi

    if [[ "$remote_file_count" -eq 0 ]]; then
        log_warn "Could not determine file count in ${remote_bin_dir} on ${source_label} — will download from network instead"
        return 1
    fi

    # Track how many coins had binaries on the source node
    # (used by ask_blockchain_rsync to skip replication when source has nothing)
    HA_PRIMARY_COIN_COUNT=$((${HA_PRIMARY_COIN_COUNT:-0} + 1))

    echo ""
    echo -e "  ${GREEN}${coin_name} binaries found on ${source_label}${NC}"
    echo -e "  ${WHITE}Source:${NC} ${source_ip}:${remote_bin_dir} (${remote_file_count} files)"

    # Create local bin directory writable by SSH user for rsync
    sudo mkdir -p "$local_bin_dir"
    sudo chown "${ssh_user}:${ssh_user}" "$local_bin_dir"

    log "Copying ${coin_name} binaries from ${source_label} (${source_ip})..."
    if sudo -u "$ssh_user" rsync -az --progress \
        -e "ssh $ssh_base_opts" \
        "${remote_user}:${remote_bin_dir}/" \
        "$local_bin_dir/" 2>&1; then

        # Restore ownership to pool user (services run as POOL_USER)
        sudo chown -R "${POOL_USER}:${POOL_USER}" "$local_bin_dir"
        # Ensure binaries are executable
        sudo chmod +x "$local_bin_dir/"* 2>/dev/null || true

        local copied_count
        copied_count=$(ls -1 "$local_bin_dir/" 2>/dev/null | wc -l)
        if [[ "$copied_count" -gt 0 ]]; then
            log_success "Copied ${copied_count} ${coin_name} binaries from ${source_label}"
            return 0
        else
            log_warn "rsync completed but no files found in ${local_bin_dir}"
            return 1
        fi
    else
        log_warn "Failed to copy binaries from ${source_label} — falling back to network download"
        return 1
    fi
}

# Download a file with retry logic and multiple mirrors
# Usage: download_with_retry <output_file> <url1> [url2] [url3] ...
# Returns: 0 on success, 1 on failure
download_with_retry() {
    local output_file="$1"
    shift
    local urls=("$@")
    local max_retries=2
    local retry_delay=3
    local connect_timeout=15
    local read_timeout=30

    for url in "${urls[@]}"; do
        log "Trying: $url"

        for ((attempt=1; attempt<=max_retries; attempt++)); do
            log "  Attempt $attempt of $max_retries..."

            # Clean up any partial download
            rm -f "$output_file"

            # Use wget with aggressive timeouts to fail fast and try next mirror
            # --connect-timeout: max time to establish connection (15s)
            # --read-timeout: max time between data packets (30s)
            # --dns-timeout: max time for DNS lookup (10s)
            # --max-redirect: follow up to 5 redirects (GitHub uses 302 redirects)
            if wget --progress=bar:force:noscroll \
                    --connect-timeout="$connect_timeout" \
                    --read-timeout="$read_timeout" \
                    --dns-timeout=10 \
                    --max-redirect=5 \
                    --tries=1 \
                    -O "$output_file" \
                    "$url" 2>&1; then

                # Verify the file was downloaded and is not empty
                if [[ -s "$output_file" ]]; then
                    log_success "Download successful"
                    return 0
                else
                    log_warn "Downloaded file is empty, retrying..."
                    rm -f "$output_file"
                fi
            else
                log_warn "Download failed (attempt $attempt)"
                rm -f "$output_file"
            fi

            # Wait before retry (except on last attempt)
            if [[ $attempt -lt $max_retries ]]; then
                log "  Waiting ${retry_delay}s before retry..."
                sleep "$retry_delay"
            fi
        done

        log_warn "All retries exhausted for this URL, trying next mirror..."
    done

    log_error "Failed to download from all mirrors after multiple retries"
    return 1
}

# Retry a function with user prompt on failure
# Usage: retry_with_prompt <max_retries> <description> <function_name> [args...]
# Returns: 0 on success, 1 if user chooses to skip/abort
retry_with_prompt() {
    local max_retries="$1"
    local description="$2"
    local func_name="$3"
    shift 3
    local args=("$@")

    for ((attempt=1; attempt<=max_retries; attempt++)); do
        if "$func_name" "${args[@]}"; then
            return 0
        fi

        if [[ $attempt -lt $max_retries ]]; then
            echo ""
            log_warn "$description failed (attempt $attempt of $max_retries)"
            echo -e "  ${WHITE}Options:${NC}"
            echo -e "    ${GREEN}r${NC} = Retry"
            echo -e "    ${YELLOW}s${NC} = Skip this step (may cause issues)"
            echo -e "    ${RED}a${NC} = Abort installation"
            echo ""
            prompt_input "Choice [r/s/a]: "; read choice
            case "$choice" in
                s|S)
                    log_warn "Skipping $description - installation may be incomplete"
                    return 0
                    ;;
                a|A)
                    log_error "Installation aborted by user"
                    exit 1
                    ;;
                *)
                    log "Retrying $description..."
                    ;;
            esac
        fi
    done

    # Final attempt failed - ask user what to do
    echo ""
    log_error "$description failed after $max_retries attempts"
    echo -e "  ${WHITE}Options:${NC}"
    echo -e "    ${GREEN}r${NC} = Retry again"
    echo -e "    ${YELLOW}s${NC} = Skip this step (may cause issues)"
    echo -e "    ${RED}a${NC} = Abort installation"
    echo ""
    prompt_input "Choice [r/s/a]: "; read choice
    case "$choice" in
        r|R)
            retry_with_prompt "$max_retries" "$description" "$func_name" "${args[@]}"
            return $?
            ;;
        s|S)
            log_warn "Skipping $description - installation may be incomplete"
            return 0
            ;;
        *)
            log_error "Installation aborted by user"
            exit 1
            ;;
    esac
}

# ═══════════════════════════════════════════════════════════════════════════════
# LVM DISK EXPANSION
# ═══════════════════════════════════════════════════════════════════════════════

expand_disk_if_needed() {
    # Auto-expand disk partitions to use all available space
    # Handles both LVM and standard partitions (common on cloud VMs)
    # Runs silently - no user prompts or output

    local root_device=$(df / | tail -1 | awk '{print $1}')
    local current_size=$(df -BG / | tail -1 | awk '{print $2}' | tr -d 'G')

    # Ensure growpart is available (required for partition expansion)
    if ! command -v growpart &>/dev/null; then
        wait_for_apt_lock
        sudo apt-get -qq -y install cloud-guest-utils &>/dev/null || true
    fi

    # ─────────────────────────────────────────────────────────────────────────────
    # CASE 1: LVM (common on Ubuntu cloud VMs)
    # ─────────────────────────────────────────────────────────────────────────────
    if [[ "$root_device" =~ /dev/mapper/ ]] || [[ "$root_device" =~ /dev/dm- ]]; then
        if command -v lvdisplay &>/dev/null; then
            # Get the LV path (e.g., /dev/ubuntu-vg/ubuntu-lv)
            # NOTE: All LVM commands require sudo to query volume information
            local lv_path=$(sudo lvdisplay 2>/dev/null | grep "LV Path" | head -1 | awk '{print $3}')
            if [[ -z "$lv_path" ]]; then
                lv_path=$(sudo lvs --noheadings -o lv_path 2>/dev/null | grep -E "ubuntu|root" | head -1 | tr -d ' ')
            fi
            if [[ -z "$lv_path" ]]; then
                lv_path=$(sudo lvs --noheadings -o lv_path 2>/dev/null | head -1 | tr -d ' ')
            fi

            if [[ -n "$lv_path" ]]; then
                # Get the volume group name
                local vg_name=$(sudo lvs --noheadings -o vg_name "$lv_path" 2>/dev/null | tr -d ' ')

                if [[ -n "$vg_name" ]]; then
                    # Get the physical volume device
                    local pv_device=$(sudo pvs --noheadings -o pv_name 2>/dev/null | head -1 | tr -d ' ')

                    if [[ -n "$pv_device" ]]; then
                        # Extract base disk and partition number
                        local base_disk=""
                        local part_num=""

                        if [[ "$pv_device" =~ nvme ]]; then
                            base_disk=$(echo "$pv_device" | sed 's/p[0-9]*$//')
                            part_num=$(echo "$pv_device" | grep -o '[0-9]*$')
                        else
                            base_disk=$(echo "$pv_device" | sed 's/[0-9]*$//')
                            part_num=$(echo "$pv_device" | grep -o '[0-9]*$')
                        fi

                        if [[ -n "$base_disk" ]] && [[ -n "$part_num" ]]; then
                            # STEP 1: Grow the partition
                            command -v growpart &>/dev/null && sudo growpart "$base_disk" "$part_num" &>/dev/null || true
                            # STEP 2: Resize the physical volume
                            sudo pvresize "$pv_device" &>/dev/null || true
                        fi
                    fi

                    # STEP 3: Extend LV to use all free space
                    sudo lvextend -l +100%FREE "$lv_path" &>/dev/null || true

                    # STEP 4: Resize the filesystem
                    local fs_type=$(df -T / | tail -1 | awk '{print $2}')
                    case "$fs_type" in
                        ext4|ext3|ext2)
                            sudo resize2fs "$lv_path" &>/dev/null || true
                            ;;
                        xfs)
                            sudo xfs_growfs / &>/dev/null || true
                            ;;
                    esac
                fi
            fi
        fi
        return 0
    fi

    # ─────────────────────────────────────────────────────────────────────────────
    # CASE 2: Standard partitions (AWS, GCP, Azure, DigitalOcean, etc.)
    # ─────────────────────────────────────────────────────────────────────────────

    # growpart already installed above, skip if not available
    command -v growpart &>/dev/null || return 0

    # Extract base disk and partition number
    local base_disk=""
    local part_num=""

    if [[ "$root_device" =~ nvme ]]; then
        base_disk=$(echo "$root_device" | sed 's/p[0-9]*$//')
        part_num=$(echo "$root_device" | grep -o 'p[0-9]*$' | tr -d 'p')
    else
        base_disk=$(echo "$root_device" | sed 's/[0-9]*$//')
        part_num=$(echo "$root_device" | grep -o '[0-9]*$')
    fi

    [[ -z "$base_disk" ]] || [[ -z "$part_num" ]] && return 0

    # Silently expand partition and filesystem
    sudo growpart "$base_disk" "$part_num" &>/dev/null || true
    local fs_type=$(df -T / | tail -1 | awk '{print $2}')
    case "$fs_type" in
        ext4|ext3|ext2)
            sudo resize2fs "$root_device" &>/dev/null || true
            ;;
        xfs)
            sudo xfs_growfs / &>/dev/null || true
            ;;
    esac
}

# Backwards compatibility alias
expand_lvm_if_needed() {
    expand_disk_if_needed
}

# ═══════════════════════════════════════════════════════════════════════════════
# MULTI-DISK STORAGE CONFIGURATION
# ═══════════════════════════════════════════════════════════════════════════════
#
# PURPOSE: Allow users with multiple disks (e.g., SSD + HDD) to optimally
# distribute data across storage devices while maintaining consistent paths.
#
# SCRIPT SAFETY CHECKS:
# 1. Only runs on FRESH installs (skipped if $INSTALL_DIR already exists)
# 2. NEVER formats or partitions disks - only uses pre-formatted filesystems
# 3. Requires explicit user opt-in (default: skip, use single disk)
# 4. All paths remain canonical - no application code changes required
# 5. Validates mounts work before proceeding
# 6. Provides rollback if configuration fails
#
# DATA PLACEMENT STRATEGY:
# - Fast storage (SSD/NVMe): PostgreSQL, WAL files, state files
# - Large storage (HDD): Blockchain data (can be 500GB+)
#
# ═══════════════════════════════════════════════════════════════════════════════

# Global flags to track multi-disk configuration (saved in checkpoint for resume)
MULTI_DISK_CONFIGURED="false"
CHAIN_STORAGE_MOUNT=""
CHAIN_MOUNT_POINT=""
CHAIN_DIRECT_DEVICE=""
CHAIN_BIND_SOURCE=""

size_to_bytes() {
    # Convert lsblk human-readable size (e.g., "1M", "500G", "1T") to bytes
    # lsblk uses 1024-based units (K=1024, M=1048576, G=1073741824, etc.)
    local size="$1"
    local num unit
    if [[ "$size" =~ ^([0-9]+(\.[0-9]+)?)([KMGTP]?)$ ]]; then
        num="${BASH_REMATCH[1]%%.*}"  # truncate any decimal
        unit="${BASH_REMATCH[3]}"
    else
        echo "0"; return
    fi
    case "$unit" in
        K) echo $((num * 1024)) ;;
        M) echo $((num * 1024 * 1024)) ;;
        G) echo $((num * 1024 * 1024 * 1024)) ;;
        T) echo $((num * 1024 * 1024 * 1024 * 1024)) ;;
        P) echo $((num * 1024 * 1024 * 1024 * 1024 * 1024)) ;;
        *) echo "$num" ;;
    esac
}

detect_available_disks() {
    # Detect block devices that could be used for additional storage
    # Returns: Prints list of available devices with size and type
    #
    # SAFETY: Only lists devices, never modifies them

    local devices=()

    # Get all block devices (excluding loop, ram, rom devices)
    while IFS= read -r line; do
        local name size type mountpoint fstype
        name=$(echo "$line" | awk '{print $1}')
        size=$(echo "$line" | awk '{print $2}')
        type=$(echo "$line" | awk '{print $3}')
        mountpoint=$(echo "$line" | awk '{print $4}')
        fstype=$(echo "$line" | awk '{print $5}')

        # Skip if:
        # - It's the root filesystem
        # - It's a boot partition
        # - It's swap
        # - It has no filesystem (unformatted)
        # - It's already mounted somewhere critical
        [[ "$mountpoint" == "/" ]] && continue
        [[ "$mountpoint" == "/boot"* ]] && continue
        [[ "$fstype" == "swap" ]] && continue
        [[ -z "$fstype" || "$fstype" == "null" ]] && continue

        # Skip devices under 8GB (avoids EFI/BIOS/recovery partitions)
        [[ $(size_to_bytes "$size") -lt 8589934592 ]] && continue

        # Only include if it has a usable filesystem
        if [[ "$fstype" == "ext4" || "$fstype" == "ext3" || "$fstype" == "xfs" || "$fstype" == "btrfs" ]]; then
            devices+=("/dev/$name|$size|$fstype|$mountpoint")
        fi
    done < <(lsblk -rno NAME,SIZE,TYPE,MOUNTPOINT,FSTYPE 2>/dev/null | grep -E "^(sd|nvme|vd|xvd)" | grep -E "(disk|part)")

    # Also check for unmounted but formatted partitions
    while IFS= read -r line; do
        local dev fstype
        dev=$(echo "$line" | awk '{print $1}' | tr -d ':')
        fstype=$(echo "$line" | awk -F'TYPE="' '{print $2}' | cut -d'"' -f1)

        # Skip if already in our list or if it's swap/unknown
        [[ "$fstype" == "swap" ]] && continue
        [[ -z "$fstype" ]] && continue

        # Check if not already mounted
        if ! mount | grep -q "^$dev "; then
            local size
            size=$(lsblk -rno SIZE "$dev" 2>/dev/null | head -1)
            if [[ -n "$size" && $(size_to_bytes "$size") -ge 8589934592 && ( "$fstype" == "ext4" || "$fstype" == "ext3" || "$fstype" == "xfs" || "$fstype" == "btrfs" ) ]]; then
                # Check if not already in devices array
                local already_added="false"
                for d in "${devices[@]+"${devices[@]}"}"; do
                    [[ "$d" == "$dev|"* ]] && already_added="true" && break
                done
                [[ "$already_added" == "false" ]] && devices+=("$dev|$size|$fstype|unmounted")
            fi
        fi
    done < <(blkid 2>/dev/null)

    # Detect unformatted (raw) disks and partitions
    local root_dev root_parent_disk
    root_dev=$(df / | tail -1 | awk '{print $1}')
    # Extract parent disk name (e.g., sda from /dev/sda1, nvme0n1 from /dev/nvme0n1p1)
    if [[ "$root_dev" =~ nvme ]]; then
        root_parent_disk=$(basename "$root_dev" | sed 's/p[0-9]*$//')
    else
        root_parent_disk=$(basename "$root_dev" | sed 's/[0-9]*$//')
    fi

    while IFS= read -r line; do
        local r_name r_size r_type r_mount r_fstype
        r_name=$(echo "$line" | awk '{print $1}')
        r_size=$(echo "$line" | awk '{print $2}')
        r_type=$(echo "$line" | awk '{print $3}')
        r_mount=$(echo "$line" | awk '{print $4}')
        r_fstype=$(echo "$line" | awk '{print $5}')

        # Only interested in devices with NO filesystem and NO mount
        [[ -n "$r_mount" ]] && continue
        [[ -n "$r_fstype" ]] && continue

        # Skip devices under 8GB (avoids EFI/BIOS/recovery partitions)
        [[ $(size_to_bytes "$r_size") -lt 8589934592 ]] && continue

        # Skip if on the same physical disk as root
        local r_parent
        if [[ "$r_name" =~ nvme ]]; then
            r_parent=$(echo "$r_name" | sed 's/p[0-9]*$//')
        else
            r_parent=$(echo "$r_name" | sed 's/[0-9]*$//')
        fi
        [[ "$r_parent" == "$root_parent_disk" || "$r_name" == "$root_parent_disk" ]] && continue

        # Skip swap (check via blkid)
        if blkid "/dev/$r_name" 2>/dev/null | grep -qi 'TYPE="swap"'; then
            continue
        fi

        # For whole disks: skip if any child partition has a filesystem
        # (those partitions are already caught by the loops above)
        if [[ "$r_type" == "disk" ]]; then
            local child_fs
            child_fs=$(lsblk -rno FSTYPE "/dev/$r_name" 2>/dev/null | grep -v '^$' || true)
            [[ -n "$child_fs" ]] && continue
        fi

        # For partitions: skip if the parent disk is entirely raw
        # (in that case, the whole disk is shown instead)
        if [[ "$r_type" == "part" ]]; then
            local r_parent_disk_name
            if [[ "$r_name" =~ nvme ]]; then
                r_parent_disk_name=$(echo "$r_name" | sed 's/p[0-9]*$//')
            else
                r_parent_disk_name=$(echo "$r_name" | sed 's/[0-9]*$//')
            fi
            local parent_has_fs
            parent_has_fs=$(lsblk -rno FSTYPE "/dev/$r_parent_disk_name" 2>/dev/null | grep -v '^$' || true)
            [[ -z "$parent_has_fs" ]] && continue
        fi

        # Skip if already in our devices list
        local already_added="false"
        for d in "${devices[@]+"${devices[@]}"}"; do
            [[ "$d" == "/dev/$r_name|"* ]] && already_added="true" && break
        done
        [[ "$already_added" == "true" ]] && continue

        local raw_type
        [[ "$r_type" == "disk" ]] && raw_type="RAW" || raw_type="RAW_PART"
        devices+=("/dev/$r_name|$r_size|$raw_type|unformatted")
    done < <(lsblk -rno NAME,SIZE,TYPE,MOUNTPOINT,FSTYPE 2>/dev/null | grep -E "^(sd|nvme|vd|xvd)" | grep -E "(disk|part)")

    # Output devices
    for d in "${devices[@]+"${devices[@]}"}"; do
        echo "$d"
    done
}

detect_disk_type() {
    # Detect if a disk is SSD/NVMe or HDD (rotational)
    # Args: $1 = device path (e.g., /dev/sda1, /dev/mapper/ubuntu--vg-ubuntu--lv)
    # Returns: "ssd" or "hdd"

    local device="$1"

    # ── LVM / device-mapper devices (/dev/mapper/...) ────────────────────────
    # These don't appear directly in /sys/block/ under their mapper name.
    # Resolve via dm name → dm-N sysfs entry → slave physical devices.
    if [[ "$device" == /dev/mapper/* ]]; then
        local mapper_name="${device#/dev/mapper/}"
        local dm_sysdir
        for d in /sys/block/dm-*/dm/name; do
            if [[ "$(cat "$d" 2>/dev/null)" == "$mapper_name" ]]; then
                dm_sysdir="$(dirname "$(dirname "$d")")"   # /sys/block/dm-N
                break
            fi
        done
        if [[ -n "$dm_sysdir" ]]; then
            # Walk slaves (the underlying physical/partition devices).
            # If ANY slave is SSD, treat the LV as SSD.
            for slave in "$dm_sysdir"/slaves/*/; do
                local slave_name
                slave_name=$(basename "$slave")
                # Strip partition suffix to reach the block device row
                local slave_base
                if [[ "$slave_name" =~ nvme ]]; then
                    slave_base=$(echo "$slave_name" | sed 's/p[0-9]*$//')
                else
                    slave_base=$(echo "$slave_name" | sed 's/[0-9]*$//')
                fi
                local rot
                rot=$(cat "/sys/block/$slave_base/queue/rotational" 2>/dev/null)
                if [[ "$rot" == "0" ]]; then
                    echo "ssd"
                    return
                fi
            done
            echo "hdd"
            return
        fi
        # dm device not found in sysfs — fall through to default (hdd)
        echo "hdd"
        return
    fi

    # ── Standard block devices (/dev/sdX, /dev/nvmeXnY, etc.) ───────────────
    local base_device
    if [[ "$device" =~ nvme ]]; then
        base_device=$(echo "$device" | sed 's/p[0-9]*$//')
    else
        base_device=$(echo "$device" | sed 's/[0-9]*$//')
    fi

    local dev_name
    dev_name=$(basename "$base_device")

    # Check rotational flag (0 = SSD, 1 = HDD)
    local rotational
    rotational=$(cat "/sys/block/$dev_name/queue/rotational" 2>/dev/null)

    if [[ "$rotational" == "0" ]]; then
        echo "ssd"
    else
        echo "hdd"
    fi
}

format_raw_disk() {
    # Format a raw (unformatted) disk or partition as ext4
    # Args: $1 = device path, $2 = raw type (RAW or RAW_PART)
    # Prints: the formatted partition device path on success
    # Returns: 0 on success, 1 on failure
    #
    # RAW (whole disk): creates GPT partition table + single partition, then formats
    # RAW_PART (existing partition): formats directly as ext4

    local device="$1"
    local raw_type="$2"

    if [[ "$raw_type" == "RAW" ]]; then
        # Whole disk — create GPT partition table with single Linux partition
        log "Creating GPT partition table on $device..."
        if ! echo ',,L,' | sudo sfdisk --label gpt "$device" 2>/dev/null; then
            log_error "Failed to create partition table on $device"
            return 1
        fi

        # Notify kernel of partition changes
        sudo partprobe "$device" 2>/dev/null
        sleep 2

        # Determine the new partition path (NVMe uses p1 suffix, SATA uses 1)
        local part_device
        if [[ "$device" =~ nvme ]]; then
            part_device="${device}p1"
        else
            part_device="${device}1"
        fi

        # Verify partition was created
        if [[ ! -b "$part_device" ]]; then
            log_error "Partition $part_device not found after partitioning"
            return 1
        fi

        # Format the new partition
        log "Formatting $part_device as ext4..."
        if ! sudo mkfs.ext4 -q "$part_device"; then
            log_error "Failed to format $part_device"
            return 1
        fi

        echo "$part_device"
    else
        # Existing partition — format directly
        log "Formatting $device as ext4..."
        if ! sudo mkfs.ext4 -q "$device"; then
            log_error "Failed to format $device"
            return 1
        fi

        echo "$device"
    fi
}

check_root_disk_speed() {
    # Check if the root filesystem is on a slow HDD
    # Returns: "ssd" if fast storage, "hdd" if slow spinning disk
    #
    # This uses the Linux rotational flag:
    # - 0 = Non-rotational (SSD, NVMe, virtual disk)
    # - 1 = Rotational (traditional spinning HDD)

    local root_device
    root_device=$(df / | tail -1 | awk '{print $1}')

    # Handle LVM - get the underlying physical device
    if [[ "$root_device" =~ /dev/mapper/ ]] || [[ "$root_device" =~ /dev/dm- ]]; then
        # Get the physical volume backing the LVM
        local pv_device
        pv_device=$(sudo pvs --noheadings -o pv_name 2>/dev/null | head -1 | tr -d ' ')
        [[ -n "$pv_device" ]] && root_device="$pv_device"
    fi

    # Extract base device name (e.g., sda from /dev/sda1, nvme0n1 from /dev/nvme0n1p1)
    local base_device
    if [[ "$root_device" =~ nvme ]]; then
        base_device=$(echo "$root_device" | sed 's|/dev/||' | sed 's/p[0-9]*$//')
    else
        base_device=$(echo "$root_device" | sed 's|/dev/||' | sed 's/[0-9]*$//')
    fi

    # Check rotational flag
    local rotational
    rotational=$(cat "/sys/block/$base_device/queue/rotational" 2>/dev/null)

    if [[ "$rotational" == "0" ]]; then
        echo "ssd"
    else
        echo "hdd"
    fi
}

configure_multi_disk_storage() {
    # Interactive configuration for multi-disk setups
    # SAFETY: Only runs on fresh installs. Formatting requires explicit YES confirmation.
    #
    # This function:
    # 1. Checks if root disk is a slow HDD (warns user)
    # 2. Detects available SSDs for blockchain data
    # 3. Lets user choose to use faster storage if available
    # 4. Sets up mount point (added to /etc/fstab for persistence)

    # SAFETY CHECK 1: Skip if this is an existing installation
    if [[ -d "$INSTALL_DIR" && -f "$INSTALL_DIR/config/config.yaml" ]]; then
        log "Existing installation detected - skipping disk configuration"
        return 0
    fi

    # SAFETY CHECK 2: Skip in non-interactive mode
    if [[ "$NON_INTERACTIVE" == "true" ]]; then
        return 0
    fi

    # ─────────────────────────────────────────────────────────────────────────────
    # Check root disk type - warn if HDD detected
    # ─────────────────────────────────────────────────────────────────────────────
    local root_disk_type
    root_disk_type=$(check_root_disk_speed)

    # Detect available disks (for multi-disk option)
    local available_disks
    available_disks=$(detect_available_disks)

    # Count usable disks and check if any are SSDs
    local disk_count=0
    local ssd_available="false"
    local ssd_device=""
    local ssd_size=""

    while IFS='|' read -r dev size fstype mount; do
        [[ -z "$dev" ]] && continue
        ((++disk_count))
        local dtype
        dtype=$(detect_disk_type "$dev")
        if [[ "$dtype" == "ssd" ]]; then
            ssd_available="true"
            ssd_device="$dev"
            ssd_size="$size"
        fi
    done <<< "$available_disks"

    # HDD is fine — no warning needed, just continue
    if [[ "$root_disk_type" == "hdd" ]]; then
        log "Root filesystem is on HDD — continuing"
    fi

    # ─────────────────────────────────────────────────────────────────────────────
    # Case 2: Root is SSD - check for additional storage options
    # ─────────────────────────────────────────────────────────────────────────────

    # If no additional disks detected, nothing to configure
    if [[ "$disk_count" -lt 1 ]]; then
        return 0
    fi

    # Root is already SSD - offer multi-disk only if user has additional storage
    # (e.g., they might want to use a large HDD for blockchain to save SSD space)
    echo ""
    echo -e "${CYAN}═══════════════════════════════════════════════════════════════════════════════${NC}"
    echo -e "${WHITE}  ADDITIONAL STORAGE DETECTED${NC}"
    echo -e "${CYAN}═══════════════════════════════════════════════════════════════════════════════${NC}"
    echo ""
    echo -e "  Your root filesystem is on ${GREEN}fast storage (SSD/NVMe)${NC} - great!"
    echo ""
    echo -e "  Additional storage device(s) available:"
    echo ""

    local idx=1
    local disk_array=()
    while IFS='|' read -r dev size fstype mount; do
        [[ -z "$dev" ]] && continue
        local disk_type
        disk_type=$(detect_disk_type "$dev")
        local type_label
        [[ "$disk_type" == "ssd" ]] && type_label="${GREEN}SSD${NC}" || type_label="${YELLOW}HDD${NC}"

        local mount_info
        if [[ "$mount" == "unformatted" ]]; then
            mount_info="${RED}(unformatted - will be formatted as ext4)${NC}"
        elif [[ "$mount" == "unmounted" ]]; then
            mount_info="${DIM}(not mounted)${NC}"
        else
            mount_info="${DIM}(mounted: $mount)${NC}"
        fi

        echo -e "    ${WHITE}$idx)${NC} $dev - $size [$type_label] $mount_info"
        disk_array+=("$dev|$fstype|$mount")
        ((idx++))
    done <<< "$available_disks"

    echo ""
    echo -e "  ${WHITE}Options:${NC}"
    echo -e "    ${GREEN}1-$((idx-1))${NC} = Move blockchain data to selected disk"
    echo -e "    ${WHITE}s${NC}     = Skip - keep everything on root SSD (${GREEN}recommended${NC})"
    echo ""

    local choice
    prompt_input "Choice [s]: "; read choice
    choice="${choice:-s}"

    # Skip if user chooses 's' or empty
    if [[ "$choice" == "s" || "$choice" == "S" || -z "$choice" ]]; then
        log "Keeping all data on root SSD"
        return 0
    fi

    # Validate numeric choice
    if ! [[ "$choice" =~ ^[0-9]+$ ]] || [[ "$choice" -lt 1 ]] || [[ "$choice" -gt ${#disk_array[@]} ]]; then
        log_warn "Invalid selection - keeping all data on root SSD"
        return 0
    fi

    # Get selected disk
    local selected="${disk_array[$((choice-1))]}"
    local sel_dev sel_fstype sel_mount
    IFS='|' read -r sel_dev sel_fstype sel_mount <<< "$selected"

    # Warn if moving to HDD
    local sel_disk_type
    sel_disk_type=$(detect_disk_type "$sel_dev")
    if [[ "$sel_disk_type" == "hdd" ]]; then
        echo ""
        echo -e "  ${YELLOW}⚠️  Warning: Moving blockchain to HDD will slow down sync.${NC}"
        prompt_input "Are you sure? [y/N]: "; read confirm
        if [[ ! "$confirm" =~ ^[Yy]$ ]]; then
            log "Keeping all data on root SSD"
            return 0
        fi
    fi

    echo ""
    log "Selected $sel_dev for blockchain data storage"

    # SAFETY CHECK: Verify the device exists
    if [[ ! -b "$sel_dev" ]]; then
        log_error "Device $sel_dev not found - keeping data on root"
        return 0
    fi

    # Handle unformatted (raw) disk — requires explicit formatting confirmation
    if [[ "$sel_fstype" == "RAW" || "$sel_fstype" == "RAW_PART" ]]; then
        local sel_size_display
        sel_size_display=$(lsblk -rno SIZE "$sel_dev" 2>/dev/null | head -1)
        echo ""
        echo -e "  ${RED}╔══════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "  ${RED}║                                                                      ║${NC}"
        echo -e "  ${RED}║  ${WHITE}WARNING: DESTRUCTIVE OPERATION${RED}                                      ║${NC}"
        echo -e "  ${RED}║                                                                      ║${NC}"
        echo -e "  ${RED}║  This will ERASE ALL DATA on ${WHITE}${sel_dev}${RED} (${sel_size_display:-unknown size})${RED}             ║${NC}"
        echo -e "  ${RED}║  The disk will be partitioned (GPT) and formatted as ext4.           ║${NC}"
        echo -e "  ${RED}║                                                                      ║${NC}"
        echo -e "  ${RED}║  ${YELLOW}THIS ACTION CANNOT BE UNDONE.${RED}                                       ║${NC}"
        echo -e "  ${RED}║                                                                      ║${NC}"
        echo -e "  ${RED}╚══════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        echo -e "  Type ${WHITE}YES${NC} (uppercase) to confirm formatting, or anything else to cancel:"
        echo ""
        local format_confirm
        prompt_input "Confirm: "; read format_confirm
        if [[ "$format_confirm" != "YES" ]]; then
            log "Formatting cancelled - keeping all data on root"
            return 0
        fi

        echo ""
        local formatted_device
        if ! formatted_device=$(format_raw_disk "$sel_dev" "$sel_fstype"); then
            log_error "Formatting failed - keeping all data on root"
            return 0
        fi

        # Update device and filesystem type for the mount flow below
        sel_dev="$formatted_device"
        sel_fstype="ext4"
        sel_mount="unmounted"
        log_success "Successfully formatted $formatted_device as ext4"
        echo ""
    fi

    # Determine mount point for blockchain data
    local chain_mount="$INSTALL_DIR/chain"

    if [[ "$sel_mount" != "unmounted" && -n "$sel_mount" && "$sel_mount" != "/" ]]; then
        CHAIN_STORAGE_MOUNT="$sel_mount"
        CHAIN_BIND_SOURCE="$sel_mount/spiralpool-chain"
        log "Will create bind mount from $CHAIN_BIND_SOURCE to $chain_mount"
    else
        CHAIN_STORAGE_MOUNT="$chain_mount"
        CHAIN_DIRECT_DEVICE="$sel_dev"
        log "Will mount $sel_dev directly to $chain_mount"
    fi

    MULTI_DISK_CONFIGURED="true"
    CHAIN_MOUNT_POINT="$chain_mount"

    log_success "Blockchain storage configured on $sel_dev"
    echo ""

    return 0
}

setup_multi_disk_mounts() {
    # Actually create the mount points and configure fstab
    # Called AFTER base directories are created
    #
    # SAFETY: Only runs if configure_multi_disk_storage() was successful

    [[ "$MULTI_DISK_CONFIGURED" != "true" ]] && return 0

    log "Setting up multi-disk storage mounts..."

    # Create the chain mount point
    sudo mkdir -p "$CHAIN_MOUNT_POINT"

    if [[ -n "$CHAIN_DIRECT_DEVICE" ]]; then
        # Direct mount - device wasn't previously mounted
        # Add to fstab for persistence
        local fstab_entry="$CHAIN_DIRECT_DEVICE $CHAIN_MOUNT_POINT auto defaults,nofail 0 2"

        # Check if already in fstab
        if ! grep -q "$CHAIN_MOUNT_POINT" /etc/fstab 2>/dev/null; then
            echo "# Spiral Pool blockchain data storage" | sudo tee -a /etc/fstab > /dev/null
            echo "$fstab_entry" | sudo tee -a /etc/fstab > /dev/null
            log "Added $CHAIN_DIRECT_DEVICE to /etc/fstab"
        fi

        # Mount it
        if ! sudo mount "$CHAIN_MOUNT_POINT" 2>/dev/null; then
            log_warn "Failed to mount $CHAIN_DIRECT_DEVICE - continuing with single disk"
            # Remove fstab entry on failure
            sudo sed -i "\|$CHAIN_MOUNT_POINT|d" /etc/fstab 2>/dev/null
            MULTI_DISK_CONFIGURED="false"
            return 0
        fi

    elif [[ -n "$CHAIN_BIND_SOURCE" ]]; then
        # Bind mount from existing mount point
        sudo mkdir -p "$CHAIN_BIND_SOURCE"

        local fstab_entry="$CHAIN_BIND_SOURCE $CHAIN_MOUNT_POINT none bind,nofail 0 0"

        if ! grep -q "$CHAIN_MOUNT_POINT" /etc/fstab 2>/dev/null; then
            echo "# Spiral Pool blockchain data storage (bind mount)" | sudo tee -a /etc/fstab > /dev/null
            echo "$fstab_entry" | sudo tee -a /etc/fstab > /dev/null
            log "Added bind mount to /etc/fstab"
        fi

        if ! sudo mount "$CHAIN_MOUNT_POINT" 2>/dev/null; then
            log_warn "Failed to create bind mount - continuing with single disk"
            sudo sed -i "\|$CHAIN_MOUNT_POINT|d" /etc/fstab 2>/dev/null
            MULTI_DISK_CONFIGURED="false"
            return 0
        fi
    fi

    # Set ownership
    sudo chown -R "$POOL_USER:$POOL_USER" "$CHAIN_MOUNT_POINT"
    sudo chmod 755 "$CHAIN_MOUNT_POINT"

    log_success "Multi-disk storage mount configured at $CHAIN_MOUNT_POINT"

    return 0
}

get_blockchain_dir() {
    # Returns the appropriate directory for blockchain data
    # If multi-disk is configured, returns the chain mount point
    # Otherwise returns the standard location under $INSTALL_DIR
    #
    # Usage: local btc_dir=$(get_blockchain_dir "btc")

    local coin="$1"

    if [[ "$MULTI_DISK_CONFIGURED" == "true" && -d "$CHAIN_MOUNT_POINT" ]]; then
        echo "$CHAIN_MOUNT_POINT/$coin"
    else
        echo "$INSTALL_DIR/$coin"
    fi
}

# ═══════════════════════════════════════════════════════════════════════════════
# PREREQUISITE CHECKS
# ═══════════════════════════════════════════════════════════════════════════════

check_prerequisites() {
    log_step "Checking Prerequisites"

    # Not root
    if [[ $EUID -eq 0 ]]; then
        log_error "Do NOT run as root. Use a regular user with sudo privileges."
        exit 1
    fi

    # Sudo access
    if ! sudo -n true 2>/dev/null; then
        log "Sudo access required. Please enter your password:"
        sudo -v
    fi
    log_success "Sudo access confirmed"

    # ═══════════════════════════════════════════════════════════════════════════════
    # GATE ZERO: HOST REALITY VALIDATION
    # These checks ensure the host environment is suitable for installation.
    # ═══════════════════════════════════════════════════════════════════════════════

    log_step "Host Environment Validation"

    # Ubuntu version enforcement (Ubuntu 24.04 LTS required)
    if [[ ! -f /etc/os-release ]]; then
        log_error "Cannot detect OS. Ubuntu 24.04 LTS required."
        exit 1
    fi
    . /etc/os-release
    if [[ "$ID" != "ubuntu" ]]; then
        log_error "Ubuntu required. Detected: $ID"
        exit 1
    fi
    if [[ "$VERSION_ID" != "24.04" ]]; then
        log_error "Ubuntu $VERSION_ID not supported. Requires Ubuntu 24.04 LTS."
        log_error "Ubuntu 24.04 LTS is required for Go 1.25, PostgreSQL 16, and system dependencies."
        exit 1
    fi
    log_success "Operating System: Ubuntu $VERSION_ID LTS"

    # Filesystem type enforcement (must be ext4, xfs, or btrfs for journaling)
    local fs_type=$(df -T / | tail -1 | awk '{print $2}')
    if [[ ! "$fs_type" =~ ^(ext4|xfs|btrfs)$ ]]; then
        log_error "Unsupported filesystem: $fs_type"
        log_error "Requires ext4, xfs, or btrfs for data integrity (journaling support)."
        exit 1
    fi
    log_success "Filesystem: $fs_type (journaled)"

    # NTP/Time synchronization validation (critical for blockchain consensus)
    local ntp_synced="false"
    if command -v timedatectl &>/dev/null; then
        if timedatectl show 2>/dev/null | grep -q "NTPSynchronized=yes"; then
            ntp_synced="true"
        elif timedatectl status 2>/dev/null | grep -q "synchronized: yes"; then
            ntp_synced="true"
        fi
    fi
    if [[ "$ntp_synced" != "true" ]]; then
        log_warn "NTP not synchronized - enabling time sync..."
        sudo timedatectl set-ntp true 2>/dev/null || true
        sleep 2
        # Re-check after enabling
        if timedatectl show 2>/dev/null | grep -q "NTPSynchronized=yes" || \
           timedatectl status 2>/dev/null | grep -q "synchronized: yes"; then
            log_success "NTP synchronization enabled"
        else
            log_warn "NTP may take a moment to synchronize - proceeding"
        fi
    else
        log_success "NTP synchronized"
    fi

    # Time drift detection (compare against HTTP header from known server)
    local time_drift_ok="true"
    if command -v curl &>/dev/null; then
        local remote_date=$(curl -sI --connect-timeout 5 https://google.com 2>/dev/null | grep -i "^date:" | cut -d' ' -f2-)
        if [[ -n "$remote_date" ]]; then
            local remote_epoch=$(date -d "$remote_date" +%s 2>/dev/null || echo "0")
            local local_epoch=$(date +%s)
            if [[ "$remote_epoch" != "0" ]]; then
                local drift=$((local_epoch - remote_epoch))
                # Convert to absolute value
                drift=${drift#-}
                if [[ $drift -gt 60 ]]; then
                    log_error "Clock drift detected: ${drift} seconds"
                    log_error "Blockchain consensus requires accurate time. Run: sudo timedatectl set-ntp true"
                    exit 1
                elif [[ $drift -gt 10 ]]; then
                    log_warn "Minor clock drift: ${drift}s (acceptable)"
                fi
            fi
        fi
    fi

    # Entropy pool validation (critical for cryptographic operations)
    local entropy=$(cat /proc/sys/kernel/random/entropy_avail 2>/dev/null || echo "0")
    if [[ $entropy -lt 256 ]]; then
        log_warn "Low entropy: $entropy bits (minimum 256 recommended)"
        log "Installing haveged for entropy generation..."
        sudo apt-get -qq -y install haveged 2>/dev/null || true
        sudo systemctl enable --now haveged 2>/dev/null || true
        sleep 1
        entropy=$(cat /proc/sys/kernel/random/entropy_avail 2>/dev/null || echo "0")
        if [[ $entropy -ge 256 ]]; then
            log_success "Entropy pool: $entropy bits (after haveged)"
        else
            log_warn "Entropy still low ($entropy bits) - crypto operations may block"
        fi
    else
        log_success "Entropy pool: $entropy bits"
    fi

    # DNS resolution pre-check (validate before starting installation)
    local dns_ok="false"
    for dns_target in "github.com" "apt.postgresql.org" "download.docker.com"; do
        if host "$dns_target" &>/dev/null || nslookup "$dns_target" &>/dev/null 2>&1 || \
           getent hosts "$dns_target" &>/dev/null; then
            dns_ok="true"
            break
        fi
    done
    if [[ "$dns_ok" != "true" ]]; then
        log_error "DNS resolution failed. Cannot resolve required hosts."
        log_error "Check /etc/resolv.conf and network connectivity."
        exit 1
    fi
    log_success "DNS resolution working"

    # SELinux detection (can silently break functionality)
    if command -v getenforce &>/dev/null; then
        local selinux_status=$(getenforce 2>/dev/null || echo "unknown")
        if [[ "$selinux_status" == "Enforcing" ]]; then
            log_warn "SELinux is ENFORCING - may require policy adjustments"
        fi
    fi

    # Check for conflicting HA software (before we install keepalived)
    local ha_conflict=""
    for svc in keepalived corosync pacemaker heartbeat; do
        if systemctl is-active --quiet "$svc" 2>/dev/null; then
            # Skip keepalived if it's ours (from a previous Spiral Pool install)
            if [[ "$svc" == "keepalived" ]] && grep -q "SPIRALPOOL_VIP" /etc/keepalived/keepalived.conf 2>/dev/null; then
                log "Existing Spiral Pool keepalived detected — will reconfigure"
                continue
            fi
            ha_conflict="$svc"
            break
        fi
    done
    if [[ -n "$ha_conflict" ]]; then
        log_error "Conflicting HA service '$ha_conflict' is running."
        log_error "Disable it before installing Spiral Pool HA: sudo systemctl stop $ha_conflict"
        exit 1
    fi
    log_success "No conflicting HA services"

    # journald validation (ensure logging works)
    if ! systemctl is-active --quiet systemd-journald 2>/dev/null; then
        log_warn "systemd-journald is not running - attempting to start..."
        sudo systemctl start systemd-journald 2>/dev/null || true
    fi
    if systemctl is-active --quiet systemd-journald 2>/dev/null; then
        # Ensure persistent journal storage
        if [[ ! -d /var/log/journal ]]; then
            sudo mkdir -p /var/log/journal 2>/dev/null || true
            sudo systemd-tmpfiles --create --prefix /var/log/journal 2>/dev/null || true
        fi
        log_success "journald running with persistent storage"
    else
        log_warn "journald not active - logs may not persist"
    fi

    log_success "Host environment validated"
    echo ""

    # Update system packages first (ensures everything is current before installation)
    wait_for_apt_lock
    run_with_spinner "Fetching package lists..." sudo apt-get -qq -y update
    wait_for_apt_lock
    run_with_spinner "Upgrading system packages..." sudo apt-get -qq -y upgrade
    log_success "System packages updated"

    # Auto-expand LVM if there's unused space in the volume group
    # This is common on cloud VMs where the disk is larger than the default partition
    expand_lvm_if_needed

    # Memory check - minimum 10GB to proceed
    local total_mem=$(free -g | awk '/^Mem:/{print $2}' | tr -d ' ')
    if [[ $total_mem -lt 10 ]]; then
        echo ""
        echo -e "${RED}═══════════════════════════════════════════════════════════════════════════════${NC}"
        echo -e "${RED}  INSUFFICIENT MEMORY: ${total_mem}GB detected (minimum 10GB required)${NC}"
        echo -e "${RED}═══════════════════════════════════════════════════════════════════════════════${NC}"
        echo ""
        echo -e "  ${YELLOW}This is spicy. 🌶️ Crashes may occur with low RAM.${NC}"
        echo -e "  ${YELLOW}Proceed at your own risk - you've been warned!${NC}"
        echo ""
        exit 1
    else
        log_success "Memory: ${total_mem}GB RAM"
    fi
}

