    echo -e "${CYAN} ░░░░░░░░███ ░███ ░███ ░███  ░███ ░░░   ███████  ░███     ░███░░░░░░  ░███ ░███░███ ░███ ░███${NC}"
    echo -e "${CYAN} ███    ░███ ░███ ░███ ░███  ░███      ███░░███  ░███     ░███        ░███ ░███░███ ░███ ░███${NC}"
