select_deploy_method() {
    clear
    log_step "Hardware Environment"

    # Auto-detect virtualization using safe Linux tools
    local detected_virt=$(detect_virtualization)
    local is_vm="false"
    local virt_name=""

    if [[ "$detected_virt" != "none" ]]; then
        is_vm="true"
        # Convert hypervisor/platform code to friendly display name
        case "$detected_virt" in
            # --- Desktop Hypervisors ---
            oracle|virtualbox)      virt_name="VirtualBox" ;;
            vmware)                 virt_name="VMware" ;;
            parallels)              virt_name="Parallels Desktop" ;;

            # --- Type-1 / Server Hypervisors ---
            kvm|qemu)               virt_name="KVM/QEMU" ;;
            microsoft|hyperv)       virt_name="Hyper-V" ;;
            xen)                    virt_name="Xen" ;;
            nutanix)                virt_name="Nutanix AHV" ;;
            bhyve)                  virt_name="bhyve (FreeBSD)" ;;
            bochs)                  virt_name="Bochs" ;;
            apple)                  virt_name="Apple Virtualization" ;;
            openstack)              virt_name="OpenStack" ;;

            # --- Containers ---
            lxc|lxc-libvirt)        virt_name="LXC Container" ;;
            docker)                 virt_name="Docker Container" ;;
            podman)                 virt_name="Podman Container" ;;
            openvz)                 virt_name="OpenVZ Container" ;;
            systemd-nspawn)         virt_name="systemd-nspawn Container" ;;
            rkt)                    virt_name="rkt Container" ;;
            proot)                  virt_name="PRoot Container" ;;
            wsl)                    virt_name="WSL" ;;

            # --- Cloud Providers ---
            amazon)                 virt_name="AWS EC2" ;;
            google)                 virt_name="Google Cloud" ;;
            digitalocean)           virt_name="DigitalOcean" ;;
            linode)                 virt_name="Linode/Akamai" ;;
            hetzner)                virt_name="Hetzner Cloud" ;;
            vultr)                  virt_name="Vultr" ;;
            oci)                    virt_name="Oracle Cloud" ;;
            ovh)                    virt_name="OVHcloud" ;;
            scaleway)               virt_name="Scaleway" ;;
            upcloud)                virt_name="UpCloud" ;;
            alibaba)                virt_name="Alibaba Cloud" ;;
            tencent)                virt_name="Tencent Cloud" ;;

            # --- Mainframe / Specialized ---
            zvm)                    virt_name="IBM z/VM" ;;
            powervm)                virt_name="IBM PowerVM" ;;
            uml)                    virt_name="User-Mode Linux" ;;
            acrn)                   virt_name="ACRN Hypervisor" ;;
            qnx)                    virt_name="QNX Hypervisor" ;;

            # --- Unknown (show raw value) ---
            *)                      virt_name="$detected_virt" ;;
        esac
    fi

    # --- Cloud provider detection (hard block) ---
    # This runs independently of systemd-detect-virt because many cloud VMs
    # report generic hypervisor types (e.g., "kvm"). DMI strings reliably
    # identify the actual cloud provider.
    local cloud_provider=""
    cloud_provider=$(detect_cloud_provider) && {
        echo ""
        echo -e "${RED}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo -e "${RED}  CLOUD DEPLOYMENT DETECTED: ${cloud_provider}${NC}"
        echo -e "${RED}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo ""
        echo -e "  Spiral Pool is ${RED}NOT${NC} designed for cloud-based instances and cloud"
        echo -e "  deployments are ${RED}NOT supported${NC}."
        echo ""
        echo -e "  ${WHITE}Why cloud deployment is blocked:${NC}"
        echo ""
        echo -e "    ${YELLOW}1.${NC} You do not own the physical hardware or hypervisor layer"
        echo -e "    ${YELLOW}2.${NC} The cloud provider has unrestricted access to your server's"
        echo -e "       memory, disk, and network traffic — including private keys,"
        echo -e "       wallet credentials, and database contents"
        echo -e "    ${YELLOW}3.${NC} Cloud instances can be snapshotted, cloned, or inspected"
        echo -e "       by the hosting provider without your knowledge or consent"
        echo -e "    ${YELLOW}4.${NC} No guarantee of data confidentiality or physical security"
        echo -e "    ${YELLOW}5.${NC} Shared infrastructure exposes you to side-channel attacks"
        echo -e "       and noisy-neighbor resource contention"
        echo ""
        echo -e "  ${WHITE}Supported deployment targets:${NC}"
        echo ""
        echo -e "    - Bare metal servers under your physical control"
        echo -e "    - Virtual machines on hypervisors YOU own and operate"
        echo ""
        echo -e "  Cloud deployments receive ${RED}NO SUPPORT${NC}. Issues arising from"
        echo -e "  cloud-hosted installations will not be investigated."
        echo ""
        echo -e "  See WARNINGS.md for complete details."
        echo ""
        echo -e "${RED}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo ""
        log_error "Cloud deployment detected (${cloud_provider}). Installation aborted."
        log_error "Spiral Pool requires operator-controlled infrastructure."
        log_error "See WARNINGS.md and README.md for supported deployment targets."
        exit 1
    }

    # --- ARM architecture detection (warning, not a hard block) ---
    local arm_info=""
    arm_info=$(detect_arm_architecture) && {
        echo ""
        echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo -e "${YELLOW}  ARM ARCHITECTURE DETECTED: ${arm_info}${NC}"
        echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo ""
        echo -e "  Spiral Pool has ${YELLOW}NOT been tested${NC} on ARM architecture."
        echo ""
        echo -e "  ${WHITE}What this means:${NC}"
        echo ""
        echo -e "    - ARM64 (aarch64) binaries will be downloaded where available"
        echo -e "    - 11 of 12 coins have official arm64 binaries upstream"
        echo -e "    - ${YELLOW}Fractal Bitcoin (FBTC) has NO arm64 binary${NC} and will be skipped"
        echo -e "    - Go cross-compilation and binary compatibility are not verified"
        echo -e "    - Performance characteristics are unknown on ARM hardware"
        echo ""
        echo -e "  ${WHITE}Supported architecture:${NC} x86_64 (amd64) on Ubuntu 24.04 LTS"
        echo ""
        echo -e "  ARM deployments are ${YELLOW}NOT supported${NC} and issues arising from"
        echo -e "  ARM-based installations may not be investigated."
        echo ""
        echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo ""
        echo -e "  Do you want to continue anyway? This is ${YELLOW}unsupported${NC}."
        echo ""
        echo -e "  Continue at your own risk? [y/N]: \c"
        read -r confirm_arm
        confirm_arm="${confirm_arm:-N}"

        if [[ ! "$confirm_arm" =~ ^[Yy]$ ]]; then
            log_error "ARM architecture detected (${arm_info}). Installation aborted by user."
            exit 1
        fi
        echo ""
        log_warn "Proceeding with unsupported ARM architecture (${arm_info})."
        echo ""
    }

    # Show detection result
    if [[ "$is_vm" == "true" ]]; then
        echo ""
        echo -e "  ${GREEN}Detected:${NC} Virtual Machine ($virt_name)"
        echo ""
        echo -e "Is this correct? [Y/n]: \c"
        read -r confirm_vm
        confirm_vm="${confirm_vm:-Y}"

        if [[ "$confirm_vm" =~ ^[Yy]$ ]]; then
            # VM - native installation only
            select_vm_deployment_method
            echo ""
            return
        fi
        echo ""
        echo -e "${DIM}Falling back to manual selection...${NC}"
        echo ""
    else
        echo ""
        echo -e "  ${GREEN}Detected:${NC} Physical Server (Bare Metal)"
        echo ""
        echo -e "Is this correct? [Y/n]: \c"
        read -r confirm_bm
        confirm_bm="${confirm_bm:-Y}"

        if [[ "$confirm_bm" =~ ^[Yy]$ ]]; then
            # Bare metal - native installation (best performance, no container overhead)
            select_baremetal_deployment_method
            return
        fi
        echo ""
        echo -e "${DIM}Falling back to manual selection...${NC}"
        echo ""
    fi

    # Manual selection fallback
    echo -e "${WHITE}What type of hardware are you running on?${NC}"
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${GREEN}1)${NC} ${WHITE}Bare Metal Server${NC}"
    echo ""
    echo -e "     Physical server with direct hardware access"
    echo -e "     Examples: Dell PowerEdge, HP ProLiant, custom build"
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${GREEN}2)${NC} ${WHITE}Virtual Machine${NC}"
    echo ""
    echo -e "     VM running on any hypervisor (VirtualBox, VMware, Hyper-V, Proxmox, KVM, Xen, Parallels, etc.)"
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""

    while true; do
        prompt_input "Enter choice (1 or 2): "; read hw_choice
        case $hw_choice in
            1)
                # Bare metal - let user choose native or Docker
                select_baremetal_deployment_method
                break
                ;;
            2)
                # VM - native installation only (Docker not supported in VMs)
                select_vm_deployment_method
                break
                ;;
            *)
                echo -e "  ${RED}Please enter 1 or 2${NC}"
                ;;
        esac
    done
    echo ""
}

select_baremetal_deployment_method() {
    # Bare metal defaults to native installation for best performance
    # Docker is available as an opt-in for users who specifically want containerized deployment
    echo ""
    log_step "Bare Metal Installation"

    DEPLOY_METHOD="vm-native"
    log "Selected: Bare Metal Native Installation"

    echo ""
    echo -e "${WHITE}Bare metal installations use native deployment for best performance.${NC}"
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${WHITE}What this means:${NC}"
    echo ""
    echo -e "     • All components installed directly on the server"
    echo -e "     • Maximum performance - no container overhead"
    echo -e "     • Direct hardware access with zero I/O penalty"
    echo -e "     • Full control over all services"
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${GREEN}✓${NC} Will install all components directly on this server"
    echo ""
    echo -e "  ${DIM}Want Docker containers instead? (Not recommended - adds I/O overhead)${NC}"
    echo -e "  ${DIM}Use: cd docker && docker compose up  (see DOCKER_GUIDE.md)${NC}"
    echo ""
}

select_vm_deployment_method() {
    # VMs now only support native installation (no Docker option)
    # Docker within a VM causes double virtualization overhead and networking issues
    echo ""
    log_step "VM Native Installation"

    DEPLOY_METHOD="vm-native"
    log "Selected: VM Native Installation"

    echo ""
    echo -e "${WHITE}Virtual Machine installations use native deployment for best performance.${NC}"
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${WHITE}What this means:${NC}"
    echo ""
    echo -e "     • All components installed directly on the VM"
    echo -e "     • Maximum performance - no container overhead"
    echo -e "     • Simple networking with bridged adapter"
    echo -e "     • Full control over all services"
    echo ""
    echo -e "  ${WHITE}Requirements:${NC}"
    echo ""
    echo -e "     • Ubuntu 24.04 LTS"
    echo -e "     • ${RED}BRIDGED networking adapter${NC} (NAT will NOT work)"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${GREEN}✓${NC} Will install all components directly on this VM"
    echo ""
    echo ""
    echo -e "  ${YELLOW}╔═══════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "  ${YELLOW}║  CRITICAL: Ensure your VM uses BRIDGED networking!                ║${NC}"
    echo -e "  ${YELLOW}║                                                                   ║${NC}"
    echo -e "  ${YELLOW}║  NAT networking will NOT work - miners cannot reach the pool.     ║${NC}"
    echo -e "  ${YELLOW}║                                                                   ║${NC}"
    echo -e "  ${YELLOW}║  VirtualBox:  Settings → Network → Bridged Adapter                ║${NC}"
    echo -e "  ${YELLOW}║  VMware:      VM Settings → Network → Bridged                     ║${NC}"
    echo -e "  ${YELLOW}║  Hyper-V:     Settings → Network → External Switch                ║${NC}"
    echo -e "  ${YELLOW}║  Proxmox:     VM → Hardware → Network → Bridge (vmbr0)            ║${NC}"
    echo -e "  ${YELLOW}║  Parallels:   Configuration → Network → Bridged                   ║${NC}"
    echo -e "  ${YELLOW}║  KVM/libvirt: Network → Bridge or macvtap                         ║${NC}"
    echo -e "  ${YELLOW}╚═══════════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    prompt_input "Press Enter to confirm your VM uses bridged networking..."; read
}

