# DOCKER DEPLOYMENT FUNCTIONS
# ═══════════════════════════════════════════════════════════════════════════════

install_docker() {
    log_step "Installing Docker"

    # Check if Docker is already installed
    if command -v docker &>/dev/null; then
        log_success "Docker is already installed"
        docker --version
    else
        log "Installing Docker Engine..."

        # Remove old versions if any
        sudo apt-get remove -y docker docker-engine docker.io containerd runc 2>/dev/null || true

        # Install prerequisites
        sudo apt-get update
        sudo apt-get install -y \
            ca-certificates \
            curl \
            gnupg \
            lsb-release

        # Add Docker's official GPG key
        sudo mkdir -p /etc/apt/keyrings
        curl -fsSL https://download.docker.com/linux/ubuntu/gpg | sudo gpg --dearmor -o /etc/apt/keyrings/docker.gpg

        # Set up repository
        echo \
            "deb [arch=$(dpkg --print-architecture) signed-by=/etc/apt/keyrings/docker.gpg] https://download.docker.com/linux/ubuntu \
            $(lsb_release -cs) stable" | sudo tee /etc/apt/sources.list.d/docker.list > /dev/null

        # Install Docker Engine
        sudo apt-get update
        sudo apt-get install -y docker-ce docker-ce-cli containerd.io docker-buildx-plugin docker-compose-plugin

        # Start and enable Docker
        sudo systemctl start docker || { log_error "Failed to start Docker"; return 1; }
        sudo systemctl enable docker || true

        # Add current user to docker group (for non-root usage)
        sudo usermod -aG docker "$USER" 2>/dev/null || true

        log_success "Docker installed successfully"
    fi

    # Verify Docker Compose
    if docker compose version &>/dev/null; then
        log_success "Docker Compose is available"
        docker compose version
    else
        log_error "Docker Compose plugin not found"
        exit 1
    fi

    echo ""
}

collect_docker_configuration() {
    clear
    log_step "Docker Configuration"

    echo -e "${WHITE}Let's configure your Docker deployment...${NC}"
    echo ""

    # Pool address
    while true; do
        echo -e "Enter your ${GREEN}DigiByte wallet address${NC} (starts with D):"
        prompt_input "Address: "; read POOL_ADDRESS
        if [[ "$POOL_ADDRESS" =~ ^D[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
            break
        else
            echo -e "  ${RED}Invalid address format. DigiByte addresses start with 'D'${NC}"
        fi
    done
    echo ""

    # Generate strong passwords
    DB_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
    RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
    ADMIN_API_KEY=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
    GRAFANA_ADMIN_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
    METRICS_TOKEN=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)

    log_success "Generated secure passwords for database, RPC, admin API, Grafana, and metrics"

    # Optional: Discord webhook
    echo -e "${WHITE}Optional: Enter Discord webhook URL for notifications${NC}"
    echo -e "${WHITE}(press Enter to skip):${NC}"
    prompt_input "Discord Webhook: "; read DISCORD_WEBHOOK_URL
    echo ""

    # Optional: Telegram
    echo -e "${WHITE}Optional: Enter Telegram bot token for notifications${NC}"
    echo -e "${WHITE}(press Enter to skip):${NC}"
    prompt_input "Telegram Bot Token: "; read TELEGRAM_BOT_TOKEN

    if [[ -n "$TELEGRAM_BOT_TOKEN" ]]; then
        prompt_input "Telegram Chat ID: "; read TELEGRAM_CHAT_ID
    fi
    echo ""

    # Optional: XMPP
    echo -e "${WHITE}Optional: Enter XMPP Bot JID for notifications${NC}"
    echo -e "${WHITE}(press Enter to skip):${NC}"
    prompt_input "XMPP Bot JID: "; read XMPP_JID

    if [[ -n "$XMPP_JID" ]]; then
        prompt_input "XMPP Bot Password: "; read -s XMPP_PASSWORD; echo ""
        prompt_input "Recipient JID: "; read XMPP_RECIPIENT
        prompt_input "Is recipient a MUC room? (y/N): "; read xmpp_muc_yn
        [[ "$xmpp_muc_yn" =~ ^[Yy] ]] && XMPP_MUC="true" || XMPP_MUC="false"
        XMPP_USE_TLS="true"
    fi
    echo ""

    # Expected hashrate
    echo -e "${WHITE}Enter expected fleet hashrate in TH/s${NC}"
    echo -e "${WHITE}(for efficiency reporting, default: 100):${NC}"
    prompt_input "Expected TH/s [100]: "; read EXPECTED_FLEET_THS
    EXPECTED_FLEET_THS=${EXPECTED_FLEET_THS:-100}
    echo ""

    # Coinbase text
    echo -e "${WHITE}Enter coinbase text (appears in mined blocks, max 40 chars)${NC}"
    echo -e "${WHITE}(default: Mined by Spiral Pool):${NC}"
    prompt_input "Coinbase text [Mined by Spiral Pool]: "; read COINBASE_TEXT
    COINBASE_TEXT=${COINBASE_TEXT:-"Mined by Spiral Pool"}
    echo ""

    # Block celebration settings
    echo -e "${WHITE}Block Celebration Settings${NC}"
    echo -e "${WHITE}When a block is found, display a celebration message on miner screens?${NC}"
    echo -e "${WHITE}(Broadcasts to all miners + triggers Avalon LED celebration)${NC}"
    echo ""
    prompt_input "Enable celebration? [Y/n]: "; read CELEBRATION_ENABLED
    if [[ "$CELEBRATION_ENABLED" =~ ^[Nn]$ ]]; then
        CELEBRATION_ENABLED="false"
        CELEBRATION_HOURS="2"
    else
        CELEBRATION_ENABLED="true"
        echo ""
        echo -e "${WHITE}How long should periodic celebration messages display? (default: 2 hours)${NC}"
        prompt_input "Celebration hours [2]: "; read CELEBRATION_HOURS
        CELEBRATION_HOURS=${CELEBRATION_HOURS:-2}
        # Validate numeric input
        if ! [[ "$CELEBRATION_HOURS" =~ ^[0-9]+$ ]]; then
            log_warn "Invalid input '$CELEBRATION_HOURS', using default: 2 hours"
            CELEBRATION_HOURS=2
        fi
    fi
    echo ""

    log_success "Docker configuration complete"
}

