    echo ""

    # Optional: Telegram
    echo -e "${WHITE}Optional: Enter Telegram bot token for notifications${NC}"
    echo -e "${WHITE}(press Enter to skip):${NC}"
    prompt_input "Telegram Bot Token: "; read TELEGRAM_BOT_TOKEN

    if [[ -n "$TELEGRAM_BOT_TOKEN" ]]; then
        prompt_input "Telegram Chat ID: "; read TELEGRAM_CHAT_ID
    fi
    echo ""

    # Optional: XMPP
    echo -e "${WHITE}Optional: Enter XMPP Bot JID for notifications${NC}"
    echo -e "${WHITE}(press Enter to skip):${NC}"
    prompt_input "XMPP Bot JID: "; read XMPP_JID

    if [[ -n "$XMPP_JID" ]]; then
        prompt_input "XMPP Bot Password: "; read -s XMPP_PASSWORD; echo ""
        prompt_input "Recipient JID: "; read XMPP_RECIPIENT
        prompt_input "Is recipient a MUC room? (y/N): "; read xmpp_muc_yn
        [[ "$xmpp_muc_yn" =~ ^[Yy] ]] && XMPP_MUC="true" || XMPP_MUC="false"
        XMPP_USE_TLS="true"
    fi
    echo ""

    # Expected hashrate
    echo -e "${WHITE}Enter expected fleet hashrate in TH/s${NC}"
    echo -e "${WHITE}(for efficiency reporting, default: 100):${NC}"
    prompt_input "Expected TH/s [100]: "; read EXPECTED_FLEET_THS
    EXPECTED_FLEET_THS=${EXPECTED_FLEET_THS:-100}
    echo ""

    # Coinbase text
    echo -e "${WHITE}Enter coinbase text (appears in mined blocks, max 40 chars)${NC}"
    echo -e "${WHITE}(default: Mined by Spiral Pool):${NC}"
    prompt_input "Coinbase text [Mined by Spiral Pool]: "; read COINBASE_TEXT
    COINBASE_TEXT=${COINBASE_TEXT:-"Mined by Spiral Pool"}
    echo ""

    # Block celebration settings
    echo -e "${WHITE}Block Celebration Settings${NC}"
    echo -e "${WHITE}When a block is found, display a celebration message on miner screens?${NC}"
    echo -e "${WHITE}(Broadcasts to all miners + triggers Avalon LED celebration)${NC}"
    echo ""
    prompt_input "Enable celebration? [Y/n]: "; read CELEBRATION_ENABLED
    if [[ "$CELEBRATION_ENABLED" =~ ^[Nn]$ ]]; then
        CELEBRATION_ENABLED="false"
        CELEBRATION_HOURS="2"
    else
        CELEBRATION_ENABLED="true"
        echo ""
        echo -e "${WHITE}How long should periodic celebration messages display? (default: 2 hours)${NC}"
        prompt_input "Celebration hours [2]: "; read CELEBRATION_HOURS
        CELEBRATION_HOURS=${CELEBRATION_HOURS:-2}
        # Validate numeric input
        if ! [[ "$CELEBRATION_HOURS" =~ ^[0-9]+$ ]]; then
            log_warn "Invalid input '$CELEBRATION_HOURS', using default: 2 hours"
            CELEBRATION_HOURS=2
        fi
    fi
    echo ""

    log_success "Docker multi-coin configuration complete"
}

collect_docker_coin_addresses() {
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo -e "${WHITE}  WALLET ADDRESSES${NC}"
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""

    # DGB Address
    if [[ "$ENABLE_DGB" == "true" ]]; then
        echo -e "${WHITE}💎 DigiByte Wallet Address${NC}"
        echo -e "${CYAN}   ─────────────────────────${NC}"
        echo -e "   Addresses start with ${GREEN}D${NC} or ${GREEN}S${NC} (26-35 chars)"
        echo ""
        while true; do
            prompt_input "DGB Address: "; read DGB_POOL_ADDRESS
            if validate_dgb_address "$DGB_POOL_ADDRESS"; then
                log_success "Valid DGB address"
                break
            else
                echo -e "  ${RED}Invalid DGB address. Must start with D or S.${NC}"
            fi
        done
        echo ""
    fi

    # BTC Address
    if [[ "$ENABLE_BTC" == "true" ]]; then
        echo -e "${WHITE}🟠 Bitcoin Wallet Address${NC}"
        echo -e "${CYAN}   ─────────────────────────${NC}"
        echo -e "   Supported formats:"
        echo -e "   • Legacy:      ${GREEN}1${NC}... or ${GREEN}3${NC}... (26-35 chars)"
        echo -e "   • Native:      ${GREEN}bc1q${NC}... (42-62 chars)"
        echo -e "   ${YELLOW}Note: Taproot (bc1p) not yet supported${NC}"
        echo ""
        while true; do
            prompt_input "BTC Address: "; read BTC_POOL_ADDRESS
            if [[ "$BTC_POOL_ADDRESS" =~ ^(1|3)[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]] || \
               [[ "$BTC_POOL_ADDRESS" =~ ^bc1q[a-z0-9]{38,58}$ ]]; then
                log_success "Valid BTC address"
                break
            elif [[ "$BTC_POOL_ADDRESS" =~ ^bc1p[a-z0-9]{58}$ ]]; then
                echo -e "  ${RED}Taproot (bc1p) not yet supported. Use bc1q, 1..., or 3...${NC}"
            else
                echo -e "  ${RED}Invalid BTC address format.${NC}"
            fi
        done
        echo ""
    fi

    # BCH Address
    if [[ "$ENABLE_BCH" == "true" ]]; then
        echo -e "${WHITE}🟢 Bitcoin Cash Wallet Address${NC}"
        echo -e "${CYAN}   ──────────────────────────────${NC}"
        echo -e "   Supported formats:"
        echo -e "   • CashAddr:    ${GREEN}bitcoincash:q${NC}... or just ${GREEN}q${NC}..."
        echo -e "   • Legacy:      ${GREEN}1${NC}... (26-35 chars)"
        echo ""
        while true; do
            prompt_input "BCH Address: "; read BCH_POOL_ADDRESS
            if [[ "$BCH_POOL_ADDRESS" =~ ^(bitcoincash:)?[qp][a-z0-9]{41}$ ]] || \
               [[ "$BCH_POOL_ADDRESS" =~ ^(1|3)[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                log_success "Valid BCH address"
                break
            else
                echo -e "  ${RED}Invalid BCH address format.${NC}"
            fi
        done
        echo ""
    fi

    # BC2 Address
    if [[ "$ENABLE_BC2" == "true" ]]; then
        echo -e "${WHITE}🔵 Bitcoin II Wallet Address${NC}"
        echo -e "${CYAN}   ────────────────────────────${NC}"
        echo -e "${YELLOW}  WARNING: BC2 uses same address format as BTC (bc1q..., 1..., 3...)${NC}"
        echo -e "${YELLOW}  Ensure this address is from a Bitcoin II wallet, NOT Bitcoin!${NC}"
        echo ""
        while true; do
            prompt_input "BC2 Address: "; read BC2_POOL_ADDRESS
            if [[ "$BC2_POOL_ADDRESS" =~ ^bc1q[a-z0-9]{38,58}$ ]] || \
               [[ "$BC2_POOL_ADDRESS" =~ ^(1|3)[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                log_success "Valid BC2 address"
                break
            elif [[ "$BC2_POOL_ADDRESS" =~ ^bc1p[a-z0-9]{58}$ ]]; then
                echo -e "  ${RED}Taproot (bc1p) not yet supported. Use bc1q, 1..., or 3...${NC}"
            else
                echo -e "  ${RED}Invalid BC2 address format.${NC}"
            fi
        done
        echo ""
    fi

    # NMC Address
    if [[ "$ENABLE_NMC" == "true" ]]; then
        echo -e "${WHITE}🔷 Namecoin Wallet Address${NC}"
        echo -e "${CYAN}   ──────────────────────────${NC}"
        echo -e "   Addresses start with ${GREEN}N${NC}, ${GREEN}M${NC}, ${GREEN}6${NC}, or ${GREEN}nc1q${NC}"
        echo ""
        while true; do
            prompt_input "NMC Address: "; read NMC_POOL_ADDRESS
            if [[ "$NMC_POOL_ADDRESS" =~ ^[NM6][a-km-zA-HJ-NP-Z1-9]{25,34}$ ]] || \
               [[ "$NMC_POOL_ADDRESS" =~ ^nc1q[a-z0-9]{38,58}$ ]]; then
                log_success "Valid NMC address"
                break
            else
                echo -e "  ${RED}Invalid NMC address. Must start with N, M, 6, or nc1q.${NC}"
            fi
        done
        echo ""
    fi

    # SYS Address
    if [[ "$ENABLE_SYS" == "true" ]]; then
        echo -e "${WHITE}🟣 Syscoin Wallet Address${NC}"
        echo -e "${CYAN}   ──────────────────────────${NC}"
        echo -e "   Addresses start with ${GREEN}S${NC} or ${GREEN}sys1q${NC}"
        echo ""
        while true; do
            prompt_input "SYS Address: "; read SYS_POOL_ADDRESS
            if [[ "$SYS_POOL_ADDRESS" =~ ^S[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]] || \
               [[ "$SYS_POOL_ADDRESS" =~ ^sys1q[a-z0-9]{38,58}$ ]]; then
                log_success "Valid SYS address"
                break
            else
                echo -e "  ${RED}Invalid SYS address. Must start with S or sys1q.${NC}"
            fi
        done
        echo ""
    fi

    # XMY Address
    if [[ "$ENABLE_XMY" == "true" ]]; then
        echo -e "${WHITE}🔶 Myriad Wallet Address${NC}"
        echo -e "${CYAN}   ──────────────────────────${NC}"
        echo -e "   Addresses start with ${GREEN}M${NC}"
        echo ""
        while true; do
            prompt_input "XMY Address: "; read XMY_POOL_ADDRESS
            if [[ "$XMY_POOL_ADDRESS" =~ ^M[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                log_success "Valid XMY address"
                break
            else
                echo -e "  ${RED}Invalid XMY address. Must start with M.${NC}"
            fi
        done
        echo ""
    fi

    # FBTC Address
    if [[ "$ENABLE_FBTC" == "true" ]]; then
        echo -e "${WHITE}🟤 Fractal Bitcoin Wallet Address${NC}"
        echo -e "${CYAN}   ──────────────────────────────────${NC}"
        echo -e "   Addresses start with ${GREEN}1${NC} or ${GREEN}bc1q${NC}"
        echo ""
        while true; do
            prompt_input "FBTC Address: "; read FBTC_POOL_ADDRESS
            if [[ "$FBTC_POOL_ADDRESS" =~ ^((1|3)[a-km-zA-HJ-NP-Z1-9]{25,34}|bc1q[a-z0-9]{38,58})$ ]]; then
                log_success "Valid FBTC address"
                break
            else
                echo -e "  ${RED}Invalid FBTC address. Must start with 1, 3, or bc1q.${NC}"
            fi
        done
        echo ""
    fi

    # QBX Address
    if [[ "$ENABLE_QBX" == "true" ]]; then
        echo -e "${WHITE}⚛️ Q-BitX Wallet Address${NC}"
        echo -e "${CYAN}   ──────────────────────────${NC}"
        echo -e "   Addresses start with ${GREEN}M${NC} (P2PKH), ${GREEN}P${NC} (P2SH), or ${GREEN}pq${NC} (post-quantum)"
        echo ""
        while true; do
            prompt_input "QBX Address: "; read QBX_POOL_ADDRESS
            if [[ "$QBX_POOL_ADDRESS" =~ ^(M[a-km-zA-HJ-NP-Z1-9]{25,34}|P[a-km-zA-HJ-NP-Z1-9]{25,34}|pq[a-zA-Z0-9]{20,80})$ ]]; then
                log_success "Valid QBX address"
                break
            else
                echo -e "  ${RED}Invalid QBX address. Must start with M (P2PKH), P (P2SH), or pq (post-quantum).${NC}"
            fi
        done
        echo ""
    fi

    # LTC Address
    if [[ "$ENABLE_LTC" == "true" ]]; then
        echo -e "${WHITE}⚪ Litecoin Wallet Address${NC}"
        echo -e "${CYAN}   ──────────────────────────${NC}"
        echo -e "   Addresses start with ${GREEN}L${NC}, ${GREEN}M${NC}, ${GREEN}3${NC}, or ${GREEN}ltc1${NC}"
        echo ""
        while true; do
            prompt_input "LTC Address: "; read LTC_POOL_ADDRESS
            if [[ "$LTC_POOL_ADDRESS" =~ ^ltc1[a-z0-9]{39,59}$ ]] || \
               [[ "$LTC_POOL_ADDRESS" =~ ^[LM3][a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                log_success "Valid LTC address"
                break
            else
                echo -e "  ${RED}Invalid LTC address.${NC}"
            fi
        done
        echo ""
    fi

    # DOGE Address
    if [[ "$ENABLE_DOGE" == "true" ]]; then
        echo -e "${WHITE}🐕 Dogecoin Wallet Address${NC}"
        echo -e "${CYAN}   ──────────────────────────${NC}"
        echo -e "   Addresses start with ${GREEN}D${NC}"
        echo ""
        while true; do
            prompt_input "DOGE Address: "; read DOGE_POOL_ADDRESS
            if [[ "$DOGE_POOL_ADDRESS" =~ ^D[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                log_success "Valid DOGE address"
                break
            else
                echo -e "  ${RED}Invalid DOGE address. Must start with D.${NC}"
            fi
        done
        echo ""
    fi

    # PEP Address
    if [[ "$ENABLE_PEP" == "true" ]]; then
        echo -e "${WHITE}🐸 PepeCoin Wallet Address${NC}"
        echo -e "${CYAN}   ──────────────────────────${NC}"
        echo -e "   Addresses start with ${GREEN}P${NC}"
        echo ""
        while true; do
            prompt_input "PEP Address: "; read PEP_POOL_ADDRESS
            if [[ "$PEP_POOL_ADDRESS" =~ ^P[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                log_success "Valid PEP address"
                break
