            fi
        done
        echo ""
    fi
}

detect_existing_docker_install() {
    local DOCKER_DIR="$SCRIPT_DIR/docker"
    local ENV_FILE="$DOCKER_DIR/.env"

    if [[ -f "$ENV_FILE" ]]; then
        log "Detected existing Docker installation"

        # Parse existing configuration - SHA256d coins
        EXISTING_ENABLE_DGB=$(grep -oP '^ENABLE_DGB=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        EXISTING_ENABLE_BTC=$(grep -oP '^ENABLE_BTC=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        EXISTING_ENABLE_BCH=$(grep -oP '^ENABLE_BCH=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        EXISTING_ENABLE_BC2=$(grep -oP '^ENABLE_BC2=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        # Scrypt coins
        EXISTING_ENABLE_LTC=$(grep -oP '^ENABLE_LTC=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        EXISTING_ENABLE_DOGE=$(grep -oP '^ENABLE_DOGE=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        EXISTING_ENABLE_DGB_SCRYPT=$(grep -oP '^ENABLE_DGB_SCRYPT=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        # Additional Scrypt coins (PEP/CAT)
        EXISTING_ENABLE_PEP=$(grep -oP '^ENABLE_PEP=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        EXISTING_ENABLE_CAT=$(grep -oP '^ENABLE_CAT=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        # Merge-minable SHA256d coins (AuxPoW)
        EXISTING_ENABLE_NMC=$(grep -oP '^ENABLE_NMC=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        EXISTING_ENABLE_SYS=$(grep -oP '^ENABLE_SYS=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        EXISTING_ENABLE_XMY=$(grep -oP '^ENABLE_XMY=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        EXISTING_ENABLE_FBTC=$(grep -oP '^ENABLE_FBTC=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
        EXISTING_ENABLE_QBX=$(grep -oP '^ENABLE_QBX=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")

        # Build list of existing coins
        local existing_coins=""
        [[ "$EXISTING_ENABLE_DGB" == "true" ]] && existing_coins="DGB "
        [[ "$EXISTING_ENABLE_BTC" == "true" ]] && existing_coins="${existing_coins}BTC "
        [[ "$EXISTING_ENABLE_BCH" == "true" ]] && existing_coins="${existing_coins}BCH "
        [[ "$EXISTING_ENABLE_BC2" == "true" ]] && existing_coins="${existing_coins}BC2 "
        [[ "$EXISTING_ENABLE_LTC" == "true" ]] && existing_coins="${existing_coins}LTC "
        [[ "$EXISTING_ENABLE_DOGE" == "true" ]] && existing_coins="${existing_coins}DOGE "
        [[ "$EXISTING_ENABLE_DGB_SCRYPT" == "true" ]] && existing_coins="${existing_coins}DGB-SCRYPT "
        [[ "$EXISTING_ENABLE_PEP" == "true" ]] && existing_coins="${existing_coins}PEP "
        [[ "$EXISTING_ENABLE_CAT" == "true" ]] && existing_coins="${existing_coins}CAT "
        [[ "$EXISTING_ENABLE_NMC" == "true" ]] && existing_coins="${existing_coins}NMC "
        [[ "$EXISTING_ENABLE_SYS" == "true" ]] && existing_coins="${existing_coins}SYS "
        [[ "$EXISTING_ENABLE_XMY" == "true" ]] && existing_coins="${existing_coins}XMY "
        [[ "$EXISTING_ENABLE_FBTC" == "true" ]] && existing_coins="${existing_coins}FBTC "
        [[ "$EXISTING_ENABLE_QBX" == "true" ]] && existing_coins="${existing_coins}QBX "

        if [[ -n "$existing_coins" ]]; then
            echo ""
            echo -e "${YELLOW}═══════════════════════════════════════════════════════════════════════${NC}"
            echo -e "${WHITE}  EXISTING DOCKER INSTALLATION DETECTED${NC}"
            echo -e "${YELLOW}═══════════════════════════════════════════════════════════════════════${NC}"
            echo ""
            echo -e "  Currently enabled coins: ${GREEN}${existing_coins}${NC}"
            echo ""
            echo -e "  ${WHITE}Options:${NC}"
            echo -e "    ${GREEN}1)${NC} Add coins to existing installation"
            echo -e "    ${GREEN}2)${NC} Fresh install (will overwrite configuration)"
            echo ""

            while true; do
                prompt_input "Choose [1] or [2]: "; read upgrade_choice
                case "$upgrade_choice" in
                    1)
                        DOCKER_UPGRADE_MODE="add"
                        log "Upgrade mode: Adding coins to existing installation"

                        # Preserve existing passwords - SHA256d coins
                        EXISTING_DB_PASSWORD=$(grep -oP '^DB_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_DGB" == "true" ]] && DGB_RPC_PASSWORD=$(grep -oP '^DGB_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_BTC" == "true" ]] && BTC_RPC_PASSWORD=$(grep -oP '^BTC_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_BCH" == "true" ]] && BCH_RPC_PASSWORD=$(grep -oP '^BCH_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_BC2" == "true" ]] && BC2_RPC_PASSWORD=$(grep -oP '^BC2_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        # Scrypt coins
                        [[ "$EXISTING_ENABLE_LTC" == "true" ]] && LTC_RPC_PASSWORD=$(grep -oP '^LTC_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_DOGE" == "true" ]] && DOGE_RPC_PASSWORD=$(grep -oP '^DOGE_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        # Additional Scrypt coins (PEP/CAT)
                        [[ "$EXISTING_ENABLE_PEP" == "true" ]] && PEP_RPC_PASSWORD=$(grep -oP '^PEP_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_CAT" == "true" ]] && CAT_RPC_PASSWORD=$(grep -oP '^CAT_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        # Merge-minable SHA256d coins (AuxPoW)
                        [[ "$EXISTING_ENABLE_NMC" == "true" ]] && NMC_RPC_PASSWORD=$(grep -oP '^NMC_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_SYS" == "true" ]] && SYS_RPC_PASSWORD=$(grep -oP '^SYS_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_XMY" == "true" ]] && XMY_RPC_PASSWORD=$(grep -oP '^XMY_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_FBTC" == "true" ]] && FBTC_RPC_PASSWORD=$(grep -oP '^FBTC_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_QBX" == "true" ]] && QBX_RPC_PASSWORD=$(grep -oP '^QBX_RPC_PASSWORD=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")

                        # Preserve existing addresses - SHA256d coins
                        [[ "$EXISTING_ENABLE_DGB" == "true" ]] && DGB_POOL_ADDRESS=$(grep -oP '^DGB_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_BTC" == "true" ]] && BTC_POOL_ADDRESS=$(grep -oP '^BTC_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_BCH" == "true" ]] && BCH_POOL_ADDRESS=$(grep -oP '^BCH_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_BC2" == "true" ]] && BC2_POOL_ADDRESS=$(grep -oP '^BC2_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        # Scrypt coins
                        [[ "$EXISTING_ENABLE_LTC" == "true" ]] && LTC_POOL_ADDRESS=$(grep -oP '^LTC_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_DOGE" == "true" ]] && DOGE_POOL_ADDRESS=$(grep -oP '^DOGE_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        # DGB-SCRYPT uses same node as DGB but can have its own pool address
                        [[ "$EXISTING_ENABLE_DGB_SCRYPT" == "true" ]] && DGB_SCRYPT_ADDRESS=$(grep -oP '^DGB_SCRYPT_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        # Additional Scrypt coins (PEP/CAT) - check both old (_ADDRESS) and new (_POOL_ADDRESS) names
                        [[ "$EXISTING_ENABLE_PEP" == "true" ]] && PEP_POOL_ADDRESS=$(grep -oP '^PEP_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || grep -oP '^PEP_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_CAT" == "true" ]] && CAT_POOL_ADDRESS=$(grep -oP '^CAT_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || grep -oP '^CAT_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        # Merge-minable SHA256d coins (AuxPoW)
                        [[ "$EXISTING_ENABLE_NMC" == "true" ]] && NMC_POOL_ADDRESS=$(grep -oP '^NMC_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_SYS" == "true" ]] && SYS_POOL_ADDRESS=$(grep -oP '^SYS_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_XMY" == "true" ]] && XMY_POOL_ADDRESS=$(grep -oP '^XMY_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_FBTC" == "true" ]] && FBTC_POOL_ADDRESS=$(grep -oP '^FBTC_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        [[ "$EXISTING_ENABLE_QBX" == "true" ]] && QBX_POOL_ADDRESS=$(grep -oP '^QBX_POOL_ADDRESS=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")

                        # Use existing DB password if available
                        if [[ -n "$EXISTING_DB_PASSWORD" ]]; then
                            DB_PASSWORD="$EXISTING_DB_PASSWORD"
                        fi

                        # Preserve admin API key from existing .env
                        local existing_api_key
                        existing_api_key=$(grep -oP '^ADMIN_API_KEY=\K.+$' "$ENV_FILE" 2>/dev/null || echo "")
                        if [[ -n "$existing_api_key" ]]; then
                            ADMIN_API_KEY="$existing_api_key"
                        fi

                        return 0
                        ;;
                    2)
                        DOCKER_UPGRADE_MODE="fresh"
                        log "Fresh install selected"
                        return 0
                        ;;
                    *)
                        echo -e "  ${RED}Please enter 1 or 2${NC}"
                        ;;
                esac
            done
        fi
    fi

    DOCKER_UPGRADE_MODE="fresh"
    return 0
}

merge_docker_configuration() {
    # Merge newly selected coins with existing configuration

    # If adding coins, only ask for addresses of NEW coins
    if [[ "$DOCKER_UPGRADE_MODE" == "add" ]]; then
        echo ""
        echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo -e "${WHITE}  ADDING NEW COINS${NC}"
        echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo ""

        # Only collect addresses for NEW coins (not already configured)
        if [[ "$ENABLE_DGB" == "true" && "$EXISTING_ENABLE_DGB" != "true" ]]; then
            echo -e "${WHITE}💎 DigiByte Wallet Address${NC}"
            echo -e "${CYAN}   ─────────────────────────${NC}"
            while true; do
                prompt_input "DGB Address: "; read DGB_POOL_ADDRESS
                if validate_dgb_address "$DGB_POOL_ADDRESS"; then
                    log_success "Valid DGB address"
                    break
                else
                    echo -e "  ${RED}Invalid DGB address.${NC}"
                fi
            done
            DGB_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        if [[ "$ENABLE_BTC" == "true" && "$EXISTING_ENABLE_BTC" != "true" ]]; then
            echo -e "${WHITE}🟠 Bitcoin Wallet Address${NC}"
            echo -e "${CYAN}   ─────────────────────────${NC}"
            while true; do
                prompt_input "BTC Address: "; read BTC_POOL_ADDRESS
                if [[ "$BTC_POOL_ADDRESS" =~ ^(1|3)[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]] || \
                   [[ "$BTC_POOL_ADDRESS" =~ ^bc1q[a-z0-9]{38,58}$ ]]; then
                    log_success "Valid BTC address"
                    break
                else
                    echo -e "  ${RED}Invalid BTC address.${NC}"
                fi
            done
            BTC_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        if [[ "$ENABLE_BCH" == "true" && "$EXISTING_ENABLE_BCH" != "true" ]]; then
            echo -e "${WHITE}🟢 Bitcoin Cash Wallet Address${NC}"
            echo -e "${CYAN}   ──────────────────────────────${NC}"
            while true; do
                prompt_input "BCH Address: "; read BCH_POOL_ADDRESS
                if [[ "$BCH_POOL_ADDRESS" =~ ^(bitcoincash:)?[qp][a-z0-9]{41}$ ]] || \
                   [[ "$BCH_POOL_ADDRESS" =~ ^(1|3)[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                    log_success "Valid BCH address"
                    break
                else
                    echo -e "  ${RED}Invalid BCH address.${NC}"
                fi
            done
            BCH_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        if [[ "$ENABLE_BC2" == "true" && "$EXISTING_ENABLE_BC2" != "true" ]]; then
            echo -e "${WHITE}🟢 Bitcoin II Wallet Address${NC}"
            echo -e "${CYAN}   ────────────────────────────${NC}"
            echo -e "${YELLOW}  WARNING: BC2 uses same address format as BTC (bc1q..., 1..., 3...)${NC}"
            echo -e "${YELLOW}  Ensure this address is from a Bitcoin II wallet, NOT Bitcoin!${NC}"
            while true; do
                prompt_input "BC2 Address: "; read BC2_POOL_ADDRESS
                # BC2 uses identical address format to BTC
                if [[ "$BC2_POOL_ADDRESS" =~ ^bc1q[a-z0-9]{38,58}$ ]] || \
                   [[ "$BC2_POOL_ADDRESS" =~ ^(1|3)[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                    log_success "Valid BC2 address format"
                    break
                elif [[ "$BC2_POOL_ADDRESS" =~ ^bc1p[a-z0-9]{58}$ ]]; then
                    echo -e "  ${RED}Taproot (bc1p) not yet supported. Use bc1q, 1..., or 3...${NC}"
                else
                    echo -e "  ${RED}Invalid BC2 address format.${NC}"
                fi
            done
            BC2_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        # Scrypt coins
        if [[ "$ENABLE_LTC" == "true" && "$EXISTING_ENABLE_LTC" != "true" ]]; then
            echo -e "${WHITE}⚪ Litecoin Wallet Address${NC}"
            echo -e "${CYAN}   ──────────────────────────${NC}"
            while true; do
                prompt_input "LTC Address: "; read LTC_POOL_ADDRESS
                if [[ "$LTC_POOL_ADDRESS" =~ ^ltc1[a-z0-9]{39,59}$ ]] || \
                   [[ "$LTC_POOL_ADDRESS" =~ ^[LM3][a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                    log_success "Valid LTC address"
                    break
                else
                    echo -e "  ${RED}Invalid LTC address.${NC}"
                fi
            done
            LTC_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        if [[ "$ENABLE_DOGE" == "true" && "$EXISTING_ENABLE_DOGE" != "true" ]]; then
            echo -e "${WHITE}🐕 Dogecoin Wallet Address${NC}"
            echo -e "${CYAN}   ───────────────────────────${NC}"
            while true; do
                prompt_input "DOGE Address: "; read DOGE_POOL_ADDRESS
                if [[ "$DOGE_POOL_ADDRESS" =~ ^D[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                    log_success "Valid DOGE address"
                    break
                else
                    echo -e "  ${RED}Invalid DOGE address.${NC}"
                fi
            done
            DOGE_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        # DGB-SCRYPT uses the same address as DGB (same blockchain)
        if [[ "$ENABLE_DGB_SCRYPT" == "true" && "$EXISTING_ENABLE_DGB_SCRYPT" != "true" ]]; then
            if [[ -z "$DGB_POOL_ADDRESS" && "$EXISTING_ENABLE_DGB" != "true" ]]; then
                echo -e "${WHITE}💎 DigiByte (Scrypt) Wallet Address${NC}"
                echo -e "${CYAN}   ───────────────────────────────────${NC}"
                echo -e "${YELLOW}  Note: Same address format as DGB SHA256d${NC}"
                while true; do
                    prompt_input "DGB Address: "; read DGB_POOL_ADDRESS
                    if validate_dgb_address "$DGB_POOL_ADDRESS"; then
                        log_success "Valid DGB address"
                        break
                    else
                        echo -e "  ${RED}Invalid DGB address.${NC}"
                    fi
                done
                echo ""
            fi
        fi

        # PepeCoin address (Scrypt fork)
        if [[ "$ENABLE_PEP" == "true" && "$EXISTING_ENABLE_PEP" != "true" ]]; then
            echo -e "${WHITE}🐸 PepeCoin Wallet Address${NC}"
            echo -e "${CYAN}   ───────────────────────────${NC}"
            echo -e "   Addresses start with ${GREEN}P${NC} (26-35 chars)"
            echo ""
            echo -e "   ${DIM}Create a wallet address using PepeCoin Core or another wallet.${NC}"
            echo -e "   ${DIM}See: https://github.com/pepecoinppc/pepecoin${NC}"
            echo ""
            while true; do
                prompt_input "PEP Address: "; read PEP_POOL_ADDRESS
                # PepeCoin P2PKH addresses start with P (version 0x37 = 55)
                if [[ "$PEP_POOL_ADDRESS" =~ ^P[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                    log_success "Valid PEP address"
                    break
                else
                    echo -e "  ${RED}Invalid PEP address. Must start with P.${NC}"
                fi
            done
            PEP_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        # Catcoin address
        if [[ "$ENABLE_CAT" == "true" && "$EXISTING_ENABLE_CAT" != "true" ]]; then
            echo -e "${WHITE}🐱 Catcoin Wallet Address${NC}"
            echo -e "${CYAN}   ──────────────────────────${NC}"
            echo -e "   Addresses start with ${GREEN}9${NC} (version byte 21 — cats have 9 lives)"
            echo ""
            echo -e "   ${DIM}Create a wallet address using Catcoin Core or another wallet.${NC}"
            echo -e "   ${DIM}See: https://github.com/CatcoinOfficial/CatcoinRelease${NC}"
            echo ""
            while true; do
                prompt_input "CAT Address: "; read CAT_POOL_ADDRESS
                # Catcoin P2PKH (version byte 21 → addresses start with 9)
                if [[ "$CAT_POOL_ADDRESS" =~ ^9[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                    log_success "Valid CAT address"
                    break
                else
                    echo -e "  ${RED}Invalid CAT address. Must start with 9.${NC}"
                fi
            done
            CAT_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        # AuxPoW merge-mining coins (SHA-256d)
        if [[ "$ENABLE_NMC" == "true" && "$EXISTING_ENABLE_NMC" != "true" ]]; then
            echo -e "${WHITE}🔷 Namecoin Wallet Address${NC}"
            echo -e "${CYAN}   ──────────────────────────${NC}"
            echo -e "   Addresses start with ${GREEN}N${NC}, ${GREEN}M${NC}, ${GREEN}6${NC}, or ${GREEN}nc1q${NC} (bech32)"
            echo ""
            while true; do
                prompt_input "NMC Address: "; read NMC_POOL_ADDRESS
                if [[ "$NMC_POOL_ADDRESS" =~ ^[NM6][a-km-zA-HJ-NP-Z1-9]{25,34}$ ]] || \
                   [[ "$NMC_POOL_ADDRESS" =~ ^nc1q[a-z0-9]{38,58}$ ]]; then
                    log_success "Valid NMC address"
                    break
                else
                    echo -e "  ${RED}Invalid NMC address. Must start with N, M, 6, or nc1q.${NC}"
                fi
            done
            NMC_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        if [[ "$ENABLE_SYS" == "true" && "$EXISTING_ENABLE_SYS" != "true" ]]; then
            echo -e "${WHITE}🟣 Syscoin Wallet Address${NC}"
            echo -e "${CYAN}   ──────────────────────────${NC}"
            echo -e "   Addresses start with ${GREEN}S${NC} or ${GREEN}sys1q${NC} (bech32)"
            echo ""
            while true; do
                prompt_input "SYS Address: "; read SYS_POOL_ADDRESS
                if [[ "$SYS_POOL_ADDRESS" =~ ^S[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]] || \
                   [[ "$SYS_POOL_ADDRESS" =~ ^sys1q[a-z0-9]{38,58}$ ]]; then
                    log_success "Valid SYS address"
                    break
                else
                    echo -e "  ${RED}Invalid SYS address. Must start with S or sys1q.${NC}"
                fi
            done
            SYS_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        if [[ "$ENABLE_XMY" == "true" && "$EXISTING_ENABLE_XMY" != "true" ]]; then
            echo -e "${WHITE}🔶 Myriad Wallet Address${NC}"
            echo -e "${CYAN}   ──────────────────────────${NC}"
            echo -e "   Addresses start with ${GREEN}M${NC}"
            echo ""
            while true; do
                prompt_input "XMY Address: "; read XMY_POOL_ADDRESS
                if [[ "$XMY_POOL_ADDRESS" =~ ^M[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                    log_success "Valid XMY address"
                    break
                else
                    echo -e "  ${RED}Invalid XMY address. Must start with M.${NC}"
                fi
            done
            XMY_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        if [[ "$ENABLE_FBTC" == "true" && "$EXISTING_ENABLE_FBTC" != "true" ]]; then
            echo -e "${WHITE}🟤 Fractal Bitcoin Wallet Address${NC}"
            echo -e "${CYAN}   ──────────────────────────────────${NC}"
            echo -e "   Addresses start with ${GREEN}1${NC} or ${GREEN}bc1q${NC} (uses BTC address format)"
            echo ""
            while true; do
                prompt_input "FBTC Address: "; read FBTC_POOL_ADDRESS
                if [[ "$FBTC_POOL_ADDRESS" =~ ^((1|3)[a-km-zA-HJ-NP-Z1-9]{25,34}|bc1q[a-z0-9]{38,58})$ ]]; then
                    log_success "Valid FBTC address"
                    break
                else
                    echo -e "  ${RED}Invalid FBTC address. Must start with 1, 3, or bc1q.${NC}"
                fi
            done
            FBTC_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        if [[ "$ENABLE_QBX" == "true" && "$EXISTING_ENABLE_QBX" != "true" ]]; then
            echo -e "${WHITE}⚛️ Q-BitX Wallet Address${NC}"
            echo -e "${CYAN}   ──────────────────────────${NC}"
            echo -e "   Addresses start with ${GREEN}M${NC} (P2PKH), ${GREEN}P${NC} (P2SH), or ${GREEN}pq${NC} (post-quantum)"
            echo ""
            while true; do
                prompt_input "QBX Address: "; read QBX_POOL_ADDRESS
                if [[ "$QBX_POOL_ADDRESS" =~ ^(M[a-km-zA-HJ-NP-Z1-9]{25,34}|P[a-km-zA-HJ-NP-Z1-9]{25,34}|pq[a-zA-Z0-9]{20,80})$ ]]; then
                    log_success "Valid QBX address format"
                    break
                else
                    echo -e "  ${RED}Invalid QBX address format.${NC}"
                fi
            done
            QBX_RPC_PASSWORD=$(openssl rand -base64 24 | tr -dc 'a-zA-Z0-9' | head -c 32)
            echo ""
        fi

        log_success "Coin configuration merged"
    fi
}

select_docker_compose_profile() {
    # Build per-coin --profile flags for Docker Compose
    # Each enabled coin gets its own --profile flag so the correct services activate.
    # Shared services (stratum, dashboard, postgres, etc.) list all individual coin
    # profiles, so they activate when ANY coin profile is used.
    DOCKER_PROFILE_ARGS=""
    local coin_list=""
    local coin_count=0

    # SHA-256d coins
    if [[ "$ENABLE_DGB" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile dgb"
        coin_list+="DGB "
        ((coin_count++)) || true
    fi
    if [[ "$ENABLE_BTC" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile btc"
        coin_list+="BTC "
        ((coin_count++)) || true
    fi
    if [[ "$ENABLE_BCH" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile bch"
        coin_list+="BCH "
        ((coin_count++)) || true
    fi
    if [[ "$ENABLE_BC2" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile bc2"
        coin_list+="BC2 "
        ((coin_count++)) || true
    fi
    if [[ "$ENABLE_NMC" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile nmc"
        coin_list+="NMC "
        ((coin_count++)) || true
    fi
    if [[ "$ENABLE_SYS" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile sys"
        coin_list+="SYS "
        ((coin_count++)) || true
    fi
    if [[ "$ENABLE_XMY" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile xmy"
        coin_list+="XMY "
        ((coin_count++)) || true
    fi
    if [[ "$ENABLE_FBTC" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile fbtc"
        coin_list+="FBTC "
        ((coin_count++)) || true
    fi
    if [[ "$ENABLE_QBX" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile qbx"
        coin_list+="QBX "
        ((coin_count++)) || true
    fi

    # Scrypt coins
    if [[ "$ENABLE_LTC" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile ltc"
        coin_list+="LTC "
        ((coin_count++)) || true
    fi
    if [[ "$ENABLE_DOGE" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile doge"
        coin_list+="DOGE "
        ((coin_count++)) || true
    fi
    if [[ "$ENABLE_DGB_SCRYPT" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile dgb-scrypt"
        coin_list+="DGB-SCRYPT "
        ((coin_count++)) || true
    fi
    if [[ "$ENABLE_PEP" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile pep"
        coin_list+="PEP "
        ((coin_count++)) || true
    fi
    if [[ "$ENABLE_CAT" == "true" ]]; then
        DOCKER_PROFILE_ARGS+=" --profile cat"
        coin_list+="CAT "
        ((coin_count++)) || true
    fi

    if [[ $coin_count -eq 0 ]]; then
        log_error "No coins enabled!"
        exit 1
    fi

    # Trim leading space from profile args
    DOCKER_PROFILE_ARGS="${DOCKER_PROFILE_ARGS# }"

    # Set display-friendly name (used in logs and credentials file)
    if [[ $coin_count -eq 1 ]]; then
        DOCKER_PROFILE="${coin_list% }"
    else
        DOCKER_PROFILE="multi-coin (${coin_count} coins: ${coin_list% })"
    fi

    log "Docker compose profile: $DOCKER_PROFILE"
    log "Docker compose args: $DOCKER_PROFILE_ARGS"
}

setup_docker_environment_multicoin() {
    log_step "Setting Up Multi-Coin Docker Environment"

    local DOCKER_DIR="$SCRIPT_DIR/docker"
    local CONFIG_DIR="$DOCKER_DIR/config"
    local DB_USER="spiralstratum"
    local DB_NAME="spiralstratum"

    # Create .env file for multi-coin
    log "Creating multi-coin .env configuration..."

    cat > "$DOCKER_DIR/.env" << EOF
# ╔════════════════════════════════════════════════════════════════════════════╗
# ║                SPIRAL POOL - MULTI-COIN DOCKER CONFIGURATION               ║
# ╚════════════════════════════════════════════════════════════════════════════╝
# Generated on $(date)

# ═══════════════════════════════════════════════════════════════════════════════
# COIN ENABLEMENT
# ═══════════════════════════════════════════════════════════════════════════════
# SHA256d coins
ENABLE_DGB=$ENABLE_DGB
ENABLE_BTC=$ENABLE_BTC
ENABLE_BCH=$ENABLE_BCH
ENABLE_BC2=$ENABLE_BC2
# Scrypt coins
ENABLE_LTC=$ENABLE_LTC
ENABLE_DOGE=$ENABLE_DOGE
ENABLE_DGB_SCRYPT=$ENABLE_DGB_SCRYPT
ENABLE_PEP=$ENABLE_PEP
ENABLE_CAT=$ENABLE_CAT
# Merge-minable coins (also solo-minable)
ENABLE_NMC=$ENABLE_NMC
ENABLE_SYS=$ENABLE_SYS
ENABLE_XMY=$ENABLE_XMY
ENABLE_FBTC=$ENABLE_FBTC

# ═══════════════════════════════════════════════════════════════════════════════
# WALLET ADDRESSES
# ═══════════════════════════════════════════════════════════════════════════════
# SHA256d coins
DGB_POOL_ADDRESS=${DGB_POOL_ADDRESS:-}
BTC_POOL_ADDRESS=${BTC_POOL_ADDRESS:-}
BCH_POOL_ADDRESS=${BCH_POOL_ADDRESS:-}
BC2_POOL_ADDRESS=${BC2_POOL_ADDRESS:-}
NMC_POOL_ADDRESS=${NMC_POOL_ADDRESS:-}
SYS_POOL_ADDRESS=${SYS_POOL_ADDRESS:-}
XMY_POOL_ADDRESS=${XMY_POOL_ADDRESS:-}
FBTC_POOL_ADDRESS=${FBTC_POOL_ADDRESS:-}
# Scrypt coins
LTC_POOL_ADDRESS=${LTC_POOL_ADDRESS:-}
DOGE_POOL_ADDRESS=${DOGE_POOL_ADDRESS:-}
PEP_POOL_ADDRESS=${PEP_POOL_ADDRESS:-}
CAT_POOL_ADDRESS=${CAT_POOL_ADDRESS:-}
# DGB-SCRYPT uses same address format as DGB (can be separate or same)
DGB_SCRYPT_ADDRESS=${DGB_SCRYPT_ADDRESS:-}

# ═══════════════════════════════════════════════════════════════════════════════
# DATABASE
# ═══════════════════════════════════════════════════════════════════════════════
DB_USER=$DB_USER
DB_NAME=$DB_NAME
DB_PASSWORD=$DB_PASSWORD
ADMIN_API_KEY=$ADMIN_API_KEY

# ═══════════════════════════════════════════════════════════════════════════════
# RPC CREDENTIALS (per coin)
# ═══════════════════════════════════════════════════════════════════════════════
# SHA256d coins
DGB_RPC_USER=spiraldgb
DGB_RPC_PASSWORD=${DGB_RPC_PASSWORD:-}
BTC_RPC_USER=spiralbtc
BTC_RPC_PASSWORD=${BTC_RPC_PASSWORD:-}
BCH_RPC_USER=spiralbch
BCH_RPC_PASSWORD=${BCH_RPC_PASSWORD:-}
BC2_RPC_USER=spiralbc2
BC2_RPC_PASSWORD=${BC2_RPC_PASSWORD:-}
# Merge-minable SHA256d coins
NMC_RPC_USER=spiralnmc
NMC_RPC_PASSWORD=${NMC_RPC_PASSWORD:-}
SYS_RPC_USER=spiralsys
SYS_RPC_PASSWORD=${SYS_RPC_PASSWORD:-}
XMY_RPC_USER=spiralxmy
XMY_RPC_PASSWORD=${XMY_RPC_PASSWORD:-}
FBTC_RPC_USER=spiralfbtc
FBTC_RPC_PASSWORD=${FBTC_RPC_PASSWORD:-}
# Scrypt coins
LTC_RPC_USER=spiralltc
LTC_RPC_PASSWORD=${LTC_RPC_PASSWORD:-}
DOGE_RPC_USER=spiraldoge
DOGE_RPC_PASSWORD=${DOGE_RPC_PASSWORD:-}
# Note: DGB-SCRYPT uses DGB node (same RPC credentials)
# Additional Scrypt coins (PEP/CAT)
PEP_RPC_USER=spiralpep
PEP_RPC_PASSWORD=${PEP_RPC_PASSWORD:-}
CAT_RPC_USER=spiralcat
CAT_RPC_PASSWORD=${CAT_RPC_PASSWORD:-}

# ═══════════════════════════════════════════════════════════════════════════════
# BRANDING
# ═══════════════════════════════════════════════════════════════════════════════
COINBASE_TEXT="${COINBASE_TEXT}"

# ═══════════════════════════════════════════════════════════════════════════════
# MONITORING (Prometheus + Grafana)
# ═══════════════════════════════════════════════════════════════════════════════
EXPECTED_FLEET_THS=$EXPECTED_FLEET_THS
GRAFANA_ADMIN_PASSWORD=$GRAFANA_ADMIN_PASSWORD
SPIRAL_METRICS_TOKEN=$METRICS_TOKEN

# ═══════════════════════════════════════════════════════════════════════════════
# NOTIFICATIONS
# ═══════════════════════════════════════════════════════════════════════════════
DISCORD_WEBHOOK_URL=${DISCORD_WEBHOOK_URL:-}
TELEGRAM_BOT_TOKEN=${TELEGRAM_BOT_TOKEN:-}
TELEGRAM_CHAT_ID=${TELEGRAM_CHAT_ID:-}
XMPP_JID=${XMPP_JID:-}
XMPP_PASSWORD=${XMPP_PASSWORD:-}
XMPP_RECIPIENT=${XMPP_RECIPIENT:-}

# ═══════════════════════════════════════════════════════════════════════════════
# DASHBOARD
# ═══════════════════════════════════════════════════════════════════════════════
DASHBOARD_AUTH_ENABLED=true
DASHBOARD_SESSION_LIFETIME=24
EOF

    chmod 600 "$DOCKER_DIR/.env"
    log_success "Created multi-coin .env with secure permissions"

    # Generate multi-coin config.yaml (V2 format)
    log "Generating multi-coin pool configuration..."
    generate_docker_stratum_config_multicoin

    # Generate daemon configs for each enabled coin
    if [[ "$ENABLE_DGB" == "true" ]]; then
        generate_docker_dgb_config
    fi

    if [[ "$ENABLE_BTC" == "true" ]]; then
        generate_docker_btc_config
    fi

    if [[ "$ENABLE_BCH" == "true" ]]; then
        generate_docker_bch_config
    fi

    if [[ "$ENABLE_BC2" == "true" ]]; then
        generate_docker_bc2_config
    fi

    if [[ "$ENABLE_NMC" == "true" ]]; then
        generate_docker_nmc_config
    fi

    if [[ "$ENABLE_SYS" == "true" ]]; then
        generate_docker_sys_config
    fi

    if [[ "$ENABLE_XMY" == "true" ]]; then
        generate_docker_xmy_config
    fi

    if [[ "$ENABLE_FBTC" == "true" ]]; then
        generate_docker_fbtc_config
    fi

    if [[ "$ENABLE_QBX" == "true" ]]; then
        generate_docker_qbx_config
    fi

    if [[ "$ENABLE_LTC" == "true" ]]; then
        generate_docker_ltc_config
    fi

    if [[ "$ENABLE_DOGE" == "true" ]]; then
        generate_docker_doge_config
    fi

    if [[ "$ENABLE_PEP" == "true" ]]; then
        generate_docker_pep_config
    fi

    if [[ "$ENABLE_CAT" == "true" ]]; then
        generate_docker_cat_config
    fi

    # DGB-SCRYPT shares the DGB daemon — no separate config needed

    # Create data directories
    log "Creating data directories..."
    mkdir -p "$DOCKER_DIR/data/postgres"
    mkdir -p "$DOCKER_DIR/logs"
    [[ "$ENABLE_DGB" == "true" ]] && mkdir -p "$DOCKER_DIR/data/digibyte"
    [[ "$ENABLE_BTC" == "true" ]] && mkdir -p "$DOCKER_DIR/data/bitcoin"
    [[ "$ENABLE_BCH" == "true" ]] && mkdir -p "$DOCKER_DIR/data/bitcoincash"
    [[ "$ENABLE_BC2" == "true" ]] && mkdir -p "$DOCKER_DIR/data/bitcoinii"
    [[ "$ENABLE_NMC" == "true" ]] && mkdir -p "$DOCKER_DIR/data/namecoin"
    [[ "$ENABLE_SYS" == "true" ]] && mkdir -p "$DOCKER_DIR/data/syscoin"
    [[ "$ENABLE_XMY" == "true" ]] && mkdir -p "$DOCKER_DIR/data/myriadcoin"
    [[ "$ENABLE_FBTC" == "true" ]] && mkdir -p "$DOCKER_DIR/data/fractalbitcoin"
    [[ "$ENABLE_QBX" == "true" ]] && mkdir -p "$DOCKER_DIR/data/qbitx"
    [[ "$ENABLE_LTC" == "true" ]] && mkdir -p "$DOCKER_DIR/data/litecoin"
    [[ "$ENABLE_DOGE" == "true" ]] && mkdir -p "$DOCKER_DIR/data/dogecoin"
    [[ "$ENABLE_PEP" == "true" ]] && mkdir -p "$DOCKER_DIR/data/pepecoin"
    [[ "$ENABLE_CAT" == "true" ]] && mkdir -p "$DOCKER_DIR/data/catcoin"

    log_success "Multi-coin Docker environment ready"
    echo ""
}

generate_docker_stratum_config_multicoin() {
    local CONFIG_DIR="$SCRIPT_DIR/docker/config"
    local DB_USER="spiralstratum"
    local DB_NAME="spiralstratum"

    # Build per-coin merge mining YAML (V2: mergeMining inside parent coin section)
    local sha256d_merge_yaml=""
    local scrypt_merge_yaml=""

    if [[ "$MERGE_MINING_ENABLED" == "true" ]]; then
        local aux_chains_to_check="$MERGE_MINING_AUX_CHAINS"
        if [[ "$MERGE_MINING_ALGO" == "both" ]]; then
            aux_chains_to_check="${MERGE_MINING_AUX_CHAINS_SHA256D},${MERGE_MINING_AUX_CHAINS_SCRYPT}"
        fi

        # SHA-256d aux chains (NMC, SYS, XMY, FBTC)
        local sha256d_aux=""
        if [[ "$MERGE_MINING_ALGO" == "sha256d" ]] || [[ "$MERGE_MINING_ALGO" == "both" ]]; then
            if [[ "$aux_chains_to_check" == *"NMC"* ]]; then
                sha256d_aux+="
        - symbol: \"NMC\"
          enabled: true
          address: \"$NMC_POOL_ADDRESS\"
          daemon:
            host: \"namecoin\"
            port: 8336
            user: \"$NMC_RPC_USER\"
            password: \"$NMC_RPC_PASSWORD\""
            fi
            if [[ "$aux_chains_to_check" == *"SYS"* ]]; then
                sha256d_aux+="
        - symbol: \"SYS\"
          enabled: true
          address: \"$SYS_POOL_ADDRESS\"
          daemon:
            host: \"syscoin\"
            port: 8370
            user: \"$SYS_RPC_USER\"
            password: \"$SYS_RPC_PASSWORD\""
            fi
            if [[ "$aux_chains_to_check" == *"XMY"* ]]; then
                sha256d_aux+="
        - symbol: \"XMY\"
          enabled: true
          address: \"$XMY_POOL_ADDRESS\"
          daemon:
            host: \"myriadcoin\"
            port: 10889
            user: \"$XMY_RPC_USER\"
            password: \"$XMY_RPC_PASSWORD\""
            fi
            if [[ "$aux_chains_to_check" == *"FBTC"* ]]; then
                sha256d_aux+="
        - symbol: \"FBTC\"
          enabled: true
          address: \"$FBTC_POOL_ADDRESS\"
          daemon:
            host: \"fractalbitcoin\"
            port: 8340
            user: \"$FBTC_RPC_USER\"
            password: \"$FBTC_RPC_PASSWORD\""
            fi
        fi
        if [[ -n "$sha256d_aux" ]]; then
            sha256d_merge_yaml="
    mergeMining:
      enabled: true
      refreshInterval: 5s
      auxChains:${sha256d_aux}"
        fi

        # Scrypt aux chains (DOGE, PEP)
        local scrypt_aux=""
        if [[ "$MERGE_MINING_ALGO" == "scrypt" ]] || [[ "$MERGE_MINING_ALGO" == "both" ]]; then
            if [[ "$aux_chains_to_check" == *"DOGE"* ]]; then
                scrypt_aux+="
        - symbol: \"DOGE\"
          enabled: true
          address: \"$DOGE_POOL_ADDRESS\"
          daemon:
            host: \"dogecoin\"
            port: 22555
            user: \"$DOGE_RPC_USER\"
            password: \"$DOGE_RPC_PASSWORD\""
            fi
            if [[ "$aux_chains_to_check" == *"PEP"* ]]; then
                scrypt_aux+="
        - symbol: \"PEP\"
          enabled: true
          address: \"$PEP_POOL_ADDRESS\"
          daemon:
            host: \"pepecoin\"
            port: 33873
            user: \"$PEP_RPC_USER\"
            password: \"$PEP_RPC_PASSWORD\""
            fi
        fi
        if [[ -n "$scrypt_aux" ]]; then
            scrypt_merge_yaml="
    mergeMining:
      enabled: true
      refreshInterval: 5s
      auxChains:${scrypt_aux}"
        fi
    fi

    # Build coins array (V2 CoinPoolConfig format — must match v2.go struct tags)
    local coins_yaml=""

    if [[ "$ENABLE_DGB" == "true" ]]; then
        # DGB gets SHA256d merge mining only if BTC is not the parent
        local dgb_merge=""
        if [[ "$ENABLE_BTC" != "true" ]] && [[ -n "$sha256d_merge_yaml" ]]; then
            dgb_merge="$sha256d_merge_yaml"
        fi
        coins_yaml="${coins_yaml}
  # DigiByte (SHA256d) - 15 sec blocks
  - symbol: \"DGB\"
    pool_id: \"dgb_sha256_1\"
    enabled: true
    address: \"$DGB_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 3333
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 10000000
          targetTime: 4
          retargetTime: 60
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"digibyte\"
        port: 14022
        user: \"spiraldgb\"
        password: \"$DGB_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://digibyte:28532\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\"${dgb_merge}"
    fi

    if [[ "$ENABLE_BTC" == "true" ]]; then
        # BTC is preferred parent for SHA256d merge mining
        coins_yaml="${coins_yaml}
  # Bitcoin (SHA256d) - 10 min blocks
  - symbol: \"BTC\"
    pool_id: \"btc_sha256_1\"
    enabled: true
    address: \"$BTC_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 4333
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 100000000
          targetTime: 10
          retargetTime: 90
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"bitcoin\"
        port: 8332
        user: \"spiralbtc\"
        password: \"$BTC_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://bitcoin:28332\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\"${sha256d_merge_yaml}"
    fi

    if [[ "$ENABLE_BCH" == "true" ]]; then
        coins_yaml="${coins_yaml}
  # Bitcoin Cash (SHA256d) - 10 min blocks
  - symbol: \"BCH\"
    pool_id: \"bch_sha256_1\"
    enabled: true
    address: \"$BCH_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 5333
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 100000000
          targetTime: 10
          retargetTime: 90
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"bitcoincash\"
        port: 8432
        user: \"spiralbch\"
        password: \"$BCH_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://bitcoincash:28432\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\""
    fi

    if [[ "$ENABLE_BC2" == "true" ]]; then
        coins_yaml="${coins_yaml}
  # Bitcoin II (SHA256d) - 10 min blocks
  - symbol: \"BC2\"
    pool_id: \"bc2_sha256_1\"
    enabled: true
    address: \"$BC2_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 6333
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 100000000
          targetTime: 10
          retargetTime: 90
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"bitcoinii\"
        port: 8339
        user: \"spiralbc2\"
        password: \"$BC2_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://bitcoinii:28338\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\""
    fi

    if [[ "$ENABLE_NMC" == "true" ]]; then
        coins_yaml="${coins_yaml}
  # Namecoin (SHA256d) - 10 min blocks, AuxPoW merge-mineable with BTC
  - symbol: \"NMC\"
    pool_id: \"nmc_sha256_1\"
    enabled: true
    address: \"$NMC_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 14335
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 100000000
          targetTime: 10
          retargetTime: 90
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"namecoin\"
        port: 8336
        user: \"spiralnmc\"
        password: \"$NMC_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://namecoin:28336\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\""
    fi

    if [[ "$ENABLE_SYS" == "true" ]]; then
        coins_yaml="${coins_yaml}
  # Syscoin (SHA256d) - 1 min blocks, AuxPoW merge-mineable with BTC
  - symbol: \"SYS\"
    pool_id: \"sys_sha256_1\"
    enabled: true
    address: \"$SYS_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 15335
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 100000000
          targetTime: 6
          retargetTime: 90
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"syscoin\"
        port: 8370
        user: \"spiralsys\"
        password: \"$SYS_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://syscoin:28370\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\""
    fi

    if [[ "$ENABLE_XMY" == "true" ]]; then
        coins_yaml="${coins_yaml}
  # Myriad (SHA256d) - multi-algo coin, AuxPoW merge-mineable with BTC
  - symbol: \"XMY\"
    pool_id: \"xmy_sha256_1\"
    enabled: true
    address: \"$XMY_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 17335
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 100000000
          targetTime: 6
          retargetTime: 90
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"myriadcoin\"
        port: 10889
        user: \"spiralxmy\"
        password: \"$XMY_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://myriadcoin:28889\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\""
    fi

    if [[ "$ENABLE_FBTC" == "true" ]]; then
        coins_yaml="${coins_yaml}
  # Fractal Bitcoin (SHA256d) - 30 sec blocks, AuxPoW merge-mineable with BTC
  - symbol: \"FBTC\"
    pool_id: \"fbtc_sha256_1\"
    enabled: true
    address: \"$FBTC_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 18335
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 100000000
          targetTime: 4
          retargetTime: 90
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"fractalbitcoin\"
        port: 8340
        user: \"spiralfbtc\"
        password: \"$FBTC_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://fractalbitcoin:28340\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\""
    fi

    if [[ "$ENABLE_QBX" == "true" ]]; then
        coins_yaml="${coins_yaml}
  # Q-BitX (SHA256d) - 2.5 min blocks, standalone (not merge-mineable)
  - symbol: \"QBX\"
    pool_id: \"qbx_sha256_1\"
    enabled: true
    address: \"$QBX_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 20335
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 100000000
          targetTime: 8
          retargetTime: 90
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"qbitx\"
        port: 8344
        user: \"spiralqbx\"
        password: \"$QBX_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://qbitx:28344\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\""
    fi

    # ═══════════════════════════════════════════════════════════════════════════
    # SCRYPT COINS
    # ═══════════════════════════════════════════════════════════════════════════

    if [[ "$ENABLE_LTC" == "true" ]]; then
        coins_yaml="${coins_yaml}
  # Litecoin (Scrypt) - 2.5 min blocks
  - symbol: \"LTC\"
    pool_id: \"ltc_scrypt_1\"
    enabled: true
    address: \"$LTC_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 7333
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 65536
          targetTime: 8
          retargetTime: 60
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"litecoin\"
        port: 9332
        user: \"spiralltc\"
        password: \"$LTC_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://litecoin:28933\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\"${scrypt_merge_yaml}"
    fi

    if [[ "$ENABLE_DOGE" == "true" ]]; then
        coins_yaml="${coins_yaml}
  # Dogecoin (Scrypt) - 1 min blocks
  - symbol: \"DOGE\"
    pool_id: \"doge_scrypt_1\"
    enabled: true
    address: \"$DOGE_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 8335
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 65536
          targetTime: 4
          retargetTime: 60
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"dogecoin\"
        port: 22555
        user: \"spiraldoge\"
        password: \"$DOGE_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://dogecoin:28555\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\""
    fi

    if [[ "$ENABLE_DGB_SCRYPT" == "true" ]]; then
        coins_yaml="${coins_yaml}
  # DigiByte (Scrypt algorithm) - 15 sec blocks, same node as DGB
  - symbol: \"DGB-SCRYPT\"
    pool_id: \"dgb_scrypt_1\"
    enabled: true
    address: \"$DGB_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 3336
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 65536
          targetTime: 3
          retargetTime: 45
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"digibyte\"
        port: 14022
        user: \"spiraldgb\"
        password: \"$DGB_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://digibyte:28532\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\""
    fi

    if [[ "$ENABLE_PEP" == "true" ]]; then
        coins_yaml="${coins_yaml}
  # PepeCoin (Scrypt) - 1 min blocks, merge-mineable with LTC
  - symbol: \"PEP\"
    pool_id: \"pep_scrypt_1\"
    enabled: true
    address: \"$PEP_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 10335
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 65536
          targetTime: 4
          retargetTime: 60
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"pepecoin\"
        port: 33873
        user: \"spiralpep\"
        password: \"$PEP_RPC_PASSWORD\"
        zmq:
          enabled: false
          endpoint: \"tcp://pepecoin:28873\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\""
    fi

    if [[ "$ENABLE_CAT" == "true" ]]; then
        coins_yaml="${coins_yaml}
  # Catcoin (Scrypt) - 10 min blocks, standalone chain
  - symbol: \"CAT\"
    pool_id: \"cat_scrypt_1\"
    enabled: true
    address: \"$CAT_POOL_ADDRESS\"
    coinbase_text: \"${COINBASE_TEXT:-SpiralPool}\"
    stratum:
      port: 12335
      difficulty:
        varDiff:
          enabled: true
          minDiff: 0.001
          maxDiff: 65536
          targetTime: 8
          retargetTime: 90
          variancePercent: 30
    nodes:
      - id: \"primary\"
        host: \"catcoin\"
        port: 9932
        user: \"spiralcat\"
        password: \"$CAT_RPC_PASSWORD\"
        zmq:
          enabled: true
          endpoint: \"tcp://catcoin:28932\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\""
    fi

    # Merge mining is now built per-coin above (V2: inside parent coin section)

    cat > "$CONFIG_DIR/config.yaml" << EOF
# Spiral Stratum V2 Configuration
# Multi-Coin Docker Configuration - Generated $(date)

version: 2

global:
  log_level: "info"
  log_format: "json"
  metrics_port: 9100
  api_port: 4000
  api_enabled: true
  admin_api_key: "$ADMIN_API_KEY"
  rate_limiting:
    enabled: true
    requests_per_second: 10

  sentinel:
    enabled: true
    check_interval: 60s
    wal_stuck_threshold: 10m
    alert_cooldown: 15m
$(if [[ -n "$DISCORD_WEBHOOK_URL" ]]; then
echo "    webhooks:"
echo "      - url: \"$DISCORD_WEBHOOK_URL\""
if [[ -n "$TELEGRAM_BOT_TOKEN" ]] && [[ -n "$TELEGRAM_CHAT_ID" ]]; then
echo "      - url: \"https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage\""
echo "        chat_id: \"$TELEGRAM_CHAT_ID\""
fi
elif [[ -n "$TELEGRAM_BOT_TOKEN" ]] && [[ -n "$TELEGRAM_CHAT_ID" ]]; then
echo "    webhooks:"
echo "      - url: \"https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage\""
echo "        chat_id: \"$TELEGRAM_CHAT_ID\""
fi)

  celebration:
    enabled: ${CELEBRATION_ENABLED:-true}
    duration_hours: ${CELEBRATION_HOURS:-2}

# Per-coin pool configurations (V2 CoinPoolConfig format)
coins:${coins_yaml}

database:
  host: "postgres"
  port: 5432
  user: "$DB_USER"
  password: "$DB_PASSWORD"
  database: "$DB_NAME"
  sslMode: "disable"
  maxConnections: 200
  batching:
    size: 1000
    interval: 3s
EOF

    chmod 640 "$CONFIG_DIR/config.yaml"
    log_success "Generated multi-coin config.yaml (V2 format)"
}

generate_docker_dgb_config() {
    local CONFIG_DIR="$SCRIPT_DIR/docker/config"

    cat > "$CONFIG_DIR/digibyte.conf" << EOF
# DigiByte Core Configuration
# Docker Multi-Coin - Generated $(date)

# Network
server=1
daemon=0
txindex=1
listen=1
listenonion=0
port=12024

# RPC Configuration
rpcuser=spiraldgb
rpcpassword=$DGB_RPC_PASSWORD
rpcbind=0.0.0.0
rpcallowip=127.0.0.1
rpcport=14022

# ZMQ (block notifications) - DGB uses port 28532
zmqpubhashblock=tcp://0.0.0.0:28532
zmqpubrawtx=tcp://0.0.0.0:28532

# Performance
dbcache=8192
maxmempool=512
maxconnections=125
par=0
maxsigcachesize=250
maxorphantx=100
rpcthreads=8
rpcworkqueue=64

# Mining
algo=sha256d
EOF
    chmod 640 "$CONFIG_DIR/digibyte.conf"
    log_success "Generated digibyte.conf"
}

generate_docker_btc_config() {
    local CONFIG_DIR="$SCRIPT_DIR/docker/config"

    cat > "$CONFIG_DIR/bitcoin.conf" << EOF
# Bitcoin Knots Configuration
# Docker Multi-Coin - Generated $(date)

# Network
chain=main
listen=1
port=8333

# RPC Configuration
server=1
rpcuser=spiralbtc
rpcpassword=$BTC_RPC_PASSWORD
rpcallowip=127.0.0.1
