validate_docker_disk_requirements() {
    log "Validating disk space requirements..."

    local INSTALL_PATH="${1:-$SCRIPT_DIR}"
    local AVAILABLE_GB=$(df -BG "$INSTALL_PATH" 2>/dev/null | tail -1 | awk '{print $4}' | tr -d 'G' || echo "0")
    local REQUIRED_GB=0

    # Calculate required space based on enabled coins
    # SHA-256d coins
    [[ "$ENABLE_DGB" == "true" ]] && ((REQUIRED_GB+=70))   # DGB: ~60GB + buffer
    [[ "$ENABLE_BTC" == "true" ]] && ((REQUIRED_GB+=700))  # BTC: ~600GB + buffer
    [[ "$ENABLE_BCH" == "true" ]] && ((REQUIRED_GB+=300))  # BCH: ~250GB + buffer
    [[ "$ENABLE_BC2" == "true" ]] && ((REQUIRED_GB+=5))    # BC2: ~3GB + buffer
    [[ "$ENABLE_NMC" == "true" ]] && ((REQUIRED_GB+=15))   # NMC: ~12GB + buffer
    [[ "$ENABLE_SYS" == "true" ]] && ((REQUIRED_GB+=50))   # SYS: ~40GB + buffer
    [[ "$ENABLE_XMY" == "true" ]] && ((REQUIRED_GB+=5))    # XMY: ~3GB + buffer
    [[ "$ENABLE_FBTC" == "true" ]] && ((REQUIRED_GB+=10))  # FBTC: ~5GB + buffer
    [[ "$ENABLE_QBX" == "true" ]] && ((REQUIRED_GB+=5))    # QBX: ~2GB + buffer
    # Scrypt coins
    [[ "$ENABLE_LTC" == "true" ]] && ((REQUIRED_GB+=120))  # LTC: ~100GB + buffer
    [[ "$ENABLE_DOGE" == "true" ]] && ((REQUIRED_GB+=80))  # DOGE: ~70GB + buffer
    [[ "$ENABLE_PEP" == "true" ]] && ((REQUIRED_GB+=5))    # PEP: ~2GB + buffer
    [[ "$ENABLE_CAT" == "true" ]] && ((REQUIRED_GB+=5))    # CAT: ~2GB + buffer

    # Add base requirements
    ((REQUIRED_GB+=10))  # PostgreSQL, logs, etc.

    if [[ "$AVAILABLE_GB" -lt "$REQUIRED_GB" ]]; then
        echo ""
        echo -e "${RED}═══════════════════════════════════════════════════════════════════════${NC}"
        echo -e "${WHITE}  INSUFFICIENT DISK SPACE${NC}"
        echo -e "${RED}═══════════════════════════════════════════════════════════════════════${NC}"
        echo ""
        echo -e "  Available: ${YELLOW}${AVAILABLE_GB} GB${NC}"
        echo -e "  Required:  ${GREEN}${REQUIRED_GB} GB${NC}"
        echo ""
        echo -e "  Breakdown:"
        [[ "$ENABLE_DGB" == "true" ]] && echo -e "    • DigiByte:          ~60 GB"
        [[ "$ENABLE_BTC" == "true" ]] && echo -e "    • Bitcoin:           ~600 GB"
        [[ "$ENABLE_BCH" == "true" ]] && echo -e "    • Bitcoin Cash:      ~250 GB"
        [[ "$ENABLE_BC2" == "true" ]] && echo -e "    • Bitcoin II:        ~3 GB"
        [[ "$ENABLE_NMC" == "true" ]] && echo -e "    • Namecoin:          ~12 GB"
        [[ "$ENABLE_SYS" == "true" ]] && echo -e "    • Syscoin:           ~40 GB"
        [[ "$ENABLE_XMY" == "true" ]] && echo -e "    • Myriad:            ~3 GB"
        [[ "$ENABLE_FBTC" == "true" ]] && echo -e "    • Fractal Bitcoin:   ~5 GB"
        [[ "$ENABLE_QBX" == "true" ]] && echo -e "    • Q-BitX:            ~2 GB"
        [[ "$ENABLE_LTC" == "true" ]] && echo -e "    • Litecoin:          ~100 GB"
        [[ "$ENABLE_DOGE" == "true" ]] && echo -e "    • Dogecoin:          ~70 GB"
        [[ "$ENABLE_PEP" == "true" ]] && echo -e "    • PepeCoin:          ~2 GB"
        [[ "$ENABLE_CAT" == "true" ]] && echo -e "    • Catcoin:           ~2 GB"
        echo -e "    • Other:             ~10 GB"
        echo ""

        while true; do
            prompt_input "Continue anyway? (y/N): "; read continue_choice
            case "${continue_choice,,}" in
                y|yes)
                    log_warn "Proceeding with insufficient disk space"
                    return 0
                    ;;
                n|no|"")
                    log_error "Installation cancelled due to insufficient disk space"
                    exit 1
                    ;;
                *)
                    echo "Please enter y or n"
                    ;;
            esac
        done
    else
        log_success "Disk space OK: ${AVAILABLE_GB} GB available, ${REQUIRED_GB} GB required"
    fi
}

check_docker_port_availability() {
    log "Checking port availability..."

    local ports_to_check=()
    local conflicts=()

    # Shared ports (always needed)
    ports_to_check+=(5432 4000 1618 9100)

    # Coin-specific ports (stratum V1/V2, RPC, P2P)
    if [[ "$ENABLE_DGB" == "true" ]]; then
        ports_to_check+=(3333 3334 12024 14022)
    fi
    if [[ "$ENABLE_BTC" == "true" ]]; then
        ports_to_check+=(4333 4334 8332 8333)
    fi
    if [[ "$ENABLE_BCH" == "true" ]]; then
        ports_to_check+=(5333 5334 8432 8433)
    fi
    if [[ "$ENABLE_BC2" == "true" ]]; then
        ports_to_check+=(6333 6334 8339 8338)
    fi
    if [[ "$ENABLE_LTC" == "true" ]]; then
        ports_to_check+=(7333 7334 9332 9333)
    fi
    if [[ "$ENABLE_DOGE" == "true" ]]; then
        ports_to_check+=(8335 8337 22555 22556)
    fi
    if [[ "$ENABLE_DGB_SCRYPT" == "true" ]]; then
        ports_to_check+=(3336 3337)
    fi
    if [[ "$ENABLE_PEP" == "true" ]]; then
        ports_to_check+=(10335 10336 33873 33874)
    fi
    if [[ "$ENABLE_CAT" == "true" ]]; then
        ports_to_check+=(12335 12336 9932 9933)
    fi
    if [[ "$ENABLE_NMC" == "true" ]]; then
        ports_to_check+=(14335 14336 8336 8334)
    fi
    if [[ "$ENABLE_SYS" == "true" ]]; then
        ports_to_check+=(15335 15336 8370 8369)
    fi
    if [[ "$ENABLE_XMY" == "true" ]]; then
        ports_to_check+=(17335 17336 10889 10888)
    fi
    if [[ "$ENABLE_FBTC" == "true" ]]; then
        ports_to_check+=(18335 18336 8340 8341)
    fi
    if [[ "$ENABLE_QBX" == "true" ]]; then
        ports_to_check+=(20335 20336 8344 8345)
    fi

    for port in "${ports_to_check[@]}"; do
        if ss -tuln 2>/dev/null | grep -q ":${port} " || \
           netstat -tuln 2>/dev/null | grep -q ":${port} "; then
            conflicts+=("$port")
        fi
    done

    if [[ ${#conflicts[@]} -gt 0 ]]; then
        echo ""
        echo -e "${YELLOW}═══════════════════════════════════════════════════════════════════════${NC}"
        echo -e "${WHITE}  PORT CONFLICTS DETECTED${NC}"
        echo -e "${YELLOW}═══════════════════════════════════════════════════════════════════════${NC}"
        echo ""
        echo -e "  The following ports are already in use:"
        for port in "${conflicts[@]}"; do
            echo -e "    • Port ${RED}${port}${NC}"
        done
        echo ""
        echo -e "  Please stop the services using these ports or choose different coins."
        echo ""

        while true; do
            prompt_input "Continue anyway? (y/N): "; read continue_choice
            case "${continue_choice,,}" in
                y|yes)
                    log_warn "Proceeding with port conflicts - containers may fail to start"
                    return 0
                    ;;
                n|no|"")
                    log_error "Installation cancelled due to port conflicts"
                    exit 1
                    ;;
                *)
                    echo "Please enter y or n"
                    ;;
            esac
        done
    else
        log_success "All required ports are available"
    fi
}

build_docker_images() {
    log_step "Building Docker Images"

    local DOCKER_DIR="$SCRIPT_DIR/docker"
    cd "$DOCKER_DIR"

    log "Building Spiral Pool images (this may take 10-15 minutes)..."
    echo ""

    # Build all images
    docker compose build --no-cache 2>&1 | while IFS= read -r line; do
        echo "  $line"
    done

    if [[ ${PIPESTATUS[0]} -eq 0 ]]; then
        log_success "All Docker images built successfully"
    else
        log_error "Docker image build failed"
        exit 1
    fi

    echo ""
}

start_docker_services() {
    log_step "Starting Docker Services"

    local DOCKER_DIR="$SCRIPT_DIR/docker"
    cd "$DOCKER_DIR"

    log "Starting containers..."

    # Start services in detached mode
    docker compose up -d

    # Wait a moment for services to initialize
    sleep 5

    # Check service status
    echo ""
    echo -e "${WHITE}Container Status:${NC}"
    echo ""
    docker compose ps

    echo ""
    log_success "Docker services started"
}

