start_docker_services_multicoin() {
    log_step "Starting Docker Services (Profile: $DOCKER_PROFILE)"

    local DOCKER_DIR="$SCRIPT_DIR/docker"
    cd "$DOCKER_DIR"

    log "Starting containers with profile: $DOCKER_PROFILE..."

    # Start services with per-coin profile flags
    # shellcheck disable=SC2086  # Intentional word splitting on DOCKER_PROFILE_ARGS
    if ! docker compose $DOCKER_PROFILE_ARGS up -d 2>&1; then
        log_error "Failed to start Docker services with profile: $DOCKER_PROFILE"
        echo ""
        echo "Troubleshooting tips:"
        echo "  1. Check if Docker is running: systemctl status docker"
        echo "  2. Check available profiles: docker compose config --profiles"
        echo "  3. Verify .env file exists: cat docker/.env"
        echo "  4. Check compose file syntax: docker compose config"
        echo "  5. View Docker logs: docker compose $DOCKER_PROFILE_ARGS logs"
        echo ""
        exit 1
    fi

    # Wait a moment for services to initialize
    sleep 5

    # Check service status
    echo ""
    echo -e "${WHITE}Container Status:${NC}"
    echo ""
    # shellcheck disable=SC2086  # Intentional word splitting on DOCKER_PROFILE_ARGS
    docker compose $DOCKER_PROFILE_ARGS ps

    # Verify critical services are running
    local unhealthy_count=0
    # shellcheck disable=SC2086
    if ! docker compose $DOCKER_PROFILE_ARGS ps --format json 2>/dev/null | grep -q '"State":"running"'; then
        # Fallback for older docker compose versions
        # shellcheck disable=SC2086
        local running_services=$(docker compose $DOCKER_PROFILE_ARGS ps --services --filter "status=running" 2>/dev/null | wc -l)
        if [[ $running_services -eq 0 ]]; then
            log_warn "No services appear to be running. Checking for errors..."
            # shellcheck disable=SC2086
            docker compose $DOCKER_PROFILE_ARGS logs --tail=50
            echo ""
            log_error "Docker services failed to start properly"
            echo "Run 'docker compose $DOCKER_PROFILE_ARGS logs' for more details"
            exit 1
        fi
    fi

    echo ""
    log_success "Docker services started"
}

