docker_main() {
    # Docker deployment - supports single and multi-coin configurations
    # Uses Docker Compose profiles for selective service startup

    # Install Docker
    install_docker

    # Check for existing installation and allow upgrade
    detect_existing_docker_install

    # Select coin mode (reuses existing function)
    select_coin_mode

    # Validate requirements
    validate_docker_disk_requirements
    check_docker_port_availability

    # Determine Docker profile based on enabled coins
    select_docker_compose_profile

    # Handle upgrade vs fresh install
    if [[ "$DOCKER_UPGRADE_MODE" == "add" ]]; then
        merge_docker_configuration
    else
        collect_docker_multicoin_configuration
    fi

    log_step "Configuring Docker Multi-Coin Environment"
    setup_docker_environment_multicoin

    build_docker_images_multicoin
    start_docker_services_multicoin
    print_docker_completion_multicoin

    # Installation complete - clear the trap
    trap - EXIT
}

build_docker_images_multicoin() {
    log_step "Building Docker Images"

    local DOCKER_DIR="$SCRIPT_DIR/docker"
    cd "$DOCKER_DIR"

    log "Building Spiral Pool images with profile: $DOCKER_PROFILE..."
    echo ""

    # Build all images for the selected profile(s)
    # shellcheck disable=SC2086  # Intentional word splitting on DOCKER_PROFILE_ARGS
    docker compose $DOCKER_PROFILE_ARGS build --no-cache 2>&1 | while IFS= read -r line; do
        echo "  $line"
    done

    if [[ ${PIPESTATUS[0]} -eq 0 ]]; then
        log_success "All Docker images built successfully"
    else
        log_error "Docker image build failed"
        exit 1
    fi

    echo ""
}

select_install_mode() {
