# ═══════════════════════════════════════════════════════════════════════════════
# COIN MODE SELECTION
# ═══════════════════════════════════════════════════════════════════════════════

select_coin_mode() {
    clear
    log_step "Mining Configuration"

    # STEP 1: Ask about merge mining FIRST
    echo ""
    echo -e "${WHITE}Would you like to enable Merge Mining (AuxPoW)?${NC}"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${YELLOW}MERGE MINING${NC} allows you to mine a parent blockchain AND auxiliary"
    echo -e "  blockchains simultaneously using the SAME mining work."
    echo ""
    echo -e "  ${WHITE}How It Works:${NC}"
    echo -e "    • Submit work to multiple blockchains simultaneously"
    echo -e "    • Uses same mining computation for parent and aux chains"
    echo ""
    echo -e "  ${WHITE}Supported Merge Mining Configurations:${NC}"
    echo -e "  ┌─────────────────────────────────────────────────────────────────────┐"
    echo -e "  │  ${CYAN}SHA-256d:${NC}  Bitcoin (BTC) + NMC, SYS, XMY, FBTC aux chains       │"
    echo -e "  │  ${CYAN}Scrypt:${NC}    Litecoin (LTC) + DOGE, PEP aux chains                │"
    echo -e "  └─────────────────────────────────────────────────────────────────────┘"
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${RED}⚠ IMPORTANT DISCLAIMER:${NC}"
    echo ""
    echo -e "  ${WHITE}Merge mining requires syncing MULTIPLE full blockchains:${NC}"
    echo -e "    • Parent chain (BTC ~600GB or LTC ~180GB)"
    echo -e "    • PLUS each auxiliary chain you enable (5-80GB each)"
    echo ""
    echo -e "  ${WHITE}This means:${NC}"
    echo -e "    • Increased disk space requirements"
    echo -e "    • Longer initial sync time (days to weeks)"
    echo -e "    • Higher RAM usage"
    echo -e "    • Mining will NOT start until ALL chains are synced (≥99.9%)"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo ""

    while true; do
        prompt_input "Enable merge mining? (y/n) [default: n]: "; read merge_choice
        merge_choice=${merge_choice:-n}
        case "${merge_choice,,}" in
            y|yes)
                # User wants merge mining - go to merge mining parent selection
                MERGE_MINING_REQUESTED="true"
                select_merge_mining_parent
                return
                ;;
            n|no)
                # User doesn't want merge mining - ask solo vs multi
                MERGE_MINING_REQUESTED="false"
                break
                ;;
            *)
                echo -e "  ${RED}Please enter y or n${NC}"
                ;;
        esac
    done

    clear

    # STEP 2: If no merge mining, ask about solo vs multi-coin
    echo ""
    echo -e "${WHITE}Do you want to run a Solo mining pool or a Multi-Coin mining pool?${NC}"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${GREEN}1)${NC} ${WHITE}Solo Mining Pool${NC} ${GREEN}(Single Blockchain)${NC}"
    echo ""
    echo -e "     Mine one cryptocurrency at a time."
    echo -e "     Simpler setup, lower resource requirements."
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${GREEN}2)${NC} ${WHITE}Multi-Coin Mining Pool${NC} ${YELLOW}(Multiple Blockchains)${NC}"
    echo ""
    echo -e "     Mine multiple cryptocurrencies simultaneously on different ports."
    echo -e "     Requires more disk space and RAM for each blockchain."
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""

    while true; do
        prompt_input "Enter choice (1 or 2): "; read pool_type
        case $pool_type in
            1)
                COIN_MODE="single"
                select_solo_coin_no_merge
                break
                ;;
            2)
                COIN_MODE="multi"
                select_multi_coins
                break
                ;;
            *)
                echo -e "  ${RED}Please enter 1 or 2${NC}"
                ;;
        esac
    done
    echo ""
}

# ═══════════════════════════════════════════════════════════════════════════════
# MERGE MINING PARENT SELECTION
# ═══════════════════════════════════════════════════════════════════════════════
# When user chooses merge mining, they select: BTC only, LTC only, or BOTH

select_merge_mining_parent() {
    clear
    echo ""
    log_step "Select Merge Mining Configuration"

    echo ""
    echo -e "${WHITE}Select your merge mining configuration:${NC}"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${GREEN}1)${NC} ${WHITE}Bitcoin (BTC) + SHA-256d Aux Chains${NC}"
    echo ""
    echo -e "     Mine Bitcoin as parent with auxiliary chains:"
    echo -e "     ${CYAN}•${NC} Namecoin (NMC)         - First AuxPoW coin, ~12 GB"
    echo -e "     ${CYAN}•${NC} Syscoin (SYS)          - Platform coin, ~8 GB"
    echo -e "     ${CYAN}•${NC} Myriad (XMY)           - Multi-algo coin, ~3 GB"
    echo -e "     ${CYAN}•${NC} Fractal Bitcoin (FBTC) - Recursive scaling, ~10 GB"
    echo ""
    echo -e "     ${WHITE}Requirements:${NC} ~600 GB + aux chains, 8+ GB RAM"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${GREEN}2)${NC} ${WHITE}Litecoin (LTC) + Scrypt Aux Chains${NC}"
    echo ""
    echo -e "     Mine Litecoin as parent with auxiliary chains:"
    echo -e "     ${CYAN}•${NC} Dogecoin (DOGE) - Largest Scrypt AuxPoW, ~80 GB"
    echo -e "     ${CYAN}•${NC} PepeCoin (PEP)  - Meme coin, ~15 GB"
    echo ""
    echo -e "     ${WHITE}Requirements:${NC} ~180 GB + aux chains, 4+ GB RAM"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${GREEN}3)${NC} ${YELLOW}BOTH - BTC + LTC with All Aux Chains${NC}"
    echo ""
    echo -e "     Run BOTH SHA-256d AND Scrypt merge mining simultaneously!"
    echo -e "     ${WHITE}SHA-256d:${NC} Bitcoin + NMC, SYS, XMY, FBTC"
    echo -e "     ${WHITE}Scrypt:${NC}   Litecoin + DOGE, PEP"
    echo ""
    echo -e "     ${RED}⚠ WARNING:${NC} This requires significant resources:"
    echo -e "     ${WHITE}•${NC} ~800+ GB disk space (BTC + LTC + all aux chains)"
    echo -e "     ${WHITE}•${NC} 16+ GB RAM recommended"
    echo -e "     ${WHITE}•${NC} Weeks to fully sync all blockchains"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo ""

    while true; do
        prompt_input "Enter choice (1, 2, or 3): "; read parent_choice

        # Reset all coins to false before enabling selected ones
        # This fixes bug where DGB (default=true) stayed enabled in merge mining mode
        ENABLE_DGB="false"
        ENABLE_BTC="false"
        ENABLE_BCH="false"
        ENABLE_BC2="false"
        ENABLE_QBX="false"
        ENABLE_LTC="false"
        ENABLE_DOGE="false"
        ENABLE_PEP="false"
        ENABLE_CAT="false"
        ENABLE_DGB_SCRYPT="false"
        ENABLE_NMC="false"
        ENABLE_SYS="false"
        ENABLE_XMY="false"
        ENABLE_FBTC="false"

        case $parent_choice in
            1)
                # Bitcoin (SHA-256d) merge mining only
                COIN_MODE="multi"
                ENABLE_BTC="true"
                MERGE_MINING_ENABLED="true"
                MERGE_MINING_ALGO="sha256d"
                MERGE_MINING_PARENT="BTC"
                SOLO_COIN="BTC"
                STRATUM_PORT=4333
                STRATUM_V2_PORT=4334
                log "Selected: Merge Mining - Bitcoin (BTC) as parent (SHA-256d)"
                echo ""
                echo -e "  ${GREEN}✓${NC} Bitcoin selected as merge mining parent"
                echo ""
                # Select which SHA-256d aux chains to enable
                select_aux_chains "BTC" "sha256d"
                break
                ;;
            2)
                # Litecoin (Scrypt) merge mining only
                COIN_MODE="multi"
                ENABLE_LTC="true"
                MERGE_MINING_ENABLED="true"
                MERGE_MINING_ALGO="scrypt"
                MERGE_MINING_PARENT="LTC"
                SOLO_COIN="LTC"
                STRATUM_PORT=7333
                STRATUM_V2_PORT=7334
                log "Selected: Merge Mining - Litecoin (LTC) as parent (Scrypt)"
                echo ""
                echo -e "  ${GREEN}✓${NC} Litecoin selected as merge mining parent"
                echo ""
                # Select which Scrypt aux chains to enable
                select_aux_chains "LTC" "scrypt"
                break
                ;;
            3)
                # BOTH SHA-256d AND Scrypt merge mining
                COIN_MODE="multi"
                ENABLE_BTC="true"
                ENABLE_LTC="true"
                MERGE_MINING_ENABLED="true"
                MERGE_MINING_ALGO="both"  # Special value for dual-algo
                MERGE_MINING_PARENT="BTC,LTC"  # Both parents
                # Primary ports for BTC, LTC gets its own port
                STRATUM_PORT=4333
                STRATUM_V2_PORT=4334
                log "Selected: Dual Merge Mining - BTC (SHA-256d) + LTC (Scrypt)"
                echo ""
                echo -e "  ${GREEN}✓${NC} Dual merge mining selected!"
                echo ""
                echo -e "  ${WHITE}Configuring SHA-256d merge mining (BTC parent):${NC}"
                # Select SHA-256d aux chains
                select_aux_chains_dual "BTC" "sha256d"
                echo ""
                echo -e "  ${WHITE}Configuring Scrypt merge mining (LTC parent):${NC}"
                # Select Scrypt aux chains
                select_aux_chains_dual "LTC" "scrypt"
                break
                ;;
            *)
                echo -e "  ${RED}Please enter 1, 2, or 3${NC}"
                ;;
        esac
    done
    echo ""
}

# Aux chain selection for dual merge mining mode (doesn't switch COIN_MODE)
select_aux_chains_dual() {
    local parent_coin="$1"
    local algo="$2"

    clear
    echo ""
    echo -e "  ${WHITE}Select auxiliary chains for ${parent_coin} (${algo}):${NC}"
    echo ""

    if [[ "$parent_coin" == "BTC" ]]; then
        # SHA-256d aux chains: NMC, SYS, XMY, FBTC
        local sel_nmc="true"   # Default: enable NMC
        local sel_sys="false"
        local sel_xmy="false"
        local sel_fbtc="false"

        while true; do
            echo -e "  ${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
            [[ "$sel_nmc" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 1) Namecoin (NMC)       ~12 GB" || echo -e "    ${DIM}[ ]${NC} 1) Namecoin (NMC)       ~12 GB"
            [[ "$sel_sys" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 2) Syscoin (SYS)        ~8 GB" || echo -e "    ${DIM}[ ]${NC} 2) Syscoin (SYS)        ~8 GB"
            [[ "$sel_xmy" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 3) Myriad (XMY)         ~3 GB" || echo -e "    ${DIM}[ ]${NC} 3) Myriad (XMY)         ~3 GB"
            [[ "$sel_fbtc" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 4) Fractal Bitcoin (FBTC) ~10 GB" || echo -e "    ${DIM}[ ]${NC} 4) Fractal Bitcoin (FBTC) ~10 GB"
            echo -e "  ${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
            echo ""
            echo -e "  Enter number to toggle, ${GREEN}a${NC}=select all, ${YELLOW}c${NC}=confirm, ${RED}q${NC}=cancel"
            prompt_input "Choice: "; read aux_choice

            case "$aux_choice" in
                1) [[ "$sel_nmc" == "true" ]] && sel_nmc="false" || sel_nmc="true" ;;
                2) [[ "$sel_sys" == "true" ]] && sel_sys="false" || sel_sys="true" ;;
                3) [[ "$sel_xmy" == "true" ]] && sel_xmy="false" || sel_xmy="true" ;;
                4) [[ "$sel_fbtc" == "true" ]] && sel_fbtc="false" || sel_fbtc="true" ;;
                a|A)
                    sel_nmc="true"; sel_sys="true"; sel_xmy="true"; sel_fbtc="true"
                    ;;
                c|C)
                    if [[ "$sel_nmc" == "false" ]] && [[ "$sel_sys" == "false" ]] && \
                       [[ "$sel_xmy" == "false" ]] && [[ "$sel_fbtc" == "false" ]]; then
                        echo -e "  ${RED}Please select at least one aux chain${NC}"
                        continue
                    fi
                    break
                    ;;
                q|Q)
                    echo -e "  ${WHITE}SHA-256d merge mining cancelled${NC}"
                    ENABLE_BTC="false"
                    # Downgrade from dual to LTC-only (Scrypt selection runs next)
                    MERGE_MINING_ALGO="scrypt"
                    MERGE_MINING_PARENT="LTC"
                    return
                    ;;
                *)
                    echo -e "  ${RED}Invalid choice${NC}"
                    ;;
            esac
            echo ""
        done

        # Apply SHA-256d selections (append to existing aux chains)
        MERGE_MINING_AUX_CHAINS_SHA256D=""
        [[ "$sel_nmc" == "true" ]] && { ENABLE_NMC="true"; MERGE_MINING_AUX_CHAINS_SHA256D="${MERGE_MINING_AUX_CHAINS_SHA256D}NMC,"; }
        [[ "$sel_sys" == "true" ]] && { ENABLE_SYS="true"; MERGE_MINING_AUX_CHAINS_SHA256D="${MERGE_MINING_AUX_CHAINS_SHA256D}SYS,"; }
        [[ "$sel_xmy" == "true" ]] && { ENABLE_XMY="true"; MERGE_MINING_AUX_CHAINS_SHA256D="${MERGE_MINING_AUX_CHAINS_SHA256D}XMY,"; }
        [[ "$sel_fbtc" == "true" ]] && { ENABLE_FBTC="true"; MERGE_MINING_AUX_CHAINS_SHA256D="${MERGE_MINING_AUX_CHAINS_SHA256D}FBTC,"; }
        MERGE_MINING_AUX_CHAINS_SHA256D="${MERGE_MINING_AUX_CHAINS_SHA256D%,}"

        echo ""
        echo -e "  ${GREEN}✓${NC} SHA-256d merge mining: BTC + ${MERGE_MINING_AUX_CHAINS_SHA256D}"
        log "Dual merge mining SHA-256d: BTC + ${MERGE_MINING_AUX_CHAINS_SHA256D}"

    elif [[ "$parent_coin" == "LTC" ]]; then
        # Scrypt aux chains: DOGE, PEP
        local sel_doge="true"   # Default: enable DOGE
        local sel_pep="false"

        while true; do
            echo -e "  ${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
            [[ "$sel_doge" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 1) Dogecoin (DOGE)  ~80 GB" || echo -e "    ${DIM}[ ]${NC} 1) Dogecoin (DOGE)  ~80 GB"
            [[ "$sel_pep" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 2) PepeCoin (PEP)   ~15 GB" || echo -e "    ${DIM}[ ]${NC} 2) PepeCoin (PEP)   ~15 GB"
            echo -e "  ${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
            echo ""
            echo -e "  Enter number to toggle, ${GREEN}a${NC}=select all, ${YELLOW}c${NC}=confirm, ${RED}q${NC}=cancel"
            prompt_input "Choice: "; read aux_choice

            case "$aux_choice" in
                1) [[ "$sel_doge" == "true" ]] && sel_doge="false" || sel_doge="true" ;;
                2) [[ "$sel_pep" == "true" ]] && sel_pep="false" || sel_pep="true" ;;
                a|A)
                    sel_doge="true"; sel_pep="true"
                    ;;
                c|C)
                    if [[ "$sel_doge" == "false" ]] && [[ "$sel_pep" == "false" ]]; then
                        echo -e "  ${RED}Please select at least one aux chain${NC}"
                        continue
                    fi
                    break
                    ;;
                q|Q)
                    echo -e "  ${WHITE}Scrypt merge mining cancelled${NC}"
                    ENABLE_LTC="false"
                    if [[ "$ENABLE_BTC" == "false" ]]; then
                        # Both algos cancelled — disable merge mining entirely
                        MERGE_MINING_ENABLED="false"
                        MERGE_MINING_ALGO=""
                        MERGE_MINING_PARENT=""
                    else
                        # Downgrade from dual to BTC-only
                        MERGE_MINING_ALGO="sha256d"
                        MERGE_MINING_PARENT="BTC"
                    fi
                    return
                    ;;
                *)
                    echo -e "  ${RED}Invalid choice${NC}"
                    ;;
            esac
            echo ""
        done

        # Apply Scrypt selections
        MERGE_MINING_AUX_CHAINS_SCRYPT=""
        [[ "$sel_doge" == "true" ]] && { ENABLE_DOGE="true"; MERGE_MINING_AUX_CHAINS_SCRYPT="${MERGE_MINING_AUX_CHAINS_SCRYPT}DOGE,"; }
        [[ "$sel_pep" == "true" ]] && { ENABLE_PEP="true"; MERGE_MINING_AUX_CHAINS_SCRYPT="${MERGE_MINING_AUX_CHAINS_SCRYPT}PEP,"; }
        MERGE_MINING_AUX_CHAINS_SCRYPT="${MERGE_MINING_AUX_CHAINS_SCRYPT%,}"

        echo ""
        echo -e "  ${GREEN}✓${NC} Scrypt merge mining: LTC + ${MERGE_MINING_AUX_CHAINS_SCRYPT}"
        log "Dual merge mining Scrypt: LTC + ${MERGE_MINING_AUX_CHAINS_SCRYPT}"
    fi
}

