# Select which auxiliary chains to enable for merge mining
select_aux_chains() {
    local parent_coin="$1"
    local algo="$2"
    local selected_aux=""

    clear
    echo ""
    echo -e "  ${WHITE}Select auxiliary chains to merge-mine:${NC}"
    echo ""

    if [[ "$parent_coin" == "BTC" ]]; then
        # SHA-256d aux chains: NMC, SYS, XMY, FBTC
        local sel_nmc="true"   # Default: enable NMC (most popular)
        local sel_sys="false"
        local sel_xmy="false"
        local sel_fbtc="false"

        while true; do
            echo -e "  ${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
            [[ "$sel_nmc" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 1) Namecoin (NMC)       ~12 GB" || echo -e "    ${DIM}[ ]${NC} 1) Namecoin (NMC)       ~12 GB"
            [[ "$sel_sys" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 2) Syscoin (SYS)        ~8 GB" || echo -e "    ${DIM}[ ]${NC} 2) Syscoin (SYS)        ~8 GB"
            [[ "$sel_xmy" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 3) Myriad (XMY)         ~3 GB" || echo -e "    ${DIM}[ ]${NC} 3) Myriad (XMY)         ~3 GB"
            [[ "$sel_fbtc" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 4) Fractal Bitcoin (FBTC) ~10 GB" || echo -e "    ${DIM}[ ]${NC} 4) Fractal Bitcoin (FBTC) ~10 GB"
            echo -e "  ${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
            echo ""
            echo -e "  Enter number to toggle, ${GREEN}a${NC}=select all, ${YELLOW}c${NC}=confirm, ${RED}q${NC}=cancel"
            prompt_input "Choice: "; read aux_choice

            case "$aux_choice" in
                1) [[ "$sel_nmc" == "true" ]] && sel_nmc="false" || sel_nmc="true" ;;
                2) [[ "$sel_sys" == "true" ]] && sel_sys="false" || sel_sys="true" ;;
                3) [[ "$sel_xmy" == "true" ]] && sel_xmy="false" || sel_xmy="true" ;;
                4) [[ "$sel_fbtc" == "true" ]] && sel_fbtc="false" || sel_fbtc="true" ;;
                a|A)
                    sel_nmc="true"; sel_sys="true"; sel_xmy="true"; sel_fbtc="true"
                    ;;
                c|C)
                    # Confirm selection - need at least one aux chain
                    if [[ "$sel_nmc" == "false" ]] && [[ "$sel_sys" == "false" ]] && \
                       [[ "$sel_xmy" == "false" ]] && [[ "$sel_fbtc" == "false" ]]; then
                        echo -e "  ${RED}Please select at least one aux chain${NC}"
                        continue
                    fi
                    break
                    ;;
                q|Q)
                    MERGE_MINING_ENABLED="false"
                    echo -e "  ${WHITE}Merge mining cancelled${NC}"
                    return
                    ;;
                *)
                    echo -e "  ${RED}Invalid choice${NC}"
                    ;;
            esac
            echo ""
        done

        # Apply selections
        MERGE_MINING_ENABLED="true"
        MERGE_MINING_ALGO="sha256d"
        MERGE_MINING_PARENT="BTC"
        MERGE_MINING_AUX_CHAINS=""

        [[ "$sel_nmc" == "true" ]] && { ENABLE_NMC="true"; MERGE_MINING_AUX_CHAINS="${MERGE_MINING_AUX_CHAINS}NMC,"; }
        [[ "$sel_sys" == "true" ]] && { ENABLE_SYS="true"; MERGE_MINING_AUX_CHAINS="${MERGE_MINING_AUX_CHAINS}SYS,"; }
        [[ "$sel_xmy" == "true" ]] && { ENABLE_XMY="true"; MERGE_MINING_AUX_CHAINS="${MERGE_MINING_AUX_CHAINS}XMY,"; }
        [[ "$sel_fbtc" == "true" ]] && { ENABLE_FBTC="true"; MERGE_MINING_AUX_CHAINS="${MERGE_MINING_AUX_CHAINS}FBTC,"; }

        # Remove trailing comma
        MERGE_MINING_AUX_CHAINS="${MERGE_MINING_AUX_CHAINS%,}"

        echo ""
        echo -e "  ${GREEN}✓${NC} Merge mining enabled: Bitcoin + ${MERGE_MINING_AUX_CHAINS} (SHA-256d)"
        log "Merge mining enabled: BTC + ${MERGE_MINING_AUX_CHAINS} (SHA-256d)"

    elif [[ "$parent_coin" == "LTC" ]]; then
        # Scrypt aux chains: DOGE, PEP
        local sel_doge="true"   # Default: enable DOGE (most popular)
        local sel_pep="false"

        while true; do
            echo -e "  ${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
            [[ "$sel_doge" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 1) Dogecoin (DOGE)  ~80 GB" || echo -e "    ${DIM}[ ]${NC} 1) Dogecoin (DOGE)  ~80 GB"
            [[ "$sel_pep" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 2) PepeCoin (PEP)   ~15 GB" || echo -e "    ${DIM}[ ]${NC} 2) PepeCoin (PEP)   ~15 GB"
            echo -e "  ${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
            echo ""
            echo -e "  Enter number to toggle, ${GREEN}a${NC}=select all, ${YELLOW}c${NC}=confirm, ${RED}q${NC}=cancel"
            prompt_input "Choice: "; read aux_choice

            case "$aux_choice" in
                1) [[ "$sel_doge" == "true" ]] && sel_doge="false" || sel_doge="true" ;;
                2) [[ "$sel_pep" == "true" ]] && sel_pep="false" || sel_pep="true" ;;
                a|A)
                    sel_doge="true"; sel_pep="true"
                    ;;
                c|C)
                    # Confirm selection - need at least one aux chain
                    if [[ "$sel_doge" == "false" ]] && [[ "$sel_pep" == "false" ]]; then
                        echo -e "  ${RED}Please select at least one aux chain${NC}"
                        continue
                    fi
                    break
                    ;;
                q|Q)
                    MERGE_MINING_ENABLED="false"
                    echo -e "  ${WHITE}Merge mining cancelled${NC}"
                    return
                    ;;
                *)
                    echo -e "  ${RED}Invalid choice${NC}"
                    ;;
            esac
            echo ""
        done

        # Apply selections
        MERGE_MINING_ENABLED="true"
        MERGE_MINING_ALGO="scrypt"
        MERGE_MINING_PARENT="LTC"
        MERGE_MINING_AUX_CHAINS=""

        [[ "$sel_doge" == "true" ]] && { ENABLE_DOGE="true"; MERGE_MINING_AUX_CHAINS="${MERGE_MINING_AUX_CHAINS}DOGE,"; }
        [[ "$sel_pep" == "true" ]] && { ENABLE_PEP="true"; MERGE_MINING_AUX_CHAINS="${MERGE_MINING_AUX_CHAINS}PEP,"; }

        # Remove trailing comma
        MERGE_MINING_AUX_CHAINS="${MERGE_MINING_AUX_CHAINS%,}"

        echo ""
        echo -e "  ${GREEN}✓${NC} Merge mining enabled: Litecoin + ${MERGE_MINING_AUX_CHAINS} (Scrypt)"
        log "Merge mining enabled: LTC + ${MERGE_MINING_AUX_CHAINS} (Scrypt)"
    fi

    # Switch to multi-coin mode since we now have multiple blockchains
    COIN_MODE="multi"
    echo -e "  ${YELLOW}Note:${NC} Pool mode switched to Multi-Coin (required for merge mining)"
}

# Multi-coin mining - select which blockchains to sync
select_multi_coins() {
    clear
    echo ""
    log_step "Select Blockchains for Multi-Coin Mining"

    echo ""
    echo -e "${WHITE}Select which blockchains to enable. Each runs on its own stratum port.${NC}"
    echo -e "${WHITE}Toggle coins on/off, then confirm your selection.${NC}"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${YELLOW}SHA-256d COINS:${NC}"
    echo ""
    echo -e "  🟠 ${WHITE}Bitcoin (BTC)${NC}              Port: 4333  |  ~600 GB"
    echo -e "  🟢 ${WHITE}Bitcoin Cash (BCH)${NC}         Port: 5333  |  ~250 GB"
    echo -e "  🔷 ${WHITE}Bitcoin II (BC2)${NC}           Port: 6333  |  ~5 GB"
    echo -e "  💎 ${WHITE}DigiByte (DGB)${NC}             Port: 3333  |  ~60 GB"
    echo -e "  🔶 ${WHITE}Fractal Bitcoin (FBTC)${NC}     Port: 18335 |  ~10 GB"
    echo -e "  🌀 ${WHITE}Myriad (XMY)${NC}              Port: 17335 |  ~3 GB"
    echo -e "  🔷 ${WHITE}Namecoin (NMC)${NC}             Port: 14335 |  ~12 GB"
    echo -e "  ⚛️ ${WHITE}Q-BitX (QBX)${NC}               Port: 20335 |  ~2 GB"
    echo -e "  ⚡ ${WHITE}Syscoin (SYS)${NC}              Port: 15335 |  ~8 GB"
    echo ""
    echo ""
    echo -e "  ${YELLOW}SCRYPT COINS:${NC}"
    echo ""
    echo -e "  🐱 ${WHITE}Catcoin (CAT)${NC}              Port: 12335 |  ~8 GB"
    echo -e "  💎 ${WHITE}DigiByte-Scrypt (DGB-S)${NC}    Port: 3336  |  (uses DGB node)"
    echo -e "  🐕 ${WHITE}Dogecoin (DOGE)${NC}            Port: 8335  |  ~80 GB"
    echo -e "  🪙 ${WHITE}Litecoin (LTC)${NC}             Port: 7333  |  ~150 GB"
    echo -e "  🐸 ${WHITE}PepeCoin (PEP)${NC}             Port: 10335 |  ~15 GB"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""

    # Check available disk space
    AVAILABLE_GB=$(df -BG "$INSTALL_DIR" 2>/dev/null | tail -1 | awk '{print $4}' | tr -d 'G' || echo "0")
    if [[ "$AVAILABLE_GB" -gt 0 ]]; then
        echo -e "  ${BLUE}Available disk space: ${AVAILABLE_GB} GB${NC}"
        echo ""
    fi

    # Interactive coin selection
    echo -e "${WHITE}Toggle coins (enter number to toggle, 'd' when done):${NC}"
    echo ""

    # Initialize all coins as disabled (user selects which to enable) - Alphabetically ordered
    local sel_bc2="false"
    local sel_bch="false"
    local sel_btc="false"
    local sel_dgb="false"
    local sel_fbtc="false"
    local sel_xmy="false"
    local sel_nmc="false"
    local sel_qbx="false"
    local sel_sys="false"
    local sel_cat="false"
    local sel_dgb_scrypt="false"
    local sel_doge="false"
    local sel_ltc="false"
    local sel_pep="false"

    while true; do
        # Display current selection (alphabetically by display name)
        echo -e "  ${WHITE}SHA-256d:${NC}"
        [[ "$sel_btc" == "true" ]]  && echo -e "    ${GREEN}[✓]${NC}  1) Bitcoin (BTC)"            || echo -e "    ${DIM}[ ]${NC}  1) Bitcoin (BTC)"
        [[ "$sel_bch" == "true" ]]  && echo -e "    ${GREEN}[✓]${NC}  2) Bitcoin Cash (BCH)"       || echo -e "    ${DIM}[ ]${NC}  2) Bitcoin Cash (BCH)"
        [[ "$sel_bc2" == "true" ]]  && echo -e "    ${GREEN}[✓]${NC}  3) Bitcoin II (BC2)"         || echo -e "    ${DIM}[ ]${NC}  3) Bitcoin II (BC2)"
        [[ "$sel_dgb" == "true" ]]  && echo -e "    ${GREEN}[✓]${NC}  4) DigiByte (DGB)"           || echo -e "    ${DIM}[ ]${NC}  4) DigiByte (DGB)"
        [[ "$sel_fbtc" == "true" ]] && echo -e "    ${GREEN}[✓]${NC}  5) Fractal Bitcoin (FBTC)"   || echo -e "    ${DIM}[ ]${NC}  5) Fractal Bitcoin (FBTC)"
        [[ "$sel_xmy" == "true" ]]  && echo -e "    ${GREEN}[✓]${NC}  6) Myriad (XMY)"             || echo -e "    ${DIM}[ ]${NC}  6) Myriad (XMY)"
        [[ "$sel_nmc" == "true" ]]  && echo -e "    ${GREEN}[✓]${NC}  7) Namecoin (NMC)"           || echo -e "    ${DIM}[ ]${NC}  7) Namecoin (NMC)"
        [[ "$sel_qbx" == "true" ]]  && echo -e "    ${GREEN}[✓]${NC}  8) Q-BitX (QBX)"             || echo -e "    ${DIM}[ ]${NC}  8) Q-BitX (QBX)"
        [[ "$sel_sys" == "true" ]]  && echo -e "    ${GREEN}[✓]${NC}  9) Syscoin (SYS)"            || echo -e "    ${DIM}[ ]${NC}  9) Syscoin (SYS)"
        echo ""
        echo -e "  ${WHITE}Scrypt (alphabetically):${NC}"
        [[ "$sel_cat" == "true" ]]        && echo -e "    ${GREEN}[✓]${NC} 10) Catcoin (CAT)"            || echo -e "    ${DIM}[ ]${NC} 10) Catcoin (CAT)"
        [[ "$sel_dgb_scrypt" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 11) DGB-Scrypt"               || echo -e "    ${DIM}[ ]${NC} 11) DGB-Scrypt"
        [[ "$sel_doge" == "true" ]]       && echo -e "    ${GREEN}[✓]${NC} 12) Dogecoin (DOGE)"          || echo -e "    ${DIM}[ ]${NC} 12) Dogecoin (DOGE)"
        [[ "$sel_ltc" == "true" ]]        && echo -e "    ${GREEN}[✓]${NC} 13) Litecoin (LTC)"           || echo -e "    ${DIM}[ ]${NC} 13) Litecoin (LTC)"
        [[ "$sel_pep" == "true" ]]        && echo -e "    ${GREEN}[✓]${NC} 14) PepeCoin (PEP)"           || echo -e "    ${DIM}[ ]${NC} 14) PepeCoin (PEP)"
        echo ""

        # Calculate estimated disk and RAM
        local est_disk=0
        local est_ram=4
        [[ "$sel_btc" == "true" ]]  && { est_disk=$((est_disk + 600)); est_ram=16; }
        [[ "$sel_bch" == "true" ]]  && { est_disk=$((est_disk + 250)); [[ $est_ram -lt 8 ]] && est_ram=8; }
        [[ "$sel_bc2" == "true" ]]  && est_disk=$((est_disk + 5))
        [[ "$sel_dgb" == "true" ]]  && est_disk=$((est_disk + 60))
        [[ "$sel_fbtc" == "true" ]] && est_disk=$((est_disk + 10))
        [[ "$sel_xmy" == "true" ]]  && est_disk=$((est_disk + 3))
        [[ "$sel_nmc" == "true" ]]  && est_disk=$((est_disk + 12))
        [[ "$sel_qbx" == "true" ]]  && est_disk=$((est_disk + 2))
        [[ "$sel_sys" == "true" ]]  && est_disk=$((est_disk + 8))
        [[ "$sel_cat" == "true" ]]  && est_disk=$((est_disk + 8))
        # DGB-Scrypt uses DGB node, no additional disk
        [[ "$sel_doge" == "true" ]] && { est_disk=$((est_disk + 80)); [[ $est_ram -lt 6 ]] && est_ram=6; }
        [[ "$sel_ltc" == "true" ]]  && { est_disk=$((est_disk + 150)); [[ $est_ram -lt 8 ]] && est_ram=8; }
        [[ "$sel_pep" == "true" ]]  && est_disk=$((est_disk + 15))

        echo -e "  ${CYAN}Estimated: ~${est_disk} GB disk, ${est_ram}+ GB RAM${NC}"
        echo ""

        prompt_input "Toggle (1-14) or 'd' to confirm: "; read toggle_choice

        case "$toggle_choice" in
            1) [[ "$sel_btc" == "true" ]] && sel_btc="false" || sel_btc="true" ;;
            2) [[ "$sel_bch" == "true" ]] && sel_bch="false" || sel_bch="true" ;;
            3) [[ "$sel_bc2" == "true" ]] && sel_bc2="false" || sel_bc2="true" ;;
            4) [[ "$sel_dgb" == "true" ]] && sel_dgb="false" || sel_dgb="true" ;;
            5) [[ "$sel_fbtc" == "true" ]] && sel_fbtc="false" || sel_fbtc="true" ;;
            6) [[ "$sel_xmy" == "true" ]] && sel_xmy="false" || sel_xmy="true" ;;
            7) [[ "$sel_nmc" == "true" ]] && sel_nmc="false" || sel_nmc="true" ;;
            8) [[ "$sel_qbx" == "true" ]] && sel_qbx="false" || sel_qbx="true" ;;
            9) [[ "$sel_sys" == "true" ]] && sel_sys="false" || sel_sys="true" ;;
            10) [[ "$sel_cat" == "true" ]] && sel_cat="false" || sel_cat="true" ;;
            11)
                [[ "$sel_dgb_scrypt" == "true" ]] && sel_dgb_scrypt="false" || sel_dgb_scrypt="true"
                # DGB-Scrypt requires DGB node
                if [[ "$sel_dgb_scrypt" == "true" ]] && [[ "$sel_dgb" == "false" ]]; then
                    echo -e "  ${YELLOW}Note: DGB-Scrypt requires DigiByte node. Enabling DGB...${NC}"
                    sel_dgb="true"
                fi
                ;;
            12) [[ "$sel_doge" == "true" ]] && sel_doge="false" || sel_doge="true" ;;
            13) [[ "$sel_ltc" == "true" ]] && sel_ltc="false" || sel_ltc="true" ;;
            14) [[ "$sel_pep" == "true" ]] && sel_pep="false" || sel_pep="true" ;;
            d|D|done|Done)
                # Validate at least one coin selected
                if [[ "$sel_bc2" == "false" ]] && [[ "$sel_bch" == "false" ]] && [[ "$sel_btc" == "false" ]] && \
                   [[ "$sel_dgb" == "false" ]] && [[ "$sel_fbtc" == "false" ]] && [[ "$sel_xmy" == "false" ]] && \
                   [[ "$sel_nmc" == "false" ]] && [[ "$sel_qbx" == "false" ]] && [[ "$sel_sys" == "false" ]] && \
                   [[ "$sel_cat" == "false" ]] && [[ "$sel_dgb_scrypt" == "false" ]] && \
                   [[ "$sel_doge" == "false" ]] && [[ "$sel_ltc" == "false" ]] && [[ "$sel_pep" == "false" ]]; then
                    echo -e "  ${RED}Please select at least one coin!${NC}"
                    continue
                fi
                # SYS requires BTC for merge mining (cannot solo mine)
                if [[ "$sel_sys" == "true" ]] && [[ "$sel_btc" == "false" ]]; then
                    echo -e "  ${YELLOW}Syscoin requires Bitcoin for merge mining. Enabling BTC automatically...${NC}"
                    sel_btc="true"
                fi
                break
                ;;
            *)
                echo -e "  ${RED}Invalid choice. Enter 1-14 to toggle or 'd' when done.${NC}"
                ;;
        esac

        # Clear previous display (move cursor up 23 lines for 14 coins)
        echo -e "\033[23A\033[J"
    done

    # Apply selections to global variables (alphabetically ordered)
    ENABLE_BC2="$sel_bc2"
    ENABLE_BCH="$sel_bch"
    ENABLE_BTC="$sel_btc"
    ENABLE_CAT="$sel_cat"
    ENABLE_DGB="$sel_dgb"
    ENABLE_DGB_SCRYPT="$sel_dgb_scrypt"
    ENABLE_DOGE="$sel_doge"
    ENABLE_FBTC="$sel_fbtc"
    ENABLE_LTC="$sel_ltc"
    ENABLE_NMC="$sel_nmc"
    ENABLE_QBX="$sel_qbx"
    ENABLE_PEP="$sel_pep"
    ENABLE_SYS="$sel_sys"
    ENABLE_XMY="$sel_xmy"

    # Build selection summary (alphabetically ordered)
    echo ""
    echo -e "  ${GREEN}✓${NC} Will install (alphabetically):"
    # SHA-256d coins
    [[ "$ENABLE_BC2" == "true" ]]  && echo -e "     🔷 Bitcoin II Node         (SHA-256d, port 6333)"
    [[ "$ENABLE_BCH" == "true" ]]  && echo -e "     🟢 Bitcoin Cash Node       (SHA-256d, port 5333)"
    [[ "$ENABLE_BTC" == "true" ]]  && echo -e "     🟠 Bitcoin Knots           (SHA-256d, port 4333)"
    [[ "$ENABLE_DGB" == "true" ]]  && echo -e "     💎 DigiByte Node           (SHA-256d, port 3333)"
    [[ "$ENABLE_FBTC" == "true" ]] && echo -e "     🔶 Fractal Bitcoin Node    (SHA-256d, port 18335)"
    [[ "$ENABLE_XMY" == "true" ]]  && echo -e "     🌀 Myriad Node             (SHA-256d, port 17335)"
    [[ "$ENABLE_NMC" == "true" ]]  && echo -e "     🔷 Namecoin Node           (SHA-256d, port 14335)"
    [[ "$ENABLE_QBX" == "true" ]]  && echo -e "     ⚛️ Q-BitX Node              (SHA-256d, port 20335)"
    [[ "$ENABLE_SYS" == "true" ]]  && echo -e "     ⚡ Syscoin Node             (SHA-256d, port 15335)"
    # Scrypt coins
    [[ "$ENABLE_CAT" == "true" ]]        && echo -e "     🐱 Catcoin Node            (Scrypt, port 12335)"
    [[ "$ENABLE_DGB_SCRYPT" == "true" ]] && echo -e "     💎 DGB-Scrypt              (Scrypt, port 3336)"
    [[ "$ENABLE_DOGE" == "true" ]]       && echo -e "     🐕 Dogecoin Node           (Scrypt, port 8335)"
    [[ "$ENABLE_LTC" == "true" ]]        && echo -e "     🪙 Litecoin Node           (Scrypt, port 7333)"
    [[ "$ENABLE_PEP" == "true" ]]        && echo -e "     🐸 PepeCoin Node           (Scrypt, port 10335)"
    echo ""

    # Log selection
    local selected_coins=""
    [[ "$ENABLE_BC2" == "true" ]]        && selected_coins+="BC2 "
    [[ "$ENABLE_BCH" == "true" ]]        && selected_coins+="BCH "
    [[ "$ENABLE_BTC" == "true" ]]        && selected_coins+="BTC "
    [[ "$ENABLE_DGB" == "true" ]]        && selected_coins+="DGB "
    [[ "$ENABLE_FBTC" == "true" ]]       && selected_coins+="FBTC "
    [[ "$ENABLE_QBX" == "true" ]]        && selected_coins+="QBX "
    [[ "$ENABLE_XMY" == "true" ]]        && selected_coins+="XMY "
    [[ "$ENABLE_NMC" == "true" ]]        && selected_coins+="NMC "
    [[ "$ENABLE_SYS" == "true" ]]        && selected_coins+="SYS "
    [[ "$ENABLE_CAT" == "true" ]]        && selected_coins+="CAT "
    [[ "$ENABLE_DGB_SCRYPT" == "true" ]] && selected_coins+="DGB-SCRYPT "
    [[ "$ENABLE_DOGE" == "true" ]]       && selected_coins+="DOGE "
    [[ "$ENABLE_LTC" == "true" ]]        && selected_coins+="LTC "
    [[ "$ENABLE_PEP" == "true" ]]        && selected_coins+="PEP "
    log "Selected coins: $selected_coins"

    # Offer merge mining configuration if compatible chains are selected
    select_merge_mining_multicoin
}

# Merge mining prompt for multi-coin mode (offers if compatible parent+aux selected)
# Supports all aux chains: SHA-256d (NMC, SYS, XMY, FBTC), Scrypt (DOGE, PEP)
select_merge_mining_multicoin() {
    clear
    # Check if BTC is selected - offer SHA-256d merge mining with all aux chains
    if [[ "$ENABLE_BTC" == "true" ]]; then
        echo ""
        echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo ""
        echo -e "  ${YELLOW}SHA-256d MERGE MINING AVAILABLE${NC}"
        echo ""
        echo -e "  You selected Bitcoin. Would you like to enable merge mining?"
        echo -e "  This submits work to auxiliary chains using the same mining computation."
        echo ""
        echo -e "  ${WHITE}AVAILABLE AUX CHAINS:${NC}"
        echo -e "  ┌────────────────────────────────────────────┐"
        echo -e "  │  ${CYAN}Namecoin (NMC)${NC}:          ~12 GB disk  │"
        echo -e "  │  ${CYAN}Syscoin (SYS)${NC}:           ~8 GB disk   │"
        echo -e "  │  ${CYAN}Myriad (XMY)${NC}:            ~3 GB disk   │"
        echo -e "  │  ${CYAN}Fractal Bitcoin (FBTC)${NC}:  ~10 GB disk  │"
        echo -e "  └────────────────────────────────────────────┘"
        echo ""
        echo -e "  ${RED}NOTE:${NC} Mining will NOT start until ALL selected blockchains are synced!"
        echo ""

        prompt_input "Enable SHA-256d merge mining? (y/n) [default: n]: "; read mm_choice
        mm_choice=${mm_choice:-n}

        if [[ "${mm_choice,,}" == "y" ]] || [[ "${mm_choice,,}" == "yes" ]]; then
            # Use the aux chain selection UI
            select_aux_chains_multicoin "BTC" "sha256d"
        fi
    fi

    # Check if LTC is selected - offer Scrypt merge mining with all aux chains
    if [[ "$ENABLE_LTC" == "true" ]]; then
        echo ""
        echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo ""
        echo -e "  ${YELLOW}SCRYPT MERGE MINING AVAILABLE${NC}"
        echo ""
        echo -e "  You selected Litecoin. Would you like to enable merge mining?"
        echo -e "  This submits work to auxiliary chains using the same mining computation."
        echo ""
        echo -e "  ${WHITE}AVAILABLE AUX CHAINS:${NC}"
        echo -e "  ┌────────────────────────────────────────────┐"
        echo -e "  │  ${CYAN}Dogecoin (DOGE)${NC}:  ~80 GB disk          │"
        echo -e "  │  ${CYAN}PepeCoin (PEP)${NC}:   ~15 GB disk          │"
        echo -e "  └────────────────────────────────────────────┘"
        echo ""
        echo -e "  ${RED}NOTE:${NC} Mining will NOT start until ALL selected blockchains are synced!"
        echo ""

        prompt_input "Enable Scrypt merge mining? (y/n) [default: n]: "; read mm_choice
        mm_choice=${mm_choice:-n}

        if [[ "${mm_choice,,}" == "y" ]] || [[ "${mm_choice,,}" == "yes" ]]; then
            # Use the aux chain selection UI
            select_aux_chains_multicoin "LTC" "scrypt"
        fi
    fi
    echo ""
}

# Aux chain selection for multi-coin mode (similar to select_aux_chains but doesn't switch mode)
select_aux_chains_multicoin() {
    local parent_coin="$1"
    local algo="$2"

    echo ""
    echo -e "  ${WHITE}Select auxiliary chains to merge-mine:${NC}"
    echo ""

    if [[ "$parent_coin" == "BTC" ]]; then
        # SHA-256d aux chains: NMC, SYS, XMY, FBTC
        # Pre-select any that user already enabled
        local sel_nmc="false"
        local sel_sys="false"
        local sel_xmy="false"
        local sel_fbtc="false"
        [[ "$ENABLE_NMC" == "true" ]] && sel_nmc="true"
        [[ "$ENABLE_SYS" == "true" ]] && sel_sys="true"
        [[ "$ENABLE_XMY" == "true" ]] && sel_xmy="true"
        [[ "$ENABLE_FBTC" == "true" ]] && sel_fbtc="true"
        # Default to NMC if nothing pre-selected
        [[ "$sel_nmc" == "false" ]] && [[ "$sel_sys" == "false" ]] && [[ "$sel_xmy" == "false" ]] && [[ "$sel_fbtc" == "false" ]] && sel_nmc="true"

        while true; do
            echo -e "  ${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
            [[ "$sel_nmc" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 1) Namecoin (NMC)       ~12 GB" || echo -e "    ${DIM}[ ]${NC} 1) Namecoin (NMC)       ~12 GB"
            [[ "$sel_sys" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 2) Syscoin (SYS)        ~8 GB" || echo -e "    ${DIM}[ ]${NC} 2) Syscoin (SYS)        ~8 GB"
            [[ "$sel_xmy" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 3) Myriad (XMY)         ~3 GB" || echo -e "    ${DIM}[ ]${NC} 3) Myriad (XMY)         ~3 GB"
            [[ "$sel_fbtc" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 4) Fractal Bitcoin (FBTC) ~10 GB" || echo -e "    ${DIM}[ ]${NC} 4) Fractal Bitcoin (FBTC) ~10 GB"
            echo -e "  ${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
            echo ""
            echo -e "  Enter number to toggle, ${GREEN}a${NC}=select all, ${YELLOW}c${NC}=confirm, ${RED}q${NC}=cancel"
            prompt_input "Choice: "; read aux_choice

            case "$aux_choice" in
                1) [[ "$sel_nmc" == "true" ]] && sel_nmc="false" || sel_nmc="true" ;;
                2) [[ "$sel_sys" == "true" ]] && sel_sys="false" || sel_sys="true" ;;
                3) [[ "$sel_xmy" == "true" ]] && sel_xmy="false" || sel_xmy="true" ;;
                4) [[ "$sel_fbtc" == "true" ]] && sel_fbtc="false" || sel_fbtc="true" ;;
                a|A)
                    sel_nmc="true"; sel_sys="true"; sel_xmy="true"; sel_fbtc="true"
                    ;;
                c|C)
                    # Confirm selection - need at least one aux chain
                    if [[ "$sel_nmc" == "false" ]] && [[ "$sel_sys" == "false" ]] && \
                       [[ "$sel_xmy" == "false" ]] && [[ "$sel_fbtc" == "false" ]]; then
                        echo -e "  ${RED}Please select at least one aux chain${NC}"
                        continue
                    fi
                    break
                    ;;
                q|Q)
                    echo -e "  ${WHITE}Merge mining cancelled${NC}"
                    return
                    ;;
                *)
                    echo -e "  ${RED}Invalid choice${NC}"
                    ;;
            esac
            echo ""
        done

        # Apply selections — use algo-specific variable to prevent overwrite
        # when both BTC and LTC merge mining are enabled in multi-coin mode
        MERGE_MINING_ENABLED="true"
        MERGE_MINING_ALGO="sha256d"
        MERGE_MINING_PARENT="BTC"
        MERGE_MINING_AUX_CHAINS_SHA256D=""

        [[ "$sel_nmc" == "true" ]] && { ENABLE_NMC="true"; MERGE_MINING_AUX_CHAINS_SHA256D="${MERGE_MINING_AUX_CHAINS_SHA256D}NMC,"; }
        [[ "$sel_sys" == "true" ]] && { ENABLE_SYS="true"; MERGE_MINING_AUX_CHAINS_SHA256D="${MERGE_MINING_AUX_CHAINS_SHA256D}SYS,"; }
        [[ "$sel_xmy" == "true" ]] && { ENABLE_XMY="true"; MERGE_MINING_AUX_CHAINS_SHA256D="${MERGE_MINING_AUX_CHAINS_SHA256D}XMY,"; }
        [[ "$sel_fbtc" == "true" ]] && { ENABLE_FBTC="true"; MERGE_MINING_AUX_CHAINS_SHA256D="${MERGE_MINING_AUX_CHAINS_SHA256D}FBTC,"; }

        # Remove trailing comma
        MERGE_MINING_AUX_CHAINS_SHA256D="${MERGE_MINING_AUX_CHAINS_SHA256D%,}"
        # Set legacy variable for single-algo compatibility
        MERGE_MINING_AUX_CHAINS="$MERGE_MINING_AUX_CHAINS_SHA256D"

        echo ""
        echo -e "  ${GREEN}✓${NC} Merge mining enabled: Bitcoin + ${MERGE_MINING_AUX_CHAINS_SHA256D} (SHA-256d)"
        log "Merge mining enabled: BTC + ${MERGE_MINING_AUX_CHAINS_SHA256D} (SHA-256d)"

    elif [[ "$parent_coin" == "LTC" ]]; then
        # Scrypt aux chains: DOGE, PEP
        # Pre-select any that user already enabled
        local sel_doge="false"
        local sel_pep="false"
        [[ "$ENABLE_DOGE" == "true" ]] && sel_doge="true"
        [[ "$ENABLE_PEP" == "true" ]] && sel_pep="true"
        # Default to DOGE if nothing pre-selected
        [[ "$sel_doge" == "false" ]] && [[ "$sel_pep" == "false" ]] && sel_doge="true"

        while true; do
            echo -e "  ${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
            [[ "$sel_doge" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 1) Dogecoin (DOGE)  ~80 GB" || echo -e "    ${DIM}[ ]${NC} 1) Dogecoin (DOGE)  ~80 GB"
            [[ "$sel_pep" == "true" ]] && echo -e "    ${GREEN}[✓]${NC} 2) PepeCoin (PEP)   ~15 GB" || echo -e "    ${DIM}[ ]${NC} 2) PepeCoin (PEP)   ~15 GB"
            echo -e "  ${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
            echo ""
            echo -e "  Enter number to toggle, ${GREEN}a${NC}=select all, ${YELLOW}c${NC}=confirm, ${RED}q${NC}=cancel"
            prompt_input "Choice: "; read aux_choice

            case "$aux_choice" in
                1) [[ "$sel_doge" == "true" ]] && sel_doge="false" || sel_doge="true" ;;
                2) [[ "$sel_pep" == "true" ]] && sel_pep="false" || sel_pep="true" ;;
                a|A)
                    sel_doge="true"; sel_pep="true"
                    ;;
                c|C)
                    # Confirm selection - need at least one aux chain
                    if [[ "$sel_doge" == "false" ]] && [[ "$sel_pep" == "false" ]]; then
                        echo -e "  ${RED}Please select at least one aux chain${NC}"
                        continue
                    fi
                    break
                    ;;
                q|Q)
                    echo -e "  ${WHITE}Merge mining cancelled${NC}"
                    return
                    ;;
                *)
                    echo -e "  ${RED}Invalid choice${NC}"
                    ;;
            esac
            echo ""
        done

        # Apply selections — use algo-specific variable to prevent overwrite
        MERGE_MINING_ENABLED="true"
        MERGE_MINING_AUX_CHAINS_SCRYPT=""

        [[ "$sel_doge" == "true" ]] && { ENABLE_DOGE="true"; MERGE_MINING_AUX_CHAINS_SCRYPT="${MERGE_MINING_AUX_CHAINS_SCRYPT}DOGE,"; }
        [[ "$sel_pep" == "true" ]] && { ENABLE_PEP="true"; MERGE_MINING_AUX_CHAINS_SCRYPT="${MERGE_MINING_AUX_CHAINS_SCRYPT}PEP,"; }

        # Remove trailing comma
        MERGE_MINING_AUX_CHAINS_SCRYPT="${MERGE_MINING_AUX_CHAINS_SCRYPT%,}"

        # Check if SHA-256d merge mining was already enabled (BTC+LTC dual mode)
        if [[ "$MERGE_MINING_ALGO" == "sha256d" ]]; then
            # Upgrade to dual-algo mode — preserve SHA-256d settings already stored
            MERGE_MINING_ALGO="both"
            MERGE_MINING_PARENT="BTC,LTC"
            log "Upgraded to dual merge mining: BTC (SHA-256d) + LTC (Scrypt)"
        else
            MERGE_MINING_ALGO="scrypt"
            MERGE_MINING_PARENT="LTC"
            # Set legacy variable for single-algo compatibility
            MERGE_MINING_AUX_CHAINS="$MERGE_MINING_AUX_CHAINS_SCRYPT"
        fi

        echo ""
        echo -e "  ${GREEN}✓${NC} Merge mining enabled: Litecoin + ${MERGE_MINING_AUX_CHAINS_SCRYPT} (Scrypt)"
        log "Merge mining enabled: LTC + ${MERGE_MINING_AUX_CHAINS_SCRYPT} (Scrypt)"
    fi
}

# ═══════════════════════════════════════════════════════════════════════════════
# HIGH AVAILABILITY MODE SELECTION
# ═══════════════════════════════════════════════════════════════════════════════

select_ha_mode() {
    clear
    log_step "High Availability Configuration"

    echo ""
    echo -e "${WHITE}Do you want to set up High Availability (HA) for this pool?${NC}"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${GREEN}1)${NC} ${WHITE}Standalone Mode${NC} ${GREEN}(Recommended for Single Server)${NC}"
    echo ""
    echo -e "     Single server setup - no failover."
    echo -e "     Simplest configuration, suitable for most users."
    echo ""
    echo -e "     ${WHITE}Best for:${NC}"
    echo -e "       • Home miners with one server"
    echo -e "       • Testing and development"
    echo -e "       • Small-scale solo mining"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${GREEN}2)${NC} ${WHITE}HA Cluster - Primary Node${NC} ${YELLOW}(Install This FIRST)${NC}"
    echo ""
    echo -e "     This server will be the PRIMARY in an HA cluster."
    echo -e "     Miners connect to a Virtual IP (VIP) that floats between nodes."
    echo ""
    echo -e "     ${RED}► INSTALL ORDER: Run this installer on Primary FIRST, then Backup(s)${NC}"
    echo ""
    echo -e "     ${WHITE}Features:${NC}"
    echo -e "       • Automatic failover if this node fails"
    echo -e "       • Virtual IP for seamless miner experience"
    echo -e "       • PostgreSQL streaming replication"
    echo -e "       • Reduced downtime during planned maintenance"
    echo -e "       • Supports 2+ nodes (3, 5, 7 recommended for etcd quorum)"
    echo ""
    echo -e "     ${WHITE}Requirements (must be completed BEFORE selecting this option):${NC}"
    echo -e "       • ${YELLOW}You must know the IP address of at least one Backup server${NC}"
    echo -e "       • All servers on the same subnet, powered on with OS installed"
    echo -e "       • ${YELLOW}All servers must have static IPs or DHCP reservations configured${NC}"
    echo -e "       • An unused IP address for the VIP — either exclude it from your"
    echo -e "         DHCP pool, or reserve it using the placeholder MAC shown during install"
    echo ""
    echo -e "     ${DIM}You can add additional Backup nodes later. Install Spiral Pool on the new${NC}"
    echo -e "     ${DIM}server, then run: ${NC}${CYAN}sudo spiralctl ha enable --vip <VIP> --token <token> --priority <N>${NC}"
    echo -e "     ${DIM}See: ${NC}${CYAN}sudo spiralctl ha setup${NC}${DIM} for full instructions.${NC}"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${GREEN}3)${NC} ${WHITE}HA Cluster - Backup Node${NC} ${YELLOW}(Install After Primary)${NC}"
    echo ""
    echo -e "     This server will be a BACKUP node in an existing HA cluster."
    echo ""
    echo -e "     ${RED}► IMPORTANT: Primary must be fully installed BEFORE running this!${NC}"
    echo -e "     ${RED}  Wait for Primary installation to complete and show the cluster token.${NC}"
    echo ""
    echo -e "     ${WHITE}Features:${NC}"
    echo -e "       • Automatic promotion if Primary fails"
    echo -e "       • Real-time database replication from Primary"
    echo -e "       • Takes over VIP when Primary is unavailable"
    echo ""
    echo -e "     ${WHITE}Requirements (must be completed BEFORE selecting this option):${NC}"
    echo -e "       • Primary node fully installed (PostgreSQL running)"
    echo -e "       • Cluster token from Primary installation output"
    echo -e "       • ${YELLOW}You must know the Primary server's IP address${NC}"
    echo -e "       • ${YELLOW}This server must have a static IP or DHCP reservation configured${NC}"
    echo -e "       • Network access to Primary (ports 5432, 2379-2380, 5354, 5363, 8008, VRRP)"
    echo -e "       • Blockchain does NOT need to be synced on Primary"
    echo ""
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""

    while true; do
        prompt_input "Enter choice (1-3) [default: 1]: "; read ha_choice
        ha_choice=${ha_choice:-1}
        case $ha_choice in
            1)
                HA_MODE="standalone"
                HA_ENABLED="false"
                log "Selected: Standalone Mode (Single Server)"
                echo ""
                echo -e "  ${GREEN}✓${NC} Single server installation, no HA configuration"
                break
                ;;
            2)
                HA_MODE="ha-master"
                HA_ENABLED="true"
                log "Selected: HA Cluster - Primary Node"
                echo ""
                collect_ha_primary_config
                break
                ;;
            3)
                HA_MODE="ha-backup"
                HA_ENABLED="true"
                log "Selected: HA Cluster - Backup Node"
                echo ""
                collect_ha_backup_config
                break
                ;;
            *)
                echo -e "  ${RED}Please enter 1, 2, or 3${NC}"
                ;;
        esac
    done
    echo ""
}

# Collect configuration for HA Primary node
collect_ha_primary_config() {
    echo ""
    log_step "HA Primary Node Configuration"

    # ════════════════════════════════════════════════════════════════════════════
    # PRE-FLIGHT CHECK: Ensure the operator has everything ready
    # ════════════════════════════════════════════════════════════════════════════
    echo ""
    echo -e "${RED}╔══════════════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${RED}║${NC}  ${WHITE}PRE-FLIGHT CHECKLIST - Read carefully before continuing${NC}                 ${RED}║${NC}"
    echo -e "${RED}╠══════════════════════════════════════════════════════════════════════════╣${NC}"
    echo -e "${RED}║${NC}                                                                          ${RED}║${NC}"
    echo -e "${RED}║${NC}  You MUST have the following ready before proceeding:                    ${RED}║${NC}"
    echo -e "${RED}║${NC}                                                                          ${RED}║${NC}"
    echo -e "${RED}║${NC}    1. ${YELLOW}Backup server IP address${NC}                                           ${RED}║${NC}"
    echo -e "${RED}║${NC}       The second server must be powered on with Ubuntu installed.        ${RED}║${NC}"
    echo -e "${RED}║${NC}       Run 'ip addr show ens33' on it to get the IP.                      ${RED}║${NC}"
    echo -e "${RED}║${NC}                                                                          ${RED}║${NC}"
    echo -e "${RED}║${NC}    2. ${YELLOW}DHCP reservations configured in your router${NC}                        ${RED}║${NC}"
    echo -e "${RED}║${NC}       Both servers (Primary + Backup) must have DHCP reservations        ${RED}║${NC}"
    echo -e "${RED}║${NC}       or static IPs so their addresses never change.                     ${RED}║${NC}"
    echo -e "${RED}║${NC}                                                                          ${RED}║${NC}"
    echo -e "${RED}║${NC}    3. ${YELLOW}An unused IP address for the Virtual IP (VIP)${NC}                      ${RED}║${NC}"
    echo -e "${RED}║${NC}       Pick an IP on the same subnet that is NOT used by any device.      ${RED}║${NC}"
    echo -e "${RED}║${NC}       To prevent DHCP conflicts, do ONE of the following:               ${RED}║${NC}"
    echo -e "${RED}║${NC}         ${YELLOW}Option A:${NC} Exclude the VIP IP from your router's DHCP pool        ${RED}║${NC}"
    echo -e "${RED}║${NC}         ${YELLOW}Option B:${NC} Create a DHCP reservation using the placeholder       ${RED}║${NC}"
    echo -e "${RED}║${NC}                   MAC address generated during install                  ${RED}║${NC}"
    echo -e "${RED}║${NC}                                                                          ${RED}║${NC}"
    echo -e "${RED}║${NC}       ${DIM}The VIP uses the physical MAC of whichever node is master.${NC}        ${RED}║${NC}"
    echo -e "${RED}║${NC}       ${DIM}The placeholder MAC just reserves the IP in your router.${NC}          ${RED}║${NC}"
    echo -e "${RED}║${NC}                                                                          ${RED}║${NC}"
    echo -e "${RED}║${NC}  ${DIM}If any of these are not ready, press Ctrl+C to exit and prepare.${NC}        ${RED}║${NC}"
    echo -e "${RED}║${NC}                                                                          ${RED}║${NC}"
    echo -e "${RED}║${NC}  ${YELLOW}NOTE: Spiral Pool is IPv4-only. IPv6 is not supported.${NC}                  ${RED}║${NC}"
    echo -e "${RED}╚══════════════════════════════════════════════════════════════════════════╝${NC}"
    echo ""

    prompt_input "Do you have all of the above ready? [y/N]: "; read preflight_confirmed
    if [[ "$preflight_confirmed" != "y" ]] && [[ "$preflight_confirmed" != "Y" ]]; then
        echo ""
        log_warn "Please prepare the following before running HA setup:"
        echo -e "  1. Power on both servers and install Ubuntu 24.04 on each"
        echo -e "  2. Set DHCP reservations in your router for both server MAC addresses"
        echo -e "  3. Choose an unused IP for the VIP, then either:"
        echo -e "     a) Exclude it from your DHCP pool, OR"
        echo -e "     b) Reserve it with the placeholder MAC shown during install"
        echo -e "  4. Run this installer again when ready"
        echo ""
        exit 0
    fi
    echo ""

    # Detect network interface
    local default_iface
    default_iface=$(ip route get 1.1.1.1 2>/dev/null | grep -oP 'dev \K\S+' | head -1)
    if [[ -z "$default_iface" ]]; then
        default_iface=$(ip link show 2>/dev/null | grep -E '^[0-9]+:' | grep -v 'lo:' | head -1 | cut -d: -f2 | tr -d ' ')
    fi

    echo -e "${CYAN}Network Interface for VIP${NC}"
    echo "The Virtual IP will be bound to this interface."
    echo ""
    # Show available interfaces
    echo "Available interfaces:"
    ip -br addr show 2>/dev/null | grep -v '^lo' | while read -r line; do
        iface=$(echo "$line" | awk '{print $1}')
        ip_addr=$(echo "$line" | awk '{print $3}' | cut -d/ -f1)
        echo -e "  • ${GREEN}$iface${NC}: $ip_addr"
    done
    echo ""
    echo -e "Default: ${GREEN}$default_iface${NC}"
    prompt_input "Network interface (or Enter for default): "; read custom_iface
    if [[ -n "$custom_iface" ]]; then
        VIP_INTERFACE="$custom_iface"
    else
        VIP_INTERFACE="$default_iface"
    fi
    log "VIP interface: $VIP_INTERFACE"
    echo ""

    # Detect subnet for VIP suggestion
    local current_ip
    local suggested_vip
    current_ip=$(ip -4 addr show "$VIP_INTERFACE" 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.\d+){3}' | head -1)
    if [[ -n "$current_ip" ]]; then
        # Suggest .200 in the same subnet
        suggested_vip=$(echo "$current_ip" | cut -d. -f1-3).200
    else
        suggested_vip=""
    fi

    echo -e "${CYAN}Virtual IP Address (VIP)${NC}"
    echo "This IP will float between Primary and Backup nodes."
    echo -e "${YELLOW}IMPORTANT: Choose an IP that is NOT in use by any device!${NC}"
    echo -e "${YELLOW}To prevent DHCP conflicts, do one of the following in your router:${NC}"
    echo -e "  ${YELLOW}Option A:${NC} Exclude this IP from your DHCP pool"
    echo -e "  ${YELLOW}Option B:${NC} Create a DHCP reservation using the placeholder MAC shown next"
    echo -e "${DIM}The VIP uses the master node's physical MAC — the placeholder just reserves the IP.${NC}"
    echo -e "${DIM}(IPv4 only — IPv6 is not supported)${NC}"
    echo ""
    if [[ -n "$suggested_vip" ]]; then
        echo -e "Suggested VIP: ${GREEN}$suggested_vip${NC}"
        echo "(Based on your current IP: $current_ip)"
    fi
    echo ""

    while true; do
        if [[ -n "$suggested_vip" ]]; then
            prompt_input "VIP address [$suggested_vip]: "; read custom_vip
            custom_vip=${custom_vip:-$suggested_vip}
        else
            prompt_input "VIP address: "; read custom_vip
        fi

        if [[ "$custom_vip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
            # Check if VIP is in use
            if ping -c 1 -W 1 "$custom_vip" &>/dev/null; then
                echo -e "  ${YELLOW}Warning: $custom_vip appears to be in use!${NC}"
                prompt_input "Use anyway? [y/N]: "; read use_anyway
                if [[ "$use_anyway" =~ ^[Yy] ]]; then
                    VIP_ADDRESS="$custom_vip"
                    break
                fi
            else
                VIP_ADDRESS="$custom_vip"
                break
            fi
        else
            echo -e "  ${RED}Invalid IP format. Please enter a valid IPv4 address.${NC}"
        fi
    done
    log "VIP address: $VIP_ADDRESS"
    echo ""

    # VIP Netmask
    echo -e "${CYAN}VIP Netmask${NC}"
    echo -e "CIDR prefix for the VIP address (32 = recommended, single-IP route)"
    echo -e "Default: ${GREEN}32${NC}"
    prompt_input "Netmask [32]: "; read custom_netmask
    if [[ -n "$custom_netmask" ]] && [[ "$custom_netmask" =~ ^[0-9]+$ ]] && [[ "$custom_netmask" -ge 8 ]] && [[ "$custom_netmask" -le 32 ]]; then
        VIP_NETMASK="$custom_netmask"
    fi
    log "VIP netmask: /$VIP_NETMASK"
    echo ""

    # Ask for peer node IPs for Patroni/etcd cluster (supports N peers)
    echo -e "${CYAN}Peer Node IP Addresses${NC}"
    echo "Enter the IP address of at least one Backup server."
    echo "This is needed for etcd cluster, Patroni, and PostgreSQL replication."
    echo ""
    echo -e "${DIM}Each peer needs a static IP or DHCP reservation. IPv4 only.${NC}"
    echo -e "${DIM}If you don't know the IPs yet, set up each server's OS first, note their IPs (ip addr)${NC}"
    echo -e "${DIM}and adapter name, then come back.${NC}"
    echo ""
    echo -e "${DIM}You only need to enter the peers you have ready now. Additional Backup nodes can be${NC}"
    echo -e "${DIM}added later — install Spiral Pool on the new server, then run on it:${NC}"
    echo -e "${CYAN}    sudo spiralctl ha enable --vip <VIP> --token <token> --priority <N>${NC}"
    echo ""
    HA_PEER_IPS=()
    local peer_count=0
    while true; do
        local prompt_label="Peer node IP address"
        if [[ $peer_count -gt 0 ]]; then
            prompt_label="Additional peer IP (Enter to finish)"
        fi
        prompt_input "${prompt_label}: "; read peer_node_ip

        # Allow empty input after first peer to finish
        if [[ -z "$peer_node_ip" ]] && [[ $peer_count -gt 0 ]]; then
            break
        fi

        if [[ "$peer_node_ip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
            # Reject this node's own IP — peer must be a DIFFERENT server
            local own_ips
            own_ips=$(hostname -I 2>/dev/null || ip -4 addr show | grep -oP 'inet \K[0-9.]+' 2>/dev/null || true)
            if echo "$own_ips" | grep -qw "$peer_node_ip"; then
                echo -e "  ${RED}That is THIS server's IP address. Enter the BACKUP server's IP.${NC}"
                continue
            fi
            # Reject the VIP address — peer must be a real node IP
            if [[ "$peer_node_ip" == "$VIP_ADDRESS" ]]; then
                echo -e "  ${RED}That is the VIP address. Enter the backup server's real IP (not the VIP).${NC}"
                continue
            fi
            # Check for duplicate
            local is_dup=false
            for existing_ip in "${HA_PEER_IPS[@]}"; do
                if [[ "$existing_ip" == "$peer_node_ip" ]]; then
                    is_dup=true
                    break
                fi
            done
            if [[ "$is_dup" == "true" ]]; then
                echo -e "  ${YELLOW}IP already added. Enter a different address.${NC}"
                continue
            fi
            HA_PEER_IPS+=("$peer_node_ip")
            peer_count=$((peer_count + 1))
            echo -e "  ${GREEN}✓${NC} Added peer: $peer_node_ip (${peer_count} peer(s) total)"
            echo ""

            prompt_input "Add another peer? [y/N]: "; read add_more
            if [[ ! "$add_more" =~ ^[Yy] ]]; then
                break
            fi
        else
            if [[ -z "$peer_node_ip" ]] && [[ $peer_count -eq 0 ]]; then
                echo -e "  ${RED}At least one peer IP is required.${NC}"
            else
                echo -e "  ${RED}Invalid IP format. Please enter a valid IPv4 address.${NC}"
            fi
        fi
    done

    # Build CSV and backward-compat scalar
    HA_PEER_IPS_CSV=$(IFS=','; echo "${HA_PEER_IPS[*]}")
    HA_PEER_IP="${HA_PEER_IPS[0]}"

    # etcd quorum warning: even total node count > 2
    local total_nodes=$(( ${#HA_PEER_IPS[@]} + 1 ))  # peers + this node
    if [[ $((total_nodes % 2)) -eq 0 ]] && [[ $total_nodes -gt 2 ]]; then
        echo ""
        echo -e "  ${YELLOW}⚠ WARNING: Cluster has $total_nodes nodes (even number).${NC}"
        echo -e "  ${YELLOW}  etcd recommends an odd number of nodes (3, 5, 7) for optimal quorum.${NC}"
        echo -e "  ${YELLOW}  With $total_nodes nodes, quorum requires $((total_nodes / 2 + 1)) — same as $((total_nodes + 1)) nodes.${NC}"
    fi

    log "Peer IPs: ${HA_PEER_IPS[*]} (${#HA_PEER_IPS[@]} peer(s))"
    echo ""

    # Generate cluster token
    HA_CLUSTER_TOKEN="spiral-$(LC_ALL=C tr -dc 'a-f0-9' < /dev/urandom | head -c 64)"
    log "Generated cluster token (save this for the Backup node!)"
    # Generate deterministic placeholder MAC for DHCP reservation (format: 02:53:XX:XX:XX:XX)
    # 02 = locally administered, 53 = "S" for Spiral
    # Note: This MAC is NOT applied to any interface — it's only used as a DHCP placeholder.
    # The VIP uses the physical MAC of whichever node is currently master via keepalived.
    IFS='.' read -r o1 o2 o3 o4 <<< "$VIP_ADDRESS"
    VIP_MAC=$(printf "02:53:%02x:%02x:%02x:%02x" "$o1" "$o2" "$o3" "$o4")
    log "VIP placeholder MAC: $VIP_MAC (for DHCP reservation only)"

    echo ""
    # Box inner width is 75 chars (between the two ║ chars)
    # We build each line carefully: "║ " + content + padding + " ║"
    # Inner content area = 73 visible chars

    # Helper to create a padded line (text only, no ANSI)
    # Args: visible_text, total_width
    # Outputs: text + spaces to fill width
    box_line() {
        local text="$1"
        local width="${2:-73}"
        local text_len=${#text}
        local pad_len=$((width - text_len))
        if [[ $pad_len -lt 0 ]]; then pad_len=0; fi
        printf "%s%*s" "$text" "$pad_len" ""
    }

    # Token is 71 chars, fits in 73 char content area
    local token_line=$(box_line " $HA_CLUSTER_TOKEN" 73)
    local vip_line=$(box_line " VIP Address: $VIP_ADDRESS" 73)
    local mac_line=$(box_line " VIP MAC:     $VIP_MAC (placeholder for DHCP)" 73)
    local mac_bullet=$(box_line "   • MAC: $VIP_MAC" 73)
    local ip_bullet=$(box_line "   • IP:  $VIP_ADDRESS" 73)

    echo -e "  ${YELLOW}╔═══════════════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "  ${YELLOW}║${NC}  IMPORTANT: Save this info for installing the Backup node!                ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}╠═══════════════════════════════════════════════════════════════════════════╣${NC}"
    echo -e "  ${YELLOW}║${NC}                                                                           ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC}  Cluster Token:                                                           ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC} ${CYAN}${token_line}${NC} ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC}                                                                           ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC} ${GREEN}${vip_line}${NC} ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC} ${CYAN}${mac_line}${NC} ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC}                                                                           ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}╠═══════════════════════════════════════════════════════════════════════════╣${NC}"
    echo -e "  ${YELLOW}║${NC}  ROUTER SETUP — do ONE of the following to prevent DHCP conflicts:        ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC}                                                                           ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC}  ${WHITE}Option A:${NC} Exclude the VIP IP from your router's DHCP pool               ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC}  ${WHITE}Option B:${NC} Create a DHCP reservation with this placeholder MAC:          ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC} ${CYAN}${mac_bullet}${NC} ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC} ${GREEN}${ip_bullet}${NC} ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC}  ${DIM}The VIP uses the physical MAC of whichever node is currently master.${NC}     ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC}  ${DIM}This placeholder MAC just reserves the IP so nothing else takes it.${NC}      ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}║${NC}                                                                           ${YELLOW}║${NC}"
    echo -e "  ${YELLOW}╚═══════════════════════════════════════════════════════════════════════════╝${NC}"
    echo ""

    # Confirm the user has saved the token before continuing
    local token_confirmed=""
    while [[ "$token_confirmed" != "y" ]]; do
        echo -ne "  ${YELLOW}Have you saved the cluster token and VIP info above? [y/N]:${NC} "
        read -r token_confirmed
        token_confirmed=$(echo "$token_confirmed" | tr '[:upper:]' '[:lower:]')
        if [[ "$token_confirmed" != "y" ]]; then
            echo -e "  ${CYAN}Please copy or screenshot the information above before continuing.${NC}"
            echo ""
        fi
    done
    echo ""

    # Primary priority is 100 (highest)
    HA_NODE_PRIORITY=100

    # Generate PostgreSQL passwords for HA/Patroni
    DB_REPLICATION_PASSWORD=$(generate_password)
    log "Generated PostgreSQL replication password"

    # Generate postgres superuser password for Patroni management
    POSTGRES_SUPERUSER_PASSWORD=$(generate_password)
    log "Generated PostgreSQL superuser password (for Patroni)"

    log "HA peer IPs saved: ${HA_PEER_IPS[*]}"

    echo ""
    echo -e "  ${GREEN}✓${NC} HA Primary configuration complete"
    echo -e "     • VIP: $VIP_ADDRESS/$VIP_NETMASK on $VIP_INTERFACE"
    echo -e "     • Peers: ${HA_PEER_IPS[*]}"
    echo -e "     • Priority: 100 (Primary)"
    echo -e "     • PostgreSQL replication: Enabled"
    echo ""
    prompt_input "Press Enter to continue..."; read
}

# ═══════════════════════════════════════════════════════════════════════════════
# AUTOMATED SSH KEY SETUP FOR HA REPLICATION
# ═══════════════════════════════════════════════════════════════════════════════

# Sets up passwordless SSH from backup node to primary for ha-replicate.sh
# Uses sshpass for automated key deployment (avoids manual ssh-copy-id)
#
# Arguments:
#   $1 - Primary node IP address
#   $2 - Password for spiraluser on primary (replication password is used)
setup_ha_ssh_keys() {
    local primary_ip="$1"
    local ssh_password="$2"
    local ssh_key_path="/home/${POOL_USER}/.ssh/id_ed25519"
    local ssh_dir="/home/${POOL_USER}/.ssh"

    # Ensure sshpass is installed for automated key copy
    if ! command -v sshpass &>/dev/null; then
        log "Installing sshpass for automated SSH key setup..."
        sudo apt-get update -qq || true
        sudo apt-get install -y -qq sshpass || { log_warn "Failed to install sshpass — manual SSH key setup may be required"; }
    fi

    # Ensure .ssh directory exists
    if [[ ! -d "$ssh_dir" ]]; then
        log "Creating SSH directory for ${POOL_USER}..."
        sudo -u "$POOL_USER" mkdir -p "$ssh_dir"
    fi
    # Always ensure correct ownership/permissions (fixes issues from previous runs)
    sudo chown "${POOL_USER}:${POOL_USER}" "$ssh_dir"
    sudo chmod 700 "$ssh_dir"

    # Check if key exists (as root to avoid permission issues with existing files)
    if [[ -f "$ssh_key_path" ]]; then
        # Fix ownership on existing key files
        sudo chown "${POOL_USER}:${POOL_USER}" "$ssh_key_path"
        sudo chmod 600 "$ssh_key_path"
        [[ -f "${ssh_key_path}.pub" ]] && sudo chown "${POOL_USER}:${POOL_USER}" "${ssh_key_path}.pub" && sudo chmod 644 "${ssh_key_path}.pub"
        log "Using existing SSH key: $ssh_key_path"
    else
        log "Generating SSH key for ${POOL_USER}..."
        sudo -u "$POOL_USER" ssh-keygen -t ed25519 -f "$ssh_key_path" -N "" -C "spiralpool-ha-replication" -q
        log_success "SSH key generated: $ssh_key_path"
    fi

    # Copy SSH key to primary node using sshpass
    log "Copying SSH key to primary node (${primary_ip})..."

    # First, test if we already have passwordless access
    if sudo -u "$POOL_USER" ssh -o BatchMode=yes -o ConnectTimeout=10 -o StrictHostKeyChecking=accept-new "${POOL_USER}@${primary_ip}" "echo 'SSH OK'" &>/dev/null 2>&1; then
        log_success "SSH key already authorized on primary node"
        HA_SSH_READY=true
        return 0
    fi

    # Try to copy the key using sshpass (-e reads from SSHPASS env var,
    # avoids exposing password in process list unlike -p).
    # Must use bash -c to set SSHPASS inside the sudo context (env_reset strips it otherwise).
    local ssh_copy_result
    ssh_copy_result=$(sudo -u "$POOL_USER" bash -c \
        'SSHPASS="$1" sshpass -e ssh-copy-id -o StrictHostKeyChecking=accept-new -o ConnectTimeout=15 -i "$2" "$3"' \
        _ "$ssh_password" "${ssh_key_path}.pub" "${POOL_USER}@${primary_ip}" 2>&1) || true

    # Clear password from memory immediately after key deployment
    unset ssh_password 2>/dev/null

    # Verify SSH access works now
    if sudo -u "$POOL_USER" ssh -o BatchMode=yes -o ConnectTimeout=10 "${POOL_USER}@${primary_ip}" "echo 'SSH OK'" &>/dev/null 2>&1; then
        log_success "SSH key successfully deployed to primary node"
        HA_SSH_READY=true

        # Bidirectional SSH: fetch primary's public key so primary can SSH back to us during failback.
        # ha-master needs ha-backup SSH access for: stopping peer stratum, restarting keepalived.
        log "Setting up bidirectional SSH (primary→backup for failback)..."
        local primary_pubkey
        primary_pubkey=$(sudo -u "$POOL_USER" ssh -o BatchMode=yes -o ConnectTimeout=10 \
            "${POOL_USER}@${primary_ip}" "cat /home/${POOL_USER}/.ssh/id_ed25519.pub" 2>/dev/null || echo "")
        if [[ -n "$primary_pubkey" ]]; then
            local auth_keys="$ssh_dir/authorized_keys"
            if ! grep -qF "$primary_pubkey" "$auth_keys" 2>/dev/null; then
                echo "$primary_pubkey" | sudo tee -a "$auth_keys" > /dev/null
                sudo chown "${POOL_USER}:${POOL_USER}" "$auth_keys"
                sudo chmod 600 "$auth_keys"
                log_success "Primary's SSH key added to local authorized_keys (bidirectional SSH ready)"
            else
                log "Primary's SSH key already in local authorized_keys"
            fi
        else
            log_warn "Could not fetch primary's SSH public key — failback SSH may need manual setup"
            log_warn "  Fix: Copy primary's /home/${POOL_USER}/.ssh/id_ed25519.pub to backup's authorized_keys"
        fi

        # SSH Mesh: Set up SSH between this backup and other existing backup nodes.
        # Discovers other cluster members via etcd on the primary, then relays SSH
        # keys through the primary (which already has bidirectional access to all backups).
        # For 2-node: etcd member list only has primary + self → loop runs 0 times → no-op.
        log "Checking for other backup nodes to set up SSH mesh..."
        local mesh_auth_keys="$ssh_dir/authorized_keys"
        local local_pub_key
        local_pub_key=$(sudo cat "${ssh_key_path}.pub" 2>/dev/null || echo "")
        if [[ -n "$local_pub_key" ]]; then
            # Get all member IPs from primary's etcd (primary has etcd running with the cluster state)
            local member_ips
            member_ips=$(sudo -u "$POOL_USER" ssh -o BatchMode=yes -o ConnectTimeout=10 \
                "${POOL_USER}@${primary_ip}" \
                "ETCDCTL_API=3 etcdctl member list --write-out=simple 2>/dev/null | grep -oP '[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+' | sort -u" 2>/dev/null || echo "")

            if [[ -n "$member_ips" ]]; then
                # Determine our own IPs so we can skip self
                local my_ips
                my_ips=$(ip -4 addr show 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.\d+){3}' || echo "")

                local mesh_count=0
                while IFS= read -r member_ip; do
                    [[ -z "$member_ip" ]] && continue
                    # Skip self
                    if echo "$my_ips" | grep -qx "$member_ip"; then
                        continue
                    fi
                    # Skip primary (already have bidirectional SSH)
                    if [[ "$member_ip" == "$primary_ip" ]]; then
                        continue
                    fi

                    log "Setting up SSH mesh with peer backup at ${member_ip}..."

                    # 1. Push our pubkey to the peer via primary relay
                    if sudo -u "$POOL_USER" ssh -o BatchMode=yes -o ConnectTimeout=10 \
                        "${POOL_USER}@${primary_ip}" \
                        "ssh -o BatchMode=yes -o ConnectTimeout=10 -o StrictHostKeyChecking=accept-new \
                         ${POOL_USER}@${member_ip} \
                         'grep -qF \"${local_pub_key}\" ~/.ssh/authorized_keys 2>/dev/null || echo \"${local_pub_key}\" >> ~/.ssh/authorized_keys'" 2>/dev/null; then
                        log_success "Our key pushed to ${member_ip}"
                    else
                        log_warn "Could not push SSH key to ${member_ip} — direct peer failback may need manual SSH setup"
                        continue
                    fi

                    # 2. Fetch peer's pubkey via primary relay and add to our authorized_keys
                    local peer_pub_key
                    peer_pub_key=$(sudo -u "$POOL_USER" ssh -o BatchMode=yes -o ConnectTimeout=10 \
                        "${POOL_USER}@${primary_ip}" \
                        "ssh -o BatchMode=yes -o ConnectTimeout=10 ${POOL_USER}@${member_ip} \
                         'cat ~/.ssh/id_ed25519.pub 2>/dev/null'" 2>/dev/null || echo "")
                    if [[ -n "$peer_pub_key" ]]; then
                        if ! grep -qF "$peer_pub_key" "$mesh_auth_keys" 2>/dev/null; then
                            echo "$peer_pub_key" | sudo tee -a "$mesh_auth_keys" > /dev/null
                            sudo chown "${POOL_USER}:${POOL_USER}" "$mesh_auth_keys"
                            sudo chmod 600 "$mesh_auth_keys"
                            log_success "Peer ${member_ip}'s key added to local authorized_keys"
                        else
                            log "Peer ${member_ip}'s key already in local authorized_keys"
                        fi
                        mesh_count=$((mesh_count + 1))
                    else
                        log_warn "Could not fetch SSH key from ${member_ip} — direct peer SSH may need manual setup"
                    fi

                    # 3. Accept the peer's host key so direct SSH works without prompts
                    sudo -u "$POOL_USER" ssh -o StrictHostKeyChecking=accept-new -o ConnectTimeout=5 \
                        "${POOL_USER}@${member_ip}" "echo 'mesh-ok'" &>/dev/null 2>&1 || true

                done <<< "$member_ips"
                if [[ $mesh_count -gt 0 ]]; then
                    log_success "SSH mesh set up with ${mesh_count} other backup node(s)"
                else
                    log "No other backup nodes found — SSH mesh not needed (2-node cluster)"
                fi
            else
                log "Could not query etcd member list on primary — SSH mesh skipped (2-node cluster likely)"
            fi
        fi
    else
        log_warn "Could not automatically set up SSH key access"
        log_warn "Possible reasons:"
        log_warn "  • Incorrect password"
        log_warn "  • SSH password authentication disabled on primary"
        log_warn "  • Network/firewall issues"
        echo ""
        log_warn "You can manually set up SSH keys later:"
        log_warn "  sudo -u ${POOL_USER} ssh-copy-id ${POOL_USER}@${primary_ip}"
        echo ""
        HA_SSH_READY=false
    fi
}

# Update existing HA peers with this node's IP (UFW + pg_hba)
# When a new node joins an existing cluster, the existing peers don't know about
# the new node's IP. This function SCPs ha-add-peer.sh to each peer and runs it
# so the peer's firewall and Patroni pg_hba are updated automatically.
#
# Called after setup_ha_ssh_keys() — requires SSH access to peers.
# Non-fatal: failures are logged as warnings with manual remediation steps.
update_existing_peers() {
    local our_ip="$SERVER_IP"

    if [[ -z "$our_ip" ]] || [[ "$our_ip" == "YOUR_SERVER_IP" ]]; then
        log_warn "SERVER_IP not set — cannot update existing peers"
        return 0
    fi

    if [[ ${#HA_PEER_IPS[@]} -eq 0 ]]; then
        log "No peer IPs configured — skipping peer update"
        return 0
    fi

    local ssh_key="/home/${POOL_USER}/.ssh/id_ed25519"
    local ssh_opts="-o StrictHostKeyChecking=accept-new -o BatchMode=yes -o ConnectTimeout=10"
    if [[ -f "$ssh_key" ]]; then
        ssh_opts="$ssh_opts -i $ssh_key"
    fi

    local updated=0
    local failed=0

    log "Updating existing peers with this node's IP (${our_ip})..."

    for peer_ip in "${HA_PEER_IPS[@]}"; do
        [[ -z "$peer_ip" ]] && continue

        # Test SSH connectivity first
        if ! sudo -u "$POOL_USER" ssh $ssh_opts "${POOL_USER}@${peer_ip}" "echo ok" &>/dev/null; then
            log_warn "Cannot SSH to ${peer_ip} — peer firewall/pg_hba must be updated manually:"
            log_warn "  On ${peer_ip}, run: sudo /spiralpool/scripts/ha-add-peer.sh ${our_ip}"
            log_warn "  Or manually: sudo ufw allow from ${our_ip} to any port 5432 proto tcp"
            failed=$((failed + 1))
            continue
        fi

        # Run ha-add-peer.sh on the peer to add our IP to its firewall/pg_hba.
        # The peer already has the script from its own install — just execute it.
        # sudo is needed because the script modifies UFW rules and patroni.yml.
        local ssh_output
        if ssh_output=$(sudo -u "$POOL_USER" ssh $ssh_opts "${POOL_USER}@${peer_ip}" \
            "sudo /spiralpool/scripts/ha-add-peer.sh ${our_ip}" 2>&1); then
            log_success "Peer ${peer_ip} updated with our IP (${our_ip})"
            updated=$((updated + 1))
        else
            log_warn "ha-add-peer.sh failed on ${peer_ip}: ${ssh_output:-no output}"
            log_warn "  On ${peer_ip}, run: sudo /spiralpool/scripts/ha-add-peer.sh ${our_ip}"
            failed=$((failed + 1))
        fi
    done

    if [[ $updated -gt 0 ]]; then
        log_success "Updated ${updated} peer(s) with this node's IP"
    fi
    if [[ $failed -gt 0 ]]; then
        log_warn "${failed} peer(s) could not be updated automatically — see warnings above"
    fi

    return 0
}

# Collect configuration for HA Backup node
collect_ha_backup_config() {
    echo ""
    log_step "HA Backup Node Configuration"

    # ════════════════════════════════════════════════════════════════════════════
    # IMPORTANT WARNING: Blockchain sync requirement
    # ════════════════════════════════════════════════════════════════════════════
    echo ""
    echo -e "${YELLOW}╔══════════════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${YELLOW}║${NC}  ${WHITE}IMPORTANT: PRIMARY NODE BLOCKCHAIN SYNC REQUIREMENT${NC}                     ${YELLOW}║${NC}"
    echo -e "${YELLOW}╠══════════════════════════════════════════════════════════════════════════╣${NC}"
    echo -e "${YELLOW}║${NC}                                                                          ${YELLOW}║${NC}"
    echo -e "${YELLOW}║${NC}  Before continuing, ensure the PRIMARY node has:                         ${YELLOW}║${NC}"
    echo -e "${YELLOW}║${NC}                                                                          ${YELLOW}║${NC}"
    echo -e "${YELLOW}║${NC}    ${GREEN}✓${NC} Fully synced blockchain(s) for all enabled coins                    ${YELLOW}║${NC}"
    echo -e "${YELLOW}║${NC}    ${GREEN}✓${NC} Spiral Pool services running and healthy                            ${YELLOW}║${NC}"
    echo -e "${YELLOW}║${NC}    ${GREEN}✓${NC} PostgreSQL database operational                                     ${YELLOW}║${NC}"
    echo -e "${YELLOW}║${NC}                                                                          ${YELLOW}║${NC}"
    echo -e "${YELLOW}║${NC}  ${RED}Replicating from an incomplete primary will result in:${NC}                  ${YELLOW}║${NC}"
    echo -e "${YELLOW}║${NC}    • Incomplete blockchain data on this backup node                      ${YELLOW}║${NC}"
    echo -e "${YELLOW}║${NC}    • Extended sync time as backup catches up via P2P                     ${YELLOW}║${NC}"
    echo -e "${YELLOW}║${NC}    • Potential issues if failover occurs before sync completes           ${YELLOW}║${NC}"
    echo -e "${YELLOW}║${NC}                                                                          ${YELLOW}║${NC}"
    echo -e "${YELLOW}║${NC}  ${DIM}Check sync status on primary: spiralctl status${NC}                          ${YELLOW}║${NC}"
    echo -e "${YELLOW}╚══════════════════════════════════════════════════════════════════════════╝${NC}"
    echo ""

    prompt_input "Is the PRIMARY node fully synced and operational? [y/N]: "; read sync_confirmed
    if [[ "$sync_confirmed" != "y" ]] && [[ "$sync_confirmed" != "Y" ]]; then
        echo ""
        log_warn "Please ensure the primary node is fully synced before setting up HA backup."
        log_warn "You can run this installer again when the primary is ready."
        echo ""
        prompt_input "Continue anyway (not recommended)? [y/N]: "; read continue_anyway
        if [[ "$continue_anyway" != "y" ]] && [[ "$continue_anyway" != "Y" ]]; then
            log "HA Backup setup cancelled. Please sync primary node first."
            exit 0
        fi
        log_warn "Proceeding with unsyncced primary - backup may need additional sync time."
    fi
    echo ""

    # Variables for cluster auto-detection
    local cluster_detected=false
    local detected_vip=""
    local detected_node_count=0
    local suggested_priority=101

    echo -e "${CYAN}Primary Node IP Address${NC}"
    echo "Enter the real IP address of the PRIMARY node (not the VIP)."
    echo -e "${YELLOW}This is the IP shown by 'ip addr show ens33' on the Primary server.${NC}"
    echo -e "${DIM}(IPv4 only — IPv6 is not supported)${NC}"
    echo ""

    while true; do
        prompt_input "Primary node IP: "; read primary_ip
        if [[ "$primary_ip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
            # Try to reach the primary (ping with fallback to nc for port check)
            local is_reachable=false
            if ping -c 1 -W 2 "$primary_ip" &>/dev/null 2>&1; then
                is_reachable=true
            elif ping -c 1 -w 2 "$primary_ip" &>/dev/null 2>&1; then
                # Some systems use -w instead of -W for timeout
                is_reachable=true
            elif timeout 2 bash -c "echo >/dev/tcp/$primary_ip/22" 2>/dev/null; then
                # Fallback: check if SSH port is open (common on Linux servers)
                is_reachable=true
            elif timeout 2 bash -c "echo >/dev/tcp/$primary_ip/5354" 2>/dev/null; then
                # Fallback: check if HA API port is open
                is_reachable=true
            fi

            if [[ "$is_reachable" == "true" ]]; then
                HA_PEER_IP="$primary_ip"
                HA_PRIMARY_IP="$primary_ip"
                log "Primary node: $HA_PRIMARY_IP (reachable)"

                # Try to query the HA status API to auto-detect cluster configuration
                # Retry up to 6 times (30s total) — stratum on primary may still be
                # initializing its VIP manager after a fresh install/reboot.
                echo ""
                echo -e "${CYAN}Checking cluster status on primary node...${NC}"
                local status_response=""
                for _api_attempt in $(seq 1 6); do
                    status_response=$(curl -s --connect-timeout 5 "http://$primary_ip:5354/status" 2>/dev/null || true)
                    if [[ -n "$status_response" ]] && echo "$status_response" | grep -q '"enabled":true'; then
                        break
                    fi
                    if [[ $_api_attempt -lt 6 ]]; then
                        echo -e "  ${YELLOW}Waiting for HA API on primary... (attempt ${_api_attempt}/6)${NC}"
                        sleep 5
                    fi
                done

                if [[ -n "$status_response" ]] && echo "$status_response" | grep -q '"enabled":true'; then
                    cluster_detected=true
                    log "HA cluster detected on primary node"

                    # Extract VIP address and validate format
                    detected_vip=$(echo "$status_response" | grep -oP '"vip":"[^"]*"' | cut -d'"' -f4)
                    if [[ -n "$detected_vip" ]] && [[ "$detected_vip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
                        echo -e "  ${GREEN}✓${NC} Detected VIP: ${GREEN}$detected_vip${NC}"
                    else
                        detected_vip=""  # Invalid or missing, don't use
                    fi

                    # Count nodes to suggest next priority (sanitize to integer)
                    detected_node_count=$(echo "$status_response" | grep -oP '"priority":[0-9]+' | wc -l)
                    # Ensure it's a valid number
                    if [[ ! "$detected_node_count" =~ ^[0-9]+$ ]]; then
                        detected_node_count=0
                    fi
                    if [[ "$detected_node_count" -gt 0 ]]; then
                        suggested_priority=$((100 + detected_node_count + 1))
                        # Cap at reasonable value
                        if [[ "$suggested_priority" -gt 999 ]]; then
                            suggested_priority=999
                        fi
                        echo -e "  ${GREEN}✓${NC} Detected $detected_node_count node(s) in cluster"
                        echo -e "  ${GREEN}✓${NC} Suggested priority for this node: ${GREEN}$suggested_priority${NC}"
                    fi

                    # Check master status (only display, not used for config)
                    local master_host
                    master_host=$(echo "$status_response" | grep -oP '"masterHost":"[^"]*"' | cut -d'"' -f4)
                    # Validate master_host looks like an IP or hostname
                    if [[ -n "$master_host" ]] && [[ "$master_host" =~ ^[a-zA-Z0-9._-]+$ ]]; then
                        echo -e "  ${GREEN}✓${NC} Current master: $master_host"
                    fi
                    echo ""
                else
                    echo -e "  ${YELLOW}Note: Could not query HA status API on primary.${NC}"
                    echo -e "  ${YELLOW}The primary may not be running yet, or HA is not enabled.${NC}"
                    echo -e "  ${YELLOW}You'll need to enter cluster details manually.${NC}"
                    echo ""
                fi
                break
            else
                echo -e "  ${YELLOW}Warning: Cannot reach $primary_ip${NC}"
                prompt_input "Continue anyway? [y/N]: "; read continue_anyway
                if [[ "$continue_anyway" =~ ^[Yy] ]]; then
                    HA_PEER_IP="$primary_ip"
                    HA_PRIMARY_IP="$primary_ip"
                    break
                fi
            fi
        else
            echo -e "  ${RED}Invalid IP format. Please enter a valid IPv4 address.${NC}"
        fi
    done
    echo ""

    # Initialize peer array with primary IP
    HA_PEER_IPS=("$HA_PRIMARY_IP")

    # Prompt for additional peer IPs (other backup nodes)
    echo -e "${CYAN}Additional Peer Nodes${NC}"
    echo "If there are other backup nodes already in the cluster, enter their IPs."
    echo "This is needed for firewall rules, etcd, and pg_hba access."
    echo ""
    while true; do
        prompt_input "Additional peer IP (Enter to skip): "; read extra_peer_ip
        if [[ -z "$extra_peer_ip" ]]; then
            break
        fi
        if [[ "$extra_peer_ip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
            # Reject this node's own IP
            local own_ips
            own_ips=$(hostname -I 2>/dev/null || ip -4 addr show | grep -oP 'inet \K[0-9.]+' 2>/dev/null || true)
            if echo "$own_ips" | grep -qw "$extra_peer_ip"; then
                echo -e "  ${RED}That is THIS server's IP address. Enter a different server's IP.${NC}"
                continue
            fi
            # Check for duplicate
            local is_dup=false
            for existing_ip in "${HA_PEER_IPS[@]}"; do
                if [[ "$existing_ip" == "$extra_peer_ip" ]]; then
                    is_dup=true
                    break
                fi
            done
            if [[ "$is_dup" == "true" ]]; then
                echo -e "  ${YELLOW}IP already added. Enter a different address.${NC}"
                continue
            fi
            HA_PEER_IPS+=("$extra_peer_ip")
            echo -e "  ${GREEN}✓${NC} Added peer: $extra_peer_ip"
        else
            echo -e "  ${RED}Invalid IP format. Please enter a valid IPv4 address.${NC}"
        fi
    done

    # Build CSV and ensure backward-compat scalar points to primary
    HA_PEER_IPS_CSV=$(IFS=','; echo "${HA_PEER_IPS[*]}")
    HA_PEER_IP="$HA_PRIMARY_IP"
    log "Peer IPs: ${HA_PEER_IPS[*]} (${#HA_PEER_IPS[@]} peer(s), primary=${HA_PRIMARY_IP})"
    echo ""

    echo -e "${CYAN}Cluster Token${NC}"
    echo "Enter the cluster token from the Primary node installation."
    echo "(It starts with 'spiral-' and is 72 characters long)"
    echo ""
    echo -e "${DIM}Lost the token? Run this on the Primary node to retrieve it:${NC}"
    echo -e "${CYAN}  sudo cat /etc/keepalived/.cluster_token${NC}"
    echo ""

    while true; do
        prompt_input "Cluster token: "; read input_token
        if [[ "$input_token" =~ ^spiral-[a-f0-9]{64}$ ]]; then
            HA_CLUSTER_TOKEN="$input_token"
            log "Cluster token accepted"
            break
        else
            echo -e "  ${RED}Invalid token format. Token should be 'spiral-' followed by 64 hex characters.${NC}"
        fi
    done
    echo ""

    # VIP Address - use detected value if available
    echo -e "${CYAN}Virtual IP Address (VIP)${NC}"
    if [[ -n "$detected_vip" ]]; then
        echo -e "Detected VIP from primary: ${GREEN}$detected_vip${NC}"
        echo "(Press Enter to use detected VIP, or enter a different one)"
    else
        echo "Enter the same VIP that was configured on the Primary node."
    fi
    echo -e "${DIM}(IPv4 only — IPv6 is not supported)${NC}"
    echo ""

    while true; do
        if [[ -n "$detected_vip" ]]; then
            prompt_input "VIP address [$detected_vip]: "; read input_vip
            input_vip=${input_vip:-$detected_vip}
        else
            prompt_input "VIP address: "; read input_vip
        fi

        if [[ "$input_vip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
            VIP_ADDRESS="$input_vip"
            log "VIP address: $VIP_ADDRESS"
            break
        else
            echo -e "  ${RED}Invalid IP format. Please enter a valid IPv4 address.${NC}"
        fi
    done
    echo ""

    # Detect network interface
    local default_iface
    default_iface=$(ip route get 1.1.1.1 2>/dev/null | grep -oP 'dev \K\S+' | head -1)

    echo -e "${CYAN}Network Interface for VIP${NC}"
    echo -e "Default: ${GREEN}$default_iface${NC}"
    prompt_input "Network interface (or Enter for default): "; read custom_iface
    if [[ -n "$custom_iface" ]]; then
        VIP_INTERFACE="$custom_iface"
    else
        VIP_INTERFACE="$default_iface"
    fi
    log "VIP interface: $VIP_INTERFACE"
    echo ""

    # VIP Netmask
    echo -e "${CYAN}VIP Netmask${NC}"
    echo -e "Default: ${GREEN}32${NC}"
    prompt_input "Netmask [32]: "; read custom_netmask
    if [[ -n "$custom_netmask" ]] && [[ "$custom_netmask" =~ ^[0-9]+$ ]] && [[ "$custom_netmask" -ge 8 ]] && [[ "$custom_netmask" -le 32 ]]; then
        VIP_NETMASK="$custom_netmask"
    fi
    log "VIP netmask: /$VIP_NETMASK"
    echo ""

    # Node priority - use auto-detected suggestion if available
    echo -e "${CYAN}Node Priority${NC}"
    echo "Each node needs a unique priority for master election."
    echo "Lower number = higher priority (Primary is 100)."
    echo ""

    if [[ "$cluster_detected" == true ]] && [[ "$detected_node_count" -gt 0 ]]; then
        echo -e "  ${GREEN}Auto-detected:${NC} Cluster has $detected_node_count node(s)"
        echo -e "  ${GREEN}Recommended priority for this node: ${WHITE}$suggested_priority${NC}"
        echo ""
    else
        echo -e "  ${WHITE}Recommended priorities:${NC}"
        echo -e "    • 1st backup node: ${GREEN}101${NC}"
        echo -e "    • 2nd backup node: ${GREEN}102${NC}"
        echo -e "    • 3rd backup node: ${GREEN}103${NC}"
        echo ""
        echo -e "${YELLOW}If this is the first backup, use 101.${NC}"
        echo -e "${YELLOW}If you already have backups, use the next number.${NC}"
        echo ""
    fi

    while true; do
        prompt_input "Node priority [$suggested_priority]: "; read custom_priority
        custom_priority=${custom_priority:-$suggested_priority}
        if [[ "$custom_priority" =~ ^[0-9]+$ ]] && [[ "$custom_priority" -gt 100 ]] && [[ "$custom_priority" -le 999 ]]; then
            HA_NODE_PRIORITY="$custom_priority"
            break
        elif [[ "$custom_priority" =~ ^[0-9]+$ ]] && [[ "$custom_priority" -le 100 ]]; then
            echo -e "  ${RED}Priority must be greater than 100 (100 is reserved for Primary)${NC}"
        else
            echo -e "  ${RED}Please enter a number between 101 and 999${NC}"
        fi
    done
    log "Node priority: $HA_NODE_PRIORITY"
    echo ""

    # Generate deterministic placeholder MAC for DHCP reservation (same as primary)
    IFS='.' read -r o1 o2 o3 o4 <<< "$VIP_ADDRESS"
    VIP_MAC=$(printf "02:53:%02x:%02x:%02x:%02x" "$o1" "$o2" "$o3" "$o4")
    log "VIP placeholder MAC: $VIP_MAC (for DHCP reservation only)"

    # Replication password will be fetched from primary or set manually
    echo -e "${CYAN}PostgreSQL Passwords (from Primary)${NC}"
    echo "Enter the passwords from the Primary node."
    echo -e "Run these on the ${WHITE}Primary${NC} to retrieve them:"
    echo "  Replication:  sudo grep SPIRAL_REPLICATION_PASSWORD /etc/spiralpool/ha.env"
    echo "  Superuser:    sudo grep -A2 'superuser:' /etc/patroni/patroni.yml"
    echo "  Database:     sudo awk '/^database:/{found=1} found && /password:/{print; exit}' /spiralpool/config/config.yaml"
    echo -e "  ${DIM}Paste the raw password only — do NOT wrap in quotes.${NC}"
    echo ""
    while true; do
        prompt_input "Replication password: "; read input_repl_pass
        if [[ "$input_repl_pass" == *\"* ]] || [[ "$input_repl_pass" == *\'* ]]; then
            echo -e "  ${RED}Quotes are not allowed — paste the raw password without quotes.${NC}"
        elif [[ -z "$input_repl_pass" ]]; then
            echo -e "  ${RED}Password cannot be empty.${NC}"
        elif [[ ${#input_repl_pass} -lt 20 ]]; then
            echo -e "  ${RED}Password too short (${#input_repl_pass} chars). Expected 32-char generated password — check you pasted the full value.${NC}"
        else
            break
        fi
    done
    DB_REPLICATION_PASSWORD="$input_repl_pass"

    while true; do
        prompt_input "PostgreSQL superuser password: "; read input_superuser_pass
        if [[ "$input_superuser_pass" == *\"* ]] || [[ "$input_superuser_pass" == *\'* ]]; then
            echo -e "  ${RED}Quotes are not allowed — paste the raw password without quotes.${NC}"
        elif [[ -z "$input_superuser_pass" ]]; then
            echo -e "  ${RED}Password cannot be empty.${NC}"
        elif [[ ${#input_superuser_pass} -lt 20 ]]; then
            echo -e "  ${RED}Password too short (${#input_superuser_pass} chars). Expected 32-char generated password — check you pasted the full value.${NC}"
        else
            break
        fi
    done
    POSTGRES_SUPERUSER_PASSWORD="$input_superuser_pass"

    while true; do
        prompt_input "Database password (spiralstratum): "; read input_db_pass
        if [[ "$input_db_pass" == *\"* ]] || [[ "$input_db_pass" == *\'* ]]; then
            echo -e "  ${RED}Quotes are not allowed — paste the raw password without quotes.${NC}"
        elif [[ -z "$input_db_pass" ]]; then
            echo -e "  ${RED}Password cannot be empty.${NC}"
        elif [[ ${#input_db_pass} -lt 20 ]]; then
            echo -e "  ${RED}Password too short (${#input_db_pass} chars). Expected 32-char generated password — check you pasted the full value.${NC}"
        else
            break
        fi
    done
    DB_PASSWORD="$input_db_pass"
    echo ""

    # Collect the spiraluser system password from the primary (needed for ssh-copy-id)
    echo -e "${CYAN}SSH Access to Primary${NC}"
    echo "Enter the spiraluser Linux password that was set during Primary installation."
    echo -e "${DIM}This is the system password, not the database password.${NC}"
    echo ""
    while true; do
        prompt_input "spiraluser password (from Primary): "; read -s HA_SSH_PASSWORD; echo
        if [[ -z "$HA_SSH_PASSWORD" ]]; then
            echo -e "  ${RED}Password cannot be empty.${NC}"
            continue
        fi
        local ha_ssh_pass_confirm
        read -sp "  Confirm password: " ha_ssh_pass_confirm; echo
        if [[ "$HA_SSH_PASSWORD" != "$ha_ssh_pass_confirm" ]]; then
            echo -e "  ${RED}Passwords do not match. Please try again.${NC}"
            unset ha_ssh_pass_confirm
        else
            unset ha_ssh_pass_confirm
            break
        fi
    done
    echo ""

    # Note: SSH key setup is deferred to setup_system() — the pool user must
    # exist before any sudo -u / ssh-keygen / ssh-copy-id commands can run.

    log "HA peer IPs saved: ${HA_PEER_IPS[*]} (primary=${HA_PRIMARY_IP})"

    echo ""
    echo -e "  ${GREEN}✓${NC} HA Backup configuration complete"
    echo -e "     • Primary node: ${HA_PRIMARY_IP:-$HA_PEER_IP}"
    echo -e "     • Peers: ${HA_PEER_IPS[*]}"
    echo -e "     • VIP: $VIP_ADDRESS/$VIP_NETMASK on $VIP_INTERFACE"
    echo -e "     • VIP MAC: $VIP_MAC (placeholder for DHCP reservation)"
    echo -e "     • Priority: $HA_NODE_PRIORITY (Backup)"
    echo -e "     • PostgreSQL replication: Enabled (replica)"
    echo ""
    prompt_input "Press Enter to continue..."; read
}

# ═══════════════════════════════════════════════════════════════════════════════
# HA BACKUP — WALLET ADDRESS SYNC FROM PRIMARY
# ═══════════════════════════════════════════════════════════════════════════════

# Helper: set address variables for a given coin (both *_ADDRESS and *_POOL_ADDRESS)
_set_synced_address() {
    local coin="$1"
    local addr="$2"
    case "$coin" in
        DGB|DIGIBYTE)
            POOL_ADDRESS="$addr"
            DGB_POOL_ADDRESS="$addr"
            ;;
        DGB-SCRYPT|DIGIBYTE-SCRYPT)
            # DGB-Scrypt shares the same address as DGB
            DGB_SCRYPT_ADDRESS="$addr"
            ;;
        BTC|BITCOIN)
            BTC_ADDRESS="$addr"
            BTC_POOL_ADDRESS="$addr"
            ;;
        BCH|BITCOINCASH)
            BCH_ADDRESS="$addr"
            BCH_POOL_ADDRESS="$addr"
            ;;
        BC2|BITCOINII)
            BC2_ADDRESS="$addr"
            BC2_POOL_ADDRESS="$addr"
            ;;
        LTC|LITECOIN)
            LTC_ADDRESS="$addr"
            LTC_POOL_ADDRESS="$addr"
            ;;
        DOGE|DOGECOIN)
            DOGE_ADDRESS="$addr"
            DOGE_POOL_ADDRESS="$addr"
            ;;
        PEP|PEPECOIN)
            PEP_ADDRESS="$addr"
            PEP_POOL_ADDRESS="$addr"
            ;;
        CAT|CATCOIN)
            CAT_ADDRESS="$addr"
            CAT_POOL_ADDRESS="$addr"
            ;;
        NMC|NAMECOIN)
            NMC_ADDRESS="$addr"
            NMC_POOL_ADDRESS="$addr"
            ;;
        SYS|SYSCOIN)
            SYS_ADDRESS="$addr"
            SYS_POOL_ADDRESS="$addr"
            ;;
        XMY|MYRIADCOIN|MYRIAD)
            XMY_ADDRESS="$addr"
            XMY_POOL_ADDRESS="$addr"
            ;;
        FBTC|FRACTALBITCOIN|FRACTAL)
            FBTC_ADDRESS="$addr"
            FBTC_POOL_ADDRESS="$addr"
            ;;
    esac
}

# Helper: display all synced addresses
_display_synced_addresses() {
    local any=false
    [[ -n "$POOL_ADDRESS" ]] && echo -e "    DGB:  ${GREEN}$POOL_ADDRESS${NC}" && any=true
    [[ -n "$BTC_POOL_ADDRESS" ]] && echo -e "    BTC:  ${GREEN}$BTC_POOL_ADDRESS${NC}" && any=true
    [[ -n "$BCH_POOL_ADDRESS" ]] && echo -e "    BCH:  ${GREEN}$BCH_POOL_ADDRESS${NC}" && any=true
    [[ -n "$BC2_POOL_ADDRESS" ]] && echo -e "    BC2:  ${GREEN}$BC2_POOL_ADDRESS${NC}" && any=true
    [[ -n "$LTC_POOL_ADDRESS" ]] && echo -e "    LTC:  ${GREEN}$LTC_POOL_ADDRESS${NC}" && any=true
    [[ -n "$DOGE_POOL_ADDRESS" ]] && echo -e "    DOGE: ${GREEN}$DOGE_POOL_ADDRESS${NC}" && any=true
    [[ -n "$PEP_POOL_ADDRESS" ]] && echo -e "    PEP:  ${GREEN}$PEP_POOL_ADDRESS${NC}" && any=true
    [[ -n "$CAT_POOL_ADDRESS" ]] && echo -e "    CAT:  ${GREEN}$CAT_POOL_ADDRESS${NC}" && any=true
    [[ -n "$NMC_POOL_ADDRESS" ]] && echo -e "    NMC:  ${GREEN}$NMC_POOL_ADDRESS${NC}" && any=true
    [[ -n "$SYS_POOL_ADDRESS" ]] && echo -e "    SYS:  ${GREEN}$SYS_POOL_ADDRESS${NC}" && any=true
    [[ -n "$XMY_POOL_ADDRESS" ]] && echo -e "    XMY:  ${GREEN}$XMY_POOL_ADDRESS${NC}" && any=true
    [[ -n "$FBTC_POOL_ADDRESS" ]] && echo -e "    FBTC: ${GREEN}$FBTC_POOL_ADDRESS${NC}" && any=true
    if [[ "$any" != "true" ]]; then
        echo -e "    ${YELLOW}No addresses found on primary${NC}"
    fi
}

# Helper: check if all enabled coins have addresses after sync
_verify_synced_coverage() {
    local missing=()

    if [[ "$COIN_MODE" == "single" ]]; then
        case "$SOLO_COIN" in
            DGB|DGB-SCRYPT)  [[ -z "$POOL_ADDRESS" ]] && missing+=("DGB") ;;
            BTC)             [[ -z "$BTC_POOL_ADDRESS" ]] && missing+=("BTC") ;;
            BCH)             [[ -z "$BCH_POOL_ADDRESS" ]] && missing+=("BCH") ;;
            BC2)             [[ -z "$BC2_POOL_ADDRESS" ]] && missing+=("BC2") ;;
            LTC)             [[ -z "$LTC_POOL_ADDRESS" ]] && missing+=("LTC") ;;
            DOGE)            [[ -z "$DOGE_POOL_ADDRESS" ]] && missing+=("DOGE") ;;
            PEP)             [[ -z "$PEP_POOL_ADDRESS" ]] && missing+=("PEP") ;;
            CAT)             [[ -z "$CAT_POOL_ADDRESS" ]] && missing+=("CAT") ;;
            NMC)             [[ -z "$NMC_POOL_ADDRESS" ]] && missing+=("NMC") ;;
            XMY)             [[ -z "$XMY_POOL_ADDRESS" ]] && missing+=("XMY") ;;
            FBTC)            [[ -z "$FBTC_POOL_ADDRESS" ]] && missing+=("FBTC") ;;
            QBX)             [[ -z "$QBX_POOL_ADDRESS" ]] && missing+=("QBX") ;;
        esac
    else
        # Multi-coin: check each enabled coin (including merge-mined aux chains)
        [[ "$ENABLE_DGB" == "true" || "$ENABLE_DGB_SCRYPT" == "true" ]] && [[ -z "$POOL_ADDRESS" ]] && missing+=("DGB")
        [[ "$ENABLE_BTC" == "true" ]]  && [[ -z "$BTC_POOL_ADDRESS" ]]  && missing+=("BTC")
        [[ "$ENABLE_BCH" == "true" ]]  && [[ -z "$BCH_POOL_ADDRESS" ]]  && missing+=("BCH")
        [[ "$ENABLE_BC2" == "true" ]]  && [[ -z "$BC2_POOL_ADDRESS" ]]  && missing+=("BC2")
        [[ "$ENABLE_LTC" == "true" ]]  && [[ -z "$LTC_POOL_ADDRESS" ]]  && missing+=("LTC")
        [[ "$ENABLE_DOGE" == "true" ]] && [[ -z "$DOGE_POOL_ADDRESS" ]] && missing+=("DOGE")
        [[ "$ENABLE_PEP" == "true" ]]  && [[ -z "$PEP_POOL_ADDRESS" ]]  && missing+=("PEP")
        [[ "$ENABLE_CAT" == "true" ]]  && [[ -z "$CAT_POOL_ADDRESS" ]]  && missing+=("CAT")
        [[ "$ENABLE_NMC" == "true" ]]  && [[ -z "$NMC_POOL_ADDRESS" ]]  && missing+=("NMC")
        [[ "$ENABLE_SYS" == "true" ]]  && [[ -z "$SYS_POOL_ADDRESS" ]]  && missing+=("SYS")
        [[ "$ENABLE_XMY" == "true" ]]  && [[ -z "$XMY_POOL_ADDRESS" ]]  && missing+=("XMY")
        [[ "$ENABLE_FBTC" == "true" ]] && [[ -z "$FBTC_POOL_ADDRESS" ]] && missing+=("FBTC")
        [[ "$ENABLE_QBX" == "true" ]] && [[ -z "$QBX_POOL_ADDRESS" ]] && missing+=("QBX")
    fi

    if [[ ${#missing[@]} -gt 0 ]]; then
        echo -e "  ${YELLOW}WARNING: Primary does not have addresses for: ${missing[*]}${NC}"
        echo -e "  ${YELLOW}These coins are enabled on this backup but not configured on primary.${NC}"
        echo -e "  ${YELLOW}You will be prompted for all addresses manually.${NC}"
        echo ""
        prompt_input "Press Enter to continue with manual address entry..."; read
        return 1
    fi
    return 0
}

# Sync wallet addresses from the primary node (HA backup only)
# Works for any number of backup nodes — each independently queries the same primary.
# Supports solo (single-coin), multi-coin, and merge-mined aux chains.
sync_addresses_from_primary() {
    # Only runs on HA backup nodes
    if [[ "$HA_MODE" != "ha-backup" ]] || [[ -z "$HA_PRIMARY_IP" ]]; then
        return 1
    fi

    echo ""
    echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
    echo -e "${WHITE}Syncing Wallet Addresses from Primary Node${NC}"
    echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
    echo ""
    echo -e "  ${WHITE}Pulling wallet addresses from primary (${HA_PRIMARY_IP})...${NC}"
    echo -e "  ${DIM}This ensures all HA nodes mine to identical addresses.${NC}"
    echo ""

    local sync_method=""
    local api_response=""
    local pending_coins=()

    # ─────────────────────────────────────────────────────────────────────────
    # Method 1: Query stratum API (unauthenticated, works when stratum is running)
    # The stratum refuses to start with PENDING_GENERATION (config.go:864),
    # so all addresses from the API are guaranteed to be real.
    # ─────────────────────────────────────────────────────────────────────────
    api_response=$(curl -s --connect-timeout 10 --max-time 15 "http://$HA_PRIMARY_IP:4000/api/pools" 2>/dev/null || true)

    if [[ -n "$api_response" ]] && echo "$api_response" | grep -q '"pools"'; then
        sync_method="api"
        echo -e "  ${GREEN}✓${NC} Connected to primary stratum API"
        echo ""

        # Parse API response: {"pools": [{"coin": {"type": "BTC"}, "address": "bc1q..."}]}
        # Break JSON into lines for simple regex parsing (no jq dependency)
        local coin_type="" address=""
        while IFS= read -r line; do
            if [[ "$line" =~ \"type\"[[:space:]]*:[[:space:]]*\"([A-Za-z0-9-]+)\" ]]; then
                coin_type="${BASH_REMATCH[1]^^}"
            fi
            if [[ "$line" =~ \"address\"[[:space:]]*:[[:space:]]*\"([^\"]+)\" ]]; then
                address="${BASH_REMATCH[1]}"
                if [[ -n "$coin_type" ]] && [[ -n "$address" ]]; then
                    _set_synced_address "$coin_type" "$address"
                    coin_type=""
                    address=""
                fi
            fi
        done <<< "$(echo "$api_response" | tr ',' '\n' | tr '{' '\n' | tr '}' '\n')"
    else
        # ─────────────────────────────────────────────────────────────────────
        # Method 2: SSH to primary and read config.yaml
        # Uses HA_SSH_PASSWORD collected earlier during HA backup configuration.
        # ─────────────────────────────────────────────────────────────────────
        echo -e "  ${YELLOW}API unavailable — trying SSH fallback...${NC}"

        local remote_config=""
        if [[ -n "$HA_SSH_PASSWORD" ]]; then
            # Ensure sshpass is installed (setup_system runs AFTER collect_configuration,
            # so sshpass may not be installed yet when this function is called)
            if ! command -v sshpass &>/dev/null; then
                echo -e "  ${DIM}Installing sshpass for SSH access...${NC}"
                sudo apt-get update -qq 2>/dev/null
                sudo apt-get install -y -qq sshpass 2>/dev/null
            fi

            if command -v sshpass &>/dev/null; then
                remote_config=$(SSHPASS="$HA_SSH_PASSWORD" sshpass -e ssh \
                    -o StrictHostKeyChecking=accept-new -o ConnectTimeout=10 -o BatchMode=no \
                    "${POOL_USER}@${HA_PRIMARY_IP}" "cat ${INSTALL_DIR}/config/config.yaml" 2>/dev/null || true)
            fi
        fi

        if [[ -n "$remote_config" ]]; then
            sync_method="ssh"
            echo -e "  ${GREEN}✓${NC} Read config.yaml from primary via SSH"
            echo ""

            # Parse config.yaml (same pattern as spiralpool-wallet)
            local current_coin=""
            while IFS= read -r line; do
                # Multi-coin format: symbol: "DGB"
                if [[ "$line" =~ symbol:[[:space:]]*\"?([A-Za-z0-9-]+)\"? ]]; then
                    current_coin="${BASH_REMATCH[1]^^}"
                # Single-coin format: coin: "digibyte"
                elif [[ "$line" =~ ^[[:space:]]*coin:[[:space:]]*\"?([A-Za-z0-9-]+)\"? ]]; then
                    local coin_name="${BASH_REMATCH[1]}"
                    case "$coin_name" in
                        digibyte)           current_coin="DGB" ;;
                        bitcoin)            current_coin="BTC" ;;
                        bitcoincash)        current_coin="BCH" ;;
                        bitcoinii)          current_coin="BC2" ;;
                        litecoin)           current_coin="LTC" ;;
                        dogecoin)           current_coin="DOGE" ;;
                        digibyte-scrypt)    current_coin="DGB-SCRYPT" ;;
                        namecoin)           current_coin="NMC" ;;
                        syscoin)            current_coin="SYS" ;;
                        myriadcoin)         current_coin="XMY" ;;
                        fractalbitcoin|fractal) current_coin="FBTC" ;;
                        pepecoin)           current_coin="PEP" ;;
                        catcoin)            current_coin="CAT" ;;
                        *)                  current_coin="${coin_name^^}" ;;
                    esac
                fi
                # Match address line
                if [[ "$line" =~ address:[[:space:]]*\"?([^\"[:space:]]+)\"? ]] && [[ -n "$current_coin" ]]; then
                    local addr="${BASH_REMATCH[1]}"
                    if [[ "$addr" == "PENDING_GENERATION" ]]; then
                        pending_coins+=("$current_coin")
                    else
                        _set_synced_address "$current_coin" "$addr"
                    fi
                    current_coin=""
                fi
            done <<< "$remote_config"

            # Block if any addresses are PENDING_GENERATION
            if [[ ${#pending_coins[@]} -gt 0 ]]; then
                echo ""
                echo -e "${RED}═══════════════════════════════════════════════════════════════${NC}"
                echo -e "${RED}  CANNOT CONTINUE — Primary has unfinished wallet generation${NC}"
                echo -e "${RED}═══════════════════════════════════════════════════════════════${NC}"
                echo ""
                echo -e "  The following coins still have ${YELLOW}PENDING_GENERATION${NC} addresses:"
                for pc in "${pending_coins[@]}"; do
                    echo -e "    ${RED}•${NC} $pc"
                done
                echo ""
                echo -e "  ${WHITE}On the PRIMARY node, run:${NC}"
                echo -e "    ${GREEN}spiralpool-wallet --auto${NC}"
                echo ""
                echo -e "  Then re-run this installer on the backup node."
                echo ""
                return 1
            fi
        else
            # ─────────────────────────────────────────────────────────────────
            # Method 3: Both methods failed — fall back to manual prompts
            # ─────────────────────────────────────────────────────────────────
            echo -e "  ${YELLOW}WARNING: Could not reach primary node to sync addresses.${NC}"
            echo -e "  ${YELLOW}You will be prompted for addresses manually.${NC}"
            echo -e "  ${RED}IMPORTANT: Ensure addresses match the primary node exactly!${NC}"
            echo ""
            prompt_input "Press Enter to continue with manual address entry..."; read
            return 1
        fi
    fi

    # Verify all enabled coins are covered by the sync
    if ! _verify_synced_coverage; then
        return 1
    fi

    # Success — display synced addresses
    echo -e "  ${WHITE}Synced addresses from primary (via ${sync_method}):${NC}"
    echo ""
    _display_synced_addresses
    echo ""

    HA_ADDRESSES_SYNCED="true"
    log "HA address sync complete via $sync_method from $HA_PRIMARY_IP"

    prompt_input "Press Enter to continue..."; read
    return 0
}

# ═══════════════════════════════════════════════════════════════════════════════
# CONFIGURATION COLLECTION
# ═══════════════════════════════════════════════════════════════════════════════

collect_configuration() {
    clear
    log_step "Configuration"

    # Load any existing credentials before configuration begins
    # This allows preserving passwords during re-installation
    load_existing_credentials

    # SUDO_USER is the actual admin who ran sudo — $(whoami) is always "root" under sudo
    ADMIN_USER="${SUDO_USER:-$(whoami)}"
    log "Running as: $ADMIN_USER"
    echo ""

    # Configuration summary
    echo ""
    echo -e "  ${WHITE}Pool Configuration${NC}"
    echo ""
    # Service account
    echo -e "    Service Account:  ${GREEN}${POOL_USER}${NC}"

    # Server IP - Auto-detect
    # Try multiple methods to detect LOCAL IP - miners on your network need local IP
    local detected_ip=""

    # Method 1: Get the IP from the default route interface (most reliable for local IP)
    detected_ip=$(ip route get 1.1.1.1 2>/dev/null | grep -oP 'src \K[0-9.]+' | head -1)

    # Method 2: Fallback to hostname -I (first IP listed)
    if [[ -z "$detected_ip" ]] || [[ ! "$detected_ip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
        detected_ip=$(hostname -I 2>/dev/null | awk '{print $1}')
    fi

    # Method 3: Parse ip addr for first non-loopback IPv4
    if [[ -z "$detected_ip" ]] || [[ ! "$detected_ip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
        detected_ip=$(ip -4 addr show 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.\d+){3}' | grep -v '^127\.' | head -1)
    fi

    if [[ -n "$detected_ip" ]] && [[ "$detected_ip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
        SERVER_IP="$detected_ip"
        # Pad IP to align columns (max IP length is 15 chars)
        local ip_padded=$(printf "%-15s" "$SERVER_IP")
        echo -e "    Server IP:        ${GREEN}${ip_padded}${NC}"
    else
        echo -e "    Server IP:        ${RED}Not detected${NC}"
        echo ""
        prompt_input "Enter your server IP address: "; read custom_ip
        if [[ "$custom_ip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
            SERVER_IP="$custom_ip"
        else
            echo -e "${YELLOW}Invalid IP format, using placeholder. Update config manually.${NC}"
            SERVER_IP="YOUR_SERVER_IP"
        fi
        # Re-display with the entered IP
        echo ""
        echo -e "  ${WHITE}Pool Configuration${NC}"
        echo ""
        echo -e "    Service Account:  ${GREEN}${POOL_USER}${NC}"
        local ip_padded=$(printf "%-15s" "$SERVER_IP")
        echo -e "    Server IP:        ${GREEN}${ip_padded}${NC}"
    fi

    # Stratum ports section
    echo ""
    echo -e "  ${WHITE}Stratum Ports${NC}"
    echo ""

    if [[ "$COIN_MODE" == "single" ]]; then
        # Alphabetically ordered by coin symbol
        case "$SOLO_COIN" in
            BC2)       echo -e "    🔷 BC2         V1: ${GREEN}6333${NC}    V2: ${GREEN}6334${NC}" ;;
            BCH)       echo -e "    🟢 BCH         V1: ${GREEN}5333${NC}    V2: ${GREEN}5334${NC}" ;;
            BTC)       echo -e "    🟠 BTC         V1: ${GREEN}4333${NC}    V2: ${GREEN}4334${NC}" ;;
            CAT)       echo -e "    🐱 CAT         V1: ${GREEN}12335${NC}   V2: ${GREEN}12336${NC}" ;;
            DGB)       echo -e "    💎 DGB         V1: ${GREEN}3333${NC}    V2: ${GREEN}3334${NC}" ;;
            DGB-SCRYPT) echo -e "    💎 DGB-Scrypt  V1: ${GREEN}3336${NC}    V2: ${GREEN}3337${NC}" ;;
            DOGE)      echo -e "    🐕 DOGE        V1: ${GREEN}8335${NC}    V2: ${GREEN}8337${NC}" ;;
            LTC)       echo -e "    🪙 LTC         V1: ${GREEN}7333${NC}    V2: ${GREEN}7334${NC}" ;;
            PEP)       echo -e "    🐸 PEP         V1: ${GREEN}10335${NC}   V2: ${GREEN}10336${NC}" ;;
            NMC)       echo -e "    🔗 NMC         V1: ${GREEN}14335${NC}   V2: ${GREEN}14336${NC}" ;;
            XMY)       echo -e "    🌀 XMY         V1: ${GREEN}17335${NC}   V2: ${GREEN}17336${NC}" ;;
            FBTC)      echo -e "    🔶 FBTC        V1: ${GREEN}18335${NC}   V2: ${GREEN}18336${NC}" ;;
            QBX)       echo -e "    ⚛️ QBX         V1: ${GREEN}20335${NC}   V2: ${GREEN}20336${NC}" ;;
        esac
    else
        # Multi-coin mode - show the ports that will be used
        [[ "$ENABLE_DGB" == "true" ]]        && echo -e "    💎 DGB         V1: ${GREEN}3333${NC}    V2: ${GREEN}3334${NC}"
        [[ "$ENABLE_BTC" == "true" ]]        && echo -e "    🟠 BTC         V1: ${GREEN}4333${NC}    V2: ${GREEN}4334${NC}"
        [[ "$ENABLE_BCH" == "true" ]]        && echo -e "    🟢 BCH         V1: ${GREEN}5333${NC}    V2: ${GREEN}5334${NC}"
        [[ "$ENABLE_BC2" == "true" ]]        && echo -e "    🔷 BC2         V1: ${GREEN}6333${NC}    V2: ${GREEN}6334${NC}"
        [[ "$ENABLE_LTC" == "true" ]]        && echo -e "    🪙 LTC         V1: ${GREEN}7333${NC}    V2: ${GREEN}7334${NC}"
        [[ "$ENABLE_DOGE" == "true" ]]       && echo -e "    🐕 DOGE        V1: ${GREEN}8335${NC}    V2: ${GREEN}8337${NC}"
        [[ "$ENABLE_PEP" == "true" ]]        && echo -e "    🐸 PEP         V1: ${GREEN}10335${NC}   V2: ${GREEN}10336${NC}"
        [[ "$ENABLE_CAT" == "true" ]]        && echo -e "    🐱 CAT         V1: ${GREEN}12335${NC}   V2: ${GREEN}12336${NC}"
        [[ "$ENABLE_DGB_SCRYPT" == "true" ]] && echo -e "    💎 DGB-Scrypt  V1: ${GREEN}3336${NC}    V2: ${GREEN}3337${NC}"
        [[ "$ENABLE_NMC" == "true" ]]        && echo -e "    🔗 NMC         V1: ${GREEN}14335${NC}   V2: ${GREEN}14336${NC}"
        [[ "$ENABLE_SYS" == "true" ]]        && echo -e "    ⚙️ SYS         V1: ${GREEN}15335${NC}   V2: ${GREEN}15336${NC}"
        [[ "$ENABLE_XMY" == "true" ]]        && echo -e "    🌀 XMY         V1: ${GREEN}17335${NC}   V2: ${GREEN}17336${NC}"
        [[ "$ENABLE_FBTC" == "true" ]]       && echo -e "    🔶 FBTC        V1: ${GREEN}18335${NC}   V2: ${GREEN}18336${NC}"
        [[ "$ENABLE_QBX" == "true" ]]        && echo -e "    ⚛️ QBX         V1: ${GREEN}20335${NC}   V2: ${GREEN}20336${NC}"
    fi

    echo ""

    # Log configuration info
    log "Server IP: $SERVER_IP"
    if [[ "$COIN_MODE" == "single" ]]; then
        log "Stratum V1 port: $STRATUM_PORT, V2 port: $STRATUM_V2_PORT"
    else
        log "Multi-coin mode: using predefined ports for each coin"
    fi

    # DNS Configuration (Optional)
    echo ""
    echo -e "${CYAN}DNS Configuration (Optional)${NC}"
    echo ""
    echo "Configure custom DNS servers for reliable domain resolution."
    echo "Common options:"
    echo "  - Cloudflare: 1.1.1.1, 1.0.0.1"
    echo "  - Google:     8.8.8.8, 8.8.4.4"
    echo "  - Quad9:      9.9.9.9, 149.112.112.112"
    echo ""
    echo "Leave blank to keep current system DNS settings."
    echo ""

    DNS_PRIMARY=""
    DNS_SECONDARY=""
    CONFIGURE_DNS="false"

    prompt_input "Configure custom DNS? [y/N]: "; read dns_response
    case "$dns_response" in
        [Yy]|[Yy][Ee][Ss])
            CONFIGURE_DNS="true"
            echo ""
            echo "Enter DNS servers (IPv4 format):"

            # Primary DNS
            while true; do
                prompt_input "Primary DNS (e.g., 1.1.1.1): "; read DNS_PRIMARY
                if [[ -z "$DNS_PRIMARY" ]]; then
                    echo -e "  ${YELLOW}Primary DNS is required. Using Cloudflare (1.1.1.1)${NC}"
                    DNS_PRIMARY="1.1.1.1"
                    break
                elif [[ "$DNS_PRIMARY" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
                    break
                else
                    echo -e "  ${RED}Invalid IP format. Please enter a valid IPv4 address.${NC}"
                fi
            done

            # Secondary DNS (optional)
            while true; do
                prompt_input "Secondary DNS (optional, Enter to skip): "; read DNS_SECONDARY
                if [[ -z "$DNS_SECONDARY" ]]; then
                    break
                elif [[ "$DNS_SECONDARY" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
                    break
                else
                    echo -e "  ${RED}Invalid IP format. Please enter a valid IPv4 address or leave blank.${NC}"
                fi
            done

            if [[ -n "$DNS_SECONDARY" ]]; then
                log_success "DNS configured: $DNS_PRIMARY, $DNS_SECONDARY"
            else
                log_success "DNS configured: $DNS_PRIMARY"
            fi
            ;;
        *)
            log "Keeping current system DNS settings"
            ;;
    esac
    echo ""

    # Tor Network Configuration — clear screen so the legal disclaimer is unmissable
    clear
    echo ""
    echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
    echo -e "${WHITE}Network Privacy: Tor Configuration${NC}"
    echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
    echo ""
    echo -e "${WHITE}What is Tor?${NC}"
    echo "  Tor (The Onion Router) anonymizes your network traffic by routing"
    echo "  it through multiple encrypted relays worldwide. Your blockchain node"
    echo "  connections become untraceable to your real IP address."
    echo ""
    echo -e "${YELLOW}╔════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${YELLOW}║  IMPORTANT: This is an ALL-OR-NOTHING setting!             ║${NC}"
    echo -e "${YELLOW}║  If enabled, ALL blockchain nodes will use Tor.            ║${NC}"
    echo -e "${YELLOW}║  Nodes act as Tor CLIENTS only (no relay/exit/bridge).     ║${NC}"
    echo -e "${YELLOW}╚════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo -e "${GREEN}Advantages:${NC}                          ${YELLOW}Trade-offs:${NC}"
    echo "  + Hidden IP from peers               - Sync is MUCH SLOWER (days vs hours)"
    echo "  + Enhanced mining privacy             - Higher latency (~500ms-2s)"
    echo "  + Reduced targeted attack exposure    - Fewer available Tor peers"
    echo "  + Bypass ISP crypto throttling        - Slight orphan block risk increase"
    echo ""
    echo -e "${CYAN}Recommended:${NC} ${GREEN}Clearnet (N)${NC} for speed, ${YELLOW}Tor (Y)${NC} for privacy"
    echo ""
    echo -e "${RED}┌─────────────────────────────────────────────────────────────┐${NC}"
    echo -e "${RED}│                    LEGAL DISCLAIMER                         │${NC}"
    echo -e "${RED}├─────────────────────────────────────────────────────────────┤${NC}"
    echo -e "${RED}│ Before enabling Tor, you MUST ensure compliance with all    │${NC}"
    echo -e "${RED}│ applicable laws and regulations in your jurisdiction.       │${NC}"
    echo -e "${RED}│                                                             │${NC}"
    echo -e "${RED}│ The use of Tor may be restricted or prohibited in some      │${NC}"
    echo -e "${RED}│ countries. The authors of this software accept NO LIABILITY │${NC}"
    echo -e "${RED}│ for any illegal use of this feature.                        │${NC}"
    echo -e "${RED}│                                                             │${NC}"
    echo -e "${RED}│ By enabling Tor, you acknowledge that you have reviewed     │${NC}"
    echo -e "${RED}│ applicable laws and accept full responsibility.             │${NC}"
    echo -e "${RED}└─────────────────────────────────────────────────────────────┘${NC}"
    echo ""

    prompt_input "I accept the legal disclaimer and want to enable Tor [y/N]: "; read tor_response
    case "$tor_response" in
        [Yy]|[Yy][Ee][Ss])
            TOR_ENABLED="true"
            echo ""
            echo -e "${YELLOW}╔════════════════════════════════════════════════════════════╗${NC}"
            echo -e "${YELLOW}║              TOR NETWORK ENABLED (ALL NODES)               ║${NC}"
            echo -e "${YELLOW}╠════════════════════════════════════════════════════════════╣${NC}"
            echo -e "${YELLOW}║  ALL blockchain nodes will connect through Tor.            ║${NC}"
            echo -e "${YELLOW}║  Sync will be slower, but your IP is hidden from peers!    ║${NC}"
            echo -e "${YELLOW}║                                                            ║${NC}"
            echo -e "${YELLOW}║  Nodes act as Tor CLIENTS only:                            ║${NC}"
            echo -e "${YELLOW}║    - NO relay functionality                                ║${NC}"
            echo -e "${YELLOW}║    - NO exit node functionality                            ║${NC}"
            echo -e "${YELLOW}║    - NO bridge functionality                               ║${NC}"
            echo -e "${YELLOW}║  No other users' traffic will pass through this server.    ║${NC}"
            echo -e "${YELLOW}╚════════════════════════════════════════════════════════════╝${NC}"
            echo ""
            log_success "Tor enabled - ALL blockchain nodes will use Tor network"
            ;;
        *)
            TOR_ENABLED="false"
            log "Clearnet selected - using direct IPv4 connections (fastest)"
            ;;
    esac
    echo ""

    # Timezone selection for reports
    echo ""
    echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
    echo -e "${WHITE}Report Timezone${NC}"
    echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
