        local byte_len=$(printf '%s' "$custom_coinbase" | wc -c)
        local char_len=$(printf '%s' "$custom_coinbase" | wc -m)

        if [[ $byte_len -gt 40 ]]; then
            echo ""
            echo -e "${RED}ERROR: Coinbase text is $byte_len bytes (max 40)${NC}"
