    echo ""
    prompt_input "Press Enter to continue..."; read
    echo ""

    # Passwords - preserve existing if found during re-installation
    screen_clear
    echo ""
    echo -e "${CYAN}Passwords${NC}"
    if [[ -n "$EXISTING_RPC_PASSWORD" ]]; then
        RPC_PASSWORD="$EXISTING_RPC_PASSWORD"
        log "Preserved existing RPC password"
    else
        RPC_PASSWORD=$(generate_password)
        log_success "Generated new RPC password"
    fi
    # Map legacy RPC_PASSWORD to DGB-specific variable
    # Every other coin has its own *_RPC_PASSWORD=$(generate_password) call,
    # but DGB uses the legacy generic variable. Without this, install_digibyte()
    # writes rpcpassword= (empty) to digibyte.conf, causing auth failure.
    DGB_RPC_PASSWORD="$RPC_PASSWORD"
    if [[ -n "$EXISTING_DB_PASSWORD" ]]; then
        DB_PASSWORD="$EXISTING_DB_PASSWORD"
        log "Preserved existing database password"
    elif [[ -n "$DB_PASSWORD" ]]; then
        # DB_PASSWORD already set (e.g., from HA backup config collection)
        log "Preserved database password from HA configuration"
    else
        DB_PASSWORD=$(generate_password)
        log_success "Generated new database password"
    fi
    # Admin API key for Sentinel device hints integration
    if [[ -n "$EXISTING_ADMIN_API_KEY" ]]; then
        ADMIN_API_KEY="$EXISTING_ADMIN_API_KEY"
        log "Preserved existing admin API key"
    elif [[ -z "$ADMIN_API_KEY" ]]; then
        ADMIN_API_KEY=$(generate_password)
        log_success "Generated admin API key"
    else
        log "Using admin API key from checkpoint"
    fi

    # Metrics auth token (Prometheus /metrics endpoint)
    if [[ -z "$METRICS_TOKEN" ]]; then
        METRICS_TOKEN=$(generate_password)
        log_success "Generated metrics auth token"
    else
        log "Using metrics token from checkpoint"
    fi
    echo ""

    # Notification settings (only ask if installing full mode with Sentinel)
    DISCORD_WEBHOOK=""
    TELEGRAM_BOT_TOKEN=""
    TELEGRAM_CHAT_ID=""
    XMPP_JID=""
    XMPP_PASSWORD=""
    XMPP_RECIPIENT=""
    XMPP_MUC="false"
    XMPP_USE_TLS="true"
    # Currency defaults (CAD)
    REPORT_CURRENCY="CAD"      # Any supported currency code
    POWER_CURRENCY="CAD"
    POWER_SYMBOL="\$"
    POWER_EMOJI="🍁"
    DISPLAY_CURRENCY_PRIMARY="CAD"    # Dashboard earnings display currency
    # Alert theme
    ALERT_THEME="cyberpunk"        # "cyberpunk" or "professional"
    # Spiral Sentinel defaults
    REPORT_FREQUENCY="6h"           # "6h" (4x daily), "daily" (1x daily), or "off"
    SENTINEL_ALERTS_ENABLED="true"  # Enable/disable all alerts
    SENTINEL_HEALTH_ENABLED="true"  # Enable/disable health monitoring (auto-restart, zombie detection)
    UPDATE_CHECK_ENABLED="true"     # Enable/disable update notifications
    AUTO_UPDATE_MODE="notify"       # "auto" (fully automatic), "notify" (alert only), "disabled"
    if [[ "$INSTALL_MODE" == "full" ]]; then
        screen_clear
        echo ""
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo -e "${WHITE}Notification Setup (Optional)${NC}"
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo ""
        echo "Spiral Sentinel can send alerts when:"
        echo "  - A block is found"
        echo "  - A miner goes offline"
        echo "  - Temperature warnings occur"
        echo "  - 6-hour, weekly, and monthly reports"
        echo ""
        echo "You can configure Discord, Telegram, XMPP, or any combination."
        echo ""
        echo -e "${DIM}Tip: For Discord, you'll need a webhook URL from Server Settings > Webhooks.${NC}"
        echo -e "${DIM}     For Telegram, you'll need a bot token from @BotFather and a chat ID.${NC}"
        echo -e "${DIM}     For XMPP, you'll need a bot JID and the recipient's JID.${NC}"
        echo -e "${DIM}     See README.md > Notifications for detailed setup instructions.${NC}"
        echo ""
        echo ""

        # Discord setup
        echo -e "${YELLOW}Discord Notifications${NC}"
        echo "To get a webhook URL:"
        echo "  1. Open Discord > Server Settings > Integrations > Webhooks"
        echo "  2. Create a webhook and copy the URL"
        echo ""
        prompt_input "Discord Webhook URL (or Enter to skip): "; read DISCORD_WEBHOOK
        if [[ -n "$DISCORD_WEBHOOK" ]]; then
            if [[ "$DISCORD_WEBHOOK" =~ ^https://discord\.com/api/webhooks/ ]] || [[ "$DISCORD_WEBHOOK" =~ ^https://discordapp\.com/api/webhooks/ ]]; then
                log_success "Discord webhook configured"
            else
                log_warn "Invalid webhook URL format, skipping Discord"
                DISCORD_WEBHOOK=""
            fi
        else
            log "Discord notifications skipped"
        fi
        echo ""

        # Telegram setup
        echo ""
        echo -e "${YELLOW}Telegram Notifications${NC}"
        echo "To set up Telegram notifications:"
        echo "  1. Message @BotFather on Telegram and create a bot"
        echo "  2. Copy the bot token (looks like: 123456789:ABCdefGHI...)"
        echo "  3. Add your bot to a group/channel or message it directly"
        echo "  4. Get your chat ID from @userinfobot or @RawDataBot"
        echo ""
        prompt_input "Telegram Bot Token (or Enter to skip): "; read TELEGRAM_BOT_TOKEN
        if [[ -n "$TELEGRAM_BOT_TOKEN" ]]; then
            prompt_input "Telegram Chat ID: "; read TELEGRAM_CHAT_ID
            if [[ -n "$TELEGRAM_CHAT_ID" ]]; then
                log_success "Telegram configured"
            else
                log_warn "No chat ID provided, skipping Telegram"
                TELEGRAM_BOT_TOKEN=""
            fi
        else
            log "Telegram notifications skipped"
        fi
        echo ""

        # XMPP Direct Send
        echo ""
        echo -e "${YELLOW}XMPP Notifications${NC}"
        echo "Send alerts directly to any XMPP account or MUC room."
        echo "  1. You need an XMPP account for the bot (e.g. sentinel@yourserver.com)"
        echo "  2. The recipient's JID (e.g. you@yourserver.com)"
        echo ""
        prompt_input "XMPP Bot JID (or Enter to skip): "; read XMPP_JID
        if [[ -n "$XMPP_JID" ]]; then
            prompt_input "XMPP Bot Password: "; read -s XMPP_PASSWORD; echo ""
            if [[ -n "$XMPP_PASSWORD" ]]; then
                prompt_input "Recipient JID (user or room): "; read XMPP_RECIPIENT
                if [[ -n "$XMPP_RECIPIENT" ]]; then
                    prompt_input "Is this a MUC room? (y/N): "; read xmpp_muc_yn
                    [[ "$xmpp_muc_yn" =~ ^[Yy] ]] && XMPP_MUC="true"
                    log_success "XMPP configured"
                else
                    log_warn "No recipient JID, skipping XMPP"
                    XMPP_JID=""
                fi
            else
                log_warn "No password provided, skipping XMPP"
                XMPP_JID=""
            fi
        else
            log "XMPP notifications skipped"
        fi
        echo ""

        # Summary of notification setup
        if [[ -z "$DISCORD_WEBHOOK" ]] && [[ -z "$TELEGRAM_BOT_TOKEN" ]] && [[ -z "$XMPP_JID" ]]; then
            log "No notifications configured (can configure later in ~/.spiralsentinel/config.json)"
        fi
        echo ""

        # Reporting Currency Preference
        screen_clear
        echo ""
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo -e "${WHITE}Reporting Currency Preference${NC}"
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo ""
        echo "What currency would you like earnings/values displayed in?"
        echo "(Reports, alerts, block notifications, etc.)"
        echo ""
        echo -e "  ${GREEN}1)${NC}  🍁 CAD - Canadian Dollar ${GREEN}(Default)${NC}"
        echo -e "  ${WHITE}2)${NC}  🦅 USD - US Dollar"
        echo -e "  ${WHITE}3)${NC}  🌐 EUR - Euro"
        echo -e "  ${WHITE}4)${NC}  🌐 GBP - British Pound"
        echo -e "  ${WHITE}5)${NC}  🌐 JPY - Japanese Yen"
        echo -e "  ${WHITE}6)${NC}  🌐 AUD - Australian Dollar"
        echo -e "  ${WHITE}7)${NC}  🌐 CHF - Swiss Franc"
        echo -e "  ${WHITE}8)${NC}  🌐 CNY - Chinese Yuan"
        echo -e "  ${WHITE}9)${NC}  🌐 NZD - New Zealand Dollar"
        echo -e "  ${WHITE}10)${NC} 🌐 SEK - Swedish Krona"
        echo ""
        prompt_input "Select currency [1-10] (default: 1): "; read earnings_currency_choice

        case "$earnings_currency_choice" in
            2)  REPORT_CURRENCY="USD"; log_success "Reports: USD 🦅" ;;
            3)  REPORT_CURRENCY="EUR"; log_success "Reports: EUR 🌐" ;;
            4)  REPORT_CURRENCY="GBP"; log_success "Reports: GBP 🌐" ;;
            5)  REPORT_CURRENCY="JPY"; log_success "Reports: JPY 🌐" ;;
            6)  REPORT_CURRENCY="AUD"; log_success "Reports: AUD 🌐" ;;
            7)  REPORT_CURRENCY="CHF"; log_success "Reports: CHF 🌐" ;;
            8)  REPORT_CURRENCY="CNY"; log_success "Reports: CNY 🌐" ;;
            9)  REPORT_CURRENCY="NZD"; log_success "Reports: NZD 🌐" ;;
            10) REPORT_CURRENCY="SEK"; log_success "Reports: SEK 🌐" ;;
            *)  REPORT_CURRENCY="CAD"; log_success "Reports: CAD 🍁" ;;
        esac
        echo ""

        # Alert Theme Preference
        screen_clear
        echo ""
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo -e "${WHITE}Alert Theme${NC}"
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo ""
        echo "Choose the personality of your Discord/Telegram alerts:"
        echo ""
        echo -e "  ${GREEN}1)${NC} 🔥 Cyberpunk ${GREEN}(Default)${NC}"
        echo -e "     Neon-lit block alerts, netrunner lingo, corpo-smashing energy"
        echo ""
        echo -e "  ${WHITE}2)${NC} 📊 Professional"
        echo -e "     Clean enterprise-ready alerts, factual tone, no slang"
        echo ""
        prompt_input "Select alert theme [1-2] (default: 1): "; read theme_choice

        case "$theme_choice" in
            2)
                ALERT_THEME="professional"
                log_success "Alert theme: Professional 📊"
                ;;
            *)
                ALERT_THEME="cyberpunk"
                log_success "Alert theme: Cyberpunk 🔥"
                ;;
        esac
        echo ""

        # Spiral Sentinel Configuration
        screen_clear
        echo ""
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo -e "${WHITE}Spiral Sentinel Configuration${NC}"
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo ""
        echo "Spiral Sentinel is your autonomous mining monitor. It provides:"
        echo "  • Discord/Telegram/XMPP alerts (blocks, offline miners, temperature)"
        echo "  • Intel reports (network stats, earnings, miner status)"
        echo "  • Health monitoring (auto-restart, zombie detection)"
        echo ""
        echo -e "${DIM}All settings can be changed later in ~/.spiralsentinel/config.json${NC}"
        echo ""

        # Question 1: Alerts
        echo ""
        echo -e "${WHITE}1. Alerts${NC}"
        echo "   Receive notifications for blocks found, miners offline, temperature warnings, etc."
        echo ""
        echo -e "  ${GREEN}1)${NC} ✅ Enabled ${GREEN}(Recommended)${NC}"
        echo -e "  ${DIM}2) ❌ Disabled${NC}"
        echo ""
        prompt_input "Enable alerts? [1-2] (default: 1): "; read alerts_choice

        case "$alerts_choice" in
            2)
                SENTINEL_ALERTS_ENABLED="false"
                log_warn "Alerts: Disabled"
                ;;
            *)
                SENTINEL_ALERTS_ENABLED="true"
                log_success "Alerts: Enabled"
                ;;
        esac
        echo ""

        # Question 2: Health Monitoring
        echo ""
        echo -e "${WHITE}2. Health Monitoring${NC}"
        echo "   Auto-restart offline miners, detect zombie miners (online but not submitting shares)."
        echo ""
        echo -e "  ${GREEN}1)${NC} ✅ Enabled ${GREEN}(Recommended)${NC}"
        echo -e "  ${DIM}2) ❌ Disabled${NC}"
        echo ""
        prompt_input "Enable health monitoring? [1-2] (default: 1): "; read health_choice

        case "$health_choice" in
            2)
                SENTINEL_HEALTH_ENABLED="false"
                log_warn "Health Monitoring: Disabled"
                ;;
            *)
                SENTINEL_HEALTH_ENABLED="true"
                log_success "Health Monitoring: Enabled"
                ;;
        esac
        echo ""

        # Question 3: Report Frequency
        echo ""
        echo -e "${WHITE}3. Intel Report Frequency${NC}"
        echo "   Scheduled reports with network stats, earnings, miner status."
        echo ""
        echo -e "  ${GREEN}1)${NC} 📊 4x Daily ${GREEN}(Default)${NC}"
        echo -e "     ${DIM}Reports at 06:00, 12:00, 18:00, and 21:55${NC}"
        echo ""
        echo -e "  ${WHITE}2)${NC} 📅 1x Daily Digest"
        echo -e "     ${DIM}Single comprehensive report at your configured major report hour${NC}"
        echo ""
        echo -e "  ${DIM}3) ❌ Disabled${NC}"
        echo -e "     ${DIM}No scheduled intel reports${NC}"
        echo ""
        echo -e "${DIM}Note: Weekly, Monthly, and Quarterly reports are always enabled.${NC}"
        echo -e "${DIM}When multiple reports are due, they're consolidated into one message.${NC}"
        echo ""
        prompt_input "Select report frequency [1-3] (default: 1): "; read report_freq_choice

        case "$report_freq_choice" in
            2)
                REPORT_FREQUENCY="daily"
                log_success "Reports: 1x Daily Digest"
                ;;
            3)
                REPORT_FREQUENCY="off"
                log_warn "Reports: Disabled"
                ;;
            *)
                REPORT_FREQUENCY="6h"
                log_success "Reports: 4x Daily"
                ;;
        esac
        echo ""

        # Update Notifications & Auto-Update
        screen_clear
        echo ""
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo -e "${WHITE}Update Mode Configuration${NC}"
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo ""
        echo "Sentinel checks for Spiral Pool updates every 6 hours."
        echo "Choose how you want updates to be handled:"
        echo ""
        echo -e "  ${GREEN}1)${NC} 📢 Notify Only ${GREEN}(Recommended)${NC}"
        echo -e "     ${DIM}Get Discord/Telegram alerts when updates are available${NC}"
        echo -e "     ${DIM}You control when to upgrade manually${NC}"
        echo ""
        echo -e "  ${WHITE}2)${NC} 🤖 Fully Automatic Updates"
        echo -e "     ${DIM}Automatically download and install updates when available${NC}"
        echo -e "     ${DIM}Services will be stopped/restarted automatically${NC}"
        echo -e "     ${DIM}Best for remote/unattended servers${NC}"
        echo ""
        echo -e "  ${DIM}3) ❌ Disable update checking${NC}"
        echo -e "     ${DIM}No update notifications (check manually)${NC}"
        echo ""
        prompt_input "Select update mode [1-3] (default: 1): "; read update_choice

        # SECURITY: Validate input is a single digit 1-3 or empty
        if [[ -n "$update_choice" ]] && ! [[ "$update_choice" =~ ^[1-3]$ ]]; then
            log_warn "Invalid choice '$update_choice', using default (1)"
            update_choice="1"
        fi

        case "$update_choice" in
            2)
                UPDATE_CHECK_ENABLED="true"
                AUTO_UPDATE_MODE="auto"
                log_success "Update mode: Fully Automatic"
                echo ""
                echo -e "${YELLOW}⚠️  AUTOMATIC UPDATES ENABLED${NC}"
                echo -e "${DIM}When a new version is detected:${NC}"
                echo -e "${DIM}  1. Services will be gracefully stopped${NC}"
                echo -e "${DIM}  2. Update will be downloaded and installed${NC}"
                echo -e "${DIM}  3. Services will be automatically restarted${NC}"
                echo -e "${DIM}  4. You'll receive a notification of the completed update${NC}"
                echo ""
                ;;
            3)
                UPDATE_CHECK_ENABLED="false"
                AUTO_UPDATE_MODE="disabled"
                log_warn "Update notifications: Disabled"
                ;;
            *)
                UPDATE_CHECK_ENABLED="true"
                AUTO_UPDATE_MODE="notify"
                log_success "Update mode: Notify Only (every 6 hours)"
                ;;
        esac
        echo ""

        # Power Cost Configuration
        screen_clear
        echo ""
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo -e "${WHITE}Power / Electricity Cost Configuration${NC}"
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo ""
        echo "For profitability tracking, enter your electricity cost."
        echo ""
        echo ""
        echo "What currency is your power bill in?"
        echo ""
        echo -e "  ${GREEN}1)${NC}  🍁 CAD - Canadian Dollar ${GREEN}(Default)${NC}"
        echo -e "  ${WHITE}2)${NC}  🦅 USD - US Dollar"
        echo -e "  ${WHITE}3)${NC}  🌐 EUR - Euro"
        echo -e "  ${WHITE}4)${NC}  🌐 GBP - British Pound"
        echo -e "  ${WHITE}5)${NC}  🌐 JPY - Japanese Yen"
        echo -e "  ${WHITE}6)${NC}  🌐 AUD - Australian Dollar"
        echo -e "  ${WHITE}7)${NC}  🌐 CHF - Swiss Franc"
        echo -e "  ${WHITE}8)${NC}  🌐 CNY - Chinese Yuan"
        echo -e "  ${WHITE}9)${NC}  🌐 NZD - New Zealand Dollar"
        echo -e "  ${WHITE}10)${NC} 🌐 SEK - Swedish Krona"
        echo ""
        prompt_input "Select power currency [1-10] (default: 1): "; read power_currency_choice

        # SECURITY: Validate input is 1-10 or empty
        if [[ -n "$power_currency_choice" ]] && ! [[ "$power_currency_choice" =~ ^([1-9]|10)$ ]]; then
            log_warn "Invalid choice, using default (CAD)"
            power_currency_choice="1"
        fi

        # Currency lookup arrays
        local -a CUR_CODES=("CAD" "USD" "EUR" "GBP" "JPY" "AUD" "CHF" "CNY" "NZD" "SEK")
        local -a CUR_SYMBOLS=("\$" "\$" "€" "£" "¥" "\$" "Fr." "¥" "\$" "kr")
        local -a CUR_EMOJIS=("🍁" "🦅" "🌐" "🌐" "🌐" "🌐" "🌐" "🌐" "🌐" "🌐")

        local idx=$(( ${power_currency_choice:-1} - 1 ))
        if [[ $idx -lt 0 || $idx -ge 10 ]]; then idx=0; fi

        POWER_CURRENCY="${CUR_CODES[$idx]}"
        POWER_SYMBOL="${CUR_SYMBOLS[$idx]}"
        POWER_EMOJI="${CUR_EMOJIS[$idx]}"
        log "Power currency: ${POWER_CURRENCY} ${POWER_EMOJI}"

        echo ""
        echo ""
        echo -e "Enter your electricity rate per kWh in ${GREEN}${POWER_CURRENCY}${NC}"
        echo ""
        echo -e "${DIM}Example: 0.12 for 12 cents per kWh${NC}"
        echo ""
        echo ""
        prompt_input "Rate per kWh (default: 0.12): "; read power_rate_input

        # Default to 0.12 if empty
        POWER_RATE="${power_rate_input:-0.12}"

        # SECURITY: Validate power rate is a valid decimal number (0.00 to 9.99)
        if ! [[ "$POWER_RATE" =~ ^[0-9]*\.?[0-9]+$ ]]; then
            log_warn "Invalid power rate format '$POWER_RATE', using default 0.12"
            POWER_RATE="0.12"
        fi
        # Cap at reasonable maximum (10.00 per kWh) — use awk (bc not yet installed)
        if awk "BEGIN{exit !($POWER_RATE > 10)}" 2>/dev/null; then
            log_warn "Power rate seems too high ($POWER_RATE), capping at 10.00"
            POWER_RATE="10.00"
        fi

        # Easter egg for free power! (handles 0, 0.0, 0.00, 0.000, etc.)
        # Use regex to match zero formats, plus awk for negative numbers (bc not yet installed)
        if [[ "$POWER_RATE" =~ ^0*(\.0*)?$ ]] || [[ "$POWER_RATE" =~ ^\.0+$ ]] || \
           awk "BEGIN{exit !($POWER_RATE <= 0)}" 2>/dev/null; then
        
            echo ""
            echo -e "${GREEN}${BOLD}"
            echo "  Power cost configured as \$0.00/kWh"
            echo -e "${NC}"
            echo ""
            echo -e "${YELLOW}NOTE: This setting affects display calculations only.${NC}"
