            echo "this software's control including network difficulty,"
            echo "hardware performance, electricity rates, and market prices."
            echo ""
            echo "No guarantees of profitability are made or implied."
            echo "See WARNINGS.md for important risk disclosures."
            echo ""
            IS_FREE_POWER=true
        else
            IS_FREE_POWER=false
            log_success "Power rate set: ${POWER_SYMBOL}${POWER_RATE}/kWh"
        fi
        echo ""

        # Dashboard Display Currency
        screen_clear
        echo ""
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo -e "${WHITE}Dashboard Display Currency${NC}"
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo ""
        echo "What currency should the dashboard earnings calculator display?"
        echo ""
        echo -e "  ${GREEN}1)${NC} 🍁 CAD ${GREEN}(Default)${NC}    ${WHITE}2)${NC} 🦅 USD    ${WHITE}3)${NC} 🌐 EUR    ${WHITE}4)${NC} 🌐 GBP    ${WHITE}5)${NC} 🌐 JPY"
        echo -e "  ${WHITE}6)${NC} 🌐 AUD    ${WHITE}7)${NC} 🌐 CHF    ${WHITE}8)${NC} 🌐 CNY    ${WHITE}9)${NC} 🌐 NZD    ${WHITE}10)${NC} 🌐 SEK"
        echo ""

        local -a DASH_CUR_CODES=("CAD" "USD" "EUR" "GBP" "JPY" "AUD" "CHF" "CNY" "NZD" "SEK")

        prompt_input "Select currency [1-10] (default: 1 = CAD): "; read dash_primary_choice
        local pri_idx=$(( ${dash_primary_choice:-1} - 1 ))
        if [[ $pri_idx -lt 0 || $pri_idx -ge 10 ]]; then pri_idx=0; fi
        DISPLAY_CURRENCY_PRIMARY="${DASH_CUR_CODES[$pri_idx]}"

        log_success "Dashboard: ${DISPLAY_CURRENCY_PRIMARY}"
        echo ""

        # Miner Discovery
        screen_clear
        echo ""
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo -e "${WHITE}  ⛏️  MINER DISCOVERY${NC}"
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo ""
        echo ""
        echo -e "${WHITE}Spiral Sentinel needs to know about your miners to monitor them.${NC}"
        echo ""
        echo -e "Without this step, Sentinel will show ${YELLOW}\"No miners configured\"${NC} and"
        echo -e "${YELLOW}\"0/0 Online\"${NC} in the dashboard and Discord notifications."
        echo ""
        echo -e "${WHITE}The network scan will:${NC}"
        echo "  • Auto-discover all mining devices on your local network"
        echo "  • Enable hashrate monitoring, temperature alerts, and offline detection"
        echo "  • Allow you to set friendly names (e.g., 'BitAxe-Office')"
        echo ""
        echo -e "${DIM}Supported: BitAxe, NerdQAxe, Antminer, Whatsminer, Avalon, Innosilicon${NC}"
        echo ""
        echo -e "  ${GREEN}1)${NC} 🔍 Scan network now ${GREEN}[Recommended - takes ~2 min]${NC}"
        echo ""
        echo -e "  ${DIM}2)${NC} ⏭️  Skip (you'll need to run 'spiralpool-scan' manually later)"
        echo ""
        prompt_input "Scan for miners? [1-2] (default: 1): "; read scan_choice

        SCAN_FOR_MINERS="true"
        case "$scan_choice" in
            2)
                SCAN_FOR_MINERS="false"
                log "Miner scan: Skipped (run 'spiralpool-scan' later)"
                echo -e "${YELLOW}⚠️  Remember: Sentinel will show 'No miners' until you run spiralpool-scan${NC}"
                ;;
            *)
                log_success "Will scan for miners after installation"
                ;;
        esac
        echo ""
    fi

    # ── Blockchain Sync Method ────────────────────────────────────────────
    # HA backup nodes skip this prompt — ask_blockchain_rsync() handles
    # replication from the primary automatically (with its own prompt).
    # Asking here too is redundant and confusing.
    if [[ "$HA_MODE" == "ha-backup" ]]; then
        BLOCKCHAIN_SYNC_CHOICE="1"  # Placeholder — HA path in ask_blockchain_rsync overrides this
        log "HA backup mode: blockchain replication will be offered after coin install"
    else
        screen_clear
        echo ""
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo -e "${WHITE}  Blockchain Data Synchronization${NC}"
        echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
        echo ""
        echo -e "  Blockchain must fully synchronize before mining can begin."
        echo ""
        echo -e "  ${WHITE}Options:${NC}"
        echo -e "    ${GREEN}1. Sync from network${NC} - Download blockchain from P2P network (default)"
        echo -e "    ${GREEN}2. Copy from another node${NC} - Fast! Replicate from existing Spiral Pool node"
        echo ""
        echo -e "  ${DIM}You can replicate blockchain data later with:${NC}"
        echo -e "  ${DIM}  sudo ${INSTALL_DIR}/scripts/ha-replicate.sh --mode blockchain --source <IP> --execute${NC}"
        echo ""
        echo -e "  ${GREEN}1${NC} = Sync from network (default)"
        echo -e "  ${GREEN}2${NC} = Copy from another Spiral Pool node"
        echo ""
        prompt_input "Choose option [1/2]: "; read sync_method_choice

        if [[ "$sync_method_choice" == "2" ]]; then
            BLOCKCHAIN_SYNC_CHOICE="2"
            echo ""
            echo -e "  ${CYAN}Enter the IP address or hostname of the source node:${NC}"
            prompt_input "Source node: "; read SYNC_SOURCE_NODE

            if [[ -z "$SYNC_SOURCE_NODE" ]]; then
                log_warn "No source node provided. Will use network sync instead."
                BLOCKCHAIN_SYNC_CHOICE="1"
            else
                # SSH user is always spiraluser — every Spiral Pool node creates it with a password
                SYNC_SSH_USER="${POOL_USER}"
                log_success "Will copy from ${SYNC_SOURCE_NODE} as ${POOL_USER} after installation"
            fi
        else
            BLOCKCHAIN_SYNC_CHOICE="1"
            log "Using network sync (P2P blockchain download)"
        fi
        echo ""
    fi

    # ── Automated Database Backups ────────────────────────────────────────
    screen_clear
    echo ""
    echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
    echo -e "${WHITE}  Automated Database Backups${NC}"
    echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
    echo ""
    echo -e "  Spiral Pool can automatically backup your database daily at 2:00 AM."
    echo -e "  This creates backup copies of your mining stats, block records, and earnings data."
    echo ""
    echo -e "  ${WHITE}Features:${NC}"
    echo -e "    • Daily database dump (gzip compressed)"
    echo -e "    • 30-day retention with automatic cleanup"
    echo -e "    • Backups stored in ${INSTALL_DIR}/backups/"
    echo ""
    echo -e "  ${DIM}You can enable/disable this later with: spiralpool-backup --schedule${NC}"
    echo ""
    echo -e "  ${GREEN}y${NC} = Enable automated daily backups (recommended)"
    echo -e "  ${YELLOW}n${NC} = Skip (you can enable later)"
    echo ""
    prompt_input "Enable automated backups? [y/N]: "; read backup_choice

    if [[ "$backup_choice" == "y" || "$backup_choice" == "Y" ]]; then
        ENABLE_AUTO_BACKUPS=true
        log_success "Automated backups will be enabled"
    else
        ENABLE_AUTO_BACKUPS=false
        log "Automated backups: skipped"
    fi
    BACKUP_CHOICE_MADE="true"
    echo ""

    # ── Watch Sync Progress ───────────────────────────────────────────────
    screen_clear
    echo ""
    echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
    echo -e "${WHITE}  Sync Progress Monitor${NC}"
    echo -e "${CYAN}═══════════════════════════════════════════════════════════${NC}"
    echo ""
    echo -e "  After installation, would you like to watch the blockchain sync in real-time?"
    echo -e "  The pool will start automatically once all blockchains are synced."
    echo ""
    echo -e "  ${DIM}(You can press 'q' to quit and 'b' to background the monitor)${NC}"
    echo ""
    echo -e "  ${GREEN}y${NC} = Watch sync progress after install (recommended)"
    echo -e "  ${YELLOW}n${NC} = Skip (pool starts automatically in background)"
    echo ""
    prompt_input "Watch sync progress? [Y/n]: "; read watch_choice

    if [[ "$watch_choice" == "n" || "$watch_choice" == "N" ]]; then
        WATCH_SYNC_ON_EXIT="declined"
        log "Sync watcher: skipped"
    else
        WATCH_SYNC_ON_EXIT="true"
        log_success "Will launch sync watcher after installation"
    fi
    echo ""

    # Summary
    screen_clear
    echo ""
    echo -e "${YELLOW}═══════════════════════════════════════════════════════════${NC}"
    echo -e "${WHITE}Configuration Summary${NC}"
    echo -e "${YELLOW}═══════════════════════════════════════════════════════════${NC}"
    echo ""
    if [[ "$INSTALL_MODE" == "full" ]]; then
        echo -e "  ${WHITE}Mode:${NC}          ${GREEN}Spiral Pool (Complete Solution)${NC}"
        echo -e "  ${WHITE}Components:${NC}    ${GREEN}Node + Pool + DB + Dashboard + Sentinel + Health${NC}"
        # Show notification status
        if [[ -n "$DISCORD_WEBHOOK" ]]; then
            echo -e "  ${WHITE}Discord:${NC}       ${GREEN}Configured${NC}"
        else
            echo -e "  ${WHITE}Discord:${NC}       ${YELLOW}Not configured${NC}"
        fi
        if [[ -n "$TELEGRAM_BOT_TOKEN" ]]; then
            echo -e "  ${WHITE}Telegram:${NC}      ${GREEN}Configured${NC}"
        else
            echo -e "  ${WHITE}Telegram:${NC}      ${YELLOW}Not configured${NC}"
        fi
        if [[ -n "$XMPP_JID" ]]; then
            echo -e "  ${WHITE}XMPP:${NC}          ${GREEN}Configured${NC}"
        else
            echo -e "  ${WHITE}XMPP:${NC}          ${YELLOW}Not configured${NC}"
        fi
        # Show update mode
        case "$AUTO_UPDATE_MODE" in
            auto) echo -e "  ${WHITE}Updates:${NC}       ${YELLOW}Auto-update${NC}" ;;
            disabled) echo -e "  ${WHITE}Updates:${NC}       ${DIM}Disabled${NC}" ;;
            *) echo -e "  ${WHITE}Updates:${NC}       ${GREEN}Notify${NC}" ;;
        esac
        # Show power cost
        if [[ "$IS_FREE_POWER" == "true" ]]; then
            echo -e "  ${WHITE}Power Cost:${NC}    ${GREEN}\$0.00/kWh${NC}"
        else
            echo -e "  ${WHITE}Power Cost:${NC}    ${GREEN}${POWER_SYMBOL}${POWER_RATE}/kWh (${POWER_CURRENCY})${NC}"
        fi
    else
        echo -e "  ${WHITE}Mode:${NC}          ${GREEN}Spiral Stratum (Pool + Dependencies)${NC}"
        echo -e "  ${WHITE}Components:${NC}    ${GREEN}Node + Pool + DB${NC}"
    fi
    echo ""
    echo -e "  ${WHITE}Pool User:${NC}     ${GREEN}$POOL_USER${NC}"

    # Show coin-specific details based on selected coin(s)
    if [[ "$COIN_MODE" == "single" ]]; then
        # Solo mode - show the selected coin's details
        local display_rpc_user=""
        local display_stratum_port=""
        local display_wallet=""
        local display_coin=""

        case "$SOLO_COIN" in
            BC2)
                display_coin="Bitcoin II (BC2)"
                display_rpc_user="$BC2_RPC_USER"
                display_stratum_port="6333"
                display_wallet="$BC2_ADDRESS"
                ;;
            BCH)
                display_coin="Bitcoin Cash (BCH)"
                display_rpc_user="$BCH_RPC_USER"
                display_stratum_port="5333"
                display_wallet="$BCH_ADDRESS"
                ;;
            BTC)
                display_coin="Bitcoin (BTC)"
                display_rpc_user="$BTC_RPC_USER"
                display_stratum_port="4333"
                display_wallet="$BTC_ADDRESS"
                ;;
            CAT)
                display_coin="Catcoin (CAT)"
                display_rpc_user="$CAT_RPC_USER"
                display_stratum_port="12335"
                display_wallet="$CAT_ADDRESS"
                ;;
            DGB)
                display_coin="DigiByte (DGB)"
                display_rpc_user="$DGB_RPC_USER"
                display_stratum_port="3333"
                display_wallet="$POOL_ADDRESS"
                ;;
            DGB-SCRYPT)
                display_coin="DigiByte Scrypt (DGB-SCRYPT)"
                display_rpc_user="$DGB_RPC_USER"
                display_stratum_port="3336"
                display_wallet="$POOL_ADDRESS"
                ;;
            DOGE)
                display_coin="Dogecoin (DOGE)"
                display_rpc_user="$DOGE_RPC_USER"
                display_stratum_port="8335"
                display_wallet="$DOGE_ADDRESS"
                ;;
            LTC)
                display_coin="Litecoin (LTC)"
                display_rpc_user="$LTC_RPC_USER"
                display_stratum_port="7333"
                display_wallet="$LTC_ADDRESS"
                ;;
            PEP)
                display_coin="PepeCoin (PEP)"
                display_rpc_user="$PEP_RPC_USER"
                display_stratum_port="10335"
                display_wallet="$PEP_ADDRESS"
                ;;
            NMC)
                display_coin="Namecoin (NMC)"
                display_rpc_user="$NMC_RPC_USER"
                display_stratum_port="14335"
                display_wallet="$NMC_ADDRESS"
                ;;
            XMY)
                display_coin="Myriadcoin (XMY)"
                display_rpc_user="$XMY_RPC_USER"
                display_stratum_port="17335"
                display_wallet="$XMY_ADDRESS"
                ;;
            SYS)
                display_coin="Syscoin (SYS)"
                display_rpc_user="$SYS_RPC_USER"
                display_stratum_port="15335"
                display_wallet="$SYS_ADDRESS"
                ;;
            FBTC)
                display_coin="Fractal Bitcoin (FBTC)"
                display_rpc_user="$FBTC_RPC_USER"
                display_stratum_port="18335"
                display_wallet="$FBTC_ADDRESS"
                ;;
            QBX)
                display_coin="Q-BitX (QBX)"
                display_rpc_user="$QBX_RPC_USER"
                display_stratum_port="20335"
                display_wallet="$QBX_ADDRESS"
                ;;
            *)
                display_coin="Unknown"
                display_rpc_user="$RPC_USER"
                display_stratum_port="$STRATUM_PORT"
                display_wallet="$POOL_ADDRESS"
                ;;
        esac

        echo -e "  ${WHITE}Coin:${NC}          ${GREEN}$display_coin${NC}"
        echo -e "  ${WHITE}RPC User:${NC}      ${GREEN}$display_rpc_user${NC}"
        echo -e "  ${WHITE}Server IP:${NC}     ${GREEN}$SERVER_IP${NC}"
        if [[ "$display_wallet" == "PENDING_GENERATION" ]]; then
            echo -e "  ${WHITE}Wallet:${NC}        ${YELLOW}Auto-generated after blockchain sync${NC}"
            echo -e "                 ${YELLOW}(address displayed in sync watcher when ready)${NC}"
        else
            echo -e "  ${WHITE}Wallet:${NC}        ${GREEN}$display_wallet${NC}"
        fi
        echo -e "  ${WHITE}Coinbase:${NC}      ${GREEN}$COINBASE_TEXT${NC}"
        echo -e "  ${WHITE}Expected TH/s:${NC} ${GREEN}$EXPECTED_THS TH/s${NC}"
        echo -e "  ${WHITE}Stratum Port:${NC}  ${GREEN}$display_stratum_port${NC}"
    else
        # Multi-coin mode - show enabled coins
        echo -e "  ${WHITE}Server IP:${NC}     ${GREEN}$SERVER_IP${NC}"
        echo -e "  ${WHITE}Enabled Coins:${NC}"
        # Helper to display coin address or pending message
        show_coin_addr() {
            local coin_label="$1" port="$2" addr="$3"
            if [[ "$addr" == "PENDING_GENERATION" ]]; then
                echo -e "    ${GREEN}• ${coin_label}${NC} (port $port) - ${YELLOW}wallet after sync${NC}"
            else
                echo -e "    ${GREEN}• ${coin_label}${NC} (port $port) - $addr"
            fi
        }
        [[ "$ENABLE_DGB" == "true" ]] && show_coin_addr "DGB" "3333" "$POOL_ADDRESS"
        [[ "$ENABLE_DGB_SCRYPT" == "true" ]] && show_coin_addr "DGB-SCRYPT" "3336" "$POOL_ADDRESS"
        [[ "$ENABLE_BTC" == "true" ]] && show_coin_addr "BTC" "4333" "$BTC_ADDRESS"
        [[ "$ENABLE_BCH" == "true" ]] && show_coin_addr "BCH" "5333" "$BCH_ADDRESS"
        [[ "$ENABLE_BC2" == "true" ]] && show_coin_addr "BC2" "6333" "$BC2_ADDRESS"
        [[ "$ENABLE_NMC" == "true" ]] && show_coin_addr "NMC" "14335" "${NMC_ADDRESS:-$NMC_POOL_ADDRESS}"
        [[ "$ENABLE_SYS" == "true" ]] && show_coin_addr "SYS" "15335" "${SYS_ADDRESS:-$SYS_POOL_ADDRESS}"
        [[ "$ENABLE_XMY" == "true" ]] && show_coin_addr "XMY" "17335" "${XMY_ADDRESS:-$XMY_POOL_ADDRESS}"
        [[ "$ENABLE_FBTC" == "true" ]] && show_coin_addr "FBTC" "18335" "${FBTC_ADDRESS:-$FBTC_POOL_ADDRESS}"
        [[ "$ENABLE_QBX" == "true" ]] && show_coin_addr "QBX" "20335" "${QBX_ADDRESS:-$QBX_POOL_ADDRESS}"
        [[ "$ENABLE_LTC" == "true" ]] && show_coin_addr "LTC" "7333" "$LTC_ADDRESS"
        [[ "$ENABLE_DOGE" == "true" ]] && show_coin_addr "DOGE" "8335" "$DOGE_ADDRESS"
        [[ "$ENABLE_PEP" == "true" ]] && show_coin_addr "PEP" "10335" "$PEP_ADDRESS"
        [[ "$ENABLE_CAT" == "true" ]] && show_coin_addr "CAT" "12335" "$CAT_ADDRESS"
        echo -e "  ${WHITE}Coinbase:${NC}      ${GREEN}$COINBASE_TEXT${NC}"
        echo -e "  ${WHITE}Expected TH/s:${NC} ${GREEN}$EXPECTED_THS TH/s${NC}"
    fi
    if [[ "$TOR_ENABLED" == "true" ]]; then
        echo -e "  ${WHITE}Network:${NC}       ${YELLOW}TOR (Privacy Mode - Slower Sync)${NC}"
    else
        echo -e "  ${WHITE}Network:${NC}       ${GREEN}CLEARNET (Fast Sync)${NC}"
    fi
    if [[ "$CONFIGURE_DNS" == "true" ]]; then
        if [[ -n "$DNS_SECONDARY" ]]; then
            echo -e "  ${WHITE}DNS Servers:${NC}   ${GREEN}$DNS_PRIMARY, $DNS_SECONDARY${NC}"
        else
            echo -e "  ${WHITE}DNS Server:${NC}    ${GREEN}$DNS_PRIMARY${NC}"
        fi
    else
        echo -e "  ${WHITE}DNS Servers:${NC}   ${GREEN}(system default)${NC}"
    fi
    if [[ "$HA_MODE" == "ha-backup" ]]; then
        echo -e "  ${WHITE}Sync Method:${NC}   ${GREEN}Replicate from primary (${HA_PRIMARY_IP:-$HA_PEER_IP}) if available, otherwise P2P${NC}"
    elif [[ "$BLOCKCHAIN_SYNC_CHOICE" == "2" ]]; then
        echo -e "  ${WHITE}Sync Method:${NC}   ${GREEN}Copy from ${SYNC_SOURCE_NODE}${NC}"
    else
        echo -e "  ${WHITE}Sync Method:${NC}   ${GREEN}Network (P2P)${NC}"
    fi
    if [[ "$ENABLE_AUTO_BACKUPS" == "true" ]]; then
        echo -e "  ${WHITE}Backups:${NC}       ${GREEN}Enabled (daily)${NC}"
    else
        echo -e "  ${WHITE}Backups:${NC}       ${YELLOW}Disabled${NC}"
    fi
    if [[ "$WATCH_SYNC_ON_EXIT" == "true" ]]; then
        echo -e "  ${WHITE}Sync Watcher:${NC}  ${GREEN}Enabled${NC}"
    else
        echo -e "  ${WHITE}Sync Watcher:${NC}  ${YELLOW}Disabled${NC}"
    fi
    echo ""
    echo -e "${YELLOW}═══════════════════════════════════════════════════════════${NC}"
    echo ""
    echo ""

    prompt_input "Proceed with installation? (Y/n): "; read -n 1 -r
    echo ""
    if [[ $REPLY =~ ^[Nn]$ ]]; then
        log "Installation cancelled"
        exit 0
    fi
}

# ═══════════════════════════════════════════════════════════════════════════════
# SYSTEM SETUP
# ═══════════════════════════════════════════════════════════════════════════════

setup_system() {
    log_step "System Setup"

    # Create pool user and group
    if ! getent group "$POOL_USER" &>/dev/null; then
        sudo groupadd -r "$POOL_USER"
        log_success "Created group: $POOL_USER"
    else
        log "Group $POOL_USER exists"
    fi

    if id "$POOL_USER" &>/dev/null; then
        log "User $POOL_USER exists"
    else
        sudo useradd -r -m -s /bin/bash -g "$POOL_USER" "$POOL_USER"
        log_success "Created user: $POOL_USER"

        # Set password for pool user (required for HA SSH, interactive sessions, sudo)
        # Uses passwd --stdin-style heredoc to avoid leaking password in process list
        echo ""
        echo -e "${CYAN}${BOLD}Set a password for the ${POOL_USER} user${NC}"
        echo -e "${DIM}This is needed for HA cluster SSH, interactive logins, and admin tasks.${NC}"
        echo ""
        local pass_set=false
        for attempt in 1 2 3; do
            local pool_pass pool_pass_confirm
            read -sp "  Enter password for ${POOL_USER}: " pool_pass
            echo ""
            read -sp "  Confirm password: " pool_pass_confirm
            echo ""
            if [[ -z "$pool_pass" ]]; then
                log_warn "Password cannot be empty."
            elif [[ "$pool_pass" != "$pool_pass_confirm" ]]; then
                log_warn "Passwords do not match."
            else
                sudo chpasswd <<< "${POOL_USER}:${pool_pass}"
                unset pool_pass pool_pass_confirm
                log_success "Password set for ${POOL_USER}"
                pass_set=true
                break
            fi
            [[ $attempt -lt 3 ]] && echo "  Please try again..."
        done
        if [[ "$pass_set" != "true" ]]; then
            log_warn "Password not set after 3 attempts. You can set it later with: sudo passwd ${POOL_USER}"
        fi
        echo ""
    fi
    sudo usermod -aG "$POOL_USER" "$ADMIN_USER" 2>/dev/null || true

    # Ensure sshd allows password auth for pool user (for HA, interactive admin, SCP)
    # Uses a Match User block so global SSH settings (e.g. key-only) are not weakened
    local sshd_dropin="/etc/ssh/sshd_config.d/spiralpool.conf"
    local sshd_main="/etc/ssh/sshd_config"
    local sshd_marker="# Spiral Pool — allow password auth for pool user"
    if ! grep -q "Match User ${POOL_USER}" "$sshd_main" 2>/dev/null && \
       ! grep -q "Match User ${POOL_USER}" "$sshd_dropin" 2>/dev/null; then
        if [[ -d "/etc/ssh/sshd_config.d" ]] && grep -q 'Include.*/etc/ssh/sshd_config.d/' "$sshd_main" 2>/dev/null; then
            # Modern sshd with drop-in support — write a clean standalone file
            sudo tee "$sshd_dropin" > /dev/null << SSHDEOF
${sshd_marker}
Match User ${POOL_USER}
    PasswordAuthentication yes
SSHDEOF
            log_success "SSH password auth enabled for ${POOL_USER} (drop-in: $sshd_dropin)"
        else
            # Legacy sshd — append Match block to main config
            sudo tee -a "$sshd_main" > /dev/null << SSHDEOF

${sshd_marker}
Match User ${POOL_USER}
    PasswordAuthentication yes
SSHDEOF
            log_success "SSH password auth enabled for ${POOL_USER} (appended to $sshd_main)"
        fi
        # Validate config before reloading — on fresh installs /run/sshd may not
        # exist yet (created when sshd first starts). Create it so sshd -t passes.
        sudo mkdir -p /run/sshd
        if sudo sshd -t 2>/dev/null; then
            sudo systemctl reload sshd 2>/dev/null || sudo systemctl reload ssh 2>/dev/null || true
        else
            log_warn "sshd config test deferred — will reload after prerequisites are installed"
            SSHD_RELOAD_DEFERRED=true
        fi
    fi

    # Generate SSH keys for pool user (used for blockchain replication between nodes)
    # For HA backup, setup_ha_ssh_keys() handles dir creation + key gen + copy to primary
    if [[ "$HA_MODE" == "ha-backup" ]]; then
        echo ""
        echo -e "${CYAN}SSH Key Setup for Replication${NC}"
        echo "Setting up passwordless SSH access to primary node for data replication..."
        echo ""
        setup_ha_ssh_keys "${HA_PRIMARY_IP:-$HA_PEER_IP}" "$HA_SSH_PASSWORD"

        # Update existing peers' firewall/pg_hba with this node's IP
        # Only runs if SSH was set up successfully — non-fatal if peers can't be reached
        if [[ "$HA_SSH_READY" == "true" ]]; then
            update_existing_peers
        fi
    else
        local ssh_dir="/home/${POOL_USER}/.ssh"
        local ssh_key_path="${ssh_dir}/id_ed25519"
        if [[ ! -d "$ssh_dir" ]]; then
            sudo -u "$POOL_USER" mkdir -p "$ssh_dir"
        fi
        # Always ensure correct ownership/permissions (fixes issues from previous runs)
        sudo chown "${POOL_USER}:${POOL_USER}" "$ssh_dir"
        sudo chmod 700 "$ssh_dir"

        # Check if key exists (as root to avoid permission issues with existing files)
        if [[ -f "$ssh_key_path" ]]; then
            # Fix ownership on existing key files
            sudo chown "${POOL_USER}:${POOL_USER}" "$ssh_key_path"
            sudo chmod 600 "$ssh_key_path"
            [[ -f "${ssh_key_path}.pub" ]] && sudo chown "${POOL_USER}:${POOL_USER}" "${ssh_key_path}.pub" && sudo chmod 644 "${ssh_key_path}.pub"
            log "Using existing SSH key: $ssh_key_path"
        else
            log "Generating SSH key for ${POOL_USER}..."
            sudo -u "$POOL_USER" ssh-keygen -t ed25519 -f "$ssh_key_path" -N "" -C "spiralpool-replication" -q || log_warn "SSH key generation failed (non-critical)"
            log_success "SSH key generated for ${POOL_USER}"
        fi
    fi

    # Note: HA cluster communication is handled entirely by the VIP manager using
    # encrypted UDP (AES-256-GCM) and does NOT require SSH. The pool user runs
    # the stratum server which includes the HA VIP manager.

    # Install prerequisites
    log "Installing prerequisites..."
    wait_for_apt_lock
    sudo apt-get update -qq || log_warn "apt-get update had errors (some repos may be unreachable)"
    wait_for_apt_lock
    sudo apt-get install -y -qq \
        apt-utils \
        curl wget git build-essential ca-certificates gnupg openssl \
        lsb-release software-properties-common ufw htop jq unzip \
        python3 python3-pip python3-venv bc \
        libzmq3-dev pkg-config \
        iproute2 iputils-arping iputils-ping \
        netcat-openbsd dnsutils \
        rsync openssh-client \
        net-tools lsof \
        cron \
        xz-utils || { log_error "Failed to install prerequisite packages"; return 1; }

    # Deferred sshd reload — sshd -t may have failed earlier if host keys weren't
    # generated yet (common on fresh installs). Now that packages are installed, retry.
    if [[ "${SSHD_RELOAD_DEFERRED:-false}" == "true" ]]; then
        sudo mkdir -p /run/sshd
        if sudo sshd -t 2>&1; then
            sudo systemctl reload sshd 2>/dev/null || sudo systemctl reload ssh 2>/dev/null || true
            log_success "sshd reloaded — SSH password auth now active for ${POOL_USER}"
        else
            log_warn "sshd config test failed — check /etc/ssh/sshd_config manually"
        fi
        SSHD_RELOAD_DEFERRED=false
    fi

    # Note: xz-utils provides 'xz' for extracting .tar.xz archives
    # Note: iproute2 provides 'ip' command for macvlan VIP interface
    # Note: iputils-arping provides 'arping' for gratuitous ARP announcements
    # Note: netcat-openbsd and dnsutils for network diagnostics and health checks
    # Note: net-tools provides 'netstat' and lsof for network diagnostics

    # ═══════════════════════════════════════════════════════════════════════════
    # SYSCTL TUNING FOR HIGH-CONNECTION MINING POOL
    # ═══════════════════════════════════════════════════════════════════════════
    log "Configuring kernel parameters for high-connection mining pool..."

    sudo tee /etc/sysctl.d/99-spiralpool.conf > /dev/null << 'SYSCTL'
# ╔════════════════════════════════════════════════════════════════════════════╗
# ║                 SPIRAL POOL - KERNEL TUNING                                ║
# ║                                                                            ║
# ║  Optimized for high-connection mining pool workloads:                      ║
# ║  - Many concurrent TCP connections (thousands of miners)                   ║
# ║  - Low latency stratum communication                                       ║
# ║  - ZMQ pub/sub for block notifications                                     ║
# ║  - PostgreSQL database connections                                         ║
# ╚════════════════════════════════════════════════════════════════════════════╝

# ═══════════════════════════════════════════════════════════════════════════════
# FILE DESCRIPTOR LIMITS
# ═══════════════════════════════════════════════════════════════════════════════
# Each miner connection uses a file descriptor. Default is too low for pools.
fs.file-max = 2097152
fs.nr_open = 2097152

# ═══════════════════════════════════════════════════════════════════════════════
# TCP CONNECTION HANDLING
# ═══════════════════════════════════════════════════════════════════════════════
# Increase connection backlog for burst connections during block notifications
net.core.somaxconn = 65535
net.core.netdev_max_backlog = 65535

# Allow more connections in TIME_WAIT state (miners reconnecting)
net.ipv4.tcp_max_tw_buckets = 2000000

# Faster cleanup of TIME_WAIT connections
net.ipv4.tcp_tw_reuse = 1
net.ipv4.tcp_fin_timeout = 15

# Increase local port range for outbound connections
net.ipv4.ip_local_port_range = 10000 65535

# ═══════════════════════════════════════════════════════════════════════════════
# TCP KEEPALIVE (detect dead miner connections faster)
# ═══════════════════════════════════════════════════════════════════════════════
net.ipv4.tcp_keepalive_time = 60
net.ipv4.tcp_keepalive_intvl = 10
net.ipv4.tcp_keepalive_probes = 6

# ═══════════════════════════════════════════════════════════════════════════════
# TCP MEMORY BUFFERS
# ═══════════════════════════════════════════════════════════════════════════════
# Increase TCP buffer sizes for better throughput
net.core.rmem_default = 262144
net.core.wmem_default = 262144
net.core.rmem_max = 16777216
net.core.wmem_max = 16777216
net.ipv4.tcp_rmem = 4096 262144 16777216
net.ipv4.tcp_wmem = 4096 262144 16777216

# Increase TCP memory limits (in pages, default page = 4KB)
net.ipv4.tcp_mem = 786432 1048576 1572864

# ═══════════════════════════════════════════════════════════════════════════════
# SYN FLOOD PROTECTION (while allowing high connection rates)
# ═══════════════════════════════════════════════════════════════════════════════
# Enable SYN cookies to handle SYN floods gracefully
net.ipv4.tcp_syncookies = 1
net.ipv4.tcp_max_syn_backlog = 65535

# ═══════════════════════════════════════════════════════════════════════════════
# VIRTUAL MEMORY (beneficial for blockchain nodes)
# ═══════════════════════════════════════════════════════════════════════════════
# Reduce swappiness - prefer keeping blockchain data in RAM
vm.swappiness = 10

# Better dirty page handling for database workloads
vm.dirty_ratio = 40
vm.dirty_background_ratio = 10

# ═══════════════════════════════════════════════════════════════════════════════
# IPv6 DISABLED
# ═══════════════════════════════════════════════════════════════════════════════
# Spiral Pool is IPv4-only. IPv6 is not supported.
# Disabling IPv6 prevents routing cache corruption when network interfaces change
# (e.g., keepalived VIP failover) and reduces attack surface.
net.ipv6.conf.all.disable_ipv6 = 1
net.ipv6.conf.default.disable_ipv6 = 1
SYSCTL

    # Apply sysctl settings immediately
    sudo sysctl -p /etc/sysctl.d/99-spiralpool.conf >/dev/null 2>&1 || true

    # Flush routing cache — disabling IPv6 triggers kernel FIB recalculation
    # which can leave stale broadcast entries in the IPv4 routing cache
    sudo ip route flush cache 2>/dev/null || true

    # Validate critical kernel parameters were actually applied
    local validation_errors=0
    local actual_swappiness=$(cat /proc/sys/vm/swappiness 2>/dev/null || echo "-1")
    if [[ "$actual_swappiness" != "10" ]]; then
        log_warn "vm.swappiness not applied (expected 10, got $actual_swappiness)"
        ((++validation_errors))
    fi
    local actual_file_max=$(cat /proc/sys/fs/file-max 2>/dev/null || echo "-1")
    if [[ "$actual_file_max" -lt 2097152 ]]; then
        log_warn "fs.file-max not applied (expected >=2097152, got $actual_file_max)"
        ((++validation_errors))
    fi
    if [[ $validation_errors -eq 0 ]]; then
        log_success "Kernel parameters validated (swappiness=$actual_swappiness, file-max=$actual_file_max)"
    else
        log_warn "Some kernel parameters may require reboot to take effect"
    fi

    # Configure ulimits for pool user
    sudo tee /etc/security/limits.d/99-spiralpool.conf > /dev/null << LIMITS
# Spiral Pool - File descriptor limits for mining pool services
${POOL_USER}     soft    nofile    65535
${POOL_USER}     hard    nofile    1048576
${POOL_USER}     soft    nproc     65535
${POOL_USER}     hard    nproc     65535
root             soft    nofile    65535
root             hard    nofile    1048576
LIMITS

    log_success "Kernel parameters configured for high-connection workloads"

    # Install Tor if enabled
    if [[ "$TOR_ENABLED" == "true" ]]; then
        log "Installing Tor (client mode only)..."
        wait_for_apt_lock
        sudo apt-get install -y -qq tor || { log_error "Failed to install Tor"; return 1; }

        # Configure Tor as CLIENT ONLY (never a relay or exit node)
        # This ensures no other users' traffic passes through this server
        sudo tee /etc/tor/torrc > /dev/null << 'TORRC'
# Tor Configuration - CLIENT ONLY
# Spiral Pool - Blockchain Node Privacy

# === CRITICAL: CLIENT MODE ONLY ===
# These settings ensure this server NEVER acts as a relay or exit node
# No traffic from other Tor users will pass through this server

# Disable relay mode completely
ORPort 0
ExitRelay 0
ExitPolicy reject *:*

# Disable bridge relay
BridgeRelay 0

# SOCKS proxy for local applications (DigiByte will use this)
SocksPort 9050
SocksPolicy accept 127.0.0.1
SocksPolicy reject *

# Control port for status checks (optional, local only)
ControlPort 9051
CookieAuthentication 1

# Logging
Log notice file /var/log/tor/notices.log

# Performance tuning for blockchain sync
# Use 3 guard nodes for reliability
NumEntryGuards 3
# Don't use extremely slow circuits
CircuitBuildTimeout 30
LearnCircuitBuildTimeout 1
TORRC

        # Start Tor service
        sudo systemctl enable tor || true
        sudo systemctl start tor || log_warn "Failed to start Tor — will retry later"
        log_success "Tor installed and configured (client mode only)"

        # Wait for Tor to establish circuits with progress display
        log "Waiting for Tor to establish circuits..."
        echo -e "  ${CYAN}This typically takes 30-60 seconds on first run...${NC}"
        echo ""
        local tor_wait=0
        local tor_max_wait=90
        local spinner=('⠋' '⠙' '⠹' '⠸' '⠼' '⠴' '⠦' '⠧' '⠇' '⠏')
        local spin_idx=0

        while ! curl --socks5-hostname 127.0.0.1:9050 -s --max-time 5 https://check.torproject.org/api/ip >/dev/null 2>&1; do
            # Show progress spinner and time elapsed
            printf "\r  ${spinner[$spin_idx]} Establishing Tor circuits... [%ds / %ds]" "$tor_wait" "$tor_max_wait"
            spin_idx=$(( (spin_idx + 1) % ${#spinner[@]} ))

            sleep 2
            tor_wait=$((tor_wait + 2))

            if [[ $tor_wait -ge $tor_max_wait ]]; then
                printf "\n"
                log_warn "Tor taking longer than expected ($tor_max_wait seconds)"
                echo -e "  ${YELLOW}This could mean:${NC}"
                echo -e "    • Slow network connection"
                echo -e "    • Tor network congestion"
                echo -e "    • Firewall blocking Tor (ports 9001, 9030)"
                echo ""
                echo -e "  ${WHITE}Options:${NC}"
                echo -e "    ${GREEN}w${NC} = Wait another 60 seconds"
                echo -e "    ${YELLOW}c${NC} = Continue without Tor (use clearnet)"
                echo -e "    ${RED}a${NC} = Abort installation"
                echo ""
                prompt_input "Choice [w/c/a]: "; read tor_choice
                case "$tor_choice" in
                    w|W)
                        log "Waiting another 60 seconds for Tor..."
                        tor_max_wait=$((tor_max_wait + 60))
                        ;;
                    c|C)
                        log_warn "Continuing without Tor - blockchain nodes will use clearnet"
                        TOR_ENABLED="false"
                        break
                        ;;
                    a|A)
                        log_error "Installation aborted by user"
                        exit 1
                        ;;
                    *)
                        log "Waiting another 60 seconds for Tor..."
                        tor_max_wait=$((tor_max_wait + 60))
                        ;;
                esac
            fi
        done

        printf "\r                                                              \r"  # Clear spinner line

        if [[ "$TOR_ENABLED" == "true" ]]; then
            # Get Tor exit IP for verification
            local tor_exit_ip
            tor_exit_ip=$(curl --socks5-hostname 127.0.0.1:9050 -s --max-time 10 https://check.torproject.org/api/ip 2>/dev/null | jq -r '.IP // empty' 2>/dev/null || echo "unknown")

            log_success "Tor connection established in ${tor_wait}s"
            if [[ "$tor_exit_ip" != "unknown" && -n "$tor_exit_ip" ]]; then
                echo -e "  ${GREEN}✓${NC} Tor exit node IP: ${CYAN}$tor_exit_ip${NC}"
                echo -e "  ${GREEN}✓${NC} Your real IP is hidden from peers"
            fi
        fi
    fi

    # ─────────────────────────────────────────────────────────────────────────────
    # Multi-disk storage configuration (optional)
    # Only offered on fresh installs when additional disks are detected
    # User can skip to use single-disk configuration (default)
    # ─────────────────────────────────────────────────────────────────────────────
    configure_multi_disk_storage

    # Create directories
    sudo mkdir -p "$INSTALL_DIR"/{bin,config,logs,data,backups}
    sudo mkdir -p /etc/spiralpool
    sudo chown -R "$POOL_USER:$POOL_USER" "$INSTALL_DIR"
    sudo chown -R "$POOL_USER:$POOL_USER" /etc/spiralpool

    # Create runtime directory config (survives reboots via tmpfiles.d)
    # /run is tmpfs — cleared on every reboot. systemd-tmpfiles recreates this on boot.
    # 13 scripts depend on /run/spiralpool/ for lock files, temp data, and caches.
    sudo tee /etc/tmpfiles.d/spiralpool.conf > /dev/null << TMPEOF
# Spiral Pool runtime directory — lock files, temp data, miner caches
d /run/spiralpool 0755 $POOL_USER $POOL_USER -
TMPEOF
    sudo systemd-tmpfiles --create /etc/tmpfiles.d/spiralpool.conf 2>/dev/null || true

    # Set up multi-disk mounts if configured (creates /spiralpool/chain mount)
    setup_multi_disk_mounts

    # Shared data directory - accessible by both spiraluser service and admin user
    # This is where miners.json and other shared config files live
    sudo chmod 775 "$INSTALL_DIR/data"
    # Add admin user to spiraluser group for shared access
    sudo usermod -aG "$POOL_USER" "$ADMIN_USER" 2>/dev/null || true

    # Initialize empty miners.json database if it doesn't exist
    # This ensures Sentinel can start without errors even before miners are scanned
    MINER_DB="$INSTALL_DIR/data/miners.json"
    if [[ ! -f "$MINER_DB" ]]; then
        log "Initializing miner database at $MINER_DB"
        sudo tee "$MINER_DB" > /dev/null << 'MINERDBEOF'
{
  "miners": {},
  "by_type": {
    "nmaxe": [],
    "nerdqaxe": [],
    "avalon": [],
    "antminer": [],
    "whatsminer": [],
    "innosilicon": []
  },
  "last_scan": null
}
MINERDBEOF
        sudo chown "$POOL_USER:$POOL_USER" "$MINER_DB"
        sudo chmod 664 "$MINER_DB"
    fi

    # Configure firewall (IMPORTANT: Allow SSH first to prevent lockout!)
    log "Configuring firewall..."

    # CRITICAL: Ensure SSH is allowed BEFORE any reset or enable
    # This prevents SSH disconnection during firewall configuration
    sudo ufw allow 22/tcp > /dev/null 2>&1          # SSH - MUST BE FIRST

    # Only reset if ufw is not already active with rules
    # This prevents disruption of existing SSH sessions
    if ! sudo ufw status | grep -q "22/tcp.*ALLOW" 2>/dev/null; then
        sudo ufw --force reset > /dev/null 2>&1
        sudo ufw allow 22/tcp > /dev/null 2>&1      # Re-add SSH after reset
    fi

    sudo ufw default deny incoming > /dev/null 2>&1
    sudo ufw default allow outgoing > /dev/null 2>&1
    # Single-coin mode: open generic stratum ports (empty in multi-coin mode)
    [[ -n "$STRATUM_PORT" ]]    && sudo ufw allow $STRATUM_PORT/tcp > /dev/null 2>&1    # Stratum V1 (miners)
    [[ -n "$STRATUM_V2_PORT" ]] && sudo ufw allow $STRATUM_V2_PORT/tcp > /dev/null 2>&1 # Stratum V2 (miners)
    sudo ufw allow $API_PORT/tcp > /dev/null 2>&1         # Pool API
    sudo ufw allow $DASHBOARD_PORT/tcp > /dev/null 2>&1  # Dashboard
    sudo ufw allow $METRICS_PORT/tcp > /dev/null 2>&1    # Prometheus metrics

    # Multi-coin P2P and Stratum ports (opened based on enabled coins)
    if [[ "$ENABLE_DGB" == "true" ]]; then
        sudo ufw allow 3333/tcp > /dev/null 2>&1         # DGB Stratum V1
        sudo ufw allow 3334/tcp > /dev/null 2>&1         # DGB Stratum V2
        sudo ufw allow 3335/tcp > /dev/null 2>&1         # DGB Stratum TLS
        sudo ufw allow 12024/tcp > /dev/null 2>&1        # DGB P2P
        log "DigiByte ports opened: 3333-3335/tcp (stratum V1/V2/TLS), 12024/tcp (P2P)"
    fi
    if [[ "$ENABLE_BTC" == "true" ]]; then
        sudo ufw allow 4333/tcp > /dev/null 2>&1         # BTC Stratum V1
        sudo ufw allow 4334/tcp > /dev/null 2>&1         # BTC Stratum V2
        sudo ufw allow 4335/tcp > /dev/null 2>&1         # BTC Stratum TLS
        sudo ufw allow 8333/tcp > /dev/null 2>&1         # BTC P2P
        log "Bitcoin ports opened: 4333-4335/tcp (stratum V1/V2/TLS), 8333/tcp (P2P)"
    fi
    if [[ "$ENABLE_BCH" == "true" ]]; then
        sudo ufw allow 5333/tcp > /dev/null 2>&1         # BCH Stratum V1
        sudo ufw allow 5334/tcp > /dev/null 2>&1         # BCH Stratum V2
        sudo ufw allow 5335/tcp > /dev/null 2>&1         # BCH Stratum TLS
        sudo ufw allow 8433/tcp > /dev/null 2>&1         # BCH P2P
        log "Bitcoin Cash ports opened: 5333-5335/tcp (stratum V1/V2/TLS), 8433/tcp (P2P)"
    fi
    if [[ "$ENABLE_BC2" == "true" ]]; then
        sudo ufw allow 6333/tcp > /dev/null 2>&1         # BC2 Stratum V1
        sudo ufw allow 6334/tcp > /dev/null 2>&1         # BC2 Stratum V2
        sudo ufw allow 6335/tcp > /dev/null 2>&1         # BC2 Stratum TLS
        sudo ufw allow 8338/tcp > /dev/null 2>&1         # BC2 P2P
        log "Bitcoin II ports opened: 6333-6335/tcp (stratum V1/V2/TLS), 8338/tcp (P2P)"
    fi
    # SHA-256d AuxPoW coins (merge-mineable with Bitcoin)
    if [[ "$ENABLE_NMC" == "true" ]]; then
        sudo ufw allow 14335/tcp > /dev/null 2>&1        # NMC Stratum V1
        sudo ufw allow 14336/tcp > /dev/null 2>&1        # NMC Stratum V2
        sudo ufw allow 14337/tcp > /dev/null 2>&1        # NMC Stratum TLS
        sudo ufw allow 8334/tcp > /dev/null 2>&1         # NMC P2P
        log "Namecoin ports opened: 14335-14337/tcp (stratum V1/V2/TLS), 8334/tcp (P2P)"
    fi
    if [[ "$ENABLE_SYS" == "true" ]]; then
        sudo ufw allow 15335/tcp > /dev/null 2>&1        # SYS Stratum V1
        sudo ufw allow 15336/tcp > /dev/null 2>&1        # SYS Stratum V2
        sudo ufw allow 15337/tcp > /dev/null 2>&1        # SYS Stratum TLS
        sudo ufw allow 8369/tcp > /dev/null 2>&1         # SYS P2P
        log "Syscoin ports opened: 15335-15337/tcp (stratum V1/V2/TLS), 8369/tcp (P2P)"
    fi
    if [[ "$ENABLE_XMY" == "true" ]]; then
        sudo ufw allow 17335/tcp > /dev/null 2>&1        # XMY Stratum V1
        sudo ufw allow 17336/tcp > /dev/null 2>&1        # XMY Stratum V2
        sudo ufw allow 17337/tcp > /dev/null 2>&1        # XMY Stratum TLS
        sudo ufw allow 10888/tcp > /dev/null 2>&1        # XMY P2P
        log "Myriad ports opened: 17335-17337/tcp (stratum V1/V2/TLS), 10888/tcp (P2P)"
    fi
    if [[ "$ENABLE_LTC" == "true" ]]; then
        sudo ufw allow 7333/tcp > /dev/null 2>&1         # LTC Stratum V1
        sudo ufw allow 7334/tcp > /dev/null 2>&1         # LTC Stratum V2
        sudo ufw allow 7335/tcp > /dev/null 2>&1         # LTC Stratum TLS
        sudo ufw allow 9333/tcp > /dev/null 2>&1         # LTC P2P
        log "Litecoin ports opened: 7333-7335/tcp (stratum V1/V2/TLS), 9333/tcp (P2P)"
    fi
    if [[ "$ENABLE_DOGE" == "true" ]]; then
        sudo ufw allow 8335/tcp > /dev/null 2>&1         # DOGE Stratum V1
        sudo ufw allow 8337/tcp > /dev/null 2>&1         # DOGE Stratum V2
        sudo ufw allow 8342/tcp > /dev/null 2>&1         # DOGE Stratum TLS
        sudo ufw allow 22556/tcp > /dev/null 2>&1        # DOGE P2P
        log "Dogecoin ports opened: 8335,8337,8342/tcp (stratum V1/V2/TLS), 22556/tcp (P2P)"
    fi
    if [[ "$ENABLE_DGB_SCRYPT" == "true" ]]; then
        sudo ufw allow 3336/tcp > /dev/null 2>&1         # DGB-Scrypt Stratum V1
        sudo ufw allow 3337/tcp > /dev/null 2>&1         # DGB-Scrypt Stratum V2
        sudo ufw allow 3338/tcp > /dev/null 2>&1         # DGB-Scrypt Stratum TLS
        # DGB-SCRYPT shares DGB daemon — ensure P2P port is open even without DGB SHA256d
        if [[ "$ENABLE_DGB" != "true" ]]; then
            sudo ufw allow 12024/tcp > /dev/null 2>&1    # DGB P2P (shared daemon)
        fi
        log "DigiByte-Scrypt ports opened: 3336-3338/tcp (stratum V1/V2/TLS)"
    fi
    if [[ "$ENABLE_PEP" == "true" ]]; then
        sudo ufw allow 10335/tcp > /dev/null 2>&1        # PEP Stratum V1
        sudo ufw allow 10336/tcp > /dev/null 2>&1        # PEP Stratum V2
        sudo ufw allow 10337/tcp > /dev/null 2>&1        # PEP Stratum TLS
        sudo ufw allow 33874/tcp > /dev/null 2>&1        # PEP P2P
        log "PepeCoin ports opened: 10335-10337/tcp (stratum V1/V2/TLS), 33874/tcp (P2P)"
    fi
    if [[ "$ENABLE_CAT" == "true" ]]; then
        sudo ufw allow 12335/tcp > /dev/null 2>&1        # CAT Stratum V1
        sudo ufw allow 12336/tcp > /dev/null 2>&1        # CAT Stratum V2
        sudo ufw allow 12337/tcp > /dev/null 2>&1        # CAT Stratum TLS
        sudo ufw allow 9933/tcp > /dev/null 2>&1         # CAT P2P
        log "Catcoin ports opened: 12335-12337/tcp (stratum V1/V2/TLS), 9933/tcp (P2P)"
    fi
    if [[ "$ENABLE_FBTC" == "true" ]]; then
        sudo ufw allow 18335/tcp > /dev/null 2>&1        # FBTC Stratum V1
        sudo ufw allow 18336/tcp > /dev/null 2>&1        # FBTC Stratum V2
        sudo ufw allow 18337/tcp > /dev/null 2>&1        # FBTC Stratum TLS
        sudo ufw allow 8341/tcp > /dev/null 2>&1         # FBTC P2P
        log "Fractal Bitcoin ports opened: 18335-18337/tcp (stratum V1/V2/TLS), 8341/tcp (P2P)"
    fi
    if [[ "$ENABLE_QBX" == "true" ]]; then
        sudo ufw allow 20335/tcp > /dev/null 2>&1        # QBX Stratum V1
        sudo ufw allow 20336/tcp > /dev/null 2>&1        # QBX Stratum V2
        sudo ufw allow 20337/tcp > /dev/null 2>&1        # QBX Stratum TLS
        sudo ufw allow 8345/tcp > /dev/null 2>&1         # QBX P2P
        log "Q-BitX ports opened: 20335-20337/tcp (stratum V1/V2/TLS), 8345/tcp (P2P)"
    fi

    # HA Cluster ports (if HA enabled) — restricted to peer IPs only
    # UFW allows loopback (127.0.0.1) by default, so local services can still connect.
    # These ports are internal-only and must NEVER be exposed to the public internet.
    if [[ "$HA_ENABLED" == "true" ]] && [[ ${#HA_PEER_IPS[@]} -gt 0 ]]; then
        for peer_ip in "${HA_PEER_IPS[@]}"; do
            sudo ufw allow from "$peer_ip" to any port 5363 proto udp > /dev/null 2>&1   # HA cluster discovery
            sudo ufw allow from "$peer_ip" to any port 5354 proto tcp > /dev/null 2>&1   # HA status API
            sudo ufw allow from "$peer_ip" to any port 5432 proto tcp > /dev/null 2>&1   # PostgreSQL replication
            sudo ufw allow from "$peer_ip" to any port 2379 proto tcp > /dev/null 2>&1   # etcd client port
            sudo ufw allow from "$peer_ip" to any port 2380 proto tcp > /dev/null 2>&1   # etcd peer port
            sudo ufw allow from "$peer_ip" to any port 8008 proto tcp > /dev/null 2>&1   # Patroni REST API
            sudo ufw allow proto vrrp from "$peer_ip" > /dev/null 2>&1 || true           # VRRP protocol
        done
        log "HA ports opened (restricted to peers: ${HA_PEER_IPS[*]}): 5363/udp, 5354/tcp, 5432/tcp, 2379-2380/tcp (etcd), 8008/tcp (Patroni), VRRP"
    elif [[ "$HA_ENABLED" == "true" ]]; then
        log_warn "HA enabled but no peer IPs configured — skipping HA firewall rules"
    fi

    # Enable firewall (SSH already allowed, so this is safe)
    sudo ufw --force enable > /dev/null 2>&1
    log_success "Firewall configured (SSH, P2P, Stratum V1/V2, API, Dashboard$(if [[ "$HA_ENABLED" == "true" ]]; then echo ", HA Cluster"; fi) allowed)"

    # Configure DNS if requested
    if [[ "$CONFIGURE_DNS" == "true" ]] && [[ -n "$DNS_PRIMARY" ]]; then
        log "Configuring DNS servers..."

        # Check if systemd-resolved is in use
        if systemctl is-active --quiet systemd-resolved 2>/dev/null; then
            # Configure via systemd-resolved
            sudo mkdir -p /etc/systemd/resolved.conf.d
            if [[ -n "$DNS_SECONDARY" ]]; then
                sudo tee /etc/systemd/resolved.conf.d/spiralpool-dns.conf > /dev/null << EOF
[Resolve]
DNS=$DNS_PRIMARY $DNS_SECONDARY
FallbackDNS=1.1.1.1 8.8.8.8
EOF
            else
                sudo tee /etc/systemd/resolved.conf.d/spiralpool-dns.conf > /dev/null << EOF
[Resolve]
DNS=$DNS_PRIMARY
FallbackDNS=1.1.1.1 8.8.8.8
EOF
            fi
            sudo systemctl restart systemd-resolved || log_warn "Failed to restart systemd-resolved"
            log_success "DNS configured via systemd-resolved: $DNS_PRIMARY${DNS_SECONDARY:+, $DNS_SECONDARY}"
        else
            # Fall back to direct /etc/resolv.conf modification
            # Backup existing resolv.conf
            if [[ -f /etc/resolv.conf ]]; then
                sudo cp /etc/resolv.conf /etc/resolv.conf.backup.$(date +%Y%m%d%H%M%S)
            fi

            # Write new resolv.conf
            if [[ -n "$DNS_SECONDARY" ]]; then
                sudo tee /etc/resolv.conf > /dev/null << EOF
# Configured by Spiral Pool installer
nameserver $DNS_PRIMARY
nameserver $DNS_SECONDARY
EOF
            else
                sudo tee /etc/resolv.conf > /dev/null << EOF
# Configured by Spiral Pool installer
nameserver $DNS_PRIMARY
EOF
            fi
            log_success "DNS configured in /etc/resolv.conf: $DNS_PRIMARY${DNS_SECONDARY:+, $DNS_SECONDARY}"
        fi
    fi

    # Swap (nice-to-have, not critical — don't abort install if creation fails)
    if [[ ! -f /swapfile ]]; then
        if sudo fallocate -l 4G /swapfile 2>/dev/null; then
            sudo chmod 600 /swapfile
            sudo mkswap /swapfile > /dev/null
            sudo swapon /swapfile
            echo '/swapfile none swap sw 0 0' | sudo tee -a /etc/fstab > /dev/null
            log_success "4GB swap configured"
        else
            sudo rm -f /swapfile 2>/dev/null
            log_warn "Could not create swap (filesystem may not support fallocate) — continuing without swap"
        fi
    fi

    # Custom MOTD (Message of the Day)
    log "Configuring MOTD..."

    # Disable default MOTD components that add clutter
    sudo chmod -x /etc/update-motd.d/* 2>/dev/null || true

    # Create custom Spiral Pool MOTD
    sudo tee /etc/update-motd.d/00-spiralpool > /dev/null << 'MOTDEOF'
#!/bin/bash
# Spiral Pool MOTD

# Colors
CYAN='\033[0;36m'
MAGENTA='\033[0;35m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
RED='\033[0;31m'
WHITE='\033[1;37m'
DIM='\033[2m'
