}

# Detect system architecture once for all coin install functions
# dpkg returns "amd64" or "arm64"; fallback to amd64 if dpkg unavailable
SYSTEM_ARCH=$(dpkg --print-architecture 2>/dev/null || echo "amd64")

# ═══════════════════════════════════════════════════════════════════════════════
# DIGIBYTE NODE INSTALLATION
# ═══════════════════════════════════════════════════════════════════════════════

install_digibyte() {
    log_step "Installing DigiByte Core $DIGIBYTE_VERSION"

    # Set DigiByte port defaults if not already set
    RPC_PORT="${RPC_PORT:-14022}"
    ZMQ_PORT="${ZMQ_PORT:-28532}"

    # Use multi-disk storage path if configured, otherwise standard location
    local DGB_DIR
    DGB_DIR=$(get_blockchain_dir "dgb")

    if [[ -f "$DGB_DIR/bin/digibyted" ]]; then
        log "DigiByte already installed"
        return
    fi

    # Try copying binaries from source node (HA primary or user-specified) before downloading
    local dgb_download_needed=true
    if copy_binaries_from_primary "DigiByte Core" "$DGB_DIR/bin" "$DGB_DIR/bin"; then
        sudo mkdir -p "$DGB_DIR"
        sudo chown -R "$POOL_USER:$POOL_USER" "$DGB_DIR"
        if [[ -f "$DGB_DIR/bin/digibyted" ]]; then
            dgb_download_needed=false
            sudo ln -sf "$DGB_DIR/bin/digibyted" /usr/local/bin/digibyted
            sudo ln -sf "$DGB_DIR/bin/digibyte-cli" /usr/local/bin/digibyte-cli
        else
            log_warn "Replicated files missing expected daemon binary — falling back to download"
        fi
    fi

    if [[ "$dgb_download_needed" == "true" ]]; then

    cd /tmp

    # Determine architecture suffix for download
    local ARCH_SUFFIX="x86_64-linux-gnu"
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        ARCH_SUFFIX="aarch64-linux-gnu"
    fi

    # Multiple mirrors for DigiByte download - GitHub primary, fallback mirrors
    local DGB_MIRRORS=(
        "https://github.com/DigiByte-Core/digibyte/releases/download/v${DIGIBYTE_VERSION}/digibyte-${DIGIBYTE_VERSION}-${ARCH_SUFFIX}.tar.gz"
        "https://github.com/digibyte/digibyte/releases/download/v${DIGIBYTE_VERSION}/digibyte-${DIGIBYTE_VERSION}-${ARCH_SUFFIX}.tar.gz"
    )

    # Download with retry loop
    local download_success=false
    local max_attempts=3
    for ((attempt=1; attempt<=max_attempts; attempt++)); do
        log "Downloading DigiByte Core $DIGIBYTE_VERSION (attempt $attempt)..."
        if download_with_retry "digibyte.tar.gz" "${DGB_MIRRORS[@]}"; then
            # Verify archive integrity
            if gzip -t digibyte.tar.gz 2>/dev/null; then
                download_success=true
                break
            else
                log_warn "Downloaded archive is corrupted, retrying..."
                rm -f digibyte.tar.gz
            fi
        fi

        if [[ $attempt -lt $max_attempts ]]; then
            echo ""
            log_warn "Download failed. Manual download URL:"
            log_warn "  https://github.com/DigiByte-Core/digibyte/releases"
            echo ""
            echo -e "  ${WHITE}Options:${NC}"
            echo -e "    ${GREEN}r${NC} = Retry download"
            echo -e "    ${RED}a${NC} = Abort installation"
            echo ""
            prompt_input "Choice [r/a]: "; read choice
            if [[ "$choice" == "a" || "$choice" == "A" ]]; then
                log_error "Installation aborted by user"
                exit 1
            fi
        fi
    done

    if [[ "$download_success" != "true" ]]; then
        log_error "Failed to download DigiByte Core after $max_attempts attempts"
        log_error "Please download manually from: https://github.com/DigiByte-Core/digibyte/releases"
        log_error "Place digibyte-${DIGIBYTE_VERSION}-${ARCH_SUFFIX}.tar.gz in /tmp and re-run"
        exit 1
    fi

    log "Extracting DigiByte Core..."
    if ! tar -xzf digibyte.tar.gz; then
        log_error "Failed to extract DigiByte archive"
        rm -f digibyte.tar.gz
        log_error "Archive may be corrupted. Please re-download and try again."
        exit 1
    fi
    rm -f digibyte.tar.gz

    sudo mkdir -p "$DGB_DIR"
    sudo cp -r digibyte-${DIGIBYTE_VERSION}/* "$DGB_DIR/"
    sudo chown -R "$POOL_USER:$POOL_USER" "$DGB_DIR"

    sudo ln -sf "$DGB_DIR/bin/digibyted" /usr/local/bin/digibyted
    sudo ln -sf "$DGB_DIR/bin/digibyte-cli" /usr/local/bin/digibyte-cli

    rm -rf /tmp/digibyte*

    fi  # end dgb_download_needed

    # Configure DigiByte
    sudo mkdir -p "$DGB_DIR"

    # Generate network-specific configuration based on Tor setting
    if [[ "$TOR_ENABLED" == "true" ]]; then
        log "Configuring DigiByte for Tor network..."
        NETWORK_CONFIG="# === TOR NETWORK - PRIVACY MODE ===
# Route all connections through Tor for IP privacy
# Your real IP address is hidden from all peers
# Note: Sync will be MUCH slower but privacy is maximized
#
# IMPORTANT: This node is configured as a Tor CLIENT ONLY
# It does NOT run a Tor relay, exit node, or bridge
# No other users' traffic passes through this server

# Use Tor SOCKS5 proxy for all outbound connections
proxy=127.0.0.1:9050
# Route .onion peer connections through Tor
onion=127.0.0.1:9050
# Allow both onion and clearnet peers (via Tor proxy)
# This improves peer discovery while maintaining privacy
onlynet=ipv4
onlynet=onion
# Do NOT listen for incoming connections (hidden node)
listen=0
# Do NOT advertise any external IP
externalip=
# Enable DNS seeding through Tor for peer discovery
dnsseed=1
# Reduce connections for Tor (high latency network)
maxconnections=32
maxoutconnections=8
# Increase timeouts for Tor latency (milliseconds)
timeout=120000"
    else
        log "Configuring DigiByte for clearnet (fast sync)..."
        NETWORK_CONFIG="# === CLEARNET - FAST SYNC MODE ===
# Direct IPv4 connections for fastest possible sync

# Maximum peer connections for faster block propagation
maxconnections=256
# Prefer outbound connections for faster sync (more downloaders)
maxoutconnections=24
# Increase receive buffer (KB) for faster block download
maxreceivebuffer=25000
# Increase send buffer (KB)
maxsendbuffer=5000

# Force IPv4 clearnet connections only (IPv6 is not supported)
onlynet=ipv4
# Listen on clearnet
bind=0.0.0.0
listen=1
# DNS seeding enabled for fast peer discovery
dnsseed=1
forcednsseed=1

# === IBD (Initial Block Download) OPTIMIZATIONS ===
# Relay more headers at once (10000 vs default 2000) - faster sync
# Enable compact block relay for faster propagation
blocksonly=0
# Increase parallel block downloads
nblocks=64"
    fi

    sudo tee "$DGB_DIR/digibyte.conf" > /dev/null << EOF
# DigiByte Core Configuration
# Spiral Pool v3 - Solo Mining Pool
# Network Mode: $(if [[ "$TOR_ENABLED" == "true" ]]; then echo "TOR (Privacy)"; else echo "CLEARNET (Fast Sync)"; fi)

# === CORE SETTINGS ===
server=1
daemon=1
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "listen=1"; else echo "listen=0"; fi)
txindex=1
prune=0

# === RPC CONFIGURATION ===
rpcuser=$DGB_RPC_USER
rpcpassword=$DGB_RPC_PASSWORD
rpcport=$RPC_PORT
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcthreads=8
rpcworkqueue=64

# === MINING ===
algo=sha256d

# === ZMQ NOTIFICATIONS (for instant block detection) ===
zmqpubhashblock=tcp://127.0.0.1:$ZMQ_PORT
zmqpubrawtx=tcp://127.0.0.1:$ZMQ_PORT

# === PERFORMANCE OPTIMIZATION ===
# Database cache (8GB - optimized for faster sync)
dbcache=8192
# Memory pool limit
maxmempool=300
# Par = parallel script verification threads (4 cores for stability)
par=4
# Signature cache size for faster validation
maxsigcachesize=250

$NETWORK_CONFIG

# === LOGGING & CONSOLE ===
printtoconsole=0
logtimestamps=1
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "logips=1"; else echo "# logips disabled for privacy"; fi)
shrinkdebugfile=1
# Reduce debug log size during sync
debuglogfile=debug.log
maxdebugfilesize=50

# === WALLET ===
disablewallet=0
addresstype=legacy

# === SECURITY ===
# Disable deprecated RPC features
deprecatedrpc=

# === CHECKPOINTS & SIGNATURE VALIDATION ===
# Enable checkpoints for faster sync verification
checkpoints=1
# Skip script verification for blocks before this known-good block (block 21,700,000)
# This is the official defaultAssumeValid from DigiByte Core v8.22+ chainparams.cpp
# Dramatically speeds up initial sync by skipping expensive script validation
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "assumevalid=457f6864b52e5076a433afe3c28e3ae0bbeeaba9036a782ddb691242326fcb80"; fi)

# === BLOCK DOWNLOAD OPTIMIZATION ===
# Increase block download window
maxblocksinprogress=$(if [[ "$TOR_ENABLED" == "true" ]]; then echo "8"; else echo "32"; fi)
# Increase orphan transaction pool
maxorphantx=100
# Minimize block reconstruction overhead
blockreconstructionextratxn=100

# === SYNC OPTIMIZATION ===
# $(if [[ "$TOR_ENABLED" == "true" ]]; then echo "Longer timeouts for Tor latency"; else echo "Reasonable timeouts for clearnet"; fi)
peertimeout=$(if [[ "$TOR_ENABLED" == "true" ]]; then echo "120"; else echo "60"; fi)
blockstallingtimeout=$(if [[ "$TOR_ENABLED" == "true" ]]; then echo "30"; else echo "10"; fi)
# Skip transaction relay during initial block download (faster sync)
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "# blocksonly=1 during IBD speeds sync but disabled for full node operation"; fi)

# === SEED NODES (verified working - Jan 2026) ===
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "# DigiByte DNS seeds (6 verified working via dig)
seednode=seed.digibyte.io
seednode=seed.digibyte.help
seednode=seed.diginode.tools
seednode=seed.digibyte.link
seednode=seed.quakeguy.com
seednode=seed.aroundtheblock.app

# DNS seeds for peer discovery
dnsseed=seed.digibyte.io
dnsseed=seed.digibyte.help
dnsseed=seed.diginode.tools
dnsseed=seed.digibyte.link
dnsseed=seed.quakeguy.com
dnsseed=seed.aroundtheblock.app"; fi)
EOF
    sudo chmod 640 "$DGB_DIR/digibyte.conf"  # 640 allows group read for CLI tools
    sudo chown -R "$POOL_USER:$POOL_USER" "$DGB_DIR"

    # Create service with memory and resource optimizations
    sudo tee /etc/systemd/system/digibyted.service > /dev/null << EOF
[Unit]
Description=DigiByte Core Node
After=network-online.target
Wants=network-online.target
Documentation=https://github.com/DigiByte-Core/digibyte
# Prevent restart loops: max 5 restarts in 10 minutes
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
ExecStart=$DGB_DIR/bin/digibyted -daemon -conf=$(get_blockchain_dir dgb)/digibyte.conf -datadir=$(get_blockchain_dir dgb)
ExecStop=$DGB_DIR/bin/digibyte-cli -conf=$(get_blockchain_dir dgb)/digibyte.conf -datadir=$(get_blockchain_dir dgb) stop

# === SELF-HEALING / AUTO-RESTART ===
# Restart=always ensures service restarts on any exit (crash, kill, clean exit)
Restart=always
RestartSec=30
# Note: WatchdogSec removed - blockchain daemons don't support sd_notify
# and will be killed during initial sync when unresponsive processing blocks

TimeoutStartSec=infinity
TimeoutStopSec=600

# === RESOURCE LIMITS FOR FAST SYNC ===
# Allow up to 12GB memory (dbcache + UTXO set + mempool overhead)
MemoryMax=12G
MemoryHigh=11G
# Increase open file limits for many peer connections
LimitNOFILE=65536
LimitNPROC=65536
# Nice priority - slightly higher than default for faster sync
Nice=-5
# I/O priority - best effort, higher priority
IOSchedulingClass=best-effort
IOSchedulingPriority=2

# NOTE: Systemd security hardening intentionally omitted.
# Some blockchain daemons crash with SIGABRT under modern systemd
# hardening options (PrivateTmp, ProtectSystem, etc.)

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable digibyted || true

    log_success "DigiByte Core installed"
    mark_progress "digibyte"
}

# ═══════════════════════════════════════════════════════════════════════════════
# BITCOIN KNOTS INSTALLATION (Multi-Coin Mode)
# ═══════════════════════════════════════════════════════════════════════════════
# NOTE: We use Bitcoin Knots instead of Bitcoin Core for consistency with Docker
# mode and for its additional features (enhanced RPC, better policy options).
# Bitcoin Knots is a derivative of Core maintained by Luke Dashjr.

# Fallback version if auto-detection fails
BITCOIN_KNOTS_FALLBACK_VERSION="29.3.knots20260210"

# Auto-detect the latest Bitcoin Knots version from bitcoinknots.org
detect_latest_knots_version() {
    # NOTE: This function returns the version via stdout (echo).
    # All log/log_success/log_warn calls MUST redirect to stderr (>&2)
    # to avoid contaminating the captured return value.
    log "Detecting latest Bitcoin Knots version..." >&2

    # Fetch the directory listing from bitcoinknots.org
    local knots_page
    knots_page=$(curl -sL --connect-timeout 10 --max-time 30 "https://bitcoinknots.org/files/" 2>/dev/null)

    if [[ -z "$knots_page" ]]; then
        log_warn "Could not fetch bitcoinknots.org, using fallback version" >&2
        echo "$BITCOIN_KNOTS_FALLBACK_VERSION"
        return
    fi

    # Find all version directories (e.g., 27.x, 28.x, 29.x) and get the highest
    local latest_major
    latest_major=$(echo "$knots_page" | grep -oP 'href="\K[0-9]+\.x(?=/")' | sort -t. -k1 -n | tail -1)

    if [[ -z "$latest_major" ]]; then
        log_warn "Could not parse major version, using fallback" >&2
        echo "$BITCOIN_KNOTS_FALLBACK_VERSION"
        return
    fi

    # Fetch the specific version directory
    local version_page
    version_page=$(curl -sL --connect-timeout 10 --max-time 30 "https://bitcoinknots.org/files/${latest_major}/" 2>/dev/null)

    if [[ -z "$version_page" ]]; then
        log_warn "Could not fetch version directory, using fallback" >&2
        echo "$BITCOIN_KNOTS_FALLBACK_VERSION"
        return
    fi

    # Find the latest version directory (e.g., 29.3.knots20260210)
    local latest_version
    latest_version=$(echo "$version_page" | grep -oP 'href="\K[0-9]+\.[0-9]+\.knots[0-9]+(?=/")' | sort -V | tail -1)

    if [[ -z "$latest_version" ]]; then
        log_warn "Could not parse version, using fallback" >&2
        echo "$BITCOIN_KNOTS_FALLBACK_VERSION"
        return
    fi

    log_success "Detected latest Bitcoin Knots: $latest_version" >&2
    echo "$latest_version"
}

# Get the major version directory (e.g., "29.x" from "29.3.knots20260210")
get_knots_major_version() {
    local version="$1"
    echo "${version%%.*}.x"
}

install_bitcoin() {
    if [[ "$ENABLE_BTC" != "true" ]]; then
        return 0
    fi

    # Auto-detect the latest Bitcoin Knots version
    local BITCOIN_KNOTS_VERSION
    BITCOIN_KNOTS_VERSION=$(detect_latest_knots_version)
    local KNOTS_MAJOR_VERSION
    KNOTS_MAJOR_VERSION=$(get_knots_major_version "$BITCOIN_KNOTS_VERSION")

    log_step "Installing Bitcoin Knots $BITCOIN_KNOTS_VERSION"

    # Use multi-disk storage path if configured, otherwise standard location
    local BTC_DIR
    BTC_DIR=$(get_blockchain_dir "btc")
    local BTC_DATA="$BTC_DIR"

    if [[ -f "$BTC_DIR/bin/bitcoind" ]]; then
        log "Bitcoin Knots already installed"
        return
    fi

    # Try copying binaries from source node (HA primary or user-specified) before downloading
    local btc_download_needed=true
    if copy_binaries_from_primary "Bitcoin Knots" "$BTC_DIR/bin" "$BTC_DIR/bin"; then
        sudo mkdir -p "$BTC_DATA"
        sudo chown -R "$POOL_USER:$POOL_USER" "$BTC_DIR"
        if [[ -f "$BTC_DIR/bin/bitcoind" ]]; then
            btc_download_needed=false
            sudo ln -sf "$BTC_DIR/bin/bitcoind" /usr/local/bin/bitcoind
            sudo ln -sf "$BTC_DIR/bin/bitcoin-cli" /usr/local/bin/bitcoin-cli
        else
            log_warn "Replicated files missing expected daemon binary — falling back to download"
        fi
    fi

    if [[ "$btc_download_needed" == "true" ]]; then

    cd /tmp

    # Determine architecture suffix for download
    local ARCH_SUFFIX="x86_64-linux-gnu"
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        ARCH_SUFFIX="aarch64-linux-gnu"
    fi

    # Bitcoin Knots download (official release)
    # Format: bitcoin-29.3.knots20260210-x86_64-linux-gnu.tar.gz
    local KNOTS_FILENAME="bitcoin-${BITCOIN_KNOTS_VERSION}-${ARCH_SUFFIX}.tar.gz"
    local BTC_MIRRORS=(
        "https://bitcoinknots.org/files/${KNOTS_MAJOR_VERSION}/${BITCOIN_KNOTS_VERSION}/${KNOTS_FILENAME}"
        "https://github.com/bitcoinknots/bitcoin/releases/download/v${BITCOIN_KNOTS_VERSION}/${KNOTS_FILENAME}"
    )

    # Download SHA256SUMS file for verification (auto-detect hash)
    # NOTE: This fetch is optional — if it fails, download proceeds without verification.
    # The 'local' keyword masks curl's exit code so set -e doesn't kill the script.
    log "Fetching SHA256 checksum from bitcoinknots.org..."
    local BTC_SHA256=""
    local sha256sums=$(curl -sL --connect-timeout 10 --max-time 30 \
        "https://bitcoinknots.org/files/${KNOTS_MAJOR_VERSION}/${BITCOIN_KNOTS_VERSION}/SHA256SUMS" 2>/dev/null || true)

    if [[ -n "$sha256sums" ]]; then
        BTC_SHA256=$(echo "$sha256sums" | grep "$KNOTS_FILENAME" | awk '{print $1}')
        if [[ -n "$BTC_SHA256" ]]; then
            log_success "Found SHA256: ${BTC_SHA256:0:16}..."
        fi
    fi

    # Download with retry
    local download_success=false
    local max_attempts=3
    for ((attempt=1; attempt<=max_attempts; attempt++)); do
        log "Downloading Bitcoin Knots $BITCOIN_KNOTS_VERSION (attempt $attempt)..."
        if download_with_retry "bitcoin.tar.gz" "${BTC_MIRRORS[@]}"; then
            # Verify SHA256 checksum if available
            if [[ -n "$BTC_SHA256" ]]; then
                local actual_sha256=$(sha256sum bitcoin.tar.gz | awk '{print $1}')
                if [[ "$actual_sha256" == "$BTC_SHA256" ]]; then
                    download_success=true
                    log_success "SHA256 checksum verified"
                    break
                else
                    log_warn "SHA256 mismatch! Expected: $BTC_SHA256"
                    log_warn "                     Got: $actual_sha256"
                    log_warn "Verify manually at:"
                    log_warn "  https://bitcoinknots.org/files/${KNOTS_MAJOR_VERSION}/${BITCOIN_KNOTS_VERSION}/"
                    rm -f bitcoin.tar.gz
                fi
            else
                log_warn "No SHA256 checksum available - proceeding without verification"
                download_success=true
                break
            fi
        fi

        if [[ $attempt -lt $max_attempts ]]; then
            echo ""
            log_warn "Download failed. Manual download URL:"
            log_warn "  https://bitcoinknots.org/files/${KNOTS_MAJOR_VERSION}/${BITCOIN_KNOTS_VERSION}/"
            echo ""
            prompt_input "Retry? [Y/n]: "; read retry_choice
            if [[ "$retry_choice" == "n" || "$retry_choice" == "N" ]]; then
                log_error "Bitcoin Knots installation aborted"
                return 1
            fi
        fi
    done

    if [[ "$download_success" != "true" ]]; then
        log_error "Failed to download Bitcoin Knots after $max_attempts attempts"
        return 1
    fi

    log "Extracting Bitcoin Knots..."
    tar -xzf bitcoin.tar.gz || { log_error "Failed to extract Bitcoin Knots archive"; return 1; }
    rm -f bitcoin.tar.gz

    # Install Bitcoin Knots (find the extracted directory dynamically)
    local extracted_dir
    extracted_dir=$(ls -d bitcoin-*/ 2>/dev/null | head -1 | tr -d '/')

    if [[ -z "$extracted_dir" ]]; then
        log_error "Could not find extracted Bitcoin Knots directory"
        return 1
    fi

    sudo mkdir -p "$BTC_DIR/bin"
    sudo mkdir -p "$BTC_DATA"
    sudo cp ${extracted_dir}/bin/* "$BTC_DIR/bin/"
    sudo chown -R "$POOL_USER:$POOL_USER" "$BTC_DIR"
    rm -rf /tmp/bitcoin-*

    sudo ln -sf "$BTC_DIR/bin/bitcoind" /usr/local/bin/bitcoind
    sudo ln -sf "$BTC_DIR/bin/bitcoin-cli" /usr/local/bin/bitcoin-cli

    fi  # end btc_download_needed

    # Generate Bitcoin configuration based on Tor/clearnet setting
    if [[ "$BTC_TOR_ENABLED" == "true" ]]; then
        log "Configuring Bitcoin Knots for Tor network..."
        BTC_NETWORK_CONFIG="# === TOR NETWORK - PRIVACY MODE ===
# Route all connections through Tor for IP privacy
# Note: Initial sync will be SLOW (1-2 weeks) but privacy is maximized
# This node is a Tor CLIENT ONLY - no relay/exit traffic

# Use Tor SOCKS5 proxy for all outbound connections
proxy=127.0.0.1:9050
# Route .onion peer connections through Tor
onion=127.0.0.1:9050
# Allow both onion and clearnet peers (via Tor proxy)
onlynet=onion
onlynet=ipv4
# Do NOT listen for incoming connections (hidden node)
listen=0
# Do NOT advertise any external IP
externalip=
# Reduce connections for Tor (high latency network)
maxconnections=40
maxuploadtarget=5000
# Increase timeouts for Tor latency
peertimeout=120"
    else
        log "Configuring Bitcoin Knots for clearnet (fastest sync)..."
        BTC_NETWORK_CONFIG="# === CLEARNET - FAST SYNC MODE ===
# Direct IPv4 connections for fastest possible sync
# Optimized for initial block download (IBD)

# Maximum peer connections for faster sync
maxconnections=256
# Prefer outbound connections for faster sync (more downloaders)
maxoutconnections=24
# Increase receive buffer (KB) for faster block download
maxreceivebuffer=25000
# Increase send buffer (KB)
maxsendbuffer=5000
# Listen on clearnet
listen=1
bind=0.0.0.0
# Force IPv4 clearnet connections only (IPv6 is not supported)
onlynet=ipv4
# DNS seeding enabled for fast peer discovery
dnsseed=1
forcednsseed=1
# Standard timeouts
peertimeout=60
blockstallingtimeout=10

# === IBD (Initial Block Download) OPTIMIZATIONS ===
# Increase parallel block downloads
nblocks=64"
    fi

    sudo tee "$BTC_DATA/bitcoin.conf" > /dev/null << EOF
# Bitcoin Knots Configuration
# Spiral Pool v3 - Multi-Coin Solo Mining
# Network Mode: $(if [[ "$BTC_TOR_ENABLED" == "true" ]]; then echo "TOR (Privacy)"; else echo "CLEARNET (Fast Sync)"; fi)
# Generated: $(date -u +"%Y-%m-%d %H:%M:%S UTC")

# === CORE SETTINGS ===
server=1
daemon=1
txindex=1
# Full node - no pruning
prune=0
# Mainnet
chain=main

# === RPC CONFIGURATION ===
rpcuser=$BTC_RPC_USER
rpcpassword=$BTC_RPC_PASSWORD
rpcport=8332
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcthreads=8
rpcworkqueue=64

# === ZMQ NOTIFICATIONS (for instant block detection) ===
zmqpubhashblock=tcp://127.0.0.1:28332
zmqpubrawtx=tcp://127.0.0.1:28332

# === PERFORMANCE OPTIMIZATION ===
# Database cache (8GB - optimized for faster sync)
dbcache=8192
# Memory pool limit
maxmempool=300
# Par = parallel script verification threads (4 cores for stability)
par=4

$BTC_NETWORK_CONFIG

# === WALLET ===
disablewallet=0
addresstype=bech32
changetype=bech32

# === LOGGING ===
printtoconsole=0
logtimestamps=1
$(if [[ "$BTC_TOR_ENABLED" != "true" ]]; then echo "logips=1"; else echo "# logips disabled for privacy"; fi)
shrinkdebugfile=1
# Reduce debug log size during sync
debuglogfile=debug.log

# === ASSUME VALID (skip signature verification for known good blocks) ===
# This dramatically speeds up initial sync
# Block height 912683 (Bitcoin Core v28+)
$(if [[ "$BTC_TOR_ENABLED" != "true" ]]; then echo "assumevalid=00000000000000000000611fd22f2df7c8fbd0688745c3a6c3bb5109cc2a12cb"; fi)

# === CHECKPOINTS ===
checkpoints=1

# === SEED NODES (official Bitcoin Core DNS seeds) ===
$(if [[ "$BTC_TOR_ENABLED" != "true" ]]; then echo "# Primary official seeds (Bitcoin Core)
seednode=seed.bitcoin.sipa.be
seednode=dnsseed.bluematt.me
seednode=seed.bitcoin.jonasschnelli.ch
seednode=seed.btc.petertodd.net
seednode=seed.bitcoin.sprovoost.nl
seednode=dnsseed.emzy.de
seednode=seed.bitcoin.wiz.biz
seednode=seed.mainnet.achownodes.xyz

# Additional DNS seeds for redundancy
dnsseed=seed.bitcoin.sipa.be
dnsseed=dnsseed.bluematt.me
dnsseed=seed.btc.petertodd.net"; fi)
EOF

    sudo chmod 640 "$BTC_DATA/bitcoin.conf"  # 640 allows group read for CLI tools
    sudo chown -R "$POOL_USER:$POOL_USER" "$BTC_DIR"

    # Create systemd service
    sudo tee /etc/systemd/system/bitcoind.service > /dev/null << EOF
[Unit]
Description=Bitcoin Knots Node
After=network-online.target
Wants=network-online.target
Documentation=https://bitcoin.org/en/full-node
# Prevent restart loops: max 5 restarts in 10 minutes
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
ExecStart=$BTC_DIR/bin/bitcoind -daemon -conf=$BTC_DATA/bitcoin.conf -datadir=$BTC_DATA
ExecStop=$BTC_DIR/bin/bitcoin-cli -conf=$BTC_DATA/bitcoin.conf -datadir=$BTC_DATA stop

# === SELF-HEALING / AUTO-RESTART ===
# Restart=always ensures service restarts on any exit (crash, kill, clean exit)
Restart=always
RestartSec=30
# Note: WatchdogSec removed - blockchain daemons don't support sd_notify
# and will be killed during initial sync when unresponsive processing blocks

TimeoutStartSec=infinity
TimeoutStopSec=600

# === RESOURCE LIMITS ===
MemoryMax=12G
MemoryHigh=10G
LimitNOFILE=65536
LimitNPROC=65536
Nice=-5
IOSchedulingClass=best-effort
IOSchedulingPriority=2

# NOTE: Systemd security hardening intentionally omitted.
# Some blockchain daemons crash with SIGABRT under modern systemd
# hardening options (PrivateTmp, ProtectSystem, etc.)

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable bitcoind || true

    log_success "Bitcoin Knots $BITCOIN_KNOTS_VERSION installed"
    log "Data directory: $BTC_DATA"
    log "RPC Port: 8332, ZMQ Port: 28332"
    mark_progress "bitcoin"
}

# ═══════════════════════════════════════════════════════════════════════════════
# BITCOIN CASH NODE INSTALLATION (Multi-Coin Mode)
# ═══════════════════════════════════════════════════════════════════════════════

BCHN_VERSION="29.0.0"

install_bitcoincash() {
    if [[ "$ENABLE_BCH" != "true" ]]; then
        return 0
    fi

    log_step "Installing Bitcoin Cash Node (BCHN) $BCHN_VERSION"

    # Use multi-disk storage path if configured, otherwise standard location
    local BCH_DIR
    BCH_DIR=$(get_blockchain_dir "bch")
    local BCH_DATA="$BCH_DIR"

    if [[ -f "$BCH_DIR/bin/bitcoind" ]]; then
        log "Bitcoin Cash Node already installed"
        return
    fi

    # Try copying binaries from source node (HA primary or user-specified) before downloading
    local bch_download_needed=true
    if copy_binaries_from_primary "Bitcoin Cash Node" "$BCH_DIR/bin" "$BCH_DIR/bin"; then
        sudo mkdir -p "$BCH_DATA"
        sudo chown -R "$POOL_USER:$POOL_USER" "$BCH_DIR"
        if [[ -f "$BCH_DIR/bin/bitcoind" ]]; then
            bch_download_needed=false
            sudo ln -sf "$BCH_DIR/bin/bitcoind" /usr/local/bin/bitcoind-bch
            sudo ln -sf "$BCH_DIR/bin/bitcoin-cli" /usr/local/bin/bitcoin-cli-bch
        else
            log_warn "Replicated files missing expected daemon binary — falling back to download"
        fi
    fi

    if [[ "$bch_download_needed" == "true" ]]; then

    cd /tmp

    # Determine architecture suffix for download
    local ARCH_SUFFIX="x86_64-linux-gnu"
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        ARCH_SUFFIX="aarch64-linux-gnu"
    fi

    # BCHN download mirror (official releases)
    local BCH_MIRRORS=(
        "https://github.com/bitcoin-cash-node/bitcoin-cash-node/releases/download/v${BCHN_VERSION}/bitcoin-cash-node-${BCHN_VERSION}-${ARCH_SUFFIX}.tar.gz"
    )

    # Download with retry
    local download_success=false
    local max_attempts=3
    for ((attempt=1; attempt<=max_attempts; attempt++)); do
        log "Downloading Bitcoin Cash Node $BCHN_VERSION (attempt $attempt)..."
        if download_with_retry "bchn.tar.gz" "${BCH_MIRRORS[@]}"; then
            # Verify archive integrity
            if gzip -t bchn.tar.gz 2>/dev/null; then
                download_success=true
                break
            else
                log_warn "Downloaded archive is corrupted, retrying..."
                rm -f bchn.tar.gz
            fi
        fi

        if [[ $attempt -lt $max_attempts ]]; then
            echo ""
            log_warn "Download failed. Manual download URL:"
            log_warn "  https://github.com/bitcoin-cash-node/bitcoin-cash-node/releases"
            echo ""
            prompt_input "Retry? [Y/n]: "; read retry_choice
            if [[ "$retry_choice" == "n" || "$retry_choice" == "N" ]]; then
                log_error "Bitcoin Cash Node installation aborted"
                return 1
            fi
        fi
    done

    if [[ "$download_success" != "true" ]]; then
        log_error "Failed to download Bitcoin Cash Node after $max_attempts attempts"
        return 1
    fi

    log "Extracting Bitcoin Cash Node..."
    tar -xzf bchn.tar.gz || { log_error "Failed to extract Bitcoin Cash Node archive"; return 1; }
    rm -f bchn.tar.gz

    # Install BCHN
    sudo mkdir -p "$BCH_DIR/bin"
    sudo mkdir -p "$BCH_DATA"
    sudo cp bitcoin-cash-node-${BCHN_VERSION}/bin/* "$BCH_DIR/bin/"
    sudo chown -R "$POOL_USER:$POOL_USER" "$BCH_DIR"
    rm -rf /tmp/bitcoin-cash-node-*

    # Use different names to avoid conflict with Bitcoin Knots
    sudo ln -sf "$BCH_DIR/bin/bitcoind" /usr/local/bin/bitcoind-bch
    sudo ln -sf "$BCH_DIR/bin/bitcoin-cli" /usr/local/bin/bitcoin-cli-bch

    fi  # end bch_download_needed

    # Generate BCH configuration based on Tor/clearnet setting
    # NOTE: BCH uses unique ports to avoid conflict with BTC
    # RPC: 8432 (not 8332), P2P: 8433 (not 8333), ZMQ: 28432
    if [[ "$BCH_TOR_ENABLED" == "true" ]]; then
        log "Configuring Bitcoin Cash for Tor network..."
        BCH_NETWORK_CONFIG="# === TOR NETWORK - PRIVACY MODE ===
# Route all connections through Tor for IP privacy
# Note: Initial sync will be slower but privacy is maximized

# Use Tor SOCKS5 proxy for all outbound connections
proxy=127.0.0.1:9050
# Route .onion peer connections through Tor
onion=127.0.0.1:9050
# Allow both onion and clearnet peers (via Tor proxy)
onlynet=onion
onlynet=ipv4
# Do NOT listen for incoming connections (hidden node)
listen=0
# Reduce connections for Tor
maxconnections=40"
    else
        log "Configuring Bitcoin Cash for clearnet (fastest sync)..."
        BCH_NETWORK_CONFIG="# === CLEARNET - FAST SYNC MODE ===
# Direct IPv4 connections for fastest possible sync

# Maximum peer connections for faster sync
maxconnections=256
# Increase receive buffer (KB) for faster block download
maxreceivebuffer=25000
# Increase send buffer (KB)
maxsendbuffer=5000
# Listen on clearnet (unique BCH port 8433)
listen=1
bind=0.0.0.0:8433
port=8433
# Force IPv4 clearnet connections only (IPv6 is not supported)
onlynet=ipv4
# DNS seeding enabled
dnsseed=1"
    fi

    sudo tee "$BCH_DATA/bitcoin.conf" > /dev/null << EOF
# Bitcoin Cash Node (BCHN) Configuration
# Spiral Pool v3 - Multi-Coin Solo Mining
# Network Mode: $(if [[ "$BCH_TOR_ENABLED" == "true" ]]; then echo "TOR (Privacy)"; else echo "CLEARNET (Fast Sync)"; fi)
# Generated: $(date -u +"%Y-%m-%d %H:%M:%S UTC")
#
# IMPORTANT: Uses unique ports to avoid conflict with Bitcoin Knots
# RPC: 8432 (not 8332), P2P: 8433 (not 8333), ZMQ: 28432

# === CORE SETTINGS ===
server=1
daemon=1
txindex=1
# Full node - no pruning
prune=0

# === RPC CONFIGURATION (unique port 8432) ===
rpcuser=$BCH_RPC_USER
rpcpassword=$BCH_RPC_PASSWORD
rpcport=8432
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcthreads=8

# === ZMQ NOTIFICATIONS (unique port 28432) ===
zmqpubhashblock=tcp://127.0.0.1:28432
zmqpubrawtx=tcp://127.0.0.1:28432

# === PERFORMANCE OPTIMIZATION ===
# Database cache (2GB - BCH has smaller chain)
dbcache=2048
# Memory pool limit
maxmempool=300
# Par = parallel script verification threads (4 cores for stability)
par=4

$BCH_NETWORK_CONFIG

# === WALLET ===
disablewallet=0

# === LOGGING ===
printtoconsole=0
logtimestamps=1
$(if [[ "$BCH_TOR_ENABLED" != "true" ]]; then echo "logips=1"; else echo "# logips disabled for privacy"; fi)
shrinkdebugfile=1

# === BCH-SPECIFIC SETTINGS ===
# Enable 32MB blocks (BCH protocol)
excessiveblocksize=32000000

# === ASSUME VALID (skip signature verification for known good blocks) ===
# This dramatically speeds up initial sync (BCHN latest)
$(if [[ "$BCH_TOR_ENABLED" != "true" ]]; then echo "assumevalid=000000000000000000982e811b14b1fe425553fc1b437a34caddea0d70ec6508"; fi)

# === SEED NODES (official Bitcoin Cash Node DNS seeds) ===
$(if [[ "$BCH_TOR_ENABLED" != "true" ]]; then echo "# Primary official seeds (BCHN)
seednode=seed.flowee.cash
seednode=seed-bch.bitcoinforks.org
seednode=btccash-seeder.bitcoinunlimited.info
seednode=seed.bchd.cash
seednode=seed.bch.loping.net
seednode=dnsseed.electroncash.de
seednode=bchseed.c3-soft.com
seednode=bch.bitjson.com"; fi)
EOF

    sudo chmod 640 "$BCH_DATA/bitcoin.conf"  # 640 allows group read for CLI tools
    sudo chown -R "$POOL_USER:$POOL_USER" "$BCH_DIR"

    # Create systemd service (unique name to avoid conflict)
    sudo tee /etc/systemd/system/bitcoind-bch.service > /dev/null << EOF
[Unit]
Description=Bitcoin Cash Node (BCHN)
After=network-online.target
Wants=network-online.target
Documentation=https://bitcoincashnode.org/
# Prevent restart loops: max 5 restarts in 10 minutes
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
ExecStart=$BCH_DIR/bin/bitcoind -daemon -conf=$BCH_DATA/bitcoin.conf -datadir=$BCH_DATA
ExecStop=$BCH_DIR/bin/bitcoin-cli -conf=$BCH_DATA/bitcoin.conf -datadir=$BCH_DATA stop

# === SELF-HEALING / AUTO-RESTART ===
# Restart=always ensures service restarts on any exit (crash, kill, clean exit)
Restart=always
RestartSec=30
# Note: WatchdogSec removed - blockchain daemons don't support sd_notify
# and will be killed during initial sync when unresponsive processing blocks

TimeoutStartSec=infinity
TimeoutStopSec=600

# === RESOURCE LIMITS ===
MemoryMax=10G
MemoryHigh=8G
LimitNOFILE=65536
LimitNPROC=65536
Nice=-5
IOSchedulingClass=best-effort
IOSchedulingPriority=2

# NOTE: Systemd security hardening intentionally omitted.
# Some blockchain daemons crash with SIGABRT under modern systemd
# hardening options (PrivateTmp, ProtectSystem, etc.)

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable bitcoind-bch || true

    log_success "Bitcoin Cash Node $BCHN_VERSION installed"
    log "Data directory: $BCH_DATA"
    log "RPC Port: 8432, P2P Port: 8433, ZMQ Port: 28432"
    mark_progress "bitcoincash"
}

# ═══════════════════════════════════════════════════════════════════════════════
# BITCOIN II (BC2) NODE INSTALLATION (Multi-Coin Mode)
# ═══════════════════════════════════════════════════════════════════════════════
# NOTE: Bitcoin II is a "nearly 1:1 re-launch of Bitcoin" with a new genesis block.
# CRITICAL: BC2 uses IDENTICAL address formats to Bitcoin (same P2PKH, P2SH, Bech32).
# Users must ensure they configure the correct address for the correct chain.

install_bitcoinii() {
    if [[ "$ENABLE_BC2" != "true" ]]; then
        return 0
    fi

    log_step "Installing Bitcoin II Core $BITCOINII_VERSION"

    # Use multi-disk storage path if configured, otherwise standard location
    local BC2_DIR
    BC2_DIR=$(get_blockchain_dir "bc2")
    local BC2_DATA="$BC2_DIR"

    # Check if already installed (Bitcoin II uses capital "II": bitcoinIId)
    if [[ -f "$BC2_DIR/bin/bitcoinIId" ]]; then
        log "Bitcoin II Core already installed"
        return
    fi

    # Try copying binaries from source node (HA primary or user-specified) before downloading
    local bc2_download_needed=true
    if copy_binaries_from_primary "Bitcoin II Core" "$BC2_DIR/bin" "$BC2_DIR/bin"; then
        sudo mkdir -p "$BC2_DATA"
        sudo chown -R "$POOL_USER:$POOL_USER" "$BC2_DIR"
        if [[ -f "$BC2_DIR/bin/bitcoinIId" ]]; then
            bc2_download_needed=false
            sudo ln -sf "$BC2_DIR/bin/bitcoinIId" /usr/local/bin/bitcoiniid
            sudo ln -sf "$BC2_DIR/bin/bitcoinII-cli" /usr/local/bin/bitcoinii-cli
        else
            log_warn "Replicated files missing expected daemon binary — falling back to download"
        fi
    fi

    if [[ "$bc2_download_needed" == "true" ]]; then

    cd /tmp

    # Determine architecture suffix for download (BC2 uses -CLI suffix, not -gnu)
    local BC2_ARCH_SUFFIX="x86_64-linux-CLI"
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        BC2_ARCH_SUFFIX="aarch64-linux-CLI"
    fi

    # Bitcoin II download mirrors (official GitHub releases)
    local BC2_MIRRORS=(
        "https://github.com/Bitcoin-II/BitcoinII-Core/releases/download/v${BITCOINII_VERSION}/BitcoinII-${BITCOINII_VERSION}-${BC2_ARCH_SUFFIX}.tar.gz"
    )

    # Download with retry
    local download_success=false
    local max_attempts=3
    for ((attempt=1; attempt<=max_attempts; attempt++)); do
        log "Downloading Bitcoin II Core $BITCOINII_VERSION (attempt $attempt)..."
        if download_with_retry "bitcoinii.tar.gz" "${BC2_MIRRORS[@]}"; then
            # Verify archive integrity
            if gzip -t bitcoinii.tar.gz 2>/dev/null; then
                download_success=true
                break
            else
                log_warn "Downloaded archive is corrupted, retrying..."
                rm -f bitcoinii.tar.gz
            fi
        fi

        if [[ $attempt -lt $max_attempts ]]; then
            echo ""
            log_warn "Download failed. Manual download URL:"
            log_warn "  https://github.com/Bitcoin-II/BitcoinII-Core/releases"
            echo ""
            prompt_input "Retry? [Y/n]: "; read retry_choice
            if [[ "$retry_choice" == "n" || "$retry_choice" == "N" ]]; then
                log_error "Bitcoin II Core installation aborted"
                return 1
            fi
        fi
    done

    if [[ "$download_success" != "true" ]]; then
        log_error "Failed to download Bitcoin II Core after $max_attempts attempts"
        return 1
    fi

    log "Extracting Bitcoin II Core..."
    tar -xzf bitcoinii.tar.gz || { log_error "Failed to extract Bitcoin II Core archive"; return 1; }
    rm -f bitcoinii.tar.gz

    # Install Bitcoin II (find the extracted directory dynamically)
    # Handle both naming conventions: BitcoinII-* and bitcoinII-*
    local extracted_dir
    extracted_dir=$(ls -d BitcoinII-*/ bitcoinII-*/ 2>/dev/null | head -1 | tr -d '/')

    if [[ -z "$extracted_dir" ]]; then
        log_error "Could not find extracted Bitcoin II directory"
        return 1
    fi

    sudo mkdir -p "$BC2_DIR/bin"
    sudo mkdir -p "$BC2_DATA"

    # Bitcoin II v29.1.0 has binaries in root directory, not bin/ subdirectory
    # IMPORTANT: Bitcoin II binaries use capital "II": bitcoinIId, bitcoinII-cli
    # Check both locations for compatibility with future versions
    if [[ -d "${extracted_dir}/bin" ]]; then
        sudo cp ${extracted_dir}/bin/* "$BC2_DIR/bin/"
    else
        # v29.1.0 structure: binaries are in root of extracted directory
        # Bitcoin II uses capital "II" in binary names: bitcoinIId, bitcoinII-cli
        sudo cp ${extracted_dir}/bitcoinIId "$BC2_DIR/bin/" 2>/dev/null || true
        sudo cp ${extracted_dir}/bitcoinII-cli "$BC2_DIR/bin/" 2>/dev/null || true
        sudo cp ${extracted_dir}/bitcoinII-qt "$BC2_DIR/bin/" 2>/dev/null || true
        sudo cp ${extracted_dir}/bitcoinII-tx "$BC2_DIR/bin/" 2>/dev/null || true
        sudo cp ${extracted_dir}/bitcoinII-wallet "$BC2_DIR/bin/" 2>/dev/null || true
    fi

    # Ensure binaries are executable
    sudo chmod +x "$BC2_DIR/bin/"* 2>/dev/null || true
    sudo chown -R "$POOL_USER:$POOL_USER" "$BC2_DIR"
    rm -rf /tmp/BitcoinII-* /tmp/bitcoinII-*

    # Verify binaries exist (Bitcoin II uses capital "II": bitcoinIId)
    if [[ ! -f "$BC2_DIR/bin/bitcoinIId" ]]; then
        log_error "Bitcoin II daemon binary not found after extraction"
        log "Expected: $BC2_DIR/bin/bitcoinIId"
        log "Directory contents: $(ls -la "$BC2_DIR/bin/" 2>/dev/null || echo 'empty')"
        return 1
    fi

    # Create lowercase symlinks in /usr/local/bin for CLI convenience
    # The actual binaries use capital "II": bitcoinIId and bitcoinII-cli
    sudo ln -sf "$BC2_DIR/bin/bitcoinIId" /usr/local/bin/bitcoiniid
    sudo ln -sf "$BC2_DIR/bin/bitcoinII-cli" /usr/local/bin/bitcoinii-cli

    fi  # end bc2_download_needed

    # Generate BC2 configuration based on Tor/clearnet setting
    # NOTE: BC2 uses unique ports: RPC 8339, P2P 8338, ZMQ 28338
    if [[ "$BC2_TOR_ENABLED" == "true" ]]; then
        log "Configuring Bitcoin II for Tor network..."
        BC2_NETWORK_CONFIG="# === TOR NETWORK - PRIVACY MODE ===
# Route all connections through Tor for IP privacy
# Note: Sync will be slower but privacy is maximized

# Use Tor SOCKS5 proxy for all outbound connections
proxy=127.0.0.1:9050
# Route .onion peer connections through Tor
onion=127.0.0.1:9050
# Allow both onion and clearnet peers (via Tor proxy)
onlynet=onion
onlynet=ipv4
# Do NOT listen for incoming connections (hidden node)
listen=0
# Reduce connections for Tor
maxconnections=40
# Increase timeouts for Tor latency
peertimeout=120"
    else
        log "Configuring Bitcoin II for clearnet (fastest sync)..."
        BC2_NETWORK_CONFIG="# === CLEARNET - FAST SYNC MODE ===
# Direct IPv4 connections for fastest possible sync

# Maximum peer connections for faster sync
maxconnections=256
# Prefer outbound connections for faster sync (more downloaders)
maxoutconnections=24
# Increase receive buffer (KB) for faster block download
maxreceivebuffer=25000
# Increase send buffer (KB)
maxsendbuffer=5000
# Listen on clearnet (BC2 P2P port 8338)
listen=1
bind=0.0.0.0:$BC2_P2P_PORT
port=$BC2_P2P_PORT
# Force IPv4 clearnet connections only (IPv6 is not supported)
onlynet=ipv4
# DNS seeding enabled for fast peer discovery
dnsseed=1
forcednsseed=1
# Standard timeouts
peertimeout=60
blockstallingtimeout=10

# === IBD (Initial Block Download) OPTIMIZATIONS ===
# Increase parallel block downloads
nblocks=64"
    fi

    sudo tee "$BC2_DATA/bitcoinii.conf" > /dev/null << EOF
# Bitcoin II Core Configuration
# Spiral Pool v3 - Multi-Coin Solo Mining
# Network Mode: $(if [[ "$BC2_TOR_ENABLED" == "true" ]]; then echo "TOR (Privacy)"; else echo "CLEARNET (Fast Sync)"; fi)
# Generated: $(date -u +"%Y-%m-%d %H:%M:%S UTC")
#
# CRITICAL ADDRESS WARNING: Bitcoin II uses IDENTICAL address formats to Bitcoin.
# P2PKH addresses start with "1", P2SH with "3", Bech32 with "bc1"
# Ensure you use addresses generated by Bitcoin II Core, NOT Bitcoin Core!
#
# Port Reference: RPC 8339, P2P 8338, ZMQ 28338

# === CORE SETTINGS ===
server=1
daemon=1
txindex=1
# Full node - no pruning
prune=0
# Mainnet
chain=main

# === RPC CONFIGURATION (BC2 RPC port 8339) ===
rpcuser=$BC2_RPC_USER
rpcpassword=$BC2_RPC_PASSWORD
rpcport=$BC2_RPC_PORT
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcthreads=8
rpcworkqueue=64

# === ZMQ NOTIFICATIONS (BC2 ZMQ port 28338) ===
zmqpubhashblock=tcp://127.0.0.1:$BC2_ZMQ_PORT
zmqpubrawtx=tcp://127.0.0.1:$BC2_ZMQ_PORT

# === PERFORMANCE OPTIMIZATION ===
# Database cache (optimized for sync speed)
dbcache=$(if [[ "$BC2_TOR_ENABLED" == "true" ]]; then echo "1024"; else echo "2048"; fi)
# Memory pool limit
maxmempool=300
# Par = parallel script verification threads (0 = auto-detect CPU cores)
par=0

$BC2_NETWORK_CONFIG

# === WALLET ===
disablewallet=0
addresstype=bech32
changetype=bech32

# === LOGGING ===
printtoconsole=0
logtimestamps=1
$(if [[ "$BC2_TOR_ENABLED" != "true" ]]; then echo "logips=1"; else echo "# logips disabled for privacy"; fi)
shrinkdebugfile=1
# Reduce debug log size during sync
debuglogfile=debug.log

# === CHECKPOINTS ===
checkpoints=1

# === SEED NODES (official Bitcoin II DNS seeds) ===
$(if [[ "$BC2_TOR_ENABLED" != "true" ]]; then echo "# Primary official seeds (Bitcoin II)
seednode=dnsseed.bitcoin-ii.org
seednode=bitcoinII.ddns.net

# DNS seeds for peer discovery
dnsseed=dnsseed.bitcoin-ii.org
dnsseed=bitcoinII.ddns.net

# Static peer fallback (BC2 DNS seed discovery is unreliable in v29.x)
addnode=144.76.79.60:8338
addnode=75.130.145.1:8338
addnode=45.32.205.199:8338
addnode=98.22.238.18:8338"; fi)
EOF

    sudo chmod 640 "$BC2_DATA/bitcoinii.conf"  # 640 allows group read for CLI tools
    sudo chown -R "$POOL_USER:$POOL_USER" "$BC2_DIR"

    # Create systemd service (unique name)
    sudo tee /etc/systemd/system/bitcoiniid.service > /dev/null << EOF
[Unit]
Description=Bitcoin II Core Node
After=network-online.target
Wants=network-online.target
Documentation=https://github.com/Bitcoin-II/BitcoinII-Core
# Prevent restart loops: max 5 restarts in 10 minutes
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
# IMPORTANT: Bitcoin II binaries use capital "II": bitcoinIId, bitcoinII-cli
ExecStart=$BC2_DIR/bin/bitcoinIId -daemon -conf=$BC2_DATA/bitcoinii.conf -datadir=$BC2_DATA
ExecStop=$BC2_DIR/bin/bitcoinII-cli -conf=$BC2_DATA/bitcoinii.conf -datadir=$BC2_DATA stop

# === SELF-HEALING / AUTO-RESTART ===
# Restart=always ensures service restarts on any exit (crash, kill, clean exit)
Restart=always
RestartSec=30
# Note: WatchdogSec removed - blockchain daemons don't support sd_notify
# and will be killed during initial sync when unresponsive processing blocks

TimeoutStartSec=infinity
TimeoutStopSec=600

# === RESOURCE LIMITS ===
# BC2 is a new chain (started Dec 2024) - smaller resource requirements
MemoryMax=4G
MemoryHigh=3G
LimitNOFILE=65536
LimitNPROC=65536
Nice=-5
IOSchedulingClass=best-effort
IOSchedulingPriority=2

# NOTE: Systemd security hardening intentionally omitted.
# Some blockchain daemons crash with SIGABRT under modern systemd
# hardening options (PrivateTmp, ProtectSystem, etc.)

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable bitcoiniid || true

    log_success "Bitcoin II Core $BITCOINII_VERSION installed"
    log "Data directory: $BC2_DATA"
    log "RPC Port: $BC2_RPC_PORT, P2P Port: $BC2_P2P_PORT, ZMQ Port: $BC2_ZMQ_PORT"
    echo ""
    echo -e "${YELLOW}  CRITICAL ADDRESS WARNING:${NC}"
    echo -e "${YELLOW}  Bitcoin II uses IDENTICAL address formats to Bitcoin.${NC}"
    echo -e "${YELLOW}  Ensure your mining address is from Bitcoin II Core, NOT Bitcoin Core!${NC}"
    echo ""
    mark_progress "bitcoinii"
}

# ═══════════════════════════════════════════════════════════════════════════════
# LITECOIN CORE INSTALLATION (Scrypt)
# ═══════════════════════════════════════════════════════════════════════════════

LITECOIN_VERSION="0.21.4"
LTC_RPC_PORT=9332
LTC_P2P_PORT=9333
LTC_ZMQ_PORT=28933  # Litecoin ZMQ port (consistent with MULTI-COIN.md)

install_litecoin() {
    if [[ "$ENABLE_LTC" != "true" ]]; then
        return 0
    fi

    log_step "Installing Litecoin Core $LITECOIN_VERSION"

    # Use multi-disk storage path if configured, otherwise standard location
    local LTC_DIR
    LTC_DIR=$(get_blockchain_dir "ltc")
    local LTC_BIN_DIR="$INSTALL_DIR/ltc-bin"

    if [[ -f "$LTC_BIN_DIR/bin/litecoind" ]]; then
        log "Litecoin Core already installed"
        return 0
    fi

    # Try copying binaries from source node (HA primary or user-specified) before downloading
    local ltc_download_needed=true
    if copy_binaries_from_primary "Litecoin Core" "$LTC_BIN_DIR/bin" "$LTC_BIN_DIR/bin"; then
        sudo mkdir -p "$LTC_BIN_DIR" "$LTC_DIR"
        sudo chown -R "$POOL_USER:$POOL_USER" "$LTC_BIN_DIR" "$LTC_DIR"
        if [[ -f "$LTC_BIN_DIR/bin/litecoind" ]]; then
            ltc_download_needed=false
            sudo ln -sf "$LTC_BIN_DIR/bin/litecoind" /usr/local/bin/litecoind
            sudo ln -sf "$LTC_BIN_DIR/bin/litecoin-cli" /usr/local/bin/litecoin-cli
        else
            log_warn "Replicated files missing expected daemon binary — falling back to download"
        fi
    fi

    if [[ "$ltc_download_needed" == "true" ]]; then

    # Determine architecture suffix for download
    local LTC_ARCH="x86_64-linux-gnu"
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        LTC_ARCH="aarch64-linux-gnu"
    fi

    cd /tmp

    # Download Litecoin Core (0.21.4+ releases are on GitHub)
    local LTC_URL="https://github.com/litecoin-project/litecoin/releases/download/v${LITECOIN_VERSION}/litecoin-${LITECOIN_VERSION}-${LTC_ARCH}.tar.gz"

    log "Downloading Litecoin Core $LITECOIN_VERSION..."
    if ! download_with_retry "litecoin.tar.gz" "$LTC_URL"; then
        log_error "Failed to download Litecoin Core"
        log_error "Please download manually from: https://litecoin.org/download/"
        return 1
    fi

    log "Extracting Litecoin Core..."
    tar -xzf litecoin.tar.gz || { log_error "Failed to extract Litecoin Core archive"; return 1; }
    sudo mkdir -p "$LTC_BIN_DIR"
    sudo cp -r litecoin-${LITECOIN_VERSION}/* "$LTC_BIN_DIR/"
    sudo chown -R "$POOL_USER:$POOL_USER" "$LTC_BIN_DIR"
    rm -rf litecoin.tar.gz litecoin-${LITECOIN_VERSION}

    sudo ln -sf "$LTC_BIN_DIR/bin/litecoind" /usr/local/bin/litecoind
    sudo ln -sf "$LTC_BIN_DIR/bin/litecoin-cli" /usr/local/bin/litecoin-cli

    fi  # end ltc_download_needed

    # Create data directory
    sudo mkdir -p "$LTC_DIR"
    sudo chown -R "$POOL_USER:$POOL_USER" "$LTC_DIR"

    # Generate network configuration based on Tor setting
    if [[ "$TOR_ENABLED" == "true" ]]; then
        log "Configuring Litecoin for Tor network..."
        LTC_NETWORK_CONFIG="# === TOR NETWORK - PRIVACY MODE ===
# Route all connections through Tor for IP privacy
# This node is a Tor CLIENT ONLY - no relay/exit traffic

# Use Tor SOCKS5 proxy for all outbound connections
proxy=127.0.0.1:9050
onion=127.0.0.1:9050
# Allow both onion and clearnet peers (via Tor proxy)
onlynet=onion
onlynet=ipv4
# Do NOT listen for incoming connections (hidden node)
listen=0
externalip=
# Reduce connections for Tor (high latency network)
maxconnections=32
# Increase timeouts for Tor latency (milliseconds)
timeout=120000"
    else
        log "Configuring Litecoin for clearnet (fast sync)..."
        LTC_NETWORK_CONFIG="# === CLEARNET - FAST SYNC MODE ===
# Direct IPv4 connections for fastest possible sync

maxconnections=125
listen=1
bind=0.0.0.0
onlynet=ipv4
dnsseed=1"
    fi

    # Create configuration
    log "Creating Litecoin configuration..."
    sudo -u "$POOL_USER" tee "$LTC_DIR/litecoin.conf" > /dev/null << EOF
# Litecoin Core Configuration for Spiral Pool
# Generated by installer v$VERSION
# Network Mode: $(if [[ "$TOR_ENABLED" == "true" ]]; then echo "TOR (Privacy)"; else echo "CLEARNET (Fast Sync)"; fi)

# === CORE SETTINGS ===
server=1
daemon=1
txindex=1

# RPC Settings
rpcuser=$LTC_RPC_USER
rpcpassword=$LTC_RPC_PASSWORD
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcport=$LTC_RPC_PORT

# ZMQ for block notifications
zmqpubhashblock=tcp://127.0.0.1:$LTC_ZMQ_PORT
zmqpubrawtx=tcp://127.0.0.1:$LTC_ZMQ_PORT

# === NETWORK CONFIGURATION ===
$LTC_NETWORK_CONFIG

# Performance
dbcache=$(if [[ "$TOR_ENABLED" == "true" ]]; then echo "512"; else echo "1024"; fi)
maxmempool=300

# Logging
debug=rpc
debug=zmq
shrinkdebugfile=1
debuglogfile=debug.log
maxdebugfilesize=50
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "logips=1"; else echo "# logips disabled for privacy"; fi)

# PID file
pid=$LTC_DIR/litecoind.pid
EOF

    sudo chmod 640 "$LTC_DIR/litecoin.conf"
    sudo chown "$POOL_USER:$POOL_USER" "$LTC_DIR/litecoin.conf"

    # Create systemd service
    sudo tee /etc/systemd/system/litecoind.service > /dev/null << EOF
[Unit]
Description=Litecoin Core Daemon
Documentation=https://litecoin.org
After=network-online.target
Wants=network-online.target
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
ExecStart=$LTC_BIN_DIR/bin/litecoind -daemon -conf=$LTC_DIR/litecoin.conf -datadir=$LTC_DIR
ExecStop=$LTC_BIN_DIR/bin/litecoin-cli -conf=$LTC_DIR/litecoin.conf -datadir=$LTC_DIR stop
PIDFile=$LTC_DIR/litecoind.pid

# === SELF-HEALING / AUTO-RESTART ===
# Restart=always ensures service restarts on any exit (crash, kill, clean exit)
Restart=always
RestartSec=30
# Note: WatchdogSec removed - blockchain daemons don't support sd_notify
TimeoutStartSec=infinity
TimeoutStopSec=600
LimitNOFILE=65535

# NOTE: Systemd security hardening intentionally omitted.
# Some blockchain daemons crash with SIGABRT under modern systemd
# hardening options (PrivateTmp, ProtectSystem, etc.)

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable litecoind || true

    log_success "Litecoin Core $LITECOIN_VERSION installed"
    log "Data directory: $LTC_DIR"
    log "RPC Port: $LTC_RPC_PORT, P2P Port: $LTC_P2P_PORT, ZMQ Port: $LTC_ZMQ_PORT"
    mark_progress "litecoin"
}

