        fi
    fi

    if [[ "$doge_download_needed" == "true" ]]; then

    # Determine architecture suffix for download
    local DOGE_ARCH="x86_64-linux-gnu"
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        DOGE_ARCH="aarch64-linux-gnu"
    fi

    cd /tmp

    # Download Dogecoin Core
    local DOGE_URL="https://github.com/dogecoin/dogecoin/releases/download/v${DOGECOIN_VERSION}/dogecoin-${DOGECOIN_VERSION}-${DOGE_ARCH}.tar.gz"

    log "Downloading Dogecoin Core $DOGECOIN_VERSION..."
    if ! download_with_retry "dogecoin.tar.gz" "$DOGE_URL"; then
        log_error "Failed to download Dogecoin Core"
        log_error "Please download manually from: https://github.com/dogecoin/dogecoin/releases"
        return 1
    fi

    log "Extracting Dogecoin Core..."
    tar -xzf dogecoin.tar.gz || { log_error "Failed to extract Dogecoin Core archive"; return 1; }
    sudo mkdir -p "$DOGE_BIN_DIR"
    sudo cp -r dogecoin-${DOGECOIN_VERSION}/* "$DOGE_BIN_DIR/"
    sudo chown -R "$POOL_USER:$POOL_USER" "$DOGE_BIN_DIR"
    rm -rf dogecoin.tar.gz dogecoin-${DOGECOIN_VERSION}

    sudo ln -sf "$DOGE_BIN_DIR/bin/dogecoind" /usr/local/bin/dogecoind
    sudo ln -sf "$DOGE_BIN_DIR/bin/dogecoin-cli" /usr/local/bin/dogecoin-cli

    fi  # end doge_download_needed

    # Create data directory
    sudo mkdir -p "$DOGE_DIR"
    sudo chown -R "$POOL_USER:$POOL_USER" "$DOGE_DIR"

    # Generate network configuration based on Tor setting
    if [[ "$TOR_ENABLED" == "true" ]]; then
        log "Configuring Dogecoin for Tor network..."
        DOGE_NETWORK_CONFIG="# === TOR NETWORK - PRIVACY MODE ===
# Route all connections through Tor for IP privacy
# This node is a Tor CLIENT ONLY - no relay/exit traffic

# Use Tor SOCKS5 proxy for all outbound connections
proxy=127.0.0.1:9050
# Route .onion peer connections through Tor
onion=127.0.0.1:9050
# Allow both onion and clearnet peers (via Tor proxy)
onlynet=ipv4
onlynet=onion
# Do NOT listen for incoming connections (hidden node)
listen=0
# Reduce connections for Tor (high latency network)
maxconnections=32"
    else
        log "Configuring Dogecoin for clearnet (fast sync)..."
        DOGE_NETWORK_CONFIG="# === CLEARNET - FAST SYNC MODE ===
# Direct IPv4 connections for fastest possible sync

maxconnections=100
listen=1
dnsseed=1"
    fi

    # Create configuration
    log "Creating Dogecoin configuration..."
    sudo -u "$POOL_USER" tee "$DOGE_DIR/dogecoin.conf" > /dev/null << EOF
# Dogecoin Core Configuration for Spiral Pool
# Generated by installer v$VERSION
# Network Mode: $(if [[ "$TOR_ENABLED" == "true" ]]; then echo "TOR (Privacy)"; else echo "CLEARNET (Fast Sync)"; fi)

# === CORE SETTINGS ===
server=1
daemon=1
txindex=1

# RPC Settings
rpcuser=$DOGE_RPC_USER
rpcpassword=$DOGE_RPC_PASSWORD
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcport=$DOGE_RPC_PORT

# ZMQ for block notifications
zmqpubhashblock=tcp://127.0.0.1:$DOGE_ZMQ_PORT
zmqpubrawtx=tcp://127.0.0.1:$DOGE_ZMQ_PORT

# P2P port
port=$DOGE_P2P_PORT

# === NETWORK CONFIGURATION ===
$DOGE_NETWORK_CONFIG

# Performance
dbcache=$(if [[ "$TOR_ENABLED" == "true" ]]; then echo "256"; else echo "512"; fi)
maxmempool=300

# Logging
debug=rpc
debug=zmq
shrinkdebugfile=1
debuglogfile=debug.log
maxdebugfilesize=50
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "logips=1"; else echo "# logips disabled for privacy"; fi)

# PID file
pid=$DOGE_DIR/dogecoind.pid
EOF

    sudo chmod 640 "$DOGE_DIR/dogecoin.conf"
    sudo chown "$POOL_USER:$POOL_USER" "$DOGE_DIR/dogecoin.conf"

    # Create systemd service
    sudo tee /etc/systemd/system/dogecoind.service > /dev/null << EOF
[Unit]
Description=Dogecoin Core Daemon
Documentation=https://dogecoin.com
After=network-online.target
Wants=network-online.target
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
ExecStart=$DOGE_BIN_DIR/bin/dogecoind -daemon -conf=$DOGE_DIR/dogecoin.conf -datadir=$DOGE_DIR
ExecStop=$DOGE_BIN_DIR/bin/dogecoin-cli -conf=$DOGE_DIR/dogecoin.conf -datadir=$DOGE_DIR stop
PIDFile=$DOGE_DIR/dogecoind.pid

# === SELF-HEALING / AUTO-RESTART ===
# Restart=always ensures service restarts on any exit (crash, kill, clean exit)
Restart=always
RestartSec=30
# Note: WatchdogSec removed - blockchain daemons don't support sd_notify
TimeoutStartSec=infinity
TimeoutStopSec=600
LimitNOFILE=65535

# NOTE: Systemd security hardening intentionally omitted.
# Dogecoin v1.14.x (Bitcoin Core 0.14.x base) crashes with SIGABRT
# under modern systemd hardening options (PrivateTmp, ProtectSystem, etc.)

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable dogecoind || true

    log_success "Dogecoin Core $DOGECOIN_VERSION installed"
    log "Data directory: $DOGE_DIR"
    log "RPC Port: $DOGE_RPC_PORT, P2P Port: $DOGE_P2P_PORT, ZMQ Port: $DOGE_ZMQ_PORT"
    mark_progress "dogecoin"
}

# ═══════════════════════════════════════════════════════════════════════════════
# ═══════════════════════════════════════════════════════════════════════════════
# PEPECOIN CORE INSTALLATION (Scrypt - merge-mineable with LTC)
# ═══════════════════════════════════════════════════════════════════════════════

PEPECOIN_VERSION="1.1.0"
PEP_RPC_PORT=33873
PEP_P2P_PORT=33874
PEP_ZMQ_PORT=28873

install_pepecoin() {
    if [[ "$ENABLE_PEP" != "true" ]]; then
        return 0
    fi

    log_step "Installing PepeCoin Core $PEPECOIN_VERSION"

    # Use multi-disk storage path if configured, otherwise standard location
    local PEP_DIR
    PEP_DIR=$(get_blockchain_dir "pep")
    local PEP_BIN_DIR="$INSTALL_DIR/pep-bin"

    if [[ -f "$PEP_BIN_DIR/bin/pepecoind" ]]; then
        log "PepeCoin Core already installed"
        return 0
    fi

    # Try copying binaries from source node (HA primary or user-specified) before downloading
    local pep_download_needed=true
    if copy_binaries_from_primary "PepeCoin Core" "$PEP_BIN_DIR/bin" "$PEP_BIN_DIR/bin"; then
        sudo mkdir -p "$PEP_BIN_DIR" "$PEP_DIR"
        sudo chown -R "$POOL_USER:$POOL_USER" "$PEP_BIN_DIR" "$PEP_DIR"
        if [[ -f "$PEP_BIN_DIR/bin/pepecoind" ]]; then
            pep_download_needed=false
            sudo ln -sf "$PEP_BIN_DIR/bin/pepecoind" /usr/local/bin/pepecoind
            sudo ln -sf "$PEP_BIN_DIR/bin/pepecoin-cli" /usr/local/bin/pepecoin-cli
        else
            log_warn "Replicated files missing expected daemon binary — falling back to download"
        fi
    fi

    if [[ "$pep_download_needed" == "true" ]]; then

    # Determine architecture suffix for download
    local PEP_ARCH="x86_64-linux-gnu"
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        PEP_ARCH="aarch64-linux-gnu"
    fi

    cd /tmp

    # Download PepeCoin Core (pepecoinppc Scrypt fork)
    local PEP_URL="https://github.com/pepecoinppc/pepecoin/releases/download/v${PEPECOIN_VERSION}/pepecoin-${PEPECOIN_VERSION}-${PEP_ARCH}.tar.gz"

    log "Downloading PepeCoin Core $PEPECOIN_VERSION..."
    if ! download_with_retry "pepecoin.tar.gz" "$PEP_URL"; then
        log_error "Failed to download PepeCoin Core"
        log_error "Please download manually from: https://github.com/pepecoinppc/pepecoin/releases"
        return 1
    fi

    log "Extracting PepeCoin Core..."
    tar -xzf pepecoin.tar.gz || { log_error "Failed to extract PepeCoin Core archive"; return 1; }
    sudo mkdir -p "$PEP_BIN_DIR"
    sudo cp -r pepecoin-${PEPECOIN_VERSION}/* "$PEP_BIN_DIR/"
    sudo chown -R "$POOL_USER:$POOL_USER" "$PEP_BIN_DIR"
    rm -rf pepecoin.tar.gz pepecoin-${PEPECOIN_VERSION}

    sudo ln -sf "$PEP_BIN_DIR/bin/pepecoind" /usr/local/bin/pepecoind
    sudo ln -sf "$PEP_BIN_DIR/bin/pepecoin-cli" /usr/local/bin/pepecoin-cli

    fi  # end pep_download_needed

    # Create data directory
    sudo mkdir -p "$PEP_DIR"
    sudo chown -R "$POOL_USER:$POOL_USER" "$PEP_DIR"

    # Generate network configuration based on Tor setting
    if [[ "$TOR_ENABLED" == "true" ]]; then
        log "Configuring PepeCoin for Tor network..."
        PEP_NETWORK_CONFIG="# === TOR NETWORK - PRIVACY MODE ===
# Route all connections through Tor for IP privacy
# This node is a Tor CLIENT ONLY - no relay/exit traffic

# Use Tor SOCKS5 proxy for all outbound connections
proxy=127.0.0.1:9050
# Route .onion peer connections through Tor
onion=127.0.0.1:9050
# Allow both onion and clearnet peers (via Tor proxy)
onlynet=ipv4
onlynet=onion
# Do NOT listen for incoming connections (hidden node)
listen=0
# Reduce connections for Tor (high latency network)
maxconnections=32"
    else
        log "Configuring PepeCoin for clearnet (fast sync)..."
        PEP_NETWORK_CONFIG="# === CLEARNET - FAST SYNC MODE ===
# Direct IPv4 connections for fastest possible sync

maxconnections=75
listen=1
dnsseed=1"
    fi

    # Create configuration
    log "Creating PepeCoin configuration..."
    sudo -u "$POOL_USER" tee "$PEP_DIR/pepecoin.conf" > /dev/null << EOF
# PepeCoin Core Configuration for Spiral Pool
# Generated by installer v$VERSION
# Network Mode: $(if [[ "$TOR_ENABLED" == "true" ]]; then echo "TOR (Privacy)"; else echo "CLEARNET (Fast Sync)"; fi)

# === CORE SETTINGS ===
server=1
daemon=1
txindex=1

# RPC Settings
rpcuser=$PEP_RPC_USER
rpcpassword=$PEP_RPC_PASSWORD
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcport=$PEP_RPC_PORT

# ZMQ: DISABLED — PepeCoin v1.1.0 binary is compiled without ZMQ support.
# The daemon crashes (SIGABRT) if zmqpub* options are present.
# Stratum uses RPC polling fallback for block notifications.
# zmqpubhashblock=tcp://127.0.0.1:$PEP_ZMQ_PORT
# zmqpubrawtx=tcp://127.0.0.1:$PEP_ZMQ_PORT

# P2P port
port=$PEP_P2P_PORT

# === NETWORK CONFIGURATION ===
$PEP_NETWORK_CONFIG

# Performance
dbcache=$(if [[ "$TOR_ENABLED" == "true" ]]; then echo "128"; else echo "256"; fi)
maxmempool=200

# Logging
debug=rpc
debug=zmq
shrinkdebugfile=1
debuglogfile=debug.log
maxdebugfilesize=50
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "logips=1"; else echo "# logips disabled for privacy"; fi)

# PID file
pid=$PEP_DIR/pepecoind.pid
EOF

    sudo chmod 640 "$PEP_DIR/pepecoin.conf"
    sudo chown "$POOL_USER:$POOL_USER" "$PEP_DIR/pepecoin.conf"

    # Create systemd service
    sudo tee /etc/systemd/system/pepecoind.service > /dev/null << EOF
[Unit]
Description=PepeCoin Core Daemon
Documentation=https://pepe.cx
After=network-online.target
Wants=network-online.target
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
ExecStart=$PEP_BIN_DIR/bin/pepecoind -daemon -conf=$PEP_DIR/pepecoin.conf -datadir=$PEP_DIR
ExecStop=$PEP_BIN_DIR/bin/pepecoin-cli -conf=$PEP_DIR/pepecoin.conf -datadir=$PEP_DIR stop
PIDFile=$PEP_DIR/pepecoind.pid

# === SELF-HEALING / AUTO-RESTART ===
Restart=always
RestartSec=30
TimeoutStartSec=infinity
TimeoutStopSec=600
LimitNOFILE=65535

# NOTE: Systemd security hardening intentionally omitted.
# PepeCoin (old Bitcoin Core base) crashes with SIGABRT
# under modern systemd hardening options (PrivateTmp, ProtectSystem, etc.)

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable pepecoind || true

    log_success "PepeCoin Core $PEPECOIN_VERSION installed"
    log "Data directory: $PEP_DIR"
    log "RPC Port: $PEP_RPC_PORT, P2P Port: $PEP_P2P_PORT, ZMQ Port: $PEP_ZMQ_PORT"
    mark_progress "pepecoin"
}

# ═══════════════════════════════════════════════════════════════════════════════
# CATCOIN CORE INSTALLATION (Scrypt - standalone, no merge mining)
# ═══════════════════════════════════════════════════════════════════════════════

CATCOIN_VERSION="2.1.1"
CAT_RPC_PORT=9932
CAT_P2P_PORT=9933
CAT_ZMQ_PORT=28932

install_catcoin() {
    if [[ "$ENABLE_CAT" != "true" ]]; then
        return 0
    fi

    log_step "Installing Catcoin Core $CATCOIN_VERSION"

    # Use multi-disk storage path if configured, otherwise standard location
    local CAT_DIR
    CAT_DIR=$(get_blockchain_dir "cat")
    local CAT_BIN_DIR="$INSTALL_DIR/cat-bin"

    if [[ -f "$CAT_BIN_DIR/bin/catcoind" ]]; then
        log "Catcoin Core already installed"
        return 0
    fi

    # Try copying binaries from source node (HA primary or user-specified) before downloading
    local cat_download_needed=true
    if copy_binaries_from_primary "Catcoin Core" "$CAT_BIN_DIR/bin" "$CAT_BIN_DIR/bin"; then
        sudo mkdir -p "$CAT_BIN_DIR" "$CAT_DIR"
        sudo chown -R "$POOL_USER:$POOL_USER" "$CAT_BIN_DIR" "$CAT_DIR"
        if [[ -f "$CAT_BIN_DIR/bin/catcoind" ]]; then
            cat_download_needed=false
            sudo ln -sf "$CAT_BIN_DIR/bin/catcoind" /usr/local/bin/catcoind
            sudo ln -sf "$CAT_BIN_DIR/bin/catcoin-cli" /usr/local/bin/catcoin-cli
        else
            log_warn "Replicated files missing expected daemon binary — falling back to download"
        fi
    fi

    if [[ "$cat_download_needed" == "true" ]]; then

    cd /tmp

    # Download Catcoin Core (uses ZIP format, different filename on ARM)
    local CAT_FILENAME="Catcoin-Linux.zip"
    local CAT_DIRNAME="Catcoin-Linux"
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        CAT_FILENAME="Catcoin-AArch.zip"
        CAT_DIRNAME="Catcoin-AArch"
    fi
    local CAT_URL="https://github.com/CatcoinCore/catcoincore/releases/download/v${CATCOIN_VERSION}/${CAT_FILENAME}"

    log "Downloading Catcoin Core $CATCOIN_VERSION..."
    if ! download_with_retry "catcoin.zip" "$CAT_URL"; then
        log_error "Failed to download Catcoin Core"
        log_error "Please download manually from: https://github.com/CatcoinCore/catcoincore/releases"
        return 1
    fi

    log "Extracting Catcoin Core..."
    unzip -q catcoin.zip || { log_error "Failed to extract Catcoin Core archive"; return 1; }
    sudo mkdir -p "$CAT_BIN_DIR"
    sudo cp -r ${CAT_DIRNAME}/* "$CAT_BIN_DIR/"
    sudo chown -R "$POOL_USER:$POOL_USER" "$CAT_BIN_DIR"
    rm -rf catcoin.zip ${CAT_DIRNAME}

    sudo ln -sf "$CAT_BIN_DIR/bin/catcoind" /usr/local/bin/catcoind
    sudo ln -sf "$CAT_BIN_DIR/bin/catcoin-cli" /usr/local/bin/catcoin-cli

    fi  # end cat_download_needed

    # Create data directory
    sudo mkdir -p "$CAT_DIR"
    sudo chown -R "$POOL_USER:$POOL_USER" "$CAT_DIR"

    # Generate network configuration based on Tor setting
    if [[ "$TOR_ENABLED" == "true" ]]; then
        log "Configuring Catcoin for Tor network..."
        CAT_NETWORK_CONFIG="# === TOR NETWORK - PRIVACY MODE ===
# Route all connections through Tor for IP privacy
# This node is a Tor CLIENT ONLY - no relay/exit traffic

# Use Tor SOCKS5 proxy for all outbound connections
proxy=127.0.0.1:9050
# Route .onion peer connections through Tor
onion=127.0.0.1:9050
# Allow both onion and clearnet peers (via Tor proxy)
onlynet=ipv4
onlynet=onion
# Do NOT listen for incoming connections (hidden node)
listen=0
# Reduce connections for Tor (high latency network)
maxconnections=32"
    else
        log "Configuring Catcoin for clearnet (fast sync)..."
        CAT_NETWORK_CONFIG="# === CLEARNET - FAST SYNC MODE ===
# Direct IPv4 connections for fastest possible sync

maxconnections=75
listen=1
dnsseed=1"
    fi

    # Create configuration
    log "Creating Catcoin configuration..."
    sudo -u "$POOL_USER" tee "$CAT_DIR/catcoin.conf" > /dev/null << EOF
# Catcoin Core Configuration for Spiral Pool
# Generated by installer v$VERSION
# Network Mode: $(if [[ "$TOR_ENABLED" == "true" ]]; then echo "TOR (Privacy)"; else echo "CLEARNET (Fast Sync)"; fi)

# === CORE SETTINGS ===
server=1
daemon=1
txindex=1

# RPC Settings
rpcuser=$CAT_RPC_USER
rpcpassword=$CAT_RPC_PASSWORD
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcport=$CAT_RPC_PORT

# ZMQ for block notifications
zmqpubhashblock=tcp://127.0.0.1:$CAT_ZMQ_PORT
zmqpubrawtx=tcp://127.0.0.1:$CAT_ZMQ_PORT

# P2P port
port=$CAT_P2P_PORT

# === NETWORK CONFIGURATION ===
$CAT_NETWORK_CONFIG

# Performance
dbcache=$(if [[ "$TOR_ENABLED" == "true" ]]; then echo "128"; else echo "256"; fi)
maxmempool=200

# Logging
debug=rpc
debug=zmq
shrinkdebugfile=1
debuglogfile=debug.log
maxdebugfilesize=50
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "logips=1"; else echo "# logips disabled for privacy"; fi)

# PID file
pid=$CAT_DIR/catcoind.pid
EOF

    sudo chmod 640 "$CAT_DIR/catcoin.conf"
    sudo chown "$POOL_USER:$POOL_USER" "$CAT_DIR/catcoin.conf"

    # Create systemd service
    sudo tee /etc/systemd/system/catcoind.service > /dev/null << EOF
[Unit]
Description=Catcoin Core Daemon
Documentation=https://www.catcoin2013.org
After=network-online.target
Wants=network-online.target
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
ExecStart=$CAT_BIN_DIR/bin/catcoind -daemon -conf=$CAT_DIR/catcoin.conf -datadir=$CAT_DIR
ExecStop=$CAT_BIN_DIR/bin/catcoin-cli -conf=$CAT_DIR/catcoin.conf -datadir=$CAT_DIR stop
PIDFile=$CAT_DIR/catcoind.pid

# === SELF-HEALING / AUTO-RESTART ===
Restart=always
RestartSec=30
TimeoutStartSec=infinity
TimeoutStopSec=600
LimitNOFILE=65535

# NOTE: Systemd security hardening intentionally omitted.
# Some blockchain daemons crash with SIGABRT under modern systemd
# hardening options (PrivateTmp, ProtectSystem, etc.)

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable catcoind || true

    log_success "Catcoin Core $CATCOIN_VERSION installed"
    log "Data directory: $CAT_DIR"
    log "RPC Port: $CAT_RPC_PORT, P2P Port: $CAT_P2P_PORT, ZMQ Port: $CAT_ZMQ_PORT"
    mark_progress "catcoin"
}


# ═══════════════════════════════════════════════════════════════════════════════
# NAMECOIN CORE INSTALLATION (SHA-256d AuxPoW - merge-mineable with Bitcoin)
# ═══════════════════════════════════════════════════════════════════════════════
# Namecoin was the first coin to implement AuxPoW (merged mining) in 2011.
# When mining Bitcoin, you can simultaneously mine Namecoin with no extra work.
# Official: https://www.namecoin.org | GitHub: https://github.com/namecoin/namecoin-core

install_namecoin() {
    if [[ "$ENABLE_NMC" != "true" ]]; then
        return 0
    fi

    log_step "Installing Namecoin Core $NAMECOIN_VERSION"

    # Use multi-disk storage path if configured, otherwise standard location
    local NMC_DIR
    NMC_DIR=$(get_blockchain_dir "nmc")
    local NMC_BIN_DIR="$INSTALL_DIR/nmc-bin"

    if [[ -f "$NMC_BIN_DIR/bin/namecoind" ]]; then
        log "Namecoin Core already installed"
        return 0
    fi

    # Try copying binaries from source node (HA primary or user-specified) before downloading
    local nmc_download_needed=true
    if copy_binaries_from_primary "Namecoin Core" "$NMC_BIN_DIR/bin" "$NMC_BIN_DIR/bin"; then
        sudo mkdir -p "$NMC_BIN_DIR" "$NMC_DIR"
        sudo chown -R "$POOL_USER:$POOL_USER" "$NMC_BIN_DIR" "$NMC_DIR"
        if [[ -f "$NMC_BIN_DIR/bin/namecoind" ]]; then
            nmc_download_needed=false
            sudo ln -sf "$NMC_BIN_DIR/bin/namecoind" /usr/local/bin/namecoind
            sudo ln -sf "$NMC_BIN_DIR/bin/namecoin-cli" /usr/local/bin/namecoin-cli
        else
            log_warn "Replicated files missing expected daemon binary — falling back to download"
        fi
    fi

    if [[ "$nmc_download_needed" == "true" ]]; then

    cd /tmp

    # Determine architecture suffix for download
    local ARCH_SUFFIX="x86_64-linux-gnu"
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        ARCH_SUFFIX="aarch64-linux-gnu"
    fi

    # Namecoin Core download from official namecoin.org
    # Note: Namecoin publishes binaries on namecoin.org, not GitHub releases
    local NMC_URL="https://www.namecoin.org/files/namecoin-core/namecoin-core-${NAMECOIN_VERSION}/namecoin-${NAMECOIN_VERSION}-${ARCH_SUFFIX}.tar.gz"

    log "Downloading Namecoin Core $NAMECOIN_VERSION..."
    if ! download_with_retry "namecoin.tar.gz" "$NMC_URL"; then
        log_error "Failed to download Namecoin Core"
        log_error "Please download manually from: https://www.namecoin.org/download/"
        return 1
    fi

    log "Extracting Namecoin Core..."
    if ! tar -xzf namecoin.tar.gz; then
        log_error "Failed to extract Namecoin archive"
        rm -f namecoin.tar.gz
        return 1
    fi

    sudo mkdir -p "$NMC_BIN_DIR"
    sudo cp -r namecoin-${NAMECOIN_VERSION}/* "$NMC_BIN_DIR/"
    sudo chown -R "$POOL_USER:$POOL_USER" "$NMC_BIN_DIR"
    rm -rf namecoin.tar.gz namecoin-${NAMECOIN_VERSION}

    # Create symlinks
    sudo ln -sf "$NMC_BIN_DIR/bin/namecoind" /usr/local/bin/namecoind
    sudo ln -sf "$NMC_BIN_DIR/bin/namecoin-cli" /usr/local/bin/namecoin-cli

    fi  # end nmc_download_needed

    # Create data directory
    sudo mkdir -p "$NMC_DIR"
    sudo chown -R "$POOL_USER:$POOL_USER" "$NMC_DIR"

    # Generate network configuration based on Tor setting
    if [[ "$TOR_ENABLED" == "true" ]]; then
        log "Configuring Namecoin for Tor network..."
        NMC_NETWORK_CONFIG="# === TOR NETWORK - PRIVACY MODE ===
proxy=127.0.0.1:9050
onion=127.0.0.1:9050
listen=0
maxconnections=32"
    else
        log "Configuring Namecoin for clearnet (fast sync)..."
        NMC_NETWORK_CONFIG="# === CLEARNET - FAST SYNC MODE ===
maxconnections=125
listen=1
dnsseed=1"
    fi

    # Create configuration
    log "Creating Namecoin configuration..."
    sudo -u "$POOL_USER" tee "$NMC_DIR/namecoin.conf" > /dev/null << EOF
# Namecoin Core Configuration for Spiral Pool
# Generated by installer v$VERSION
# First AuxPoW coin - merge-mineable with Bitcoin (2011)

# === CORE SETTINGS ===
server=1
daemon=1
txindex=1

# RPC Settings
rpcuser=$NMC_RPC_USER
rpcpassword=$NMC_RPC_PASSWORD
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcport=$NMC_RPC_PORT

# ZMQ for block notifications
zmqpubhashblock=tcp://127.0.0.1:$NMC_ZMQ_PORT
zmqpubrawtx=tcp://127.0.0.1:$NMC_ZMQ_PORT

# P2P port
port=$NMC_P2P_PORT

# === NETWORK CONFIGURATION ===
$NMC_NETWORK_CONFIG

# Performance
dbcache=512
maxmempool=300

# Wallet (enabled for address generation)
disablewallet=0

# Logging
shrinkdebugfile=1
debuglogfile=debug.log
maxdebugfilesize=50
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "logips=1"; else echo "# logips disabled for privacy"; fi)

# PID file
pid=$NMC_DIR/namecoind.pid
EOF

    sudo chmod 640 "$NMC_DIR/namecoin.conf"
    sudo chown "$POOL_USER:$POOL_USER" "$NMC_DIR/namecoin.conf"

    # Create systemd service
    sudo tee /etc/systemd/system/namecoind.service > /dev/null << EOF
[Unit]
Description=Namecoin Core Daemon (AuxPoW merge-mined with Bitcoin)
Documentation=https://www.namecoin.org
After=network-online.target
Wants=network-online.target
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
ExecStart=$NMC_BIN_DIR/bin/namecoind -daemon -conf=$NMC_DIR/namecoin.conf -datadir=$NMC_DIR
ExecStop=$NMC_BIN_DIR/bin/namecoin-cli -conf=$NMC_DIR/namecoin.conf -datadir=$NMC_DIR stop
PIDFile=$NMC_DIR/namecoind.pid

# === SELF-HEALING / AUTO-RESTART ===
Restart=always
RestartSec=30
TimeoutStartSec=infinity
TimeoutStopSec=600
LimitNOFILE=65535

# NOTE: Systemd security hardening intentionally omitted.
# Namecoin Core v28.0 crashes with SIGABRT under modern systemd
# hardening options (PrivateTmp, ProtectSystem, etc.) despite being
# based on Bitcoin Core 28.0. Root cause under investigation.

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable namecoind || true

    log_success "Namecoin Core $NAMECOIN_VERSION installed"
    log "Data directory: $NMC_DIR"
    log "RPC Port: $NMC_RPC_PORT, P2P Port: $NMC_P2P_PORT, ZMQ Port: $NMC_ZMQ_PORT"
    mark_progress "namecoin"
}

# ═══════════════════════════════════════════════════════════════════════════════
# SYSCOIN CORE INSTALLATION (SHA-256d AuxPoW - merge-mineable with Bitcoin)
# ═══════════════════════════════════════════════════════════════════════════════
# Syscoin is a UTXO platform with Z-DAG for fast confirmations.
# Supports AuxPoW merge mining with Bitcoin since version 3.0 (2018).
# Official: https://syscoin.org | GitHub: https://github.com/syscoin/syscoin

install_syscoin() {
    if [[ "$ENABLE_SYS" != "true" ]]; then
        return 0
    fi

    log_step "Installing Syscoin Core $SYSCOIN_VERSION"

    # Use multi-disk storage path if configured, otherwise standard location
    local SYS_DIR
    SYS_DIR=$(get_blockchain_dir "sys")
    local SYS_BIN_DIR="$INSTALL_DIR/sys-bin"

    if [[ -f "$SYS_BIN_DIR/bin/syscoind" ]]; then
        log "Syscoin Core already installed"
        return 0
    fi

    # Try copying binaries from source node (HA primary or user-specified) before downloading
    local sys_download_needed=true
    if copy_binaries_from_primary "Syscoin Core" "$SYS_BIN_DIR/bin" "$SYS_BIN_DIR/bin"; then
        sudo mkdir -p "$SYS_BIN_DIR" "$SYS_DIR"
        sudo chown -R "$POOL_USER:$POOL_USER" "$SYS_BIN_DIR" "$SYS_DIR"
        if [[ -f "$SYS_BIN_DIR/bin/syscoind" ]]; then
            sys_download_needed=false
            sudo ln -sf "$SYS_BIN_DIR/bin/syscoind" /usr/local/bin/syscoind
            sudo ln -sf "$SYS_BIN_DIR/bin/syscoin-cli" /usr/local/bin/syscoin-cli
        else
            log_warn "Replicated files missing expected daemon binary — falling back to download"
        fi
    fi

    if [[ "$sys_download_needed" == "true" ]]; then

    cd /tmp

    # Determine architecture suffix for download
    local ARCH_SUFFIX="x86_64-linux-gnu"
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        ARCH_SUFFIX="aarch64-linux-gnu"
    fi

    # Syscoin Core download from GitHub releases
    local SYS_URL="https://github.com/syscoin/syscoin/releases/download/v${SYSCOIN_VERSION}/syscoin-${SYSCOIN_VERSION}-${ARCH_SUFFIX}.tar.gz"

    log "Downloading Syscoin Core $SYSCOIN_VERSION..."
    if ! download_with_retry "syscoin.tar.gz" "$SYS_URL"; then
        log_error "Failed to download Syscoin Core"
        log_error "Please download manually from: https://github.com/syscoin/syscoin/releases"
        return 1
    fi

    log "Extracting Syscoin Core..."
    if ! tar -xzf syscoin.tar.gz; then
        log_error "Failed to extract Syscoin archive"
        rm -f syscoin.tar.gz
        return 1
    fi

    sudo mkdir -p "$SYS_BIN_DIR"
    sudo cp -r syscoin-${SYSCOIN_VERSION}/* "$SYS_BIN_DIR/"
    sudo chown -R "$POOL_USER:$POOL_USER" "$SYS_BIN_DIR"
    rm -rf syscoin.tar.gz syscoin-${SYSCOIN_VERSION}

    # Create symlinks
    sudo ln -sf "$SYS_BIN_DIR/bin/syscoind" /usr/local/bin/syscoind
    sudo ln -sf "$SYS_BIN_DIR/bin/syscoin-cli" /usr/local/bin/syscoin-cli

    fi  # end sys_download_needed

    # Create data directory
    sudo mkdir -p "$SYS_DIR"
    sudo chown -R "$POOL_USER:$POOL_USER" "$SYS_DIR"

    # Generate network configuration based on Tor setting
    if [[ "$TOR_ENABLED" == "true" ]]; then
        log "Configuring Syscoin for Tor network..."
        SYS_NETWORK_CONFIG="# === TOR NETWORK - PRIVACY MODE ===
proxy=127.0.0.1:9050
onion=127.0.0.1:9050
listen=0
maxconnections=32"
    else
        log "Configuring Syscoin for clearnet (fast sync)..."
        SYS_NETWORK_CONFIG="# === CLEARNET - FAST SYNC MODE ===
maxconnections=125
listen=1
dnsseed=1"
    fi

    # Create configuration
    log "Creating Syscoin configuration..."
    sudo -u "$POOL_USER" tee "$SYS_DIR/syscoin.conf" > /dev/null << EOF
# Syscoin Core Configuration for Spiral Pool
# Generated by installer v$VERSION
# UTXO platform with AuxPoW - merge-mineable with Bitcoin

# === CORE SETTINGS ===
server=1
daemon=1
txindex=1

# RPC Settings
rpcuser=$SYS_RPC_USER
rpcpassword=$SYS_RPC_PASSWORD
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcport=$SYS_RPC_PORT

# ZMQ for block notifications
zmqpubhashblock=tcp://127.0.0.1:$SYS_ZMQ_PORT
zmqpubrawtx=tcp://127.0.0.1:$SYS_ZMQ_PORT

# P2P port
port=$SYS_P2P_PORT

# === NETWORK CONFIGURATION ===
$SYS_NETWORK_CONFIG

# Performance (Syscoin 5.0 is larger - needs more resources)
dbcache=1024
maxmempool=300

# Wallet (descriptor wallets are default in Syscoin 5.0)
disablewallet=0

# Logging
shrinkdebugfile=1
debuglogfile=debug.log
maxdebugfilesize=50
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "logips=1"; else echo "# logips disabled for privacy"; fi)

# PID file
pid=$SYS_DIR/syscoind.pid
EOF

    sudo chmod 640 "$SYS_DIR/syscoin.conf"
    sudo chown "$POOL_USER:$POOL_USER" "$SYS_DIR/syscoin.conf"

    # Create systemd service
    sudo tee /etc/systemd/system/syscoind.service > /dev/null << EOF
[Unit]
Description=Syscoin Core Daemon (AuxPoW merge-mined with Bitcoin)
Documentation=https://syscoin.org
After=network-online.target
Wants=network-online.target
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
ExecStart=$SYS_BIN_DIR/bin/syscoind -daemon -conf=$SYS_DIR/syscoin.conf -datadir=$SYS_DIR
ExecStop=$SYS_BIN_DIR/bin/syscoin-cli -conf=$SYS_DIR/syscoin.conf -datadir=$SYS_DIR stop
PIDFile=$SYS_DIR/syscoind.pid

# === SELF-HEALING / AUTO-RESTART ===
Restart=always
RestartSec=30
TimeoutStartSec=infinity
TimeoutStopSec=600
LimitNOFILE=65535

# Syscoin 5.0 needs more memory
MemoryMax=4G

# NOTE: Systemd security hardening intentionally omitted.
# Some blockchain daemons crash with SIGABRT under modern systemd
# hardening options (PrivateTmp, ProtectSystem, etc.)

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable syscoind || true

    log_success "Syscoin Core $SYSCOIN_VERSION installed"
    log "Data directory: $SYS_DIR"
    log "RPC Port: $SYS_RPC_PORT, P2P Port: $SYS_P2P_PORT, ZMQ Port: $SYS_ZMQ_PORT"
    mark_progress "syscoin"
}

# ═══════════════════════════════════════════════════════════════════════════════
# MYRIAD CORE INSTALLATION (SHA-256d AuxPoW - merge-mineable with Bitcoin)
# ═══════════════════════════════════════════════════════════════════════════════
# Myriad is a multi-algorithm coin (SHA256d, Scrypt, Myr-Groestl, Skein, Yescrypt).
# The SHA256d algorithm supports AuxPoW merge mining with Bitcoin from block 1,402,000.
# Official: https://myriadcoin.org | GitHub: https://github.com/myriadteam/myriadcoin

install_myriad() {
    if [[ "$ENABLE_XMY" != "true" ]]; then
        return 0
    fi

    log_step "Installing Myriad Core $MYRIAD_VERSION"

    # Use multi-disk storage path if configured, otherwise standard location
    local XMY_DIR
    XMY_DIR=$(get_blockchain_dir "xmy")
    local XMY_BIN_DIR="$INSTALL_DIR/xmy-bin"

    if [[ -f "$XMY_BIN_DIR/bin/myriadcoind" ]]; then
        log "Myriad Core already installed"
        return 0
    fi

    # Try copying binaries from source node (HA primary or user-specified) before downloading
    local xmy_download_needed=true
    if copy_binaries_from_primary "Myriad Core" "$XMY_BIN_DIR/bin" "$XMY_BIN_DIR/bin"; then
        sudo mkdir -p "$XMY_BIN_DIR" "$XMY_DIR"
        sudo chown -R "$POOL_USER:$POOL_USER" "$XMY_BIN_DIR" "$XMY_DIR"
        if [[ -f "$XMY_BIN_DIR/bin/myriadcoind" ]]; then
            xmy_download_needed=false
            sudo ln -sf "$XMY_BIN_DIR/bin/myriadcoind" /usr/local/bin/myriadcoind
            sudo ln -sf "$XMY_BIN_DIR/bin/myriadcoin-cli" /usr/local/bin/myriadcoin-cli
        else
            log_warn "Replicated files missing expected daemon binary — falling back to download"
        fi
    fi

    if [[ "$xmy_download_needed" == "true" ]]; then

    cd /tmp

    # Determine architecture suffix for download
    local ARCH_SUFFIX="x86_64-linux-gnu"
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        ARCH_SUFFIX="aarch64-linux-gnu"
    fi

    # Myriad Core download from GitHub releases
    local XMY_URL="https://github.com/myriadteam/myriadcoin/releases/download/v${MYRIAD_VERSION}/myriadcoin-${MYRIAD_VERSION}-${ARCH_SUFFIX}.tar.gz"

    log "Downloading Myriad Core $MYRIAD_VERSION..."
    if ! download_with_retry "myriadcoin.tar.gz" "$XMY_URL"; then
        log_error "Failed to download Myriad Core"
        log_error "Please download manually from: https://github.com/myriadteam/myriadcoin/releases"
        return 1
    fi

    log "Extracting Myriad Core..."
    if ! tar -xzf myriadcoin.tar.gz; then
        log_error "Failed to extract Myriad archive"
        rm -f myriadcoin.tar.gz
        return 1
    fi

    # Myriad tarball uses inconsistent directory naming (e.g., 0.18.1.0 extracts
    # to myriadcoin-0.18.1/). Detect the actual extracted directory via glob.
    local XMY_EXTRACTED=$(ls -d myriadcoin-*/ 2>/dev/null | head -1 | tr -d '/')
    if [[ -z "$XMY_EXTRACTED" ]]; then
        log_error "Failed to find extracted Myriad directory"
        rm -f myriadcoin.tar.gz
        return 1
    fi
    sudo mkdir -p "$XMY_BIN_DIR"
    sudo cp -r "${XMY_EXTRACTED}/"* "$XMY_BIN_DIR/"
    sudo chown -R "$POOL_USER:$POOL_USER" "$XMY_BIN_DIR"
    rm -rf myriadcoin.tar.gz "${XMY_EXTRACTED}"

    # Create symlinks
    sudo ln -sf "$XMY_BIN_DIR/bin/myriadcoind" /usr/local/bin/myriadcoind
    sudo ln -sf "$XMY_BIN_DIR/bin/myriadcoin-cli" /usr/local/bin/myriadcoin-cli

    fi  # end xmy_download_needed

    # Create data directory
    sudo mkdir -p "$XMY_DIR"
    sudo chown -R "$POOL_USER:$POOL_USER" "$XMY_DIR"

    # Generate network configuration based on Tor setting
    if [[ "$TOR_ENABLED" == "true" ]]; then
        log "Configuring Myriad for Tor network..."
        XMY_NETWORK_CONFIG="# === TOR NETWORK - PRIVACY MODE ===
proxy=127.0.0.1:9050
onion=127.0.0.1:9050
listen=0
maxconnections=32"
    else
        log "Configuring Myriad for clearnet (fast sync)..."
        XMY_NETWORK_CONFIG="# === CLEARNET - FAST SYNC MODE ===
maxconnections=125
listen=1
dnsseed=1"
    fi

    # Create configuration
    log "Creating Myriad configuration..."
    sudo -u "$POOL_USER" tee "$XMY_DIR/myriadcoin.conf" > /dev/null << EOF
# Myriad Core Configuration for Spiral Pool
# Generated by installer v$VERSION
# Multi-algo coin (SHA256d AuxPoW) - merge-mineable with Bitcoin

# === CORE SETTINGS ===
server=1
daemon=1
txindex=1

# RPC Settings
rpcuser=$XMY_RPC_USER
rpcpassword=$XMY_RPC_PASSWORD
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcport=$XMY_RPC_PORT

# ZMQ for block notifications
zmqpubhashblock=tcp://127.0.0.1:$XMY_ZMQ_PORT
zmqpubrawtx=tcp://127.0.0.1:$XMY_ZMQ_PORT

# P2P port
port=$XMY_P2P_PORT

# === NETWORK CONFIGURATION ===
$XMY_NETWORK_CONFIG

# Performance
dbcache=512
maxmempool=300

# Wallet (enabled for address generation)
disablewallet=0

# Logging
shrinkdebugfile=1
debuglogfile=debug.log
maxdebugfilesize=50
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "logips=1"; else echo "# logips disabled for privacy"; fi)

# PID file
pid=$XMY_DIR/myriadcoind.pid
EOF

    sudo chmod 640 "$XMY_DIR/myriadcoin.conf"
    sudo chown "$POOL_USER:$POOL_USER" "$XMY_DIR/myriadcoin.conf"

    # Create systemd service
    sudo tee /etc/systemd/system/myriadcoind.service > /dev/null << EOF
[Unit]
Description=Myriad Core Daemon (AuxPoW merge-mined with Bitcoin)
Documentation=https://myriadcoin.org
After=network-online.target
Wants=network-online.target
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
ExecStart=$XMY_BIN_DIR/bin/myriadcoind -daemon -conf=$XMY_DIR/myriadcoin.conf -datadir=$XMY_DIR
ExecStop=$XMY_BIN_DIR/bin/myriadcoin-cli -conf=$XMY_DIR/myriadcoin.conf -datadir=$XMY_DIR stop
PIDFile=$XMY_DIR/myriadcoind.pid

# === SELF-HEALING / AUTO-RESTART ===
Restart=always
RestartSec=30
TimeoutStartSec=infinity
TimeoutStopSec=600
LimitNOFILE=65535

# NOTE: Systemd security hardening intentionally omitted.
# Some blockchain daemons crash with SIGABRT under modern systemd
# hardening options (PrivateTmp, ProtectSystem, etc.)

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable myriadcoind || true

    log_success "Myriad Core $MYRIAD_VERSION installed"
    log "Data directory: $XMY_DIR"
    log "RPC Port: $XMY_RPC_PORT, P2P Port: $XMY_P2P_PORT, ZMQ Port: $XMY_ZMQ_PORT"
    mark_progress "myriadcoin"
}

# ═══════════════════════════════════════════════════════════════════════════════
# FRACTAL BITCOIN INSTALLATION (SHA-256d AuxPoW - merge-mineable with Bitcoin)
# ═══════════════════════════════════════════════════════════════════════════════
# Fractal Bitcoin is the only Bitcoin scaling solution using Bitcoin Core code
# to recursively scale unlimited layers. It supports AuxPoW merge mining with BTC.
# Official: https://fractalbitcoin.io | GitHub: https://github.com/fractal-bitcoin

install_fbtc() {
    if [[ "$ENABLE_FBTC" != "true" ]]; then
        return 0
    fi

    # Fractal Bitcoin does not provide ARM64 binaries — skip on ARM
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        log_warn "Fractal Bitcoin does not provide ARM64 binaries — skipping FBTC"
        ENABLE_FBTC="false"
        return 0
    fi

    log_step "Installing Fractal Bitcoin $FBTC_VERSION"

    # Use multi-disk storage path if configured, otherwise standard location
    local FBTC_DIR
    FBTC_DIR=$(get_blockchain_dir "fbtc")
    local FBTC_BIN_DIR="$INSTALL_DIR/fbtc-bin"

    if [[ -f "$FBTC_BIN_DIR/bin/bitcoind" ]]; then
        log "Fractal Bitcoin already installed"
        return 0
    fi

    # Try copying binaries from source node (HA primary or user-specified) before downloading
    local fbtc_download_needed=true
    if copy_binaries_from_primary "Fractal Bitcoin" "$FBTC_BIN_DIR/bin" "$FBTC_BIN_DIR/bin"; then
        sudo mkdir -p "$FBTC_BIN_DIR" "$FBTC_DIR"
        sudo chown -R "$POOL_USER:$POOL_USER" "$FBTC_BIN_DIR" "$FBTC_DIR"
        if [[ -f "$FBTC_BIN_DIR/bin/bitcoind" ]]; then
            fbtc_download_needed=false
            sudo ln -sf "$FBTC_BIN_DIR/bin/bitcoind" /usr/local/bin/fractald
            sudo ln -sf "$FBTC_BIN_DIR/bin/bitcoin-cli" /usr/local/bin/fractal-cli
        else
            log_warn "Replicated files missing expected daemon binary — falling back to download"
        fi
    fi

    if [[ "$fbtc_download_needed" == "true" ]]; then

    cd /tmp

    # Fractal Bitcoin download from GitHub releases
    local FBTC_URL="https://github.com/fractal-bitcoin/fractald-release/releases/download/v${FBTC_VERSION}/fractald-${FBTC_VERSION}-x86_64-linux-gnu.tar.gz"

    log "Downloading Fractal Bitcoin $FBTC_VERSION..."
    if ! download_with_retry "fractald.tar.gz" "$FBTC_URL"; then
        log_error "Failed to download Fractal Bitcoin"
        log_error "Please download manually from: https://github.com/fractal-bitcoin/fractald-release/releases"
        return 1
    fi

    log "Extracting Fractal Bitcoin..."
    if ! tar -xzf fractald.tar.gz; then
        log_error "Failed to extract Fractal Bitcoin archive"
        rm -f fractald.tar.gz
        return 1
    fi

    sudo mkdir -p "$FBTC_BIN_DIR"
    sudo cp -r fractald-${FBTC_VERSION}-x86_64-linux-gnu/* "$FBTC_BIN_DIR/"
    sudo chown -R "$POOL_USER:$POOL_USER" "$FBTC_BIN_DIR"
    rm -rf fractald.tar.gz fractald-${FBTC_VERSION}-x86_64-linux-gnu

    # Create symlinks (archive ships bitcoind/bitcoin-cli, we alias as fractald/fractal-cli)
    sudo ln -sf "$FBTC_BIN_DIR/bin/bitcoind" /usr/local/bin/fractald
    sudo ln -sf "$FBTC_BIN_DIR/bin/bitcoin-cli" /usr/local/bin/fractal-cli

    fi  # end fbtc_download_needed

    # Create data directory
    sudo mkdir -p "$FBTC_DIR"
    sudo chown -R "$POOL_USER:$POOL_USER" "$FBTC_DIR"

    # Generate network configuration based on Tor setting
    if [[ "$TOR_ENABLED" == "true" ]]; then
        log "Configuring Fractal Bitcoin for Tor network..."
        FBTC_NETWORK_CONFIG="# === TOR NETWORK - PRIVACY MODE ===
proxy=127.0.0.1:9050
onion=127.0.0.1:9050
listen=0
maxconnections=32"
    else
        log "Configuring Fractal Bitcoin for clearnet (fast sync)..."
        FBTC_NETWORK_CONFIG="# === CLEARNET - FAST SYNC MODE ===
maxconnections=125
listen=1
dnsseed=1
forcednsseed=1

# === SEED NODES (official Fractal Bitcoin DNS seeds) ===
seednode=dnsseed-mainnet.fractalbitcoin.io
seednode=dnsseed-mainnet.unisat.io

# DNS seeds for peer discovery
dnsseed=dnsseed-mainnet.fractalbitcoin.io
dnsseed=dnsseed-mainnet.unisat.io"
    fi

    # Create configuration
    log "Creating Fractal Bitcoin configuration..."
    sudo -u "$POOL_USER" tee "$FBTC_DIR/fractal.conf" > /dev/null << EOF
# Fractal Bitcoin Configuration for Spiral Pool
# Generated by installer v$VERSION
# SHA-256d AuxPoW - merge-mineable with Bitcoin

# === CORE SETTINGS ===
server=1
daemon=1
txindex=1

# RPC Settings
rpcuser=$FBTC_RPC_USER
rpcpassword=$FBTC_RPC_PASSWORD
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcport=$FBTC_RPC_PORT

# ZMQ for block notifications
zmqpubhashblock=tcp://127.0.0.1:$FBTC_ZMQ_PORT
zmqpubrawtx=tcp://127.0.0.1:$FBTC_ZMQ_PORT

# P2P port
port=$FBTC_P2P_PORT

# === NETWORK CONFIGURATION ===
$FBTC_NETWORK_CONFIG

# Performance
dbcache=1024
maxmempool=300

# Wallet (enabled for address generation)
disablewallet=0

# Logging
shrinkdebugfile=1
debuglogfile=debug.log
maxdebugfilesize=50
$(if [[ "$TOR_ENABLED" != "true" ]]; then echo "logips=1"; else echo "# logips disabled for privacy"; fi)

# PID file
pid=$FBTC_DIR/fractald.pid
EOF

    sudo chmod 640 "$FBTC_DIR/fractal.conf"
    sudo chown "$POOL_USER:$POOL_USER" "$FBTC_DIR/fractal.conf"

    # Create systemd service
    sudo tee /etc/systemd/system/fractald.service > /dev/null << EOF
[Unit]
Description=Fractal Bitcoin Daemon (AuxPoW merge-mined with Bitcoin)
Documentation=https://fractalbitcoin.io
After=network-online.target
Wants=network-online.target
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
ExecStart=$FBTC_BIN_DIR/bin/bitcoind -daemon -conf=$FBTC_DIR/fractal.conf -datadir=$FBTC_DIR
ExecStop=$FBTC_BIN_DIR/bin/bitcoin-cli -conf=$FBTC_DIR/fractal.conf -datadir=$FBTC_DIR stop
PIDFile=$FBTC_DIR/fractald.pid

# === SELF-HEALING / AUTO-RESTART ===
Restart=always
RestartSec=30
TimeoutStartSec=infinity
TimeoutStopSec=600
LimitNOFILE=65535

# NOTE: Systemd security hardening intentionally omitted.
# Some blockchain daemons crash with SIGABRT under modern systemd
# hardening options (PrivateTmp, ProtectSystem, etc.)

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable fractald || true

    log_success "Fractal Bitcoin $FBTC_VERSION installed"
    log "Data directory: $FBTC_DIR"
    log "RPC Port: $FBTC_RPC_PORT, P2P Port: $FBTC_P2P_PORT, ZMQ Port: $FBTC_ZMQ_PORT"
    mark_progress "fractal"
}

# ═══════════════════════════════════════════════════════════════════════════════
# Q-BITX (QBX) INSTALLATION — Post-Quantum Bitcoin Fork (SHA-256d)
# ═══════════════════════════════════════════════════════════════════════════════

install_qbx() {
    if [[ "$ENABLE_QBX" != "true" ]]; then
        return 0
    fi

    # Q-BitX does not provide ARM64 binaries — skip on ARM
    if [[ "$SYSTEM_ARCH" == "arm64" ]]; then
        log_warn "Q-BitX does not provide ARM64 binaries — skipping QBX"
        ENABLE_QBX="false"
        return 0
    fi

    log_step "Installing Q-BitX"

    # Use multi-disk storage path if configured, otherwise standard location
    local QBX_DIR
    QBX_DIR=$(get_blockchain_dir "qbx")
    local QBX_BIN_DIR="$INSTALL_DIR/qbx-bin"

    # Try copying binaries from source node (HA primary or user-specified) before downloading
    local qbx_download_needed=true
    if [[ -f "$QBX_BIN_DIR/qbitx" ]]; then
        log "Q-BitX binary already installed — skipping download, regenerating config"
        # Fall through to config/service creation below (password may have been blank on first run)
        qbx_download_needed=false
    fi
    if copy_binaries_from_primary "Q-BitX" "$QBX_BIN_DIR" "$QBX_BIN_DIR"; then
        sudo mkdir -p "$QBX_BIN_DIR" "$QBX_DIR"
        sudo chown -R "$POOL_USER:$POOL_USER" "$QBX_BIN_DIR" "$QBX_DIR"
        if [[ -f "$QBX_BIN_DIR/qbitx" ]]; then
            qbx_download_needed=false
        else
            log_warn "Replicated files missing expected daemon binary — falling back to download"
        fi
    fi

    if [[ "$qbx_download_needed" == "true" ]]; then

    cd /tmp

    # Install required dependencies
    log "Installing Q-BitX dependencies..."
    wait_for_apt_lock
    sudo apt-get install -y -qq unzip libevent-2.1-7 libleveldb1d libevent-pthreads-2.1-7t64 2>/dev/null || true

    # Q-BitX download from GitHub releases
    local QBX_URL="https://github.com/q-bitx/Source-/releases/download/v0.1.0/qbitx-linux-x86.zip"

    log "Downloading Q-BitX..."
    if ! download_with_retry "qbitx-linux-x86.zip" "$QBX_URL"; then
        log_error "Failed to download Q-BitX"
        log_error "Please download manually from: https://github.com/q-bitx/Source-/releases"
        return 1
    fi

    log "Extracting Q-BitX..."
    if ! unzip -o qbitx-linux-x86.zip -d qbitx-extract; then
        log_error "Failed to extract Q-BitX archive"
        rm -f qbitx-linux-x86.zip
        return 1
    fi

    sudo mkdir -p "$QBX_BIN_DIR"
    # Copy binaries (qbitx and qbitx-cli)
    sudo cp qbitx-extract/qbitx "$QBX_BIN_DIR/" 2>/dev/null || sudo cp qbitx-extract/*/qbitx "$QBX_BIN_DIR/" 2>/dev/null || true
    sudo cp qbitx-extract/qbitx-cli "$QBX_BIN_DIR/" 2>/dev/null || sudo cp qbitx-extract/*/qbitx-cli "$QBX_BIN_DIR/" 2>/dev/null || true
    sudo chmod +x "$QBX_BIN_DIR/qbitx" "$QBX_BIN_DIR/qbitx-cli"
    sudo chown -R "$POOL_USER:$POOL_USER" "$QBX_BIN_DIR"
    rm -rf qbitx-linux-x86.zip qbitx-extract

    # Create symlinks for CLI access
    sudo ln -sf "$QBX_BIN_DIR/qbitx" /usr/local/bin/qbitx
    sudo ln -sf "$QBX_BIN_DIR/qbitx-cli" /usr/local/bin/qbitx-cli

    fi  # end qbx_download_needed

    # Create data directory
    sudo mkdir -p "$QBX_DIR"
    sudo chown -R "$POOL_USER:$POOL_USER" "$QBX_DIR"

    # Create configuration
    log "Creating Q-BitX configuration..."
    sudo -u "$POOL_USER" tee "$QBX_DIR/qbitx.conf" > /dev/null << EOF
# Q-BitX Configuration for Spiral Pool
# Generated by installer v$VERSION
# SHA-256d Post-Quantum Bitcoin Fork

# === CORE SETTINGS ===
server=1
daemon=1
txindex=1

# RPC Settings
rpcuser=$QBX_RPC_USER
rpcpassword=$QBX_RPC_PASSWORD
rpcallowip=127.0.0.1
rpcbind=127.0.0.1
rpcport=$QBX_RPC_PORT

# ZMQ for block notifications
zmqpubhashblock=tcp://127.0.0.1:$QBX_ZMQ_PORT
zmqpubrawtx=tcp://127.0.0.1:$QBX_ZMQ_PORT

# P2P port (remapped from default 8334 to avoid NMC conflict)
port=$QBX_P2P_PORT

# === NETWORK CONFIGURATION ===
maxconnections=32
listen=1

# Performance
dbcache=512
maxmempool=300

# Wallet (enabled for address generation)
disablewallet=0

# Logging
shrinkdebugfile=1
printtoconsole=0

# PID file
pid=$QBX_DIR/qbitxd.pid
EOF

    sudo chmod 640 "$QBX_DIR/qbitx.conf"
    sudo chown "$POOL_USER:$POOL_USER" "$QBX_DIR/qbitx.conf"

    # Create systemd service
    sudo tee /etc/systemd/system/qbitxd.service > /dev/null << EOF
[Unit]
Description=Q-BitX Daemon (Post-Quantum Bitcoin Fork, SHA-256d)
Documentation=https://qbitx.org
After=network-online.target
Wants=network-online.target
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=forking
User=$POOL_USER
Group=$POOL_USER
ExecStart=$QBX_BIN_DIR/qbitx -daemon -conf=$QBX_DIR/qbitx.conf -datadir=$QBX_DIR
ExecStop=$QBX_BIN_DIR/qbitx-cli -conf=$QBX_DIR/qbitx.conf -datadir=$QBX_DIR stop
PIDFile=$QBX_DIR/qbitxd.pid

# === SELF-HEALING / AUTO-RESTART ===
Restart=always
RestartSec=30
TimeoutStartSec=infinity
TimeoutStopSec=600
LimitNOFILE=65535

# NOTE: Systemd security hardening intentionally omitted.
# Some blockchain daemons crash with SIGABRT under modern systemd
# hardening options (PrivateTmp, ProtectSystem, etc.)

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable qbitxd || true

    log_success "Q-BitX installed"
    log "Data directory: $QBX_DIR"
    log "RPC Port: $QBX_RPC_PORT, P2P Port: $QBX_P2P_PORT, ZMQ Port: $QBX_ZMQ_PORT"
    mark_progress "qbx"
}

# ═══════════════════════════════════════════════════════════════════════════════
# POSTGRESQL INSTALLATION
# ═══════════════════════════════════════════════════════════════════════════════

install_postgresql() {
    log_step "Installing PostgreSQL $POSTGRES_VERSION"

    # Validate locale for PostgreSQL (must be en_US.UTF-8 for proper encoding)
    if ! locale -a 2>/dev/null | grep -qiE "^en_US\.utf-?8$"; then
        log "Generating en_US.UTF-8 locale for PostgreSQL..."
        sudo locale-gen en_US.UTF-8 2>/dev/null || true
        sudo update-locale LANG=en_US.UTF-8 2>/dev/null || true
    fi
    log_success "Locale en_US.UTF-8 available"

    # Calculate shared_buffers based on available RAM (25% of total, min 256MB, max 4GB)
    local total_ram_mb=$(free -m | awk '/^Mem:/ {print $2}')
    local shared_buffers_mb=$((total_ram_mb / 4))
    if [[ $shared_buffers_mb -lt 256 ]]; then
        shared_buffers_mb=256
    elif [[ $shared_buffers_mb -gt 4096 ]]; then
        shared_buffers_mb=4096
    fi
    log_success "PostgreSQL shared_buffers: ${shared_buffers_mb}MB (25% of ${total_ram_mb}MB RAM)"

    if check_command psql; then
        log "PostgreSQL already installed"
    else
        curl -fsSL https://www.postgresql.org/media/keys/ACCC4CF8.asc | sudo gpg --dearmor -o /usr/share/keyrings/postgresql-keyring.gpg 2>/dev/null
        echo "deb [signed-by=/usr/share/keyrings/postgresql-keyring.gpg] http://apt.postgresql.org/pub/repos/apt $(lsb_release -cs)-pgdg main" | sudo tee /etc/apt/sources.list.d/pgdg.list > /dev/null
        wait_for_apt_lock
        sudo apt-get update -qq
        wait_for_apt_lock
        sudo apt-get install -y -qq postgresql-$POSTGRES_VERSION postgresql-contrib-$POSTGRES_VERSION
        sudo systemctl start postgresql || { log_error "Failed to start PostgreSQL"; return 1; }
        sudo systemctl enable postgresql || true
        log_success "PostgreSQL installed"
    fi

    # Configure database
    # SKIP if Patroni is already managing PostgreSQL (resume after partial HA setup).
    # On HA backup, Patroni makes this node a read-only replica. Running CREATE ROLE
    # or CREATE DATABASE on a replica fails with "cannot execute in a read-only
    # transaction", and set -e aborts the entire install. This happens when:
    #   1. Previous run succeeded through setup_patroni() (Patroni started)
    #   2. Previous run failed at install_keepalived_vip() (no checkpoint saved)
    #   3. User resumes → install_postgresql() reruns → SQL hits read-only replica
    if systemctl is-active --quiet patroni 2>/dev/null; then
        log "Patroni already manages PostgreSQL — skipping standalone DB setup"
    else

    log "Configuring database user and schema..."

    # Validate identifiers to prevent SQL injection
    if ! validate_sql_identifier "$DB_USER"; then
        log_error "Invalid database username"
        return 1
    fi
    if ! validate_sql_identifier "$DB_NAME"; then
        log_error "Invalid database name"
        return 1
    fi

    # Escape password for SQL (prevents injection via password field)
    local escaped_db_password
    escaped_db_password=$(sql_escape "$DB_PASSWORD")

    # Create role if not exists, update password if exists
    sudo -u postgres psql -q -c "DO \$\$
    BEGIN
        IF NOT EXISTS (SELECT FROM pg_roles WHERE rolname = '$DB_USER') THEN
            CREATE ROLE $DB_USER WITH LOGIN ENCRYPTED PASSWORD '$escaped_db_password';
        ELSE
            ALTER ROLE $DB_USER WITH ENCRYPTED PASSWORD '$escaped_db_password';
        END IF;
    END
    \$\$;"

    # Create database if not exists
    if ! sudo -u postgres psql -lqt | cut -d \| -f 1 | grep -qw "$DB_NAME"; then
        sudo -u postgres createdb -O "$DB_USER" "$DB_NAME"
        log "Created database: $DB_NAME"
    else
        log "Database $DB_NAME already exists"
    fi

    # Grant privileges on database
    sudo -u postgres psql -q -c "GRANT ALL PRIVILEGES ON DATABASE $DB_NAME TO $DB_USER;"

    # Set up database permissions for schema creation
    # NOTE: Tables are created by the Go binary (migrate.go) on first run
    # Tables are created with column names compatible with standard pool tooling
    log "Setting up database permissions..."
    sudo -u postgres psql -d "$DB_NAME" -q << OWNER_EOF
-- Create uuid extension (may be needed by application)
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Transfer schema ownership to allow table creation
ALTER SCHEMA public OWNER TO $DB_USER;

-- Grant create privileges so Go binary can create tables
GRANT CREATE ON SCHEMA public TO $DB_USER;
GRANT ALL PRIVILEGES ON SCHEMA public TO $DB_USER;

-- Grant default privileges for future tables/sequences
ALTER DEFAULT PRIVILEGES IN SCHEMA public GRANT ALL ON TABLES TO $DB_USER;
ALTER DEFAULT PRIVILEGES IN SCHEMA public GRANT ALL ON SEQUENCES TO $DB_USER;

-- Transfer any existing table/sequence ownership (for upgrades)
DO \$\$
DECLARE
    tbl RECORD;
BEGIN
    FOR tbl IN SELECT tablename FROM pg_tables WHERE schemaname = 'public'
    LOOP
        EXECUTE format('ALTER TABLE public.%I OWNER TO $DB_USER', tbl.tablename);
    END LOOP;
END \$\$;

DO \$\$
DECLARE
    seq RECORD;
BEGIN
    FOR seq IN SELECT sequencename FROM pg_sequences WHERE schemaname = 'public'
    LOOP
        EXECUTE format('ALTER SEQUENCE public.%I OWNER TO $DB_USER', seq.sequencename);
    END LOOP;
END \$\$;
OWNER_EOF
    log_success "Database configured - tables will be created by spiralstratum on first run"

    # Apply PostgreSQL hardening settings (GATE 7 compliance)
    local PG_CONF_DIR="/etc/postgresql/$POSTGRES_VERSION/main"
    if [[ -d "$PG_CONF_DIR/conf.d" ]]; then
        log "Applying PostgreSQL disaster recovery hardening..."
        sudo tee "$PG_CONF_DIR/conf.d/spiral-hardening.conf" > /dev/null << 'HARDENING_EOF'
# Spiral Pool PostgreSQL Hardening Configuration
# GATE 7 Compliant: Disaster Recovery Settings
# Applied to both standalone and HA installations

# ========================================
# Timeout Settings (Prevent deadlocks & hung queries)
# ========================================
# Statement timeout: Kill queries running longer than 5 minutes
statement_timeout = 300000

# Lock timeout: Fail if lock not acquired within 30 seconds
lock_timeout = 30000

# Idle transaction timeout: Rollback abandoned transactions after 10 minutes
idle_in_transaction_session_timeout = 600000

# ========================================
# WAL Management (Prevent disk exhaustion)
# ========================================
max_wal_size = 2GB
min_wal_size = 256MB

# ========================================
# Connection Management
# ========================================
# Reasonable defaults for mining pool workload
max_connections = 200
# shared_buffers set dynamically based on available RAM (see below)

# ========================================
# Logging (for monitoring/alerting)
# ========================================
log_lock_waits = on
deadlock_timeout = 1s
log_min_duration_statement = 5000

# ========================================
# Checkpointing (Balance between safety and performance)
# ========================================
checkpoint_completion_target = 0.9
checkpoint_timeout = 10min
HARDENING_EOF
        sudo chown postgres:postgres "$PG_CONF_DIR/conf.d/spiral-hardening.conf"

        # Z8: Set shared_buffers based on calculated RAM (variable expansion needed)
        echo "# Z8: Dynamic shared_buffers based on system RAM" | sudo tee -a "$PG_CONF_DIR/conf.d/spiral-hardening.conf" > /dev/null
        echo "shared_buffers = ${shared_buffers_mb}MB" | sudo tee -a "$PG_CONF_DIR/conf.d/spiral-hardening.conf" > /dev/null
        log_success "PostgreSQL hardening applied (shared_buffers=${shared_buffers_mb}MB)"

        # Reload PostgreSQL to apply settings
        sudo systemctl reload postgresql 2>/dev/null || true
    fi

    fi  # end: Patroni-not-already-running guard

    # Configure HA replication if enabled
    if [[ "$HA_ENABLED" == "true" ]]; then
        if [[ "$PATRONI_ENABLED" == "true" ]]; then
            # Use Patroni for automatic PostgreSQL failover
            # Patroni replaces manual PostgreSQL replication setup
            setup_patroni || { log_error "setup_patroni failed — aborting HA setup"; return 1; }
        else
            # Legacy: Manual PostgreSQL replication (no automatic failover)
            configure_postgresql_ha || { log_error "configure_postgresql_ha failed — aborting HA setup"; return 1; }
        fi
        install_keepalived_vip || { log_error "install_keepalived_vip failed"; return 1; }
    fi

    if [[ "${PATRONI_ROLE_UNKNOWN:-false}" == "true" ]]; then
        log_warn "Database configured (Patroni role pending — will resolve when etcd cluster is healthy)"
    else
        log_success "Database configured"
    fi
    mark_progress "database"
}

# ═══════════════════════════════════════════════════════════════════════════════
# REDIS INSTALLATION (HA cross-node share/block deduplication)
# ═══════════════════════════════════════════════════════════════════════════════
# Redis provides cross-node deduplication for HA clusters:
#   - Block submission dedup: prevents duplicate block submits across nodes
#   - Share dedup: prevents duplicate share credits during failover
# The pool gracefully falls back to local in-memory dedup if Redis is unavailable.
# ═══════════════════════════════════════════════════════════════════════════════
install_redis() {
    log_step "Installing Redis (HA cross-node deduplication)"

    if check_command redis-server; then
        log "Redis already installed"
    else
        wait_for_apt_lock
        sudo apt-get install -y -qq redis-server || { log_error "Failed to install Redis"; return 1; }
        log_success "Redis installed"
    fi

    # Configure Redis for pool workload
    log "Configuring Redis for Spiral Pool HA deduplication..."

    local REDIS_CONF="/etc/redis/redis.conf"
    local config_applied=false

    if [[ -f "$REDIS_CONF" ]]; then
        # Guard: only append if not already configured (idempotent)
        if ! grep -q "Spiral Pool HA Configuration" "$REDIS_CONF" 2>/dev/null; then
            sudo tee -a "$REDIS_CONF" > /dev/null << 'REDIS_CONF_EOF'

# ========================================
# Spiral Pool HA Configuration
# ========================================
# Optimized for cross-node share/block deduplication.
# All pool keys use TTLs, so volatile-ttl evicts the key closest
# to expiration when memory is full — safest for dedup workload.

# Memory limit: 256MB is sufficient for dedup keys (each ~100 bytes, TTL 5min)
maxmemory 256mb

# Eviction policy: only evict keys with TTLs, prefer those closest to expiry
maxmemory-policy volatile-ttl

# Disable RDB persistence (dedup data is ephemeral, not worth disk I/O)
save ""

# Disable AOF (not needed for cache-only workload)
appendonly no

# Security: bind to localhost only (pool connects locally)
bind 127.0.0.1
REDIS_CONF_EOF
            log_success "Redis configuration appended to $REDIS_CONF"
            config_applied=true
        else
            log "Redis already configured for Spiral Pool (skipping)"
            config_applied=true
        fi
    fi

    # Start Redis (must be running before fallback config path)
    sudo systemctl enable redis-server || true
    sudo systemctl restart redis-server || { log_error "Failed to start Redis"; return 1; }

    # Brief wait for Redis to finish starting
    sleep 1

    # Fallback: if config file was missing, create it and restart Redis so settings persist.
    # CONFIG REWRITE requires Redis to have been started with a config file — if the file
    # doesn't exist at startup, CONFIG REWRITE has no path to write to and fails silently.
    if [[ "$config_applied" == "false" ]]; then
        log_warn "Redis config file not found at $REDIS_CONF — creating it..."
        sudo mkdir -p "$(dirname "$REDIS_CONF")"
        sudo tee "$REDIS_CONF" > /dev/null << 'REDIS_FALLBACK_EOF'
# Redis configuration created by Spiral Pool installer
# (original config file was missing after package install)

# ========================================
# Spiral Pool HA Configuration
# ========================================
# Optimized for cross-node share/block deduplication.
# All pool keys use TTLs, so volatile-ttl evicts the key closest
# to expiration when memory is full — safest for dedup workload.

# Memory limit: 256MB is sufficient for dedup keys (each ~100 bytes, TTL 5min)
maxmemory 256mb

# Eviction policy: only evict keys with TTLs, prefer those closest to expiry
maxmemory-policy volatile-ttl

# Disable RDB persistence (dedup data is ephemeral, not worth disk I/O)
save ""

# Disable AOF (not needed for cache-only workload)
appendonly no

# Security: bind to localhost only (pool connects locally)
bind 127.0.0.1

# Systemd supervision
supervised systemd
REDIS_FALLBACK_EOF
        log_success "Created $REDIS_CONF"

        # Restart Redis so it picks up the new config file (CONFIG REWRITE now has a path)
        sudo systemctl restart redis-server || log_warn "Failed to restart Redis with new config"
        sleep 1
        config_applied=true
    fi

    # Verify Redis is running and settings are correct
    local redis_ok=false
    if redis-cli ping 2>/dev/null | grep -q "PONG"; then
        log_success "Redis is running and responding"

        # Verify our settings took effect
        local policy
        policy=$(redis-cli CONFIG GET maxmemory-policy 2>/dev/null | tail -1)
        if [[ "$policy" == "volatile-ttl" ]]; then
            log_success "Redis maxmemory-policy confirmed: volatile-ttl"
            redis_ok=true
        else
            log_warn "Redis maxmemory-policy is '$policy' (expected volatile-ttl) — check config"
        fi
    else
        log_warn "Redis may not be responding — check 'systemctl status redis-server'"
    fi

    if [[ "$redis_ok" == "true" ]]; then
        log_success "Redis configured for HA deduplication"
    else
        log_warn "Redis installed but configuration could not be fully verified"
    fi
    mark_progress "redis"
}

# Configure PostgreSQL for High Availability replication
configure_postgresql_ha() {
    log "Configuring PostgreSQL for High Availability..."

    local PG_CONF_DIR="/etc/postgresql/$POSTGRES_VERSION/main"
    local PG_DATA_DIR="/var/lib/postgresql/$POSTGRES_VERSION/main"

    # Create replication user
    log "Creating replication user..."

    # Validate identifier to prevent SQL injection
    if ! validate_sql_identifier "$DB_REPLICATION_USER"; then
        log_error "Invalid replication username"
        return 1
    fi

    # Escape password for SQL (prevents injection via password field)
    local escaped_password
    escaped_password=$(sql_escape "$DB_REPLICATION_PASSWORD")

    sudo -u postgres psql -q -c "DO \$\$
    BEGIN
        IF NOT EXISTS (SELECT FROM pg_roles WHERE rolname = '$DB_REPLICATION_USER') THEN
            CREATE ROLE $DB_REPLICATION_USER WITH REPLICATION LOGIN ENCRYPTED PASSWORD '$escaped_password';
        ELSE
            ALTER ROLE $DB_REPLICATION_USER WITH ENCRYPTED PASSWORD '$escaped_password';
        END IF;
    END
    \$\$;"

    # Grant replication privileges
    sudo -u postgres psql -q -c "GRANT USAGE ON SCHEMA pg_catalog TO $DB_REPLICATION_USER;"
    sudo -u postgres psql -q -c "GRANT SELECT ON pg_catalog.pg_stat_replication TO $DB_REPLICATION_USER;"

    if [[ "$HA_MODE" == "ha-master" ]]; then
        # Configure as PRIMARY
        log "Configuring PostgreSQL as PRIMARY for replication..."

        # Update postgresql.conf for replication (overwrite, not append, for re-run safety)
        sudo tee "$PG_CONF_DIR/conf.d/spiral-ha.conf" > /dev/null << EOF
# Spiral Pool HA Replication Configuration (Primary)
# Generated by installer on $(date)
# GATE 7 Compliant: Disaster Recovery Hardening

# ========================================
# Replication Settings
# ========================================
wal_level = replica
max_wal_senders = 10
max_replication_slots = 10
synchronous_commit = on
hot_standby = on

# ========================================
# WAL Management (GATE 7 - Prevent disk exhaustion)
# ========================================
# Keep enough WAL for replica to catch up (1GB segments * 64 = ~64GB max)
max_wal_size = 4GB
min_wal_size = 1GB
wal_keep_size = 2GB

# Archive settings (optional but recommended for PITR)
archive_mode = on
archive_command = '/bin/true'

# ========================================
# Timeout Settings (GATE 7 - Prevent deadlocks)
# ========================================
# Statement timeout: Kill queries running longer than 5 minutes
statement_timeout = 300000

# Lock timeout: Fail if lock not acquired within 30 seconds
lock_timeout = 30000

# Idle transaction timeout: Rollback abandoned transactions after 10 minutes
idle_in_transaction_session_timeout = 600000

# ========================================
# Connection settings for replication
# ========================================
listen_addresses = '*'

# ========================================
# Security
# ========================================
password_encryption = scram-sha-256

# ========================================
# Logging (for monitoring/alerting)
# ========================================
log_replication_commands = on
log_connections = on
log_disconnections = on
log_lock_waits = on
deadlock_timeout = 1s
EOF

        # Add pg_hba.conf entry for replication
        # Allow replication from any host in the same subnet
        local SUBNET
        SUBNET=$(ip -4 addr show "$VIP_INTERFACE" 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.\d+){3}/\d+' | head -1)
        if [[ -z "$SUBNET" ]]; then
            SUBNET="0.0.0.0/0"  # Fallback to allow all (protected by password)
        fi

        # Check if replication entry already exists
        if ! sudo grep -q "host.*replication.*$DB_REPLICATION_USER" "$PG_CONF_DIR/pg_hba.conf" 2>/dev/null; then
            sudo tee -a "$PG_CONF_DIR/pg_hba.conf" > /dev/null << EOF

# Spiral Pool HA Replication
hostssl replication $DB_REPLICATION_USER $SUBNET scram-sha-256
host    replication $DB_REPLICATION_USER $SUBNET scram-sha-256
EOF
        fi

        # NOTE: Replication slot is created AFTER PostgreSQL restart below
        # This ensures the configuration is loaded before slot creation

        log_success "PostgreSQL PRIMARY configuration complete"

    elif [[ "$HA_MODE" == "ha-backup" ]]; then
        # Configure as REPLICA
        log "Configuring PostgreSQL as REPLICA..."

        # Stop PostgreSQL to set up as standby
        sudo systemctl stop postgresql || true

        # Backup existing data directory
        if [[ -d "$PG_DATA_DIR" ]]; then
            sudo mv "$PG_DATA_DIR" "${PG_DATA_DIR}.backup.$(date +%Y%m%d%H%M%S)"
        fi

        # Create .pgpass file for pg_basebackup authentication (secure, non-interactive)
        log "Setting up PostgreSQL authentication for replication..."
        local PGPASS_FILE="/var/lib/postgresql/.pgpass"
        sudo -u postgres bash -c "cat > '$PGPASS_FILE' << EOF
${HA_PRIMARY_IP:-$HA_PEER_IP}:5432:*:$DB_REPLICATION_USER:$DB_REPLICATION_PASSWORD
EOF"
        sudo chmod 600 "$PGPASS_FILE"
        sudo chown postgres:postgres "$PGPASS_FILE"

        # Use pg_basebackup to clone from primary
        log "Cloning data from primary node (${HA_PRIMARY_IP:-$HA_PEER_IP})..."

        # Use set -o pipefail to capture pg_basebackup exit code through the pipe
        local basebackup_output
        local basebackup_exit
        set -o pipefail
        basebackup_output=$(sudo -u postgres pg_basebackup \
            -h "${HA_PRIMARY_IP:-$HA_PEER_IP}" \
            -U "$DB_REPLICATION_USER" \
            -D "$PG_DATA_DIR" \
            -Fp -Xs -P -R \
            --slot=spiral_backup_slot \
            --checkpoint=fast \
            2>&1) && basebackup_exit=0 || basebackup_exit=$?
        set +o pipefail

        # Log the output
        while IFS= read -r line; do
            log "  $line"
        done <<< "$basebackup_output"

        if [[ $basebackup_exit -ne 0 ]]; then
            log_error "Failed to clone database from primary (exit code: $basebackup_exit). Check:"
            log_error "  1. Primary node is running and reachable"
            log_error "  2. Replication password is correct"
            log_error "  3. pg_hba.conf on primary allows this node"
            log_error "  4. Replication slot 'spiral_backup_slot' exists on primary"
            return 1
        fi

        # Ensure standby.signal exists (PostgreSQL 12+)
        sudo touch "$PG_DATA_DIR/standby.signal"
        sudo chown postgres:postgres "$PG_DATA_DIR/standby.signal"

        # Update postgresql.conf for standby (overwrite, not append, for re-run safety)
        sudo tee "$PG_CONF_DIR/conf.d/spiral-ha.conf" > /dev/null << EOF
# Spiral Pool HA Replication Configuration (Standby/Replica)
# Generated by installer on $(date)
# GATE 7 Compliant: Disaster Recovery Hardening

# ========================================
# Standby Settings
# ========================================
hot_standby = on
hot_standby_feedback = on

# Primary connection
primary_conninfo = 'host=${HA_PRIMARY_IP:-$HA_PEER_IP} port=5432 user=$DB_REPLICATION_USER password=$DB_REPLICATION_PASSWORD application_name=spiral_replica'
primary_slot_name = 'spiral_backup_slot'

# Recovery settings
recovery_target_timeline = 'latest'

# ========================================
# WAL Management (GATE 7 - Match primary settings)
# ========================================
max_wal_size = 4GB
min_wal_size = 1GB

# ========================================
# Timeout Settings (GATE 7 - Prevent deadlocks on read queries)
# ========================================
statement_timeout = 300000
lock_timeout = 30000
idle_in_transaction_session_timeout = 600000

# ========================================
# Security
# ========================================
password_encryption = scram-sha-256

# ========================================
# Logging (for monitoring/alerting)
# ========================================
log_connections = on
log_disconnections = on
log_lock_waits = on
deadlock_timeout = 1s
EOF

        # Start PostgreSQL
        sudo systemctl start postgresql || { log_error "Failed to start PostgreSQL replica"; return 1; }

        log_success "PostgreSQL REPLICA configuration complete"
    fi

    # Restart PostgreSQL to apply configuration (only for primary, replica already restarted)
    if [[ "$HA_MODE" == "ha-master" ]]; then
        sudo systemctl restart postgresql || { log_error "Failed to restart PostgreSQL"; return 1; }

        # Create replication slot AFTER restart so config is loaded
        sleep 2
        local SLOT_NAME="spiral_backup_slot"
        log "Creating replication slot '$SLOT_NAME'..."
        sudo -u postgres psql -q -c "SELECT pg_create_physical_replication_slot('$SLOT_NAME', true);" 2>/dev/null || true
    fi

    # Verify replication status
    sleep 3
    if [[ "$HA_MODE" == "ha-master" ]]; then
        log "Primary node ready for replication connections"
    else
        local repl_status
        repl_status=$(sudo -u postgres psql -t -c "SELECT pg_is_in_recovery();" 2>/dev/null | tr -d '[:space:]')
        if [[ "$repl_status" == "t" ]]; then
            log_success "Replica is connected and streaming from primary"
        else
            log_warn "Replica may not be streaming yet - check logs"
        fi
    fi
}

# ═══════════════════════════════════════════════════════════════════════════════
# PATRONI INSTALLATION (Automatic PostgreSQL Failover)
# ═══════════════════════════════════════════════════════════════════════════════

# Install etcd for Patroni distributed consensus
install_etcd() {
    log "Installing etcd for distributed consensus..."

    if check_command etcd; then
        log "etcd already installed"
        return 0
    fi

    # Ubuntu 24.04 split the 'etcd' package into 'etcd-server' + 'etcd-client'
    # Ensure universe repository is enabled (these packages live there)
    sudo add-apt-repository -y universe > /dev/null 2>&1 || true
    wait_for_apt_lock
    sudo apt-get update -qq > /dev/null 2>&1
    sudo apt-get install -y -qq etcd-server etcd-client || { log_error "Failed to install etcd"; return 1; }

    log_success "etcd installed"
}

# Configure etcd for this node
# PRIMARY: Starts as single-node cluster (immediate quorum), backup added later
# BACKUP:  Joins existing cluster as LEARNER via etcdctl member add on primary,
#          promoted to voter after health check (prevents primary quorum disruption)
configure_etcd() {
    log "Configuring etcd..."

    local node_ip="$SERVER_IP"

    # Safety check: never write config with empty IPs
    if [[ -z "$node_ip" ]] || [[ "$node_ip" == "YOUR_SERVER_IP" ]]; then
        log_error "SERVER_IP is empty — cannot configure etcd. Aborting."
        return 1
    fi

    local etcd_name=""
    local cluster_peers=""
    local etcd_hosts=""
    local cluster_state=""

    if [[ "$HA_MODE" == "ha-master" ]]; then
        # ══════════════════════════════════════════════════════════════════
        # PRIMARY: Bootstrap as single-node cluster
        # Quorum = 1/1 — starts immediately without waiting for backup
        # Backup nodes will add themselves via etcdctl member add later
        # ══════════════════════════════════════════════════════════════════
        etcd_name="etcd-$(hostname -s)"
        cluster_peers="${etcd_name}=http://${node_ip}:2380"
        etcd_hosts="${node_ip}:2379"
        cluster_state="new"
        log "etcd primary (${etcd_name}): single-node bootstrap (peers will join later)"

    elif [[ "$HA_MODE" == "ha-backup" ]]; then
        # ══════════════════════════════════════════════════════════════════
        # BACKUP: Join existing cluster on the primary
        # 1. Register this node with primary's etcd as LEARNER (preserves primary quorum)
        # 2. Start with ETCD_INITIAL_CLUSTER_STATE="existing"
        # 3. After health: promote learner to voter (cluster gains this node)
        # ══════════════════════════════════════════════════════════════════
        etcd_name="etcd-$(hostname -s)"
        cluster_state="existing"
        local primary_etcd="${HA_PRIMARY_IP:-$HA_PEER_IP}"

        # Build etcd_hosts from all peers + self
        etcd_hosts="${node_ip}:2379"
        for peer_ip in "${HA_PEER_IPS[@]}"; do
            etcd_hosts+=",${peer_ip}:2379"
        done

        log "etcd backup (${etcd_name}): joining existing cluster on ${primary_etcd}..."

        # Check if this node is already a member (idempotent on re-run)
        # --write-out=simple ensures comma-separated format (etcd 3.4+ defaults to table)
        # Match on BOTH name and peerURL — after a failed first run, the member exists
        # in the cluster but has an empty name (unstarted), so name-only grep misses it.
        local existing_member
        existing_member=$(ETCDCTL_API=3 etcdctl --command-timeout=10s --endpoints="http://${primary_etcd}:2379" \
            member list --write-out=simple 2>/dev/null | grep -E "(${etcd_name}|http://${node_ip}:2380)" || echo "")
        if [[ -n "$existing_member" ]]; then
            log "etcd member ${etcd_name} already exists, skipping add"
        else
            # Add this node as a LEARNER member (retry up to 5 times with backoff).
            # CRITICAL: --learner prevents quorum disruption. Without it, member add
            # immediately increases the voting member count. If this node's etcd then
            # fails to start, the cluster loses a voter — potentially dropping below
            # quorum — Patroni loses its leader key — production DB goes read-only.
            # With --learner, existing quorum is unaffected until we explicitly promote.
            local add_output add_ok=false add_attempts=5
            for ((attempt=1; attempt<=add_attempts; attempt++)); do
                add_output=$(ETCDCTL_API=3 etcdctl --command-timeout=10s --endpoints="http://${primary_etcd}:2379" \
                    member add "${etcd_name}" --learner --peer-urls="http://${node_ip}:2380" 2>&1) && {
                    add_ok=true
                    break
                }
                if [[ $attempt -lt $add_attempts ]]; then
                    log_warn "etcd member add attempt $attempt/$add_attempts failed, retrying in ${attempt}s..."
                    sleep "$attempt"
                fi
            done
            if [[ "$add_ok" != "true" ]]; then
                log_error "Failed to add this node to primary's etcd cluster after $add_attempts attempts"
                log_error "Output: $add_output"
                log_error "Ensure the primary node is running and etcd is healthy"
                return 1
            fi
            log "etcd member add succeeded"
        fi

        # Build cluster_peers dynamically from primary's member list
        # --write-out=simple: "ID, status, name, peerURLs, clientURLs, isLearner"
        # Retry up to 3 times (etcd may be briefly busy after member add)
        local member_list=""
        local list_retries=3
        while [[ $list_retries -gt 0 ]] && [[ -z "$member_list" ]]; do
            member_list=$(ETCDCTL_API=3 etcdctl --command-timeout=10s --endpoints="http://${primary_etcd}:2379" \
                member list --write-out=simple 2>/dev/null || echo "")
            if [[ -z "$member_list" ]]; then
                list_retries=$((list_retries - 1))
                [[ $list_retries -gt 0 ]] && sleep 2
            fi
        done
        if [[ -n "$member_list" ]]; then
            # Parse member list: extract name=peerURL pairs
            # Note: newly-added members appear with an empty name (unstarted) until
            # they boot. We use their peerURL to match our own entry and fill in the name.
            cluster_peers=""
            while IFS= read -r line; do
                local m_name m_peer_url
                m_name=$(echo "$line" | awk -F', ' '{print $3}')
                m_peer_url=$(echo "$line" | awk -F', ' '{print $4}' | tr -d '[]')
                # If name is empty but peerURL matches our own, use our known name
                if [[ -z "$m_name" ]] && [[ "$m_peer_url" == "http://${node_ip}:2380" ]]; then
                    m_name="$etcd_name"
                fi
                if [[ -n "$m_name" ]] && [[ -n "$m_peer_url" ]]; then
                    [[ -n "$cluster_peers" ]] && cluster_peers+=","
                    cluster_peers+="${m_name}=${m_peer_url}"
                fi
            done <<< "$member_list"
            log "etcd cluster peers (from member list): $cluster_peers"
        fi

        # Fallback: if member list query failed after retries, fail rather than
        # constructing with wrong member names (which would cause etcd startup failure)
        if [[ -z "$cluster_peers" ]]; then
            log_error "Could not query etcd member list from primary after retries"
            log_error "Ensure etcd is running and healthy on primary node (${primary_etcd})"
            log_error "Check: ETCDCTL_API=3 etcdctl --endpoints=http://${primary_etcd}:2379 member list"
            return 1
        fi
    else
        log_error "Unknown HA_MODE: $HA_MODE — cannot configure etcd"
        return 1
    fi

    # Store for Patroni configuration
    ETCD_HOSTS_CONFIG="$etcd_hosts"

    # Clear etcd data if name changed or etcd is unhealthy (prevents stale member identity)
    if [[ -d "/var/lib/etcd/member" ]]; then
        local current_etcd_name=""
        if [[ -f "/etc/default/etcd" ]]; then
            current_etcd_name=$(grep '^ETCD_NAME=' /etc/default/etcd 2>/dev/null | cut -d'"' -f2)
        fi

        if [[ -n "$current_etcd_name" ]] && [[ "$current_etcd_name" != "$etcd_name" ]]; then
            log "etcd member name changed (${current_etcd_name} → ${etcd_name}) — clearing data directory..."
            sudo systemctl stop etcd 2>/dev/null || true
            sudo rm -rf /var/lib/etcd/member
        elif ! ETCDCTL_API=3 etcdctl --command-timeout=5s endpoint health 2>&1 | grep -q "is healthy"; then
            log "Clearing stale etcd data directory (etcd not healthy)..."
            sudo systemctl stop etcd 2>/dev/null || true
            sudo rm -rf /var/lib/etcd/member
        else
            log "etcd data exists and is healthy (name=${current_etcd_name}) — preserving"
        fi
    fi

    # Create etcd configuration
    sudo tee /etc/default/etcd > /dev/null << EOF
# Spiral Pool etcd configuration
# Generated by installer on $(date)
# Part of Patroni HA PostgreSQL setup

ETCD_NAME="$etcd_name"
ETCD_DATA_DIR="/var/lib/etcd"
ETCD_LISTEN_CLIENT_URLS="http://${node_ip}:2379,http://127.0.0.1:2379"
ETCD_ADVERTISE_CLIENT_URLS="http://${node_ip}:2379"
ETCD_LISTEN_PEER_URLS="http://${node_ip}:2380"
ETCD_INITIAL_ADVERTISE_PEER_URLS="http://${node_ip}:2380"
ETCD_INITIAL_CLUSTER="$cluster_peers"
ETCD_INITIAL_CLUSTER_STATE="$cluster_state"
ETCD_INITIAL_CLUSTER_TOKEN="spiralpool-etcd-cluster"
EOF

    # Enable and start etcd
    sudo systemctl enable etcd || true
    sudo systemctl restart etcd || { log_error "Failed to start etcd"; return 1; }

    # BACKUP: Promote learner BEFORE checking local health.
    # Learner nodes reject health RPCs (etcdserver: rpc not supported for learner),
    # creating a chicken-and-egg: health check never passes → promotion never runs.
    # Fix: wait for learner to connect ("started"), promote via primary, then check local health.
    if [[ "$HA_MODE" == "ha-backup" ]] && [[ -n "${primary_etcd:-}" ]]; then
        # Poll primary's member list until learner shows "started" (connected to leader).
        # "started" = peer connection established and Raft log syncing.
        # Timeout 30s — on LAN with near-empty cluster, typically <2s.
        local learner_started=false
        for ((lw=1; lw<=30; lw++)); do
            if ETCDCTL_API=3 etcdctl --command-timeout=5s --endpoints="http://${primary_etcd}:2379" \
                member list --write-out=simple 2>/dev/null | grep "http://${node_ip}:2380" | \
                awk -F', ' '{print $2}' | tr -d ' ' | grep -qx "started"; then
                learner_started=true
                break
            fi
            [[ $lw -eq 1 ]] && log "Waiting for etcd learner to connect to leader..."
            sleep 1
        done

        if [[ "$learner_started" != "true" ]]; then
            log_warn "etcd learner did not reach 'started' state in 30s — attempting promotion anyway"
        fi

        # Promote learner to voter via primary endpoint.
        # Primary always serves RPCs (it's a voter/leader). Learner must have caught up
        # with leader's Raft log before etcd allows promotion.
        # TOCTOU FIX: Single member list fetch, parse twice (matches etcd-cluster-rejoin.sh pattern)
        local promote_member_line promote_member_id promote_is_learner promote_ok=false
        promote_member_line=$(ETCDCTL_API=3 etcdctl --command-timeout=5s --endpoints="http://${primary_etcd}:2379" \
            member list --write-out=simple 2>/dev/null | grep "http://${node_ip}:2380" | head -1 || echo "")
        promote_member_id=$(echo "$promote_member_line" | awk -F', ' '{print $1}' | tr -d '[:space:]')
        promote_is_learner=$(echo "$promote_member_line" | awk -F', ' '{print $6}' | tr -d ' ')

        if [[ "${promote_is_learner:-}" == "true" ]] && [[ -n "${promote_member_id:-}" ]]; then
            for ((promote_try=1; promote_try<=6; promote_try++)); do
                if ETCDCTL_API=3 etcdctl --command-timeout=10s --endpoints="http://${primary_etcd}:2379" \
                    member promote "$promote_member_id" 2>&1; then
                    log_success "etcd learner promoted to voting member"
                    promote_ok=true
                    break
                fi
                log "Learner not ready for promotion (attempt $promote_try/6) — waiting..."
                sleep 5
            done
            if [[ "$promote_ok" != "true" ]]; then
                log_warn "Learner promotion did not succeed in 30s — health check will retry"
            fi
        fi
    fi

    # Wait for etcd to be ready
    local retries=30
    while [[ $retries -gt 0 ]]; do
        # etcd 3.4 outputs health status to stderr, not stdout — use 2>&1 so grep can read it
        if ETCDCTL_API=3 etcdctl --command-timeout=5s endpoint health 2>&1 | grep -q "is healthy"; then
            log_success "etcd is healthy"

            # BACKUP: Promote learner to full voting member.
            # Until promoted, backup doesn't participate in Raft quorum.
            # After promotion, this node participates in Raft quorum.
            if [[ "$HA_MODE" == "ha-backup" ]] && [[ -n "${primary_etcd:-}" ]]; then
                # TOCTOU FIX: Single member list fetch, parse twice
                local my_member_line my_member_id my_is_learner
                my_member_line=$(ETCDCTL_API=3 etcdctl --command-timeout=5s --endpoints="http://${primary_etcd}:2379" \
                    member list --write-out=simple 2>/dev/null | grep "http://${node_ip}:2380" | head -1 || echo "")
                my_member_id=$(echo "$my_member_line" | awk -F', ' '{print $1}' | tr -d '[:space:]')
                my_is_learner=$(echo "$my_member_line" | awk -F', ' '{print $6}' | tr -d ' ')

                if [[ "${my_is_learner:-}" == "true" ]] && [[ -n "${my_member_id:-}" ]]; then
                    log "Promoting etcd learner to voting member..."
                    if ETCDCTL_API=3 etcdctl --command-timeout=10s --endpoints="http://${primary_etcd}:2379" \
                        member promote "$my_member_id" 2>&1; then
                        log_success "etcd promoted — this node is now a voting member"
                    else
                        log_warn "etcd learner promotion failed — cluster has no backup voter"
                        log_warn "Manual fix: ETCDCTL_API=3 etcdctl --endpoints=http://${primary_etcd}:2379 member promote $my_member_id"
                    fi
                fi
            fi

            return 0
        fi
        sleep 1
        retries=$((retries - 1))
    done

    if [[ "$HA_MODE" == "ha-master" ]]; then
        # Primary single-node should be healthy — this is a real problem
        log_error "etcd failed to become healthy as single-node cluster"
        return 1
    else
        # Backup etcd failed to become healthy within 30 seconds.
        # Because --learner was used, primary quorum is UNAFFECTED (1/1).
        # Automatically retry: remove learner, wipe data, re-add, restart.
        local etcd_retry_max=2
        local etcd_retry_ok=false

        for ((etcd_retry=1; etcd_retry<=etcd_retry_max; etcd_retry++)); do
            log_warn "etcd backup not healthy (attempt $etcd_retry/$etcd_retry_max) — retrying automatically..."

            # 1. Remove stale learner from primary (safe — learner doesn't affect quorum)
            if [[ -n "${primary_etcd:-}" ]]; then
                local stale_id stale_learner
                stale_id=$(ETCDCTL_API=3 etcdctl --command-timeout=5s --endpoints="http://${primary_etcd}:2379" \
                    member list --write-out=simple 2>/dev/null | grep "http://${node_ip}:2380" | awk -F', ' '{print $1}' || echo "")
                stale_learner=$(ETCDCTL_API=3 etcdctl --command-timeout=5s --endpoints="http://${primary_etcd}:2379" \
                    member list --write-out=simple 2>/dev/null | grep "http://${node_ip}:2380" | awk -F', ' '{print $6}' | tr -d ' ' || echo "false")
                if [[ -n "$stale_id" ]]; then
                    if [[ "${stale_learner:-}" == "true" ]]; then
                        log "Removing stale learner from primary cluster..."
                        ETCDCTL_API=3 etcdctl --command-timeout=10s --endpoints="http://${primary_etcd}:2379" \
                            member remove "$stale_id" 2>/dev/null && \
                            log "Learner removed" || \
                            log_warn "Could not remove learner entry"
                    else
                        # It's a voter — remove it too since it never started
                        log "Removing stale voter entry from primary cluster..."
                        ETCDCTL_API=3 etcdctl --command-timeout=10s --endpoints="http://${primary_etcd}:2379" \
                            member remove "$stale_id" 2>/dev/null && \
                            log "Stale member removed" || \
                            log_warn "Could not remove stale member"
                    fi
                fi
            fi

            # 2. Stop etcd and wipe local data directory
            sudo systemctl stop etcd 2>/dev/null || true
            sudo rm -rf /var/lib/etcd/member
            sleep 3

            # 3. Re-add as learner
            local retry_add_output retry_add_ok=false
            for ((ra=1; ra<=3; ra++)); do
                retry_add_output=$(ETCDCTL_API=3 etcdctl --command-timeout=10s --endpoints="http://${primary_etcd}:2379" \
                    member add "${etcd_name}" --learner --peer-urls="http://${node_ip}:2380" 2>&1) && {
                    retry_add_ok=true
                    break
                }
                sleep 2
            done
            if [[ "$retry_add_ok" != "true" ]]; then
                log_warn "Re-add learner failed on retry $etcd_retry — will try again"
                continue
            fi
            log "etcd member re-added as learner"

            # 4. Rebuild cluster_peers from member list
            local retry_member_list=""
            for ((rl=1; rl<=3; rl++)); do
                retry_member_list=$(ETCDCTL_API=3 etcdctl --command-timeout=10s --endpoints="http://${primary_etcd}:2379" \
                    member list --write-out=simple 2>/dev/null || echo "")
                [[ -n "$retry_member_list" ]] && break
                sleep 2
            done
            if [[ -n "$retry_member_list" ]]; then
                cluster_peers=""
                while IFS= read -r line; do
                    local m_name m_peer_url
                    m_name=$(echo "$line" | awk -F', ' '{print $3}')
                    m_peer_url=$(echo "$line" | awk -F', ' '{print $4}' | tr -d '[]')
                    if [[ -z "$m_name" ]] && [[ "$m_peer_url" == "http://${node_ip}:2380" ]]; then
                        m_name="$etcd_name"
                    fi
                    if [[ -n "$m_name" ]] && [[ -n "$m_peer_url" ]]; then
                        [[ -n "$cluster_peers" ]] && cluster_peers+=","
                        cluster_peers+="${m_name}=${m_peer_url}"
                    fi
                done <<< "$retry_member_list"
                log "Rebuilt cluster peers: $cluster_peers"
            fi

            # 5. Rewrite config with fresh cluster_peers
            sudo tee /etc/default/etcd > /dev/null << EOF
# Spiral Pool etcd configuration
# Generated by installer on $(date) (retry $etcd_retry)
# Part of Patroni HA PostgreSQL setup

ETCD_NAME="$etcd_name"
ETCD_DATA_DIR="/var/lib/etcd"
ETCD_LISTEN_CLIENT_URLS="http://${node_ip}:2379,http://127.0.0.1:2379"
ETCD_ADVERTISE_CLIENT_URLS="http://${node_ip}:2379"
ETCD_LISTEN_PEER_URLS="http://${node_ip}:2380"
ETCD_INITIAL_ADVERTISE_PEER_URLS="http://${node_ip}:2380"
ETCD_INITIAL_CLUSTER="$cluster_peers"
ETCD_INITIAL_CLUSTER_STATE="existing"
ETCD_INITIAL_CLUSTER_TOKEN="spiralpool-etcd-cluster"
EOF

            # 6. Restart etcd
            sudo systemctl restart etcd || { log_warn "etcd restart failed on retry"; continue; }

            # 6b. Wait for learner "started", then promote (same fix as initial path)
            local rlearner_started=false
            for ((rlw=1; rlw<=30; rlw++)); do
                if ETCDCTL_API=3 etcdctl --command-timeout=5s --endpoints="http://${primary_etcd}:2379" \
                    member list --write-out=simple 2>/dev/null | grep "http://${node_ip}:2380" | \
                    awk -F', ' '{print $2}' | tr -d ' ' | grep -qx "started"; then
                    rlearner_started=true
                    break
                fi
                [[ $rlw -eq 1 ]] && log "Waiting for etcd learner to connect to leader (retry $etcd_retry)..."
                sleep 1
            done

            if [[ "$rlearner_started" != "true" ]]; then
                log_warn "etcd learner did not reach 'started' state — attempting promotion anyway"
            fi

            # TOCTOU FIX: Single member list fetch, parse twice
            local rpromote_line rpromote_id rpromote_learner rpromote_ok=false
            rpromote_line=$(ETCDCTL_API=3 etcdctl --command-timeout=5s --endpoints="http://${primary_etcd}:2379" \
                member list --write-out=simple 2>/dev/null | grep "http://${node_ip}:2380" | head -1 || echo "")
            rpromote_id=$(echo "$rpromote_line" | awk -F', ' '{print $1}' | tr -d '[:space:]')
            rpromote_learner=$(echo "$rpromote_line" | awk -F', ' '{print $6}' | tr -d ' ')
            if [[ "${rpromote_learner:-}" == "true" ]] && [[ -n "${rpromote_id:-}" ]]; then
                for ((rpt=1; rpt<=6; rpt++)); do
                    if ETCDCTL_API=3 etcdctl --command-timeout=10s --endpoints="http://${primary_etcd}:2379" \
                        member promote "$rpromote_id" 2>&1; then
                        log_success "etcd learner promoted to voting member (retry $etcd_retry)"
                        rpromote_ok=true
                        break
                    fi
                    log "Learner not ready for promotion (attempt $rpt/6) — waiting..."
                    sleep 5
                done
                if [[ "$rpromote_ok" != "true" ]]; then
                    log_warn "Learner promotion did not succeed on retry"
                fi
            fi

            # 7. Wait for health (30s)
            local retry_health=30
            while [[ $retry_health -gt 0 ]]; do
                if ETCDCTL_API=3 etcdctl --command-timeout=5s endpoint health 2>&1 | grep -q "is healthy"; then
                    log_success "etcd is healthy after retry $etcd_retry"

                    # Promote learner to voting member
                    # TOCTOU FIX: Single member list fetch, parse twice
                    local retry_member_line retry_member_id retry_is_learner
                    retry_member_line=$(ETCDCTL_API=3 etcdctl --command-timeout=5s --endpoints="http://${primary_etcd}:2379" \
                        member list --write-out=simple 2>/dev/null | grep "http://${node_ip}:2380" | head -1 || echo "")
                    retry_member_id=$(echo "$retry_member_line" | awk -F', ' '{print $1}' | tr -d '[:space:]')
                    retry_is_learner=$(echo "$retry_member_line" | awk -F', ' '{print $6}' | tr -d ' ')
                    if [[ "${retry_is_learner:-}" == "true" ]] && [[ -n "${retry_member_id:-}" ]]; then
                        log "Promoting etcd learner to voting member..."
                        if ETCDCTL_API=3 etcdctl --command-timeout=10s --endpoints="http://${primary_etcd}:2379" \
                            member promote "$retry_member_id" 2>&1; then
                            log_success "etcd promoted — this node is now a voting member"
                        else
                            log_warn "etcd learner promotion failed — will retry on next Patroni restart"
                        fi
                    fi

                    etcd_retry_ok=true
                    break 2  # Break out of both the health loop and the retry loop
                fi
                sleep 1
                retry_health=$((retry_health - 1))
            done
        done

        if [[ "$etcd_retry_ok" != "true" ]]; then
            # All retries exhausted — clean up and warn
            if [[ -n "${primary_etcd:-}" ]]; then
                local final_stale_id
                final_stale_id=$(ETCDCTL_API=3 etcdctl --command-timeout=5s --endpoints="http://${primary_etcd}:2379" \
                    member list --write-out=simple 2>/dev/null | grep "http://${node_ip}:2380" | awk -F', ' '{print $1}' || echo "")
                if [[ -n "$final_stale_id" ]]; then
                    ETCDCTL_API=3 etcdctl --command-timeout=10s --endpoints="http://${primary_etcd}:2379" \
                        member remove "$final_stale_id" 2>/dev/null || true
                    log "Cleaned up stale member from primary"
                fi
            fi
            log_warn "etcd backup did not become healthy after $etcd_retry_max retries"
            log_warn "Primary etcd is unaffected (learner mode was used)"
            log_warn "Patroni will show 'unknown' role until etcd is fixed. Investigate with:"
            log_warn "  journalctl -u etcd -n 50"
            log_warn "  ETCDCTL_API=3 etcdctl endpoint health"
            log_warn "After fixing, restart Patroni: sudo systemctl restart patroni"
        fi
    fi
}

# Install Patroni for PostgreSQL HA
install_patroni() {
    log "Installing Patroni for automatic PostgreSQL failover..."

    # Install Patroni in a virtual environment (PEP 668 compliant for Ubuntu 24.04)
    local patroni_venv="/opt/patroni/venv"
    sudo mkdir -p /opt/patroni
    sudo python3 -m venv "$patroni_venv"
    sudo "$patroni_venv/bin/pip" install --upgrade pip -q 2>/dev/null
    sudo "$patroni_venv/bin/pip" install --quiet patroni[etcd] python-etcd psycopg2-binary

    # Symlink patroni and patronictl into /usr/local/bin for convenience
    sudo ln -sf "$patroni_venv/bin/patroni" /usr/local/bin/patroni
    sudo ln -sf "$patroni_venv/bin/patronictl" /usr/local/bin/patronictl

    # Create Patroni directories
    sudo mkdir -p /etc/patroni
    sudo mkdir -p /var/log/patroni
    sudo chown -R postgres:postgres /etc/patroni /var/log/patroni

    log_success "Patroni installed"
}

# Configure Patroni for this node
configure_patroni() {
    log "Configuring Patroni..."

    local node_ip="$SERVER_IP"
    local patroni_name="${PATRONI_NODE_NAME:-patroni-$(hostname -s)}"
    local pg_data_dir="/var/lib/postgresql/$POSTGRES_VERSION/main"
    local pg_bin_dir="/usr/lib/postgresql/$POSTGRES_VERSION/bin"
    local pg_conf_dir="/etc/postgresql/$POSTGRES_VERSION/main"

    # Validate PostgreSQL version directory exists
    if [[ ! -d "$pg_bin_dir" ]]; then
        log_error "PostgreSQL version ${POSTGRES_VERSION} not found at ${pg_bin_dir}"
        return 1
    fi

    # Escape passwords for YAML (double-quote escaping)
    # NOTE: generate_password() produces alphanumeric-only [A-Za-z0-9] output,
    # so YAML metacharacters (:, #, |, >, {, }) and SQL injection chars (', \)
    # cannot appear. This escaping is defense-in-depth for manual password overrides.
    local escaped_superuser_password
    local escaped_repl_password
    local escaped_app_password
    escaped_superuser_password=$(echo "$POSTGRES_SUPERUSER_PASSWORD" | sed 's/"/\\"/g')
    escaped_repl_password=$(echo "$DB_REPLICATION_PASSWORD" | sed 's/"/\\"/g')
    escaped_app_password=$(echo "$DB_PASSWORD" | sed 's/"/\\"/g')

    # Determine etcd hosts (all peers + self)
    local etcd_hosts="${ETCD_HOSTS_CONFIG:-${node_ip}:2379}"
    for peer_ip in "${HA_PEER_IPS[@]}"; do
        if [[ ! "$etcd_hosts" =~ "${peer_ip}:2379" ]]; then
            etcd_hosts+=",${peer_ip}:2379"
        fi
    done

    # Calculate shared_buffers (same as PostgreSQL config)
    local total_ram_mb=$(free -m | awk '/^Mem:/ {print $2}')
    local shared_buffers_mb=$((total_ram_mb / 4))
    [[ $shared_buffers_mb -lt 256 ]] && shared_buffers_mb=256
    [[ $shared_buffers_mb -gt 4096 ]] && shared_buffers_mb=4096

    # Build pg_hba entries for all peers (must be done before heredoc)
    local pg_hba_entries=""
    pg_hba_entries+="    - local all all peer"$'\n'
    pg_hba_entries+="    - host replication ${DB_REPLICATION_USER} ${node_ip}/32 scram-sha-256"$'\n'
    pg_hba_entries+="    - host all all ${node_ip}/32 scram-sha-256"$'\n'
    for peer_ip in "${HA_PEER_IPS[@]}"; do
        pg_hba_entries+="    - host replication ${DB_REPLICATION_USER} ${peer_ip}/32 scram-sha-256"$'\n'
        pg_hba_entries+="    - host all all ${peer_ip}/32 scram-sha-256"$'\n'
    done
    pg_hba_entries+="    - host replication ${DB_REPLICATION_USER} 127.0.0.1/32 scram-sha-256"$'\n'
    pg_hba_entries+="    - host all all 127.0.0.1/32 scram-sha-256"

    # Runtime pg_hba entries (applied when Patroni manages existing clusters, not just bootstrap)
    # Same as bootstrap entries — local peer auth + all network entries
    local pg_hba_runtime_entries="${pg_hba_entries}"

    # Generate Patroni configuration
    sudo tee /etc/patroni/patroni.yml > /dev/null << EOF
# ╔════════════════════════════════════════════════════════════════════════════╗
# ║  SPIRAL POOL - PATRONI CONFIGURATION                                       ║
# ║  Automatic PostgreSQL failover for mining pool high availability           ║
# ║                                                                            ║
# ║  IMPORTANT: The pool's pg_is_in_recovery() check remains authoritative.    ║
# ║  Patroni handles promotion; the pool handles write routing.                ║
# ║                                                                            ║
# ║  Generated by installer on $(date)
# ╚════════════════════════════════════════════════════════════════════════════╝

scope: spiralpool-postgres
namespace: /spiralpool/
name: ${patroni_name}

restapi:
  # NOTE: Patroni REST API is HTTP-only (no TLS). Access is restricted to the
  # HA peer network via firewall rules configured during install.
  # Listen on 0.0.0.0 so local health checks (localhost:8008) work alongside
  # remote peer health checks. connect_address advertises the real IP to peers.
  listen: 0.0.0.0:8008
  connect_address: ${node_ip}:8008

etcd3:
  hosts: ${etcd_hosts}

bootstrap:
  dcs:
    ttl: 30
    loop_wait: 10
    retry_timeout: 10
    maximum_lag_on_failover: 1048576  # 1MB - tight for mining pool consistency
    failsafe_mode: true               # Keep primary running if DCS (etcd) goes down
    synchronous_mode: true            # CRITICAL: Designed to minimize data loss on failover
    synchronous_mode_strict: false    # Allow async if no sync replica available
    postgresql:
      use_pg_rewind: true
      use_slots: true
      remove_data_directory_on_diverged_timelines: true  # Auto-wipe replica if timeline diverges from primary
      parameters:
        # Connection settings
        max_connections: 200
        # WAL settings for synchronous replication
        wal_level: replica
        hot_standby: 'on'
        max_wal_senders: 10
        max_replication_slots: 10
        wal_keep_size: '1GB'
        # Synchronous commit for data safety
        synchronous_commit: 'on'
        # Memory settings
        shared_buffers: '${shared_buffers_mb}MB'
        effective_cache_size: '$((shared_buffers_mb * 3))MB'
        # Logging
        log_destination: 'stderr'
        logging_collector: 'off'
        log_statement: 'ddl'
        log_min_duration_statement: 1000

  initdb:
    - encoding: UTF8
    - data-checksums

  pg_hba:
${pg_hba_entries}

  # Post-initialization SQL for Spiral Pool database
  post_init: /etc/patroni/post_init.sh

postgresql:
  listen: 0.0.0.0:5432
  connect_address: ${node_ip}:5432
  data_dir: ${pg_data_dir}
  bin_dir: ${pg_bin_dir}
  config_dir: ${pg_conf_dir}

  authentication:
    replication:
      username: ${DB_REPLICATION_USER}
      password: "${escaped_repl_password}"
    superuser:
      username: postgres
      password: "${escaped_superuser_password}"

  parameters:
    unix_socket_directories: '/var/run/postgresql'

  pg_hba:
${pg_hba_runtime_entries}

tags:
  nofailover: false
  noloadbalance: false
  clonefrom: false
  nosync: false
EOF

    # Create post-init script for database setup
    sudo tee /etc/patroni/post_init.sh > /dev/null << 'POSTINIT'
#!/bin/bash
# Spiral Pool Patroni post-initialization script
# Creates the spiralstratum database and user

set -e

# Wait for PostgreSQL to be ready
sleep 5

# Create application user and database
# NOTE: ${DB_USER} and ${DB_NAME} are pre-validated by validate_sql_identifier()
# (alphanumeric + underscore only). Double-quoting identifiers is defense-in-depth.
psql -U postgres << EOF
DO \$\$
BEGIN
    IF NOT EXISTS (SELECT FROM pg_roles WHERE rolname = '${DB_USER}') THEN
        CREATE ROLE "${DB_USER}" WITH LOGIN PASSWORD '${DB_PASSWORD}' CREATEDB;
    END IF;
END
\$\$;

SELECT 'CREATE DATABASE "${DB_NAME}" OWNER "${DB_USER}"'
WHERE NOT EXISTS (SELECT FROM pg_database WHERE datname = '${DB_NAME}')\gexec

GRANT ALL PRIVILEGES ON DATABASE "${DB_NAME}" TO "${DB_USER}";
EOF
POSTINIT

    # Replace variables in post_init.sh
    # Escape single quotes for SQL safety (prevents injection if password contains ')
    local safe_password="${DB_PASSWORD//\'/\'\'}"
    # Escape sed metacharacters (\ & |) so passwords with special chars don't break sed.
    # We use | as the sed delimiter (instead of /) because passwords and paths commonly
    # contain forward slashes. The | character is escaped in sed_safe_password above,
    # so passwords containing | are handled correctly.
    local sed_safe_password
    sed_safe_password=$(printf '%s' "$safe_password" | sed 's/[\\&|]/\\&/g')
    sudo sed -i "s|\${DB_USER}|$DB_USER|g" /etc/patroni/post_init.sh
    sudo sed -i "s|\${DB_NAME}|$DB_NAME|g" /etc/patroni/post_init.sh
    sudo sed -i "s|\${DB_PASSWORD}|${sed_safe_password}|g" /etc/patroni/post_init.sh

    sudo chmod 700 /etc/patroni/post_init.sh
    sudo chown postgres:postgres /etc/patroni/post_init.sh

    # Secure the configuration file
    sudo chmod 600 /etc/patroni/patroni.yml
    sudo chown postgres:postgres /etc/patroni/patroni.yml

    log_success "Patroni configured"
}

# Create Patroni systemd service
create_patroni_service() {
    log "Creating Patroni systemd service..."

    sudo tee /etc/systemd/system/patroni.service > /dev/null << 'EOF'
[Unit]
Description=Patroni PostgreSQL HA Manager for Spiral Pool
Documentation=https://patroni.readthedocs.io
After=network.target etcd.service
Requires=etcd.service

[Service]
Type=simple
User=postgres
Group=postgres
ExecStart=/opt/patroni/venv/bin/patroni /etc/patroni/patroni.yml
ExecReload=/bin/kill -HUP $MAINPID
KillMode=process
TimeoutSec=30
Restart=always
RestartSec=5

# Logging
StandardOutput=journal
StandardError=journal
SyslogIdentifier=patroni

# Security hardening
NoNewPrivileges=false
PrivateTmp=true
ProtectSystem=full
ProtectHome=true
# Patroni needs write access to PostgreSQL config dir (ProtectSystem=full makes /etc/ read-only)
ReadWritePaths=/etc/postgresql

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    log_success "Patroni service created"
}

# Migrate existing PostgreSQL to Patroni management
migrate_to_patroni() {
    log "Migrating PostgreSQL to Patroni management..."

    # ══════════════════════════════════════════════════════════════════════════
    # CRITICAL: Prepare PostgreSQL for Patroni BEFORE stopping it.
    # Patroni connects as 'postgres' via TCP (not unix socket), so the
    # superuser MUST have a password set and pg_hba.conf must allow
    # scram-sha-256 auth from 127.0.0.1. Without this, Patroni fails with:
    #   FATAL: password authentication failed for user "postgres"
    # ══════════════════════════════════════════════════════════════════════════
    if [[ "$HA_MODE" == "ha-master" ]] && sudo systemctl is-active --quiet postgresql 2>/dev/null; then
        log "Preparing PostgreSQL for Patroni takeover..."

        # Set postgres superuser password (Patroni needs password auth, not peer)
        local escaped_su_pw
        escaped_su_pw=$(printf '%s' "$POSTGRES_SUPERUSER_PASSWORD" | sed "s/'/''/g")
        if sudo -u postgres psql -q -c "ALTER USER postgres WITH PASSWORD '${escaped_su_pw}';" 2>/dev/null; then
            log_success "PostgreSQL superuser password set"
        else
            log_error "Failed to set PostgreSQL superuser password"
            return 1
        fi

        # Create replication user (needed for HA replicas)
        local escaped_repl_pw
        escaped_repl_pw=$(printf '%s' "$DB_REPLICATION_PASSWORD" | sed "s/'/''/g")
        sudo -u postgres psql -q -c "DO \$\$
        BEGIN
            IF NOT EXISTS (SELECT FROM pg_roles WHERE rolname = '${DB_REPLICATION_USER}') THEN
                CREATE ROLE ${DB_REPLICATION_USER} WITH REPLICATION LOGIN ENCRYPTED PASSWORD '${escaped_repl_pw}';
            ELSE
                ALTER ROLE ${DB_REPLICATION_USER} WITH ENCRYPTED PASSWORD '${escaped_repl_pw}';
            END IF;
        END
        \$\$;" 2>/dev/null || log_warn "Could not create replication user (Patroni will handle)"

        # Ensure pg_hba.conf allows TCP connections from localhost
        local pg_hba="/etc/postgresql/$POSTGRES_VERSION/main/pg_hba.conf"
        if [[ -f "$pg_hba" ]] && ! sudo grep -q "host.*all.*all.*127.0.0.1/32.*scram-sha-256" "$pg_hba" 2>/dev/null; then
            log "Adding localhost TCP auth entry to pg_hba.conf..."
            echo "host all all 127.0.0.1/32 scram-sha-256" | sudo tee -a "$pg_hba" > /dev/null
        fi

        # Reload to pick up any pg_hba changes
        sudo systemctl reload postgresql 2>/dev/null || true
        log_success "PostgreSQL prepared for Patroni takeover"
    fi

    # Stop standalone PostgreSQL service (Patroni will manage it)
    log "Stopping standalone PostgreSQL service..."
    sudo systemctl stop postgresql || true
    sudo systemctl disable postgresql || true

    # Backup existing data directory marker
    local pg_data_dir="/var/lib/postgresql/$POSTGRES_VERSION/main"
    if [[ -d "$pg_data_dir" ]] && [[ "$HA_MODE" == "ha-master" ]]; then
        # For master, let Patroni take over existing data
        log "Preserving existing PostgreSQL data for Patroni takeover..."
    elif [[ "$HA_MODE" == "ha-backup" ]]; then
        # For backup, Patroni will bootstrap from primary
        if [[ -d "$pg_data_dir" ]]; then
            log "Backing up existing data directory (Patroni will bootstrap from primary)..."
            sudo mv "$pg_data_dir" "${pg_data_dir}.backup.$(date +%Y%m%d%H%M%S)" || true
        fi
    fi

    # Start Patroni
    log "Starting Patroni..."
    sudo systemctl enable patroni || true
    sudo systemctl start patroni || { log_error "Failed to start Patroni"; return 1; }

    # Wait for Patroni to initialize
    local retries=60
    log "Waiting for Patroni to become healthy..."
    while [[ $retries -gt 0 ]]; do
        if curl -sf --connect-timeout 3 --max-time 5 http://localhost:8008/health &>/dev/null; then
            log_success "Patroni is healthy"

            # Wait for role to resolve (may take a few seconds after health endpoint responds)
            local role="unknown"
            local role_retries=15
            while [[ "$role" == "unknown" ]] && [[ $role_retries -gt 0 ]]; do
                role=$(curl -sf --connect-timeout 3 --max-time 5 http://localhost:8008/ 2>/dev/null | grep -oP '"role"\s*:\s*"\K[^"]+' || echo "unknown")
                if [[ "$role" != "unknown" ]]; then
                    break
                fi
                sleep 2
                role_retries=$((role_retries - 1))
            done

            if [[ "$role" == "unknown" ]]; then
                log_warn "This node is: unknown (Patroni cannot determine role — check etcd connectivity)"
                if [[ "$HA_MODE" == "ha-backup" ]]; then
                    log_warn "Expected role 'replica' on backup node. Patroni may not be able to reach etcd."
                    log_warn "Check: patronictl list, etcdctl member list, journalctl -u patroni -n 50"
                fi
                # Signal to caller that Patroni is running but role not resolved
                PATRONI_ROLE_UNKNOWN=true
            else
                log_success "This node is: $role"
            fi
            return 0
        fi
        sleep 2
        retries=$((retries - 1))
        if [[ $((retries % 10)) -eq 0 ]]; then
            log "Still waiting for Patroni... ($retries retries left)"
        fi
    done

    log_error "Patroni failed to become healthy within timeout"
    log "Check logs: journalctl -u patroni -n 50"
    return 1
}

# Main Patroni setup function
setup_patroni() {
    if [[ "$PATRONI_ENABLED" != "true" ]]; then
        log "Patroni disabled, using manual PostgreSQL failover"
        return 0
    fi

    log_step "Setting up Patroni (Automatic PostgreSQL Failover)"

    # Validate SERVER_IP is set before proceeding (it's needed by configure_etcd)
    if [[ -z "$SERVER_IP" ]] || [[ "$SERVER_IP" == "YOUR_SERVER_IP" ]]; then
        log_error "SERVER_IP is not set — cannot configure etcd cluster"
        return 1
    fi

    # Validate SQL identifiers (same check as configure_postgresql_ha)
    if ! validate_sql_identifier "$DB_USER"; then
        log_error "Invalid database username: $DB_USER"
        return 1
    fi
    if ! validate_sql_identifier "$DB_NAME"; then
        log_error "Invalid database name: $DB_NAME"
        return 1
    fi
    if ! validate_sql_identifier "$DB_REPLICATION_USER"; then
        log_error "Invalid replication username: $DB_REPLICATION_USER"
        return 1
    fi

    install_etcd || { log_error "install_etcd failed"; return 1; }
    configure_etcd || { log_error "configure_etcd failed"; return 1; }
    install_patroni || { log_error "install_patroni failed"; return 1; }
    configure_patroni || { log_error "configure_patroni failed"; return 1; }
    create_patroni_service || { log_error "create_patroni_service failed"; return 1; }
    migrate_to_patroni || { log_error "migrate_to_patroni failed"; return 1; }

    if [[ "${PATRONI_ROLE_UNKNOWN:-false}" == "true" ]]; then
        log_warn "Patroni setup complete - role not yet resolved (will retry when etcd cluster is healthy)"
    else
        log_success "Patroni setup complete - PostgreSQL now has automatic failover"
    fi

    # Create sudoers for HA operations on ALL HA nodes (master AND backup).
    # Both roles need these rules because:
    #   - Backup nodes SSH to master to run ha-add-peer.sh during install
    #   - Master nodes SSH to backups for the same reason during peer updates
    #   - Either node may need replication access after a failover/role swap
    local ha_sudoers="/etc/sudoers.d/spiralpool-ha-postgres"
    if [[ ! -f "$ha_sudoers" ]] || ! grep -q "ha-add-peer" "$ha_sudoers" 2>/dev/null; then
        log "Creating sudoers rules for HA operations..."
        sudo tee "$ha_sudoers" > /dev/null << SUDOERS_EOF
# Allow ${POOL_USER} to run rsync as postgres (for HA PostgreSQL replication)
${POOL_USER} ALL=(postgres) NOPASSWD: /usr/bin/rsync, /usr/bin/true, /usr/bin/ls
# Allow ${POOL_USER} to stop/start PostgreSQL and Patroni (for cold-copy replication)
${POOL_USER} ALL=(root) NOPASSWD: /usr/bin/systemctl stop postgresql@*, /usr/bin/systemctl start postgresql@*, /usr/bin/systemctl is-active postgresql@*, /usr/bin/systemctl stop patroni, /usr/bin/systemctl start patroni
# Allow ${POOL_USER} to run ha-add-peer.sh (called remotely during HA peer setup)
${POOL_USER} ALL=(root) NOPASSWD: ${INSTALL_DIR}/scripts/ha-add-peer.sh
SUDOERS_EOF
        sudo chmod 440 "$ha_sudoers"
        log_success "HA sudoers created"
    fi
}

# Append merge mining configuration to a V2 config.yaml
# Inserts mergeMining: block inside the parent coin's section
# Usage: append_merge_mining_to_config <config_file>
append_merge_mining_to_config() {
    local config_file="$1"

    if [[ "$MERGE_MINING_ENABLED" != "true" ]]; then
        return 0
    fi

    log "Adding merge mining configuration to config.yaml..."

    # Determine which parent coins have merge mining
    local parents=""
    case "$MERGE_MINING_PARENT" in
        BTC)     parents="BTC" ;;
        LTC)     parents="LTC" ;;
        BTC,LTC) parents="BTC LTC" ;;
        *)       log_warn "Unknown merge mining parent: $MERGE_MINING_PARENT"; return 0 ;;
    esac

    for parent in $parents; do
        local aux_chains=""
        local aux_yaml=""

        if [[ "$parent" == "BTC" ]]; then
            # Determine which aux chains for SHA-256d
            if [[ "$MERGE_MINING_PARENT" == "BTC,LTC" ]]; then
                aux_chains="$MERGE_MINING_AUX_CHAINS_SHA256D"
            else
                aux_chains="$MERGE_MINING_AUX_CHAINS"
            fi

            # Build aux chain YAML entries
            if [[ "$aux_chains" == *"NMC"* ]]; then
                local nmc_pass="$NMC_RPC_PASSWORD"
                local nmc_conf="$(get_blockchain_dir nmc)/namecoin.conf"
                if [[ -f "$nmc_conf" ]]; then
                    local conf_pass
                    conf_pass=$(grep -E "^rpcpassword=" "$nmc_conf" 2>/dev/null | head -1 | cut -d= -f2)
                    [[ -n "$conf_pass" ]] && nmc_pass="$conf_pass"
                fi
                aux_yaml="$aux_yaml
        - symbol: \"NMC\"
          enabled: true
          address: \"$NMC_POOL_ADDRESS\"
          daemon:
            host: \"127.0.0.1\"
            port: 8336
            user: \"$NMC_RPC_USER\"
            password: \"$nmc_pass\""
            fi

            if [[ "$aux_chains" == *"SYS"* ]]; then
                local sys_pass="$SYS_RPC_PASSWORD"
                local sys_conf="$(get_blockchain_dir sys)/syscoin.conf"
                if [[ -f "$sys_conf" ]]; then
                    local conf_pass
                    conf_pass=$(grep -E "^rpcpassword=" "$sys_conf" 2>/dev/null | head -1 | cut -d= -f2)
                    [[ -n "$conf_pass" ]] && sys_pass="$conf_pass"
                fi
                aux_yaml="$aux_yaml
        - symbol: \"SYS\"
          enabled: true
          address: \"$SYS_POOL_ADDRESS\"
          daemon:
            host: \"127.0.0.1\"
            port: 8370
            user: \"$SYS_RPC_USER\"
            password: \"$sys_pass\""
            fi

            if [[ "$aux_chains" == *"XMY"* ]]; then
                local xmy_pass="$XMY_RPC_PASSWORD"
                local xmy_conf="$(get_blockchain_dir xmy)/myriadcoin.conf"
                if [[ -f "$xmy_conf" ]]; then
                    local conf_pass
                    conf_pass=$(grep -E "^rpcpassword=" "$xmy_conf" 2>/dev/null | head -1 | cut -d= -f2)
                    [[ -n "$conf_pass" ]] && xmy_pass="$conf_pass"
                fi
                aux_yaml="$aux_yaml
        - symbol: \"XMY\"
          enabled: true
          address: \"$XMY_POOL_ADDRESS\"
          daemon:
            host: \"127.0.0.1\"
            port: 10889
            user: \"$XMY_RPC_USER\"
            password: \"$xmy_pass\""
            fi

            if [[ "$aux_chains" == *"FBTC"* ]]; then
                local fbtc_pass="$FBTC_RPC_PASSWORD"
                local fbtc_conf="$(get_blockchain_dir fbtc)/fractal.conf"
                if [[ -f "$fbtc_conf" ]]; then
                    local conf_pass
                    conf_pass=$(grep -E "^rpcpassword=" "$fbtc_conf" 2>/dev/null | head -1 | cut -d= -f2)
                    [[ -n "$conf_pass" ]] && fbtc_pass="$conf_pass"
                fi
                aux_yaml="$aux_yaml
        - symbol: \"FBTC\"
          enabled: true
          address: \"$FBTC_POOL_ADDRESS\"
          daemon:
            host: \"127.0.0.1\"
            port: 8340
            user: \"$FBTC_RPC_USER\"
            password: \"$fbtc_pass\""
            fi

        elif [[ "$parent" == "LTC" ]]; then
            # Determine which aux chains for Scrypt
            if [[ "$MERGE_MINING_PARENT" == "BTC,LTC" ]]; then
                aux_chains="$MERGE_MINING_AUX_CHAINS_SCRYPT"
            else
                aux_chains="$MERGE_MINING_AUX_CHAINS"
            fi

            if [[ "$aux_chains" == *"DOGE"* ]]; then
                local doge_pass="$DOGE_RPC_PASSWORD"
                local doge_conf="$(get_blockchain_dir doge)/dogecoin.conf"
                if [[ -f "$doge_conf" ]]; then
                    local conf_pass
                    conf_pass=$(grep -E "^rpcpassword=" "$doge_conf" 2>/dev/null | head -1 | cut -d= -f2)
                    [[ -n "$conf_pass" ]] && doge_pass="$conf_pass"
                fi
                aux_yaml="$aux_yaml
        - symbol: \"DOGE\"
          enabled: true
          address: \"$DOGE_POOL_ADDRESS\"
          daemon:
            host: \"127.0.0.1\"
            port: 22555
            user: \"$DOGE_RPC_USER\"
            password: \"$doge_pass\""
            fi

            if [[ "$aux_chains" == *"PEP"* ]]; then
                local pep_pass="$PEP_RPC_PASSWORD"
                local pep_conf="$(get_blockchain_dir pep)/pepecoin.conf"
                if [[ -f "$pep_conf" ]]; then
                    local conf_pass
                    conf_pass=$(grep -E "^rpcpassword=" "$pep_conf" 2>/dev/null | head -1 | cut -d= -f2)
                    [[ -n "$conf_pass" ]] && pep_pass="$conf_pass"
                fi
                aux_yaml="$aux_yaml
        - symbol: \"PEP\"
          enabled: true
          address: \"$PEP_POOL_ADDRESS\"
          daemon:
            host: \"127.0.0.1\"
            port: 33873
            user: \"$PEP_RPC_USER\"
            password: \"$pep_pass\""
            fi
        fi

        # Skip if no aux chains selected
        if [[ -z "$aux_yaml" ]]; then
            log_warn "No aux chains configured for $parent merge mining"
            continue
        fi

        # Build the complete mergeMining YAML block (4-space indent = inside coin section)
        local mm_block="    mergeMining:
      enabled: true
      refreshInterval: 5s
      auxChains:${aux_yaml}"

        # Insert the mergeMining block into the parent coin's section
        # Strategy: find 'symbol: "BTC"' (or LTC), then find the next coin boundary
        # (comment or '  - symbol:' at 2-space indent) and insert before it.
        # If no next coin, append before the next root-level key or EOF.
        local temp_file
        temp_file=$(mktemp) || { log_error "Failed to create temp file"; return 1; }

        # Use awk to insert the block inside the parent coin section
        # Uses index() instead of regex for parent matching (safe for special chars)
        awk -v parent="$parent" -v mm_block="$mm_block" '
        BEGIN { found_parent = 0; inserted = 0 }
        {
            # Detect parent coin start (index() avoids regex special char issues)
            if (index($0, "symbol: \"" parent "\"") > 0) {
                found_parent = 1
            }
            # After finding parent, look for the next coin boundary or end of section
            # Skip the parent coin line itself
            if (found_parent && !inserted && index($0, "symbol: \"" parent "\"") == 0) {
                # Next coin comment at coins-array level (2-space indent comment)
                # Insert BEFORE the comment so mergeMining stays inside parent section
                if ($0 ~ /^  #/) {
                    print mm_block
                    inserted = 1
                }
                # Next coin entry (new sequence item at coins level)
                if (!inserted && $0 ~ /^  - symbol:/) {
                    print mm_block
                    inserted = 1
                }
                # End of coins section (root-level key or comment at column 0)
                if (!inserted && $0 ~ /^[a-zA-Z#]/ && $0 !~ /^  / && NR > 1) {
                    print mm_block
                    inserted = 1
                }
            }
            print
        }
        END {
            # If parent was found but no insertion point (last coin), append before EOF
            if (found_parent && !inserted) {
                print mm_block
            }
        }
        ' <(sudo cat "$config_file") > "$temp_file"

        # Replace original with modified file (preserve ownership/perms)
        if [[ -s "$temp_file" ]]; then
            sudo cp "$temp_file" "$config_file"
            log_success "Added merge mining config for $parent"
        else
            log_error "Failed to insert merge mining config (empty result)"
        fi
        rm -f "$temp_file"
    done
}

# Append merge mining configuration to a V1 (single-coin) config.yaml
# Appends mergeMining: block at root level (correct for V1 format)
# Usage: append_merge_mining_v1_to_config <config_file>
append_merge_mining_v1_to_config() {
    local config_file="$1"

    if [[ "$MERGE_MINING_ENABLED" != "true" ]]; then
        return 0
    fi

    log "Adding merge mining configuration to V1 config.yaml..."

    local aux_chains="$MERGE_MINING_AUX_CHAINS"
    local aux_yaml=""

    # Determine parent type from SOLO_COIN
    local parent_algo=""
    case "$SOLO_COIN" in
        BTC) parent_algo="sha256d" ;;
        LTC) parent_algo="scrypt" ;;
        *)   log_warn "Single-coin $SOLO_COIN does not support merge mining"; return 0 ;;
    esac

    if [[ "$parent_algo" == "sha256d" ]]; then
        if [[ "$aux_chains" == *"NMC"* ]]; then
            aux_yaml="$aux_yaml
    - symbol: \"NMC\"
      enabled: true
      address: \"$NMC_POOL_ADDRESS\"
      daemon:
        host: \"127.0.0.1\"
        port: 8336
        user: \"$NMC_RPC_USER\"
        password: \"$NMC_RPC_PASSWORD\""
        fi
        if [[ "$aux_chains" == *"SYS"* ]]; then
            aux_yaml="$aux_yaml
    - symbol: \"SYS\"
      enabled: true
      address: \"$SYS_POOL_ADDRESS\"
      daemon:
        host: \"127.0.0.1\"
        port: 8370
        user: \"$SYS_RPC_USER\"
        password: \"$SYS_RPC_PASSWORD\""
        fi
        if [[ "$aux_chains" == *"XMY"* ]]; then
            aux_yaml="$aux_yaml
    - symbol: \"XMY\"
      enabled: true
      address: \"$XMY_POOL_ADDRESS\"
      daemon:
        host: \"127.0.0.1\"
        port: 10889
        user: \"$XMY_RPC_USER\"
        password: \"$XMY_RPC_PASSWORD\""
        fi
        if [[ "$aux_chains" == *"FBTC"* ]]; then
            aux_yaml="$aux_yaml
    - symbol: \"FBTC\"
      enabled: true
      address: \"$FBTC_POOL_ADDRESS\"
      daemon:
        host: \"127.0.0.1\"
        port: 8340
        user: \"$FBTC_RPC_USER\"
        password: \"$FBTC_RPC_PASSWORD\""
        fi
    elif [[ "$parent_algo" == "scrypt" ]]; then
        if [[ "$aux_chains" == *"DOGE"* ]]; then
            aux_yaml="$aux_yaml
    - symbol: \"DOGE\"
      enabled: true
      address: \"$DOGE_POOL_ADDRESS\"
      daemon:
        host: \"127.0.0.1\"
        port: 22555
        user: \"$DOGE_RPC_USER\"
        password: \"$DOGE_RPC_PASSWORD\""
        fi
        if [[ "$aux_chains" == *"PEP"* ]]; then
            aux_yaml="$aux_yaml
    - symbol: \"PEP\"
      enabled: true
      address: \"$PEP_POOL_ADDRESS\"
      daemon:
        host: \"127.0.0.1\"
        port: 33873
        user: \"$PEP_RPC_USER\"
        password: \"$PEP_RPC_PASSWORD\""
        fi
    fi

    if [[ -z "$aux_yaml" ]]; then
        log_warn "No aux chains configured for merge mining"
        return 0
    fi

    sudo -u "$POOL_USER" tee -a "$config_file" > /dev/null << EOF

# Merge Mining (AuxPoW) Configuration
mergeMining:
  enabled: true
  refreshInterval: 5s
  auxChains:${aux_yaml}
EOF

    log_success "Added merge mining configuration (V1 root-level)"
}

# Append HA configuration to config.yaml
append_ha_config_to_yaml() {
    local config_file="$1"

    log "Adding HA configuration to config.yaml..."

    # Determine node role string
    local node_role="primary"
    if [[ "$HA_MODE" == "ha-backup" ]]; then
        node_role="backup"
    fi

    # Get local IP for this node
    local local_ip
    local_ip=$(ip -4 addr show "$VIP_INTERFACE" 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.\d+){3}' | head -1)
    if [[ -z "$local_ip" ]]; then
        local_ip="$SERVER_IP"
    fi

    # Determine primary host for HA config
    # primaryHost should point to THIS node on the primary, or to the peer on the backup
    local peer_host=""
    if [[ "$node_role" == "primary" ]]; then
        peer_host="$local_ip"    # Primary node: I am the primary host
    else
        peer_host="${HA_PRIMARY_IP:-$HA_PEER_IP}"  # Backup node: peer is the primary host
    fi

    sudo -u "$POOL_USER" tee -a "$config_file" > /dev/null << EOF

# ═══════════════════════════════════════════════════════════════════════════════
# HIGH AVAILABILITY CONFIGURATION
# ═══════════════════════════════════════════════════════════════════════════════

# VIP (Virtual IP) Configuration - for transparent miner failover
vip:
  enabled: true
  address: "$VIP_ADDRESS"
  interface: "$VIP_INTERFACE"
  netmask: $VIP_NETMASK
  priority: $HA_NODE_PRIORITY       # Lower = higher priority for master election (primary=100)
  autoPriority: false               # Priority set explicitly
  clusterToken: "$HA_CLUSTER_TOKEN"
  canBecomeMaster: true
  discoveryPort: 5363               # UDP cluster discovery
  statusPort: 5354                  # HTTP status API
  heartbeatInterval: 30s
  failoverTimeout: 90s

# HA Coordination - database replication and failover settings
ha:
  enabled: true
  primaryHost: "${peer_host:-127.0.0.1}"
  replicaHost: ""                   # Auto-detected from cluster
  checkInterval: 5s
  failoverTimeout: 30s
EOF

    # Create environment file for replication password
    sudo tee /etc/spiralpool/ha.env > /dev/null << EOF
# Spiral Pool HA Environment Variables
# Generated by installer on $(date)

# PostgreSQL Replication Password (SCRAM-SHA-256)
SPIRAL_REPLICATION_PASSWORD="${DB_REPLICATION_PASSWORD}"

# Master encryption key for credential storage
# SPIRAL_MASTER_KEY=  # Set this for production (auto-generated if not set)
EOF
    sudo chmod 600 /etc/spiralpool/ha.env
    sudo chown "$POOL_USER:$POOL_USER" /etc/spiralpool/ha.env

    log_success "HA configuration added to config.yaml"
}

# NOTE: SSH infrastructure for HA has been removed.
# HA cluster communication uses encrypted UDP (AES-256-GCM) via the VIP manager.
# No dedicated SSH user or keys are needed - the cluster token provides authentication.

# ═══════════════════════════════════════════════════════════════════════════════
# KEEPALIVED VIP INSTALLATION
# ═══════════════════════════════════════════════════════════════════════════════

install_keepalived_vip() {
    # Only install for HA modes
    if [[ "$HA_MODE" != "ha-master" ]] && [[ "$HA_MODE" != "ha-backup" ]]; then
        return 0
    fi

    log_step "Installing Keepalived for VIP failover"

    # Install keepalived
    if ! command -v keepalived &>/dev/null; then
        log "Installing keepalived package..."
        sudo apt-get install -y keepalived >/dev/null 2>&1 || {
            log_error "Failed to install keepalived"
            return 1
        }
    fi
    log_success "Keepalived installed"

    # Determine keepalived priority based on HA mode
    # IMPORTANT: Keepalived uses HIGHER number = MORE likely to be MASTER.
    # Spiral Pool uses LOWER number = HIGHER priority (primary=100, backup=101+).
    # We must convert: keepalived_priority = 200 - spiral_priority
    # Primary (spiral 100) → keepalived 100, Backup (spiral 101) → keepalived 99
    #
    # ALL nodes start as state BACKUP with nopreempt. This prevents the primary
    # from automatically reclaiming VIP on return — which would cause VIP/DB split
    # (keepalived gives VIP but Patroni leader stays on the other node).
    # Higher priority still wins the INITIAL election; nopreempt only prevents
    # preemption of an already-running MASTER.
    local state="BACKUP"
    local priority=$((200 - HA_NODE_PRIORITY))
    # Ensure keepalived priority stays in valid range (1-254)
    [[ $priority -lt 1 ]] && priority=1
    [[ $priority -gt 254 ]] && priority=254
    if [[ "$HA_MODE" == "ha-master" ]]; then
        priority=100
    fi

    # Get hostname for router_id
    local hostname_short
    hostname_short=$(hostname -s 2>/dev/null || echo "spiralpool")

    # Extract auth password from token (use first 8 chars after 'spiral-' prefix)
    local auth_pass="${HA_CLUSTER_TOKEN:7:8}"
    if [[ -z "$auth_pass" ]]; then
        # Generate a random auth pass rather than using a hardcoded fallback
        auth_pass=$(tr -dc 'A-Za-z0-9' < /dev/urandom | head -c 8)
        log_warn "HA cluster token too short — generated random keepalived auth password"
    fi

    # Derive virtual_router_id from cluster token (1-255 range).
    # Prevents VRRP ID conflicts when multiple Spiral Pool clusters share a L2 segment.
    local vrid=51  # fallback
    if [[ -n "$HA_CLUSTER_TOKEN" ]]; then
        # Sum ASCII values of token chars, mod 254, + 1 (valid range 1-255)
        local _sum=0 _i
        for (( _i=0; _i<${#HA_CLUSTER_TOKEN}; _i++ )); do
            _sum=$(( _sum + $(printf '%d' "'${HA_CLUSTER_TOKEN:_i:1}") ))
        done
        vrid=$(( (_sum % 254) + 1 ))
    fi

    # Validate VIP interface exists before writing config
    if ! ip link show "$VIP_INTERFACE" &>/dev/null; then
        log_error "Network interface '$VIP_INTERFACE' not found. Available interfaces:"
        ip -br link show | grep -v '^lo ' | awk '{print "  " $1}'
        return 1
    fi

    log "Configuring keepalived..."
    log "  VIP: $VIP_ADDRESS/$VIP_NETMASK on $VIP_INTERFACE"
    log "  State: $state (priority $priority)"

    # Create keepalived configuration
    sudo mkdir -p /etc/keepalived

    sudo tee /etc/keepalived/keepalived.conf > /dev/null << EOF
# Spiral Pool VIP Configuration
# Generated by installer on $(date)
# HA Mode: $HA_MODE
# Token: [configured]

global_defs {
    router_id spiralpool_${hostname_short}
    script_user root
    enable_script_security
    # Disable email notifications
    notification_email_from spiralpool@localhost
}

# Health check script - verify stratum server is running
# fall 5 = 10s of failures before reducing priority (prevents VIP flapping
# on transient crashes — systemd Restart=always recovers stratum in ~5s)
# rise 2 = 4s of success before restoring priority
vrrp_script check_stratum {
    script "$(command -v pgrep) -x spiralstratum"
    interval 2
    weight 2
    fall 5
    rise 2
}

# VIP instance for miner failover
# nopreempt: Prevents higher-priority node from automatically reclaiming VIP on return.
# Without this, a rebooted primary steals VIP before Patroni can switchover,
# causing VIP/DB split (VIP node has read-only DB). Failback is manual via
# spiralctl or Patroni switchover. Requires state BACKUP on all nodes.
vrrp_instance SPIRALPOOL_VIP {
    state $state
    interface $VIP_INTERFACE
    virtual_router_id $vrid
    priority $priority
    advert_int 1
    nopreempt

    # Authentication between nodes
    authentication {
        auth_type PASS
        auth_pass $auth_pass
    }

    # Virtual IP address
    virtual_ipaddress {
        $VIP_ADDRESS/$VIP_NETMASK dev $VIP_INTERFACE label spiralpool-vip
    }

    # Track stratum health
    track_script {
        check_stratum
    }

    # Logging on state changes
    notify_master "/bin/logger -t keepalived 'SPIRALPOOL: Became MASTER for VIP $VIP_ADDRESS'"
    notify_backup "/bin/logger -t keepalived 'SPIRALPOOL: Became BACKUP for VIP $VIP_ADDRESS'"
    notify_fault  "/bin/logger -t keepalived 'SPIRALPOOL: FAULT state for VIP $VIP_ADDRESS'"
}
EOF

    # Restrict keepalived.conf permissions (contains auth credentials)
    sudo chmod 600 /etc/keepalived/keepalived.conf

    # Save cluster token for reference
    echo "$HA_CLUSTER_TOKEN" | sudo tee /etc/keepalived/.cluster_token > /dev/null
    sudo chmod 600 /etc/keepalived/.cluster_token

    # Enable and start keepalived
    sudo systemctl enable keepalived >/dev/null 2>&1 || true
    sudo systemctl restart keepalived || log_warn "Failed to start keepalived"

    # Wait for VIP assignment
    sleep 2

    # Flush routing cache — keepalived adding the VIP can leave stale broadcast
    # entries in the kernel FIB cache, breaking outbound connectivity
    sudo ip route flush cache 2>/dev/null || true

    # Verify VIP status
    if ip addr show "$VIP_INTERFACE" 2>/dev/null | grep -q " ${VIP_ADDRESS}/"; then
        log_success "VIP $VIP_ADDRESS is active on this node (MASTER)"
    else
        if [[ "$HA_MODE" == "ha-master" ]]; then
            log_warn "VIP not yet assigned - stratum service may not be running yet"
        else
            log_success "VIP not on this node (BACKUP mode - waiting for master failover)"
        fi
    fi

    log_success "Keepalived VIP configuration complete"

    # Show next steps for primary - use correct port based on coin selection
    if [[ "$HA_MODE" == "ha-master" ]]; then
        echo ""
        if [[ "$COIN_MODE" == "multi" ]]; then
            echo -e "  ${CYAN}Miners should connect to VIP: $VIP_ADDRESS${NC}"
            echo -e "  ${WHITE}Each coin uses its dedicated port (see 'spiralctl ports')${NC}"
        else
            echo -e "  ${CYAN}Miners should connect to: stratum+tcp://$VIP_ADDRESS:$STRATUM_PORT${NC}"
        fi
        echo ""
    fi
}

# ═══════════════════════════════════════════════════════════════════════════════
# GO INSTALLATION
# ═══════════════════════════════════════════════════════════════════════════════

install_go() {
    log_step "Installing Go $GO_VERSION"

    if check_command go; then
        local current_version=$(go version 2>/dev/null | awk '{print $3}' | sed 's/go//')
        log "Go already installed (version $current_version)"
        return
    fi

    cd /tmp

    # Determine Go arch suffix (dpkg "amd64"/"arm64" matches Go's naming directly)
    local GO_ARCH="${SYSTEM_ARCH}"

    # Multiple mirrors for Go download - primary and Google CDN fallback
    local GO_MIRRORS=(
        "https://go.dev/dl/go${GO_VERSION}.linux-${GO_ARCH}.tar.gz"
        "https://dl.google.com/go/go${GO_VERSION}.linux-${GO_ARCH}.tar.gz"
        "https://golang.org/dl/go${GO_VERSION}.linux-${GO_ARCH}.tar.gz"
    )

    # Download with retry loop
    local download_success=false
    local max_attempts=3
    for ((attempt=1; attempt<=max_attempts; attempt++)); do
        log "Downloading Go $GO_VERSION (attempt $attempt)..."
        if download_with_retry "go.tar.gz" "${GO_MIRRORS[@]}"; then
            # Verify archive integrity
            if gzip -t go.tar.gz 2>/dev/null; then
                download_success=true
                break
            else
                log_warn "Downloaded archive is corrupted, retrying..."
                rm -f go.tar.gz
            fi
        fi

        if [[ $attempt -lt $max_attempts ]]; then
            echo ""
            log_warn "Download failed. Manual download URL: https://go.dev/dl/"
            echo ""
            echo -e "  ${WHITE}Options:${NC}"
            echo -e "    ${GREEN}r${NC} = Retry download"
            echo -e "    ${RED}a${NC} = Abort installation"
            echo ""
            prompt_input "Choice [r/a]: "; read choice
            if [[ "$choice" == "a" || "$choice" == "A" ]]; then
                log_error "Installation aborted by user"
                exit 1
            fi
        fi
    done

    if [[ "$download_success" != "true" ]]; then
        log_error "Failed to download Go after $max_attempts attempts"
        log_error "Please download manually from: https://go.dev/dl/"
        log_error "Place go${GO_VERSION}.linux-${GO_ARCH}.tar.gz in /tmp and re-run"
        exit 1
    fi

    log "Extracting Go..."
    sudo rm -rf /usr/local/go
    if ! sudo tar -C /usr/local -xzf go.tar.gz; then
        log_error "Failed to extract Go archive - may be corrupted"
        rm -f go.tar.gz
        log_warn "Please re-run the installer to retry"
        exit 1
    fi
    rm -f go.tar.gz

    # Add Go to PATH
    echo 'export PATH=$PATH:/usr/local/go/bin' | sudo tee /etc/profile.d/go.sh > /dev/null
    export PATH=$PATH:/usr/local/go/bin

    # Verify installation with retry
    local verify_attempts=3
    for ((i=1; i<=verify_attempts; i++)); do
        if /usr/local/go/bin/go version &>/dev/null; then
            break
        fi
        if [[ $i -eq $verify_attempts ]]; then
            log_error "Go installation verification failed after $verify_attempts attempts"
            log_warn "Try running: source /etc/profile.d/go.sh"
            exit 1
        fi
        sleep 1
    done

    local installed_version=$(/usr/local/go/bin/go version | awk '{print $3}')
    log_success "Go $installed_version installed successfully"
}

# ═══════════════════════════════════════════════════════════════════════════════
# SPIRAL STRATUM BUILD
# ═══════════════════════════════════════════════════════════════════════════════

build_stratum() {
    log_step "Building Spiral Stratum"

    local SRC_DIR="$INSTALL_DIR/stratum-src"
    local BIN="$INSTALL_DIR/bin/spiralstratum"

    # Copy source
    if [[ -d "$SCRIPT_DIR/src/stratum" ]]; then
        sudo mkdir -p "$SRC_DIR"
        sudo cp -r "$SCRIPT_DIR/src/stratum/"* "$SRC_DIR/"
        sudo chown -R "$POOL_USER:$POOL_USER" "$SRC_DIR"
    else
        log_error "Stratum source not found at $SCRIPT_DIR/src/stratum"
        log_error "Expected location: $SCRIPT_DIR/src/stratum"
        log_error "Please ensure the source files are present and re-run the installer"
        exit 1
    fi

    # Set up Go environment
    export PATH=$PATH:/usr/local/go/bin
    local GOPATH_DIR="/home/$POOL_USER/go"
    # SECURITY: Use mktemp for unpredictable temp directory
    local GOCACHE_DIR
    GOCACHE_DIR=$(mktemp -d "/tmp/go-cache-XXXXXX") || {
        log_error "Failed to create secure temporary directory for Go cache"
        return 1
    }
    chmod 700 "$GOCACHE_DIR"

    # Ensure directories exist and are writable
    sudo -u "$POOL_USER" mkdir -p "$GOPATH_DIR"
    sudo chown "$POOL_USER:$POOL_USER" "$GOCACHE_DIR"

    log "Downloading dependencies..."
    # Use go mod tidy to generate go.sum and download dependencies
    sudo -u "$POOL_USER" bash -c "cd '$SRC_DIR' && PATH='$PATH' GOPATH='$GOPATH_DIR' GOCACHE='$GOCACHE_DIR' go mod tidy" 2>&1 || {
        log_warn "go mod tidy had warnings, continuing..."
    }

    # Read version for ldflags injection (matches upgrade.sh behavior)
    local BUILD_VERSION="1.0.0"
    if [[ -f "$SCRIPT_DIR/VERSION" ]]; then
        BUILD_VERSION=$(tr -d '[:space:]' < "$SCRIPT_DIR/VERSION")
    fi
    local BUILD_TIME
    BUILD_TIME=$(date -u +%Y-%m-%dT%H:%M:%SZ)
    local GIT_COMMIT="unknown"
    if [[ -d "$SCRIPT_DIR/.git" ]]; then
        GIT_COMMIT=$(git -C "$SCRIPT_DIR" rev-parse --short HEAD 2>/dev/null || echo "unknown")
    fi
    local LDFLAGS="-s -w -X main.Version=${BUILD_VERSION} -X main.BuildTime=${BUILD_TIME} -X main.GitCommit=${GIT_COMMIT} -X github.com/spiralpool/stratum/internal/ha.SpiralPoolVersion=${BUILD_VERSION}"

    # Build with retry logic
    local build_success=false
    local max_attempts=3
    for ((attempt=1; attempt<=max_attempts; attempt++)); do
        log "Building (attempt $attempt of $max_attempts)..."

        # CGO_ENABLED=1 required for ZMQ support (libzmq3-dev)
        if sudo -u "$POOL_USER" bash -c "cd '$SRC_DIR' && PATH='$PATH' GOPATH='$GOPATH_DIR' GOCACHE='$GOCACHE_DIR' CGO_ENABLED=1 go build -ldflags '${LDFLAGS}' -o '$BIN' ./cmd/spiralpool" 2>&1; then
            if [[ -f "$BIN" ]]; then
                build_success=true
                break
            else
                log_warn "Build completed but binary not created"
            fi
        else
            log_warn "Build failed on attempt $attempt"
        fi

        if [[ $attempt -lt $max_attempts ]]; then
            log_warn "Build failed. Cleaning cache and retrying automatically..."
            log_warn "  Possible causes: missing libzmq3-dev, network issues, insufficient memory"
            # Auto-clean cache and create fresh temp dir for retry (avoid TOCTOU on reused path)
            sudo rm -rf "$GOCACHE_DIR" 2>/dev/null || true
            GOCACHE_DIR=$(mktemp -d "/tmp/go-cache-XXXXXX")
            chmod 700 "$GOCACHE_DIR"
            sudo chown "$POOL_USER:$POOL_USER" "$GOCACHE_DIR"
            sudo -u "$POOL_USER" bash -c "cd '$SRC_DIR' && PATH='$PATH' GOPATH='$GOPATH_DIR' GOCACHE='$GOCACHE_DIR' go clean -cache" 2>/dev/null || true
            sleep 2
        fi
    done

    if [[ "$build_success" != "true" ]]; then
        log_error "Build failed after $max_attempts attempts"
        echo ""
        echo -e "  ${WHITE}Troubleshooting:${NC}"
        echo -e "    1. Ensure libzmq3-dev is installed: ${CYAN}sudo apt install libzmq3-dev${NC}"
        echo -e "    2. Check Go installation: ${CYAN}/usr/local/go/bin/go version${NC}"
        echo -e "    3. Check available memory: ${CYAN}free -h${NC}"
        echo -e "    4. Re-run installer after fixing issues"
        echo ""
        exit 1
    fi

    sudo chmod +x "$BIN"

    # Write VERSION file for runtime version detection (update-checker, upgrade.sh, spiralctl)
    echo "$BUILD_VERSION" | sudo tee "${INSTALL_DIR}/VERSION" > /dev/null
    sudo chmod 644 "${INSTALL_DIR}/VERSION"
    log_success "Stratum v${BUILD_VERSION} built successfully"

    # Build spiralctl control utility (Go binary for mining/merge commands)
    # CGO_ENABLED=0: spiralctl doesn't need ZMQ, pure Go binary
    local SPIRALCTL_BIN="$INSTALL_DIR/bin/spiralctl"
    log "Building spiralctl control utility..."
    local SPIRALCTL_LDFLAGS="-s -w -X main.Version=${BUILD_VERSION} -X main.BuildTime=${BUILD_TIME} -X main.GitCommit=${GIT_COMMIT}"
    if sudo -u "$POOL_USER" bash -c "cd '$SRC_DIR' && PATH='$PATH' GOPATH='$GOPATH_DIR' GOCACHE='$GOCACHE_DIR' CGO_ENABLED=0 go build -ldflags '${SPIRALCTL_LDFLAGS}' -o '$SPIRALCTL_BIN' ./cmd/spiralctl" 2>&1; then
        if [[ -f "$SPIRALCTL_BIN" ]]; then
            sudo chmod +x "$SPIRALCTL_BIN"
            log_success "spiralctl built successfully"
        else
            log_warn "spiralctl build completed but binary not created"
        fi
    else
        log_warn "spiralctl build failed (non-critical, bash spiralctl.sh still works for most commands)"
    fi

    sudo rm -rf "$GOCACHE_DIR" 2>/dev/null || true  # Cleanup temp cache (ignore errors)

    # Install wait-for-node.sh script (used by systemd ExecStartPre)
    if [[ -f "$SCRIPT_DIR/scripts/linux/wait-for-node.sh" ]]; then
        sudo cp "$SCRIPT_DIR/scripts/linux/wait-for-node.sh" "$INSTALL_DIR/bin/"
        sudo chmod +x "$INSTALL_DIR/bin/wait-for-node.sh"
        sudo chown "$POOL_USER:$POOL_USER" "$INSTALL_DIR/bin/wait-for-node.sh"
        log "Installed wait-for-node.sh startup script"
    fi

    log_success "Spiral Stratum built"
    mark_progress "stratum"
}

# ═══════════════════════════════════════════════════════════════════════════════
# RUN TESTS
# ═══════════════════════════════════════════════════════════════════════════════

run_stratum_tests() {
    log_step "Running Stratum Tests"

    local SRC_DIR="$INSTALL_DIR/stratum-src"

    # Set up Go environment
    export PATH=$PATH:/usr/local/go/bin
    local GOPATH_DIR="/home/$POOL_USER/go"
    # SECURITY: Use mktemp for unpredictable temp directory
    local GOCACHE_DIR
    GOCACHE_DIR=$(mktemp -d "/tmp/go-cache-test-XXXXXX") || {
        log_error "Failed to create secure temporary directory for Go test cache"
        return 1
    }
    chmod 700 "$GOCACHE_DIR"

    # Ensure directories exist
    sudo -u "$POOL_USER" mkdir -p "$GOPATH_DIR"
    sudo chown "$POOL_USER:$POOL_USER" "$GOCACHE_DIR"

    log "Running test suite to verify build integrity..."

    # Check if ZMQ is available
    local BUILD_TAGS=""
    if ! pkg-config --exists libzmq 2>/dev/null; then
        BUILD_TAGS="-tags nozmq"
        log "ZMQ not detected - running tests with nozmq tag"
    else
        log "ZMQ detected - running full test suite"
    fi

    # Run tests in two phases:
    # Phase 1: Core packages where all tests pass reliably
    # Phase 2: HA/failover tests across all packages (race-detector enabled)
    #
    # Note: Some packages (payments, shares, jobs) contain pre-existing test
    # issues (timing-sensitive tests, mock setup gaps) unrelated to production
    # code. Running ./... would show ~100 false-positive failures. Instead we
    # run those packages with an HA-specific -run filter that covers the
    # critical failover, circuit breaker, and payment fencing tests.

    local test_output
    local test_exit_code=0

    # Phase 1: Core packages (all tests in these packages pass)
    log "Phase 1: Core package tests..."
    test_output=$(sudo -u "$POOL_USER" bash -c "cd '$SRC_DIR' && PATH='$PATH' GOPATH='$GOPATH_DIR' GOCACHE='$GOCACHE_DIR' go test $BUILD_TAGS -v -count=1 \
        ./internal/coin/... \
        ./internal/crypto/... \
        ./internal/auxpow/... \
        ./internal/stratum/... \
        ./internal/vardiff/... \
        ./internal/ha/... \
        ./internal/pool/... \
        ./pkg/... \
        2>&1" | tr -d '\0') || test_exit_code=$?

    # Phase 2: HA-specific tests across database/payments/shares (with race detector)
    log "Phase 2: HA failover & payment fencing tests (with race detector)..."
    local ha_test_output
    local ha_exit_code=0
    ha_test_output=$(sudo -u "$POOL_USER" bash -c "cd '$SRC_DIR' && PATH='$PATH' GOPATH='$GOPATH_DIR' GOCACHE='$GOCACHE_DIR' go test $BUILD_TAGS -v -count=1 -race \
        -run 'HA|CircuitBreaker|BlockQueue|DBNodeState|DBFailover' \
        ./internal/database/... \
        ./internal/payments/... \
        ./internal/shares/... \
        2>&1" | tr -d '\0') || ha_exit_code=$?

    # Merge outputs
    test_output="${test_output}"$'\n'"${ha_test_output}"
    if [[ $ha_exit_code -ne 0 ]]; then
        test_exit_code=$ha_exit_code
    fi

    # Count passed/failed
    local passed_count
    local failed_count
    passed_count=$(echo "$test_output" | grep -c "^--- PASS" 2>/dev/null || true)
    failed_count=$(echo "$test_output" | grep -c "^--- FAIL" 2>/dev/null || true)
    # Ensure we have valid numbers (grep -c returns 0 with exit code 1 when no matches)
    [[ -z "$passed_count" ]] && passed_count=0
    [[ -z "$failed_count" ]] && failed_count=0

    # Show summary
    echo ""
    echo -e "  ${GREEN}Tests passed: $passed_count${NC}"
    if [[ $failed_count -gt 0 ]]; then
        echo -e "  ${RED}Tests failed: $failed_count${NC}"
    fi
    echo ""

    if [[ $test_exit_code -ne 0 ]] || [[ $failed_count -gt 0 ]]; then
        echo ""
        log_error "Test suite failed!"
        echo ""

        # Show failed test details
        echo -e "${RED}Failed tests:${NC}"
        echo "$test_output" | grep -A 5 "^--- FAIL" | head -50
        echo ""

        echo -e "  ${WHITE}Options:${NC}"
        echo -e "    ${YELLOW}v${NC} = View full test output"
        echo -e "    ${GREEN}c${NC} = Continue anyway (not recommended)"
        echo -e "    ${RED}a${NC} = Abort installation"
        echo ""
        prompt_input "Choice [v/c/a]: "; read choice
        case "$choice" in
            v|V)
                echo ""
                echo -e "${BLUE}Full test output:${NC}"
                echo "─────────────────────────────────────────────────────────────────"
                echo "$test_output"
                echo "─────────────────────────────────────────────────────────────────"
                echo ""
                echo -e "  ${WHITE}Options:${NC}"
                echo -e "    ${GREEN}c${NC} = Continue anyway (not recommended)"
                echo -e "    ${RED}a${NC} = Abort installation"
                prompt_input "Choice [c/a]: "; read choice2
                if [[ "$choice2" != "c" && "$choice2" != "C" ]]; then
                    log_error "Installation aborted due to test failures"
                    exit 2
                fi
                log_warn "Continuing despite test failures - some features may not work correctly"
                ;;
            c|C)
                log_warn "Continuing despite test failures - some features may not work correctly"
                ;;
            *)
                log_error "Installation aborted due to test failures"
                exit 2
                ;;
        esac
    else
        log_success "All tests passed ($passed_count tests)"
    fi

    # Cleanup test cache
    sudo rm -rf "$GOCACHE_DIR" 2>/dev/null || true
}

# ═══════════════════════════════════════════════════════════════════════════════
# STRATUM CONFIGURATION
# ═══════════════════════════════════════════════════════════════════════════════

configure_stratum() {
    log_step "Configuring Spiral Stratum"

    # Generate TLS certificate for encrypted stratum connections (stratum+ssl://)
    generate_tls_certificate

    if [[ "$COIN_MODE" == "multi" ]]; then
        # Multi-coin configuration (Config V2 format)
        configure_stratum_multicoin
    else
        # Single-coin configuration (Config V1 format - DGB only)
        configure_stratum_single
    fi

    # HA: Configure Redis dedup environment for the stratum service.
    # Uses a systemd drop-in so the base service file stays clean and
    # Redis env vars are modular (easy to add/remove without touching the service).
    if [[ "$HA_ENABLED" == "true" ]]; then
        log "Configuring Redis dedup environment for stratum service..."
        sudo mkdir -p /etc/systemd/system/spiralstratum.service.d
        sudo tee /etc/systemd/system/spiralstratum.service.d/redis-dedup.conf > /dev/null << 'REDIS_SVC_EOF'
# Spiral Pool: Enable Redis cross-node deduplication for HA clusters.
# The pool reads these at startup to connect to the local Redis instance
# for share and block submission deduplication across cluster nodes.
[Service]
Environment=REDIS_DEDUP_ENABLED=true
Environment=REDIS_DEDUP_ADDR=localhost:6379
REDIS_SVC_EOF
        sudo systemctl daemon-reload || true
        log_success "Redis dedup environment configured (systemd drop-in)"
    fi

    log_success "Stratum configured"
}

# Single-coin configuration (DGB, BTC, or BCH based on SOLO_COIN selection)
# ═══════════════════════════════════════════════════════════════════════════════
# TLS Certificate Generation for Encrypted Stratum (stratum+ssl://)
# ═══════════════════════════════════════════════════════════════════════════════
generate_tls_certificate() {
    local tls_dir="$INSTALL_DIR/tls"
    local cert_file="$tls_dir/stratum.crt"
    local key_file="$tls_dir/stratum.key"

    # Skip if certificate already exists
    if [[ -f "$cert_file" && -f "$key_file" ]]; then
        log "TLS certificate already exists at $cert_file"
        return 0
    fi

    log "Generating self-signed TLS certificate for encrypted V1 stratum..."
    sudo mkdir -p "$tls_dir"
    sudo openssl req -x509 -newkey rsa:4096 -sha256 -days 3650 \
        -nodes -keyout "$key_file" -out "$cert_file" \
        -subj "/CN=spiralpool/O=SpiralPool/C=CA" \
        -addext "subjectAltName=DNS:localhost,IP:0.0.0.0" 2>/dev/null

    sudo chmod 600 "$key_file"
    sudo chmod 644 "$cert_file"
    sudo chown "$POOL_USER:$POOL_USER" "$tls_dir" "$cert_file" "$key_file"
    log "TLS certificate generated: $cert_file"
}

configure_stratum_single() {
    # Set coin-specific variables based on SOLO_COIN selection
    local pool_id=""
    local coin_type=""
    local rpc_port=""
    local zmq_port=""
    local zmq_enabled="true"
    local rpc_user=""
    local rpc_password=""
    local daemon_service=""
    local pool_address=""
    # Per-coin difficulty settings (optimized for NerdQAxe++ ~5 TH/s with vardiff)
    local initial_diff=""
    local target_time=""
    local max_diff=""

    # Alphabetically ordered by coin symbol
    case "$SOLO_COIN" in
        BC2)
            pool_id="bc2_sha256_1"
            coin_type="bitcoinii"
            rpc_port="8339"
            zmq_port="28338"
            rpc_user="$BC2_RPC_USER"
            # CRITICAL: Read password from daemon config to ensure consistency
            # This prevents password mismatch between node and stratum configs
            local bc2_conf="$(get_blockchain_dir bc2)/bitcoinii.conf"
            if [[ -f "$bc2_conf" ]]; then
                rpc_password=$(grep -E "^rpcpassword=" "$bc2_conf" 2>/dev/null | head -1 | cut -d= -f2)
                if [[ -n "$rpc_password" ]]; then
                    log "Read BC2 RPC password from existing node config"
                else
                    log_warn "BC2 node config exists but password not found, using generated password"
                    rpc_password="$BC2_RPC_PASSWORD"
                    # Update node config to match (prevents future mismatch)
                    if [[ -n "$rpc_password" ]]; then
                        sudo sed -i "s/^rpcpassword=.*/rpcpassword=$rpc_password/" "$bc2_conf"
                        log "Updated BC2 node config with correct password"
                    fi
                fi
            else
                log_warn "BC2 node config not found at $bc2_conf"
                rpc_password="$BC2_RPC_PASSWORD"
            fi
            # Final validation - if still empty, generate new password
            if [[ -z "$rpc_password" ]]; then
                log_warn "No BC2 RPC password available, generating new one"
                rpc_password=$(generate_password)
                BC2_RPC_PASSWORD="$rpc_password"
            fi
            daemon_service="bitcoiniid"
            pool_address="$BC2_ADDRESS"
            # BC2: 10 min blocks - can have longer share times
            initial_diff="5000"
            target_time="10"
            max_diff="100000000"
            ;;
        BCH)
