    esac

    # Backup existing config before overwrite (for re-run safety)
    backup_config_if_exists_sudo "$INSTALL_DIR/config/config.yaml"

    # Write config atomically (temp file + mv) to prevent corruption if interrupted
    atomic_write_as "$POOL_USER" "$INSTALL_DIR/config/config.yaml" "640" << EOF
# Spiral Stratum Pool Configuration
# Generated by installer v$VERSION
# Mode: Single-Coin ($SOLO_COIN)

pool:
  id: "$pool_id"
  coin: "$coin_type"
  address: "$pool_address"
  coinbaseText: "$COINBASE_TEXT"

stratum:
  listen: "0.0.0.0:$STRATUM_PORT"
  listenV2: "0.0.0.0:$STRATUM_V2_PORT"
  tls:
    enabled: true
    listenTLS: "0.0.0.0:${STRATUM_TLS_PORT:-$((STRATUM_V2_PORT + 1))}"
    certFile: "$INSTALL_DIR/tls/stratum.crt"
    keyFile: "$INSTALL_DIR/tls/stratum.key"
    minVersion: "1.2"
  difficulty:
    initial: $initial_diff
    varDiff:
      enabled: true
      minDiff: 0.001
      maxDiff: $max_diff
      targetTime: $target_time
      retargetTime: 60    # Adjust every 60 seconds
      variancePercent: 30
  banning:
    enabled: true
    banDuration: 600s
    invalidSharesThreshold: 5
  connection:
    timeout: 600s
    maxConnections: 10000
    keepaliveInterval: 30s   # Seconds between mining.ping (30s for Avalon/cgminer compatibility)
    shutdownTimeout: 10s     # Seconds to wait for graceful shutdown
  versionRolling:
    enabled: true
    mask: 0x1FFFE000

daemon:
  host: "127.0.0.1"
  port: $rpc_port
  user: "$rpc_user"
  password: "$rpc_password"
  zmq:
    enabled: $zmq_enabled
    endpoint: "tcp://127.0.0.1:$zmq_port"

database:
  host: "127.0.0.1"
  port: 5432
  user: "$DB_USER"
  password: "$DB_PASSWORD"
  database: "$DB_NAME"
  sslMode: "disable"
  maxConnections: 200
  batching:
    size: 1000
    interval: 3s

payments:
  enabled: true
  interval: 600s
  minimumPayment: 1.0
  scheme: "SOLO"

api:
  enabled: true
  listen: "0.0.0.0:$API_PORT"
  adminApiKey: "$ADMIN_API_KEY"
  rateLimiting:
    enabled: true
    requestsPerSecond: 10
    whitelist:
      - "127.0.0.1"

metrics:
  enabled: true
  listen: "0.0.0.0:$METRICS_PORT"
  authToken: "$METRICS_TOKEN"

logging:
  level: "info"
  format: "json"
  output: "file"
  file: "$INSTALL_DIR/logs/spiralstratum.log"
  maxSizeMB: 100      # Max log file size before rotation
  maxBackups: 730     # ~2 years of daily logs
  maxAgeDays: 730     # Keep logs for 2 years
  compress: true      # Gzip rotated files

# Spiral Sentinel — internal pool health monitoring
# Monitors WAL stuck entries, node health, hashrate drops, disk space, etc.
sentinel:
  enabled: true
  check_interval: 60s
  wal_stuck_threshold: 10m
  disconnect_drop_percent: 30
  hashrate_drop_percent: 30
  wal_disk_space_warning_mb: 500
  wal_max_files: 60
  alert_cooldown: 15m
$(if [[ -n "$DISCORD_WEBHOOK" ]] || [[ -n "$TELEGRAM_BOT_TOKEN" ]]; then
echo "  webhooks:"
if [[ -n "$DISCORD_WEBHOOK" ]]; then
echo "    - url: \"$DISCORD_WEBHOOK\""
fi
if [[ -n "$TELEGRAM_BOT_TOKEN" ]] && [[ -n "$TELEGRAM_CHAT_ID" ]]; then
echo "    - url: \"https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage\""
echo "      chat_id: \"$TELEGRAM_CHAT_ID\""
fi
fi)

# Block celebration — display messages on miner screens when blocks are found
celebration:
  enabled: ${CELEBRATION_ENABLED:-true}
  duration_hours: ${CELEBRATION_HOURS:-2}
EOF

    # Add HA configuration if enabled
    if [[ "$HA_ENABLED" == "true" ]]; then
        append_ha_config_to_yaml "$INSTALL_DIR/config/config.yaml"
    fi

    # Add merge mining configuration if enabled (V1: appends at root level)
    if [[ "$MERGE_MINING_ENABLED" == "true" ]]; then
        append_merge_mining_v1_to_config "$INSTALL_DIR/config/config.yaml"
    fi

    # Set secure permissions: owner read/write, group read (service user needs to read)
    sudo chown "$POOL_USER:$POOL_USER" "$INSTALL_DIR/config/config.yaml"
    sudo chmod 640 "$INSTALL_DIR/config/config.yaml"

    # Determine correct PostgreSQL dependency (Patroni manages PG in HA mode)
    local pg_service_dep="postgresql.service"
    if [[ "$PATRONI_ENABLED" == "true" ]] && [[ "$HA_ENABLED" == "true" ]]; then
        pg_service_dep="patroni.service"
    fi

    # Create single-coin service with dependency on the appropriate daemon
    sudo tee /etc/systemd/system/spiralstratum.service > /dev/null << EOF
[Unit]
Description=Spiral Stratum Pool ($SOLO_COIN)
After=network-online.target ${pg_service_dep} ${daemon_service}.service
Requires=${pg_service_dep}
Wants=${daemon_service}.service
# Prevent restart loops: max 10 restarts in 5 minutes (stratum is critical)
StartLimitIntervalSec=300
StartLimitBurst=10

[Service]
Type=simple
User=$POOL_USER
Group=$POOL_USER
WorkingDirectory=$INSTALL_DIR

# Ensure log directory and file exist with proper permissions
# Note: chown removed — service runs as $POOL_USER, so mkdir/touch create files owned by that user already
ExecStartPre=/bin/bash -c 'mkdir -p $INSTALL_DIR/logs && touch $INSTALL_DIR/logs/spiralstratum.log'

# Wait for blockchain node RPC to be ready (up to 30 minutes)
# This prevents boot loops when the node is still starting after reboot
ExecStartPre=$INSTALL_DIR/bin/wait-for-node.sh $INSTALL_DIR/config/config.yaml 1800

ExecStart=$INSTALL_DIR/bin/spiralstratum -config $INSTALL_DIR/config/config.yaml

# === SELF-HEALING / AUTO-RESTART ===
# Restart=always ensures service restarts on any exit (crash, kill, clean exit)
Restart=always
RestartSec=10
# CRITICAL: Must be >= 120s to allow block submission to complete before SIGKILL
# Block submission can take up to 90 seconds (5 retries with exponential backoff)
TimeoutStopSec=120
# Note: WatchdogSec removed - service doesn't implement sd_notify

LimitNOFILE=65535
Environment=GOMAXPROCS=0

# Allow longer startup time for ExecStartPre (node wait script)
TimeoutStartSec=1900

# === SECURITY HARDENING ===
PrivateTmp=yes
ProtectSystem=strict
ProtectHome=yes
RuntimeDirectory=spiralpool
RuntimeDirectoryPreserve=yes
ReadWritePaths=$INSTALL_DIR /run/spiralpool
NoNewPrivileges=yes
# VIP management: ip addr add/del, ip link (macvlan), arping (split-brain detection)
CapabilityBoundingSet=CAP_NET_ADMIN CAP_NET_RAW
AmbientCapabilities=CAP_NET_ADMIN CAP_NET_RAW
ProtectKernelTunables=yes
ProtectKernelModules=yes
ProtectControlGroups=yes

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable spiralstratum || true
}

# Multi-coin configuration (Config V2 format with coins array)
configure_stratum_multicoin() {
    log "Generating multi-coin configuration (V2 format)..."

    # CRITICAL: Read passwords from daemon configs to ensure consistency
    # This prevents mismatches if passwords were regenerated during install
    local dgb_rpc_pass=""
    local btc_rpc_pass=""
    local bch_rpc_pass=""
    local bc2_rpc_pass=""
    local ltc_rpc_pass=""
    local doge_rpc_pass=""

    # Read actual daemon config passwords — these are authoritative.
    # Always use get_blockchain_dir so multi-disk installs (CHAIN_MOUNT_POINT)
    # find the conf in the right place instead of hardcoded $INSTALL_DIR/coin.
    if [[ -f "$(get_blockchain_dir dgb)/digibyte.conf" ]]; then
        dgb_rpc_pass=$(grep -E "^rpcpassword=" "$(get_blockchain_dir dgb)/digibyte.conf" 2>/dev/null | head -1 | cut -d= -f2)
        [[ -n "$dgb_rpc_pass" ]] && log "Read DGB RPC password from node config"
    fi
    [[ -z "$dgb_rpc_pass" ]] && dgb_rpc_pass="${DGB_RPC_PASSWORD:-$RPC_PASSWORD}"

    if [[ -f "$(get_blockchain_dir btc)/bitcoin.conf" ]]; then
        btc_rpc_pass=$(grep -E "^rpcpassword=" "$(get_blockchain_dir btc)/bitcoin.conf" 2>/dev/null | head -1 | cut -d= -f2)
        [[ -n "$btc_rpc_pass" ]] && log "Read BTC RPC password from node config"
    fi
    [[ -z "$btc_rpc_pass" ]] && btc_rpc_pass="$BTC_RPC_PASSWORD"

    if [[ -f "$(get_blockchain_dir bch)/bitcoin.conf" ]]; then
        bch_rpc_pass=$(grep -E "^rpcpassword=" "$(get_blockchain_dir bch)/bitcoin.conf" 2>/dev/null | head -1 | cut -d= -f2)
        [[ -n "$bch_rpc_pass" ]] && log "Read BCH RPC password from node config"
    fi
    [[ -z "$bch_rpc_pass" ]] && bch_rpc_pass="$BCH_RPC_PASSWORD"

    if [[ -f "$(get_blockchain_dir bc2)/bitcoinii.conf" ]]; then
        bc2_rpc_pass=$(grep -E "^rpcpassword=" "$(get_blockchain_dir bc2)/bitcoinii.conf" 2>/dev/null | head -1 | cut -d= -f2)
        [[ -n "$bc2_rpc_pass" ]] && log "Read BC2 RPC password from node config"
    fi
    [[ -z "$bc2_rpc_pass" ]] && bc2_rpc_pass="$BC2_RPC_PASSWORD"

    if [[ -f "$(get_blockchain_dir ltc)/litecoin.conf" ]]; then
        ltc_rpc_pass=$(grep -E "^rpcpassword=" "$(get_blockchain_dir ltc)/litecoin.conf" 2>/dev/null | head -1 | cut -d= -f2)
        [[ -n "$ltc_rpc_pass" ]] && log "Read LTC RPC password from node config"
    fi
    [[ -z "$ltc_rpc_pass" ]] && ltc_rpc_pass="$LTC_RPC_PASSWORD"

    if [[ -f "$(get_blockchain_dir doge)/dogecoin.conf" ]]; then
        doge_rpc_pass=$(grep -E "^rpcpassword=" "$(get_blockchain_dir doge)/dogecoin.conf" 2>/dev/null | head -1 | cut -d= -f2)
        [[ -n "$doge_rpc_pass" ]] && log "Read DOGE RPC password from node config"
    fi
    [[ -z "$doge_rpc_pass" ]] && doge_rpc_pass="$DOGE_RPC_PASSWORD"

    local nmc_rpc_pass=""
    local sys_rpc_pass=""
    local xmy_rpc_pass=""
    local fbtc_rpc_pass=""
    local qbx_rpc_pass=""

    if [[ -f "$(get_blockchain_dir nmc)/namecoin.conf" ]]; then
        nmc_rpc_pass=$(grep -E "^rpcpassword=" "$(get_blockchain_dir nmc)/namecoin.conf" 2>/dev/null | head -1 | cut -d= -f2)
        [[ -n "$nmc_rpc_pass" ]] && log "Read NMC RPC password from node config"
    fi
    [[ -z "$nmc_rpc_pass" ]] && nmc_rpc_pass="$NMC_RPC_PASSWORD"

    if [[ -f "$(get_blockchain_dir sys)/syscoin.conf" ]]; then
        sys_rpc_pass=$(grep -E "^rpcpassword=" "$(get_blockchain_dir sys)/syscoin.conf" 2>/dev/null | head -1 | cut -d= -f2)
        [[ -n "$sys_rpc_pass" ]] && log "Read SYS RPC password from node config"
    fi
    [[ -z "$sys_rpc_pass" ]] && sys_rpc_pass="$SYS_RPC_PASSWORD"

    if [[ -f "$(get_blockchain_dir xmy)/myriadcoin.conf" ]]; then
        xmy_rpc_pass=$(grep -E "^rpcpassword=" "$(get_blockchain_dir xmy)/myriadcoin.conf" 2>/dev/null | head -1 | cut -d= -f2)
        [[ -n "$xmy_rpc_pass" ]] && log "Read XMY RPC password from node config"
    fi
    [[ -z "$xmy_rpc_pass" ]] && xmy_rpc_pass="$XMY_RPC_PASSWORD"

    if [[ -f "$(get_blockchain_dir fbtc)/fractal.conf" ]]; then
        fbtc_rpc_pass=$(grep -E "^rpcpassword=" "$(get_blockchain_dir fbtc)/fractal.conf" 2>/dev/null | head -1 | cut -d= -f2)
        [[ -n "$fbtc_rpc_pass" ]] && log "Read FBTC RPC password from node config"
    fi
    [[ -z "$fbtc_rpc_pass" ]] && fbtc_rpc_pass="$FBTC_RPC_PASSWORD"

    local _qbx_conf_path
    _qbx_conf_path="$(get_blockchain_dir qbx)/qbitx.conf"
    if [[ -f "$_qbx_conf_path" ]]; then
        qbx_rpc_pass=$(grep -E "^rpcpassword=" "$_qbx_conf_path" 2>/dev/null | head -1 | cut -d= -f2)
        if [[ -n "$qbx_rpc_pass" ]]; then
            log "Read QBX RPC password from node config"
        else
            log_warn "QBX node config exists but rpcpassword not found — using generated password and patching config"
            qbx_rpc_pass="$QBX_RPC_PASSWORD"
            [[ -n "$qbx_rpc_pass" ]] && sudo sed -i "s/^rpcpassword=.*/rpcpassword=$qbx_rpc_pass/" "$_qbx_conf_path"
        fi
    else
        qbx_rpc_pass="$QBX_RPC_PASSWORD"
    fi
    if [[ -z "$qbx_rpc_pass" ]]; then
        log_warn "No QBX RPC password available — generating new one and patching qbitx.conf"
        qbx_rpc_pass=$(generate_password)
        QBX_RPC_PASSWORD="$qbx_rpc_pass"
        [[ -f "$_qbx_conf_path" ]] && sudo sed -i "s/^rpcpassword=.*/rpcpassword=$qbx_rpc_pass/" "$_qbx_conf_path"
    fi

    # Build the coins array based on enabled coins
    local COINS_CONFIG=""

    # Add DigiByte if enabled
    if [[ "$ENABLE_DGB" == "true" ]]; then
        COINS_CONFIG="  # DigiByte (SHA256d) - 15 sec blocks
  - symbol: \"DGB\"
    pool_id: \"dgb_sha256_1\"
    enabled: true
    address: \"${DGB_POOL_ADDRESS:-$POOL_ADDRESS}\"
    coinbase_text: \"$COINBASE_TEXT\"
    stratum:
      port: 3333
