        cert_file: \"$INSTALL_DIR/tls/stratum.crt\"
        key_file: \"$INSTALL_DIR/tls/stratum.key\"
      difficulty:
        initial: 5000          # ~5 TH/s @ 4s target, vardiff adjusts
        varDiff:
          enabled: true
          minDiff: 0.001       # Support tiny miners (ESP32)
          maxDiff: 10000000    # Support large ASICs (S19/S21)
          targetTime: 4        # 4 seconds (~3-4 shares per 15s block)
          retargetTime: 60     # Adjust every 60 seconds
          variancePercent: 30
      version_rolling:
        enabled: true
        mask: 536862720
    nodes:
      - id: \"primary\"
        host: \"127.0.0.1\"
        port: $RPC_PORT
        user: \"$DGB_RPC_USER\"
        password: \"$dgb_rpc_pass\"
        priority: 0
        zmq:
          enabled: true
          endpoint: \"tcp://127.0.0.1:$ZMQ_PORT\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\"
"
    fi

    # Add Bitcoin if enabled
    if [[ "$ENABLE_BTC" == "true" ]]; then
        COINS_CONFIG="$COINS_CONFIG
  # Bitcoin (SHA256d) - 10 min blocks
  - symbol: \"BTC\"
    pool_id: \"btc_sha256_1\"
    enabled: true
    address: \"$BTC_POOL_ADDRESS\"
    coinbase_text: \"$COINBASE_TEXT\"
    stratum:
      port: 4333
