          retargetTime: 90     # Adjust every 90 seconds
          variancePercent: 30
      version_rolling:
        enabled: true
        mask: 536862720
    nodes:
      - id: \"primary\"
        host: \"127.0.0.1\"
        port: 8332
        user: \"$BTC_RPC_USER\"
        password: \"$btc_rpc_pass\"
        priority: 0
        zmq:
          enabled: true
          endpoint: \"tcp://127.0.0.1:28332\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\"
"
    fi

    # Add Bitcoin Cash if enabled
    if [[ "$ENABLE_BCH" == "true" ]]; then
        COINS_CONFIG="$COINS_CONFIG
  # Bitcoin Cash (SHA256d) - 10 min blocks
  - symbol: \"BCH\"
    pool_id: \"bch_sha256_1\"
