      tls:
        cert_file: \"$INSTALL_DIR/tls/stratum.crt\"
        key_file: \"$INSTALL_DIR/tls/stratum.key\"
      difficulty:
        initial: 5000          # ~2.5 TH/s @ 4s target, vardiff adjusts
        varDiff:
          enabled: true
          minDiff: 0.001       # Support tiny miners (ESP32)
          maxDiff: 100000000   # Support large ASICs (S19/S21)
          targetTime: 4        # 4 seconds
          retargetTime: 90     # Adjust every 90 seconds
          variancePercent: 30
      version_rolling:
        enabled: true
        mask: 536862720
    nodes:
      - id: \"primary\"
        host: \"127.0.0.1\"
        port: $QBX_RPC_PORT
        user: \"$QBX_RPC_USER\"
        password: \"$qbx_rpc_pass\"
        priority: 0
        zmq:
          enabled: true
          endpoint: \"tcp://127.0.0.1:$QBX_ZMQ_PORT\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\"
"
    fi

    # ═══════════════════════════════════════════════════════════════════════════
    # SCRYPT COINS
    # ═══════════════════════════════════════════════════════════════════════════

    # Add Litecoin if enabled
    if [[ "$ENABLE_LTC" == "true" ]]; then
        COINS_CONFIG="$COINS_CONFIG
  # Litecoin (Scrypt) - 2.5 min blocks
  - symbol: \"LTC\"
    pool_id: \"ltc_scrypt_1\"
    enabled: true
    address: \"$LTC_POOL_ADDRESS\"
    coinbase_text: \"$COINBASE_TEXT\"
    stratum:
      port: 7333
      port_v2: 7334
      port_tls: 7335
      tls:
        cert_file: \"$INSTALL_DIR/tls/stratum.crt\"
        key_file: \"$INSTALL_DIR/tls/stratum.key\"
      difficulty:
        initial: 128           # ~500 MH/s Scrypt @ 8s target
        varDiff:
          enabled: true
          minDiff: 0.001       # Support tiny miners
          maxDiff: 65536       # Support L7 (~9.5 GH/s Scrypt)
          targetTime: 8        # 8 seconds (~18 shares per 2.5 min block)
          retargetTime: 60
          variancePercent: 30
      version_rolling:
        enabled: true
        mask: 536862720
    nodes:
      - id: \"primary\"
        host: \"127.0.0.1\"
        port: 9332
        user: \"$LTC_RPC_USER\"
        password: \"$ltc_rpc_pass\"
        priority: 0
        zmq:
          enabled: true
          endpoint: \"tcp://127.0.0.1:28933\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\"
"
    fi

    # Add Dogecoin if enabled
    if [[ "$ENABLE_DOGE" == "true" ]]; then
        COINS_CONFIG="$COINS_CONFIG
  # Dogecoin (Scrypt) - 1 min blocks
  - symbol: \"DOGE\"
    pool_id: \"doge_scrypt_1\"
    enabled: true
    address: \"$DOGE_POOL_ADDRESS\"
    coinbase_text: \"$COINBASE_TEXT\"
    stratum:
      port: 8335
      port_v2: 8337
      port_tls: 8342
      tls:
        cert_file: \"$INSTALL_DIR/tls/stratum.crt\"
        key_file: \"$INSTALL_DIR/tls/stratum.key\"
      difficulty:
        initial: 64            # ~500 MH/s Scrypt @ 4s target
        varDiff:
          enabled: true
          minDiff: 0.001       # Support tiny miners
          maxDiff: 65536       # Support L7 (~9.5 GH/s Scrypt)
          targetTime: 4        # 4 seconds (~15 shares per 1 min block)
          retargetTime: 60
          variancePercent: 30
      version_rolling:
        enabled: true
        mask: 536862720
    nodes:
      - id: \"primary\"
        host: \"127.0.0.1\"
        port: 22555
        user: \"$DOGE_RPC_USER\"
        password: \"$doge_rpc_pass\"
        priority: 0
        zmq:
          enabled: true
          endpoint: \"tcp://127.0.0.1:28555\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\"
"
    fi

    # Add DigiByte Scrypt if enabled
    # IMPORTANT: Uses symbol "DGB-SCRYPT" to trigger Scrypt algorithm in stratum
    # Same blockchain/node as DGB, but different mining algorithm
    if [[ "$ENABLE_DGB_SCRYPT" == "true" ]]; then
        COINS_CONFIG="$COINS_CONFIG
  # DigiByte (Scrypt algorithm) - 15 sec blocks, same node as DGB
  - symbol: \"DGB-SCRYPT\"
    pool_id: \"dgb_scrypt_1\"
    enabled: true
    address: \"${DGB_POOL_ADDRESS:-$POOL_ADDRESS}\"
    coinbase_text: \"$COINBASE_TEXT\"
    stratum:
      port: 3336
      port_v2: 3337
      port_tls: 3338
      tls:
        cert_file: \"$INSTALL_DIR/tls/stratum.crt\"
        key_file: \"$INSTALL_DIR/tls/stratum.key\"
      difficulty:
        initial: 32            # ~500 MH/s Scrypt @ 3s target
        varDiff:
          enabled: true
          minDiff: 0.001       # Support tiny miners
          maxDiff: 65536       # Support L7 (~9.5 GH/s Scrypt)
          targetTime: 3        # 3 seconds (~5 shares per 15s block)
          retargetTime: 45
          variancePercent: 30
      version_rolling:
        enabled: true
        mask: 536862720
    nodes:
      - id: \"primary\"
        host: \"127.0.0.1\"
        port: $RPC_PORT
        user: \"$DGB_RPC_USER\"
        password: \"$dgb_rpc_pass\"
        priority: 0
        zmq:
          enabled: true
          endpoint: \"tcp://127.0.0.1:$ZMQ_PORT\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\"
"
    fi

    # Add PepeCoin if enabled
    if [[ "$ENABLE_PEP" == "true" ]]; then
        # Read PEP RPC password from daemon config if it exists
        local pep_rpc_pass="$PEP_RPC_PASSWORD"
        local pep_conf="$(get_blockchain_dir pep)/pepecoin.conf"
        if [[ -f "$pep_conf" ]]; then
            local conf_pass=$(grep -E "^rpcpassword=" "$pep_conf" 2>/dev/null | head -1 | cut -d= -f2)
            [[ -n "$conf_pass" ]] && pep_rpc_pass="$conf_pass"
        fi
        COINS_CONFIG="$COINS_CONFIG
  # PepeCoin (Scrypt) - 1 min blocks, merge-mineable with LTC
  - symbol: \"PEP\"
    pool_id: \"pep_scrypt_1\"
    enabled: true
    address: \"$PEP_POOL_ADDRESS\"
    coinbase_text: \"$COINBASE_TEXT\"
    stratum:
      port: 10335
      port_v2: 10336
      port_tls: 10337
      tls:
        cert_file: \"$INSTALL_DIR/tls/stratum.crt\"
        key_file: \"$INSTALL_DIR/tls/stratum.key\"
      difficulty:
        initial: 64            # ~500 MH/s Scrypt @ 4s target
        varDiff:
          enabled: true
          minDiff: 0.001       # Support tiny miners
          maxDiff: 65536       # Support L7 (~9.5 GH/s Scrypt)
          targetTime: 4        # 4 seconds (~15 shares per 1 min block)
          retargetTime: 60
          variancePercent: 30
      version_rolling:
        enabled: true
        mask: 536862720
    nodes:
      - id: \"primary\"
        host: \"127.0.0.1\"
        port: 33873
        user: \"$PEP_RPC_USER\"
        password: \"$pep_rpc_pass\"
        priority: 0
        zmq:
          enabled: false
          endpoint: \"tcp://127.0.0.1:28873\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\"
"
    fi

    # Add Catcoin if enabled
    if [[ "$ENABLE_CAT" == "true" ]]; then
        # Read CAT RPC password from daemon config if it exists
        local cat_rpc_pass="$CAT_RPC_PASSWORD"
        local cat_conf="$(get_blockchain_dir cat)/catcoin.conf"
        if [[ -f "$cat_conf" ]]; then
            local conf_pass=$(grep -E "^rpcpassword=" "$cat_conf" 2>/dev/null | head -1 | cut -d= -f2)
            [[ -n "$conf_pass" ]] && cat_rpc_pass="$conf_pass"
        fi
        COINS_CONFIG="$COINS_CONFIG
  # Catcoin (Scrypt) - 10 min blocks (like Bitcoin), standalone chain
  - symbol: \"CAT\"
    pool_id: \"cat_scrypt_1\"
    enabled: true
    address: \"$CAT_POOL_ADDRESS\"
    coinbase_text: \"$COINBASE_TEXT\"
    stratum:
      port: 12335
      port_v2: 12336
      port_tls: 12337
      tls:
        cert_file: \"$INSTALL_DIR/tls/stratum.crt\"
        key_file: \"$INSTALL_DIR/tls/stratum.key\"
      difficulty:
        initial: 128           # ~500 MH/s Scrypt @ 8s target
        varDiff:
          enabled: true
          minDiff: 0.001       # Support tiny miners
          maxDiff: 65536       # Support L7 (~9.5 GH/s Scrypt)
          targetTime: 8        # 8 seconds (~75 shares per 10 min block)
          retargetTime: 90
          variancePercent: 30
      version_rolling:
        enabled: true
        mask: 536862720
    nodes:
      - id: \"primary\"
        host: \"127.0.0.1\"
        port: 9932
        user: \"$CAT_RPC_USER\"
        password: \"$cat_rpc_pass\"
        priority: 0
        zmq:
          enabled: true
          endpoint: \"tcp://127.0.0.1:28932\"
    payments:
      enabled: true
      interval: 600s
      minimum_payment: 0.01
      scheme: \"SOLO\"
"
    fi

    # Backup existing config before overwrite (for re-run safety)
    backup_config_if_exists_sudo "$INSTALL_DIR/config/config.yaml"

    # Use atomic write for config file (temp + mv pattern prevents corruption on interrupt)
    atomic_write_as "$POOL_USER" "$INSTALL_DIR/config/config.yaml" "640" << EOF
# Spiral Stratum Pool Configuration
# Generated by installer v$VERSION
# Mode: Multi-Coin (Config V2)
# Enabled:$(if [[ "$ENABLE_DGB" == "true" ]]; then echo " DGB"; fi)$(if [[ "$ENABLE_BTC" == "true" ]]; then echo " + BTC"; fi)$(if [[ "$ENABLE_BCH" == "true" ]]; then echo " + BCH"; fi)$(if [[ "$ENABLE_BC2" == "true" ]]; then echo " + BC2"; fi)$(if [[ "$ENABLE_NMC" == "true" ]]; then echo " + NMC"; fi)$(if [[ "$ENABLE_SYS" == "true" ]]; then echo " + SYS"; fi)$(if [[ "$ENABLE_XMY" == "true" ]]; then echo " + XMY"; fi)$(if [[ "$ENABLE_FBTC" == "true" ]]; then echo " + FBTC"; fi)$(if [[ "$ENABLE_QBX" == "true" ]]; then echo " + QBX"; fi)$(if [[ "$ENABLE_LTC" == "true" ]]; then echo " + LTC"; fi)$(if [[ "$ENABLE_DOGE" == "true" ]]; then echo " + DOGE"; fi)$(if [[ "$ENABLE_DGB_SCRYPT" == "true" ]]; then echo " + DGB-Scrypt"; fi)$(if [[ "$ENABLE_PEP" == "true" ]]; then echo " + PEP"; fi)$(if [[ "$ENABLE_CAT" == "true" ]]; then echo " + CAT"; fi)

# V2 multi-coin configuration format
version: 2

# Global settings
global:
  log_level: "info"
  log_format: "json"
  metrics_port: $METRICS_PORT
  metrics_auth_token: "$METRICS_TOKEN"
  api_port: $API_PORT
  api_enabled: true
  admin_api_key: "$ADMIN_API_KEY"

  # Spiral Sentinel — internal pool health monitoring
  # Monitors WAL stuck entries, node health, hashrate drops, disk space, etc.
  # Complements the external Python Spiral Sentinel (miner hardware monitoring)
  sentinel:
    enabled: true
    check_interval: 60s
    wal_stuck_threshold: 10m
    disconnect_drop_percent: 30
    hashrate_drop_percent: 30
    wal_disk_space_warning_mb: 500
    wal_max_files: 60
    alert_cooldown: 15m
$(if [[ -n "$DISCORD_WEBHOOK" ]] || [[ -n "$TELEGRAM_BOT_TOKEN" ]]; then
echo "    webhooks:"
if [[ -n "$DISCORD_WEBHOOK" ]]; then
echo "      - url: \"$DISCORD_WEBHOOK\""
fi
if [[ -n "$TELEGRAM_BOT_TOKEN" ]] && [[ -n "$TELEGRAM_CHAT_ID" ]]; then
echo "      - url: \"https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage\""
echo "        chat_id: \"$TELEGRAM_CHAT_ID\""
fi
fi)

  # Block celebration — display messages on miner screens when blocks are found
  celebration:
    enabled: ${CELEBRATION_ENABLED:-true}
    duration_hours: ${CELEBRATION_HOURS:-2}

# Per-coin pool configurations
coins:
$COINS_CONFIG

# Shared database for all coins
database:
  host: "127.0.0.1"
  port: 5432
  user: "$DB_USER"
  password: "$DB_PASSWORD"
  database: "$DB_NAME"
  sslMode: "disable"
  maxConnections: 200
  batching:
    size: 1000
    interval: 3s
EOF

    # Add HA configuration if enabled
    if [[ "$HA_ENABLED" == "true" ]]; then
        append_ha_config_to_yaml "$INSTALL_DIR/config/config.yaml"
    fi

    # Add merge mining configuration if enabled (V2: inserts inside parent coin section)
    if [[ "$MERGE_MINING_ENABLED" == "true" ]]; then
        append_merge_mining_to_config "$INSTALL_DIR/config/config.yaml"
    fi

    # Set secure permissions: owner read/write, group read (service user needs to read)
    sudo chown "$POOL_USER:$POOL_USER" "$INSTALL_DIR/config/config.yaml"
    sudo chmod 640 "$INSTALL_DIR/config/config.yaml"

    # Build service dependencies based on enabled coins
    local WANTS_DEPS=""
    if [[ "$ENABLE_DGB" == "true" ]]; then
        WANTS_DEPS="digibyted.service"
    fi
    if [[ "$ENABLE_BTC" == "true" ]]; then
        WANTS_DEPS="$WANTS_DEPS bitcoind.service"
    fi
    if [[ "$ENABLE_BCH" == "true" ]]; then
        WANTS_DEPS="$WANTS_DEPS bitcoind-bch.service"
    fi
    if [[ "$ENABLE_BC2" == "true" ]]; then
        WANTS_DEPS="$WANTS_DEPS bitcoiniid.service"
    fi
    if [[ "$ENABLE_LTC" == "true" ]]; then
        WANTS_DEPS="$WANTS_DEPS litecoind.service"
    fi
    if [[ "$ENABLE_DOGE" == "true" ]]; then
        WANTS_DEPS="$WANTS_DEPS dogecoind.service"
    fi
    if [[ "$ENABLE_PEP" == "true" ]]; then
        WANTS_DEPS="$WANTS_DEPS pepecoind.service"
    fi
    if [[ "$ENABLE_CAT" == "true" ]]; then
        WANTS_DEPS="$WANTS_DEPS catcoind.service"
    fi
    # Aux chain daemons (merge mining)
    if [[ "$ENABLE_NMC" == "true" ]]; then
        WANTS_DEPS="$WANTS_DEPS namecoind.service"
    fi
    if [[ "$ENABLE_SYS" == "true" ]]; then
        WANTS_DEPS="$WANTS_DEPS syscoind.service"
    fi
    if [[ "$ENABLE_XMY" == "true" ]]; then
        WANTS_DEPS="$WANTS_DEPS myriadcoind.service"
    fi
    if [[ "$ENABLE_FBTC" == "true" ]]; then
        WANTS_DEPS="$WANTS_DEPS fractald.service"
    fi
    if [[ "$ENABLE_QBX" == "true" ]]; then
        WANTS_DEPS="$WANTS_DEPS qbitxd.service"
    fi

    # Determine correct PostgreSQL dependency (Patroni manages PG in HA mode)
    local pg_service_dep="postgresql.service"
    if [[ "$PATRONI_ENABLED" == "true" ]] && [[ "$HA_ENABLED" == "true" ]]; then
        pg_service_dep="patroni.service"
    fi

    # Create multi-coin service
    # Note: V2 Coordinator has its own 30-minute retry logic, but we still use
    # wait-for-node.sh for the primary node as a cleaner startup experience
    sudo tee /etc/systemd/system/spiralstratum.service > /dev/null << EOF
[Unit]
Description=Spiral Stratum Pool (Multi-Coin)
After=network-online.target ${pg_service_dep} $WANTS_DEPS
Requires=${pg_service_dep}
Wants=$WANTS_DEPS
# Prevent restart loops: max 10 restarts in 5 minutes (stratum is critical)
StartLimitIntervalSec=300
StartLimitBurst=10

[Service]
Type=simple
User=$POOL_USER
Group=$POOL_USER
WorkingDirectory=$INSTALL_DIR

# Ensure log directory and file exist with proper permissions
# Note: chown removed — service runs as $POOL_USER, so mkdir/touch create files owned by that user already
ExecStartPre=/bin/bash -c 'mkdir -p $INSTALL_DIR/logs && touch $INSTALL_DIR/logs/spiralstratum.log'

# Wait for primary blockchain node RPC to be ready (up to 30 minutes)
# V2 mode has its own retry logic but this ensures clean startup
ExecStartPre=$INSTALL_DIR/bin/wait-for-node.sh $INSTALL_DIR/config/config.yaml 1800

ExecStart=$INSTALL_DIR/bin/spiralstratum -config $INSTALL_DIR/config/config.yaml

# === SELF-HEALING / AUTO-RESTART ===
# Restart=always ensures service restarts on any exit (crash, kill, clean exit)
Restart=always
RestartSec=10
# Graceful shutdown timeout - SIGKILL after 30s if stratum hasn't exited.
# WAL recovery replays any in-flight shares on restart, so SIGKILL is safe.
TimeoutStopSec=30
# Note: WatchdogSec removed - service doesn't implement sd_notify

LimitNOFILE=65535
Environment=GOMAXPROCS=0

# Allow longer startup time for ExecStartPre (node wait script)
TimeoutStartSec=1900

# === SECURITY HARDENING ===
PrivateTmp=yes
ProtectSystem=strict
ProtectHome=yes
RuntimeDirectory=spiralpool
RuntimeDirectoryPreserve=yes
ReadWritePaths=$INSTALL_DIR /run/spiralpool
NoNewPrivileges=yes
# VIP management: ip addr add/del, ip link (macvlan), arping (split-brain detection)
CapabilityBoundingSet=CAP_NET_ADMIN CAP_NET_RAW
AmbientCapabilities=CAP_NET_ADMIN CAP_NET_RAW
ProtectKernelTunables=yes
ProtectKernelModules=yes
ProtectControlGroups=yes

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable spiralstratum || true

    # Log enabled coins and ports
    log "Multi-coin configuration created:"
    log "  === SHA-256d Coins ==="
    log "  DGB Stratum: port 3333 (V1), 3334 (V2)"
    if [[ "$ENABLE_BTC" == "true" ]]; then
        log "  BTC Stratum: port 4333 (V1), 4334 (V2)"
    fi
    if [[ "$ENABLE_BCH" == "true" ]]; then
        log "  BCH Stratum: port 5333 (V1), 5334 (V2)"
    fi
    if [[ "$ENABLE_BC2" == "true" ]]; then
        log "  BC2 Stratum: port 6333 (V1), 6334 (V2)"
    fi
    if [[ "$ENABLE_NMC" == "true" ]]; then
        log "  NMC Stratum: port 14335 (V1), 14336 (V2)"
    fi
    if [[ "$ENABLE_SYS" == "true" ]]; then
        log "  SYS Stratum: port 15335 (V1), 15336 (V2)"
    fi
    if [[ "$ENABLE_XMY" == "true" ]]; then
        log "  XMY Stratum: port 17335 (V1), 17336 (V2)"
    fi
    if [[ "$ENABLE_FBTC" == "true" ]]; then
        log "  FBTC Stratum: port 18335 (V1), 18336 (V2)"
    fi
    if [[ "$ENABLE_QBX" == "true" ]]; then
        log "  QBX Stratum: port 20335 (V1), 20336 (V2)"
    fi
    if [[ "$ENABLE_LTC" == "true" ]] || [[ "$ENABLE_DOGE" == "true" ]] || [[ "$ENABLE_DGB_SCRYPT" == "true" ]] || [[ "$ENABLE_PEP" == "true" ]] || [[ "$ENABLE_CAT" == "true" ]]; then
        log "  === Scrypt Coins ==="
    fi
    if [[ "$ENABLE_LTC" == "true" ]]; then
        log "  LTC Stratum: port 7333 (V1), 7334 (V2)"
    fi
    if [[ "$ENABLE_DOGE" == "true" ]]; then
        log "  DOGE Stratum: port 8335 (V1), 8337 (V2)"
    fi
    if [[ "$ENABLE_DGB_SCRYPT" == "true" ]]; then
        log "  DGB-Scrypt Stratum: port 3336 (V1), 3337 (V2)"
    fi
    if [[ "$ENABLE_PEP" == "true" ]]; then
        log "  PEP Stratum: port 10335 (V1), 10336 (V2)"
    fi
    if [[ "$ENABLE_CAT" == "true" ]]; then
        log "  CAT Stratum: port 12335 (V1), 12336 (V2)"
    fi
}

# ═══════════════════════════════════════════════════════════════════════════════
# DASHBOARD INSTALLATION
# ═══════════════════════════════════════════════════════════════════════════════

install_dashboard() {
    log_step "Installing Spiral Dash"

    local DASH_DIR="$INSTALL_DIR/dashboard"

    if [[ ! -d "$SCRIPT_DIR/src/dashboard" ]]; then
        log_warn "Dashboard source not found at $SCRIPT_DIR/src/dashboard, skipping..."
        return
    fi

    if [[ ! -f "$SCRIPT_DIR/src/dashboard/requirements.txt" ]]; then
        log_warn "Dashboard requirements.txt not found, skipping..."
        return
    fi

    if [[ ! -f "$SCRIPT_DIR/src/dashboard/dashboard.py" ]]; then
        log_warn "Dashboard main file (dashboard.py) not found, skipping..."
        return
    fi

    sudo mkdir -p "$DASH_DIR"
    sudo cp -r "$SCRIPT_DIR/src/dashboard/"* "$DASH_DIR/"
    sudo chown -R "$POOL_USER:$POOL_USER" "$DASH_DIR"

    log "Creating Python virtual environment..."
    sudo -u "$POOL_USER" python3 -m venv "$DASH_DIR/venv"

    log "Installing Python dependencies..."
    sudo -u "$POOL_USER" "$DASH_DIR/venv/bin/pip" install --upgrade pip -q 2>/dev/null
    if ! sudo -u "$POOL_USER" "$DASH_DIR/venv/bin/pip" install -r "$DASH_DIR/requirements.txt" -q 2>/dev/null; then
        log_warn "Some dashboard dependencies may have failed to install"
    fi

    # Create data directory for dashboard auth
    sudo mkdir -p "$DASH_DIR/data"
    sudo chown "$POOL_USER:$POOL_USER" "$DASH_DIR/data"
    sudo chmod 700 "$DASH_DIR/data"

    # Create service
    sudo tee /etc/systemd/system/spiraldash.service > /dev/null << EOF
[Unit]
Description=Spiral Dash - Mining Pool Dashboard
After=network-online.target spiralstratum.service
# Prevent restart loops: max 5 restarts in 10 minutes
# R-11 FIX: Increased from 300s to 600s — dashboard depends on stratum, which
# can take 5+ minutes after cold boot. 300s was too aggressive.
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=simple
User=$POOL_USER
Group=$POOL_USER
WorkingDirectory=$DASH_DIR
ExecStart=$DASH_DIR/venv/bin/gunicorn --bind 0.0.0.0:$DASHBOARD_PORT --workers 1 --threads 4 --timeout 120 dashboard:app

# === INSTALLATION PATHS ===
# Tell dashboard where to find data files (miners.json, etc.)
Environment="SPIRALPOOL_INSTALL_DIR=$INSTALL_DIR"

# === POOL API & METRICS ===
# Metrics auth token for Prometheus /metrics endpoint on Spiral Stratum
Environment="SPIRAL_METRICS_TOKEN=$METRICS_TOKEN"

# === DASHBOARD AUTHENTICATION ===
# Dashboard requires authentication by default (set password on first access)
Environment="DASHBOARD_AUTH_ENABLED=true"
Environment="DASHBOARD_SESSION_LIFETIME=24"
# Optional: Set API key for programmatic access (uncomment and set your own key)
# Environment="DASHBOARD_API_KEY=your-secure-api-key-here"
# Optional: Set allowed CORS origins (empty = same-origin only, most secure)
# Environment="DASHBOARD_CORS_ORIGINS="

# === SELF-HEALING / AUTO-RESTART ===
# Restart=always ensures service restarts on any exit (crash, kill, clean exit)
Restart=always
RestartSec=10
TimeoutStopSec=30
# Note: WatchdogSec removed - Flask doesn't implement sd_notify

# === SECURITY HARDENING ===
PrivateTmp=yes
ProtectSystem=strict
ProtectHome=yes
ReadWritePaths=$DASH_DIR $INSTALL_DIR/config $INSTALL_DIR/data /home/$POOL_USER/.spiralpool
# NoNewPrivileges must be 'no' — dashboard uses sudo systemctl restart/stop
# for service control via web UI. sudo is a setuid binary that requires
# privilege escalation. Allowed commands are restricted via sudoers rules
# in /etc/sudoers.d/spiralpool-dashboard (created below).
NoNewPrivileges=no
ProtectKernelTunables=yes
ProtectKernelModules=yes
ProtectControlGroups=yes

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    # HA backup: do NOT enable spiraldash — ha-role-watcher manages it on promotion.
    # Enabling it would cause systemd to auto-start it on reboot before the watcher can stop it.
    if [[ "$HA_MODE" != "ha-backup" ]]; then
        sudo systemctl enable spiraldash || true
    fi

    # Set up sudoers for dashboard service control (allows restart from web UI)
    local DASH_SUDOERS="/etc/sudoers.d/spiralpool-dashboard"
    log "Configuring dashboard service control permissions..."
    sudo tee "$DASH_SUDOERS" > /dev/null << SUDOERS_EOF
# Spiral Pool Dashboard - Service control permissions
# Allows the dashboard and wallet generator to control pool services
# These are the ONLY commands the pool user can run with sudo

# Pool service control (stratum + sentinel) - start, stop, restart, enable
$POOL_USER ALL=(ALL) NOPASSWD: /bin/systemctl start spiralstratum
