        "currency_symbol": "${POWER_SYMBOL:-\$}",
        "rate_per_kwh": ${POWER_RATE:-0.12},
        "is_free_power": ${IS_FREE_POWER:-false}
    }
}
EOF
        sudo chown "$POOL_USER:$POOL_USER" "$DASH_CONFIG_FILE"
        sudo chmod 600 "$DASH_CONFIG_FILE"
        log "Dashboard config created with power cost settings"
    fi

    log_success "Dashboard installed"
