# ═══════════════════════════════════════════════════════════════════════════════
# SENTINEL INSTALLATION
# ═══════════════════════════════════════════════════════════════════════════════

install_sentinel() {
    log_step "Installing Spiral Sentinel"

    local SENTINEL_SRC="$SCRIPT_DIR/src/sentinel/SpiralSentinel.py"

    log "Looking for Sentinel at: $SENTINEL_SRC"

    if [[ ! -f "$SENTINEL_SRC" ]]; then
        log_warn "Sentinel source not found at $SENTINEL_SRC"
        log "Available files in $SCRIPT_DIR/src/sentinel/:"
        ls -la "$SCRIPT_DIR/src/sentinel/" 2>/dev/null || log "  (directory not found)"
        log_warn "Skipping Sentinel installation..."
        return 0
    fi

    # If XMPP is configured, create a venv and install slixmpp
    if [[ -n "$XMPP_JID" ]]; then
        log "Creating Sentinel Python venv for XMPP support..."
        sudo -u "$POOL_USER" python3 -m venv "$INSTALL_DIR/sentinel-venv"
        sudo -u "$POOL_USER" "$INSTALL_DIR/sentinel-venv/bin/pip" install --upgrade pip -q 2>/dev/null
        if sudo -u "$POOL_USER" "$INSTALL_DIR/sentinel-venv/bin/pip" install slixmpp -q 2>/dev/null; then
            log_success "slixmpp installed for XMPP notifications"
            SENTINEL_PYTHON="$INSTALL_DIR/sentinel-venv/bin/python3"
        else
            log_warn "Failed to install slixmpp - XMPP notifications will not work"
            SENTINEL_PYTHON="/usr/bin/python3"
        fi
    else
        # No XMPP - use system Python (zero dependencies)
        SENTINEL_PYTHON="/usr/bin/python3"
    fi

    # Ensure bin directory exists (owned by pool user for easy updates)
    sudo mkdir -p "$INSTALL_DIR/bin"
    sudo chown "$POOL_USER:$POOL_USER" "$INSTALL_DIR/bin"
    sudo chmod 775 "$INSTALL_DIR/bin"

    log "Copying Sentinel from $SENTINEL_SRC..."
    if ! sudo cp "$SENTINEL_SRC" "$INSTALL_DIR/bin/"; then
        log_error "Failed to copy Sentinel to $INSTALL_DIR/bin/"
        return 1
    fi
    sudo chmod +x "$INSTALL_DIR/bin/SpiralSentinel.py"
    sudo chown "$POOL_USER:$POOL_USER" "$INSTALL_DIR/bin/SpiralSentinel.py"

    # Create Sentinel config directory
    sudo -u "$POOL_USER" mkdir -p "/home/$POOL_USER/.spiralsentinel"

    # Create Sentinel config.json with user settings
    local SENTINEL_CONFIG="/home/$POOL_USER/.spiralsentinel/config.json"

    # Determine telegram enabled status
    local TELEGRAM_ENABLED="false"
    if [[ -n "$TELEGRAM_BOT_TOKEN" ]] && [[ -n "$TELEGRAM_CHAT_ID" ]]; then
        TELEGRAM_ENABLED="true"
    fi

    # Determine XMPP enabled status
    local XMPP_ENABLED="false"
    if [[ -n "$XMPP_JID" ]] && [[ -n "$XMPP_PASSWORD" ]] && [[ -n "$XMPP_RECIPIENT" ]]; then
        XMPP_ENABLED="true"
    fi

    # Map collected wallet addresses to Sentinel config variables
    # - Single-coin mode: Sets POOL_ADDRESS (DGB) or *_ADDRESS directly - no mapping needed
    # - Multi-coin mode: Sets *_POOL_ADDRESS variables, need to map to *_ADDRESS for Sentinel
    # This ensures Sentinel's wallet_address matches stratum's pool address (same destination
    # for block rewards and balance monitoring in solo/instant-payout mode)
    [[ -n "$DGB_POOL_ADDRESS" ]] && POOL_ADDRESS="$DGB_POOL_ADDRESS"
    [[ -n "$BTC_POOL_ADDRESS" ]] && BTC_ADDRESS="$BTC_POOL_ADDRESS"
    [[ -n "$BCH_POOL_ADDRESS" ]] && BCH_ADDRESS="$BCH_POOL_ADDRESS"
    [[ -n "$BC2_POOL_ADDRESS" ]] && BC2_ADDRESS="$BC2_POOL_ADDRESS"
    [[ -n "$LTC_POOL_ADDRESS" ]] && LTC_ADDRESS="$LTC_POOL_ADDRESS"
    [[ -n "$DOGE_POOL_ADDRESS" ]] && DOGE_ADDRESS="$DOGE_POOL_ADDRESS"
    [[ -n "$PEP_POOL_ADDRESS" ]] && PEP_ADDRESS="$PEP_POOL_ADDRESS"
    [[ -n "$CAT_POOL_ADDRESS" ]] && CAT_ADDRESS="$CAT_POOL_ADDRESS"
    [[ -n "$NMC_POOL_ADDRESS" ]] && NMC_ADDRESS="$NMC_POOL_ADDRESS"
    [[ -n "$SYS_POOL_ADDRESS" ]] && SYS_ADDRESS="$SYS_POOL_ADDRESS"
    [[ -n "$XMY_POOL_ADDRESS" ]] && XMY_ADDRESS="$XMY_POOL_ADDRESS"
    [[ -n "$FBTC_POOL_ADDRESS" ]] && FBTC_ADDRESS="$FBTC_POOL_ADDRESS"
    [[ -n "$QBX_POOL_ADDRESS" ]] && QBX_ADDRESS="$QBX_POOL_ADDRESS"

    # Set POOL_ADDRESS to primary coin's wallet if not already set (for non-DGB installs)
    # This determines which wallet fills the legacy singular wallet_address field
    # when multiple coins are enabled. Does NOT affect mining or rewards.
    # SHA-256d: DGB > BTC > BCH > BC2 > others
    # Scrypt:   LTC > DOGE > PEP > DGB_SCRYPT > CAT
    if [[ -z "$POOL_ADDRESS" ]]; then
        # SHA-256d coins
        if [[ "${ENABLE_BTC:-false}" == "true" ]] && [[ -n "$BTC_ADDRESS" ]] && [[ "$BTC_ADDRESS" != "PENDING_GENERATION" ]]; then
            POOL_ADDRESS="$BTC_ADDRESS"
        elif [[ "${ENABLE_BCH:-false}" == "true" ]] && [[ -n "$BCH_ADDRESS" ]] && [[ "$BCH_ADDRESS" != "PENDING_GENERATION" ]]; then
            POOL_ADDRESS="$BCH_ADDRESS"
        elif [[ "${ENABLE_BC2:-false}" == "true" ]] && [[ -n "$BC2_ADDRESS" ]] && [[ "$BC2_ADDRESS" != "PENDING_GENERATION" ]]; then
            POOL_ADDRESS="$BC2_ADDRESS"
        # Scrypt coins
        elif [[ "${ENABLE_LTC:-false}" == "true" ]] && [[ -n "$LTC_ADDRESS" ]] && [[ "$LTC_ADDRESS" != "PENDING_GENERATION" ]]; then
            POOL_ADDRESS="$LTC_ADDRESS"
        elif [[ "${ENABLE_DOGE:-false}" == "true" ]] && [[ -n "$DOGE_ADDRESS" ]] && [[ "$DOGE_ADDRESS" != "PENDING_GENERATION" ]]; then
            POOL_ADDRESS="$DOGE_ADDRESS"
        elif [[ "${ENABLE_PEP:-false}" == "true" ]] && [[ -n "$PEP_ADDRESS" ]] && [[ "$PEP_ADDRESS" != "PENDING_GENERATION" ]]; then
            POOL_ADDRESS="$PEP_ADDRESS"
        elif [[ "${ENABLE_DGB_SCRYPT:-false}" == "true" ]] && [[ -n "$DGB_SCRYPT_ADDRESS" ]] && [[ "$DGB_SCRYPT_ADDRESS" != "PENDING_GENERATION" ]]; then
            POOL_ADDRESS="$DGB_SCRYPT_ADDRESS"
        elif [[ "${ENABLE_CAT:-false}" == "true" ]] && [[ -n "$CAT_ADDRESS" ]] && [[ "$CAT_ADDRESS" != "PENDING_GENERATION" ]]; then
            POOL_ADDRESS="$CAT_ADDRESS"
        fi
    fi

    # UPGRADE SAFETY: Preserve existing config if it has user settings
    # Only overwrite if: no config exists, or config has empty webhook AND user provided one
    if [[ -f "$SENTINEL_CONFIG" ]]; then
        local EXISTING_WEBHOOK
        EXISTING_WEBHOOK=$(grep -o '"discord_webhook_url"[[:space:]]*:[[:space:]]*"[^"]*"' "$SENTINEL_CONFIG" 2>/dev/null | sed 's/.*: *"//' | sed 's/"$//')

        if [[ -n "$EXISTING_WEBHOOK" ]] && [[ "$EXISTING_WEBHOOK" != "" ]]; then
            # Existing config has a webhook - preserve it, update key settings
            log "Preserving existing Sentinel config (has webhook configured)"
            # Update pool_api_url, currency, power, wallet settings from installer
            # Validate no interpolated values contain chars that could break Python string literals
            local _sentinel_update_safe=true
            for _addr_var in POOL_ADDRESS ADMIN_API_KEY BTC_ADDRESS BCH_ADDRESS BC2_ADDRESS \
                             LTC_ADDRESS DOGE_ADDRESS DGB_SCRYPT_ADDRESS PEP_ADDRESS CAT_ADDRESS \
                             NMC_ADDRESS SYS_ADDRESS XMY_ADDRESS FBTC_ADDRESS DISPLAY_TIMEZONE; do
                local _addr_val="${!_addr_var:-}"
                if [[ "$_addr_val" =~ [\'\"\\\`\$] ]]; then
                    log_error "Variable $_addr_var contains unsafe characters — skipping sentinel config update"
                    _sentinel_update_safe=false
                    break
                fi
            done
            [[ "$_sentinel_update_safe" == "true" ]] && \
            sudo -u "$POOL_USER" python3 -c "
import json
with open('$SENTINEL_CONFIG', 'r') as f:
    cfg = json.load(f)

# Core settings
cfg['pool_api_url'] = 'http://localhost:$API_PORT'
cfg['pool_admin_api_key'] = '$ADMIN_API_KEY'
cfg['push_device_hints'] = True
cfg['report_currency'] = '${REPORT_CURRENCY:-CAD}'
cfg['alert_theme'] = '${ALERT_THEME:-cyberpunk}'
cfg['power_currency'] = '${POWER_CURRENCY:-CAD}'
cfg['power_rate_kwh'] = ${POWER_RATE:-0.12}
cfg['display_timezone'] = '$DISPLAY_TIMEZONE'
cfg['expected_fleet_ths'] = $EXPECTED_THS

# Wallet address - use primary coin address
cfg['wallet_address'] = '$POOL_ADDRESS'

# Multi-coin settings - all 12 coins
enable_dgb = '${ENABLE_DGB:-false}' == 'true'
enable_btc = '${ENABLE_BTC:-false}' == 'true'
enable_bch = '${ENABLE_BCH:-false}' == 'true'
enable_bc2 = '${ENABLE_BC2:-false}' == 'true'
enable_ltc = '${ENABLE_LTC:-false}' == 'true'
enable_doge = '${ENABLE_DOGE:-false}' == 'true'
enable_dgb_scrypt = '${ENABLE_DGB_SCRYPT:-false}' == 'true'
enable_pep = '${ENABLE_PEP:-false}' == 'true'
enable_cat = '${ENABLE_CAT:-false}' == 'true'
enable_nmc = '${ENABLE_NMC:-false}' == 'true'
enable_sys = '${ENABLE_SYS:-false}' == 'true'
enable_xmy = '${ENABLE_XMY:-false}' == 'true'
enable_fbtc = '${ENABLE_FBTC:-false}' == 'true'
enable_qbx = '${ENABLE_QBX:-false}' == 'true'

enabled_count = sum([enable_dgb, enable_btc, enable_bch, enable_bc2, enable_nmc, enable_sys, enable_xmy, enable_fbtc, enable_qbx, enable_ltc, enable_doge, enable_dgb_scrypt, enable_pep, enable_cat])
is_multi_coin = enabled_count > 1

cfg['multi_coin_enabled'] = is_multi_coin

# Determine primary pool_id (first enabled coin for display purposes)
# NOTE: Pool IDs use _1 suffix to match stratum pool config
# This only affects which pool stats are shown first - does NOT affect mining/rewards
# SHA-256d: DGB > BTC > BCH > BC2 > others
# Scrypt:   LTC > DOGE > PEP > DGB_SCRYPT > CAT
if enable_dgb:
    cfg['pool_id'] = 'dgb_sha256_1'
elif enable_btc:
    cfg['pool_id'] = 'btc_sha256_1'
elif enable_bch:
    cfg['pool_id'] = 'bch_sha256_1'
elif enable_bc2:
    cfg['pool_id'] = 'bc2_sha256_1'
elif enable_ltc:
    cfg['pool_id'] = 'ltc_scrypt_1'
elif enable_doge:
    cfg['pool_id'] = 'doge_scrypt_1'
elif enable_nmc:
    cfg['pool_id'] = 'nmc_sha256_1'
elif enable_sys:
    cfg['pool_id'] = 'sys_sha256_1'
elif enable_xmy:
    cfg['pool_id'] = 'xmy_sha256_1'
elif enable_fbtc:
    cfg['pool_id'] = 'fbtc_sha256_1'
elif enable_qbx:
    cfg['pool_id'] = 'qbx_sha256_1'
elif enable_pep:
    cfg['pool_id'] = 'pep_scrypt_1'
elif enable_dgb_scrypt:
    cfg['pool_id'] = 'dgb_scrypt_1'
elif enable_cat:
    cfg['pool_id'] = 'cat_scrypt_1'

# Update coins array with actual wallet addresses and enabled status
coins = cfg.get('coins', [])
for coin in coins:
    sym = coin.get('symbol', '')
    if sym == 'DGB':
        coin['enabled'] = enable_dgb
        if '$POOL_ADDRESS' and '$POOL_ADDRESS' != 'PENDING_GENERATION':
            coin['wallet_address'] = '$POOL_ADDRESS'
    elif sym == 'BTC':
        coin['enabled'] = enable_btc
        if '${BTC_ADDRESS:-}' and '${BTC_ADDRESS:-}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${BTC_ADDRESS:-}'
    elif sym == 'BCH':
        coin['enabled'] = enable_bch
        if '${BCH_ADDRESS:-}' and '${BCH_ADDRESS:-}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${BCH_ADDRESS:-}'
    elif sym == 'BC2':
        coin['enabled'] = enable_bc2
        if '${BC2_ADDRESS:-}' and '${BC2_ADDRESS:-}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${BC2_ADDRESS:-}'
    elif sym == 'LTC':
        coin['enabled'] = enable_ltc
        if '${LTC_ADDRESS:-}' and '${LTC_ADDRESS:-}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${LTC_ADDRESS:-}'
    elif sym == 'DOGE':
        coin['enabled'] = enable_doge
        if '${DOGE_ADDRESS:-}' and '${DOGE_ADDRESS:-}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${DOGE_ADDRESS:-}'
    elif sym == 'DGB-SCRYPT':
        coin['enabled'] = enable_dgb_scrypt
        if '${DGB_SCRYPT_ADDRESS:-$POOL_ADDRESS}' and '${DGB_SCRYPT_ADDRESS:-$POOL_ADDRESS}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${DGB_SCRYPT_ADDRESS:-$POOL_ADDRESS}'
    elif sym == 'PEP':
        coin['enabled'] = enable_pep
        if '${PEP_ADDRESS:-}' and '${PEP_ADDRESS:-}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${PEP_ADDRESS:-}'
    elif sym == 'CAT':
        coin['enabled'] = enable_cat
        if '${CAT_ADDRESS:-}' and '${CAT_ADDRESS:-}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${CAT_ADDRESS:-}'
    elif sym == 'NMC':
        coin['enabled'] = enable_nmc
        if '${NMC_ADDRESS:-}' and '${NMC_ADDRESS:-}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${NMC_ADDRESS:-}'
    elif sym == 'SYS':
        coin['enabled'] = enable_sys
        if '${SYS_ADDRESS:-}' and '${SYS_ADDRESS:-}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${SYS_ADDRESS:-}'
    elif sym == 'XMY':
        coin['enabled'] = enable_xmy
        if '${XMY_ADDRESS:-}' and '${XMY_ADDRESS:-}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${XMY_ADDRESS:-}'
    elif sym == 'FBTC':
        coin['enabled'] = enable_fbtc
        if '${FBTC_ADDRESS:-}' and '${FBTC_ADDRESS:-}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${FBTC_ADDRESS:-}'
    elif sym == 'QBX':
        coin['enabled'] = enable_qbx
        if '${QBX_ADDRESS:-}' and '${QBX_ADDRESS:-}' != 'PENDING_GENERATION':
            coin['wallet_address'] = '${QBX_ADDRESS:-}'
cfg['coins'] = coins

with open('$SENTINEL_CONFIG', 'w') as f:
    json.dump(cfg, f, indent=2)
" 2>/dev/null || true
            sudo chmod 600 "$SENTINEL_CONFIG"
            sudo chown "$POOL_USER:$POOL_USER" "$SENTINEL_CONFIG"
        else
            # Existing config has empty webhook - safe to overwrite if user provided one
            log "Updating Sentinel config (existing had no webhook)"
            # Determine multi-coin status (count all 12 supported coins)
            local IS_MULTI_COIN="false"
            local ENABLED_COUNT=0
            [[ "${ENABLE_DGB:-false}" == "true" ]] && ((ENABLED_COUNT++)) || true
            [[ "${ENABLE_BTC:-false}" == "true" ]] && ((ENABLED_COUNT++)) || true
            [[ "${ENABLE_BCH:-false}" == "true" ]] && ((ENABLED_COUNT++)) || true
            [[ "${ENABLE_BC2:-false}" == "true" ]] && ((ENABLED_COUNT++)) || true
            [[ "${ENABLE_LTC:-false}" == "true" ]] && ((ENABLED_COUNT++)) || true
            [[ "${ENABLE_DOGE:-false}" == "true" ]] && ((ENABLED_COUNT++)) || true
            [[ "${ENABLE_DGB_SCRYPT:-false}" == "true" ]] && ((ENABLED_COUNT++)) || true
            [[ "${ENABLE_PEP:-false}" == "true" ]] && ((ENABLED_COUNT++)) || true
            [[ "${ENABLE_CAT:-false}" == "true" ]] && ((ENABLED_COUNT++)) || true
            [[ "${ENABLE_NMC:-false}" == "true" ]] && ((ENABLED_COUNT++)) || true
            [[ "${ENABLE_SYS:-false}" == "true" ]] && ((ENABLED_COUNT++)) || true
