[Unit]
Description=Spiral Sentinel - Mining Monitor
After=network-online.target spiralstratum.service
# Prevent restart loops: max 3 restarts in 10 minutes (monitor is less critical)
StartLimitIntervalSec=600
StartLimitBurst=3

[Service]
Type=simple
User=$POOL_USER
Group=$POOL_USER
# Explicitly set HOME so Python's Path.home() resolves correctly
Environment="HOME=/home/$POOL_USER"
# Force unbuffered Python output so logs appear in journalctl immediately
Environment="PYTHONUNBUFFERED=1"
# Tell Sentinel where to find data files (miners.json, etc.)
Environment="SPIRALPOOL_INSTALL_DIR=$INSTALL_DIR"
WorkingDirectory=$INSTALL_DIR
# -u flag ensures unbuffered stdout/stderr for real-time logging
ExecStart=$SENTINEL_PYTHON -u $INSTALL_DIR/bin/SpiralSentinel.py
# Capture all output to systemd journal
StandardOutput=journal
StandardError=journal

# === SELF-HEALING / AUTO-RESTART ===
# Restart=always ensures service restarts on any exit (crash, kill, clean exit)
Restart=always
RestartSec=30
TimeoutStopSec=30
# Note: WatchdogSec removed - Python doesn't implement sd_notify

# === SECURITY HARDENING ===
PrivateTmp=yes
ProtectSystem=strict
ProtectHome=yes
RuntimeDirectory=spiralpool
RuntimeDirectoryPreserve=yes
ReadWritePaths=$INSTALL_DIR /home/$POOL_USER/.spiralsentinel /run/spiralpool
NoNewPrivileges=yes
ProtectKernelTunables=yes
ProtectKernelModules=yes
ProtectControlGroups=yes

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true

    # Ensure Sentinel data directory exists BEFORE service start
    # systemd's ProtectHome=yes + ReadWritePaths requires the directory to exist
    # on the real filesystem for the bind mount to succeed
    sudo mkdir -p "/home/$POOL_USER/.spiralsentinel"
    sudo chown "$POOL_USER:$POOL_USER" "/home/$POOL_USER/.spiralsentinel"

    # Enable Sentinel if any notification method is configured
    # HA backup: do NOT enable — ha-role-watcher manages sentinel on promotion.
    # Enabling it would cause systemd to auto-start it on reboot before the watcher can stop it.
    if [[ -n "$DISCORD_WEBHOOK" ]] || [[ -n "$TELEGRAM_BOT_TOKEN" ]] || [[ -n "$XMPP_JID" ]]; then
        if [[ "$HA_MODE" != "ha-backup" ]]; then
            sudo systemctl enable spiralsentinel || true
        fi
        local notify_methods=""
        [[ -n "$DISCORD_WEBHOOK" ]] && notify_methods="Discord"
        [[ -n "$TELEGRAM_BOT_TOKEN" ]] && notify_methods="${notify_methods:+$notify_methods + }Telegram"
        [[ -n "$XMPP_JID" ]] && notify_methods="${notify_methods:+$notify_methods + }XMPP"
        log_success "Sentinel installed and enabled ($notify_methods notifications active)"
    else
        log_success "Sentinel installed (configure notifications in $INSTALL_DIR/config/sentinel/config.json to enable)"
    fi
    mark_progress "sentinel"
}

# ═══════════════════════════════════════════════════════════════════════════════
# HEALTH MONITOR
# ═══════════════════════════════════════════════════════════════════════════════

install_health_monitor() {
    log_step "Installing Health Monitor"

    sudo tee "$INSTALL_DIR/bin/health-monitor.sh" > /dev/null << 'HEALTHEOF'
#!/bin/bash
#
# Spiral Pool Health Monitor - Self-Healing Service Watchdog
# Monitors all pool services and performs automatic restarts
# Includes: disk space, memory, blockchain sync, and service monitoring
#

INSTALL_DIR="/spiralpool"
# Multi-disk support: load CHAIN_MOUNT_POINT so get_blockchain_dir returns the right path
MULTI_DISK_CONFIGURED="false"; CHAIN_MOUNT_POINT=""
_env="$INSTALL_DIR/config/coins.env"
if [[ -f "$_env" ]] && [[ ! -L "$_env" ]]; then
    MULTI_DISK_CONFIGURED=$(grep -oP '^MULTI_DISK_CONFIGURED=\K(true|false)$' "$_env" 2>/dev/null || echo "false")
    CHAIN_MOUNT_POINT=$(grep -oP '^CHAIN_MOUNT_POINT=\K\S+$' "$_env" 2>/dev/null || echo "")
fi
get_blockchain_dir() { local c="$1"; if [[ "$MULTI_DISK_CONFIGURED" == "true" && -n "$CHAIN_MOUNT_POINT" && -d "$CHAIN_MOUNT_POINT" ]]; then echo "$CHAIN_MOUNT_POINT/$c"; else echo "$INSTALL_DIR/$c"; fi; }
LOG_FILE="$INSTALL_DIR/logs/health-monitor.log"
CHECK_INTERVAL=60
MAX_RESTART_ATTEMPTS=3
DISK_WARNING_PERCENT=85
DISK_CRITICAL_PERCENT=95
MEMORY_WARNING_PERCENT=90
declare -A restart_counts

# Core services (always monitored)
# Detect correct PostgreSQL manager: Patroni (HA) or standalone postgresql
if systemctl is-enabled --quiet "patroni" 2>/dev/null; then
    CORE_SERVICES=("patroni")
else
    CORE_SERVICES=("postgresql")
fi

# HA services (monitored if enabled)
for ha_svc in etcd keepalived redis-server; do
    if systemctl is-enabled --quiet "$ha_svc" 2>/dev/null; then
        CORE_SERVICES+=("$ha_svc")
    fi
done

# Blockchain daemon services (added if enabled)
for daemon in digibyted bitcoind bitcoind-bch bitcoiniid litecoind dogecoind pepecoind catcoind namecoind syscoind myriadcoind fractald; do
    if systemctl is-enabled --quiet "$daemon" 2>/dev/null; then
        CORE_SERVICES+=("$daemon")
    fi
done

# Pool services (only after sync)
POOL_SERVICES=("spiralstratum")

# Optional services (monitored if enabled)
OPTIONAL_SERVICES=("spiraldash" "spiralsentinel")

log() { echo "[$(date '+%Y-%m-%d %H:%M:%S')] $1" | tee -a "$LOG_FILE"; }

service_exists() { [[ -f "/etc/systemd/system/$1.service" ]] || systemctl cat "$1.service" &>/dev/null; }
service_enabled() { systemctl is-enabled --quiet "$1" 2>/dev/null; }
check_service() { systemctl is-active --quiet "$1"; }

restart_service() {
    local service=$1
    local count=${restart_counts[$service]:-0}
    if [[ $count -ge $MAX_RESTART_ATTEMPTS ]]; then
        log "ERROR: $service failed $MAX_RESTART_ATTEMPTS times this hour - manual intervention required"
        return 1
    fi
    log "WARNING: $service down, restarting (attempt $((count+1))/$MAX_RESTART_ATTEMPTS)"

    # Force stop first - services tend to hang during shutdown
    sudo /bin/systemctl stop "$service" 2>/dev/null
    sleep 2

    # Force kill any remaining processes (especially for spiralstratum)
    if [[ "$service" == "spiralstratum" ]]; then
        sudo /usr/bin/pkill -9 -f spiralstratum 2>/dev/null
        sleep 1
    fi

    # Now start fresh
    sudo /bin/systemctl start "$service"
    sleep 10
    if check_service "$service"; then
        log "SUCCESS: $service restarted successfully"
        restart_counts[$service]=0
    else
        restart_counts[$service]=$((count+1))
        log "FAILED: $service restart attempt failed"
    fi
}

# Check if a specific blockchain is synced
is_daemon_synced() {
    local cli=$1
    local conf=$2
    local info progress ibd
    info=$(timeout 10 "$cli" -conf="$conf" getblockchaininfo 2>/dev/null)
    [[ -z "$info" ]] && return 1
    # Primary check: initialblockdownload=false is authoritative (works for all chains including BC2)
    ibd=$(echo "$info" | grep -o '"initialblockdownload":[^,]*' | cut -d: -f2 | tr -d ' ')
    [[ "$ibd" == "false" ]] && return 0
    # Fallback: verificationprogress >= 0.9999 for older daemons
    progress=$(echo "$info" | grep -o '"verificationprogress":[^,]*' | cut -d: -f2)
    [[ -z "$progress" ]] && return 1
    echo "$progress" | awk '{exit ($1 >= 0.9999) ? 0 : 1}'
}

# Check if any enabled blockchain is synced (for stratum readiness)
is_blockchain_synced() {
    # Check each enabled blockchain daemon
    if service_enabled "digibyted" && is_daemon_synced "digibyte-cli" "$(get_blockchain_dir dgb)/digibyte.conf"; then
        return 0
    fi
    if service_enabled "bitcoind" && is_daemon_synced "bitcoin-cli" "$(get_blockchain_dir btc)/bitcoin.conf"; then
        return 0
    fi
    if service_enabled "bitcoind-bch" && is_daemon_synced "bitcoin-cli-bch" "$(get_blockchain_dir bch)/bitcoin.conf"; then
        return 0
    fi
    # Bitcoin II (BC2) - uses bitcoinii-cli
    if service_enabled "bitcoiniid" && is_daemon_synced "bitcoinii-cli" "$(get_blockchain_dir bc2)/bitcoinii.conf"; then
        return 0
    fi
    if service_enabled "litecoind" && is_daemon_synced "litecoin-cli" "$(get_blockchain_dir ltc)/litecoin.conf"; then
        return 0
    fi
    if service_enabled "dogecoind" && is_daemon_synced "dogecoin-cli" "$(get_blockchain_dir doge)/dogecoin.conf"; then
        return 0
    fi
    if service_enabled "pepecoind" && is_daemon_synced "pepecoin-cli" "$(get_blockchain_dir pep)/pepecoin.conf"; then
        return 0
    fi
    if service_enabled "catcoind" && is_daemon_synced "catcoin-cli" "$(get_blockchain_dir cat)/catcoin.conf"; then
        return 0
    fi
    # SHA-256d AuxPoW coins
    if service_enabled "namecoind" && is_daemon_synced "namecoin-cli" "$(get_blockchain_dir nmc)/namecoin.conf"; then
        return 0
    fi
    if service_enabled "syscoind" && is_daemon_synced "syscoin-cli" "$(get_blockchain_dir sys)/syscoin.conf"; then
        return 0
    fi
    if service_enabled "myriadcoind" && is_daemon_synced "myriadcoin-cli" "$(get_blockchain_dir xmy)/myriadcoin.conf"; then
        return 0
    fi
    if service_enabled "fractald" && is_daemon_synced "fractal-cli" "$(get_blockchain_dir fbtc)/fractal.conf"; then
        return 0
    fi
    if service_enabled "qbitxd" && is_daemon_synced "qbitx-cli" "$(get_blockchain_dir qbx)/qbitx.conf"; then
        return 0
    fi
    return 1
}

check_stratum_health() {
    # Only check stratum if blockchain is synced and service is enabled
    if ! service_enabled "spiralstratum"; then
        return
    fi

    if ! is_blockchain_synced; then
        # Blockchain not synced - stratum shouldn't be running
        return
    fi

    # Check if stratum service is running
    if ! check_service "spiralstratum"; then
        log "WARNING: Spiral Stratum not running (blockchain synced)"
        restart_service "spiralstratum"
        return
    fi

    # Check stratum ports - in multi-coin mode, check all enabled coin ports
    # In single-coin mode, just check the configured port
    local COIN_MODE STRATUM_PORT
    local ports_to_check=()

    if [[ -f "$INSTALL_DIR/config/coins.env" ]] && [[ ! -L "$INSTALL_DIR/config/coins.env" ]]; then
        # Safe parsing — extract only expected values (no arbitrary code execution)
        COIN_MODE=$(grep -oP '^COIN_MODE=\K(single|multi)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "single")
        STRATUM_PORT=$(grep -oP '^STRATUM_PORT=\K[0-9]+$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "")
        ENABLE_DGB=$(grep -oP '^ENABLE_DGB=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_BTC=$(grep -oP '^ENABLE_BTC=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_BCH=$(grep -oP '^ENABLE_BCH=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_BC2=$(grep -oP '^ENABLE_BC2=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_LTC=$(grep -oP '^ENABLE_LTC=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_DOGE=$(grep -oP '^ENABLE_DOGE=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_DGB_SCRYPT=$(grep -oP '^ENABLE_DGB_SCRYPT=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_PEP=$(grep -oP '^ENABLE_PEP=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_CAT=$(grep -oP '^ENABLE_CAT=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_NMC=$(grep -oP '^ENABLE_NMC=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_SYS=$(grep -oP '^ENABLE_SYS=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_XMY=$(grep -oP '^ENABLE_XMY=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_FBTC=$(grep -oP '^ENABLE_FBTC=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")
        ENABLE_QBX=$(grep -oP '^ENABLE_QBX=\K(true|false)$' "$INSTALL_DIR/config/coins.env" 2>/dev/null || echo "false")

        if [[ "$COIN_MODE" == "multi" ]]; then
            # Multi-coin mode: check each enabled coin's port
            [[ "$ENABLE_DGB" == "true" ]] && ports_to_check+=(3333)
            [[ "$ENABLE_BTC" == "true" ]] && ports_to_check+=(4333)
            [[ "$ENABLE_BCH" == "true" ]] && ports_to_check+=(5333)
            [[ "$ENABLE_BC2" == "true" ]] && ports_to_check+=(6333)
            [[ "$ENABLE_LTC" == "true" ]] && ports_to_check+=(7333)
            [[ "$ENABLE_DOGE" == "true" ]] && ports_to_check+=(8335)
            [[ "$ENABLE_DGB_SCRYPT" == "true" ]] && ports_to_check+=(3336)
            [[ "$ENABLE_PEP" == "true" ]] && ports_to_check+=(10335)
            [[ "$ENABLE_CAT" == "true" ]] && ports_to_check+=(12335)
            [[ "$ENABLE_NMC" == "true" ]] && ports_to_check+=(14335)
            [[ "$ENABLE_SYS" == "true" ]] && ports_to_check+=(15335)
            [[ "$ENABLE_XMY" == "true" ]] && ports_to_check+=(17335)
            [[ "$ENABLE_FBTC" == "true" ]] && ports_to_check+=(18335)
            [[ "$ENABLE_QBX" == "true" ]] && ports_to_check+=(20335)
        else
            # Single-coin mode: use configured port (no default)
            if [[ -n "$STRATUM_PORT" ]]; then
                ports_to_check+=("$STRATUM_PORT")
            fi
        fi
    else
        # No config file - cannot determine port
        log "WARNING: No configuration file found - skipping port check"
        return
    fi

    # Validate we have ports to check
    if [[ ${#ports_to_check[@]} -eq 0 ]]; then
        log "ERROR: No stratum ports configured. Cannot determine port to check."
        log "ERROR: Please configure STRATUM_PORT for your coin."
        return 1
    fi

    # Check if at least one stratum port is listening
    local any_listening=false
    for port in "${ports_to_check[@]}"; do
        if ss -tlnp 2>/dev/null | grep -q ":$port"; then
            any_listening=true
            break
        fi
    done

    if [[ "$any_listening" == "false" ]]; then
        log "WARNING: No stratum ports listening (checked: ${ports_to_check[*]})"
        restart_service "spiralstratum"
        return
    fi

    # CRITICAL: Test actual stratum protocol handshake on first available port
    # This catches the case where TCP port is open but stratum is not responding
    local test_port="${ports_to_check[0]}"
    local stratum_response
    stratum_response=$(echo '{"id":1,"method":"mining.subscribe","params":["health-check/1.0"]}' | \
        timeout 5 nc -w 3 127.0.0.1 $test_port 2>/dev/null | head -1)

    if [[ -z "$stratum_response" ]]; then
        log "CRITICAL: Stratum not responding to mining.subscribe on port $test_port - protocol failure detected"
        log "TCP port open but stratum protocol not responding - forcing restart"
        # Force kill if normal restart doesn't work
        sudo /bin/systemctl stop spiralstratum
        sleep 2
        sudo /usr/bin/pkill -9 -f spiralstratum 2>/dev/null
        sleep 1
        restart_service "spiralstratum"
        return
    fi

    # Verify response contains expected result (subscription confirmation)
    if ! echo "$stratum_response" | grep -q '"result":\[\['; then
        log "WARNING: Stratum returned unexpected response on port $test_port: $stratum_response"
        # Don't restart for malformed response, just log it
    fi

    # Check API health (optional, non-critical)
    local health=$(curl -s -o /dev/null -w "%{http_code}" --max-time 5 http://127.0.0.1:4000/health 2>/dev/null)
    if [[ "$health" != "200" ]] && [[ "$health" != "000" ]]; then
        log "WARNING: Pool API returned HTTP $health"
    fi
}

check_database_health() {
    # Determine correct DB service (Patroni manages PostgreSQL in HA mode)
    local db_service="postgresql"
    if systemctl is-enabled --quiet "patroni" 2>/dev/null; then
        db_service="patroni"
    fi

    if ! systemctl is-active --quiet "$db_service"; then
        log "WARNING: $db_service service not active"
        restart_service "$db_service"
        return
    fi
    # Test actual query (using sudo to run psql as postgres user)
    if ! sudo -u postgres /usr/bin/psql -c "SELECT 1" &>/dev/null; then
        log "WARNING: PostgreSQL not responding to queries (managed by $db_service)"
        restart_service "$db_service"
    fi
}

# Generic blockchain health check function
check_blockchain_daemon_health() {
    local daemon=$1
    local cli=$2
    local conf=$3
    local name=$4

    # Skip if daemon is not enabled
    if ! service_enabled "$daemon"; then
        return 0
    fi

    if ! check_service "$daemon"; then
        log "WARNING: $name daemon not running"
        restart_service "$daemon"
        return
    fi

    # Check if daemon is responsive (30s timeout - blockchain daemons can be slow
    # during heavy chainstate verification / block loading I/O)
    local cli_output
    cli_output=$(timeout 30 "$cli" -conf="$conf" getblockchaininfo 2>&1)
    local cli_exit=$?

    if [[ $cli_exit -eq 0 ]]; then
        # Daemon is responsive and synced/syncing normally
        return 0
    fi

    # Exit code 124 = timeout killed the CLI. This means the daemon accepted the
    # RPC connection but is busy (heavy I/O during block loading / chainstate verify).
    # The process IS alive and working - do NOT restart.
    if [[ $cli_exit -eq 124 ]]; then
        return 0
    fi

    # Check for specific error codes that indicate the daemon is still starting up
    # Error -28: "Loading block index..." / "Loading blocks..." / "Verifying blocks..."
    # Error -1: "Loading wallet..."
    # "Could not connect" / "couldn't connect" = RPC server hasn't started yet
    # These are NOT failures - daemon is actively working
    if echo "$cli_output" | grep -qE "error code: -28|Loading block|Verifying block|Rewinding block|Loading wallet|[Cc]ould not connect|[Cc]ouldn't connect"; then
        # Daemon is starting up / loading - this is normal, don't restart
        return 0
    fi

    log "WARNING: $name daemon not responding"
    # Don't restart immediately - it may be starting up
    sleep 30

    # Recheck
    cli_output=$(timeout 30 "$cli" -conf="$conf" getblockchaininfo 2>&1)
    cli_exit=$?

    if [[ $cli_exit -eq 0 ]]; then
        return 0
    fi

    # Timeout = daemon is busy with heavy I/O, not dead
    if [[ $cli_exit -eq 124 ]]; then
        return 0
    fi

    # Still check for loading states after the wait
    if echo "$cli_output" | grep -qE "error code: -28|Loading block|Verifying block|Rewinding block|Loading wallet|[Cc]ould not connect|[Cc]ouldn't connect"; then
        # Still loading - this is fine for large blockchains
        return 0
    fi

    log "WARNING: $name daemon still not responding, restarting"
    restart_service "$daemon"
}

# Check all enabled blockchain daemons
check_blockchain_health() {
    check_blockchain_daemon_health "digibyted" "digibyte-cli" "$(get_blockchain_dir dgb)/digibyte.conf" "DigiByte"
    check_blockchain_daemon_health "bitcoind" "bitcoin-cli" "$(get_blockchain_dir btc)/bitcoin.conf" "Bitcoin"
    check_blockchain_daemon_health "bitcoind-bch" "bitcoin-cli-bch" "$(get_blockchain_dir bch)/bitcoin.conf" "Bitcoin Cash"
    check_blockchain_daemon_health "bitcoiniid" "bitcoinii-cli" "$(get_blockchain_dir bc2)/bitcoinii.conf" "Bitcoin II"
    check_blockchain_daemon_health "litecoind" "litecoin-cli" "$(get_blockchain_dir ltc)/litecoin.conf" "Litecoin"
    check_blockchain_daemon_health "dogecoind" "dogecoin-cli" "$(get_blockchain_dir doge)/dogecoin.conf" "Dogecoin"
    check_blockchain_daemon_health "pepecoind" "pepecoin-cli" "$(get_blockchain_dir pep)/pepecoin.conf" "PepeCoin"
    check_blockchain_daemon_health "catcoind" "catcoin-cli" "$(get_blockchain_dir cat)/catcoin.conf" "Catcoin"
    # Aux chain daemons (merge mining)
    check_blockchain_daemon_health "namecoind" "namecoin-cli" "$(get_blockchain_dir nmc)/namecoin.conf" "Namecoin"
    check_blockchain_daemon_health "syscoind" "syscoin-cli" "$(get_blockchain_dir sys)/syscoin.conf" "Syscoin"
    check_blockchain_daemon_health "myriadcoind" "myriadcoin-cli" "$(get_blockchain_dir xmy)/myriadcoin.conf" "Myriadcoin"
    check_blockchain_daemon_health "fractald" "fractal-cli" "$(get_blockchain_dir fbtc)/fractal.conf" "Fractal Bitcoin"
    check_blockchain_daemon_health "qbitxd" "qbitx-cli" "$(get_blockchain_dir qbx)/qbitx.conf" "Q-BitX"
}

check_disk_space() {
    local usage=$(df "$INSTALL_DIR" 2>/dev/null | tail -1 | awk '{print $5}' | tr -d '%')
    if [[ -n "$usage" ]]; then
        if [[ $usage -ge $DISK_CRITICAL_PERCENT ]]; then
            log "CRITICAL: Disk usage at ${usage}% - pool may fail!"
        elif [[ $usage -ge $DISK_WARNING_PERCENT ]]; then
            log "WARNING: Disk usage at ${usage}%"
        fi
    fi
}

check_memory() {
    local mem_usage=$(free | awk '/Mem:/ {printf "%.0f", $3/$2 * 100}')
    if [[ -n "$mem_usage" ]] && [[ $mem_usage -ge $MEMORY_WARNING_PERCENT ]]; then
        log "WARNING: Memory usage at ${mem_usage}%"
        # Clear system caches if memory is critical (requires root - skip if not available)
        if [[ $mem_usage -ge 95 ]]; then
            log "CRITICAL: Memory at ${mem_usage}%"
        fi
    fi
}

check_blockchain_sync_status() {
    # If blockchain just finished syncing, ensure stratum gets started
    if is_blockchain_synced; then
        if ! service_enabled "spiralstratum"; then
            log "Blockchain synced - enabling Spiral Stratum"
            sudo /bin/systemctl enable spiralstratum
            sudo /bin/systemctl start spiralstratum
        fi
    fi
}

# Ensure log directory exists
mkdir -p "$(dirname "$LOG_FILE")"

log "=========================================="
log "Health monitor started"
log "=========================================="
log "Monitoring core: ${CORE_SERVICES[*]}"
log "Monitoring pool: ${POOL_SERVICES[*]} (when synced)"

# Build list of active optional services
ACTIVE_OPTIONAL=()
for svc in "${OPTIONAL_SERVICES[@]}"; do
    if service_exists "$svc" && service_enabled "$svc"; then
        ACTIVE_OPTIONAL+=("$svc")
    fi
done
[[ ${#ACTIVE_OPTIONAL[@]} -gt 0 ]] && log "Monitoring optional: ${ACTIVE_OPTIONAL[*]}"

# Main monitoring loop
while true; do
    # Reset restart counts when the hour changes (prevents permanent restart blocks)
    _current_hour=$(date +%H)
    if [[ -z "${_last_reset_hour:-}" ]] || [[ "$_current_hour" != "$_last_reset_hour" ]]; then
        for _key in "${!restart_counts[@]}"; do unset 'restart_counts[$_key]'; done
        _last_reset_hour="$_current_hour"
    fi

    # System health checks
    check_disk_space
    check_memory

    # Core service checks
    check_blockchain_health
    check_database_health

    # Pool service checks (sync-aware)
    check_blockchain_sync_status
    check_stratum_health

    # Check enabled optional services (sentinel, dashboard).
    # HA BACKUP GUARD: On HA backup nodes, these services are intentionally
    # stopped by ha-service-control.sh. Without this guard, the health monitor
    # restarts them every 60s, causing an infinite start/stop fight with the
    # ha-role-watcher (which re-demotes them on the next 5s poll).
    # Check the ha-service-control state file to determine if services should run.
    _ha_state_role=""
    if [[ -f "$INSTALL_DIR/config/.ha-service-state" ]]; then
        _ha_state_role=$(grep -oP '"role":\s*"\K[^"]+' "$INSTALL_DIR/config/.ha-service-state" 2>/dev/null || echo "")
    fi
    if [[ "$_ha_state_role" == "BACKUP" ]] || [[ "$_ha_state_role" == "OBSERVER" ]]; then
        : # HA backup/observer — optional services intentionally stopped, skip
    else
        for service in "${ACTIVE_OPTIONAL[@]}"; do
            check_service "$service" || restart_service "$service"
        done
    fi

    sleep $CHECK_INTERVAL
done
HEALTHEOF

    sudo chmod +x "$INSTALL_DIR/bin/health-monitor.sh"

    # Determine correct PostgreSQL dependency for health monitor
    local health_pg_dep="postgresql.service"
    if [[ "$PATRONI_ENABLED" == "true" ]] && [[ "$HA_ENABLED" == "true" ]]; then
        health_pg_dep="patroni.service"
    fi

    sudo tee /etc/systemd/system/spiralpool-health.service > /dev/null << EOF
[Unit]
Description=Spiral Pool Health Monitor
# Start after network and node daemon, but NOT after stratum
# (health monitor is responsible for starting stratum when blockchain is synced)
After=network-online.target ${health_pg_dep}
Wants=${health_pg_dep}
# Prevent restart loops: max 5 restarts in 10 minutes
StartLimitIntervalSec=600
StartLimitBurst=5

[Service]
Type=simple
User=$POOL_USER
Group=$POOL_USER
ExecStart=$INSTALL_DIR/bin/health-monitor.sh

# === SELF-HEALING / AUTO-RESTART ===
# Restart=always ensures health monitor always runs
# This is the watchdog service - it MUST stay running
Restart=always
RestartSec=30
TimeoutStopSec=30
# Note: WatchdogSec removed - bash scripts don't implement sd_notify

# === SECURITY HARDENING ===
PrivateTmp=yes
ProtectSystem=strict
ProtectHome=yes
ReadWritePaths=$INSTALL_DIR
# NOTE: NoNewPrivileges must be 'no' — health monitor uses sudo for self-healing
# (sudo systemctl stop/start to restart failed services)
NoNewPrivileges=no
ProtectKernelTunables=yes
ProtectKernelModules=yes
ProtectControlGroups=yes

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable spiralpool-health || true

    # Install standalone stratum protocol health check script
    # This can be run manually or via cron as a backup safety net
    log "Installing stratum protocol health check script..."
    sudo tee "$INSTALL_DIR/bin/stratum-health-check.sh" > /dev/null << 'HEALTHCHECKEOF'
#!/bin/bash
# Stratum Protocol Health Check
# Tests if stratum is actually responding to mining protocol, not just TCP
# Can be run manually or added to cron: * * * * * /spiralpool/bin/stratum-health-check.sh

# Read configuration from environment file
ENV_FILE="/spiralpool/config/coins.env"
LOG_FILE="/spiralpool/logs/health-monitor.log"

log() { echo "[$(date '+%Y-%m-%d %H:%M:%S')] $1" | tee -a "$LOG_FILE" 2>/dev/null; }

# Determine which port(s) to check based on coin mode
ports_to_check=()
if [[ -f "$ENV_FILE" ]] && [[ ! -L "$ENV_FILE" ]]; then
    # Safe parsing — extract only expected values (no arbitrary code execution)
    COIN_MODE=$(grep -oP '^COIN_MODE=\K(single|multi)$' "$ENV_FILE" 2>/dev/null || echo "single")
    STRATUM_PORT=$(grep -oP '^STRATUM_PORT=\K[0-9]+$' "$ENV_FILE" 2>/dev/null || echo "3333")
    ENABLE_DGB=$(grep -oP '^ENABLE_DGB=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_BTC=$(grep -oP '^ENABLE_BTC=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_BCH=$(grep -oP '^ENABLE_BCH=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_BC2=$(grep -oP '^ENABLE_BC2=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_LTC=$(grep -oP '^ENABLE_LTC=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_DOGE=$(grep -oP '^ENABLE_DOGE=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_DGB_SCRYPT=$(grep -oP '^ENABLE_DGB_SCRYPT=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_PEP=$(grep -oP '^ENABLE_PEP=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_CAT=$(grep -oP '^ENABLE_CAT=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_NMC=$(grep -oP '^ENABLE_NMC=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_SYS=$(grep -oP '^ENABLE_SYS=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_XMY=$(grep -oP '^ENABLE_XMY=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_FBTC=$(grep -oP '^ENABLE_FBTC=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")
    ENABLE_QBX=$(grep -oP '^ENABLE_QBX=\K(true|false)$' "$ENV_FILE" 2>/dev/null || echo "false")

    if [[ "$COIN_MODE" == "multi" ]]; then
        # Multi-coin mode: check first enabled coin's port
        [[ "$ENABLE_DGB" == "true" ]] && ports_to_check+=(3333)
        [[ "$ENABLE_BTC" == "true" ]] && ports_to_check+=(4333)
        [[ "$ENABLE_BCH" == "true" ]] && ports_to_check+=(5333)
        [[ "$ENABLE_BC2" == "true" ]] && ports_to_check+=(6333)
        [[ "$ENABLE_LTC" == "true" ]] && ports_to_check+=(7333)
        [[ "$ENABLE_DOGE" == "true" ]] && ports_to_check+=(8335)
        [[ "$ENABLE_DGB_SCRYPT" == "true" ]] && ports_to_check+=(3336)
        [[ "$ENABLE_PEP" == "true" ]] && ports_to_check+=(10335)
        [[ "$ENABLE_CAT" == "true" ]] && ports_to_check+=(12335)
        [[ "$ENABLE_NMC" == "true" ]] && ports_to_check+=(14335)
        [[ "$ENABLE_SYS" == "true" ]] && ports_to_check+=(15335)
        [[ "$ENABLE_XMY" == "true" ]] && ports_to_check+=(17335)
        [[ "$ENABLE_FBTC" == "true" ]] && ports_to_check+=(18335)
        [[ "$ENABLE_QBX" == "true" ]] && ports_to_check+=(20335)
    else
        # Single-coin mode
        ports_to_check+=("${STRATUM_PORT:-3333}")
    fi
fi

# Default if nothing configured - try config.yaml before hardcoding
if [[ ${#ports_to_check[@]} -eq 0 ]]; then
    cfg_port=$(grep -m1 'port:' /spiralpool/stratum/config.yaml 2>/dev/null | awk '{print $2}' | tr -d '"')
    if [[ -n "$cfg_port" && "$cfg_port" =~ ^[0-9]+$ ]]; then
        ports_to_check+=("$cfg_port")
    else
        ports_to_check+=(3333)
    fi
fi

# Test first available port
TEST_PORT="${ports_to_check[0]}"

# Test stratum protocol handshake
stratum_response=$(echo '{"id":1,"method":"mining.subscribe","params":["health-check/1.0"]}' | \
    timeout 5 nc -w 3 127.0.0.1 $TEST_PORT 2>/dev/null | head -1)

if [[ -z "$stratum_response" ]]; then
    log "CRITICAL: Stratum not responding to mining.subscribe on port $TEST_PORT - protocol failure"
    log "Forcing restart..."
    sudo /bin/systemctl stop spiralstratum
    sleep 2
    sudo /usr/bin/pkill -9 -f spiralstratum 2>/dev/null
    sleep 1
    sudo /bin/systemctl start spiralstratum
    log "Stratum restarted"
    exit 1
fi

if echo "$stratum_response" | grep -q '"result":\[\['; then
    echo "Stratum protocol healthy (port $TEST_PORT)"
    exit 0
else
    log "WARNING: Unexpected stratum response on port $TEST_PORT: $stratum_response"
    exit 0
fi
HEALTHCHECKEOF

    sudo chmod +x "$INSTALL_DIR/bin/stratum-health-check.sh"
    log_success "Stratum health check script installed"

    log_success "Health monitor installed"
}

# ═══════════════════════════════════════════════════════════════════════════════
# AUTO-UPDATE SERVICE
# ═══════════════════════════════════════════════════════════════════════════════

setup_auto_updates() {
    log_step "Setting Up Auto-Updates"

    # Install unattended-upgrades for security updates
    log "Installing unattended-upgrades..."
    sudo apt-get install -y -qq unattended-upgrades apt-listchanges || log_warn "Failed to install auto-update packages (non-critical)"

    # Configure unattended-upgrades for security updates only
    sudo tee /etc/apt/apt.conf.d/50unattended-upgrades > /dev/null << 'EOF'
// Spiral Pool Auto-Update Configuration
// Only security updates are applied automatically

Unattended-Upgrade::Allowed-Origins {
    "${distro_id}:${distro_codename}";
    "${distro_id}:${distro_codename}-security";
    "${distro_id}ESMApps:${distro_codename}-apps-security";
    "${distro_id}ESM:${distro_codename}-infra-security";
};

// Don't auto-upgrade these packages (mining-critical)
Unattended-Upgrade::Package-Blacklist {
    "postgresql*";
    "libpq*";
};

// Auto-reboot if required (at 4 AM, minimal mining impact)
Unattended-Upgrade::Automatic-Reboot "true";
Unattended-Upgrade::Automatic-Reboot-Time "04:00";
Unattended-Upgrade::Automatic-Reboot-WithUsers "false";

// Remove unused dependencies
Unattended-Upgrade::Remove-Unused-Dependencies "true";
Unattended-Upgrade::Remove-New-Unused-Dependencies "true";

// Email notifications (optional - configure if needed)
// Unattended-Upgrade::Mail "admin@example.com";
// Unattended-Upgrade::MailReport "on-change";

// Keep 7 days of logs
Unattended-Upgrade::SyslogEnable "true";
Unattended-Upgrade::SyslogFacility "daemon";
EOF

    # Enable automatic updates
    sudo tee /etc/apt/apt.conf.d/20auto-upgrades > /dev/null << 'EOF'
APT::Periodic::Update-Package-Lists "1";
APT::Periodic::Download-Upgradeable-Packages "1";
APT::Periodic::AutocleanInterval "7";
APT::Periodic::Unattended-Upgrade "1";
EOF

    # Create pre-reboot hook to gracefully stop pool services
    sudo mkdir -p /etc/systemd/system-shutdown
    sudo tee /etc/systemd/system-shutdown/spiralpool-pre-shutdown.sh > /dev/null << 'EOF'
#!/bin/bash
# Gracefully stop Spiral Pool services before reboot
# This ensures shares are flushed and connections closed properly

log() { logger -t spiralpool-shutdown "$1"; }

log "System shutdown detected - stopping Spiral Pool services gracefully"

# Stop stratum first (flushes pending shares)
if systemctl is-active --quiet spiralstratum; then
    log "Stopping spiralstratum..."
    systemctl stop spiralstratum
    sleep 5
fi

# Stop optional services
for svc in spiraldash spiralsentinel spiralpool-health; do
    if systemctl is-active --quiet "$svc"; then
        log "Stopping $svc..."
        systemctl stop "$svc"
    fi
done

log "Spiral Pool services stopped"
EOF
    sudo chmod +x /etc/systemd/system-shutdown/spiralpool-pre-shutdown.sh

    # Determine correct DB dependency for startup ordering
    local startup_pg_dep="postgresql.service"
    if [[ "$PATRONI_ENABLED" == "true" ]] && [[ "$HA_ENABLED" == "true" ]]; then
        startup_pg_dep="patroni.service"
    fi

    # Create post-reboot service to ensure clean startup
    sudo tee /etc/systemd/system/spiralpool-startup.service > /dev/null << EOF
[Unit]
Description=Spiral Pool Post-Reboot Startup
After=network-online.target digibyted.service ${startup_pg_dep}
Wants=network-online.target

[Service]
Type=oneshot
RemainAfterExit=yes
ExecStart=/bin/bash -c 'sleep 30 && systemctl start spiralpool-health'
ExecStartPost=/bin/bash -c 'logger -t spiralpool-startup "Spiral Pool services started after reboot"'

[Install]
WantedBy=multi-user.target
EOF

    # Deploy post-update service restart script
    # When unattended-upgrades patches system libraries (Python, OpenSSL, glibc),
    # pool services need to restart to pick up the new code. Without this,
    # services run with stale security patches until the next reboot.
    sudo cp "${INSTALL_DIR}/scripts/linux/apt-post-update-restart.sh" "${INSTALL_DIR}/scripts/apt-post-update-restart.sh" 2>/dev/null || true
    sudo chmod +x "${INSTALL_DIR}/scripts/apt-post-update-restart.sh" 2>/dev/null || true

    # Create systemd oneshot service for post-update restart
    sudo tee /etc/systemd/system/spiralpool-apt-restart.service > /dev/null << EOF
[Unit]
Description=Spiral Pool Post-APT-Update Service Restart
Documentation=https://github.com/SpiralPool/Spiral-Pool
After=apt-daily-upgrade.service

[Service]
Type=oneshot
ExecStart=${INSTALL_DIR}/scripts/apt-post-update-restart.sh

# Run as root (needs systemctl restart permissions)
User=root

# Don't block system shutdown for this
TimeoutStartSec=120

# Logging
StandardOutput=journal
StandardError=journal
SyslogIdentifier=spiralpool-apt-restart
EOF

    # Create systemd drop-in to trigger our restart after apt-daily-upgrade completes
    # apt-daily-upgrade.service is what runs unattended-upgrades
    sudo mkdir -p /etc/systemd/system/apt-daily-upgrade.service.d
    sudo tee /etc/systemd/system/apt-daily-upgrade.service.d/spiralpool-restart.conf > /dev/null << 'EOF'
[Service]
ExecStartPost=-/bin/systemctl start --no-block spiralpool-apt-restart.service
EOF

    sudo systemctl daemon-reload || true
    sudo systemctl enable spiralpool-startup || true
    sudo systemctl enable unattended-upgrades || true

    # Enable the unattended-upgrades service (non-interactive, pre-answer yes)
    echo "unattended-upgrades unattended-upgrades/enable_auto_updates boolean true" | sudo debconf-set-selections
    sudo DEBIAN_FRONTEND=noninteractive dpkg-reconfigure -plow unattended-upgrades 2>/dev/null || true

    log_success "Auto-updates configured (security updates only)"
    log "  • Security updates: Daily at random time"
    log "  • Auto-reboot if needed: 4:00 AM"
    log "  • PostgreSQL excluded from auto-updates"
    log "  • Pool services auto-restart after library updates"
}

# ═══════════════════════════════════════════════════════════════════════════════
# HELPER SCRIPTS
# ═══════════════════════════════════════════════════════════════════════════════

create_helper_scripts() {
    log_step "Creating Helper Scripts"

    # Status
    sudo tee /usr/local/bin/spiralpool-status > /dev/null << 'STATUSEOF'
#!/bin/bash
# Colors
GREEN='\033[0;32m'
RED='\033[0;31m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
WHITE='\033[1;37m'
DIM='\033[2m'
NC='\033[0m'

echo ""
echo "═══════════════════════════════════════════════════════════════"
echo "                    SPIRAL POOL STATUS"
echo "═══════════════════════════════════════════════════════════════"
echo ""

# Database service (Patroni manages PG in HA mode)
if systemctl is-enabled --quiet "patroni" 2>/dev/null; then
    db_service="patroni"
else
    db_service="postgresql"
fi
status=$(systemctl is-active "$db_service" 2>/dev/null || echo "not-found")
case $status in
    active) echo -e "  [${GREEN}●${NC}] $db_service" ;;
    inactive) echo -e "  [${RED}○${NC}] $db_service (stopped)" ;;
esac

# Core services
for service in spiralstratum spiraldash spiralsentinel spiralpool-health; do
    status=$(systemctl is-active "$service" 2>/dev/null || echo "not-found")
    case $status in
        active) echo -e "  [${GREEN}●${NC}] $service" ;;
        inactive) echo -e "  [${RED}○${NC}] $service (stopped)" ;;
        *) ;; # Skip not-found services
    esac
done

# HA services (only show if enabled)
for ha_svc in etcd keepalived redis-server; do
    if systemctl is-enabled --quiet "$ha_svc" 2>/dev/null; then
        status=$(systemctl is-active "$ha_svc" 2>/dev/null || echo "inactive")
        case $status in
            active) echo -e "  [${GREEN}●${NC}] $ha_svc" ;;
            inactive) echo -e "  [${RED}○${NC}] $ha_svc (stopped)" ;;
        esac
    fi
done

# Blockchain daemon services (only show if installed)
for daemon in digibyted bitcoind bitcoind-bch bitcoiniid litecoind dogecoind pepecoind catcoind namecoind syscoind myriadcoind fractald; do
    if systemctl is-enabled --quiet "$daemon" 2>/dev/null; then
        status=$(systemctl is-active "$daemon" 2>/dev/null || echo "inactive")
        case $status in
            active) echo -e "  [${GREEN}●${NC}] $daemon" ;;
            inactive) echo -e "  [${RED}○${NC}] $daemon (stopped)" ;;
        esac
    fi
done
echo ""

# Function to check blockchain sync status
check_blockchain_sync() {
    local name=$1
    local cli=$2
    local conf=$3
    local daemon=$4

    if ! systemctl is-active --quiet "$daemon" 2>/dev/null; then
        return 1
    fi

    INFO=$($cli -conf="$conf" getblockchaininfo 2>/dev/null)
    if [[ -z "$INFO" ]]; then
        echo -e "  ${YELLOW}⏳ $name daemon initializing...${NC}"
        return 0
    fi

    BLOCKS=$(echo "$INFO" | grep -o '"blocks":[^,]*' | cut -d: -f2 | tr -d ' ')
    HEADERS=$(echo "$INFO" | grep -o '"headers":[^,]*' | cut -d: -f2 | tr -d ' ')
    PROGRESS=$(echo "$INFO" | grep -o '"verificationprogress":[^,]*' | cut -d: -f2 | tr -d ' ')
    IBD=$(echo "$INFO" | grep -o '"initialblockdownload":[^,]*' | cut -d: -f2 | tr -d ' ')
    PCT=$(echo "$PROGRESS" | awk '{printf "%.2f", $1 * 100}')

    echo -e "${WHITE}$name:${NC}"
    echo -e "  Blocks: ${WHITE}$BLOCKS${NC} / ${WHITE}$HEADERS${NC}"
    echo -e "  Progress: ${CYAN}${PCT}%${NC}"

    # Check sync: initialblockdownload=false is authoritative (works for BC2 and all chains)
    if [[ "$IBD" == "false" ]] || echo "$PROGRESS" | awk '{exit ($1 >= 0.9999) ? 0 : 1}'; then
        echo -e "  ${GREEN}✓ Fully synced${NC}"
    else
        REMAINING=$((HEADERS - BLOCKS))
        echo -e "  ${YELLOW}⏳ Syncing... ${WHITE}$REMAINING${NC} blocks remaining${NC}"
    fi
    echo ""
    return 0
}

# Check each installed blockchain
SHOWED_BLOCKCHAIN=false

if systemctl is-enabled --quiet digibyted 2>/dev/null; then
    check_blockchain_sync "DigiByte" "digibyte-cli" "$(get_blockchain_dir dgb)/digibyte.conf" "digibyted"
    SHOWED_BLOCKCHAIN=true
fi

if systemctl is-enabled --quiet bitcoind 2>/dev/null; then
    check_blockchain_sync "Bitcoin" "bitcoin-cli" "$(get_blockchain_dir btc)/bitcoin.conf" "bitcoind"
    SHOWED_BLOCKCHAIN=true
fi

if systemctl is-enabled --quiet bitcoind-bch 2>/dev/null; then
    check_blockchain_sync "Bitcoin Cash" "bitcoin-cli-bch" "$(get_blockchain_dir bch)/bitcoin.conf" "bitcoind-bch"
    SHOWED_BLOCKCHAIN=true
fi

if systemctl is-enabled --quiet bitcoiniid 2>/dev/null; then
    check_blockchain_sync "Bitcoin II" "bitcoinii-cli" "$(get_blockchain_dir bc2)/bitcoinii.conf" "bitcoiniid"
    SHOWED_BLOCKCHAIN=true
fi

# SHA-256d AuxPoW coins (merge-mineable with Bitcoin)
if systemctl is-enabled --quiet namecoind 2>/dev/null; then
    check_blockchain_sync "Namecoin" "namecoin-cli" "$(get_blockchain_dir nmc)/namecoin.conf" "namecoind"
    SHOWED_BLOCKCHAIN=true
fi

if systemctl is-enabled --quiet syscoind 2>/dev/null; then
    check_blockchain_sync "Syscoin" "syscoin-cli" "$(get_blockchain_dir sys)/syscoin.conf" "syscoind"
    SHOWED_BLOCKCHAIN=true
fi

if systemctl is-enabled --quiet myriadcoind 2>/dev/null; then
    check_blockchain_sync "Myriad" "myriadcoin-cli" "$(get_blockchain_dir xmy)/myriadcoin.conf" "myriadcoind"
    SHOWED_BLOCKCHAIN=true
fi

if systemctl is-enabled --quiet fractald 2>/dev/null; then
    check_blockchain_sync "Fractal BTC" "fractal-cli" "$(get_blockchain_dir fbtc)/fractal.conf" "fractald"
    SHOWED_BLOCKCHAIN=true
fi

if systemctl is-enabled --quiet qbitxd 2>/dev/null; then
    check_blockchain_sync "Q-BitX" "qbitx-cli" "$(get_blockchain_dir qbx)/qbitx.conf" "qbitxd"
    SHOWED_BLOCKCHAIN=true
fi

if systemctl is-enabled --quiet litecoind 2>/dev/null; then
    check_blockchain_sync "Litecoin" "litecoin-cli" "$(get_blockchain_dir ltc)/litecoin.conf" "litecoind"
    SHOWED_BLOCKCHAIN=true
fi

if systemctl is-enabled --quiet dogecoind 2>/dev/null; then
    check_blockchain_sync "Dogecoin" "dogecoin-cli" "$(get_blockchain_dir doge)/dogecoin.conf" "dogecoind"
    SHOWED_BLOCKCHAIN=true
fi

if systemctl is-enabled --quiet pepecoind 2>/dev/null; then
    check_blockchain_sync "PepeCoin" "pepecoin-cli" "$(get_blockchain_dir pep)/pepecoin.conf" "pepecoind"
    SHOWED_BLOCKCHAIN=true
fi

if systemctl is-enabled --quiet catcoind 2>/dev/null; then
    check_blockchain_sync "Catcoin" "catcoin-cli" "$(get_blockchain_dir cat)/catcoin.conf" "catcoind"
    SHOWED_BLOCKCHAIN=true
fi

# Show pool status if any blockchain is synced
if [[ "$SHOWED_BLOCKCHAIN" == "true" ]] && systemctl is-active --quiet spiralstratum; then
    echo -e "  ${GREEN}✓ Pool is ONLINE - Ready for miners!${NC}"
fi

if [[ "$SHOWED_BLOCKCHAIN" == "false" ]]; then
    echo -e "  ${YELLOW}No blockchain daemons running${NC}"
fi
echo ""
STATUSEOF

    # Logs
    sudo tee /usr/local/bin/spiralpool-logs > /dev/null << 'LOGSEOF'
#!/bin/bash
journalctl -u "${1:-spiralstratum}" -f
LOGSEOF

    # Restart
    sudo tee /usr/local/bin/spiralpool-restart > /dev/null << 'RESTARTEOF'
#!/bin/bash
echo "Restarting Spiral Pool..."
sudo systemctl restart spiralstratum
echo "Done. Run: spiralpool-status"
RESTARTEOF

    # Sync status checker
    sudo tee /usr/local/bin/spiralpool-sync > /dev/null << 'SYNCSTATUSEOF'
#!/bin/bash
#
# Multi-Coin Blockchain Sync Status with Pretty Progress Display
# Supports: BTC, BCH, BC2, DGB, NMC, SYS, XMY, FBTC (SHA256d) | LTC, DOGE, PEP, CAT (Scrypt)
#
# Usage:
#   spiralpool-sync                  - Show status for all enabled coins
#   spiralpool-sync --watch          - Live progress display (updates every 5s)
#   spiralpool-sync -w               - Same as --watch
#   spiralpool-sync --coin dgb       - Show status for specific coin
#   spiralpool-sync --coin ltc -w    - Watch specific coin
#   spiralpool-sync --multi          - Show all coins in multi-coin mode
#
# In watch mode:
#   Press 'q' or Ctrl+C to exit (sync continues in background)
#   Press 'b' to background the display and return to terminal
#

#===============================================================================
# USER DETECTION AND SWITCHING
# The CLI tools need to read config files owned by the pool user.
# This section detects the pool user and re-executes as that user if needed.
#===============================================================================

INSTALL_DIR="/spiralpool"
# Multi-disk support: load CHAIN_MOUNT_POINT so get_blockchain_dir returns the right path
MULTI_DISK_CONFIGURED="false"; CHAIN_MOUNT_POINT=""
_env="$INSTALL_DIR/config/coins.env"
if [[ -f "$_env" ]] && [[ ! -L "$_env" ]]; then
    MULTI_DISK_CONFIGURED=$(grep -oP '^MULTI_DISK_CONFIGURED=\K(true|false)$' "$_env" 2>/dev/null || echo "false")
    CHAIN_MOUNT_POINT=$(grep -oP '^CHAIN_MOUNT_POINT=\K\S+$' "$_env" 2>/dev/null || echo "")
fi
get_blockchain_dir() { local c="$1"; if [[ "$MULTI_DISK_CONFIGURED" == "true" && -n "$CHAIN_MOUNT_POINT" && -d "$CHAIN_MOUNT_POINT" ]]; then echo "$CHAIN_MOUNT_POINT/$c"; else echo "$INSTALL_DIR/$c"; fi; }

# Detect the pool user from systemd service files or directory ownership
detect_pool_user() {
    local pool_user=""

    # Method 1: Check systemd service files for User= directive
    for service in digibyted bitcoind bitcoind-bch bitcoiniid fractald namecoind syscoind myriadcoind litecoind dogecoind pepecoind catcoind spiralstratum; do
        if [[ -f "/etc/systemd/system/${service}.service" ]]; then
            pool_user=$(grep -oP '^User=\K.*' "/etc/systemd/system/${service}.service" 2>/dev/null | head -1)
            [[ -n "$pool_user" ]] && break
        fi
    done

    # Method 2: Fallback to directory ownership (use get_blockchain_dir for multi-disk support)
    if [[ -z "$pool_user" ]] || [[ "$pool_user" == "root" ]]; then
        for dir in "$(get_blockchain_dir dgb)" "$(get_blockchain_dir btc)" "$(get_blockchain_dir bch)" "$(get_blockchain_dir bc2)" "$(get_blockchain_dir fbtc)" "$(get_blockchain_dir qbx)" "$(get_blockchain_dir nmc)" "$(get_blockchain_dir sys)" "$(get_blockchain_dir xmy)" "$(get_blockchain_dir ltc)" "$(get_blockchain_dir doge)" "$(get_blockchain_dir pep)" "$(get_blockchain_dir cat)"; do
            if [[ -d "$dir" ]]; then
                pool_user=$(stat -c '%U' "$dir" 2>/dev/null)
                [[ -n "$pool_user" ]] && [[ "$pool_user" != "root" ]] && break
            fi
        done
    fi

    echo "$pool_user"
}

# Switch to pool user if needed
ensure_correct_user() {
    local pool_user=$(detect_pool_user)

    # Validate: must be a valid Unix username (security check)
    if [[ -n "$pool_user" ]] && [[ ! "$pool_user" =~ ^[a-z_][a-z0-9_-]*$ ]]; then
        return 1
    fi

    # Validate: user must exist
    if [[ -n "$pool_user" ]] && ! id "$pool_user" &>/dev/null; then
        return 1
    fi

    # If we found a pool user and we're not already that user, re-exec as them
    if [[ -n "$pool_user" ]] && [[ "$(whoami)" != "$pool_user" ]]; then
        exec sudo -u "$pool_user" "$0" "$@"
    fi
}

# Run user check (passes all arguments for re-exec)
ensure_correct_user "$@"

#===============================================================================

# Colors
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
WHITE='\033[1;37m'
DIM='\033[2m'
BOLD='\033[1m'
NC='\033[0m'

# Get local IP address (for display purposes)
get_local_ip() {
    local ip=""

    # Method 1: Use route to determine primary interface IP (most reliable)
    ip=$(ip -4 route get 1.1.1.1 2>/dev/null | grep -oP 'src \K\S+' | head -1)
    # Validate IP format
    if [[ -n "$ip" ]] && [[ "$ip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
        echo "$ip"
        return
    fi

    # Method 2: Use hostname command
    ip=$(hostname -I 2>/dev/null | awk '{print $1}')
    if [[ -n "$ip" ]] && [[ "$ip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
        echo "$ip"
        return
    fi

    # Method 3: Parse ip addr output directly
    ip=$(ip -4 addr show 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.\d+){3}' | grep -v '^127\.' | head -1)
    if [[ -n "$ip" ]] && [[ "$ip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
        echo "$ip"
        return
    fi

    # Fallback: return placeholder
    echo "<your-ip>"
}
LOCAL_IP=$(get_local_ip)

# Parse arguments
COIN=""
WATCH_MODE=false
MULTI_MODE=false
TEST_MODE=false

while [[ $# -gt 0 ]]; do
    case $1 in
        --coin|-c)
            COIN="${2,,}"  # Convert to lowercase
            shift 2
            ;;
        --watch|-w)
            WATCH_MODE=true
            shift
            ;;
        --multi|-m)
            MULTI_MODE=true
            shift
            ;;
        --help|-h)
            echo "Usage: spiralpool-sync [OPTIONS]"
            echo ""
            echo "Options:"
            echo "  --coin, -c COIN   Check specific coin (btc, bch, bc2, dgb, nmc, sys, xmy, fbtc, qbx, ltc, doge, pep, cat)"
            echo "  --watch, -w       Live progress display"
            echo "  --multi, -m       Show all coins in multi-coin mode"
            echo "  --test, -t        Test/debug mode - show paths and test CLI"
            echo "  --help, -h        Show this help"
            echo ""
            echo "Examples:"
            echo "  spiralpool-sync              # Auto-detect and show default coin"
            echo "  spiralpool-sync --watch      # Live progress for default coin"
            echo "  spiralpool-sync --coin btc   # Show Bitcoin sync status"
            echo "  spiralpool-sync --multi -w   # Watch all coins in multi-coin mode"
            echo "  spiralpool-sync --test       # Debug: show detected paths and test CLI"
            exit 0
            ;;
        --test|-t)
            TEST_MODE=true
            shift
            ;;
        *)
            shift
            ;;
    esac
done

# Function to setup coin-specific variables
setup_coin() {
    local coin="$1"
    case "${coin,,}" in
        # SHA-256d coins
        dgb|digibyte)
            COIN_NAME="DigiByte"
            COIN_SYMBOL="DGB"
            COIN_EMOJI="💎"
            SERVICE_NAME="digibyted"
            CONF="$(get_blockchain_dir dgb)/digibyte.conf"
            DATADIR="$(get_blockchain_dir dgb)"
            CLI="digibyte-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        btc|bitcoin)
            COIN_NAME="Bitcoin"
            COIN_SYMBOL="BTC"
            COIN_EMOJI="₿"
            SERVICE_NAME="bitcoind"
            CONF="$(get_blockchain_dir btc)/bitcoin.conf"
            DATADIR="$(get_blockchain_dir btc)"
            CLI="bitcoin-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        bch|bitcoincash)
            COIN_NAME="Bitcoin Cash"
            COIN_SYMBOL="BCH"
            COIN_EMOJI="💚"
            SERVICE_NAME="bitcoind-bch"
            CONF="$(get_blockchain_dir bch)/bitcoin.conf"
            DATADIR="$(get_blockchain_dir bch)"
            CLI="bitcoin-cli-bch -conf=$CONF -datadir=$DATADIR"
            ;;
        bc2|bitcoinii)
            COIN_NAME="Bitcoin II"
            COIN_SYMBOL="BC2"
            COIN_EMOJI="🔷"
            SERVICE_NAME="bitcoiniid"
            CONF="$(get_blockchain_dir bc2)/bitcoinii.conf"
            DATADIR="$(get_blockchain_dir bc2)"
            # Bitcoin II uses lowercase symlink bitcoinii-cli
            CLI="bitcoinii-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        # Scrypt coins
        ltc|litecoin)
            COIN_NAME="Litecoin"
            COIN_SYMBOL="LTC"
            COIN_EMOJI="🪙"
            SERVICE_NAME="litecoind"
            CONF="$(get_blockchain_dir ltc)/litecoin.conf"
            DATADIR="$(get_blockchain_dir ltc)"
            CLI="litecoin-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        doge|dogecoin)
            COIN_NAME="Dogecoin"
            COIN_SYMBOL="DOGE"
            COIN_EMOJI="🐕"
            SERVICE_NAME="dogecoind"
            CONF="$(get_blockchain_dir doge)/dogecoin.conf"
            DATADIR="$(get_blockchain_dir doge)"
            CLI="dogecoin-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        dgb_scrypt|dgb-scrypt)
            # DGB-Scrypt uses the same daemon as DGB
            COIN_NAME="DGB-Scrypt"
            COIN_SYMBOL="DGB-SCRYPT"
            COIN_EMOJI="💎"
            SERVICE_NAME="digibyted"
            CONF="$(get_blockchain_dir dgb)/digibyte.conf"
            DATADIR="$(get_blockchain_dir dgb)"
            CLI="digibyte-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        fbtc|fractalbtc|fractal)
            COIN_NAME="Fractal Bitcoin"
            COIN_SYMBOL="FBTC"
            COIN_EMOJI="🔶"
            SERVICE_NAME="fractald"
            CONF="$(get_blockchain_dir fbtc)/fractal.conf"
            DATADIR="$(get_blockchain_dir fbtc)"
            CLI="fractal-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        qbx|qbitx)
            COIN_NAME="Q-BitX"
            COIN_SYMBOL="QBX"
            COIN_EMOJI="⚛️"
            SERVICE_NAME="qbitxd"
            CONF="$(get_blockchain_dir qbx)/qbitx.conf"
            DATADIR="$(get_blockchain_dir qbx)"
            CLI="qbitx-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        nmc|namecoin)
            COIN_NAME="Namecoin"
            COIN_SYMBOL="NMC"
            COIN_EMOJI="📛"
            SERVICE_NAME="namecoind"
            CONF="$(get_blockchain_dir nmc)/namecoin.conf"
            DATADIR="$(get_blockchain_dir nmc)"
            CLI="namecoin-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        sys|syscoin)
            COIN_NAME="Syscoin"
            COIN_SYMBOL="SYS"
            COIN_EMOJI="⚙️"
            SERVICE_NAME="syscoind"
            CONF="$(get_blockchain_dir sys)/syscoin.conf"
            DATADIR="$(get_blockchain_dir sys)"
            CLI="syscoin-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        xmy|myriad|myriadcoin)
            COIN_NAME="Myriad"
            COIN_SYMBOL="XMY"
            COIN_EMOJI="🌀"
            SERVICE_NAME="myriadcoind"
            CONF="$(get_blockchain_dir xmy)/myriadcoin.conf"
            DATADIR="$(get_blockchain_dir xmy)"
            CLI="myriadcoin-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        pep|pepecoin)
            COIN_NAME="PepeCoin"
            COIN_SYMBOL="PEP"
            COIN_EMOJI="🐸"
            SERVICE_NAME="pepecoind"
            CONF="$(get_blockchain_dir pep)/pepecoin.conf"
            DATADIR="$(get_blockchain_dir pep)"
            CLI="pepecoin-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        cat|catcoin)
            COIN_NAME="Catcoin"
            COIN_SYMBOL="CAT"
            COIN_EMOJI="🐱"
            SERVICE_NAME="catcoind"
            CONF="$(get_blockchain_dir cat)/catcoin.conf"
            DATADIR="$(get_blockchain_dir cat)"
            CLI="catcoin-cli -conf=$CONF -datadir=$DATADIR"
            ;;
        *)
            return 1
            ;;
    esac
    return 0
}

# Function to detect which coins are installed/enabled
detect_coins() {
    local coins=()
    local env_file="/spiralpool/.env"
    local config_file="/spiralpool/config/config.yaml"

    # Method 1: Check config.yaml for enabled coins (most authoritative)
    # Parse YAML to find coins with enabled: true
    if [[ -f "$config_file" ]]; then
        # Use awk to parse coin entries - handles various YAML formats
        # Looks for pattern: symbol: "XXX" followed by enabled: true within same block
        local yaml_coins=$(awk '
            # Only match top-level coin entries (2-space indent "  - symbol:")
            # NOT deeply nested mergeMining auxChains (8-space indent "        - symbol:")
            /^  - (symbol|id):/ {
                # Start of new coin entry - reset
                in_coin = 1
                enabled = 0
                symbol = ""
            }
            # Deeper nested "- symbol:" means auxChains entry — ignore
            /^        - symbol:/ {
                in_coin = 0
                next
            }
            in_coin && /symbol:/ {
                # Extract symbol value, remove quotes
                gsub(/.*symbol:[[:space:]]*/, "")
                gsub(/["'"'"']/, "")
                gsub(/[[:space:]].*/, "")
                symbol = tolower($0)
            }
            in_coin && /^[[:space:]]+enabled:[[:space:]]*true/ {
                enabled = 1
            }
            # When we have both symbol and enabled, print it
            in_coin && symbol != "" && enabled {
                print symbol
                symbol = ""
                enabled = 0
            }
            # Reset on new top-level key (not indented with -)
            /^[a-z]/ && !/^[[:space:]]/ { in_coin = 0 }
        ' "$config_file" 2>/dev/null)

        if [[ -n "$yaml_coins" ]]; then
            for c in $yaml_coins; do
                case "$c" in
                    dgb|btc|bch|bc2|ltc|doge|dgb-scrypt|pep|cat|fbtc|qbx|nmc|sys|xmy) coins+=("$c") ;;
                esac
            done
        fi
    fi

    # Method 2: Check .env file for ENABLE_* flags (fallback)
    if [[ ${#coins[@]} -eq 0 ]] && [[ -f "$env_file" ]]; then
        source "$env_file" 2>/dev/null || true
        [[ "$ENABLE_DGB" == "true" ]] && coins+=("dgb")
        [[ "$ENABLE_BTC" == "true" ]] && coins+=("btc")
        [[ "$ENABLE_BCH" == "true" ]] && coins+=("bch")
        [[ "$ENABLE_BC2" == "true" ]] && coins+=("bc2")
        [[ "$ENABLE_LTC" == "true" ]] && coins+=("ltc")
        [[ "$ENABLE_DOGE" == "true" ]] && coins+=("doge")
        [[ "$ENABLE_DGB_SCRYPT" == "true" ]] && coins+=("dgb-scrypt")
        [[ "$ENABLE_PEP" == "true" ]] && coins+=("pep")
        [[ "$ENABLE_CAT" == "true" ]] && coins+=("cat")
        [[ "$ENABLE_FBTC" == "true" ]] && coins+=("fbtc")
        [[ "$ENABLE_QBX" == "true" ]] && coins+=("qbx")
        [[ "$ENABLE_NMC" == "true" ]] && coins+=("nmc")
        [[ "$ENABLE_SYS" == "true" ]] && coins+=("sys")
        [[ "$ENABLE_XMY" == "true" ]] && coins+=("xmy")
    fi

    # Method 3: Check for running daemon services (fallback)
    if [[ ${#coins[@]} -eq 0 ]]; then
        systemctl is-active --quiet digibyted 2>/dev/null && coins+=("dgb")
        systemctl is-active --quiet bitcoind 2>/dev/null && coins+=("btc")
        systemctl is-active --quiet bitcoind-bch 2>/dev/null && coins+=("bch")
        systemctl is-active --quiet bitcoiniid 2>/dev/null && coins+=("bc2")
        systemctl is-active --quiet litecoind 2>/dev/null && coins+=("ltc")
        systemctl is-active --quiet dogecoind 2>/dev/null && coins+=("doge")
        systemctl is-active --quiet pepecoind 2>/dev/null && coins+=("pep")
        systemctl is-active --quiet catcoind 2>/dev/null && coins+=("cat")
        systemctl is-active --quiet fractald 2>/dev/null && coins+=("fbtc")
        systemctl is-active --quiet qbitxd 2>/dev/null && coins+=("qbx")
        systemctl is-active --quiet namecoind 2>/dev/null && coins+=("nmc")
        systemctl is-active --quiet syscoind 2>/dev/null && coins+=("sys")
        systemctl is-active --quiet myriadcoind 2>/dev/null && coins+=("xmy")
    fi

    # Method 4: Check for config files (last resort fallback)
    if [[ ${#coins[@]} -eq 0 ]]; then
        [[ -f "$(get_blockchain_dir dgb)/digibyte.conf" ]] && coins+=("dgb")
        [[ -f "$(get_blockchain_dir btc)/bitcoin.conf" ]] && coins+=("btc")
        [[ -f "$(get_blockchain_dir bch)/bitcoin.conf" ]] && coins+=("bch")
        [[ -f "$(get_blockchain_dir bc2)/bitcoinii.conf" ]] && coins+=("bc2")
        [[ -f "$(get_blockchain_dir ltc)/litecoin.conf" ]] && coins+=("ltc")
        [[ -f "$(get_blockchain_dir doge)/dogecoin.conf" ]] && coins+=("doge")
        [[ -f "$(get_blockchain_dir fbtc)/fractal.conf" ]] && coins+=("fbtc")
        [[ -f "$(get_blockchain_dir qbx)/qbitx.conf" ]] && coins+=("qbx")
        [[ -f "$(get_blockchain_dir nmc)/namecoin.conf" ]] && coins+=("nmc")
        [[ -f "$(get_blockchain_dir sys)/syscoin.conf" ]] && coins+=("sys")
        [[ -f "$(get_blockchain_dir xmy)/myriadcoin.conf" ]] && coins+=("xmy")
        [[ -f "$(get_blockchain_dir pep)/pepecoin.conf" ]] && coins+=("pep")
        [[ -f "$(get_blockchain_dir cat)/catcoin.conf" ]] && coins+=("cat")
    fi

    echo "${coins[@]}"
}

# Auto-detect coin if not specified
if [[ -z "$COIN" ]]; then
    detected=($(detect_coins))
    if [[ ${#detected[@]} -eq 0 ]]; then
        echo -e "${RED}ERROR: No blockchain configurations found.${NC}"
        echo "Make sure at least one daemon is installed (DGB, BTC, BCH, BC2, LTC, DOGE, PEP, CAT, FBTC, NMC, SYS, or XMY)."
        exit 1
    elif [[ ${#detected[@]} -eq 1 ]]; then
        COIN="${detected[0]}"
    elif [[ "$MULTI_MODE" == "true" ]]; then
        # Multi-coin mode - will iterate through all
        COIN="multi"
    else
        # Multiple coins detected, default to first (usually DGB)
        COIN="${detected[0]}"
        echo -e "${DIM}Multiple coins detected: ${detected[*]}. Using $COIN (use --coin to specify)${NC}"
    fi
fi

# Setup the selected coin (if not multi mode)
if [[ "$COIN" != "multi" ]]; then
    if ! setup_coin "$COIN"; then
        echo -e "${RED}ERROR: Unknown coin '$COIN'. Use dgb, dgb-scrypt, btc, bch, bc2, ltc, doge, pep, cat, nmc, sys, xmy, fbtc, or qbx.${NC}"
        exit 1
    fi

    if [[ -z "$CLI" ]]; then
        echo -e "${RED}ERROR: Cannot find configuration for $COIN_NAME.${NC}"
        echo "Make sure $COIN_NAME daemon is installed."
        exit 1
    fi
fi

# Network resilience settings
MAX_RETRIES=3
RETRY_DELAY=5
CONSECUTIVE_FAILURES=0
OUTAGE_START_TIME=0
NETWORK_WAS_DOWN=false

# Timing thresholds
NORMAL_CHECK_INTERVAL=0.5    # Normal: check every 0.5 seconds for responsive UI
OUTAGE_CHECK_INTERVAL=5      # During outage: check every 5 seconds
OUTAGE_THRESHOLD=180         # 3 minutes = network outage (not just a hiccup)

# Function to check if network/internet is available
check_network() {
    # Try multiple methods to verify connectivity
    # 1. Check if we can reach the daemon locally
    local cli_out
    cli_out=$($CLI getblockchaininfo 2>&1)
    if [[ $? -eq 0 ]]; then
        return 0
    fi
    # Distinguish RPC auth failure from real network/daemon outage.
    # An auth error means the daemon IS running but qbitx.conf rpcpassword
    # does not match what the daemon started with — this is a config issue,
    # not a network outage. Surface it clearly instead of masking it.
    if echo "$cli_out" | grep -qi "incorrect\|unauthorized\|forbidden\|wrong password\|error code: -32\|error code: -1"; then
        echo "RPC_AUTH_FAILURE"
        return 2
    fi
    # 2. Check if daemon process is running (local check, no network needed)
    if systemctl is-active --quiet "$SERVICE_NAME" 2>/dev/null; then
        # Daemon running but not responding - could be initializing or network issue
        return 1
    fi
    return 1
}

# Global variable to track daemon loading state (error -28)
DAEMON_LOADING=false
DAEMON_LOADING_MESSAGE=""

# Global output variable — cli_call writes here instead of stdout so callers
# don't need command substitution ($(...)) which runs in a subshell and loses
# all state variable changes (CONSECUTIVE_FAILURES, DAEMON_LOADING, etc.).
CLI_OUTPUT=""

# Function to call CLI with retry logic and self-healing
# Usage:  cli_call "getblockchaininfo"
#         local rc=$?; local info="$CLI_OUTPUT"
cli_call() {
    local cmd="$1"
    local retries=0
    local result=""
    local stderr_output=""
    CLI_OUTPUT=""

    while [[ $retries -lt $MAX_RETRIES ]]; do
        # Single CLI call with timeout (prevents indefinite hangs in watch mode)
        # Captures stderr separately to detect error -28 loading states
        local _cli_stderr
        _cli_stderr=$(mktemp /tmp/.sp-cli-XXXXXX)
        result=$(timeout 10 $CLI $cmd 2>"$_cli_stderr") || true
        stderr_output=$(cat "$_cli_stderr" 2>/dev/null)
        rm -f "$_cli_stderr"

        if [[ -n "$result" ]]; then
            # Success! Reset failure tracking
            if [[ $CONSECUTIVE_FAILURES -gt 0 ]]; then
                # We recovered from failures
                if [[ "$NETWORK_WAS_DOWN" == "true" ]]; then
                    NETWORK_WAS_DOWN=false
                fi
            fi
            CONSECUTIVE_FAILURES=0
            OUTAGE_START_TIME=0
            DAEMON_LOADING=false
            DAEMON_LOADING_MESSAGE=""
            CLI_OUTPUT="$result"
            return 0
        fi

        # Check for error -28 (daemon is loading blocks - this is NORMAL after restart)
        if echo "$stderr_output" | grep -qE "error code: -28|Loading block|Verifying block|Rewinding block|Loading wallet"; then
            DAEMON_LOADING=true
            # Extract the loading message for display
            if echo "$stderr_output" | grep -q "Loading block index"; then
                DAEMON_LOADING_MESSAGE="Loading block index..."
            elif echo "$stderr_output" | grep -q "Loading blocks"; then
                DAEMON_LOADING_MESSAGE="Loading blocks..."
            elif echo "$stderr_output" | grep -q "Verifying block"; then
                DAEMON_LOADING_MESSAGE="Verifying blocks..."
            elif echo "$stderr_output" | grep -q "Rewinding block"; then
                DAEMON_LOADING_MESSAGE="Rewinding blocks..."
            elif echo "$stderr_output" | grep -q "Loading wallet"; then
                DAEMON_LOADING_MESSAGE="Loading wallet..."
            else
                DAEMON_LOADING_MESSAGE="Initializing..."
            fi
            # Don't count this as a failure - daemon is working correctly
            return 2  # Special return code for "loading" state
        fi

        retries=$((retries + 1))
        if [[ $retries -lt $MAX_RETRIES ]]; then
            sleep 1
        fi
    done

    # Track failures (only for non-loading states)
    DAEMON_LOADING=false
    DAEMON_LOADING_MESSAGE=""
    CONSECUTIVE_FAILURES=$((CONSECUTIVE_FAILURES + 1))

    # Start outage timer on first failure
    if [[ $OUTAGE_START_TIME -eq 0 ]]; then
        OUTAGE_START_TIME=$(date +%s)
    fi

    # Check if this is a prolonged outage (3+ minutes)
    local current_time=$(date +%s)
    local outage_duration=$((current_time - OUTAGE_START_TIME))
    if [[ $outage_duration -ge $OUTAGE_THRESHOLD ]]; then
        NETWORK_WAS_DOWN=true
    fi

    return 1
}

# Function to get appropriate sleep interval based on network state
get_check_interval() {
    if [[ "$NETWORK_WAS_DOWN" == "true" ]] || [[ $CONSECUTIVE_FAILURES -gt 0 ]]; then
        # During outage or recovery: check every 15 seconds
        echo $OUTAGE_CHECK_INTERVAL
    else
        # Normal operation: check every 0.5 seconds
        echo $NORMAL_CHECK_INTERVAL
    fi
}

# Function to format outage duration
format_outage_duration() {
    local seconds=$1
    if [[ $seconds -lt 60 ]]; then
        echo "${seconds}s"
    elif [[ $seconds -lt 3600 ]]; then
        echo "$((seconds / 60))m $((seconds % 60))s"
    else
        echo "$((seconds / 3600))h $((seconds % 3600 / 60))m"
    fi
}

# Additional colors for extended display
BLUE='\033[0;34m'
MAGENTA='\033[0;35m'

# Progress bar characters (ASCII for terminal compatibility — Unicode block
# chars have East Asian Width "Ambiguous" and render double-width on some
# terminals, breaking cursor-positioned displays)
BAR_FILLED="#"
BAR_PARTIAL="="
BAR_EMPTY="-"
BAR_WIDTH=50

# Function to draw progress bar with gradient effect
draw_progress_bar() {
    local progress=$1
    local filled=$(echo "$progress $BAR_WIDTH" | awk '{printf "%d", $1 * $2 / 100}')
    local empty=$((BAR_WIDTH - filled))

    # Color gradient based on progress
    local bar_color="$YELLOW"
    if (( $(echo "$progress >= 75" | bc -l 2>/dev/null || echo "0") )); then
        bar_color="$GREEN"
    elif (( $(echo "$progress >= 50" | bc -l 2>/dev/null || echo "0") )); then
        bar_color="$CYAN"
    fi

    printf "${bar_color}"
    for ((i=0; i<filled; i++)); do printf "%s" "$BAR_FILLED"; done
    printf "${DIM}"
    for ((i=0; i<empty; i++)); do printf "%s" "$BAR_EMPTY"; done
    printf "${NC}"
}

# Function to format time
format_time() {
    local seconds=$1
    if [[ $seconds -lt 60 ]]; then
        echo "${seconds}s"
    elif [[ $seconds -lt 3600 ]]; then
        local mins=$((seconds / 60))
        local secs=$((seconds % 60))
        echo "${mins}m ${secs}s"
    elif [[ $seconds -lt 86400 ]]; then
        local hours=$((seconds / 3600))
        local mins=$(((seconds % 3600) / 60))
        echo "${hours}h ${mins}m"
    else
        local days=$((seconds / 86400))
        local hours=$(((seconds % 86400) / 3600))
        echo "${days}d ${hours}h"
    fi
}

# Function to format number with commas
format_number() {
    printf "%'d" "$1" 2>/dev/null || echo "$1" | sed ':a;s/\([0-9]\)\([0-9]\{3\}\)\($\|,\)/\1,\2\3/;ta'
}

# Function to format bytes
format_bytes() {
    local bytes=$1
    if [[ $bytes -lt 1024 ]]; then
        echo "${bytes} B"
    elif [[ $bytes -lt 1048576 ]]; then
        echo "$(echo "scale=1; $bytes / 1024" | bc) KB"
    elif [[ $bytes -lt 1073741824 ]]; then
        echo "$(echo "scale=1; $bytes / 1048576" | bc) MB"
    else
        echo "$(echo "scale=2; $bytes / 1073741824" | bc) GB"
    fi
}

# Function to format speed (bytes per second)
format_speed() {
    local bps=$1
    if [[ $bps -lt 1024 ]]; then
        echo "${bps} B/s"
    elif [[ $bps -lt 1048576 ]]; then
        echo "$(echo "scale=1; $bps / 1024" | bc) KB/s"
    elif [[ $bps -lt 1073741824 ]]; then
        echo "$(echo "scale=1; $bps / 1048576" | bc) MB/s"
    else
        echo "$(echo "scale=2; $bps / 1073741824" | bc) GB/s"
    fi
}

# Check if daemon is running (use coin-specific service name)
check_daemon_running() {
    local service="$1"
    systemctl is-active --quiet "$service" 2>/dev/null
}

# Function to get coin status for one coin (used in multi-mode and single-mode)
get_coin_sync_status() {
    local coin="$1"
    local saved_cli="$CLI"
    local saved_service="$SERVICE_NAME"
    local saved_name="$COIN_NAME"
    local saved_symbol="$COIN_SYMBOL"
    local saved_emoji="$COIN_EMOJI"

    setup_coin "$coin"

    local result=""
    if [[ -z "$CLI" ]]; then
        result="not_installed"
    elif ! check_daemon_running "$SERVICE_NAME"; then
        result="not_running"
    else
        # Capture both stdout and stderr to detect error -28 (loading state)
        local CLI_STDERR=$($CLI getblockchaininfo 2>&1 >/dev/null)
        local INFO=$($CLI getblockchaininfo 2>/dev/null)
        if [[ -z "$INFO" ]]; then
            # Check for error -28 (daemon is loading blocks - this is NORMAL)
            if echo "$CLI_STDERR" | grep -qE "error code: -28|Loading block|Verifying block|Rewinding block|Loading wallet"; then
                # Extract the specific loading message
                local loading_msg="Initializing"
                if echo "$CLI_STDERR" | grep -q "Loading block index"; then
                    loading_msg="Loading block index"
                elif echo "$CLI_STDERR" | grep -q "Loading blocks"; then
                    loading_msg="Loading blocks"
                elif echo "$CLI_STDERR" | grep -q "Verifying block"; then
                    loading_msg="Verifying blocks"
                elif echo "$CLI_STDERR" | grep -q "Rewinding block"; then
                    loading_msg="Rewinding blocks"
                elif echo "$CLI_STDERR" | grep -q "Loading wallet"; then
                    loading_msg="Loading wallet"
                fi
                result="loading:$loading_msg"
            else
                result="not_responding"
            fi
        else
            local PROGRESS=$(echo "$INFO" | grep -o '"verificationprogress":[^,]*' | cut -d: -f2 | tr -d ' ')
            local IBD=$(echo "$INFO" | grep -o '"initialblockdownload":[^,]*' | cut -d: -f2 | tr -d ' ')
            local BLOCKS=$(echo "$INFO" | grep -o '"blocks":[^,]*' | cut -d: -f2 | tr -d ' ')
            local HEADERS=$(echo "$INFO" | grep -o '"headers":[^,]*' | cut -d: -f2 | tr -d ' ')
            local PCT=$(echo "$PROGRESS" | awk '{printf "%.2f", $1 * 100}')

            # Check sync: initialblockdownload=false is authoritative (works for BC2 and all chains)
            if [[ "$IBD" == "false" ]] || echo "$PROGRESS" | awk '{exit ($1 >= 0.9999) ? 0 : 1}'; then
                result="synced:$PCT:$BLOCKS:$HEADERS"
            else
                result="syncing:$PCT:$BLOCKS:$HEADERS"
            fi
        fi
    fi

    # Restore saved values for single-coin mode
    CLI="$saved_cli"
    SERVICE_NAME="$saved_service"
    COIN_NAME="$saved_name"
    COIN_SYMBOL="$saved_symbol"
    COIN_EMOJI="$saved_emoji"

    echo "$result"
}

# Multi-coin status display
show_multi_status() {
    local coins=($(detect_coins))

    echo ""
    echo -e "${CYAN}╔════════════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${CYAN}║${NC}${WHITE}${BOLD}                    MULTI-COIN BLOCKCHAIN SYNC STATUS                   ${NC}${CYAN}║${NC}"
    echo -e "${CYAN}╚════════════════════════════════════════════════════════════════════════╝${NC}"
    echo ""

    local all_synced=true

    for coin in "${coins[@]}"; do
        setup_coin "$coin"
        local status=$(get_coin_sync_status "$coin")
        local status_type=$(echo "$status" | cut -d: -f1)

        printf "  ${COIN_EMOJI} ${WHITE}%-12s${NC} " "$COIN_NAME"

        case "$status_type" in
            not_installed)
                echo -e "${DIM}Not installed${NC}"
                ;;
            not_running)
                echo -e "${RED}Daemon not running${NC}"
                all_synced=false
                ;;
            loading)
                # Error -28: daemon is loading blocks - this is NORMAL after restart
                local loading_msg=$(echo "$status" | cut -d: -f2)
                echo -e "${CYAN}⏳ ${loading_msg}${NC} ${GREEN}(normal)${NC}"
                all_synced=false
                ;;
            not_responding)
                echo -e "${YELLOW}⏳ Starting...${NC}"
                all_synced=false
                ;;
            synced)
                local pct=$(echo "$status" | cut -d: -f2)
                local blocks=$(echo "$status" | cut -d: -f3)
                echo -e "${GREEN}✓ Synced${NC} (${blocks} blocks)"
                ;;
            syncing)
                local pct=$(echo "$status" | cut -d: -f2)
                local blocks=$(echo "$status" | cut -d: -f3)
                local headers=$(echo "$status" | cut -d: -f4)
                printf "${YELLOW}%-6s%%${NC} " "$pct"
                draw_progress_bar "$pct"
                echo ""
                all_synced=false
                ;;
        esac
    done

    echo ""

    if $all_synced; then
        if systemctl is-active --quiet spiralstratum; then
            echo -e "  ${GREEN}✓${NC} All blockchains synced - Spiral Stratum ${GREEN}ONLINE${NC}"
        else
            echo -e "  ${GREEN}✓${NC} All blockchains synced"
            echo -e "  ${YELLOW}○${NC} Spiral Stratum not running"
        fi
    else
        echo -e "  ${DIM}Sync in progress... This may take several hours.${NC}"
    fi
    echo ""
}

# Check if daemon is running (single coin mode)
if [[ "$COIN" != "multi" ]]; then
    if ! check_daemon_running "$SERVICE_NAME"; then
        echo ""
        echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo -e "${WHITE}${BOLD}  ${COIN_SYMBOL} BLOCKCHAIN SYNC STATUS${NC}"
        echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo ""
        echo -e "  ${RED}✗ ${COIN_NAME} daemon is not running${NC}"
        echo ""
        echo -e "  Start with: ${WHITE}sudo systemctl start ${SERVICE_NAME}${NC}"
        echo ""
        exit 1
    fi
fi

# Single status display function
show_status() {
    # Handle multi-coin mode
    if [[ "$COIN" == "multi" ]]; then
        show_multi_status
        return $?
    fi

    cli_call "getblockchaininfo"
    local INFO="$CLI_OUTPUT"

    if [[ -z "$INFO" ]]; then
        echo ""
        echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo -e "${WHITE}${BOLD}  ${COIN_EMOJI} ${COIN_SYMBOL} BLOCKCHAIN SYNC STATUS${NC}"
        echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo ""

        # Check if daemon is in loading state (error -28) - this is NORMAL
        if [[ "$DAEMON_LOADING" == "true" ]]; then
            echo -e "  ${CYAN}⏳ ${DAEMON_LOADING_MESSAGE}${NC}"
            echo ""
            echo -e "  ${GREEN}✓ This is normal!${NC} After a restart, the daemon must reload and verify"
            echo -e "    the blockchain from disk. This can take ${WHITE}30-60+ minutes${NC} depending"
            echo -e "    on disk speed and blockchain size."
            echo ""
            echo -e "  ${DIM}The daemon is working correctly - RPC will be available when done.${NC}"
            echo -e "  ${DIM}To see detailed progress:${NC} ${CYAN}tail -f $DATADIR/debug.log${NC}"
            echo ""
            echo -e "  ${DIM}Use ${WHITE}--watch${NC}${DIM} flag for live updates: ${WHITE}spiralpool-sync --watch${NC}"
        else
            echo -e "  ${YELLOW}⏳ Waiting for ${COIN_NAME} daemon to respond...${NC}"
            echo -e "  ${DIM}(This can take up to 5 minutes after startup)${NC}"
        fi
        echo ""
        return 1
    fi

    # Parse values
    local BLOCKS=$(echo "$INFO" | grep -o '"blocks":[^,]*' | cut -d: -f2 | tr -d ' ')
    local HEADERS=$(echo "$INFO" | grep -o '"headers":[^,]*' | cut -d: -f2 | tr -d ' ')
    local PROGRESS=$(echo "$INFO" | grep -o '"verificationprogress":[^,]*' | cut -d: -f2 | tr -d ' ')
    local IBD=$(echo "$INFO" | grep -o '"initialblockdownload":[^,]*' | cut -d: -f2 | tr -d ' ')
    local CHAIN=$(echo "$INFO" | grep -o '"chain":"[^"]*' | cut -d'"' -f4)

    # QBX has near-zero verificationprogress due to low chain work — use blocks/headers instead
    local PCT
    if [[ "$COIN_SYMBOL" == "QBX" ]] && [[ -n "$BLOCKS" ]] && [[ -n "$HEADERS" ]] && [[ "$HEADERS" -gt 0 ]]; then
        PCT=$(echo "scale=4; $BLOCKS / $HEADERS * 100" | bc 2>/dev/null | awk '{printf "%.2f", $1}')
    else
        PCT=$(echo "$PROGRESS" | awk '{printf "%.2f", $1 * 100}')
    fi
    local BLOCKS_FMT=$(format_number "$BLOCKS")
    local HEADERS_FMT=$(format_number "$HEADERS")

    # Check if synced: initialblockdownload=false is authoritative (works for BC2 and all chains)
    if [[ "$IBD" == "false" ]] || echo "$PROGRESS" | awk '{exit ($1 >= 0.9999) ? 0 : 1}'; then
        echo ""
        echo -e "${GREEN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo -e "${WHITE}${BOLD}  ${COIN_EMOJI} ${COIN_SYMBOL} BLOCKCHAIN FULLY SYNCED!${NC}"
        echo -e "${GREEN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo ""
        echo -ne "  "
        draw_progress_bar "100"
        echo -e " ${WHITE}100.00%${NC}"
        echo ""
        echo -e "  ${DIM}Chain:${NC}  ${WHITE}$CHAIN${NC}"
        echo -e "  ${DIM}Blocks:${NC} ${WHITE}$BLOCKS_FMT${NC}"
        echo ""

        # Start stratum service if not running (blockchain is synced)
        if ! systemctl is-active --quiet spiralstratum; then
            echo -e "  ${YELLOW}Starting Spiral Stratum...${NC}"
            # Start in background — ExecStartPre (wait-for-node.sh) can block for 30+ seconds
            sudo systemctl start --no-block spiralstratum 2>/dev/null || true
        fi

        # Poll stratum status with retries (ExecStartPre + startup can take 30-60s)
        local stratum_state="unknown"
        local _wait=0
        local _max_wait=60
        echo -ne "  ${YELLOW}⟳${NC} Waiting for stratum to start"
        while [[ $_wait -lt $_max_wait ]]; do
            stratum_state=$(systemctl is-active spiralstratum 2>/dev/null || echo "unknown")
            [[ "$stratum_state" == "active" ]] && break
            echo -n "."
            [[ "$stratum_state" == "activating" ]] && { sleep 2; ((_wait+=2)); continue; }
            [[ "$stratum_state" == "inactive" || "$stratum_state" == "auto-restart" ]] && { sleep 3; ((_wait+=3)); continue; }
            [[ "$stratum_state" == "failed" ]] && { sleep 5; ((_wait+=5)); continue; }
            sleep 2; ((_wait+=2))
        done
        echo ""

        if [[ "$stratum_state" == "active" ]]; then
            echo -e "  ${GREEN}✓${NC} Spiral Stratum is ${GREEN}ONLINE${NC} - Ready for miners!"
        elif [[ "$stratum_state" == "activating" ]]; then
            echo -e "  ${YELLOW}⟳${NC} Spiral Stratum is ${YELLOW}starting up${NC} (waiting for node RPC)"
            echo -e "    ${DIM}This is normal - the service will be ready shortly${NC}"
            echo -e "    ${DIM}Check status: ${WHITE}systemctl status spiralstratum${NC}"
        else
            echo -e "  ${YELLOW}⟳${NC} Spiral Stratum is ${YELLOW}starting up${NC} (state: ${stratum_state})"
            echo -e "    ${DIM}The service has Restart=always and will come online automatically${NC}"
            echo -e "    ${DIM}Check status: ${WHITE}systemctl status spiralstratum${NC}"
        fi

        # Show pool address — single-coin config uses pool.address directly (no symbol: block)
        local pool_addr
        pool_addr=$(grep -E '^\s*address:' "${INSTALL_DIR}/config/config.yaml" 2>/dev/null \
            | grep -v 'PENDING_GENERATION' | head -1 \
            | sed 's/.*address:[[:space:]]*["'\'']\?\([^"'\'' ]*\)["'\'']\?.*/\1/')
        if [[ -n "$pool_addr" ]] && [[ "$pool_addr" != "PENDING_GENERATION" ]] && [[ "$pool_addr" != '""' ]]; then
            echo ""
            echo -e "  ${WHITE}Pool Address:${NC} ${GREEN}$pool_addr${NC}"
            echo -e "  ${DIM}Point your miners to this address (Username field)${NC}"
        fi
        echo ""
        return 0
    else
        # Still syncing
        local REMAINING=$((HEADERS - BLOCKS))

        # Estimate time - rough estimate based on block rate
        local MINS=$((REMAINING / 1000))
        local ETA_STR=""
        if [[ $MINS -gt 1440 ]]; then
            local DAYS=$((MINS / 1440))
            local HOURS=$(((MINS % 1440) / 60))
            ETA_STR="${DAYS}d ${HOURS}h"
        elif [[ $MINS -gt 60 ]]; then
            local HOURS=$((MINS / 60))
            local LEFTMINS=$((MINS % 60))
            ETA_STR="${HOURS}h ${LEFTMINS}m"
        elif [[ $MINS -gt 0 ]]; then
            ETA_STR="${MINS}m"
        else
            ETA_STR="< 1m"
        fi

        echo ""
        local _sync_box_w=72
        printf -v _sync_title "%-${_sync_box_w}s" "${COIN_NAME^^} BLOCKCHAIN SYNC STATUS"
        echo -e "${CYAN}╔════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${CYAN}║${NC}${WHITE}${BOLD}${_sync_title}${NC}${CYAN}║${NC}"
        echo -e "${CYAN}╚════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        echo -ne "  "
        draw_progress_bar "$PCT"
        printf " ${WHITE}%6.2f%%${NC}\n" "$PCT"
        echo ""
        # Get peer count and network stats (with retry on failure)
        cli_call "getconnectioncount" || true
        local PEER_COUNT="${CLI_OUTPUT:-0}"
        cli_call "getnettotals" || true
        local NET_INFO="$CLI_OUTPUT"
        local TOTAL_RECV=$(echo "$NET_INFO" | grep -o '"totalbytesrecv":[^,]*' | cut -d: -f2 | tr -d ' ')
        local TOTAL_SENT=$(echo "$NET_INFO" | grep -o '"totalbytessent":[^,]*' | cut -d: -f2 | tr -d ' ')

        local RECV_STR="--"
        local SENT_STR="--"
        if [[ -n "$TOTAL_RECV" ]] && [[ "$TOTAL_RECV" != "0" ]]; then
            RECV_STR=$(format_bytes $TOTAL_RECV)
        fi
        if [[ -n "$TOTAL_SENT" ]] && [[ "$TOTAL_SENT" != "0" ]]; then
            SENT_STR=$(format_bytes $TOTAL_SENT)
        fi

        local PEER_COLOR="${RED}"
        local PEER_NOTE=""
        if [[ $PEER_COUNT -ge 50 ]]; then
            PEER_COLOR="${GREEN}"
        elif [[ $PEER_COUNT -ge 20 ]]; then
            PEER_COLOR="${YELLOW}"
        else
            PEER_NOTE=" ${DIM}(low - check firewall allows peer port)${NC}"
        fi

        echo -e "  ${DIM}Chain:${NC}     ${WHITE}$CHAIN${NC}"
        echo -e "  ${DIM}Blocks:${NC}    ${WHITE}$BLOCKS_FMT${NC} / ${WHITE}$HEADERS_FMT${NC}"
        echo -e "  ${DIM}Remaining:${NC} ${YELLOW}$(format_number $REMAINING)${NC} blocks"
        echo -e "  ${DIM}ETA:${NC}       ${CYAN}~$ETA_STR${NC} ${DIM}(estimate)${NC}"
        echo -e "  ${DIM}Peers:${NC}     ${PEER_COLOR}$PEER_COUNT${NC}$PEER_NOTE"
        echo -e "  ${DIM}Traffic:${NC}   ${DIM}↓${NC} ${CYAN}$RECV_STR${NC}  ${DIM}↑${NC} ${CYAN}$SENT_STR${NC}"
        echo ""

        if [[ "$WATCH_MODE" != true ]]; then
            echo -e "  ${DIM}Tip: Run ${WHITE}spiralpool-sync --watch${NC}${DIM} for live updates${NC}"
            echo ""
            echo -e "${DIM}────────────────────────────────────────────────────────────────────────${NC}"
            echo -e " ${WHITE}What happens when sync completes:${NC}"
            echo -e "   ${GREEN}✓${NC} Spiral Stratum starts automatically (no action needed)"
            echo -e "   ${GREEN}✓${NC} Pool becomes ready to accept miner connections"
            echo -e "   ${GREEN}✓${NC} Dashboard goes live at ${WHITE}http://${LOCAL_IP}:1618${NC}"
            echo ""
            echo -e " ${YELLOW}Everything is automated - just wait for sync to finish!${NC}"
            echo -e "${DIM}────────────────────────────────────────────────────────────────────────${NC}"
            echo ""
        fi
        return 1
    fi
}

# Live watch mode with interactive controls
watch_sync() {
    # Handle multi-coin mode watch
    if [[ "$COIN" == "multi" ]]; then
        watch_sync_multi
        return $?
    fi

    # Fix terminal output processing — sudo use_pty may allocate a new PTY
    # with opost/onlcr disabled, causing \n to produce LF-only (no CR).
    # Symptom: staircase display where each line shifts progressively right.
    stty opost onlcr 2>/dev/null

    # Hide cursor
    tput civis 2>/dev/null

    # Restore cursor and terminal on exit — always exit 0 so the parent
    # install.sh doesn't mistake a user-initiated exit (Ctrl+C = exit 130)
    # for a permission failure and re-run the sync watcher 2 more times
    trap 'tput cnorm 2>/dev/null; stty sane 2>/dev/null; stty opost onlcr 2>/dev/null; exit 0' EXIT INT TERM

    clear
    local START_TIME=$(date +%s)
    local LAST_BLOCKS=0
    local LAST_CHECK_TIME=$START_TIME
    local BLOCKS_PER_SEC=0
    local DAEMON_WAIT_START=0
    local LAST_RECV=0
    local LAST_SENT=0
    local RECV_SPEED=0
    local SENT_SPEED=0
    local SPIRAL_FRAME=0

    # ETA smoothing - use exponential moving average for stable estimates
    local ETA_SMOOTH_RATE=0
    local INITIAL_BLOCKS=0
    local SPEED_SAMPLES=""
    local MAX_SAMPLES=12  # Keep last 12 samples (about 6 seconds at 0.5s intervals)

    # Draw initial header (coin-specific)
    # Uses ASCII box chars for terminal compatibility (Unicode box-drawing chars
    # render double-width on some terminals, breaking cursor-positioned displays)
    echo ""
    echo -e "${CYAN}+============================================================================+${NC}"
    printf "${CYAN}|%76s|${NC}\n" ""

    # Dynamic centering for title with coin name
    local title_text="${COIN_NAME} BLOCKCHAIN SYNC - LIVE VIEW"
    local title_len=${#title_text}
    local box_width=76  # Total width between the | borders
    local left_padding=$(( (box_width - title_len) / 2 ))
    local right_padding=$(( box_width - title_len - left_padding ))

    printf "${CYAN}|${NC}${WHITE}${BOLD}%*s%s%*s${NC}${CYAN}|${NC}\n" "$left_padding" "" "$title_text" "$right_padding" ""

    printf "${CYAN}|%76s|${NC}\n" ""
    echo -e "${CYAN}+============================================================================+${NC}"
    echo -e "${CYAN}|${NC}  ${DIM}Controls:${NC} ${WHITE}q${NC}${DIM}=quit${NC}  ${WHITE}b${NC}${DIM}=background${NC}  ${DIM}|${NC}  ${DIM}Sync continues even if you exit${NC}        ${CYAN}|${NC}"
    echo -e "${CYAN}+============================================================================+${NC}"
    echo ""
    echo ""  # Line 10: Progress bar
    echo ""  # Line 11: Blocks info
    echo ""  # Line 12: Speed/ETA
    echo ""  # Line 13: Remaining
    echo ""  # Line 14: Peers/Network
    echo ""
    echo ""
    # Line 17-26: Info box with spiral animation placeholder
    echo -e "${DIM}------------------------------------------------------------------------${NC}"
    echo -e " ${WHITE}What happens when sync completes:${NC}"
    echo -e "   ${GREEN}+${NC} Spiral Stratum starts automatically (no action needed)"
    echo -e "   ${GREEN}+${NC} Pool becomes ready to accept miner connections"
    echo -e "   ${GREEN}+${NC} Dashboard goes live at ${WHITE}http://${LOCAL_IP}:1618${NC}"
    echo ""
    echo -e " ${YELLOW}Everything is automated - just wait for sync to finish!${NC}"
    echo -e "${DIM}------------------------------------------------------------------------${NC}"
    echo ""
    echo ""  # Lines for spiral animation (28-32)

    # Suppress key echo during display (read -s also handles this per-read,
    # but this prevents stray echoes between reads)
    stty -echo 2>/dev/null

    while true; do
        # Check for keypress — bash built-in read with timeout (never blocks)
        # read -n1 internally sets non-canonical mode, -t ensures timeout,
        # -s suppresses echo. No stty -icanon or dd subprocess needed.
        local key=""
        read -rsn1 -t 0.1 key 2>/dev/null || true
        case "$key" in
            q|Q)
                tput cnorm 2>/dev/null
                stty sane 2>/dev/null
                echo ""
                echo -e "  ${DIM}Exiting... (sync continues in background)${NC}"
                echo ""
                exit 0
                ;;
            b|B)
                tput cnorm 2>/dev/null
                stty sane 2>/dev/null
                echo ""
                echo ""
                echo -e "  ${GREEN}✓${NC} Sync monitor backgrounded"
                echo -e "  ${DIM}Run ${WHITE}spiralpool-sync --watch${NC}${DIM} to return to live view${NC}"
                echo -e "  ${DIM}Run ${WHITE}spiralpool-sync${NC}${DIM} for quick status check${NC}"
                echo ""
                exit 0
                ;;
        esac

        cli_call "getblockchaininfo"
        local CLI_RESULT=$?
        local INFO="$CLI_OUTPUT"
        local CURRENT_TIME=$(date +%s)

        # Check if daemon is in loading state (error -28) - this is NORMAL after restart
        if [[ "$DAEMON_LOADING" == "true" ]]; then
            # Track how long we've been in loading state
            if [[ $DAEMON_WAIT_START -eq 0 ]]; then
                DAEMON_WAIT_START=$CURRENT_TIME
            fi
            local WAIT_SECS=$((CURRENT_TIME - DAEMON_WAIT_START))
            local WAIT_MINS=$((WAIT_SECS / 60))

            # Move to content area and update
            printf "\033[10;1H"  # Move to line 10

            # Show friendly loading message - this is NORMAL, not an error!
            echo -e "  ${CYAN}⏳ ${DAEMON_LOADING_MESSAGE}${NC}                                              "
            echo -e "                                                                            "
            echo -e "  ${WHITE}Time elapsed:${NC} ${WAIT_MINS}m $((WAIT_SECS % 60))s                                        "
            echo -e "                                                                            "
            echo -e "  ${GREEN}✓ This is normal!${NC} After a restart, the daemon must reload and verify   "
            echo -e "    the blockchain from disk. This can take ${WHITE}30-60+ minutes${NC} depending    "
            echo -e "    on disk speed and blockchain size.                                       "
            echo -e "                                                                            "
            echo -e "  ${DIM}The daemon is working correctly - RPC will be available when done.${NC}      "
            echo -e "  ${DIM}You can safely close this window; loading continues in background.${NC}      "
            echo -e "                                                                            "
            echo -e "  ${DIM}To see detailed progress:${NC} ${CYAN}tail -f $DATADIR/debug.log${NC}                   "

            sleep 5  # Check every 5 seconds during loading
            continue
        fi

        if [[ -z "$INFO" ]]; then
            # Track how long we've been waiting
            if [[ $DAEMON_WAIT_START -eq 0 ]]; then
                DAEMON_WAIT_START=$CURRENT_TIME
            fi
            local WAIT_SECS=$((CURRENT_TIME - DAEMON_WAIT_START))

            # Calculate outage duration if we have one
            local OUTAGE_DURATION=0
            if [[ $OUTAGE_START_TIME -gt 0 ]]; then
                OUTAGE_DURATION=$((CURRENT_TIME - OUTAGE_START_TIME))
            fi

            # Move to content area and update
            printf "\033[10;1H"  # Move to line 10

            # Check if this is a network issue vs daemon issue
            local DAEMON_RUNNING=$(systemctl is-active "$SERVICE_NAME" 2>/dev/null || echo "unknown")

            # Check for RPC auth failure specifically (return code 2 from check_network)
            local NET_CHECK_OUTPUT
            NET_CHECK_OUTPUT=$(check_network 2>&1)
            local NET_CHECK_RC=$?

            if [[ "$DAEMON_RUNNING" == "active" ]] && [[ $NET_CHECK_RC -eq 2 ]] || echo "$NET_CHECK_OUTPUT" | grep -q "RPC_AUTH_FAILURE"; then
                # RPC auth failure — password mismatch between qbitx.conf and running daemon
                echo -e "  ${RED}⚠ RPC AUTH FAILURE — password mismatch${NC}                               "
                echo -e "                                                                            "
                echo -e "  ${YELLOW}The daemon is running but rejecting the CLI password.${NC}                  "
                echo -e "  ${WHITE}Fix:${NC} ${CYAN}sudo systemctl restart $SERVICE_NAME${NC}                             "
                echo -e "  ${DIM}This reloads qbitx.conf and syncs the password with the CLI.${NC}           "
                echo -e "                                                                            "
            elif [[ "$DAEMON_RUNNING" == "active" ]] && [[ $CONSECUTIVE_FAILURES -gt 0 ]]; then
                # Daemon running but CLI failing - likely network or temporary issue
                local CHECK_INTERVAL=$(get_check_interval)

                if [[ "$NETWORK_WAS_DOWN" == "true" ]] || [[ $OUTAGE_DURATION -ge $OUTAGE_THRESHOLD ]]; then
                    # Prolonged outage (3+ minutes) - network/internet outage
                    local OUTAGE_STR=$(format_outage_duration $OUTAGE_DURATION)
                    echo -e "  ${RED}⚠ NETWORK OUTAGE DETECTED${NC} - Duration: ${WHITE}$OUTAGE_STR${NC}                "
                    echo -e "                                                                            "
                    echo -e "  ${YELLOW}Self-healing active${NC} - checking every ${WHITE}${CHECK_INTERVAL}s${NC}                        "
                    echo -e "  ${DIM}Will automatically resume when connectivity is restored.${NC}               "
                    echo -e "                                                                            "
                    echo -e "  ${DIM}The blockchain daemon continues syncing in the background.${NC}             "
                    echo -e "  ${DIM}Sync progress is preserved - will resume where it left off.${NC}              "
                else
                    # Short interruption - not yet classified as outage
                    echo -e "  ${YELLOW}⚠ Connection interrupted - reconnecting...${NC} ${DIM}(${CONSECUTIVE_FAILURES} attempts)${NC}  "
                    echo -e "                                                                            "
                    echo -e "  ${DIM}Daemon is running, waiting for RPC to respond...${NC}                        "
                    echo -e "  ${DIM}This can happen during network issues or heavy load.${NC}                    "
                    echo -e "                                                                            "
                    echo -e "  ${DIM}Checking every ${WHITE}${CHECK_INTERVAL}s${NC}${DIM} - will auto-resume when restored.${NC}           "
                fi
            elif [[ $WAIT_SECS -gt 90 ]]; then
                # Extended wait - show troubleshooting info (only if NOT in loading state)
                echo -e "  ${RED}⚠ Daemon not responding after ${WAIT_SECS}s${NC}                              "
                echo -e "                                                                            "
                echo -e "  ${WHITE}Troubleshooting:${NC}                                                      "
                echo -e "    ${DIM}1. Check daemon status:${NC} ${CYAN}systemctl status $SERVICE_NAME${NC}               "
                echo -e "    ${DIM}2. Check daemon logs:${NC}   ${CYAN}journalctl -u $SERVICE_NAME -n 50${NC}            "
                echo -e "    ${DIM}3. Restart daemon:${NC}      ${CYAN}sudo systemctl restart $SERVICE_NAME${NC}          "
                echo -e "                                                                            "
                echo -e "  ${DIM}Press 'q' to quit and troubleshoot manually${NC}                           "
            else
                echo -e "  ${YELLOW}⏳ Waiting for daemon to respond... ${WHITE}(${WAIT_SECS}s)${NC}                    "
                echo -e "                                                                            "
                echo -e "  ${DIM}The daemon can take up to 5 minutes to initialize after starting.${NC}      "
                echo -e "  ${DIM}This is normal - please wait...${NC}                                        "
            fi

            # Use appropriate check interval based on outage state
            local SLEEP_TIME=$(get_check_interval)
            sleep $SLEEP_TIME
            continue
        fi

        # Connection restored! Reset all failure tracking
        if [[ $CONSECUTIVE_FAILURES -gt 0 ]] || [[ "$NETWORK_WAS_DOWN" == "true" ]]; then
            # We just recovered from an outage
            if [[ "$NETWORK_WAS_DOWN" == "true" ]]; then
                # Log recovery from major outage
                local RECOVERY_DURATION=0
                if [[ $OUTAGE_START_TIME -gt 0 ]]; then
                    RECOVERY_DURATION=$((CURRENT_TIME - OUTAGE_START_TIME))
                fi
                # Brief flash of recovery message (will be overwritten by normal display)
            fi
            NETWORK_WAS_DOWN=false
        fi
        DAEMON_WAIT_START=0
        CONSECUTIVE_FAILURES=0
        OUTAGE_START_TIME=0

        # Parse values
        local PROGRESS=$(echo "$INFO" | grep -o '"verificationprogress":[^,]*' | cut -d: -f2 | tr -d ' ')
        local IBD=$(echo "$INFO" | grep -o '"initialblockdownload":[^,]*' | cut -d: -f2 | tr -d ' ')
        local BLOCKS=$(echo "$INFO" | grep -o '"blocks":[^,]*' | cut -d: -f2 | tr -d ' ')
        local HEADERS=$(echo "$INFO" | grep -o '"headers":[^,]*' | cut -d: -f2 | tr -d ' ')

        # Handle case where daemon just started and hasn't discovered chain yet
        if [[ -z "$HEADERS" ]] || [[ "$HEADERS" == "0" ]]; then
            printf "\033[10;1H"
            echo -e "  ${YELLOW}⏳ Connecting to network peers...${NC}                                      "
            echo -e "                                                                            "
            echo -e "  ${DIM}The daemon is running but hasn't discovered the blockchain yet.${NC}        "
            echo -e "  ${DIM}This is normal - waiting for peer connections...${NC}                       "
            echo -e "                                                                            "
            echo -e "  ${DIM}Checking every second...${NC}                                               "
            sleep 1
            continue
        fi

        # QBX has near-zero verificationprogress due to low chain work — use blocks/headers instead
        local PCT
        if [[ "$COIN_SYMBOL" == "QBX" ]] && [[ -n "$BLOCKS" ]] && [[ -n "$HEADERS" ]] && [[ "$HEADERS" -gt 0 ]]; then
            PCT=$(echo "scale=4; $BLOCKS / $HEADERS * 100" | bc 2>/dev/null | awk '{printf "%.2f", $1}')
        else
            PCT=$(echo "$PROGRESS" | awk '{printf "%.2f", $1 * 100}')
        fi
        local BLOCKS_FMT=$(format_number "$BLOCKS")
        local HEADERS_FMT=$(format_number "$HEADERS")

        # Calculate blocks per second with smoothing for stable ETA
        local TIME_DIFF=$((CURRENT_TIME - LAST_CHECK_TIME))
        if [[ $TIME_DIFF -ge 5 ]] && [[ $LAST_BLOCKS -gt 0 ]]; then
            local BLOCKS_DIFF=$((BLOCKS - LAST_BLOCKS))
            if [[ $BLOCKS_DIFF -gt 0 ]]; then
                local INSTANT_RATE=$(echo "scale=2; $BLOCKS_DIFF / $TIME_DIFF" | bc 2>/dev/null || echo "0")

                # Add to samples (keep last MAX_SAMPLES for moving average)
                if [[ -z "$SPEED_SAMPLES" ]]; then
                    SPEED_SAMPLES="$INSTANT_RATE"
                else
                    # Count samples and trim if needed
                    local SAMPLE_COUNT=$(echo "$SPEED_SAMPLES" | tr ' ' '\n' | wc -l)
                    if [[ $SAMPLE_COUNT -ge $MAX_SAMPLES ]]; then
                        # Remove oldest sample
                        SPEED_SAMPLES=$(echo "$SPEED_SAMPLES" | cut -d' ' -f2-)
                    fi
                    SPEED_SAMPLES="$SPEED_SAMPLES $INSTANT_RATE"
                fi

                # Calculate moving average from all samples
                BLOCKS_PER_SEC=$(echo "$SPEED_SAMPLES" | tr ' ' '\n' | awk '
                    { sum += $1; count++ }
                    END { if (count > 0) printf "%.1f", sum/count; else print "0" }
                ')

                # Also calculate overall rate from start for comparison (more stable for ETA)
                if [[ $INITIAL_BLOCKS -eq 0 ]]; then
                    INITIAL_BLOCKS=$LAST_BLOCKS
                fi
                local TOTAL_ELAPSED=$((CURRENT_TIME - START_TIME))
                local TOTAL_SYNCED=$((BLOCKS - INITIAL_BLOCKS))
                if [[ $TOTAL_ELAPSED -gt 30 ]] && [[ $TOTAL_SYNCED -gt 0 ]]; then
                    ETA_SMOOTH_RATE=$(echo "scale=2; $TOTAL_SYNCED / $TOTAL_ELAPSED" | bc 2>/dev/null || echo "0")
                fi
            fi
            LAST_BLOCKS=$BLOCKS
            LAST_CHECK_TIME=$CURRENT_TIME
        elif [[ $LAST_BLOCKS -eq 0 ]]; then
            LAST_BLOCKS=$BLOCKS
            LAST_CHECK_TIME=$CURRENT_TIME
        fi

        # Check if synced: initialblockdownload=false is authoritative (works for BC2 and all chains)
        if [[ "$IBD" == "false" ]] || echo "$PROGRESS" | awk '{exit ($1 >= 0.9999) ? 0 : 1}'; then
            # Restore terminal state before showing completion
            tput cnorm 2>/dev/null
            stty sane 2>/dev/null
            # Clear and show completion
            clear
            echo ""
            echo -e "${GREEN}+========================================================================+${NC}"
            printf "${GREEN}|%72s|${NC}\n" ""
            echo -e "${GREEN}|${NC}${WHITE}${BOLD}                      BLOCKCHAIN SYNC COMPLETE!                         ${NC}${GREEN}|${NC}"
            printf "${GREEN}|%72s|${NC}\n" ""
            echo -e "${GREEN}+========================================================================+${NC}"
            echo ""
            echo -ne "  "
            draw_progress_bar "100"
            echo -e " ${GREEN}${BOLD}100.00%${NC}"
            echo ""
            echo -e "  ${DIM}Blocks:${NC} ${WHITE}$BLOCKS_FMT${NC}"
            echo ""

            # Start stratum service now that blockchain is synced
            if ! systemctl is-active --quiet spiralstratum; then
                echo -e "  ${YELLOW}Starting Spiral Stratum...${NC}"
                # Start in background (--no-block) so we can poll status ourselves.
                # ExecStartPre (wait-for-node.sh) can block systemctl start for 30+ seconds
                # doing RPC checks and wallet verification, which would make us appear hung.
                sudo systemctl start --no-block spiralstratum 2>/dev/null || true
            fi

            # Poll stratum status with retries (ExecStartPre + startup can take 30-60s)
            local stratum_state="unknown"
            local _wait=0
            local _max_wait=60
            echo -ne "  ${YELLOW}⟳${NC} Waiting for stratum to start"
            while [[ $_wait -lt $_max_wait ]]; do
                stratum_state=$(systemctl is-active spiralstratum 2>/dev/null || echo "unknown")
                [[ "$stratum_state" == "active" ]] && break
                echo -n "."
                # Still starting (ExecStartPre running or binary initializing)
                [[ "$stratum_state" == "activating" ]] && { sleep 2; ((_wait+=2)); continue; }
                # Not yet picked up by systemd or auto-restart pending
                [[ "$stratum_state" == "inactive" || "$stratum_state" == "auto-restart" ]] && { sleep 3; ((_wait+=3)); continue; }
                # Failed — but Restart=always will retry in 10s, so wait for that
                [[ "$stratum_state" == "failed" ]] && { sleep 5; ((_wait+=5)); continue; }
                # Unknown state — brief wait and recheck
                sleep 2; ((_wait+=2))
            done
            echo ""

            if [[ "$stratum_state" == "active" ]]; then
                echo -e "  ${GREEN}✓${NC} Spiral Stratum is ${GREEN}${BOLD}ONLINE${NC} - Ready for miners!"
            elif [[ "$stratum_state" == "activating" ]]; then
                echo -e "  ${YELLOW}⟳${NC} Spiral Stratum is ${YELLOW}starting up${NC} (waiting for node RPC)"
                echo -e "    ${DIM}This is normal - the service will be ready shortly${NC}"
                echo -e "    ${DIM}Check status: ${WHITE}systemctl status spiralstratum${NC}"
            else
                echo -e "  ${YELLOW}⟳${NC} Spiral Stratum is ${YELLOW}starting up${NC} (state: ${stratum_state})"
                echo -e "    ${DIM}The service has Restart=always and will come online automatically${NC}"
                echo -e "    ${DIM}Check status: ${WHITE}systemctl status spiralstratum${NC}"
            fi
            echo ""
            echo -e "  ${DIM}Your pool is ready. Connect miners to:${NC}"
            # Read stratum port from config - look for "port:" under stratum section
            # The config uses "port:" not "v1_port:", and V2 is typically port+1
            local STRATUM_V1_PORT=""

            # Try to extract port from stratum section of config
            if [[ -f /spiralpool/config/config.yaml ]]; then
                # Look for port: under stratum: section (first occurrence after stratum:)
                STRATUM_V1_PORT=$(awk '/^stratum:/{found=1; next} found && /^[a-z]/{exit} found' /spiralpool/config/config.yaml 2>/dev/null | grep -E "^[[:space:]]*port:" | head -1 | awk '{print $2}' | tr -d '"')
            fi

            # If not found, determine from coin type
            if [[ -z "$STRATUM_V1_PORT" ]]; then
                # Detect coin from config
                local config_coin=$(grep -E "^[[:space:]]*coin:" /spiralpool/config/config.yaml 2>/dev/null | head -1 | awk '{print $2}' | tr -d '"')
                case "$config_coin" in
                    digibyte) STRATUM_V1_PORT=3333 ;;
                    digibyte-scrypt) STRATUM_V1_PORT=3336 ;;
                    bitcoin) STRATUM_V1_PORT=4333 ;;
                    bitcoincash) STRATUM_V1_PORT=5333 ;;
                    bitcoinii) STRATUM_V1_PORT=6333 ;;
                    litecoin) STRATUM_V1_PORT=7333 ;;
                    dogecoin) STRATUM_V1_PORT=8335 ;;
                    pepecoin) STRATUM_V1_PORT=10335 ;;
                    catcoin) STRATUM_V1_PORT=12335 ;;
                    namecoin) STRATUM_V1_PORT=14335 ;;
                    syscoin) STRATUM_V1_PORT=15335 ;;
                    myriad|myriadcoin) STRATUM_V1_PORT=17335 ;;
                    fractal|fractalbitcoin) STRATUM_V1_PORT=18335 ;;
                    qbitx|qbx) STRATUM_V1_PORT=20335 ;;
                    *) STRATUM_V1_PORT=3333 ;;
                esac
            fi

            # V2 port mapping (most are V1+1, except DOGE=8337 and DGB-SCRYPT=3337)
            local STRATUM_V2_PORT
            case "$STRATUM_V1_PORT" in
                8335) STRATUM_V2_PORT=8337 ;;
                3336) STRATUM_V2_PORT=3337 ;;
                *) STRATUM_V2_PORT=$((STRATUM_V1_PORT + 1)) ;;
            esac

            # Use VIP for HA setups, otherwise detect server IP
            # Note: this script is in a single-quoted heredoc, so install-time variables
            # aren't available. Read VIP from config file at runtime instead.
            local connect_ip=""
            local _vip_addr=""
            if [[ -f /spiralpool/config/config.yaml ]]; then
                _vip_addr=$(grep -A5 '^vip:' /spiralpool/config/config.yaml 2>/dev/null | grep 'address:' | head -1 | awk '{print $2}' | tr -d '"' | tr -d "'")
            fi
            if [[ -n "$_vip_addr" ]] && [[ "$_vip_addr" != "0.0.0.0" ]]; then
                connect_ip="$_vip_addr"
            else
                # Detect server internal IP address (prefer private IPs)
                # Get first private IP from hostname -I (10.x, 172.16-31.x, 192.168.x)
                for ip in $(hostname -I 2>/dev/null); do
                    if [[ "$ip" =~ ^10\. ]] || [[ "$ip" =~ ^172\.(1[6-9]|2[0-9]|3[01])\. ]] || [[ "$ip" =~ ^192\.168\. ]]; then
                        connect_ip="$ip"
                        break
                    fi
                done
                # Fallback to first IP from hostname -I
                [[ -z "$connect_ip" ]] && connect_ip=$(hostname -I 2>/dev/null | awk '{print $1}')
                [[ -z "$connect_ip" ]] && connect_ip="YOUR_SERVER_IP"
            fi

            echo -e "  ${CYAN}Stratum V1: stratum+tcp://${connect_ip}:${STRATUM_V1_PORT}${NC}"
            echo -e "  ${CYAN}Stratum V2: stratum+tcp://${connect_ip}:${STRATUM_V2_PORT}${NC}"
            if [[ -n "$_vip_addr" ]] && [[ "$_vip_addr" != "0.0.0.0" ]]; then
                echo -e "  ${DIM}(VIP address — miners auto-failover to healthy node)${NC}"
            fi
            echo ""

            # Always show pool address — point miners here as their username
            local _pool_addr
            _pool_addr=$(grep -E '^\s*address:' /spiralpool/config/config.yaml 2>/dev/null \
                | grep -v 'PENDING_GENERATION' | head -1 \
                | sed 's/.*address:[[:space:]]*["'\'']\?\([^"'\'' ]*\)["'\'']\?.*/\1/')
            if [[ -n "$_pool_addr" ]]; then
                echo -e "  ${WHITE}Pool Address:${NC} ${GREEN}${_pool_addr}${NC}"
                echo -e "  ${DIM}Use this as the username on your miners${NC}"
                echo ""
            fi

            # ═══════════════════════════════════════════════════════════════════
            # AUTO-GENERATE WALLET IF REQUESTED DURING INSTALL
            # Check if any coin has PENDING_GENERATION and trigger wallet creation
            # This works for both single-coin and multi-coin modes
            # ═══════════════════════════════════════════════════════════════════
            if grep -q "PENDING_GENERATION" /spiralpool/config/config.yaml 2>/dev/null; then
                echo ""
                echo -e "${YELLOW}+========================================================================+${NC}"
                echo -e "${YELLOW}|${NC}  ${WHITE}WALLET GENERATION REQUIRED${NC}                                            ${YELLOW}|${NC}"
                echo -e "${YELLOW}+========================================================================+${NC}"
                echo ""
                echo -e "  ${WHITE}You requested wallet generation during installation.${NC}"
                echo -e "  ${WHITE}Now that the blockchain is synced, creating your wallet...${NC}"
                echo ""

                # Detect which coins need wallet generation by parsing config.yaml
                # This works for both single-coin and multi-coin modes
                # Single-coin uses: coin: "bitcoinii", address: "PENDING_GENERATION"
                # Multi-coin uses: symbol: "BC2", address: "PENDING_GENERATION"
                local WALLETS_TO_GENERATE=()
                local current_coin=""

                while IFS= read -r line; do
                    # Match symbol lines (multi-coin format): symbol: "BC2" or symbol: BC2
                    if [[ "$line" =~ symbol:[[:space:]]*\"?([A-Za-z0-9-]+)\"? ]]; then
                        current_coin="${BASH_REMATCH[1]}"
                    # Match coin lines (single-coin format): coin: "bitcoinii" or coin: bitcoinii
                    elif [[ "$line" =~ ^[[:space:]]*coin:[[:space:]]*\"?([A-Za-z0-9-]+)\"? ]]; then
                        # Map coin type to symbol for normalization
                        local coin_type="${BASH_REMATCH[1]}"
                        case "$coin_type" in
                            digibyte) current_coin="DGB" ;;
                            bitcoin) current_coin="BTC" ;;
                            bitcoincash) current_coin="BCH" ;;
                            bitcoinii) current_coin="BC2" ;;
                            namecoin) current_coin="NMC" ;;
                            syscoin) current_coin="SYS" ;;
                            myriadcoin) current_coin="XMY" ;;
                            fractalbitcoin|fractal) current_coin="FBTC" ;;
                            litecoin) current_coin="LTC" ;;
                            dogecoin) current_coin="DOGE" ;;
                            pepecoin) current_coin="PEP" ;;
                            catcoin) current_coin="CAT" ;;
                            digibyte-scrypt) current_coin="DGB-SCRYPT" ;;
                            *) current_coin="$coin_type" ;;
                        esac
                    # Match address: PENDING_GENERATION or address: "PENDING_GENERATION"
                    elif [[ "$line" =~ address:[[:space:]]*\"?PENDING_GENERATION\"? ]] && [[ -n "$current_coin" ]]; then
                        WALLETS_TO_GENERATE+=("$current_coin")
                        current_coin=""
                    fi
                done < /spiralpool/config/config.yaml

                # If no coins found via YAML parsing, try simpler approach
                if [[ ${#WALLETS_TO_GENERATE[@]} -eq 0 ]]; then
                    # Fallback: use the current coin being watched (single-coin mode)
                    if [[ -n "$COIN" ]] && [[ "$COIN" != "multi" ]]; then
                        WALLETS_TO_GENERATE+=("$COIN")
                    fi
                fi

                # Generate wallets for each coin that needs one
                for wallet_coin in "${WALLETS_TO_GENERATE[@]}"; do
                    local coin_lower="${wallet_coin,,}"
                    # Normalize coin name for CLI
                    case "$coin_lower" in
                        dgb|digibyte) coin_lower="dgb" ;;
                        btc|bitcoin) coin_lower="btc" ;;
                        bch|bitcoincash) coin_lower="bch" ;;
                        bc2|bitcoinii|bitcoin2) coin_lower="bc2" ;;
                        nmc|namecoin) coin_lower="nmc" ;;
                        sys|syscoin) coin_lower="sys" ;;
                        xmy|myriadcoin) coin_lower="xmy" ;;
                        fbtc|fractalbitcoin|fractal) coin_lower="fbtc" ;;
                        qbx|qbitx) coin_lower="qbx" ;;
                        ltc|litecoin) coin_lower="ltc" ;;
                        doge|dogecoin) coin_lower="doge" ;;
                        pep|pepecoin) coin_lower="pep" ;;
                        cat|catcoin) coin_lower="cat" ;;
                        dgb-scrypt|digibyte-scrypt) coin_lower="dgb" ;;  # Uses same wallet as DGB
                    esac

                    echo -e "  ${CYAN}Generating ${wallet_coin^^} wallet...${NC}"
                    # Try auto mode first, which should work since we just finished syncing
                    local wallet_result=0
                    spiralpool-wallet --coin "$coin_lower" --auto || wallet_result=$?

                    if [[ $wallet_result -eq 0 ]]; then
                        echo -e "  ${GREEN}✓${NC} ${wallet_coin^^} wallet created successfully"
                        # Read the generated address from config and display it prominently
                        local generated_addr
                        # Multi-coin config uses symbol: blocks; single-coin uses flat pool.address
                        if grep -q '^\s*symbol:' /spiralpool/config/config.yaml 2>/dev/null; then
                            generated_addr=$(awk -v sym="$wallet_coin" '
                                /symbol:/ { in_section = ($0 ~ "\"?"sym"\"?") }
                                in_section && /address:/ && !/PENDING_GENERATION/ {
                                    gsub(/.*address:[[:space:]]*"?/, ""); gsub(/".*/, ""); gsub(/[[:space:]]/, ""); print; exit
                                }
                            ' /spiralpool/config/config.yaml 2>/dev/null)
                        else
                            generated_addr=$(grep -E '^\s*address:' /spiralpool/config/config.yaml 2>/dev/null \
                                | grep -v 'PENDING_GENERATION' | head -1 \
                                | sed 's/.*address:[[:space:]]*["'\'']\?\([^"'\'' ]*\)["'\'']\?.*/\1/')
                        fi
                        if [[ -n "$generated_addr" ]] && [[ "$generated_addr" != "PENDING_GENERATION" ]] && [[ "$generated_addr" != '""' ]]; then
                            echo ""
                            echo -e "  ${WHITE}╔══════════════════════════════════════════════╗${NC}"
                            echo -e "  ${WHITE}║  Pool Wallet Address (point miners here):    ║${NC}"
                            echo -e "  ${WHITE}╠══════════════════════════════════════════════╣${NC}"
                            echo -e "  ${GREEN}║  $generated_addr${NC}"
                            echo -e "  ${WHITE}╚══════════════════════════════════════════════╝${NC}"
                            echo ""
                        fi
                    elif [[ $wallet_result -eq 2 ]]; then
                        # Exit code 2 = blockchain not synced (shouldn't happen here, but handle it)
                        echo -e "  ${YELLOW}⚠${NC} ${wallet_coin^^} blockchain still syncing - wallet deferred"
                        echo -e "    ${DIM}Run: spiralpool-wallet --coin ${coin_lower}${NC}"
                    else
                        echo -e "  ${YELLOW}⚠${NC} ${wallet_coin^^} wallet generation needs manual completion"
                        echo -e "    ${DIM}Run: spiralpool-wallet --coin ${coin_lower}${NC}"
                    fi
                    echo ""
                done

                # Restart stratum to pick up new addresses
                echo -e "  ${WHITE}Restarting Spiral Stratum with new wallet addresses...${NC}"
                sudo systemctl restart spiralstratum 2>/dev/null || true
                sleep 3

                if systemctl is-active --quiet spiralstratum; then
                    echo -e "  ${GREEN}✓${NC} Spiral Stratum restarted successfully"
                else
                    echo -e "  ${YELLOW}⚠${NC} Spiral Stratum may need manual restart"
                    echo -e "    ${DIM}Run: sudo systemctl restart spiralstratum${NC}"
                fi
                echo ""
            fi

            tput cnorm 2>/dev/null
            stty sane 2>/dev/null
            break
        fi

        # Calculate ETA using the more stable overall rate (ETA_SMOOTH_RATE)
        # Falls back to moving average (BLOCKS_PER_SEC) if overall not available
        local REMAINING_BLOCKS=$((HEADERS - BLOCKS))
        local ETA_STR="calculating..."

        # Prefer the overall session rate for ETA (more stable)
        local ETA_RATE="$ETA_SMOOTH_RATE"
        if [[ $(echo "$ETA_RATE <= 0" | bc 2>/dev/null || echo "1") -eq 1 ]]; then
            ETA_RATE="$BLOCKS_PER_SEC"
        fi

        if [[ $(echo "$ETA_RATE > 0" | bc 2>/dev/null || echo "0") -eq 1 ]]; then
            local ETA_SECONDS=$(echo "scale=0; $REMAINING_BLOCKS / $ETA_RATE" | bc 2>/dev/null || echo "0")
            if [[ $ETA_SECONDS -gt 0 ]]; then
                ETA_STR=$(format_time $ETA_SECONDS)
            fi
        else
            # Fallback estimate based on typical sync speeds
            # DigiByte: ~100-500 blocks/sec, BTC: ~10-50, BCH: ~50-200
            local MINS=$((REMAINING_BLOCKS / 200))  # Conservative estimate
            if [[ $MINS -gt 1440 ]]; then
                ETA_STR="$((MINS / 1440))d $((MINS % 1440 / 60))h"
            elif [[ $MINS -gt 60 ]]; then
                ETA_STR="$((MINS / 60))h $((MINS % 60))m"
            elif [[ $MINS -gt 0 ]]; then
                ETA_STR="${MINS}m"
            else
                ETA_STR="< 1m"
            fi
        fi

        # Speed string - show current moving average
        local SPEED_STR=""
        if [[ $(echo "$BLOCKS_PER_SEC > 0" | bc 2>/dev/null || echo "0") -eq 1 ]]; then
            SPEED_STR="${BLOCKS_PER_SEC} blocks/sec"
        else
            SPEED_STR="measuring..."
        fi

        # Move to content area — use explicit \033[row;1H for each line
        # instead of relying on \n for carriage return (defense-in-depth)
        printf "\033[10;1H"
        echo -ne "  "
        draw_progress_bar "$PCT"
        printf " ${WHITE}${BOLD}%6.2f%%${NC}              " "$PCT"

        printf "\033[11;1H"
        printf "  ${DIM}Blocks:${NC}    ${WHITE}%-14s${NC} / ${WHITE}%-14s${NC}        " "$BLOCKS_FMT" "$HEADERS_FMT"

        printf "\033[12;1H"
        printf "  ${DIM}Speed:${NC}     ${CYAN}%-18s${NC} ${DIM}ETA:${NC} ${YELLOW}%-12s${NC}                    " "$SPEED_STR" "~$ETA_STR"

        printf "\033[13;1H"
        printf "  ${DIM}Remaining:${NC} ${MAGENTA}%-14s${NC} blocks                      " "$(format_number $REMAINING_BLOCKS)"

        # Get peer count and network stats (with retry on failure)
        cli_call "getconnectioncount" || true
        local PEER_COUNT="${CLI_OUTPUT:-0}"
        cli_call "getnettotals" || true
        local NET_INFO="$CLI_OUTPUT"
        local TOTAL_RECV=$(echo "$NET_INFO" | grep -o '"totalbytesrecv":[^,]*' | cut -d: -f2 | tr -d ' ')
        local TOTAL_SENT=$(echo "$NET_INFO" | grep -o '"totalbytessent":[^,]*' | cut -d: -f2 | tr -d ' ')

        # Calculate network speed (bytes per second)
        if [[ -n "$TOTAL_RECV" ]] && [[ "$TOTAL_RECV" != "0" ]] && [[ $LAST_RECV -gt 0 ]] && [[ $TIME_DIFF -gt 0 ]]; then
            local RECV_DIFF=$((TOTAL_RECV - LAST_RECV))
            if [[ $RECV_DIFF -gt 0 ]]; then
                RECV_SPEED=$((RECV_DIFF / TIME_DIFF))
            fi
        fi
        if [[ -n "$TOTAL_SENT" ]] && [[ "$TOTAL_SENT" != "0" ]] && [[ $LAST_SENT -gt 0 ]] && [[ $TIME_DIFF -gt 0 ]]; then
            local SENT_DIFF=$((TOTAL_SENT - LAST_SENT))
            if [[ $SENT_DIFF -gt 0 ]]; then
                SENT_SPEED=$((SENT_DIFF / TIME_DIFF))
            fi
        fi

        # Update last values for next iteration
        [[ -n "$TOTAL_RECV" ]] && [[ "$TOTAL_RECV" != "0" ]] && LAST_RECV=$TOTAL_RECV
        [[ -n "$TOTAL_SENT" ]] && [[ "$TOTAL_SENT" != "0" ]] && LAST_SENT=$TOTAL_SENT

        # Format network traffic (total and speed)
        local RECV_STR="--"
        local SENT_STR="--"
        local RECV_SPEED_STR=""
        local SENT_SPEED_STR=""
        if [[ -n "$TOTAL_RECV" ]] && [[ "$TOTAL_RECV" != "0" ]]; then
            RECV_STR=$(format_bytes $TOTAL_RECV)
            if [[ $RECV_SPEED -gt 0 ]]; then
                RECV_SPEED_STR=" ($(format_speed $RECV_SPEED))"
            fi
        fi
        if [[ -n "$TOTAL_SENT" ]] && [[ "$TOTAL_SENT" != "0" ]]; then
            SENT_STR=$(format_bytes $TOTAL_SENT)
            if [[ $SENT_SPEED -gt 0 ]]; then
                SENT_SPEED_STR=" ($(format_speed $SENT_SPEED))"
            fi
        fi

        # Peers and network traffic with speeds
        local PEER_COLOR="${RED}"
        if [[ $PEER_COUNT -ge 50 ]]; then
            PEER_COLOR="${GREEN}"
        elif [[ $PEER_COUNT -ge 20 ]]; then
            PEER_COLOR="${YELLOW}"
        fi
        printf "\033[14;1H"
        printf "  ${DIM}Peers:${NC}     ${PEER_COLOR}%-4s${NC}  ${DIM}↓${NC} ${CYAN}%-10s${NC}${GREEN}%-12s${NC} ${DIM}↑${NC} ${CYAN}%-10s${NC}${GREEN}%-12s${NC}    " "$PEER_COUNT" "$RECV_STR" "$RECV_SPEED_STR" "$SENT_STR" "$SENT_SPEED_STR"

        # Clear line 15 (leftover from waiting-for-peers phase) and update timestamp
        printf "\033[15;1H"
        printf "                                                                              "
        printf "\033[16;1H"
        printf "  ${DIM}Updated: $(date '+%H:%M:%S')${NC}                                              "

        # Use normal check interval when connection is healthy
        sleep $NORMAL_CHECK_INTERVAL
    done
}

# Multi-coin watch mode - shows all coins syncing simultaneously
watch_sync_multi() {
    # Fix terminal output processing (see watch_sync comment for details)
    stty opost onlcr 2>/dev/null

    # Hide cursor
    tput civis 2>/dev/null

    # Restore cursor and terminal on exit — always exit 0 so the parent
    # install.sh doesn't mistake a user-initiated exit (Ctrl+C = exit 130)
    # for a permission failure and re-run the sync watcher 2 more times
    trap 'tput cnorm 2>/dev/null; stty sane 2>/dev/null; stty opost onlcr 2>/dev/null; exit 0' EXIT INT TERM

    local coins=($(detect_coins))
    local num_coins=${#coins[@]}

    while true; do
        clear
        echo ""
        echo -e "${CYAN}+============================================================================+${NC}"
        printf "${CYAN}|%76s|${NC}\n" ""
        echo -e "${CYAN}|${NC}${WHITE}${BOLD}              MULTI-COIN BLOCKCHAIN SYNC - LIVE VIEW                      ${NC}${CYAN}|${NC}"
        printf "${CYAN}|%76s|${NC}\n" ""
        echo -e "${CYAN}+============================================================================+${NC}"
        echo -e "${CYAN}|${NC}  ${DIM}Controls:${NC} ${WHITE}q${NC}${DIM}=quit${NC}  ${WHITE}b${NC}${DIM}=background${NC}  ${DIM}|${NC}  ${DIM}Sync continues even if you exit${NC}        ${CYAN}|${NC}"
        echo -e "${CYAN}+============================================================================+${NC}"
        echo ""

        local all_synced=true

        for coin in "${coins[@]}"; do
            setup_coin "$coin"
            local status=$(get_coin_sync_status "$coin")
            local status_type=$(echo "$status" | cut -d: -f1)

            echo -e "  ${COIN_EMOJI} ${WHITE}${BOLD}${COIN_NAME}${NC}"

            case "$status_type" in
                not_installed)
                    echo -e "     ${DIM}Not installed${NC}"
                    ;;
                not_running)
                    echo -e "     ${RED}⚠ Daemon not running${NC}"
                    echo -e "     ${DIM}Start with: sudo systemctl start ${SERVICE_NAME}${NC}"
                    all_synced=false
                    ;;
                loading)
                    # Error -28: daemon is loading blocks - this is NORMAL after restart
                    local loading_msg=$(echo "$status" | cut -d: -f2)
                    echo -e "     ${CYAN}⏳ ${loading_msg}...${NC}"
                    echo -e "     ${GREEN}✓ Normal${NC} ${DIM}- daemon is rebuilding from disk (can take 30-60+ min)${NC}"
                    all_synced=false
                    ;;
                not_responding)
                    echo -e "     ${YELLOW}⏳ Waiting for daemon to respond...${NC}"
                    all_synced=false
                    ;;
                synced)
                    local blocks=$(echo "$status" | cut -d: -f3)
                    echo -ne "     "
                    draw_progress_bar "100"
                    echo -e " ${GREEN}100.00%${NC}"
                    echo -e "     ${GREEN}✓ Fully synced${NC} ($(format_number $blocks) blocks)"
                    ;;
                syncing)
                    local pct=$(echo "$status" | cut -d: -f2)
                    local blocks=$(echo "$status" | cut -d: -f3)
                    local headers=$(echo "$status" | cut -d: -f4)
                    local remaining=$((headers - blocks))
                    echo -ne "     "
                    draw_progress_bar "$pct"
                    printf " ${YELLOW}%6.2f%%${NC}\n" "$pct"
                    echo -e "     ${DIM}Blocks:${NC} $(format_number $blocks) / $(format_number $headers) ${DIM}(${remaining} remaining)${NC}"
                    all_synced=false
                    ;;
            esac
            echo ""
        done

        echo -e "${DIM}----------------------------------------------------------------------------${NC}"

        if $all_synced; then
            if systemctl is-active --quiet spiralstratum; then
                echo -e "  ${GREEN}✓${NC} All blockchains fully synced - Spiral Stratum ${GREEN}ONLINE${NC}"
            else
                echo -e "  ${GREEN}✓${NC} All blockchains fully synced"
                echo -e "  ${YELLOW}○${NC} Spiral Stratum starting..."
            fi
        else
            echo -e "  ${DIM}Sync in progress... Updated: $(date '+%H:%M:%S')${NC}"
        fi
        echo ""

        # Check for keypress (timeout doubles as polling interval)
        local key=""
        read -rsn1 -t $NORMAL_CHECK_INTERVAL key 2>/dev/null || true
        case "$key" in
            q|Q)
                tput cnorm 2>/dev/null
                stty sane 2>/dev/null
                echo ""
                echo -e "  ${DIM}Exiting... (sync continues in background)${NC}"
                echo ""
                exit 0
                ;;
            b|B)
                tput cnorm 2>/dev/null
                stty sane 2>/dev/null
                echo ""
                echo -e "  ${GREEN}✓${NC} Sync monitor backgrounded"
                echo -e "  ${DIM}Run ${WHITE}spiralpool-sync --multi --watch${NC}${DIM} to return${NC}"
                echo ""
                exit 0
                ;;
        esac
    done
}

# Test/debug function
run_test() {
    echo -e "${CYAN}═══════════════════════════════════════════════════════════════${NC}"
    echo -e "${WHITE}${BOLD}  Spiral Pool Sync - Diagnostic Test${NC}"
    echo -e "${CYAN}═══════════════════════════════════════════════════════════════${NC}"
    echo ""

    echo -e "${WHITE}1. Checking for installed coins...${NC}"
    echo -e "   ${DIM}Looking for config files...${NC}"

    # Check each coin (SHA-256d and Scrypt)
    for coin_check in dgb btc bch bc2 nmc sys xmy fbtc qbx ltc doge pep cat; do
        case $coin_check in
            dgb) conf_path="$(get_blockchain_dir dgb)/digibyte.conf"; label="DGB" ;;
            btc) conf_path="$(get_blockchain_dir btc)/bitcoin.conf"; label="BTC" ;;
            bch) conf_path="$(get_blockchain_dir bch)/bitcoin.conf"; label="BCH" ;;
            bc2) conf_path="$(get_blockchain_dir bc2)/bitcoinii.conf"; label="BC2" ;;
            nmc) conf_path="$(get_blockchain_dir nmc)/namecoin.conf"; label="NMC" ;;
            sys) conf_path="$(get_blockchain_dir sys)/syscoin.conf"; label="SYS" ;;
            xmy) conf_path="$(get_blockchain_dir xmy)/myriadcoin.conf"; label="XMY" ;;
            fbtc) conf_path="$(get_blockchain_dir fbtc)/fractal.conf"; label="FBTC" ;;
            qbx) conf_path="$(get_blockchain_dir qbx)/qbitx.conf"; label="QBX" ;;
            ltc) conf_path="$(get_blockchain_dir ltc)/litecoin.conf"; label="LTC" ;;
            doge) conf_path="$(get_blockchain_dir doge)/dogecoin.conf"; label="DOGE" ;;
            pep) conf_path="$(get_blockchain_dir pep)/pepecoin.conf"; label="PEP" ;;
            cat) conf_path="$(get_blockchain_dir cat)/catcoin.conf"; label="CAT" ;;
        esac
        echo -n "   ${YELLOW}$label:${NC} "
        if [[ -f "$conf_path" ]]; then
            echo -e "${GREEN}✓${NC} $conf_path"
        else
            echo -e "${DIM}✗${NC} $conf_path"
        fi
    done

    echo ""
    echo -e "${WHITE}2. Auto-detected coins:${NC}"
    detected=($(detect_coins))
    if [[ ${#detected[@]} -eq 0 ]]; then
        echo -e "   ${RED}No coins detected!${NC}"
    else
        echo -e "   ${GREEN}Found: ${detected[*]}${NC}"
    fi

    echo ""
    echo -e "${WHITE}3. Selected coin: ${CYAN}$COIN${NC}"

    if [[ "$COIN" != "multi" ]] && [[ -n "$COIN" ]]; then
        echo ""
        echo -e "${WHITE}4. Configuration for $COIN_NAME:${NC}"
        echo -e "   Config file:   ${CYAN}$CONF${NC}"
        echo -e "   Data dir:      ${CYAN}$DATADIR${NC}"
        echo -e "   Service name:  ${CYAN}$SERVICE_NAME${NC}"
        echo -e "   CLI command:   ${CYAN}$CLI${NC}"

        echo ""
        echo -e "${WHITE}5. Testing daemon...${NC}"

        # Check if service is running
        echo -n "   Service status: "
        if systemctl is-active --quiet "$SERVICE_NAME" 2>/dev/null; then
            echo -e "${GREEN}running${NC}"
        else
            echo -e "${RED}not running${NC}"
            echo -e "   ${DIM}Try: sudo systemctl start $SERVICE_NAME${NC}"
        fi

        # Check if config file exists and is readable
        echo -n "   Config readable: "
        if [[ -r "$CONF" ]]; then
            echo -e "${GREEN}yes${NC}"
        else
            echo -e "${RED}no${NC}"
            echo -e "   ${DIM}Check permissions: ls -la $CONF${NC}"
        fi

        # Test CLI command
        echo -n "   CLI response: "
        cli_output=$($CLI getblockchaininfo 2>&1)
        cli_exit=$?
        if [[ $cli_exit -eq 0 ]]; then
            echo -e "${GREEN}success${NC}"
            blocks=$(echo "$cli_output" | grep -o '"blocks":[^,]*' | cut -d: -f2 | tr -d ' ')
            progress=$(echo "$cli_output" | grep -o '"verificationprogress":[^,]*' | cut -d: -f2)
            echo -e "   Current blocks: ${WHITE}$blocks${NC}"
            echo -e "   Sync progress:  ${WHITE}${progress}${NC}"
        else
            echo -e "${RED}failed${NC}"
            echo -e "   ${DIM}Error: $cli_output${NC}"
            echo ""
            echo -e "${WHITE}6. Troubleshooting:${NC}"
            echo -e "   ${DIM}a) Check service logs:${NC}"
            echo -e "      ${CYAN}sudo journalctl -u $SERVICE_NAME -n 20${NC}"
            echo -e "   ${DIM}b) Check RPC credentials in config:${NC}"
            echo -e "      ${CYAN}grep -E 'rpcuser|rpcpassword|rpcallowip' $CONF${NC}"
            echo -e "   ${DIM}c) Try CLI manually:${NC}"
            echo -e "      ${CYAN}$CLI getblockchaininfo${NC}"
        fi
    fi

    echo ""
    echo -e "${CYAN}═══════════════════════════════════════════════════════════════${NC}"
}

# Main execution
if [[ "$TEST_MODE" == true ]]; then
    run_test
elif [[ "$WATCH_MODE" == true ]]; then
    watch_sync
else
    show_status
fi
SYNCSTATUSEOF

    # Wallet generation helper script (multi-coin support)
    sudo tee /usr/local/bin/spiralpool-wallet > /dev/null << 'WALLETEOF'
#!/bin/bash
#
# Spiral Pool Wallet Generator
# Creates a wallet in the blockchain node and generates a legacy address for pool payouts
#
# Supports: DGB, BTC, BCH, BC2, NMC, SYS, XMY, FBTC, QBX (SHA256d) and LTC, DOGE, PEP, CAT (Scrypt)
#
# Usage: spiralpool-wallet [--coin dgb|btc|bch|bc2|nmc|sys|xmy|fbtc|qbx|ltc|doge|pep|cat]
#
# This script will WAIT for the blockchain to fully sync before generating the wallet.
# It can take several hours to a few days depending on your connection speed.
#

INSTALL_DIR="/spiralpool"
# Multi-disk support: load CHAIN_MOUNT_POINT so get_blockchain_dir returns the right path
MULTI_DISK_CONFIGURED="false"; CHAIN_MOUNT_POINT=""
_env="$INSTALL_DIR/config/coins.env"
if [[ -f "$_env" ]] && [[ ! -L "$_env" ]]; then
    MULTI_DISK_CONFIGURED=$(grep -oP '^MULTI_DISK_CONFIGURED=\K(true|false)$' "$_env" 2>/dev/null || echo "false")
    CHAIN_MOUNT_POINT=$(grep -oP '^CHAIN_MOUNT_POINT=\K\S+$' "$_env" 2>/dev/null || echo "")
fi
get_blockchain_dir() { local c="$1"; if [[ "$MULTI_DISK_CONFIGURED" == "true" && -n "$CHAIN_MOUNT_POINT" && -d "$CHAIN_MOUNT_POINT" ]]; then echo "$CHAIN_MOUNT_POINT/$c"; else echo "$INSTALL_DIR/$c"; fi; }
BACKUP_DIR="$INSTALL_DIR/backups"

# Colors
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
WHITE='\033[1;37m'
BLUE='\033[0;34m'
MAGENTA='\033[0;35m'
DIM='\033[2m'
BOLD='\033[1m'
NC='\033[0m'

# Progress bar characters (ASCII for terminal compatibility)
BAR_FILLED="#"
BAR_EMPTY="-"
BAR_WIDTH=40

# Prompt helper (styled input prompt)
prompt_input() {
    echo -ne "  ${GREEN}▸${NC} ${WHITE}${1}${NC}"
}

# Parse command line arguments
COIN=""  # Will be auto-detected if not specified
AUTO_MODE="false"  # Non-interactive mode for scripted calls
MANUAL_INPUT_USED="false"  # Track if manual address input was used
WALLET_GEN_WARNING=""  # Warning flag for coins with limited wallet support
while [[ $# -gt 0 ]]; do
    case $1 in
        --coin|-c)
            COIN="${2,,}"  # Convert to lowercase
            shift 2
            ;;
        --auto|-a)
            # Non-interactive mode - no prompts, just generate and exit
            AUTO_MODE="true"
            shift
            ;;
        --help|-h)
            echo "Usage: spiralpool-wallet [--coin dgb|btc|bch|bc2|nmc|sys|xmy|fbtc|qbx|ltc|doge|pep|cat] [--auto]"
            echo ""
            echo "Options:"
            echo "  --coin, -c    Coin to generate wallet for (auto-detected if not specified)"
            echo "  --auto, -a    Non-interactive mode (for scripted calls)"
            echo "  --help, -h    Show this help message"
            echo ""
            echo "SHA256d Coins:"
            echo "  dgb     DigiByte"
            echo "  btc     Bitcoin"
            echo "  bch     Bitcoin Cash"
            echo "  bc2     Bitcoin II"
            echo ""
            echo "SHA256d AuxPoW Coins (merge-mineable with Bitcoin):"
            echo "  nmc     Namecoin"
            echo "  sys     Syscoin"
            echo "  xmy     Myriad"
            echo "  fbtc    Fractal Bitcoin"
            echo "  qbx     Q-BitX"
            echo ""
            echo "Scrypt Coins:"
            echo "  ltc     Litecoin"
            echo "  doge    Dogecoin"
            echo "  pep     PepeCoin"
            echo "  cat     Catcoin"
            echo ""
            echo "Examples:"
            echo "  spiralpool-wallet              # Auto-detect coin and generate wallet"
            echo "  spiralpool-wallet --coin btc   # Generate BTC wallet"
            echo "  spiralpool-wallet --coin nmc   # Generate NMC wallet (Namecoin)"
            echo "  spiralpool-wallet --coin ltc   # Generate LTC wallet"
            echo "  spiralpool-wallet --auto       # Auto mode (no prompts)"
            exit 0
            ;;
        *)
            echo "Unknown option: $1"
            echo "Use --help for usage information"
            exit 1
            ;;
    esac
done

# ═══════════════════════════════════════════════════════════════════════════════
# SCAN INSTALLED COINS & WALLET STATUS
# ═══════════════════════════════════════════════════════════════════════════════
INSTALLED_COINS=()
# SHA-256d coins
[[ -f "$(get_blockchain_dir dgb)/digibyte.conf" ]] && INSTALLED_COINS+=("dgb")
[[ -f "$(get_blockchain_dir btc)/bitcoin.conf" ]] && INSTALLED_COINS+=("btc")
[[ -f "$(get_blockchain_dir bch)/bitcoin.conf" ]] && INSTALLED_COINS+=("bch")
[[ -f "$(get_blockchain_dir bc2)/bitcoinii.conf" ]] && INSTALLED_COINS+=("bc2")
# SHA-256d AuxPoW coins (merge-mineable with Bitcoin)
[[ -f "$(get_blockchain_dir nmc)/namecoin.conf" ]] && INSTALLED_COINS+=("nmc")
[[ -f "$(get_blockchain_dir sys)/syscoin.conf" ]] && INSTALLED_COINS+=("sys")
[[ -f "$(get_blockchain_dir xmy)/myriadcoin.conf" ]] && INSTALLED_COINS+=("xmy")
[[ -f "$(get_blockchain_dir fbtc)/fractal.conf" ]] && INSTALLED_COINS+=("fbtc")
[[ -f "$(get_blockchain_dir qbx)/qbitx.conf" ]] && INSTALLED_COINS+=("qbx")
# Scrypt coins
[[ -f "$(get_blockchain_dir ltc)/litecoin.conf" ]] && INSTALLED_COINS+=("ltc")
[[ -f "$(get_blockchain_dir doge)/dogecoin.conf" ]] && INSTALLED_COINS+=("doge")
[[ -f "$(get_blockchain_dir pep)/pepecoin.conf" ]] && INSTALLED_COINS+=("pep")
[[ -f "$(get_blockchain_dir cat)/catcoin.conf" ]] && INSTALLED_COINS+=("cat")

if [[ ${#INSTALLED_COINS[@]} -eq 0 ]]; then
    echo "Error: No blockchain nodes found in $INSTALL_DIR"
    echo "Please run the Spiral Pool installer first."
    exit 1
fi

# Read wallet addresses from config for each installed coin
declare -A COIN_ADDRESSES
PENDING_COINS=()
if [[ -f "$INSTALL_DIR/config/config.yaml" ]]; then
    current_coin=""
    while IFS= read -r line; do
        # Multi-coin format: symbol: "DGB"
        if [[ "$line" =~ symbol:[[:space:]]*\"?([A-Za-z0-9-]+)\"? ]]; then
            current_coin="${BASH_REMATCH[1],,}"
        # Single-coin format: coin: "digibyte"
        elif [[ "$line" =~ ^[[:space:]]*coin:[[:space:]]*\"?([A-Za-z0-9-]+)\"? ]]; then
            coin_type="${BASH_REMATCH[1]}"
            case "$coin_type" in
                digibyte) current_coin="dgb" ;;
                bitcoin) current_coin="btc" ;;
                bitcoincash) current_coin="bch" ;;
                bitcoinii) current_coin="bc2" ;;
                litecoin) current_coin="ltc" ;;
                dogecoin) current_coin="doge" ;;
                digibyte-scrypt) current_coin="dgb-scrypt" ;;
                namecoin) current_coin="nmc" ;;
                syscoin) current_coin="sys" ;;
                myriadcoin) current_coin="xmy" ;;
                fractalbitcoin|fractal) current_coin="fbtc" ;;
                qbitx) current_coin="qbx" ;;
                pepecoin) current_coin="pep" ;;
                catcoin) current_coin="cat" ;;
                *) current_coin="${coin_type,,}" ;;
            esac
        fi
        # Match address line
        if [[ "$line" =~ address:[[:space:]]*\"?([^\"[:space:]]+)\"? ]] && [[ -n "$current_coin" ]]; then
            COIN_ADDRESSES["$current_coin"]="${BASH_REMATCH[1]}"
            if [[ "${BASH_REMATCH[1]}" == "PENDING_GENERATION" ]]; then
                PENDING_COINS+=("$current_coin")
            fi
            current_coin=""
        fi
    done < "$INSTALL_DIR/config/config.yaml"
fi

# Helper: get emoji for a coin
coin_emoji() {
    case "$1" in
        dgb) echo "💎" ;; btc) echo "🟠" ;; bch) echo "🟢" ;; bc2) echo "🔵" ;;
        nmc) echo "🔶" ;; sys) echo "🔷" ;; xmy) echo "🔴" ;; fbtc) echo "🔶" ;; qbx) echo "⚛️" ;;
        ltc) echo "⚪" ;; doge) echo "🐕" ;; pep) echo "🐸" ;; cat) echo "🐱" ;;
        *) echo "•" ;;
    esac
}

# Helper: get display name for a coin
coin_name() {
    case "$1" in
        dgb) echo "DigiByte" ;; btc) echo "Bitcoin" ;; bch) echo "Bitcoin Cash" ;; bc2) echo "Bitcoin II" ;;
        nmc) echo "Namecoin" ;; sys) echo "Syscoin" ;; xmy) echo "Myriad" ;; fbtc) echo "Fractal Bitcoin" ;; qbx) echo "Q-BitX" ;;
        ltc) echo "Litecoin" ;; doge) echo "Dogecoin" ;; pep) echo "PepeCoin" ;; cat) echo "Catcoin" ;;
        *) echo "$1" ;;
    esac
}

# ═══════════════════════════════════════════════════════════════════════════════
# INTERACTIVE DASHBOARD (when no --coin and not --auto)
# ═══════════════════════════════════════════════════════════════════════════════
if [[ -z "$COIN" ]] && [[ "$AUTO_MODE" != "true" ]]; then
    clear
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo -e "${WHITE}${BOLD}  SPIRAL POOL WALLET MANAGER${NC}"
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${WHITE}${BOLD}INSTALLED COINS & WALLET STATUS${NC}"
    echo -e "  ${DIM}────────────────────────────────────────────────────────────${NC}"
    echo ""

    idx=0
    for c in "${INSTALLED_COINS[@]}"; do
        idx=$((idx + 1))
        c_emoji=$(coin_emoji "$c")
        c_name=$(coin_name "$c")
        c_sym="${c^^}"
        c_addr="${COIN_ADDRESSES[$c]:-}"

        if [[ "$c_addr" == "PENDING_GENERATION" ]]; then
            c_status="${YELLOW}⚠ Needs Wallet${NC}"
            c_addr_display="${YELLOW}PENDING_GENERATION${NC}"
        elif [[ -n "$c_addr" ]]; then
            c_status="${GREEN}✓ Active${NC}"
            c_addr_display="${GREEN}${c_addr}${NC}"
        else
            c_status="${DIM}─ Not Configured${NC}"
            c_addr_display="${DIM}(no address set)${NC}"
        fi

        printf "  ${WHITE}%2d)${NC}  %s %-5s %-16s %b\n" "$idx" "$c_emoji" "$c_sym" "$c_name" "$c_status"
        printf "       ${DIM}Address:${NC} %b\n" "$c_addr_display"
        echo ""
    done

    # Show merge-mining pairs if relevant parent coins are installed
    has_btc=false; has_ltc=false
    for c in "${INSTALLED_COINS[@]}"; do
        [[ "$c" == "btc" ]] && has_btc=true
        [[ "$c" == "ltc" ]] && has_ltc=true
    done

    show_merge=false
    for c in "${INSTALLED_COINS[@]}"; do
        case "$c" in nmc|fbtc|sys|xmy|doge|pep) show_merge=true ;; esac
    done

    if $show_merge; then
        echo -e "  ${WHITE}${BOLD}MERGE-MINING PAIRS${NC}"
        echo -e "  ${DIM}────────────────────────────────────────────────────────────${NC}"
        echo ""
        if $has_btc; then
            for pair_child in nmc fbtc sys xmy; do
                for c in "${INSTALLED_COINS[@]}"; do
                    if [[ "$c" == "$pair_child" ]]; then
                        case "$pair_child" in
                            nmc) chain_id=1 ;; fbtc) chain_id=8228 ;; sys) chain_id=16 ;; xmy) chain_id=90 ;;
                        esac
                        btc_a="${COIN_ADDRESSES[btc]:-}"
                        child_a="${COIN_ADDRESSES[$pair_child]:-}"
                        btc_icon="${RED}✗${NC}"; child_icon="${RED}✗${NC}"
                        [[ -n "$btc_a" ]] && [[ "$btc_a" != "PENDING_GENERATION" ]] && btc_icon="${GREEN}✓${NC}"
                        [[ -n "$child_a" ]] && [[ "$child_a" != "PENDING_GENERATION" ]] && child_icon="${GREEN}✓${NC}"
                        printf "    BTC+%-4s (%4d)   BTC:%b  %s:%b\n" "${pair_child^^}" "$chain_id" "$btc_icon" "${pair_child^^}" "$child_icon"
                    fi
                done
            done
        fi
        if $has_ltc; then
            for pair_child in doge pep; do
                for c in "${INSTALLED_COINS[@]}"; do
                    if [[ "$c" == "$pair_child" ]]; then
                        case "$pair_child" in doge) chain_id=98 ;; pep) chain_id=63 ;; esac
                        ltc_a="${COIN_ADDRESSES[ltc]:-}"
                        child_a="${COIN_ADDRESSES[$pair_child]:-}"
                        ltc_icon="${RED}✗${NC}"; child_icon="${RED}✗${NC}"
                        [[ -n "$ltc_a" ]] && [[ "$ltc_a" != "PENDING_GENERATION" ]] && ltc_icon="${GREEN}✓${NC}"
                        [[ -n "$child_a" ]] && [[ "$child_a" != "PENDING_GENERATION" ]] && child_icon="${GREEN}✓${NC}"
                        printf "    LTC+%-4s (%4d)   LTC:%b  %s:%b\n" "${pair_child^^}" "$chain_id" "$ltc_icon" "${pair_child^^}" "$child_icon"
                    fi
                done
            done
        fi
        echo ""
    fi

    echo -e "  ${DIM}────────────────────────────────────────────────────────────${NC}"
    echo ""
    echo -e "  ${WHITE}g)${NC} Generate wallet for a coin"
    echo -e "  ${WHITE}q)${NC} Quit"
    echo ""
    prompt_input "Select option: "; read dashboard_choice

    case "${dashboard_choice,,}" in
        g|gen|generate)
            echo ""
            if [[ ${#PENDING_COINS[@]} -gt 0 ]]; then
                echo -e "  ${YELLOW}Coins needing wallets:${NC} ${PENDING_COINS[*]^^}"
                echo ""
            fi
            echo "  Select coin to generate wallet for:"
            for i in "${!INSTALLED_COINS[@]}"; do
                c="${INSTALLED_COINS[$i]}"
                c_emoji=$(coin_emoji "$c")
                c_addr="${COIN_ADDRESSES[$c]:-}"
                c_tag=""
                if [[ "$c_addr" == "PENDING_GENERATION" ]]; then
                    c_tag=" ${YELLOW}(needs wallet)${NC}"
                elif [[ -n "$c_addr" ]]; then
                    c_tag=" ${DIM}(has address)${NC}"
                fi
                echo -e "    $((i+1))) ${c_emoji} ${c^^}${c_tag}"
            done
            echo ""
            prompt_input "Coin number: "; read coin_choice
            if [[ "$coin_choice" =~ ^[0-9]+$ ]] && [[ "$coin_choice" -ge 1 ]] && [[ "$coin_choice" -le ${#INSTALLED_COINS[@]} ]]; then
                COIN="${INSTALLED_COINS[$((coin_choice-1))]}"
            else
                echo -e "  ${RED}Invalid selection.${NC}"
                exit 1
            fi
            ;;
        q|quit|exit|"")
            echo ""
            echo -e "  ${GREEN}No changes made.${NC}"
            echo ""
            exit 0
            ;;
        *)
            echo -e "  ${RED}Invalid option.${NC}"
            exit 1
            ;;
    esac

elif [[ -z "$COIN" ]]; then
    # ═══════════════════════════════════════════════════════════════════════════
    # AUTO-DETECT COIN (--auto mode or --coin not specified)
    # ═══════════════════════════════════════════════════════════════════════════
    if [[ ${#PENDING_COINS[@]} -eq 1 ]]; then
        COIN="${PENDING_COINS[0]}"
        echo "Auto-detected: ${COIN^^} needs wallet generation"
    elif [[ ${#PENDING_COINS[@]} -gt 1 ]]; then
        COIN="${PENDING_COINS[0]}"
        echo "Auto-mode: Generating wallet for ${COIN^^} (first of ${#PENDING_COINS[@]} pending)"
    elif [[ ${#INSTALLED_COINS[@]} -eq 1 ]]; then
        COIN="${INSTALLED_COINS[0]}"
        echo "Auto-detected: Only ${COIN^^} is installed"
    else
        echo "Error: Multiple coins installed, please specify --coin"
        echo "Installed: ${INSTALLED_COINS[*]}"
        exit 1
    fi
fi

# Set coin-specific variables
case "$COIN" in
    dgb|digibyte)
        COIN_NAME="DigiByte"
        COIN_SYMBOL="DGB"
        COIN_EMOJI="💎"
        CONF="$(get_blockchain_dir dgb)/digibyte.conf"
        CLI="digibyte-cli -conf=$CONF"
        SERVICE_NAME="digibyted"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="D or S"
        ADDRESS_TYPE="legacy"
        WALLET_DIR="$(get_blockchain_dir dgb)"
        ;;
    dgb-scrypt|digibyte-scrypt)
        COIN_NAME="DigiByte-Scrypt"
        COIN_SYMBOL="DGB"
        COIN_EMOJI="💎"
        CONF="$(get_blockchain_dir dgb)/digibyte.conf"
        CLI="digibyte-cli -conf=$CONF"
        SERVICE_NAME="digibyted"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="D or S"
        ADDRESS_TYPE="legacy"
        WALLET_DIR="$(get_blockchain_dir dgb)"
        ;;
    btc|bitcoin)
        COIN_NAME="Bitcoin"
        COIN_SYMBOL="BTC"
        COIN_EMOJI="🟠"
        CONF="$(get_blockchain_dir btc)/bitcoin.conf"
        CLI="bitcoin-cli -conf=$CONF"
        SERVICE_NAME="bitcoind"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="bc1q, 1, or 3"
        ADDRESS_TYPE="bech32"
        WALLET_DIR="$(get_blockchain_dir btc)"
        ;;
    bch|bitcoincash)
        COIN_NAME="Bitcoin Cash"
        COIN_SYMBOL="BCH"
        COIN_EMOJI="🟢"
        CONF="$(get_blockchain_dir bch)/bitcoin.conf"
        CLI="bitcoin-cli-bch -conf=$CONF -chain=main"
        SERVICE_NAME="bitcoind-bch"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="bitcoincash:q or 1"
        ADDRESS_TYPE=""
        WALLET_DIR="$(get_blockchain_dir bch)"
        ;;
    bc2|bitcoinii|bitcoin2)
        COIN_NAME="Bitcoin II"
        COIN_SYMBOL="BC2"
        COIN_EMOJI="🔵"
        CONF="$(get_blockchain_dir bc2)/bitcoinii.conf"
        CLI="bitcoinii-cli -conf=$CONF"
        SERVICE_NAME="bitcoiniid"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="bc1q, 1, or 3 (same as BTC)"
        ADDRESS_TYPE="bech32"
        WALLET_DIR="$(get_blockchain_dir bc2)"
        # Special warning for BC2
        BC2_ADDRESS_WARNING="true"
        ;;
    # SHA-256d AuxPoW coins (merge-mineable with Bitcoin)
    nmc|namecoin)
        COIN_NAME="Namecoin"
        COIN_SYMBOL="NMC"
        COIN_EMOJI="🔶"
        CONF="$(get_blockchain_dir nmc)/namecoin.conf"
        CLI="namecoin-cli -conf=$CONF"
        SERVICE_NAME="namecoind"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="N or M"
        ADDRESS_TYPE="legacy"
        WALLET_DIR="$(get_blockchain_dir nmc)"
        ;;
    sys|syscoin)
        COIN_NAME="Syscoin"
        COIN_SYMBOL="SYS"
        COIN_EMOJI="🔷"
        CONF="$(get_blockchain_dir sys)/syscoin.conf"
        CLI="syscoin-cli -conf=$CONF"
        SERVICE_NAME="syscoind"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="sys1q or S"
        ADDRESS_TYPE="legacy"
        WALLET_DIR="$(get_blockchain_dir sys)"
        ;;
    xmy|myriad|myriadcoin)
        COIN_NAME="Myriad"
        COIN_SYMBOL="XMY"
        COIN_EMOJI="🔴"
        CONF="$(get_blockchain_dir xmy)/myriadcoin.conf"
        CLI="myriadcoin-cli -conf=$CONF"
        SERVICE_NAME="myriadcoind"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="M"
        ADDRESS_TYPE="legacy"
        WALLET_DIR="$(get_blockchain_dir xmy)"
        ;;
    ltc|litecoin)
        COIN_NAME="Litecoin"
        COIN_SYMBOL="LTC"
        COIN_EMOJI="⚪"
        CONF="$(get_blockchain_dir ltc)/litecoin.conf"
        CLI="litecoin-cli -conf=$CONF"
        SERVICE_NAME="litecoind"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="ltc1q, L, or M"
        ADDRESS_TYPE="bech32"
        WALLET_DIR="$(get_blockchain_dir ltc)"
        ;;
    doge|dogecoin)
        COIN_NAME="Dogecoin"
        COIN_SYMBOL="DOGE"
        COIN_EMOJI="🐕"
        CONF="$(get_blockchain_dir doge)/dogecoin.conf"
        CLI="dogecoin-cli -conf=$CONF"
        SERVICE_NAME="dogecoind"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="D"
        ADDRESS_TYPE="legacy"
        WALLET_DIR="$(get_blockchain_dir doge)"
        ;;
    pep|pepecoin)
        COIN_NAME="PepeCoin"
        COIN_SYMBOL="PEP"
        COIN_EMOJI="🐸"
        CONF="$(get_blockchain_dir pep)/pepecoin.conf"
        CLI="pepecoin-cli -conf=$CONF"
        SERVICE_NAME="pepecoind"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="P"
        ADDRESS_TYPE="legacy"
        WALLET_DIR="$(get_blockchain_dir pep)"
        # Note: Wallet generation may not be fully supported
        WALLET_GEN_WARNING="true"
        ;;
    cat|catcoin)
        COIN_NAME="Catcoin"
        COIN_SYMBOL="CAT"
        COIN_EMOJI="🐱"
        CONF="$(get_blockchain_dir cat)/catcoin.conf"
        CLI="catcoin-cli -conf=$CONF"
        SERVICE_NAME="catcoind"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="9"
        ADDRESS_TYPE="legacy"
        WALLET_DIR="$(get_blockchain_dir cat)"
        # Note: Wallet generation may not be fully supported
        WALLET_GEN_WARNING="true"
        ;;
    fbtc|fractalbtc|fractal|fractalbitcoin)
        COIN_NAME="Fractal Bitcoin"
        COIN_SYMBOL="FBTC"
        COIN_EMOJI="🔶"
        CONF="$(get_blockchain_dir fbtc)/fractal.conf"
        CLI="fractal-cli -conf=$CONF -datadir=$(get_blockchain_dir fbtc)"
        SERVICE_NAME="fractald"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="bc1q or 1 (same as BTC)"
        ADDRESS_TYPE="bech32"
        WALLET_DIR="$(get_blockchain_dir fbtc)"
        ;;
    qbx|qbitx)
        COIN_NAME="Q-BitX"
        COIN_SYMBOL="QBX"
        COIN_EMOJI="⚛️"
        CONF="$(get_blockchain_dir qbx)/qbitx.conf"
        CLI="qbitx-cli -conf=$CONF -datadir=$(get_blockchain_dir qbx)"
        SERVICE_NAME="qbitxd"
        CONFIG_FILE="$INSTALL_DIR/config/config.yaml"
        ADDRESS_PREFIX="M (P2PKH), P (P2SH), or pq (post-quantum)"
        ADDRESS_TYPE="pq"
        WALLET_DIR="$(get_blockchain_dir qbx)"
        ;;
    *)
        echo "Unsupported coin: $COIN"
        echo "Supported: dgb, dgb-scrypt, btc, bch, bc2, nmc, sys, xmy, fbtc, qbx (SHA256d) | ltc, doge, pep, cat (Scrypt)"
        exit 1
        ;;
esac

clear
echo ""
echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
echo -e "${WHITE}${BOLD}  SPIRAL POOL WALLET GENERATOR${NC}"
echo -e "  ${COIN_EMOJI} ${COIN_NAME} (${COIN_SYMBOL})"
echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
echo ""

# Show warning for coins with potentially unsupported wallet generation
if [[ "$WALLET_GEN_WARNING" == "true" ]]; then
    echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo -e "${WHITE}  WARNING: WALLET GENERATION MAY NOT BE FULLY SUPPORTED${NC}"
    echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${COIN_NAME} wallet generation via CLI may not work correctly."
    echo -e "  If wallet creation fails, you will need to create an address"
    echo -e "  externally using ${COIN_NAME} Core or another wallet."
    echo ""
    echo -e "  ${DIM}Check the coin's documentation for wallet instructions.${NC}"
    echo ""
fi

# ═══════════════════════════════════════════════════════════════════════════════
# CONFIRM BEFORE GENERATING (interactive mode only)
# ═══════════════════════════════════════════════════════════════════════════════
if [[ "$AUTO_MODE" != "true" ]]; then
    # Show current address if one exists in config
    CURRENT_ADDR="${COIN_ADDRESSES[${COIN}]:-}"
    # Fallback: try direct config parse for single-coin format
    if [[ -z "$CURRENT_ADDR" ]] && [[ -f "$CONFIG_FILE" ]]; then
        CURRENT_ADDR=$(grep -E "^\s*address:" "$CONFIG_FILE" 2>/dev/null | head -1 | sed 's/.*address:[[:space:]]*//' | tr -d '"' | tr -d "'" | xargs)
    fi

    if [[ -n "$CURRENT_ADDR" ]] && [[ "$CURRENT_ADDR" != "PENDING_GENERATION" ]]; then
        echo -e "  ${YELLOW}Current address:${NC} ${WHITE}${CURRENT_ADDR}${NC}"
        echo ""
        prompt_input "Generate a NEW address? This will replace the current one. (y/N): "; read confirm_gen
        if [[ ! "$confirm_gen" =~ ^[Yy] ]]; then
            echo ""
            echo -e "  ${GREEN}Keeping existing address. No changes made.${NC}"
            echo ""
            exit 0
        fi
    elif [[ "$CURRENT_ADDR" == "PENDING_GENERATION" ]]; then
        echo -e "  ${YELLOW}Status:${NC} Wallet address needed (PENDING_GENERATION)"
        echo ""
        prompt_input "Generate wallet address for ${COIN_NAME}? (Y/n): "; read confirm_gen
        if [[ "$confirm_gen" =~ ^[Nn] ]]; then
            echo ""
            echo -e "  No changes made."
            echo ""
            exit 0
        fi
    else
        prompt_input "Generate wallet address for ${COIN_NAME}? (Y/n): "; read confirm_gen
        if [[ "$confirm_gen" =~ ^[Nn] ]]; then
            echo ""
            echo -e "  No changes made."
            echo ""
            exit 0
        fi
    fi
    echo ""
fi

# Check if daemon is running
if ! systemctl is-active --quiet "$SERVICE_NAME"; then
    echo -e "  ${RED}✗ ERROR: ${COIN_NAME} daemon is not running${NC}"
    echo ""
    echo -e "  Start with: ${WHITE}sudo systemctl start ${SERVICE_NAME}${NC}"
    echo ""
    exit 1
fi

# Function to draw progress bar
draw_progress_bar() {
    local progress=$1
    local filled=$(echo "$progress $BAR_WIDTH" | awk '{printf "%d", $1 * $2 / 100}')
    local empty=$((BAR_WIDTH - filled))

    printf "${GREEN}"
    for ((i=0; i<filled; i++)); do printf "%s" "$BAR_FILLED"; done
    printf "${DIM}"
    for ((i=0; i<empty; i++)); do printf "%s" "$BAR_EMPTY"; done
    printf "${NC}"
}

# Function to format time
format_time() {
    local seconds=$1
    if [[ $seconds -lt 60 ]]; then
        echo "${seconds}s"
    elif [[ $seconds -lt 3600 ]]; then
        local mins=$((seconds / 60))
        local secs=$((seconds % 60))
        echo "${mins}m ${secs}s"
    elif [[ $seconds -lt 86400 ]]; then
        local hours=$((seconds / 3600))
        local mins=$(((seconds % 3600) / 60))
        echo "${hours}h ${mins}m"
    else
        local days=$((seconds / 86400))
        local hours=$(((seconds % 86400) / 3600))
        echo "${days}d ${hours}h"
    fi
}

# Wait for daemon to respond
echo -e "  ${YELLOW}Connecting to ${COIN_NAME} daemon...${NC}"
ATTEMPTS=0
while true; do
    INFO=$($CLI getblockchaininfo 2>/dev/null)
    if [[ -n "$INFO" ]]; then
        break
    fi
    ATTEMPTS=$((ATTEMPTS + 1))
    if [[ $ATTEMPTS -gt 30 ]]; then
        echo -e "  ${RED}✗ Failed to connect to daemon after 30 attempts${NC}"
        exit 1
    fi
    sleep 2
done

echo -e "  ${GREEN}✓${NC} Connected to ${COIN_NAME} daemon"
echo ""

# Check current sync status
# Use initialblockdownload as the authoritative sync indicator (works for all chains)
# Some chains (like BC2) may have verificationprogress < 0.9999 even when fully synced
IBD=$(echo "$INFO" | grep -o '"initialblockdownload":[^,]*' | cut -d: -f2 | tr -d ' ')
PROGRESS=$(echo "$INFO" | grep -o '"verificationprogress":[^,]*' | cut -d: -f2)
PCT=$(echo "$PROGRESS" | awk '{printf "%.4f", $1 * 100}')

# If already synced, skip the wait
# Primary check: initialblockdownload=false means sync is complete
# Fallback: verificationprogress >= 0.9999 for older daemons without IBD field
if [[ "$IBD" == "false" ]] || echo "$PROGRESS" | awk '{exit ($1 >= 0.9999) ? 0 : 1}'; then
    echo -e "  ${GREEN}✓${NC} Blockchain is already fully synced!"
    echo ""
else
    # In auto mode, exit if not synced (caller should wait for sync first)
    if [[ "$AUTO_MODE" == "true" ]]; then
        echo -e "  ${YELLOW}⚠${NC} Blockchain not yet synced (${PCT}%)"
        echo -e "  ${DIM}Auto-mode requires synced blockchain. Exiting.${NC}"
        exit 2  # Exit code 2 = not synced yet
    fi

    # Show warning and wait for user confirmation
    echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo -e "${WHITE}  BLOCKCHAIN SYNC REQUIRED${NC}"
    echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  The blockchain must fully sync before generating a wallet."
    echo -e "  This process downloads the entire ${COIN_NAME} blockchain."
    echo ""
    echo -e "  ${CYAN}Current progress:${NC} ${PCT}%"
    echo ""
    echo -e "  ${DIM}You can safely close this terminal (Ctrl+C) and return later.${NC}"
    echo -e "  ${DIM}The blockchain will continue syncing in the background.${NC}"
    echo -e "  ${DIM}Run 'spiralpool-wallet --coin ${COIN}' again when ready.${NC}"
    echo ""
    echo -e "  Press ${WHITE}ENTER${NC} to wait for sync, or ${WHITE}Ctrl+C${NC} to exit and return later."
    read -r

    echo ""
    echo -e "${CYAN}╔═══════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${CYAN}║${NC}${WHITE}${BOLD}                     BLOCKCHAIN SYNC PROGRESS                      ${NC}${CYAN}║${NC}"
    echo -e "${CYAN}╚═══════════════════════════════════════════════════════════════════╝${NC}"
    echo ""

    START_TIME=$(date +%s)
    LAST_PROGRESS=0

    # Main sync loop
    while true; do
        INFO=$($CLI getblockchaininfo 2>/dev/null)
        if [[ -z "$INFO" ]]; then
            echo -e "\r  ${YELLOW}Waiting for daemon...${NC}                                         "
            sleep 5
            continue
        fi

        # Extract values
        IBD=$(echo "$INFO" | grep -o '"initialblockdownload":[^,]*' | cut -d: -f2 | tr -d ' ')
        PROGRESS=$(echo "$INFO" | grep -o '"verificationprogress":[^,]*' | cut -d: -f2)
        BLOCKS=$(echo "$INFO" | grep -o '"blocks":[^,]*' | cut -d: -f2)
        HEADERS=$(echo "$INFO" | grep -o '"headers":[^,]*' | cut -d: -f2)

        PCT=$(echo "$PROGRESS" | awk '{printf "%.4f", $1 * 100}')
        PCT_DISPLAY=$(echo "$PROGRESS" | awk '{printf "%.2f", $1 * 100}')

        # Check if synced (initialblockdownload=false is authoritative)
        if [[ "$IBD" == "false" ]] || echo "$PROGRESS" | awk '{exit ($1 >= 0.9999) ? 0 : 1}'; then
            break
        fi

        # Calculate ETA
        CURRENT_TIME=$(date +%s)
        ELAPSED=$((CURRENT_TIME - START_TIME))

        if [[ $ELAPSED -gt 60 ]]; then
            # Calculate rate of progress
            PROGRESS_MADE=$(echo "$PROGRESS $LAST_PROGRESS" | awk '{printf "%.10f", $1 - $2}')
            if [[ $(echo "$PROGRESS_MADE" | awk '{print ($1 > 0)}') -eq 1 ]]; then
                REMAINING=$(echo "$PROGRESS" | awk '{printf "%.10f", 1.0 - $1}')
                RATE=$(echo "$PROGRESS_MADE $ELAPSED" | awk '{printf "%.15f", $1 / $2}')
                if [[ $(echo "$RATE" | awk '{print ($1 > 0)}') -eq 1 ]]; then
                    ETA_SECONDS=$(echo "$REMAINING $RATE" | awk '{printf "%d", $1 / $2}')
                    ETA_STR=$(format_time $ETA_SECONDS)
                else
                    ETA_STR="calculating..."
                fi
            else
                ETA_STR="calculating..."
            fi
        else
            ETA_STR="calculating..."
        fi

        # Draw the display
        printf "\r"
        printf "  "
        draw_progress_bar "$PCT_DISPLAY"
        printf " ${WHITE}%6.2f%%${NC}" "$PCT_DISPLAY"
        echo ""

        printf "  ${DIM}Blocks:${NC} ${WHITE}%s${NC} / ${WHITE}%s${NC}    " "$BLOCKS" "$HEADERS"
        printf "${DIM}ETA:${NC} ${CYAN}%s${NC}          \n" "$ETA_STR"

        # Move cursor back up
        printf "\033[2A"

        # Update last progress for rate calculation
        if [[ $ELAPSED -ge 60 ]] && [[ "$LAST_PROGRESS" == "0" ]]; then
            LAST_PROGRESS="$PROGRESS"
        fi

        sleep 10
    done

    # Clear the progress display
    printf "\r                                                                              \n"
    printf "\r                                                                              \n"
    printf "\033[2A"

    echo ""
    echo -e "  ${GREEN}╔═══════════════════════════════════════════════════════════════╗${NC}"
    echo -e "  ${GREEN}║${NC}${WHITE}${BOLD}                    BLOCKCHAIN SYNC COMPLETE!                  ${NC}${GREEN}║${NC}"
    echo -e "  ${GREEN}╚═══════════════════════════════════════════════════════════════╝${NC}"
    echo ""
fi

echo -e "  ${GREEN}✓${NC} Blockchain is fully synced"
echo ""

# Function to prompt for manual address input with validation
prompt_manual_address() {
    # In auto mode, cannot prompt for input - fail gracefully
    if [[ "${AUTO_MODE:-}" == "true" ]]; then
        # Determine config symbol (DGB-SCRYPT uses COIN_SYMBOL=DGB but config has DGB-SCRYPT)
        local config_sym="${COIN_SYMBOL}"
        case "$COIN" in
            dgb-scrypt|digibyte-scrypt) config_sym="DGB-SCRYPT" ;;
        esac

        # Per-coin wallet software suggestions
        local wallet_suggestion=""
        case "$COIN" in
            dgb|digibyte|dgb-scrypt|digibyte-scrypt) wallet_suggestion="DigiByte Core (digibyte.org)" ;;
            btc|bitcoin)    wallet_suggestion="Bitcoin Core (bitcoin.org), Electrum, or Sparrow Wallet" ;;
            bch|bitcoincash) wallet_suggestion="Bitcoin Cash Node (bitcoincashnode.org) or Electron Cash" ;;
            bc2|bitcoinii|bitcoin2) wallet_suggestion="Bitcoin II Core wallet" ;;
            nmc|namecoin)   wallet_suggestion="Namecoin Core (namecoin.org)" ;;
            sys|syscoin)    wallet_suggestion="Syscoin Core (syscoin.org)" ;;
            xmy|myriad|myriadcoin) wallet_suggestion="Myriad Core (myriadcoin.org)" ;;
            ltc|litecoin)   wallet_suggestion="Litecoin Core (litecoin.org) or Electrum-LTC" ;;
            doge|dogecoin)  wallet_suggestion="Dogecoin Core (dogecoin.com)" ;;
            pep|pepecoin)   wallet_suggestion="PepeCoin Core (pepecoin.org)" ;;
            cat|catcoin)    wallet_suggestion="Catcoin Core wallet" ;;
            fbtc|fractalbtc|fractal|fractalbitcoin) wallet_suggestion="Fractal Bitcoin Core wallet" ;;
            qbx|qbitx) wallet_suggestion="Q-BitX Core wallet" ;;
            *) wallet_suggestion="the official ${COIN_NAME} wallet" ;;
        esac

        echo ""
        echo -e "${RED}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo -e "  ${WHITE}${COIN_SYMBOL} WALLET GENERATION FAILED — MANUAL SETUP REQUIRED${NC}"
        echo -e "${RED}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
        echo ""
        echo -e "  Automatic wallet generation failed for ${COIN_NAME} (${COIN_SYMBOL})."
        echo -e "  You must generate a wallet address externally and set it manually."
        echo ""
        echo -e "  ${WHITE}Step 1: Generate a ${COIN_NAME} address${NC}"
        echo -e "    Recommended: ${GREEN}${wallet_suggestion}${NC}"
        echo -e "    Or use a hardware wallet (Ledger, Trezor) if supported."
        echo -e "    ${WHITE}You MUST use a wallet where YOU control the private keys.${NC}"
        echo ""
        echo -e "  ${WHITE}Expected address format:${NC} ${GREEN}${ADDRESS_PREFIX}${NC}"
        echo ""
        echo -e "${RED}╔═══════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${RED}║${NC}  ${WHITE}DO NOT USE EXCHANGE ADDRESSES${NC}                                    ${RED}║${NC}"
        echo -e "${RED}║${NC}                                                                   ${RED}║${NC}"
        echo -e "${RED}║${NC}  Exchanges (Binance, Coinbase, Kraken, etc.) often require a      ${RED}║${NC}"
        echo -e "${RED}║${NC}  memo, tag, or note to credit deposits to your account.           ${RED}║${NC}"
        echo -e "${RED}║${NC}  Pool payouts CANNOT include memos/tags. Funds sent to exchange   ${RED}║${NC}"
        echo -e "${RED}║${NC}  addresses without proper identification may be permanently LOST. ${RED}║${NC}"
        echo -e "${RED}╚═══════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        echo -e "  ${WHITE}Step 2: Set the address in config (replace YOUR_ADDRESS):${NC}"
        echo ""
        echo -e "    ${GREEN}sudo sed -i '/symbol:.*\"${config_sym}\"/,/address:/{s|address:.*|address: \"YOUR_ADDRESS\"|}' /spiralpool/config/config.yaml${NC}"
        echo ""
        echo -e "  ${WHITE}Step 3: Restart all pool services:${NC}"
        echo ""
        echo -e "    ${GREEN}sudo systemctl restart spiralstratum spiralsentinel spiraldash spiralpool-health${NC}"
        echo ""
        echo -e "  ${DIM}If running HA: repeat Steps 2-3 on all peer nodes, or copy config.yaml${NC}"
        echo -e "  ${DIM}to peers and restart services on each node.${NC}"
        echo ""
        echo -e "  ${DIM}Or run wallet setup interactively: spiralpool-wallet --coin ${COIN}${NC}"
        echo ""
        return 1
    fi

    echo ""
    echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo -e "  ${WHITE}MANUAL WALLET ADDRESS INPUT REQUIRED${NC}"
    echo -e "${YELLOW}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  Automatic wallet generation failed or is not supported."
    echo -e "  Please create a wallet address externally and enter it below."
    echo ""
    echo -e "  ${DIM}Use ${COIN_NAME} Core or another compatible wallet to create${NC}"
    echo -e "  ${DIM}an address. Check the coin's documentation for help.${NC}"
    echo ""
    echo -e "${RED}╔═══════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${RED}║${NC}  ${WHITE}WARNING: EXCHANGE ADDRESSES NOT SUPPORTED${NC}                        ${RED}║${NC}"
    echo -e "${RED}╠═══════════════════════════════════════════════════════════════════╣${NC}"
    echo -e "${RED}║${NC}                                                                   ${RED}║${NC}"
    echo -e "${RED}║${NC}  Do NOT use an exchange deposit address (Binance, Coinbase,       ${RED}║${NC}"
    echo -e "${RED}║${NC}  Kraken, etc.) for pool payouts. Exchange addresses often         ${RED}║${NC}"
    echo -e "${RED}║${NC}  require memos, tags, or notes to properly credit deposits.       ${RED}║${NC}"
    echo -e "${RED}║${NC}                                                                   ${RED}║${NC}"
    echo -e "${RED}║${NC}  Pool payouts cannot include memos/notes, and funds sent to       ${RED}║${NC}"
    echo -e "${RED}║${NC}  exchange addresses without proper identification may be LOST.    ${RED}║${NC}"
    echo -e "${RED}║${NC}                                                                   ${RED}║${NC}"
    echo -e "${RED}║${NC}  ${WHITE}USE A PERSONAL WALLET WHERE YOU CONTROL THE PRIVATE KEYS.${NC}        ${RED}║${NC}"
    echo -e "${RED}║${NC}                                                                   ${RED}║${NC}"
    echo -e "${RED}╚═══════════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo -e "  Expected address format: ${GREEN}${ADDRESS_PREFIX}${NC}"
    echo ""

    while true; do
        prompt_input "Enter ${COIN_SYMBOL} address: "; read MANUAL_ADDRESS

        # Validate address format based on coin
        local valid=false
        case "$COIN" in
            dgb|digibyte|dgb-scrypt|digibyte-scrypt)
                if [[ "$MANUAL_ADDRESS" =~ ^[DS][a-km-zA-HJ-NP-Z1-9]{25,34}$ ]] || \
                   [[ "$MANUAL_ADDRESS" =~ ^dgb1[a-z0-9]{39,59}$ ]]; then
                    valid=true
                fi
                ;;
            btc|bitcoin)
                if [[ "$MANUAL_ADDRESS" =~ ^(1|3)[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]] || \
                   [[ "$MANUAL_ADDRESS" =~ ^bc1q[a-z0-9]{38,58}$ ]]; then
                    valid=true
                fi
                ;;
            bch|bitcoincash)
                if [[ "$MANUAL_ADDRESS" =~ ^(bitcoincash:)?[qp][a-z0-9]{41}$ ]] || \
                   [[ "$MANUAL_ADDRESS" =~ ^(1|3)[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                    valid=true
                fi
                ;;
            bc2|bitcoinii|bitcoin2)
                if [[ "$MANUAL_ADDRESS" =~ ^(1|3)[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]] || \
                   [[ "$MANUAL_ADDRESS" =~ ^bc1q[a-z0-9]{38,58}$ ]]; then
                    valid=true
                fi
                ;;
            nmc|namecoin)
                if [[ "$MANUAL_ADDRESS" =~ ^[NM6][a-km-zA-HJ-NP-Z1-9]{25,34}$ ]] || \
                   [[ "$MANUAL_ADDRESS" =~ ^nc1q[a-z0-9]{38,58}$ ]]; then
                    valid=true
                fi
                ;;
            sys|syscoin)
                if [[ "$MANUAL_ADDRESS" =~ ^S[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]] || \
                   [[ "$MANUAL_ADDRESS" =~ ^sys1q[a-z0-9]{38,58}$ ]]; then
                    valid=true
                fi
                ;;
            xmy|myriad|myriadcoin)
                if [[ "$MANUAL_ADDRESS" =~ ^M[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                    valid=true
                fi
                ;;
            ltc|litecoin)
                if [[ "$MANUAL_ADDRESS" =~ ^[LM3][a-km-zA-HJ-NP-Z1-9]{25,34}$ ]] || \
                   [[ "$MANUAL_ADDRESS" =~ ^ltc1[a-z0-9]{39,59}$ ]]; then
                    valid=true
                fi
                ;;
            doge|dogecoin)
                if [[ "$MANUAL_ADDRESS" =~ ^D[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                    valid=true
                fi
                ;;
            pep|pepecoin)
                if [[ "$MANUAL_ADDRESS" =~ ^P[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                    valid=true
                fi
                ;;
            cat|catcoin)
                # Catcoin P2PKH: version byte 21 → addresses start with 9
                if [[ "$MANUAL_ADDRESS" =~ ^9[a-km-zA-HJ-NP-Z1-9]{25,34}$ ]]; then
                    valid=true
                fi
                ;;
            fbtc|fractalbtc|fractal|fractalbitcoin)
                # FBTC uses same address format as BTC
                if [[ "$MANUAL_ADDRESS" =~ ^((1|3)[a-km-zA-HJ-NP-Z1-9]{25,34}|bc1q[a-z0-9]{38,58})$ ]]; then
                    valid=true
                fi
                ;;
            qbx|qbitx)
                # QBX uses M... (P2PKH, version 0x32), P... (P2SH, version 0x37), or pq... (post-quantum Dilithium)
                if [[ "$MANUAL_ADDRESS" =~ ^(M[a-km-zA-HJ-NP-Z1-9]{25,34}|P[a-km-zA-HJ-NP-Z1-9]{25,34}|pq[a-zA-Z0-9]{20,80})$ ]]; then
                    valid=true
                fi
                ;;
            *)
                # Accept any reasonable address format for unknown coins
                if [[ ${#MANUAL_ADDRESS} -ge 26 ]] && [[ ${#MANUAL_ADDRESS} -le 62 ]]; then
                    valid=true
                fi
                ;;
        esac

        if [[ "$valid" == "true" ]]; then
            echo -e "  ${GREEN}✓${NC} Valid ${COIN_SYMBOL} address format"
            NEW_ADDRESS="$MANUAL_ADDRESS"
            MANUAL_INPUT_USED="true"
            return 0
        else
            echo -e "  ${RED}✗ Invalid address format. Expected: ${ADDRESS_PREFIX}${NC}"
            echo ""
        fi
    done
}

# ═══════════════════════════════════════════════════════════════════════════════
# HA BACKUP: Pull address from primary node (skips local wallet creation)
# Works for any number of backup nodes — each independently queries the primary.
# ═══════════════════════════════════════════════════════════════════════════════
HA_ADDR_PULLED="false"
if [[ -f "$INSTALL_DIR/config/config.yaml" ]]; then
    # Detect if this is an HA backup node by checking ha.primaryHost
    # On primary: primaryHost = local IP. On backup: primaryHost = primary's IP.
    # The primaryHost field only exists in HA configs, so its presence + non-local value
    # is the definitive indicator that this is a backup node.
    _ha_primary_host=$(grep -oP 'primaryHost:\s*"?\K[^"\s]+' "$INSTALL_DIR/config/config.yaml" 2>/dev/null | head -1)
    _local_ip=$(ip -4 addr show 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.\d+){3}' | grep -v '^127\.' | head -1)

    if [[ -n "$_ha_primary_host" ]] && \
       [[ "$_ha_primary_host" != "127.0.0.1" ]] && [[ "$_ha_primary_host" != "$_local_ip" ]]; then

        echo -e "  ${CYAN}HA backup detected — pulling ${COIN_SYMBOL} address from primary (${_ha_primary_host})...${NC}"
        _primary_addr=""

        # Method 1: Stratum API (unauthenticated, all addresses guaranteed real)
        _api_resp=$(curl -s --connect-timeout 10 --max-time 15 "http://${_ha_primary_host}:4000/api/pools" 2>/dev/null || true)
        if [[ -n "$_api_resp" ]] && echo "$_api_resp" | grep -q '"pools"'; then
            _api_coin="" _api_addr=""
            while IFS= read -r _jline; do
                if [[ "$_jline" =~ \"type\"[[:space:]]*:[[:space:]]*\"([A-Za-z0-9-]+)\" ]]; then
                    _api_coin="${BASH_REMATCH[1]}"
                fi
                if [[ "$_jline" =~ \"address\"[[:space:]]*:[[:space:]]*\"([^\"]+)\" ]]; then
                    _api_addr="${BASH_REMATCH[1]}"
                    if [[ -n "$_api_coin" ]] && [[ -n "$_api_addr" ]]; then
                        if [[ "${_api_coin,,}" == "${COIN_SYMBOL,,}" ]] || [[ "${_api_coin,,}" == "${COIN,,}" ]]; then
                            _primary_addr="$_api_addr"
                        fi
                        _api_coin="" _api_addr=""
                    fi
                fi
            done <<< "$(echo "$_api_resp" | tr ',' '\n' | tr '{' '\n' | tr '}' '\n')"
        fi

        # Method 2: SSH (keys set up during setup_system)
        if [[ -z "$_primary_addr" ]]; then
            _remote_cfg=$(ssh -i /home/spiraluser/.ssh/id_ed25519 \
                -o StrictHostKeyChecking=accept-new -o ConnectTimeout=10 -o BatchMode=yes \
                -o UserKnownHostsFile=/home/spiraluser/.ssh/known_hosts \
                "spiraluser@${_ha_primary_host}" "cat /spiralpool/config/config.yaml" 2>/dev/null || true)
            if [[ -n "$_remote_cfg" ]]; then
                _rcoin=""
                while IFS= read -r _rline; do
                    if [[ "$_rline" =~ symbol:[[:space:]]*\"?([A-Za-z0-9-]+)\"? ]]; then
                        _rcoin="${BASH_REMATCH[1],,}"
                    elif [[ "$_rline" =~ ^[[:space:]]*coin:[[:space:]]*\"?([A-Za-z0-9-]+)\"? ]]; then
                        case "${BASH_REMATCH[1]}" in
                            digibyte) _rcoin="dgb" ;; bitcoin) _rcoin="btc" ;;
                            bitcoincash) _rcoin="bch" ;; bitcoinii) _rcoin="bc2" ;;
                            litecoin) _rcoin="ltc" ;; dogecoin) _rcoin="doge" ;;
                            digibyte-scrypt) _rcoin="dgb-scrypt" ;;
                            namecoin) _rcoin="nmc" ;; syscoin) _rcoin="sys" ;;
                            myriadcoin) _rcoin="xmy" ;;
                            fractalbitcoin|fractal) _rcoin="fbtc" ;;
                            qbitx) _rcoin="qbx" ;;
                            pepecoin) _rcoin="pep" ;; catcoin) _rcoin="cat" ;;
                            *) _rcoin="${BASH_REMATCH[1],,}" ;;
                        esac
                    fi
                    if [[ "$_rline" =~ address:[[:space:]]*\"?([^\"[:space:]]+)\"? ]] && [[ -n "$_rcoin" ]]; then
                        if [[ "$_rcoin" == "${COIN_SYMBOL,,}" ]] || [[ "$_rcoin" == "${COIN,,}" ]]; then
                            _primary_addr="${BASH_REMATCH[1]}"
                        fi
                        _rcoin=""
                    fi
                done <<< "$_remote_cfg"
            fi
        fi

        # Process result
        if [[ -n "$_primary_addr" ]]; then
            if [[ "$_primary_addr" == "PENDING_GENERATION" ]]; then
                echo -e "  ${YELLOW}Primary has PENDING_GENERATION for ${COIN_SYMBOL}.${NC}"
                echo -e "  ${YELLOW}Run 'spiralpool-wallet --auto' on primary first.${NC}"
                exit 2  # sync-monitor will retry later
            else
                echo -e "  ${GREEN}✓${NC} Pulled ${COIN_SYMBOL} address from primary: ${GREEN}$_primary_addr${NC}"
                NEW_ADDRESS="$_primary_addr"
                HA_ADDR_PULLED="true"
            fi
        else
            echo -e "  ${YELLOW}Could not reach primary for ${COIN_SYMBOL} address — using local wallet${NC}"
        fi
    fi
fi

if [[ "$HA_ADDR_PULLED" != "true" ]]; then

# HA Support: Try to load the expected named wallet first.
# After ha-replicate.sh copies blockchain data from primary, the named wallet
# (e.g., pool-btc) exists on disk but may not be auto-loaded by the daemon.
# Loading it here ensures replicated wallets are detected and reused, so both
# HA nodes end up with identical wallet addresses.
WALLET_NAME="pool-${COIN_SYMBOL,,}"
LOAD_RESULT=$($CLI loadwallet "$WALLET_NAME" 2>&1)
LOAD_RC=$?
if [[ $LOAD_RC -eq 0 ]] || echo "$LOAD_RESULT" | grep -qi "already loaded"; then
    # Named wallet is available — target it for all subsequent operations
    CLI="$CLI -rpcwallet=$WALLET_NAME"
fi

# Check if wallet already exists (named wallet loaded above, or default wallet)
WALLET_INFO=$($CLI getwalletinfo 2>/dev/null)
if [[ -n "$WALLET_INFO" ]]; then
    echo -e "  ${YELLOW}A wallet already exists on this node.${NC}"
    echo ""

    # Get existing address
    EXISTING_ADDR=$($CLI listreceivedbyaddress 0 true 2>/dev/null | grep -o '"address":"[^"]*' | head -1 | cut -d'"' -f4)
    if [[ -z "$EXISTING_ADDR" ]]; then
        if [[ -n "$ADDRESS_TYPE" ]]; then
            EXISTING_ADDR=$($CLI getnewaddress "pool" "$ADDRESS_TYPE" 2>&1)
            # Old daemons (DOGE v1.14.9, PEP v1.1.0) don't accept type param — try without
            if echo "$EXISTING_ADDR" | grep -qi "error"; then
                EXISTING_ADDR=$($CLI getnewaddress "" 2>&1)
            fi
        else
            EXISTING_ADDR=$($CLI getnewaddress "pool" 2>&1)
        fi
        # If getnewaddress returned an error instead of an address, clear it
        if echo "$EXISTING_ADDR" | grep -qi "error"; then
            echo -e "  ${YELLOW}WARNING: getnewaddress failed: ${EXISTING_ADDR}${NC}"
            EXISTING_ADDR=""
        fi
    fi

    if [[ -n "$EXISTING_ADDR" ]]; then
        echo -e "  Existing address: ${GREEN}$EXISTING_ADDR${NC}"
        echo ""
        if [[ "$AUTO_MODE" == "true" ]]; then
            # Auto-mode: reuse existing address without prompting.
            # This is the correct behavior for HA replication (wallet.dat copied
            # from primary) and for re-running wallet generation on the same node.
            echo -e "  ${GREEN}✓${NC} Auto-mode: using existing wallet address"
            NEW_ADDRESS="$EXISTING_ADDR"
        else
            prompt_input "Use this address for pool payouts? (Y/n): "; read use_existing
            if [[ ! "$use_existing" =~ ^[Nn]$ ]]; then
                NEW_ADDRESS="$EXISTING_ADDR"
            else
                echo ""
                echo "  Generating new address..."
                if [[ -n "$ADDRESS_TYPE" ]]; then
                    NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "$ADDRESS_TYPE" 2>&1)
                    # Old daemons (DOGE v1.14.9, PEP v1.1.0) don't accept type param — try without
                    if echo "$NEW_ADDRESS" | grep -qi "error"; then
                        NEW_ADDRESS=$($CLI getnewaddress "" 2>&1)
                    fi
                else
                    NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" 2>&1)
                fi
                if echo "$NEW_ADDRESS" | grep -qi "error"; then
                    echo -e "  ${YELLOW}WARNING: getnewaddress failed: ${NEW_ADDRESS}${NC}"
                    NEW_ADDRESS=""
                fi
            fi
        fi
    fi
else
    # Create new wallet with coin-specific name to avoid any confusion
    # Each daemon stores wallets in its own data directory, but using unique names
    # provides additional safety and clarity (e.g., pool-dgb, pool-btc, pool-ltc)
    WALLET_NAME="pool-${COIN_SYMBOL,,}"
    echo "  Creating new wallet '${WALLET_NAME}'..."
    CREATE_RESULT=$($CLI createwallet "$WALLET_NAME" 2>&1)

    if echo "$CREATE_RESULT" | grep -qi "error"; then
        # Check if the wallet already exists (e.g., from HA replication copying wallet files)
        if echo "$CREATE_RESULT" | grep -qi "already exists\|already loaded\|Database already exists"; then
            echo -e "  ${GREEN}✓${NC} Wallet '${WALLET_NAME}' already exists — loading..."
            LOAD_RESULT=$($CLI loadwallet "$WALLET_NAME" 2>&1)
            LOAD_RC=$?
            if [[ $LOAD_RC -eq 0 ]] || echo "$LOAD_RESULT" | grep -qi "already loaded"; then
                CLI="$CLI -rpcwallet=$WALLET_NAME"
                # Try to get existing address from the loaded wallet
                EXISTING_ADDR=$($CLI listreceivedbyaddress 0 true 2>/dev/null | grep -o '"address":"[^"]*' | head -1 | cut -d'"' -f4)
                if [[ -n "$EXISTING_ADDR" ]]; then
                    echo -e "  ${GREEN}✓${NC} Found existing address: $EXISTING_ADDR"
                    if [[ "$AUTO_MODE" == "true" ]]; then
                        NEW_ADDRESS="$EXISTING_ADDR"
                    else
                        prompt_input "Use this address for pool payouts? (Y/n): "; read use_existing
                        if [[ ! "$use_existing" =~ ^[Nn]$ ]]; then
                            NEW_ADDRESS="$EXISTING_ADDR"
                        fi
                    fi
                else
                    # Wallet loaded but no address found — generate one
                    echo -e "  ${YELLOW}Wallet loaded but no address found — generating...${NC}"
                    if [[ -n "$ADDRESS_TYPE" ]]; then
                        NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "$ADDRESS_TYPE" 2>&1)
                    else
                        NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" 2>&1)
                    fi
                    if echo "$NEW_ADDRESS" | grep -qi "error"; then
                        echo -e "  ${YELLOW}WARNING: getnewaddress failed: ${NEW_ADDRESS}${NC}"
                        NEW_ADDRESS=""
                    fi
                fi
            else
                echo -e "  ${YELLOW}WARNING: Cannot load existing wallet${NC}"
                echo -e "  ${DIM}$LOAD_RESULT${NC}"
                if ! prompt_manual_address; then
                    echo -e "  ${RED}[ERROR]${NC} Cannot generate wallet address. Exiting."
                    exit 1
                fi
            fi
        else
            # createwallet not supported — try generating address from default wallet
            # Old daemons (e.g., DOGE v1.14.9, PEP v1.1.0) don't have createwallet
            # but can generate addresses via getnewaddress on the default wallet
            echo -e "  ${YELLOW}NOTE: createwallet not supported for ${COIN_NAME} — trying default wallet...${NC}"
            NEW_ADDRESS=""
            # Try with address type first (modern daemons), then without (old daemons)
            if [[ -n "$ADDRESS_TYPE" ]]; then
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "$ADDRESS_TYPE" 2>&1) || true
                if echo "$NEW_ADDRESS" | grep -qi "error"; then
                    NEW_ADDRESS=""
                fi
            fi
            if [[ -z "$NEW_ADDRESS" ]]; then
                # Old daemons: getnewaddress only takes [account], no type parameter
                NEW_ADDRESS=$($CLI getnewaddress "" 2>&1) || true
            fi

            if [[ -n "$NEW_ADDRESS" ]] && ! echo "$NEW_ADDRESS" | grep -qi "error"; then
                echo -e "  ${GREEN}✓${NC} Address generated from default wallet: $NEW_ADDRESS"
            else
                echo -e "  ${YELLOW}WARNING: Cannot generate address automatically${NC}"
                if [[ -n "$NEW_ADDRESS" ]]; then
                    echo -e "  ${DIM}$NEW_ADDRESS${NC}"
                fi
                NEW_ADDRESS=""
                if ! prompt_manual_address; then
                    echo -e "  ${RED}[ERROR]${NC} Cannot generate wallet address. Exiting."
                    exit 1
                fi
            fi
        fi
    else
        echo -e "  ${GREEN}✓${NC} Wallet created: ${WALLET_NAME}"

        # Ensure wallet is loaded (some daemons need explicit load after create)
        LOAD_RESULT=$($CLI loadwallet "$WALLET_NAME" 2>&1) || true
        if echo "$LOAD_RESULT" | grep -qi "error" && ! echo "$LOAD_RESULT" | grep -qi "already loaded"; then
            echo -e "  ${YELLOW}WARNING: Wallet load returned: ${LOAD_RESULT}${NC}"
        fi

        # Target the specific wallet for all subsequent operations
        # Prevents generating addresses from wrong wallet when multiple wallets exist
        CLI="$CLI -rpcwallet=$WALLET_NAME"
        echo ""

        # Generate new address (type varies by coin)
        # Wallet name is coin-specific (pool-dgb, pool-btc, etc.)
        echo "  Generating address (${ADDRESS_PREFIX})..."
        case "$COIN" in
            dgb|digibyte|dgb-scrypt|digibyte-scrypt)
                # DGB: Legacy addresses starting with D or S
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
                ;;
            btc|bitcoin)
                # BTC: Native SegWit (bech32) for lower fees
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "bech32" 2>&1)
                ;;
            bch|bitcoincash)
                # BCH: CashAddr format by default
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" 2>&1)
                ;;
            bc2|bitcoinii|bitcoin2)
                # BC2: Same format as BTC (bech32 or legacy)
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "bech32" 2>&1)
                ;;
            nmc|namecoin)
                # NMC: Legacy addresses starting with N or M
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
                ;;
            sys|syscoin)
                # SYS: Legacy addresses starting with S or SegWit sys1q
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
                ;;
            xmy|myriad|myriadcoin)
                # XMY: Legacy addresses starting with M
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
                ;;
            ltc|litecoin)
                # LTC: Native SegWit (bech32) for lower fees, prefix ltc1
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "bech32" 2>&1)
                ;;
            doge|dogecoin)
                # DOGE: Legacy addresses starting with D
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
                ;;
            pep|pepecoin)
                # PEP: Legacy addresses starting with P
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
                ;;
            cat|catcoin)
                # CAT: P2PKH addresses starting with 9 (version byte 21)
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
                ;;
            fbtc|fractalbtc|fractal|fractalbitcoin)
                # FBTC: Same format as BTC (bech32 or legacy)
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "bech32" 2>&1)
                ;;
            qbx|qbitx)
                # QBX: Post-quantum addresses (pq prefix) or legacy
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "pq" 2>&1)
                ;;
            *)
                # Fallback: try legacy format
                NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
                ;;
        esac

        # Check if address generation failed or returned an error
        if [[ -z "$NEW_ADDRESS" ]] || echo "$NEW_ADDRESS" | grep -qi "error"; then
            if [[ -n "$NEW_ADDRESS" ]]; then
                echo -e "  ${YELLOW}WARNING: getnewaddress failed: ${NEW_ADDRESS}${NC}"
            else
                echo -e "  ${YELLOW}WARNING: Failed to generate address (no response from daemon)${NC}"
            fi
            NEW_ADDRESS=""
            if ! prompt_manual_address; then
                echo -e "  ${RED}[ERROR]${NC} Cannot generate wallet address. Exiting."
                exit 1
            fi
        fi
    fi
fi

fi  # end if [[ "$HA_ADDR_PULLED" != "true" ]]

# Final check - if we still don't have an address, prompt for manual input
if [[ -z "$NEW_ADDRESS" ]]; then
    echo -e "  ${YELLOW}No address available. Manual input required.${NC}"
    if ! prompt_manual_address; then
        echo -e "  ${RED}[ERROR]${NC} Cannot generate wallet address. Exiting."
        exit 1
    fi
fi

# Verify address format is correct for coin
case "$COIN" in
    dgb|digibyte|dgb-scrypt|digibyte-scrypt)
        if [[ ! "$NEW_ADDRESS" =~ ^[DS] ]]; then
            echo -e "  ${YELLOW}WARNING: Unexpected address format, regenerating...${NC}"
            NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
        fi
        ;;
    btc|bitcoin)
        if [[ ! "$NEW_ADDRESS" =~ ^bc1 ]] && [[ ! "$NEW_ADDRESS" =~ ^[13] ]]; then
            echo -e "  ${YELLOW}WARNING: Unexpected address format, regenerating...${NC}"
            NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "bech32" 2>&1)
        fi
        ;;
    bch|bitcoincash)
        # BCH addresses are valid in CashAddr or legacy format
        ;;
    bc2|bitcoinii|bitcoin2)
        # BC2 uses same format as BTC
        if [[ ! "$NEW_ADDRESS" =~ ^bc1 ]] && [[ ! "$NEW_ADDRESS" =~ ^[13] ]]; then
            echo -e "  ${YELLOW}WARNING: Unexpected address format, regenerating...${NC}"
            NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "bech32" 2>&1)
        fi
        ;;
    nmc|namecoin)
        if [[ ! "$NEW_ADDRESS" =~ ^[NM6] ]] && [[ ! "$NEW_ADDRESS" =~ ^nc1q ]]; then
            echo -e "  ${YELLOW}WARNING: Unexpected address format, regenerating...${NC}"
            NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
        fi
        ;;
    sys|syscoin)
        if [[ ! "$NEW_ADDRESS" =~ ^S ]] && [[ ! "$NEW_ADDRESS" =~ ^sys1q ]]; then
            echo -e "  ${YELLOW}WARNING: Unexpected address format, regenerating...${NC}"
            NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
        fi
        ;;
    xmy|myriad|myriadcoin)
        if [[ ! "$NEW_ADDRESS" =~ ^M ]]; then
            echo -e "  ${YELLOW}WARNING: Unexpected address format, regenerating...${NC}"
            NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
        fi
        ;;
    ltc|litecoin)
        if [[ ! "$NEW_ADDRESS" =~ ^ltc1 ]] && [[ ! "$NEW_ADDRESS" =~ ^[LM3] ]]; then
            echo -e "  ${YELLOW}WARNING: Unexpected address format, regenerating...${NC}"
            NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "bech32" 2>&1)
        fi
        ;;
    doge|dogecoin)
        if [[ ! "$NEW_ADDRESS" =~ ^D ]]; then
            echo -e "  ${YELLOW}WARNING: Unexpected address format, regenerating...${NC}"
            NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
        fi
        ;;
    pep|pepecoin)
        if [[ ! "$NEW_ADDRESS" =~ ^P ]]; then
            echo -e "  ${YELLOW}WARNING: Unexpected address format, regenerating...${NC}"
            NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
        fi
        ;;
    cat|catcoin)
        if [[ ! "$NEW_ADDRESS" =~ ^9 ]]; then
            echo -e "  ${YELLOW}WARNING: Unexpected address format, regenerating...${NC}"
            NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "legacy" 2>&1)
        fi
        ;;
    fbtc|fractalbtc|fractal|fractalbitcoin)
        # FBTC uses same format as BTC
        if [[ ! "$NEW_ADDRESS" =~ ^bc1 ]] && [[ ! "$NEW_ADDRESS" =~ ^[13] ]]; then
            echo -e "  ${YELLOW}WARNING: Unexpected address format, regenerating...${NC}"
            NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "bech32" 2>&1)
        fi
        ;;
    qbx|qbitx)
        # QBX uses M... (P2PKH, version 0x32) or P... (P2SH, version 0x37)
        # getnewaddress "" pq returns M... addresses backed by Dilithium keys
        if [[ ! "$NEW_ADDRESS" =~ ^[MP] ]] && [[ ! "$NEW_ADDRESS" =~ ^pq ]]; then
            echo -e "  ${YELLOW}WARNING: Unexpected address format, regenerating...${NC}"
            NEW_ADDRESS=$($CLI getnewaddress "pool-rewards" "pq" 2>&1)
        fi
        ;;
esac

# Safety check: if verification regeneration produced an error, revert to empty and exit
if echo "$NEW_ADDRESS" | grep -qi "error"; then
    # Determine config symbol for sed command
    regen_config_sym="${COIN_SYMBOL}"
    case "$COIN" in
        dgb-scrypt|digibyte-scrypt) regen_config_sym="DGB-SCRYPT" ;;
    esac

    echo -e "  ${RED}[ERROR]${NC} Address regeneration failed: ${NEW_ADDRESS}"
    echo ""
    echo -e "  ${WHITE}To set a ${COIN_SYMBOL} address manually:${NC}"
    echo ""
    echo -e "  1. Generate a ${COIN_NAME} address using the official wallet"
    echo -e "     software or a hardware wallet (Ledger, Trezor)."
    echo -e "     ${WHITE}You MUST use a wallet where YOU control the private keys.${NC}"
    echo ""
    echo -e "  ${WHITE}Expected address format:${NC} ${GREEN}${ADDRESS_PREFIX}${NC}"
    echo ""
    echo -e "${RED}╔═══════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${RED}║${NC}  ${WHITE}DO NOT USE EXCHANGE ADDRESSES${NC}                                    ${RED}║${NC}"
    echo -e "${RED}║${NC}                                                                   ${RED}║${NC}"
    echo -e "${RED}║${NC}  Exchanges (Binance, Coinbase, Kraken, etc.) often require a      ${RED}║${NC}"
    echo -e "${RED}║${NC}  memo, tag, or note to credit deposits to your account.           ${RED}║${NC}"
    echo -e "${RED}║${NC}  Pool payouts CANNOT include memos/tags. Funds sent to exchange   ${RED}║${NC}"
    echo -e "${RED}║${NC}  addresses without proper identification may be permanently LOST. ${RED}║${NC}"
    echo -e "${RED}╚═══════════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo -e "  2. Run this command (replace YOUR_ADDRESS with your actual address):"
    echo ""
    echo -e "    ${GREEN}sudo sed -i '/symbol:.*\"${regen_config_sym}\"/,/address:/{s|address:.*|address: \"YOUR_ADDRESS\"|}' /spiralpool/config/config.yaml${NC}"
    echo ""
    echo -e "  3. Restart all pool services:"
    echo ""
    echo -e "    ${GREEN}sudo systemctl restart spiralstratum spiralsentinel spiraldash spiralpool-health${NC}"
    echo ""
    echo -e "  ${DIM}If running HA: repeat on all peer nodes.${NC}"
    echo ""
    exit 1
fi

echo ""
echo -e "${CYAN}═══════════════════════════════════════════════════════════════${NC}"
echo -e "${WHITE}  YOUR NEW POOL WALLET ADDRESS${NC}"
echo -e "${CYAN}═══════════════════════════════════════════════════════════════${NC}"
echo ""
echo -e "  ${GREEN}$NEW_ADDRESS${NC}"
echo ""

# Update pool configuration
if [[ -f "$CONFIG_FILE" ]]; then
    echo "  Updating pool configuration..."

    # Backup config first (spiraluser should own these files)
    cp "$CONFIG_FILE" "$CONFIG_FILE.bak" 2>/dev/null || sudo cp "$CONFIG_FILE" "$CONFIG_FILE.bak"

    # Escape NEW_ADDRESS for use in sed replacement string.
    # Defense-in-depth: addresses should be alphanumeric but daemon bugs or
    # manual input could inject sed metacharacters (& \ | newline).
    SAFE_ADDRESS=$(printf '%s' "$NEW_ADDRESS" | sed -e 's/[&\|]/\\&/g')

    # Update the address in config.yaml
    # SAFETY: Never blindly replace all "address:" lines — multi-coin configs have one per coin
    config_updated="false"

    if grep -q "PENDING_GENERATION" "$CONFIG_FILE" 2>/dev/null; then
        # Primary path: replace PENDING_GENERATION placeholder for THIS coin only
        sym_line=""
        sym_line=$(grep -ni "symbol:.*${COIN_SYMBOL}" "$CONFIG_FILE" 2>/dev/null | head -1 | cut -d: -f1)
        if [[ -n "$sym_line" ]]; then
            # Multi-coin: find the PENDING_GENERATION line in this coin's section
            addr_offset=""
            addr_offset=$(tail -n "+${sym_line}" "$CONFIG_FILE" | grep -n "PENDING_GENERATION" | head -1 | cut -d: -f1)
            if [[ -n "$addr_offset" ]]; then
                target_line=$((sym_line + addr_offset - 1))
                if sed -i "${target_line}s|PENDING_GENERATION|${SAFE_ADDRESS}|" "$CONFIG_FILE" 2>/dev/null || \
                   sudo sed -i "${target_line}s|PENDING_GENERATION|${SAFE_ADDRESS}|" "$CONFIG_FILE" 2>/dev/null; then
                    config_updated="true"
                fi
            fi
        else
            # Single-coin config: safe to replace the one instance
            if sed -i "s|PENDING_GENERATION|${SAFE_ADDRESS}|" "$CONFIG_FILE" 2>/dev/null || \
               sudo sed -i "s|PENDING_GENERATION|${SAFE_ADDRESS}|" "$CONFIG_FILE" 2>/dev/null; then
                config_updated="true"
            fi
        fi
    else
        # Fallback: coin-specific address replacement for regenerating existing addresses
        # Find this coin's section by symbol, then replace only that coin's address line
        sym_line=""
        sym_line=$(grep -ni "symbol:.*${COIN_SYMBOL}" "$CONFIG_FILE" 2>/dev/null | head -1 | cut -d: -f1)
        if [[ -n "$sym_line" ]]; then
            # V2 multi-coin format: find next "address:" line after the symbol line
            addr_offset=""
            addr_offset=$(tail -n "+${sym_line}" "$CONFIG_FILE" | grep -n "address:" | head -1 | cut -d: -f1)
            if [[ -n "$addr_offset" ]]; then
                target_line=$((sym_line + addr_offset - 1))
                if sed -i "${target_line}s|address:.*|address: \"${SAFE_ADDRESS}\"|" "$CONFIG_FILE" 2>/dev/null || \
                   sudo sed -i "${target_line}s|address:.*|address: \"${SAFE_ADDRESS}\"|" "$CONFIG_FILE" 2>/dev/null; then
                    config_updated="true"
                fi
            fi
        else
            # V1 single-coin format — only one address line, safe to replace
            if sed -i "s|address:.*|address: \"${SAFE_ADDRESS}\"|" "$CONFIG_FILE" 2>/dev/null || \
               sudo sed -i "s|address:.*|address: \"${SAFE_ADDRESS}\"|" "$CONFIG_FILE" 2>/dev/null; then
                config_updated="true"
            fi
        fi
    fi

    if [[ "$config_updated" == "true" ]]; then
        echo -e "  ${GREEN}✓${NC} Pool configuration updated"
    else
        echo -e "  ${YELLOW}WARNING: Could not update config automatically${NC}"
        echo -e "  ${YELLOW}Please manually set address to: ${NEW_ADDRESS}${NC}"
        echo -e "  ${YELLOW}Config file: ${CONFIG_FILE}${NC}"
    fi
    echo ""
fi

# For QBX: add wallet=<name> to qbitx.conf so it auto-loads on daemon restart.
# QBX (unlike older Bitcoin forks) does NOT auto-create a default wallet, so
# without this line the named wallet is gone after every restart.
# Only do this when a local wallet was actually generated (not manual address entry).
if [[ "$MANUAL_INPUT_USED" != "true" ]] && [[ "$COIN" == "qbx" || "$COIN" == "qbitx" ]]; then
    qbx_node_conf="$(get_blockchain_dir qbx)/qbitx.conf"
    if [[ -f "$qbx_node_conf" ]]; then
        if ! grep -q "^wallet=" "$qbx_node_conf" 2>/dev/null; then
            echo "wallet=$WALLET_NAME" | sudo -u "$POOL_USER" tee -a "$qbx_node_conf" > /dev/null
            echo -e "  ${GREEN}✓${NC} Added wallet auto-load to qbitx.conf (wallet=${WALLET_NAME})"
        fi
    fi
fi

# Create backup directory and backup wallet (only if not using manual input)
if [[ "$MANUAL_INPUT_USED" != "true" ]]; then
    sudo mkdir -p "$BACKUP_DIR"
    # Ensure daemon user can write backups (daemon writes via RPC backupwallet)
    BACKUP_OWNER=$(stat -c '%U:%G' "$INSTALL_DIR" 2>/dev/null || echo "spiraluser:spiraluser")
    sudo chown "$BACKUP_OWNER" "$BACKUP_DIR"
    BACKUP_FILE="$BACKUP_DIR/wallet-$(date +%Y%m%d-%H%M%S).dat"
    if ! $CLI backupwallet "$BACKUP_FILE" 2>/dev/null; then
        echo -e "  ${YELLOW}WARNING: Wallet backup may have failed — verify file exists at:${NC}"
        echo -e "    ${WHITE}$BACKUP_FILE${NC}"
    fi

    echo -e "${CYAN}═══════════════════════════════════════════════════════════════${NC}"
    echo -e "${WHITE}  CRITICAL: WALLET BACKUP INFORMATION${NC}"
    echo -e "${CYAN}═══════════════════════════════════════════════════════════════${NC}"
    echo ""
    echo -e "  ${RED}YOUR PRIVATE KEYS ARE STORED IN:${NC}"
    echo ""
    echo -e "    ${WHITE}${WALLET_DIR}/wallets/${WALLET_NAME}/wallet.dat${NC}"
    echo ""
    echo -e "  A backup has been created at:"
    echo -e "    ${WHITE}$BACKUP_FILE${NC}"
    echo ""
    echo -e "${YELLOW}  ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo -e "${WHITE}  IMPORTANT: UNDERSTAND YOUR WALLET${NC}"
    echo -e "${YELLOW}  ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""
    echo -e "  ${YELLOW}• wallet.dat contains your PRIVATE KEYS${NC}"
    echo -e "  ${YELLOW}• If you lose this file, you lose your ${COIN_SYMBOL} forever${NC}"
    echo -e "  ${YELLOW}• If someone gets this file, they can steal your ${COIN_SYMBOL}${NC}"
    echo ""
    echo -e "  ${WHITE}BACKUP RECOMMENDATIONS:${NC}"
    echo ""
    echo -e "  ${YELLOW}1. Copy wallet.dat to a USB drive${NC}"
    echo -e "  ${YELLOW}2. Store the USB in a safe/secure location${NC}"
    echo -e "  ${YELLOW}3. Make multiple copies in different locations${NC}"
    echo -e "  ${YELLOW}4. NEVER share wallet.dat with anyone${NC}"
    echo -e "  ${YELLOW}5. Create new backups after generating new addresses${NC}"
    echo ""
    echo "  To backup your wallet to a USB drive or external location:"
    echo ""
    echo -e "    ${WHITE}scp ${WALLET_DIR}/wallets/${WALLET_NAME}/wallet.dat user@backup-server:/path/${NC}"
    echo ""
    echo "  Or copy to USB mounted at /mnt/usb:"
    echo ""
    echo -e "    ${WHITE}sudo cp ${WALLET_DIR}/wallets/${WALLET_NAME}/wallet.dat /mnt/usb/${COIN_SYMBOL}-wallet-backup.dat${NC}"
    echo ""
    echo -e "${CYAN}═══════════════════════════════════════════════════════════════${NC}"
    echo ""
else
    # Manual input was used - no local wallet to backup
    echo -e "${CYAN}═══════════════════════════════════════════════════════════════${NC}"
    echo -e "${WHITE}  EXTERNAL WALLET ADDRESS CONFIGURED${NC}"
    echo -e "${CYAN}═══════════════════════════════════════════════════════════════${NC}"
    echo ""
    echo -e "  You provided an externally-created wallet address."
    echo -e "  ${YELLOW}Make sure to backup your wallet using your external wallet software.${NC}"
    echo ""
    echo -e "  The address ${GREEN}$NEW_ADDRESS${NC} has been configured for pool payouts."
    echo ""
    echo -e "${CYAN}═══════════════════════════════════════════════════════════════${NC}"
    echo ""
fi

# Verify the address was updated and restart stratum
if [[ -f "$CONFIG_FILE" ]]; then
    # Check if THIS coin's section still has PENDING_GENERATION (not other coins)
    sym_line=$(grep -ni "symbol:.*${COIN_SYMBOL}" "$CONFIG_FILE" 2>/dev/null | head -1 | cut -d: -f1)
    if [[ -n "$sym_line" ]] && tail -n "+${sym_line}" "$CONFIG_FILE" 2>/dev/null | head -20 | grep -q "PENDING_GENERATION"; then
        # sed failed to update this coin - retry coin-specific replacement only
        echo "  ⚠ Config still has PENDING_GENERATION for $COIN_SYMBOL, retrying update..."

        sym_retry=$(grep -ni "symbol:.*${COIN_SYMBOL}" "$CONFIG_FILE" 2>/dev/null | head -1 | cut -d: -f1)
        if [[ -n "$sym_retry" ]]; then
            addr_retry=$(tail -n "+${sym_retry}" "$CONFIG_FILE" | grep -n "PENDING_GENERATION" | head -1 | cut -d: -f1)
            if [[ -n "$addr_retry" ]]; then
                target=$((sym_retry + addr_retry - 1))
                sed -i "${target}s|PENDING_GENERATION|${SAFE_ADDRESS}|" "$CONFIG_FILE" 2>/dev/null || \
                sudo sed -i "${target}s|PENDING_GENERATION|${SAFE_ADDRESS}|" "$CONFIG_FILE" 2>/dev/null || true
            fi
        fi
    fi

    # Verify update succeeded
    if grep -q "$NEW_ADDRESS" "$CONFIG_FILE" 2>/dev/null; then
        echo "  Restarting pool with new address..."
        sudo systemctl enable spiralstratum 2>/dev/null || true
        sudo systemctl restart spiralstratum 2>/dev/null || true
        echo -e "  ${GREEN}✓${NC} Pool services restarted with new address"
        echo ""
    else
        echo -e "  ${RED}✗${NC} Failed to update config with new address"
        echo "  Please manually update: $CONFIG_FILE"
        echo "  Set: address: \"$NEW_ADDRESS\""
    fi
fi

# Check if pool should be started
if ! systemctl is-active --quiet spiralstratum 2>/dev/null; then
    echo "  Starting Spiral Stratum pool..."
    sudo systemctl enable spiralstratum 2>/dev/null || true
    sudo systemctl start spiralstratum 2>/dev/null || true
    sleep 5
    stratum_state=$(systemctl is-active spiralstratum 2>/dev/null || echo "unknown")
    if [[ "$stratum_state" == "active" ]]; then
        echo -e "  ${GREEN}✓${NC} Spiral Stratum is now ONLINE"
    elif [[ "$stratum_state" == "activating" ]]; then
        echo -e "  ${YELLOW}⟳${NC} Spiral Stratum is starting up (waiting for sync gate)"
        echo -e "    ${DIM}This is normal - the service will be ready shortly${NC}"
    else
        echo -e "  ${YELLOW}Pool may need manual start: sudo systemctl start spiralstratum${NC}"
    fi
    echo ""
fi

# Determine stratum port based on coin
case "$COIN" in
    dgb|digibyte) STRATUM_PORT=3333; STRATUM_V2_PORT=3334 ;;
    dgb-scrypt|digibyte-scrypt) STRATUM_PORT=3336; STRATUM_V2_PORT=3337 ;;
    btc|bitcoin) STRATUM_PORT=4333; STRATUM_V2_PORT=4334 ;;
    bch|bitcoincash) STRATUM_PORT=5333; STRATUM_V2_PORT=5334 ;;
    bc2|bitcoinii|bitcoin2) STRATUM_PORT=6333; STRATUM_V2_PORT=6334 ;;
    ltc|litecoin) STRATUM_PORT=7333; STRATUM_V2_PORT=7334 ;;
    doge|dogecoin) STRATUM_PORT=8335; STRATUM_V2_PORT=8337 ;;
    pep|pepecoin) STRATUM_PORT=10335; STRATUM_V2_PORT=10336 ;;
    cat|catcoin) STRATUM_PORT=12335; STRATUM_V2_PORT=12336 ;;
    nmc|namecoin) STRATUM_PORT=14335; STRATUM_V2_PORT=14336 ;;
    sys|syscoin) STRATUM_PORT=15335; STRATUM_V2_PORT=15336 ;;
    xmy|myriadcoin|myriad) STRATUM_PORT=17335; STRATUM_V2_PORT=17336 ;;
    fbtc|fractalbtc|fractalbitcoin|fractal) STRATUM_PORT=18335; STRATUM_V2_PORT=18336 ;;
    qbx|qbitx) STRATUM_PORT=20335; STRATUM_V2_PORT=20336 ;;
    *) STRATUM_PORT=3333; STRATUM_V2_PORT=3334 ;;
esac

# Try to get actual port from config if available (search within this coin's section)
if [[ -f "$CONFIG_FILE" ]]; then
    _sym_line=$(grep -ni "symbol:.*${COIN_SYMBOL}" "$CONFIG_FILE" 2>/dev/null | head -1 | cut -d: -f1)
    if [[ -n "$_sym_line" ]]; then
        # Find the port line within this coin's section (next 30 lines)
        CONFIG_PORT=$(tail -n "+${_sym_line}" "$CONFIG_FILE" | head -30 | grep -E "^\s*port:" | head -1 | awk '{print $2}' | tr -d '"' || echo "")
    else
        # Single-coin config — first port line is correct
        CONFIG_PORT=$(grep -E "^\s*port:" "$CONFIG_FILE" 2>/dev/null | head -1 | awk '{print $2}' | tr -d '"' || echo "")
    fi
    [[ -n "$CONFIG_PORT" ]] && STRATUM_PORT="$CONFIG_PORT"
fi

# Detect server internal IP address (prefer private IPs)
SERVER_IP=""
for ip in $(hostname -I 2>/dev/null); do
    if [[ "$ip" =~ ^10\. ]] || [[ "$ip" =~ ^172\.(1[6-9]|2[0-9]|3[01])\. ]] || [[ "$ip" =~ ^192\.168\. ]]; then
        SERVER_IP="$ip"
        break
    fi
done
[[ -z "$SERVER_IP" ]] && SERVER_IP=$(hostname -I 2>/dev/null | awk '{print $1}')
[[ -z "$SERVER_IP" ]] && SERVER_IP="YOUR_SERVER_IP"

echo -e "  ${GREEN}SETUP COMPLETE!${NC}"
echo ""
echo -e "  ${GREEN}✓${NC} $COIN_NAME wallet created successfully"
echo ""
echo "  Your pool wallet address: $NEW_ADDRESS"
echo ""
echo "  Configure your miners with:"
echo -e "    V1 Pool: ${WHITE}stratum+tcp://${SERVER_IP}:${STRATUM_PORT}${NC}"
echo -e "    V2 Pool: ${WHITE}stratum+tcp://${SERVER_IP}:${STRATUM_V2_PORT}${NC}"
echo -e "    Worker:  ${WHITE}$NEW_ADDRESS.worker_name${NC}"
echo ""
WALLETEOF

    # V1.0-BLACKICE: Create backup command
    sudo tee /usr/local/bin/spiralpool-backup > /dev/null << 'BACKUPEOF'
#!/bin/bash
#
# Spiral Pool Backup Utility - V1.0-BLACKICE
# Creates encrypted, compressed backups of wallet, database, and config
#

set -e

# Configuration
INSTALL_DIR="/spiralpool"
# Multi-disk support: load CHAIN_MOUNT_POINT so get_blockchain_dir returns the right path
MULTI_DISK_CONFIGURED="false"; CHAIN_MOUNT_POINT=""
_env="$INSTALL_DIR/config/coins.env"
if [[ -f "$_env" ]] && [[ ! -L "$_env" ]]; then
    MULTI_DISK_CONFIGURED=$(grep -oP '^MULTI_DISK_CONFIGURED=\K(true|false)$' "$_env" 2>/dev/null || echo "false")
    CHAIN_MOUNT_POINT=$(grep -oP '^CHAIN_MOUNT_POINT=\K\S+$' "$_env" 2>/dev/null || echo "")
fi
get_blockchain_dir() { local c="$1"; if [[ "$MULTI_DISK_CONFIGURED" == "true" && -n "$CHAIN_MOUNT_POINT" && -d "$CHAIN_MOUNT_POINT" ]]; then echo "$CHAIN_MOUNT_POINT/$c"; else echo "$INSTALL_DIR/$c"; fi; }
BACKUP_DIR="${INSTALL_DIR}/backups"
TIMESTAMP=$(date +%Y%m%d_%H%M%S)
BACKUP_NAME="spiralpool_backup_${TIMESTAMP}"
# SECURITY: Use /run/spiralpool (not world-writable /tmp) for temp directory
mkdir -p /run/spiralpool 2>/dev/null || true
TEMP_DIR=$(mktemp -d "/run/spiralpool/backup-XXXXXX") || {
    echo "ERROR: Failed to create secure temporary directory"
    exit 1
}
chmod 700 "$TEMP_DIR"
# Ensure cleanup on exit
trap 'rm -rf "$TEMP_DIR" 2>/dev/null' EXIT

# Colors
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
WHITE='\033[1;37m'
NC='\033[0m'

log() { echo -e "${GREEN}[$(date '+%H:%M:%S')]${NC} $1"; }
log_warn() { echo -e "${YELLOW}[$(date '+%H:%M:%S')] WARNING:${NC} $1"; }
log_error() { echo -e "${RED}[$(date '+%H:%M:%S')] ERROR:${NC} $1"; }
log_success() { echo -e "${GREEN}[$(date '+%H:%M:%S')] ✓${NC} $1"; }

show_help() {
    echo ""
    echo -e "${CYAN}╔══════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${CYAN}║${NC}${WHITE}          SPIRAL POOL BACKUP UTILITY - V1.0-BLACKICE          ${NC}${CYAN}║${NC}"
    echo -e "${CYAN}╚══════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo "Usage: spiralpool-backup [OPTIONS]"
    echo ""
    echo "Options:"
    echo "  --full              Full backup (wallet + database + config + logs)"
    echo "  --wallet            Backup wallet.dat only"
    echo "  --database          Backup PostgreSQL database only"
    echo "  --config            Backup configuration files only"
    echo "  --encrypt KEY       Encrypt backup with passphrase"
    echo "  --output DIR        Custom output directory (default: ${BACKUP_DIR})"
    echo "  --schedule [ACTION] Manage automated daily backups (enable/disable/status)"
    echo "  --list              List existing backups"
    echo "  --help              Show this help message"
    echo ""
    echo "Examples:"
    echo "  spiralpool-backup --full"
    echo "  spiralpool-backup --full --encrypt"
    echo "  spiralpool-backup --wallet --output /mnt/backup"
    echo "  spiralpool-backup --schedule enable"
    echo ""
}

backup_wallet() {
    log "Backing up wallets..."

    mkdir -p "${TEMP_DIR}/wallets"
    local found_wallet=false

    # Backup DigiByte wallet (named wallet path first, legacy fallback)
    if [[ -f "$(get_blockchain_dir dgb)/wallets/pool-dgb/wallet.dat" ]]; then
        digibyte-cli -conf="$(get_blockchain_dir dgb)/digibyte.conf" walletlock 2>/dev/null || true
        cp "$(get_blockchain_dir dgb)/wallets/pool-dgb/wallet.dat" "${TEMP_DIR}/wallets/digibyte-wallet.dat"
        found_wallet=true
        log "  Backed up DigiByte wallet (named: pool-dgb)"
    elif [[ -f "$(get_blockchain_dir dgb)/wallet.dat" ]]; then
        digibyte-cli -conf="$(get_blockchain_dir dgb)/digibyte.conf" walletlock 2>/dev/null || true
        cp "$(get_blockchain_dir dgb)/wallet.dat" "${TEMP_DIR}/wallets/digibyte-wallet.dat"
        found_wallet=true
        log "  Backed up DigiByte wallet (legacy)"
    fi
    if ls "$(get_blockchain_dir dgb)/wallet_backup_"* 1>/dev/null 2>&1; then
        cp "$(get_blockchain_dir dgb)/wallet_backup_"* "${TEMP_DIR}/wallets/" 2>/dev/null || true
    fi

    # Backup Bitcoin wallet (named wallet path first, legacy fallback)
    if [[ -f "$(get_blockchain_dir btc)/wallets/pool-btc/wallet.dat" ]]; then
