    elif [[ -f "$(get_blockchain_dir pep)/wallet.dat" ]]; then
        pepecoin-cli -conf="$(get_blockchain_dir pep)/pepecoin.conf" walletlock 2>/dev/null || true
        cp "$(get_blockchain_dir pep)/wallet.dat" "${TEMP_DIR}/wallets/pepecoin-wallet.dat"
