    elif [[ -f "$(get_blockchain_dir cat)/wallet.dat" ]]; then
        catcoin-cli -conf="$(get_blockchain_dir cat)/catcoin.conf" walletlock 2>/dev/null || true
        cp "$(get_blockchain_dir cat)/wallet.dat" "${TEMP_DIR}/wallets/catcoin-wallet.dat"
