}

backup_database() {
    log "Backing up PostgreSQL database..."

    # Get database credentials from config
    DB_NAME="spiralstratum"
    DB_USER="spiralstratum"

    # Use pg_dump for database backup
    if command -v pg_dump &>/dev/null; then
        sudo -u postgres pg_dump "$DB_NAME" > "${TEMP_DIR}/database.sql" 2>/dev/null || {
            log_warn "Failed to backup database - is PostgreSQL running?"
            return 0
        }

        # Compress the database dump
        gzip "${TEMP_DIR}/database.sql"
        log_success "Database backed up ($(du -h "${TEMP_DIR}/database.sql.gz" | cut -f1))"
    else
        log_warn "pg_dump not found - skipping database backup"
    fi
}

backup_config() {
    log "Backing up configuration files..."

    mkdir -p "${TEMP_DIR}/config"

    # Backup pool config
    if [[ -f "${INSTALL_DIR}/config/config.yaml" ]]; then
        cp "${INSTALL_DIR}/config/config.yaml" "${TEMP_DIR}/config/"
    fi

    # Backup blockchain configs (mask passwords)
    if [[ -f "$(get_blockchain_dir dgb)/digibyte.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir dgb)/digibyte.conf" > "${TEMP_DIR}/config/digibyte.conf"
    fi
    if [[ -f "$(get_blockchain_dir btc)/bitcoin.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir btc)/bitcoin.conf" > "${TEMP_DIR}/config/bitcoin.conf"
    fi
    if [[ -f "$(get_blockchain_dir bch)/bitcoin.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir bch)/bitcoin.conf" > "${TEMP_DIR}/config/bitcoin-cash.conf"
    fi
    if [[ -f "$(get_blockchain_dir bc2)/bitcoinii.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir bc2)/bitcoinii.conf" > "${TEMP_DIR}/config/bitcoinii.conf"
    fi
    if [[ -f "$(get_blockchain_dir ltc)/litecoin.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir ltc)/litecoin.conf" > "${TEMP_DIR}/config/litecoin.conf"
    fi
    if [[ -f "$(get_blockchain_dir doge)/dogecoin.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir doge)/dogecoin.conf" > "${TEMP_DIR}/config/dogecoin.conf"
    fi
    if [[ -f "$(get_blockchain_dir pep)/pepecoin.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir pep)/pepecoin.conf" > "${TEMP_DIR}/config/pepecoin.conf"
    fi
    if [[ -f "$(get_blockchain_dir cat)/catcoin.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir cat)/catcoin.conf" > "${TEMP_DIR}/config/catcoin.conf"
    fi
    if [[ -f "$(get_blockchain_dir nmc)/namecoin.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir nmc)/namecoin.conf" > "${TEMP_DIR}/config/namecoin.conf"
    fi
    if [[ -f "$(get_blockchain_dir sys)/syscoin.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir sys)/syscoin.conf" > "${TEMP_DIR}/config/syscoin.conf"
    fi
    if [[ -f "$(get_blockchain_dir xmy)/myriadcoin.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir xmy)/myriadcoin.conf" > "${TEMP_DIR}/config/myriadcoin.conf"
    fi
    if [[ -f "$(get_blockchain_dir fbtc)/fractal.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir fbtc)/fractal.conf" > "${TEMP_DIR}/config/fractal.conf"
    fi
    if [[ -f "$(get_blockchain_dir qbx)/qbitx.conf" ]]; then
        sed 's/rpcpassword=.*/rpcpassword=REDACTED/' \
            "$(get_blockchain_dir qbx)/qbitx.conf" > "${TEMP_DIR}/config/qbitx.conf"
    fi

    # Backup systemd service files
    mkdir -p "${TEMP_DIR}/config/systemd"
    cp /etc/systemd/system/spiral*.service "${TEMP_DIR}/config/systemd/" 2>/dev/null || true
    for daemon_svc in digibyted bitcoind bitcoind-bch bitcoiniid litecoind dogecoind pepecoind catcoind namecoind syscoind myriadcoind fractald qbitxd; do
        cp "/etc/systemd/system/${daemon_svc}.service" "${TEMP_DIR}/config/systemd/" 2>/dev/null || true
    done

    log_success "Configuration backed up"
}

backup_logs() {
    log "Backing up log files..."

    mkdir -p "${TEMP_DIR}/logs"

    # Copy recent logs (last 7 days)
    if [[ -d "${INSTALL_DIR}/logs" ]]; then
        find "${INSTALL_DIR}/logs" -type f -mtime -7 -exec cp {} "${TEMP_DIR}/logs/" \; 2>/dev/null || true
    fi

    # Copy systemd journal logs for pool services
    journalctl -u spiralstratum --since "7 days ago" --no-pager > "${TEMP_DIR}/logs/spiralstratum.log" 2>/dev/null || true

    # Copy logs for each enabled blockchain daemon
    for daemon in digibyted bitcoind bitcoind-bch bitcoiniid litecoind dogecoind pepecoind catcoind namecoind syscoind myriadcoind fractald; do
        if systemctl is-enabled --quiet "$daemon" 2>/dev/null; then
            journalctl -u "$daemon" --since "7 days ago" --no-pager > "${TEMP_DIR}/logs/${daemon}.log" 2>/dev/null || true
        fi
    done

    log_success "Logs backed up"
}

create_manifest() {
    log "Creating backup manifest..."

    # Get blockchain info from whichever daemon is enabled
    local blockchain_version="unknown"
    local block_height=0

    if systemctl is-enabled --quiet digibyted 2>/dev/null && [[ -f "$(get_blockchain_dir dgb)/digibyte.conf" ]]; then
        blockchain_version=$(digibyte-cli -conf="$(get_blockchain_dir dgb)/digibyte.conf" getnetworkinfo 2>/dev/null | grep -o '"subversion"[^,]*' | cut -d'"' -f4 || echo "unknown")
        block_height=$(digibyte-cli -conf="$(get_blockchain_dir dgb)/digibyte.conf" getblockcount 2>/dev/null || echo "0")
    elif systemctl is-enabled --quiet bitcoind 2>/dev/null && [[ -f "$(get_blockchain_dir btc)/bitcoin.conf" ]]; then
        blockchain_version=$(bitcoin-cli -conf="$(get_blockchain_dir btc)/bitcoin.conf" getnetworkinfo 2>/dev/null | grep -o '"subversion"[^,]*' | cut -d'"' -f4 || echo "unknown")
        block_height=$(bitcoin-cli -conf="$(get_blockchain_dir btc)/bitcoin.conf" getblockcount 2>/dev/null || echo "0")
    elif systemctl is-enabled --quiet bitcoind-bch 2>/dev/null && [[ -f "$(get_blockchain_dir bch)/bitcoin.conf" ]]; then
        blockchain_version=$(bitcoin-cli-bch -conf="$(get_blockchain_dir bch)/bitcoin.conf" getnetworkinfo 2>/dev/null | grep -o '"subversion"[^,]*' | cut -d'"' -f4 || echo "unknown")
        block_height=$(bitcoin-cli-bch -conf="$(get_blockchain_dir bch)/bitcoin.conf" getblockcount 2>/dev/null || echo "0")
    fi

    cat > "${TEMP_DIR}/manifest.json" << MANIFEST
{
    "version": "1.1.0",
    "created": "$(date -Iseconds)",
    "hostname": "$(hostname)",
    "components": {
        "wallet": $([ -d "${TEMP_DIR}/wallets" ] && echo "true" || echo "false"),
        "database": $([ -f "${TEMP_DIR}/database.sql.gz" ] && echo "true" || echo "false"),
        "config": $([ -d "${TEMP_DIR}/config" ] && echo "true" || echo "false"),
        "logs": $([ -d "${TEMP_DIR}/logs" ] && echo "true" || echo "false")
    },
    "blockchain_version": "${blockchain_version}",
    "block_height": ${block_height}
}
MANIFEST

    log_success "Manifest created"
}

compress_backup() {
    local OUTPUT_FILE="$1"

    log "Compressing backup..."

    tar -czf "${OUTPUT_FILE}" -C "$(dirname "$TEMP_DIR")" "$(basename "$TEMP_DIR")"

    log_success "Backup compressed: $(du -h "${OUTPUT_FILE}" | cut -f1)"
}

encrypt_backup() {
    local INPUT_FILE="$1"
    local OUTPUT_FILE="${INPUT_FILE}.enc"

    log "Encrypting backup..."

    # Prompt for passphrase
    echo -n "Enter encryption passphrase: "
    read -s PASSPHRASE
    echo ""
    echo -n "Confirm passphrase: "
    read -s PASSPHRASE_CONFIRM
    echo ""

    if [[ "$PASSPHRASE" != "$PASSPHRASE_CONFIRM" ]]; then
        log_error "Passphrases do not match!"
        exit 1
    fi

    # Encrypt with OpenSSL AES-256-CBC
    # SECURITY: Pass passphrase via stdin (not -pass pass: which leaks to ps)
    echo "$PASSPHRASE" | openssl enc -aes-256-cbc -salt -pbkdf2 -iter 100000 \
        -in "$INPUT_FILE" -out "$OUTPUT_FILE" -pass stdin

    # Remove unencrypted backup
    rm -f "$INPUT_FILE"

    log_success "Backup encrypted: ${OUTPUT_FILE}"
    echo "$OUTPUT_FILE"
}

list_backups() {
    echo ""
    echo -e "${CYAN}╔══════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${CYAN}║${NC}${WHITE}                       EXISTING BACKUPS                       ${NC}${CYAN}║${NC}"
    echo -e "${CYAN}╚══════════════════════════════════════════════════════════════╝${NC}"
    echo ""

    if [[ ! -d "$BACKUP_DIR" ]]; then
        echo "  No backup directory found."
        return
    fi

    BACKUPS=$(ls -lh "${BACKUP_DIR}"/spiralpool_backup_*.tar.gz* 2>/dev/null || true)

    if [[ -z "$BACKUPS" ]]; then
        echo "  No backups found in ${BACKUP_DIR}"
        return
    fi

    echo "  Location: ${BACKUP_DIR}"
    echo ""
    echo "  SIZE      DATE                 FILENAME"
    echo "  ────────  ───────────────────  ─────────────────────────────────"

    ls -lh "${BACKUP_DIR}"/spiralpool_backup_*.tar.gz* 2>/dev/null | \
        awk '{printf "  %-8s  %s %s %s  %s\n", $5, $6, $7, $8, $9}' | \
        sed "s|${BACKUP_DIR}/||"

    echo ""
    echo "  Total: $(ls "${BACKUP_DIR}"/spiralpool_backup_*.tar.gz* 2>/dev/null | wc -l) backup(s)"
    echo ""
}

schedule_backups() {
    local action="${1:-status}"
    local BACKUP_SCRIPT="${INSTALL_DIR}/scripts/daily-backup.sh"
    local CRON_FILE="/etc/cron.d/spiralpool-backup"

    case "$action" in
        enable)
            # Create backup directory
            sudo mkdir -p "${INSTALL_DIR}/backups"
            local pool_user
            pool_user=$(stat -c '%U' "$INSTALL_DIR" 2>/dev/null || echo "spiralpool")
            sudo chown "$pool_user:$pool_user" "${INSTALL_DIR}/backups"
            sudo chmod 700 "${INSTALL_DIR}/backups"

            # Verify daily-backup.sh exists
            if [[ ! -f "$BACKUP_SCRIPT" ]]; then
                log_error "Daily backup script not found: $BACKUP_SCRIPT"
                log_error "Please reinstall Spiral Pool to create it"
                exit 1
            fi

            # Create cron job (daily at 2:00 AM)
            sudo tee "$CRON_FILE" > /dev/null << SCHEDEOF
# Spiral Pool - Automated Daily Database Backup
# Runs at 2:00 AM daily to minimize impact on mining operations
# Script logs to /spiralpool/logs/backup.log via tee

SHELL=/bin/bash
PATH=/usr/local/sbin:/usr/local/bin:/sbin:/bin:/usr/sbin:/usr/bin

0 2 * * * root ${BACKUP_SCRIPT} > /dev/null 2>&1
SCHEDEOF
            sudo chmod 644 "$CRON_FILE"

            log_success "Automated daily backups ENABLED"
            echo "  Schedule:  Daily at 2:00 AM"
            echo "  Location:  ${INSTALL_DIR}/backups/"
            echo "  Retention: 30 days"
            echo "  Log:       /spiralpool/logs/backup.log"
            echo ""
            echo "  To disable: spiralpool-backup --schedule disable"
            ;;
        disable)
            if [[ -f "$CRON_FILE" ]]; then
                sudo rm -f "$CRON_FILE"
                log_success "Automated daily backups DISABLED"
                echo "  To re-enable: spiralpool-backup --schedule enable"
            else
                echo "Automated backups are not currently enabled."
            fi
            ;;
        status)
            echo ""
            echo -e "${CYAN}Automated Backup Status${NC}"
            echo "─────────────────────────────────────"
            if [[ -f "$CRON_FILE" ]]; then
                echo -e "  Status:    ${GREEN}ENABLED${NC}"
                echo "  Schedule:  Daily at 2:00 AM"
                echo "  Location:  ${INSTALL_DIR}/backups/"
                echo "  Retention: 30 days"
                echo "  Log:       /spiralpool/logs/backup.log"
                # Show latest backup info
                local latest
                latest=$(find "${INSTALL_DIR}/backups" -maxdepth 1 -type d -name "daily-*" 2>/dev/null | sort | tail -1)
                if [[ -n "$latest" ]]; then
                    local bname
                    bname=$(basename "$latest")
                    local bdate="${bname#daily-}"
                    bdate="${bdate%%_*}"
                    local btime="${bname#*_}"
                    echo "  Last:      ${bdate:0:4}-${bdate:4:2}-${bdate:6:2} ${btime:0:2}:${btime:2:2}:${btime:4:2}"
                    local bcount
                    bcount=$(find "${INSTALL_DIR}/backups" -maxdepth 1 -type d -name "daily-*" 2>/dev/null | wc -l)
                    echo "  Backups:   ${bcount}"
                    local bsize
                    bsize=$(du -sh "${INSTALL_DIR}/backups" 2>/dev/null | cut -f1)
                    echo "  Disk Used: ${bsize}"
                else
                    echo "  Last:      No backups yet"
                fi
            else
                echo -e "  Status:    ${YELLOW}DISABLED${NC}"
                echo ""
                echo "  To enable: spiralpool-backup --schedule enable"
            fi
            echo ""
            ;;
        *)
            log_error "Unknown schedule action: $action"
            echo "Usage: spiralpool-backup --schedule [enable|disable|status]"
            exit 1
            ;;
    esac
}

# Main logic
BACKUP_TYPE=""
DO_ENCRYPT=false
OUTPUT_DIR="$BACKUP_DIR"
DO_LIST=false
DO_SCHEDULE=false
SCHEDULE_ACTION="status"

while [[ $# -gt 0 ]]; do
    case "$1" in
        --full)
            BACKUP_TYPE="full"
            shift
            ;;
        --wallet)
            BACKUP_TYPE="wallet"
            shift
            ;;
        --database)
            BACKUP_TYPE="database"
            shift
            ;;
        --config)
            BACKUP_TYPE="config"
            shift
            ;;
        --encrypt)
            DO_ENCRYPT=true
            shift
            ;;
        --output)
            OUTPUT_DIR="$2"
            shift 2
            ;;
        --list)
            DO_LIST=true
            shift
            ;;
        --schedule)
            DO_SCHEDULE=true
            if [[ "${2:-}" == "enable" || "${2:-}" == "disable" || "${2:-}" == "status" ]]; then
                SCHEDULE_ACTION="$2"
                shift 2
            else
                SCHEDULE_ACTION="status"
                shift
            fi
            ;;
        --help|-h)
            show_help
            exit 0
            ;;
        *)
            log_error "Unknown option: $1"
            show_help
            exit 1
            ;;
    esac
done

if [[ "$DO_SCHEDULE" == "true" ]]; then
    schedule_backups "$SCHEDULE_ACTION"
    exit 0
fi

if [[ "$DO_LIST" == "true" ]]; then
    list_backups
    exit 0
fi

if [[ -z "$BACKUP_TYPE" ]]; then
    show_help
    exit 1
fi

# Ensure backup directory exists
mkdir -p "$OUTPUT_DIR"
mkdir -p "$TEMP_DIR"

echo ""
echo -e "${CYAN}╔══════════════════════════════════════════════════════════════╗${NC}"
echo -e "${CYAN}║${NC}${WHITE}                  SPIRAL POOL BACKUP - V1.0                   ${NC}${CYAN}║${NC}"
echo -e "${CYAN}╚══════════════════════════════════════════════════════════════╝${NC}"
echo ""

# Perform backup based on type
case "$BACKUP_TYPE" in
    full)
        backup_wallet
        backup_database
        backup_config
        backup_logs
        ;;
    wallet)
        backup_wallet
        ;;
    database)
        backup_database
        ;;
    config)
        backup_config
        ;;
esac

# Create manifest
create_manifest

# Compress
OUTPUT_FILE="${OUTPUT_DIR}/${BACKUP_NAME}.tar.gz"
compress_backup "$OUTPUT_FILE"

# Encrypt if requested
if [[ "$DO_ENCRYPT" == "true" ]]; then
    OUTPUT_FILE=$(encrypt_backup "$OUTPUT_FILE")
fi

# SECURITY: Restrict backup file permissions (may contain wallet.dat)
chmod 600 "$OUTPUT_FILE"

# Cleanup temp directory
rm -rf "$TEMP_DIR"

echo ""
echo -e "${GREEN}╔══════════════════════════════════════════════════════════════╗${NC}"
echo -e "${GREEN}║${NC}${WHITE}                       BACKUP COMPLETE!                       ${NC}${GREEN}║${NC}"
echo -e "${GREEN}╚══════════════════════════════════════════════════════════════╝${NC}"
echo ""
echo "  Backup saved to: ${OUTPUT_FILE}"
echo "  Size: $(du -h "$OUTPUT_FILE" | cut -f1)"
echo ""
echo "  To restore: spiralpool-restore ${OUTPUT_FILE}"
echo ""
BACKUPEOF

    # V1.0-BLACKICE: Create restore command
    sudo tee /usr/local/bin/spiralpool-restore > /dev/null << 'RESTOREEOF'
#!/bin/bash
#
# Spiral Pool Restore Utility - V1.0-BLACKICE
# Restores backups created by spiralpool-backup
#

set -e

# Configuration
INSTALL_DIR="/spiralpool"
# Multi-disk support: load CHAIN_MOUNT_POINT so get_blockchain_dir returns the right path
MULTI_DISK_CONFIGURED="false"; CHAIN_MOUNT_POINT=""
_env="$INSTALL_DIR/config/coins.env"
if [[ -f "$_env" ]] && [[ ! -L "$_env" ]]; then
    MULTI_DISK_CONFIGURED=$(grep -oP '^MULTI_DISK_CONFIGURED=\K(true|false)$' "$_env" 2>/dev/null || echo "false")
    CHAIN_MOUNT_POINT=$(grep -oP '^CHAIN_MOUNT_POINT=\K\S+$' "$_env" 2>/dev/null || echo "")
fi
get_blockchain_dir() { local c="$1"; if [[ "$MULTI_DISK_CONFIGURED" == "true" && -n "$CHAIN_MOUNT_POINT" && -d "$CHAIN_MOUNT_POINT" ]]; then echo "$CHAIN_MOUNT_POINT/$c"; else echo "$INSTALL_DIR/$c"; fi; }
# Standard pool user - hardcoded (no customization)
POOL_USER="spiraluser"
# SECURITY: Use /run/spiralpool (not world-writable /tmp) for temp directory
mkdir -p /run/spiralpool 2>/dev/null || true
TEMP_DIR=$(mktemp -d "/run/spiralpool/restore-XXXXXX") || {
    echo "ERROR: Failed to create secure temporary directory"
    exit 1
}
chmod 700 "$TEMP_DIR"

# Colors
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
WHITE='\033[1;37m'
NC='\033[0m'

# Prompt helper (styled input prompt)
prompt_input() {
    echo -ne "  ${GREEN}▸${NC} ${WHITE}${1}${NC}"
}

log() { echo -e "${GREEN}[$(date '+%H:%M:%S')]${NC} $1"; }
log_warn() { echo -e "${YELLOW}[$(date '+%H:%M:%S')] WARNING:${NC} $1"; }
log_error() { echo -e "${RED}[$(date '+%H:%M:%S')] ERROR:${NC} $1"; }
log_success() { echo -e "${GREEN}[$(date '+%H:%M:%S')] ✓${NC} $1"; }

show_help() {
    echo ""
    echo -e "${CYAN}╔══════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${CYAN}║${NC}${WHITE}              SPIRAL POOL RESTORE UTILITY - V1.0              ${NC}${CYAN}║${NC}"
    echo -e "${CYAN}╚══════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo "Usage: spiralpool-restore BACKUP_FILE [OPTIONS]"
    echo ""
    echo "Options:"
    echo "  --wallet            Restore wallet only"
    echo "  --database          Restore database only"
    echo "  --config            Restore config only"
    echo "  --decrypt           Backup is encrypted"
    echo "  --dry-run           Show what would be restored without making changes"
    echo "  --force             Skip confirmation prompts"
    echo "  --help              Show this help message"
    echo ""
    echo "Examples:"
    echo "  spiralpool-restore /spiralpool/backups/backup.tar.gz"
    echo "  spiralpool-restore backup.tar.gz.enc --decrypt"
    echo "  spiralpool-restore backup.tar.gz --wallet --force"
    echo ""
}

decrypt_backup() {
    local INPUT_FILE="$1"
    local OUTPUT_FILE="${INPUT_FILE%.enc}"

    # Guard against self-overwrite if file doesn't end in .enc
    if [[ "$OUTPUT_FILE" == "$INPUT_FILE" ]]; then
        OUTPUT_FILE="${INPUT_FILE}.decrypted"
    fi

    log "Decrypting backup..." >&2

    echo -n "Enter decryption passphrase: " >&2
    read -s PASSPHRASE
    echo "" >&2

    # SECURITY: Pass passphrase via stdin (not -pass pass: which leaks to ps)
    echo "$PASSPHRASE" | openssl enc -aes-256-cbc -d -salt -pbkdf2 -iter 100000 \
        -in "$INPUT_FILE" -out "$OUTPUT_FILE" -pass stdin || {
        log_error "Decryption failed - wrong passphrase?" >&2
        exit 1
    }

    log_success "Backup decrypted" >&2
    echo "$OUTPUT_FILE"
}

extract_backup() {
    local BACKUP_FILE="$1"

    log "Extracting backup..."

    # SECURITY: Check for path traversal entries before extracting
    if tar -tzf "$BACKUP_FILE" 2>/dev/null | grep -q '\.\.'; then
        log_error "Archive contains path traversal entries (../) — refusing to extract"
        exit 1
    fi

    mkdir -p "$TEMP_DIR"
    tar -xzf "$BACKUP_FILE" -C "$TEMP_DIR" --strip-components=1

    log_success "Backup extracted"
}

show_manifest() {
    if [[ -f "${TEMP_DIR}/manifest.json" ]]; then
        echo ""
        echo -e "${CYAN}Backup Information:${NC}"
        echo "  Created:  $(grep '"created"' "${TEMP_DIR}/manifest.json" | cut -d'"' -f4)"
        echo "  Hostname: $(grep '"hostname"' "${TEMP_DIR}/manifest.json" | cut -d'"' -f4)"
        echo "  Version:  $(grep '"version"' "${TEMP_DIR}/manifest.json" | cut -d'"' -f4)"
        echo "  Block:    $(grep '"block_height"' "${TEMP_DIR}/manifest.json" | grep -o '[0-9]*')"
        echo ""
        echo -e "${CYAN}Components:${NC}"
        grep -o '"wallet": [^,}]*' "${TEMP_DIR}/manifest.json" | sed 's/"wallet": /  Wallet:   /'
        grep -o '"database": [^,}]*' "${TEMP_DIR}/manifest.json" | sed 's/"database": /  Database: /'
        grep -o '"config": [^,}]*' "${TEMP_DIR}/manifest.json" | sed 's/"config": /  Config:   /'
        grep -o '"logs": [^,}]*' "${TEMP_DIR}/manifest.json" | sed 's/"logs": /  Logs:     /'
        echo ""
    fi
}

restore_single_wallet() {
    local name=$1
    local daemon=$2
    local wallet_dir=$3
    local backup_file=$4

    if [[ ! -f "$backup_file" ]]; then
        return 1
    fi

    log "Restoring $name wallet..."

    # Stop daemon for safe restore
    sudo systemctl stop "$daemon" 2>/dev/null || true
    sleep 5

    # Determine wallet name from wallet_dir (matches WALLETEOF createwallet convention: pool-<symbol>)
    # wallet_dir is e.g. /spiralpool/dgb → basename "dgb" → wallet name "pool-dgb"
    local coin_abbr
    coin_abbr=$(basename "$wallet_dir")
    local wallet_name="pool-${coin_abbr}"
    local named_wallet_dir="${wallet_dir}/wallets/${wallet_name}"

    # Backup current wallet (check named path first, then legacy)
    if [[ -f "${named_wallet_dir}/wallet.dat" ]]; then
        BACKUP_CURRENT="${named_wallet_dir}/wallet.dat.pre_restore_$(date +%Y%m%d_%H%M%S)"
        cp "${named_wallet_dir}/wallet.dat" "$BACKUP_CURRENT"
        log "  Current wallet backed up to: $BACKUP_CURRENT"
    elif [[ -f "${wallet_dir}/wallet.dat" ]]; then
        BACKUP_CURRENT="${wallet_dir}/wallet.dat.pre_restore_$(date +%Y%m%d_%H%M%S)"
        cp "${wallet_dir}/wallet.dat" "$BACKUP_CURRENT"
        log "  Current wallet (legacy) backed up to: $BACKUP_CURRENT"
    fi

    # Restore wallet to named wallet directory (where createwallet puts it)
    if [[ -d "${named_wallet_dir}" ]]; then
        cp "$backup_file" "${named_wallet_dir}/wallet.dat"
        chown "$POOL_USER:$POOL_USER" "${named_wallet_dir}/wallet.dat" 2>/dev/null || true
        chmod 600 "${named_wallet_dir}/wallet.dat"
    else
        # Fallback to legacy path if named wallet dir doesn't exist
        mkdir -p "$wallet_dir"
        cp "$backup_file" "${wallet_dir}/wallet.dat"
        chown "$POOL_USER:$POOL_USER" "${wallet_dir}/wallet.dat" 2>/dev/null || true
        chmod 600 "${wallet_dir}/wallet.dat"
    fi

    # Start daemon
    sudo systemctl start "$daemon" 2>/dev/null || true
    log_success "$name wallet restored"
}

restore_wallet() {
    log "Restoring wallets..."

    local found_wallet=false

    # Check for new multi-wallet backup format
    if [[ -d "${TEMP_DIR}/wallets" ]]; then
        if [[ -f "${TEMP_DIR}/wallets/digibyte-wallet.dat" ]]; then
            restore_single_wallet "DigiByte" "digibyted" "$(get_blockchain_dir dgb)" "${TEMP_DIR}/wallets/digibyte-wallet.dat"
            found_wallet=true
        fi
        if [[ -f "${TEMP_DIR}/wallets/bitcoin-wallet.dat" ]]; then
            restore_single_wallet "Bitcoin" "bitcoind" "$(get_blockchain_dir btc)" "${TEMP_DIR}/wallets/bitcoin-wallet.dat"
            found_wallet=true
        fi
        if [[ -f "${TEMP_DIR}/wallets/bitcoincash-wallet.dat" ]]; then
            restore_single_wallet "Bitcoin Cash" "bitcoind-bch" "$(get_blockchain_dir bch)" "${TEMP_DIR}/wallets/bitcoincash-wallet.dat"
            found_wallet=true
        fi
        if [[ -f "${TEMP_DIR}/wallets/bitcoinii-wallet.dat" ]]; then
            restore_single_wallet "Bitcoin II" "bitcoiniid" "$(get_blockchain_dir bc2)" "${TEMP_DIR}/wallets/bitcoinii-wallet.dat"
            found_wallet=true
        fi
        if [[ -f "${TEMP_DIR}/wallets/litecoin-wallet.dat" ]]; then
            restore_single_wallet "Litecoin" "litecoind" "$(get_blockchain_dir ltc)" "${TEMP_DIR}/wallets/litecoin-wallet.dat"
            found_wallet=true
        fi
        if [[ -f "${TEMP_DIR}/wallets/dogecoin-wallet.dat" ]]; then
            restore_single_wallet "Dogecoin" "dogecoind" "$(get_blockchain_dir doge)" "${TEMP_DIR}/wallets/dogecoin-wallet.dat"
            found_wallet=true
        fi
        if [[ -f "${TEMP_DIR}/wallets/pepecoin-wallet.dat" ]]; then
            restore_single_wallet "PepeCoin" "pepecoind" "$(get_blockchain_dir pep)" "${TEMP_DIR}/wallets/pepecoin-wallet.dat"
            found_wallet=true
        fi
        if [[ -f "${TEMP_DIR}/wallets/catcoin-wallet.dat" ]]; then
            restore_single_wallet "Catcoin" "catcoind" "$(get_blockchain_dir cat)" "${TEMP_DIR}/wallets/catcoin-wallet.dat"
            found_wallet=true
        fi
        if [[ -f "${TEMP_DIR}/wallets/namecoin-wallet.dat" ]]; then
            restore_single_wallet "Namecoin" "namecoind" "$(get_blockchain_dir nmc)" "${TEMP_DIR}/wallets/namecoin-wallet.dat"
            found_wallet=true
        fi
        if [[ -f "${TEMP_DIR}/wallets/syscoin-wallet.dat" ]]; then
            restore_single_wallet "Syscoin" "syscoind" "$(get_blockchain_dir sys)" "${TEMP_DIR}/wallets/syscoin-wallet.dat"
            found_wallet=true
        fi
        if [[ -f "${TEMP_DIR}/wallets/myriadcoin-wallet.dat" ]]; then
            restore_single_wallet "Myriadcoin" "myriadcoind" "$(get_blockchain_dir xmy)" "${TEMP_DIR}/wallets/myriadcoin-wallet.dat"
            found_wallet=true
        fi
        if [[ -f "${TEMP_DIR}/wallets/fractal-wallet.dat" ]]; then
            restore_single_wallet "Fractal Bitcoin" "fractald" "$(get_blockchain_dir fbtc)" "${TEMP_DIR}/wallets/fractal-wallet.dat"
            found_wallet=true
        fi
        if [[ -f "${TEMP_DIR}/wallets/qbitx-wallet.dat" ]]; then
            restore_single_wallet "Q-BitX" "qbitxd" "$(get_blockchain_dir qbx)" "${TEMP_DIR}/wallets/qbitx-wallet.dat"
            found_wallet=true
        fi
    # Legacy single wallet.dat format (assume DGB)
    elif [[ -f "${TEMP_DIR}/wallet.dat" ]]; then
        restore_single_wallet "DigiByte" "digibyted" "$(get_blockchain_dir dgb)" "${TEMP_DIR}/wallet.dat"
        found_wallet=true
    fi

    if [[ "$found_wallet" == "false" ]]; then
        log_warn "No wallet files found in backup - skipping"
        return 0
    fi

    log_success "Wallet restore complete"
}

restore_database() {
    log "Restoring database..."

    if [[ ! -f "${TEMP_DIR}/database.sql.gz" ]]; then
        log_warn "No database dump in backup - skipping"
        return 0
    fi

    # Stop stratum for safe restore
    log "Stopping Spiral Stratum..."
    sudo systemctl stop spiralstratum 2>/dev/null || true

    # Restore database
    gunzip -c "${TEMP_DIR}/database.sql.gz" | sudo -u postgres psql spiralstratum > /dev/null 2>&1 || {
        log_warn "Database restore had warnings (this is often normal)"
    }

    # Start stratum
    log "Starting Spiral Stratum..."
    sudo systemctl start spiralstratum

    log_success "Database restored"
}

restore_config() {
    log "Restoring configuration..."

    if [[ ! -d "${TEMP_DIR}/config" ]]; then
        log_warn "No config directory in backup - skipping"
        return 0
    fi

    # Restore pool config
    if [[ -f "${TEMP_DIR}/config/config.yaml" ]]; then
        cp "${TEMP_DIR}/config/config.yaml" "${INSTALL_DIR}/config/config.yaml"
        log_success "Pool config restored"
    fi

    log_success "Configuration restored"
}

DECRYPTED_FILE=""

cleanup() {
    rm -rf "$TEMP_DIR"
    # Also remove decrypted file if we created one
    if [[ -n "$DECRYPTED_FILE" ]] && [[ -f "$DECRYPTED_FILE" ]]; then
        rm -f "$DECRYPTED_FILE"
    fi
}

trap cleanup EXIT

# Parse arguments
BACKUP_FILE=""
RESTORE_TYPE="full"
DO_DECRYPT=false
DRY_RUN=false
FORCE=false

while [[ $# -gt 0 ]]; do
    case "$1" in
        --wallet)
            RESTORE_TYPE="wallet"
            shift
            ;;
        --database)
            RESTORE_TYPE="database"
            shift
            ;;
        --config)
            RESTORE_TYPE="config"
            shift
            ;;
        --decrypt)
            DO_DECRYPT=true
            shift
            ;;
        --dry-run)
            DRY_RUN=true
            shift
            ;;
        --force)
            FORCE=true
            shift
            ;;
        --help|-h)
            show_help
            exit 0
            ;;
        *)
            if [[ -z "$BACKUP_FILE" ]]; then
                BACKUP_FILE="$1"
            else
                log_error "Unknown option: $1"
                show_help
                exit 1
            fi
            shift
            ;;
    esac
done

if [[ -z "$BACKUP_FILE" ]]; then
    show_help
    exit 1
fi

if [[ ! -f "$BACKUP_FILE" ]]; then
    log_error "Backup file not found: $BACKUP_FILE"
    exit 1
fi

echo ""
echo -e "${CYAN}╔══════════════════════════════════════════════════════════════╗${NC}"
echo -e "${CYAN}║${NC}${WHITE}             SPIRAL POOL RESTORE - V1.0-BLACKICE              ${NC}${CYAN}║${NC}"
echo -e "${CYAN}╚══════════════════════════════════════════════════════════════╝${NC}"
echo ""

# Decrypt if needed
WORKING_FILE="$BACKUP_FILE"
if [[ "$DO_DECRYPT" == "true" ]] || [[ "$BACKUP_FILE" == *.enc ]]; then
    DECRYPTED_FILE=$(decrypt_backup "$BACKUP_FILE")
    WORKING_FILE="$DECRYPTED_FILE"
fi

# Extract backup
extract_backup "$WORKING_FILE"

# Show manifest
show_manifest

if [[ "$DRY_RUN" == "true" ]]; then
    echo -e "${YELLOW}DRY RUN - No changes will be made${NC}"
    echo ""
    exit 0
fi

# Confirmation
if [[ "$FORCE" != "true" ]]; then
    echo -e "${YELLOW}WARNING: This will overwrite existing data!${NC}"
    echo ""
    prompt_input "Continue with restore? (yes/no): "; read CONFIRM
    if [[ "$CONFIRM" != "yes" ]]; then
        log "Restore cancelled"
        exit 0
    fi
fi

echo ""

# Perform restore
case "$RESTORE_TYPE" in
    full)
        restore_wallet
        restore_database
        restore_config
        ;;
    wallet)
        restore_wallet
        ;;
    database)
        restore_database
        ;;
    config)
        restore_config
        ;;
esac

echo ""
echo -e "${GREEN}╔══════════════════════════════════════════════════════════════╗${NC}"
echo -e "${GREEN}║${NC}${WHITE}                      RESTORE COMPLETE!                       ${NC}${GREEN}║${NC}"
echo -e "${GREEN}╚══════════════════════════════════════════════════════════════╝${NC}"
echo ""
echo "  Services may need to be restarted: spiralpool-restart"
echo ""
RESTOREEOF

    # Maintenance mode (pause alerts)
    sudo tee /usr/local/bin/spiralpool-pause > /dev/null << 'PAUSEEOF'
#!/bin/bash
#
# Spiral Pool Maintenance Mode - Pause Alerts
# Usage: spiralpool-pause [minutes] [reason]
#        spiralpool-pause status
#        spiralpool-pause resume
#

# Colors
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
NC='\033[0m'

# Detect Sentinel's data directory — matches SpiralSentinel.py fallback logic
# When run under sudo, $HOME is /root, but Sentinel runs as spiraluser
_SENTINEL_HOME=$(getent passwd spiraluser 2>/dev/null | cut -d: -f6)
_SENTINEL_HOME="${_SENTINEL_HOME:-/home/spiraluser}"
if [[ -d "${_SENTINEL_HOME}/.spiralsentinel" ]]; then
    PAUSE_FILE="${_SENTINEL_HOME}/.spiralsentinel/maintenance_pause"
elif [[ -d "/spiralpool/config/sentinel" ]]; then
    # ProtectHome=yes fallback — same as SpiralSentinel.py
    PAUSE_FILE="/spiralpool/config/sentinel/maintenance_pause"
else
    # Last resort: create in spiraluser's home
    PAUSE_FILE="${_SENTINEL_HOME}/.spiralsentinel/maintenance_pause"
fi

show_banner() {
    echo -e "${CYAN}"
    echo "╔════════════════════════════════════════════════════════════════╗"
    echo "║              SPIRAL POOL MAINTENANCE MODE                      ║"
    echo "╚════════════════════════════════════════════════════════════════╝"
    echo -e "${NC}"
}

show_usage() {
    echo ""
    echo -e "${YELLOW}Usage:${NC}"
    echo "  spiralpool-pause <minutes> [reason]  - Pause alerts for X minutes"
    echo "  spiralpool-pause status              - Check maintenance mode status"
    echo "  spiralpool-pause resume              - Resume alerts immediately"
    echo ""
    echo -e "${YELLOW}Examples:${NC}"
    echo "  spiralpool-pause 30                  - Pause for 30 minutes"
    echo "  spiralpool-pause 60 'Firmware update' - Pause for 60 minutes with reason"
    echo "  spiralpool-pause 120 'Hardware maintenance'"
    echo ""
    echo -e "${YELLOW}Notes:${NC}"
    echo "  • Block found alerts will STILL be sent during maintenance"
    echo "  • All other alerts (offline, temperature, etc.) are paused"
    echo "  • Alerts automatically resume when the timer expires"
    echo ""
}

check_status() {
    if [[ ! -f "$PAUSE_FILE" ]]; then
        echo -e "${GREEN}✓ Maintenance mode: INACTIVE${NC}"
        echo "  Alerts are being sent normally."
        return 0
    fi

    # Parse the pause file
    pause_until=$(python3 -c "import json; print(json.load(open('$PAUSE_FILE'))['pause_until'])" 2>/dev/null)
    reason=$(python3 -c "import json; print(json.load(open('$PAUSE_FILE')).get('reason', 'Scheduled maintenance'))" 2>/dev/null)
    duration=$(python3 -c "import json; print(json.load(open('$PAUSE_FILE')).get('duration_minutes', 0))" 2>/dev/null)

    if [[ -z "$pause_until" ]]; then
        echo -e "${RED}✗ Invalid pause file${NC}"
        rm -f "$PAUSE_FILE"
        return 1
    fi

    now=$(date +%s)
    if (( now >= ${pause_until%.*} )); then
        echo -e "${GREEN}✓ Maintenance mode: EXPIRED${NC}"
        echo "  Timer has ended. Alerts resuming."
        rm -f "$PAUSE_FILE"
        return 0
    fi

    remaining=$(python3 -c "print(int(($pause_until - $now) / 60))")
    end_time=$(date -d "@${pause_until%.*}" "+%H:%M:%S" 2>/dev/null || date -r "${pause_until%.*}" "+%H:%M:%S" 2>/dev/null)

    echo -e "${YELLOW}⏸ Maintenance mode: ACTIVE${NC}"
    echo ""
    echo -e "  ${CYAN}Reason:${NC} $reason"
    echo -e "  ${CYAN}Duration:${NC} $duration minutes total"
    echo -e "  ${CYAN}Remaining:${NC} $remaining minutes"
    echo -e "  ${CYAN}Ends at:${NC} $end_time"
    echo ""
    echo -e "  ${GREEN}Note:${NC} Block found alerts will still be sent!"
    echo ""
    echo "  To resume alerts now: spiralpool-pause resume"
    return 0
}

pause_alerts() {
    local minutes=$1
    local reason="${2:-Scheduled maintenance}"

    # Validate minutes
    if ! [[ "$minutes" =~ ^[0-9]+$ ]] || [[ "$minutes" -lt 1 ]]; then
        echo -e "${RED}Error: Please specify a valid number of minutes (1 or more)${NC}"
        show_usage
        return 1
    fi

    if [[ "$minutes" -gt 1440 ]]; then
        echo -e "${YELLOW}Warning: Maximum pause duration is 24 hours (1440 minutes)${NC}"
        minutes=1440
    fi

    # Create pause file directory (use detected path, not $HOME which is /root under sudo)
    mkdir -p "$(dirname "$PAUSE_FILE")"
    pause_until=$(python3 -c "import time; print(time.time() + ($minutes * 60))")
    pause_start=$(python3 -c "import time; print(time.time())")

    PAUSE_UNTIL="$pause_until" PAUSE_START="$pause_start" MINUTES="$minutes" REASON="$reason" \
    PFILE="$PAUSE_FILE" python3 -c "
import json, os
data = {
    'pause_until': float(os.environ['PAUSE_UNTIL']),
    'pause_start': float(os.environ['PAUSE_START']),
    'duration_minutes': int(os.environ['MINUTES']),
    'reason': os.environ['REASON']
}
with open(os.environ['PFILE'], 'w') as f:
    json.dump(data, f, indent=2)
"

    end_time=$(date -d "+${minutes} minutes" "+%H:%M:%S" 2>/dev/null || date -v+${minutes}M "+%H:%M:%S" 2>/dev/null)

    echo -e "${GREEN}╔════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${GREEN}║               MAINTENANCE MODE ENABLED                         ║${NC}"
    echo -e "${GREEN}╚════════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo -e "  ${CYAN}Duration:${NC} $minutes $([ $minutes -eq 1 ] && echo minute || echo minutes)"
    echo -e "  ${CYAN}Reason:${NC} $reason"
    echo -e "  ${CYAN}Ends at:${NC} $end_time"
    echo ""
    echo -e "  ${YELLOW}Paused alerts:${NC}"
    echo "    • Miner offline/online notifications"
    echo "    • Temperature warnings"
    echo "    • Hashrate drop alerts"
    echo "    • Auto-restart notifications"
    echo "    • 6-hour/weekly reports"
    echo ""
    echo -e "  ${GREEN}Still active:${NC}"
    echo "    • Block found celebrations 🎉"
    echo ""
    echo "  To resume early: spiralpool-pause resume"
    echo ""
}

resume_alerts() {
    if [[ ! -f "$PAUSE_FILE" ]]; then
        echo -e "${GREEN}✓ Maintenance mode was not active${NC}"
        return 0
    fi

    rm -f "$PAUSE_FILE"

    echo -e "${GREEN}╔════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${GREEN}║                    ALERTS RESUMED                              ║${NC}"
    echo -e "${GREEN}╚════════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo "  Maintenance mode has been disabled."
    echo "  All alerts are now active."
    echo ""
}

# Main
show_banner

case "${1:-}" in
    ""|"-h"|"--help"|"help")
        show_usage
        ;;
    "status")
        check_status
        ;;
    "resume"|"unpause"|"clear"|"stop")
        resume_alerts
        ;;
    *)
        if [[ "$1" =~ ^[0-9]+$ ]]; then
            pause_alerts "$1" "${2:-Scheduled maintenance}"
        else
            echo -e "${RED}Error: Invalid argument '$1'${NC}"
            show_usage
            exit 1
        fi
        ;;
esac
PAUSEEOF

    # Quick stats command
    sudo tee /usr/local/bin/spiralpool-stats > /dev/null << 'STATSEOF'
#!/bin/bash
#
# Spiral Pool Quick Stats - At-a-glance mining summary
#

# Colors
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
WHITE='\033[1;37m'
MAGENTA='\033[0;35m'
DIM='\033[2m'
NC='\033[0m'

POOL_API="http://localhost:4000"

# Fetch pool stats
POOL_DATA=$(curl -s "${POOL_API}/api/pools" 2>/dev/null)

if [[ -z "$POOL_DATA" ]] || ! echo "$POOL_DATA" | python3 -c "import sys,json; json.load(sys.stdin)" 2>/dev/null; then
    echo -e "${YELLOW}Pool API not available. Is spiralstratum running?${NC}"
    echo "Run: spiralpool-status"
    exit 1
fi

# Parse data with Python for reliability
read -r HASHRATE MINERS BLOCKS_FOUND POOL_EFFORT NETWORK_HASH NETWORK_DIFF <<< $(echo "$POOL_DATA" | python3 -c "
import sys, json
try:
    # Per-algo block times in seconds (fallback for network hashrate computation)
    BT = {'DGB':75,'DGB-SCRYPT':75,'BTC':600,'BCH':600,'BC2':600,'NMC':600,
          'SYS':150,'XMY':60,'FBTC':30,'LTC':150,'DOGE':60,'PEP':60,'CAT':600}
    data = json.load(sys.stdin)
    pool = data.get('pools', [{}])[0] if isinstance(data.get('pools'), list) else {}
    ps = pool.get('poolStats', {})
    coin = pool.get('coin', {})
    symbol = coin.get('type', 'UNKNOWN').upper()

    hashrate = ps.get('poolHashrate', 0)
    miners = ps.get('connectedMiners', 0)
    blocks = ps.get('blocksFound', 0)
    effort = ps.get('poolEffort', 0)
    net_diff = ps.get('networkDifficulty', 0)
    net_hash = ps.get('networkHashrate', 0)
    if net_hash == 0 and net_diff > 0:
        bt = BT.get(symbol, 600)
        net_hash = net_diff * (2**32) / bt if bt > 0 else 0

    print(f'{hashrate} {miners} {blocks} {effort} {net_hash} {net_diff}')
except:
    print('0 0 0 0 0 0')
" 2>/dev/null)

# Format hashrate
format_hashrate() {
    local h=$1
    if (( $(echo "$h >= 1000000000000000" | bc -l) )); then
        echo "$(echo "scale=2; $h / 1000000000000000" | bc) PH/s"
    elif (( $(echo "$h >= 1000000000000" | bc -l) )); then
        echo "$(echo "scale=2; $h / 1000000000000" | bc) TH/s"
    elif (( $(echo "$h >= 1000000000" | bc -l) )); then
        echo "$(echo "scale=2; $h / 1000000000" | bc) GH/s"
    elif (( $(echo "$h >= 1000000" | bc -l) )); then
        echo "$(echo "scale=2; $h / 1000000" | bc) MH/s"
    else
        echo "${h} H/s"
    fi
}

POOL_HR=$(format_hashrate "$HASHRATE")
NET_HR=$(format_hashrate "$NETWORK_HASH")

# Get uptime
UPTIME=""
if systemctl is-active spiralstratum &>/dev/null; then
    UPTIME=$(systemctl show spiralstratum --property=ActiveEnterTimestamp --value 2>/dev/null | xargs -I{} date -d {} +%s 2>/dev/null)
    if [[ -n "$UPTIME" ]]; then
        NOW=$(date +%s)
        SECS=$((NOW - UPTIME))
        DAYS=$((SECS / 86400))
        HOURS=$(( (SECS % 86400) / 3600 ))
        MINS=$(( (SECS % 3600) / 60 ))
        if [[ $DAYS -gt 0 ]]; then
            UPTIME="${DAYS}d ${HOURS}h"
        elif [[ $HOURS -gt 0 ]]; then
            UPTIME="${HOURS}h ${MINS}m"
        else
            UPTIME="${MINS}m"
        fi
    fi
fi

# Calculate pool share percentage
POOL_SHARE="0.0000"
if (( $(echo "$NETWORK_HASH > 0" | bc -l) )); then
    POOL_SHARE=$(echo "scale=4; ($HASHRATE / $NETWORK_HASH) * 100" | bc 2>/dev/null || echo "0.0000")
fi

# Display
echo ""
echo -e "${CYAN}╔════════════════════════════════════════════════════════════════╗${NC}"
echo -e "${CYAN}║${NC}               ${WHITE}SPIRAL POOL QUICK STATS${NC}                          ${CYAN}║${NC}"
echo -e "${CYAN}╚════════════════════════════════════════════════════════════════╝${NC}"
echo ""
echo -e "  ${WHITE}Pool Hashrate:${NC}    ${GREEN}${POOL_HR}${NC}"
echo -e "  ${WHITE}Connected Miners:${NC} ${CYAN}${MINERS}${NC}"
echo -e "  ${WHITE}Blocks Found:${NC}     ${MAGENTA}${BLOCKS_FOUND}${NC}"
echo -e "  ${WHITE}Pool Share:${NC}       ${YELLOW}${POOL_SHARE}%${NC} of network"
[[ -n "$UPTIME" ]] && echo -e "  ${WHITE}Uptime:${NC}           ${DIM}${UPTIME}${NC}"
echo ""
echo -e "  ${DIM}Network: ${NET_HR} | Diff: $(printf "%.2f" $(echo "$NETWORK_DIFF / 1000000000" | bc -l 2>/dev/null || echo 0))G${NC}"
echo ""

# Show effort if available
if (( $(echo "$POOL_EFFORT > 0" | bc -l 2>/dev/null) )); then
    EFFORT_PCT=$(printf "%.1f" "$POOL_EFFORT")
    if (( $(echo "$POOL_EFFORT < 100" | bc -l) )); then
        echo -e "  ${GREEN}Current Effort: ${EFFORT_PCT}% (Lucky!)${NC}"
    elif (( $(echo "$POOL_EFFORT < 200" | bc -l) )); then
        echo -e "  ${YELLOW}Current Effort: ${EFFORT_PCT}%${NC}"
    else
        echo -e "  ${YELLOW}Current Effort: ${EFFORT_PCT}% (Unlucky streak)${NC}"
    fi
    echo ""
fi
STATSEOF

    # Block history command - show last N blocks with finder info
    sudo tee /usr/local/bin/spiralpool-blocks > /dev/null << 'BLOCKSEOF'
#!/bin/bash
#
# Spiral Pool Block History - Show recent blocks found by the pool
#
# Usage: spiralpool-blocks [count]    (default: 5)
#

# Colors
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
WHITE='\033[1;37m'
MAGENTA='\033[0;35m'
RED='\033[0;31m'
DIM='\033[2m'
NC='\033[0m'

POOL_API="http://localhost:4000"
LIMIT="${1:-5}"

# Validate limit is a number
if ! [[ "$LIMIT" =~ ^[0-9]+$ ]] || [[ "$LIMIT" -lt 1 ]] || [[ "$LIMIT" -gt 50 ]]; then
    echo -e "${YELLOW}Usage: spiralpool-blocks [count]${NC}"
    echo "  count: Number of blocks to show (1-50, default: 5)"
    exit 1
fi

# Fetch pool list to get pool ID
POOL_DATA=$(curl -s "${POOL_API}/api/pools" 2>/dev/null)

if [[ -z "$POOL_DATA" ]] || ! echo "$POOL_DATA" | python3 -c "import sys,json; json.load(sys.stdin)" 2>/dev/null; then
    echo -e "${YELLOW}Pool API not available. Is spiralstratum running?${NC}"
    echo "Run: spiralpool-status"
    exit 1
fi

# Extract pool ID
POOL_ID=$(echo "$POOL_DATA" | python3 -c "
import sys, json
try:
    data = json.load(sys.stdin)
    pools = data.get('pools', [])
    if pools:
        print(pools[0].get('id', ''))
except:
    pass
" 2>/dev/null)

if [[ -z "$POOL_ID" ]]; then
    echo -e "${RED}Could not determine pool ID from API${NC}"
    exit 1
fi

# Fetch blocks
BLOCKS_DATA=$(curl -s "${POOL_API}/api/pools/${POOL_ID}/blocks" 2>/dev/null)

if [[ -z "$BLOCKS_DATA" ]] || ! echo "$BLOCKS_DATA" | python3 -c "import sys,json; json.load(sys.stdin)" 2>/dev/null; then
    echo -e "${YELLOW}Could not fetch block data${NC}"
    exit 1
fi

# Parse and display blocks
echo "$BLOCKS_DATA" | python3 -c "
import sys, json
from datetime import datetime, timezone

try:
    blocks = json.load(sys.stdin)
except:
    print('\033[1;33mInvalid block data\033[0m')
    sys.exit(1)

limit = int('${LIMIT}')

if not blocks:
    print()
    print('\033[0;36m╔════════════════════════════════════════════════════════════════╗\033[0m')
    print('\033[0;36m║\033[0m            \033[1;37mSPIRAL POOL BLOCK HISTORY\033[0m                           \033[0;36m║\033[0m')
    print('\033[0;36m╚════════════════════════════════════════════════════════════════╝\033[0m')
    print()
    print('  No blocks found yet. Keep mining!')
    print()
    sys.exit(0)

# Time ago helper
def time_ago(ts_str):
    try:
        # Handle ISO format with Z or +00:00
        ts_str = ts_str.replace('Z', '+00:00')
        dt = datetime.fromisoformat(ts_str)
        now = datetime.now(timezone.utc)
        diff = now - dt
        secs = int(diff.total_seconds())
        if secs < 60:
            return f'{secs}s ago'
        elif secs < 3600:
            return f'{secs // 60}m ago'
        elif secs < 86400:
            h = secs // 3600
            m = (secs % 3600) // 60
            return f'{h}h {m}m ago'
        else:
            d = secs // 86400
            h = (secs % 86400) // 3600
            return f'{d}d {h}h ago'
    except:
        return ts_str[:19] if ts_str else 'unknown'

# Status color/symbol
def status_fmt(status):
    s = status.lower() if status else 'unknown'
    if s == 'confirmed':
        return '\033[0;32m\u2714 confirmed\033[0m'
    elif s == 'pending':
        return '\033[1;33m\u23f3 pending\033[0m'
    elif s == 'orphaned':
        return '\033[0;31m\u2718 orphaned\033[0m'
    else:
        return f'\033[2m{s}\033[0m'

# Extract worker name: prefer 'source' (worker name), fall back to 'miner' (wallet)
def get_finder(block):
    # source field contains the actual worker name (e.g. 'HashForge')
    source = block.get('source', '') or ''
    if source and source.lower() not in ('stratum', 'default', 'x', ''):
        return source
    miner = block.get('miner', '') or ''
    # If miner contains a dot, the part after the last dot is the worker name
    if '.' in miner:
        parts = miner.rsplit('.', 1)
        worker = parts[1] if len(parts) > 1 else miner
        # If worker is just 'default' or 'x', show the truncated address instead
        if worker.lower() in ('default', 'x', ''):
            return miner[:12] + '...' if len(miner) > 12 else miner
        return worker
    # No dot - show truncated address
    if len(miner) > 16:
        return miner[:12] + '...'
    return miner if miner else 'unknown'

# Format reward
def fmt_reward(reward):
    if not reward:
        return '?'
    r = float(reward)
    if r >= 1:
        return f'{r:.4f}'
    elif r >= 0.001:
        return f'{r:.6f}'
    else:
        return f'{r:.8f}'

shown = blocks[:limit]

print()
print('\033[0;36m\u2554' + '\u2550' * 64 + '\u2557\033[0m')
print('\033[0;36m\u2551\033[0m            \033[1;37mSPIRAL POOL BLOCK HISTORY\033[0m                           \033[0;36m\u2551\033[0m')
print('\033[0;36m\u255a' + '\u2550' * 64 + '\u255d\033[0m')
print()
print(f'  Showing last {len(shown)} of {len(blocks)} total blocks found')
print()

for i, block in enumerate(shown):
    height = block.get('blockHeight', '?')
    finder = get_finder(block)
    status = status_fmt(block.get('status', ''))
    reward_val = fmt_reward(block.get('reward'))
    created = block.get('created', '')
    ago = time_ago(created)
    effort = block.get('effort', 0)
    effort_str = f'{effort:.1f}%' if effort else '?'

    # Block number with color
    print(f'  \033[0;35m#{height}\033[0m')
    print(f'    \033[1;37mFound by:\033[0m  \033[0;32m{finder}\033[0m')
    print(f'    \033[1;37mStatus:\033[0m    {status}')
    print(f'    \033[1;37mReward:\033[0m    \033[0;36m{reward_val}\033[0m')
    print(f'    \033[1;37mEffort:\033[0m    {effort_str}')
    print(f'    \033[1;37mWhen:\033[0m      \033[2m{ago}\033[0m')
    if i < len(shown) - 1:
        sep = "─" * 50
        print(f'  \033[2m{sep}\033[0m')

print()
" 2>/dev/null

