#!/bin/bash
#
# Spiral Pool Diagnostic Test - Verify all connections
#

# Colors
GREEN='\033[0;32m'
RED='\033[0;31m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
WHITE='\033[1;37m'
NC='\033[0m'

PASS=0
FAIL=0
WARN=0

echo ""
echo -e "${CYAN}╔════════════════════════════════════════════════════════════════╗${NC}"
echo -e "${CYAN}║${NC}${WHITE}                  SPIRAL POOL DIAGNOSTIC TEST                   ${NC}${CYAN}║${NC}"
echo -e "${CYAN}╚════════════════════════════════════════════════════════════════╝${NC}"
echo ""

test_pass() { echo -e "  [${GREEN}✓${NC}] $1"; ((PASS++)); }
test_fail() { echo -e "  [${RED}✗${NC}] $1"; ((FAIL++)); }
test_warn() { echo -e "  [${YELLOW}!${NC}] $1"; ((WARN++)); }

# === SERVICES ===
echo -e "${WHITE}Services:${NC}"

# Database service (Patroni manages PG in HA mode)
if systemctl is-enabled --quiet "patroni" 2>/dev/null; then
    db_svc="patroni"
else
    db_svc="postgresql"
fi
if systemctl is-active --quiet "$db_svc" 2>/dev/null; then
    test_pass "$db_svc is running"
else
    test_fail "$db_svc is NOT running"
fi

# Core services (always required)
if systemctl is-active --quiet "spiralstratum" 2>/dev/null; then
    test_pass "spiralstratum is running"
else
    test_fail "spiralstratum is NOT running"
fi

# Blockchain daemon services (check which ones are installed)
for daemon in digibyted bitcoind bitcoind-bch bitcoiniid litecoind dogecoind pepecoind catcoind namecoind syscoind myriadcoind fractald; do
    if systemctl is-enabled --quiet "$daemon" 2>/dev/null; then
        if systemctl is-active --quiet "$daemon" 2>/dev/null; then
            test_pass "$daemon is running"
        else
            test_fail "$daemon is NOT running"
        fi
    fi
done

# Optional services
for svc in spiraldash spiralsentinel; do
    if systemctl is-active --quiet "$svc" 2>/dev/null; then
        test_pass "$svc is running"
    elif systemctl is-enabled --quiet "$svc" 2>/dev/null; then
        test_warn "$svc is enabled but not running"
    fi
done

# HA services (only check if enabled)
for ha_svc in etcd keepalived redis-server; do
    if systemctl is-enabled --quiet "$ha_svc" 2>/dev/null; then
        if systemctl is-active --quiet "$ha_svc" 2>/dev/null; then
            test_pass "$ha_svc is running"
        else
            test_fail "$ha_svc is NOT running"
        fi
    fi
done
echo ""

# === BLOCKCHAIN RPC ===
# Check each installed blockchain daemon
check_blockchain_rpc() {
    local name=$1
    local cli=$2
    local conf=$3

    if [[ ! -f "$conf" ]]; then
        return 1
    fi

    echo -e "${WHITE}${name} RPC:${NC}"

    if $cli -conf="$conf" getblockchaininfo &>/dev/null; then
        test_pass "RPC connection working"

        # Check sync status: initialblockdownload=false is authoritative (works for BC2 and all chains)
        local INFO=$($cli -conf="$conf" getblockchaininfo 2>/dev/null)
        PROGRESS=$(echo "$INFO" | grep -o '"verificationprogress":[^,]*' | cut -d: -f2)
        IBD=$(echo "$INFO" | grep -o '"initialblockdownload":[^,]*' | cut -d: -f2 | tr -d ' ')
        if [[ "$IBD" == "false" ]] || echo "$PROGRESS" | awk '{exit ($1 >= 0.9999) ? 0 : 1}' 2>/dev/null; then
            test_pass "Blockchain fully synced"
        else
            PCT=$(echo "$PROGRESS" | awk '{printf "%.2f", $1 * 100}')
            test_warn "Blockchain syncing (${PCT}%)"
        fi

        # Check connections
        CONNS=$($cli -conf="$conf" getconnectioncount 2>/dev/null || echo "0")
        if [[ "$CONNS" -ge 4 ]]; then
            test_pass "Peer connections: $CONNS"
        elif [[ "$CONNS" -ge 1 ]]; then
            test_warn "Low peer connections: $CONNS (recommend 8+)"
        else
            test_fail "No peer connections"
        fi
    else
        test_fail "RPC connection failed"
    fi
    echo ""
    return 0
}

# Check DigiByte
check_blockchain_rpc "DigiByte" "digibyte-cli" "$(get_blockchain_dir dgb)/digibyte.conf"

# Check Bitcoin
check_blockchain_rpc "Bitcoin" "bitcoin-cli" "$(get_blockchain_dir btc)/bitcoin.conf"

# Check Bitcoin Cash
check_blockchain_rpc "Bitcoin Cash" "bitcoin-cli-bch" "$(get_blockchain_dir bch)/bitcoin.conf"

# Check Bitcoin II
check_blockchain_rpc "Bitcoin II" "bitcoinii-cli" "$(get_blockchain_dir bc2)/bitcoinii.conf"

# Check Litecoin
check_blockchain_rpc "Litecoin" "litecoin-cli" "$(get_blockchain_dir ltc)/litecoin.conf"

# Check Dogecoin
check_blockchain_rpc "Dogecoin" "dogecoin-cli" "$(get_blockchain_dir doge)/dogecoin.conf"

# Check PepeCoin
check_blockchain_rpc "PepeCoin" "pepecoin-cli" "$(get_blockchain_dir pep)/pepecoin.conf"

# Check Catcoin
check_blockchain_rpc "Catcoin" "catcoin-cli" "$(get_blockchain_dir cat)/catcoin.conf"

# Check Namecoin
check_blockchain_rpc "Namecoin" "namecoin-cli" "$(get_blockchain_dir nmc)/namecoin.conf"

# Check Syscoin
check_blockchain_rpc "Syscoin" "syscoin-cli" "$(get_blockchain_dir sys)/syscoin.conf"

# Check Myriadcoin
check_blockchain_rpc "Myriadcoin" "myriadcoin-cli" "$(get_blockchain_dir xmy)/myriadcoin.conf"

# Check Fractal Bitcoin
check_blockchain_rpc "Fractal Bitcoin" "fractal-cli" "$(get_blockchain_dir fbtc)/fractal.conf"

# Check Q-BitX
check_blockchain_rpc "Q-BitX" "qbitx-cli" "$(get_blockchain_dir qbx)/qbitx.conf"

# === DATABASE ===
echo -e "${WHITE}PostgreSQL Database:${NC}"

# Load credentials from config if available
DB_USER="spiralstratum"
DB_NAME="spiralstratum"
if [[ -f /spiralpool/config/config.yaml ]]; then
    DB_USER=$(grep -A5 'postgres:' /spiralpool/config/config.yaml 2>/dev/null | grep 'user:' | awk '{print $2}' | tr -d '"' || echo "spiralstratum")
fi

if sudo -u postgres psql -c "SELECT 1" &>/dev/null; then
    test_pass "PostgreSQL accepting connections"

    if sudo -u postgres psql -d "$DB_NAME" -c "SELECT 1" &>/dev/null; then
        test_pass "Database '$DB_NAME' exists"

        # Check tables
        TABLES=$(sudo -u postgres psql -d "$DB_NAME" -t -c "SELECT COUNT(*) FROM information_schema.tables WHERE table_schema='public'" 2>/dev/null | tr -d ' ')
        if [[ "$TABLES" -gt 0 ]]; then
            test_pass "Database has $TABLES tables"
        else
            test_warn "Database has no tables (first run?)"
        fi
    else
        test_fail "Database '$DB_NAME' not found"
    fi
else
    test_fail "PostgreSQL not accepting connections"
fi
echo ""

# === POOL API ===
echo -e "${WHITE}Pool API:${NC}"

API_RESPONSE=$(curl -s -o /dev/null -w "%{http_code}" "http://localhost:4000/api/pools" 2>/dev/null)
if [[ "$API_RESPONSE" == "200" ]]; then
    test_pass "Pool API responding (port 4000)"

    # Check if we have pool data
    POOL_DATA=$(curl -s "http://localhost:4000/api/pools" 2>/dev/null)
    if echo "$POOL_DATA" | grep -q '"pools"'; then
        test_pass "Pool data available"
    else
        test_warn "Pool API responding but no pool data"
    fi
else
    test_fail "Pool API not responding (HTTP $API_RESPONSE)"
fi
echo ""

# === PORTS ===
echo -e "${WHITE}Network Ports:${NC}"

check_port() {
    local port=$1
    local name=$2
    if ss -tlnp 2>/dev/null | grep -q ":${port} " || netstat -tlnp 2>/dev/null | grep -q ":${port} "; then
        test_pass "Port $port ($name) is listening"
    else
        test_fail "Port $port ($name) is NOT listening"
    fi
}

# Check stratum ports for enabled coins
if systemctl is-enabled --quiet digibyted 2>/dev/null; then
    check_port 3333 "DGB Stratum V1"
    check_port 14022 "DGB RPC"
fi
# DGB-SCRYPT shares digibyted daemon - check config for stratum port
if grep -q "port: 3336" /spiralpool/config/config.yaml 2>/dev/null; then
    check_port 3336 "DGB-SCRYPT Stratum V1"
fi
if systemctl is-enabled --quiet bitcoind 2>/dev/null; then
    check_port 4333 "BTC Stratum V1"
    check_port 8332 "BTC RPC"
fi
if systemctl is-enabled --quiet bitcoind-bch 2>/dev/null; then
    check_port 5333 "BCH Stratum V1"
    check_port 8432 "BCH RPC"
fi
if systemctl is-enabled --quiet bitcoiniid 2>/dev/null; then
    check_port 6333 "BC2 Stratum V1"
    check_port 8339 "BC2 RPC"
fi
if systemctl is-enabled --quiet litecoind 2>/dev/null; then
    check_port 7333 "LTC Stratum V1"
    check_port 9332 "LTC RPC"
fi
if systemctl is-enabled --quiet dogecoind 2>/dev/null; then
    check_port 8335 "DOGE Stratum V1"
    check_port 22555 "DOGE RPC"
fi
if systemctl is-enabled --quiet pepecoind 2>/dev/null; then
    check_port 10335 "PEP Stratum V1"
    check_port 33873 "PEP RPC"
fi
if systemctl is-enabled --quiet catcoind 2>/dev/null; then
    check_port 12335 "CAT Stratum V1"
    check_port 9932 "CAT RPC"
fi
if systemctl is-enabled --quiet namecoind 2>/dev/null; then
    check_port 14335 "NMC Stratum V1"
    check_port 8336 "NMC RPC"
fi
if systemctl is-enabled --quiet syscoind 2>/dev/null; then
    check_port 15335 "SYS Stratum V1"
    check_port 8370 "SYS RPC"
fi
if systemctl is-enabled --quiet myriadcoind 2>/dev/null; then
    check_port 17335 "XMY Stratum V1"
    check_port 10889 "XMY RPC"
fi
if systemctl is-enabled --quiet fractald 2>/dev/null; then
    check_port 18335 "FBTC Stratum V1"
    check_port 8340 "FBTC RPC"
fi
if systemctl is-enabled --quiet qbitxd 2>/dev/null; then
    check_port 20335 "QBX Stratum V1"
    check_port 8344 "QBX RPC"
fi

check_port 4000 "Pool API"

# Optional ports - check if listening (all possible V2 ports + dashboard)
for port_info in "3334:DGB Stratum V2" "4334:BTC Stratum V2" "5334:BCH Stratum V2" "6334:BC2 Stratum V2" "7334:LTC Stratum V2" "8337:DOGE Stratum V2" "10336:PEP Stratum V2" "3337:DGB-SCRYPT V2" "12336:CAT Stratum V2" "14336:NMC Stratum V2" "15336:SYS Stratum V2" "17336:XMY Stratum V2" "18336:FBTC Stratum V2" "20336:QBX Stratum V2" "1618:Dashboard"; do
    port="${port_info%%:*}"
    name="${port_info##*:}"
    if ss -tlnp 2>/dev/null | grep -q ":${port} " || netstat -tlnp 2>/dev/null | grep -q ":${port} "; then
        test_pass "Port $port ($name) is listening"
    fi
done
echo ""

# === STRATUM CONNECTION TEST ===
echo -e "${WHITE}Stratum Connection:${NC}"

test_stratum_port() {
    local port=$1
    local coin=$2
    if command -v nc &>/dev/null || command -v netcat &>/dev/null; then
        NC_CMD=$(command -v nc || command -v netcat)
        # Send a subscribe request
        RESPONSE=$(echo '{"id":1,"method":"mining.subscribe","params":[]}' | timeout 3 $NC_CMD localhost $port 2>/dev/null | head -1)
        if echo "$RESPONSE" | grep -q '"result"'; then
            test_pass "$coin Stratum accepting connections (port $port)"
        elif [[ -n "$RESPONSE" ]]; then
            test_warn "$coin Stratum responded but unexpected format"
        else
            test_fail "$coin Stratum not responding (port $port)"
        fi
    else
        test_warn "netcat not installed - skipping stratum test"
    fi
}

# Test stratum for each enabled coin
STRATUM_TESTED=false
if systemctl is-enabled --quiet digibyted 2>/dev/null; then
