    test_stratum_port 12335 "CAT"
    STRATUM_TESTED=true
fi
if systemctl is-enabled --quiet namecoind 2>/dev/null; then
    test_stratum_port 14335 "NMC"
    STRATUM_TESTED=true
fi
if systemctl is-enabled --quiet syscoind 2>/dev/null; then
    test_stratum_port 15335 "SYS"
    STRATUM_TESTED=true
fi
if systemctl is-enabled --quiet myriadcoind 2>/dev/null; then
    test_stratum_port 17335 "XMY"
    STRATUM_TESTED=true
fi
if systemctl is-enabled --quiet fractald 2>/dev/null; then
    test_stratum_port 18335 "FBTC"
    STRATUM_TESTED=true
fi

if [[ "$STRATUM_TESTED" != "true" ]]; then
    test_warn "No blockchain daemons enabled - cannot test stratum"
fi
echo ""

# === SUMMARY ===
echo -e "${CYAN}════════════════════════════════════════════════════════════════${NC}"
TOTAL=$((PASS + FAIL + WARN))
echo -e "  ${GREEN}Passed:${NC} $PASS   ${RED}Failed:${NC} $FAIL   ${YELLOW}Warnings:${NC} $WARN   ${DIM}Total: $TOTAL${NC}"
