    # Interactive config editor
    sudo tee /usr/local/bin/spiralpool-config > /dev/null << 'CONFIGEOF'
#!/bin/bash
#
# Spiral Pool Interactive Config Editor
#

# Colors
GREEN='\033[0;32m'
RED='\033[0;31m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
WHITE='\033[1;37m'
DIM='\033[2m'
NC='\033[0m'

# Standard pool service account (matches install.sh)
POOL_USER="spiraluser"

# Detect Sentinel config directory — matches SpiralSentinel.py fallback logic
# When run under sudo, $HOME is /root, but Sentinel runs as spiraluser
_SENTINEL_HOME=$(getent passwd "$POOL_USER" 2>/dev/null | cut -d: -f6)
_SENTINEL_HOME="${_SENTINEL_HOME:-/home/$POOL_USER}"
if [[ -d "${_SENTINEL_HOME}/.spiralsentinel" ]]; then
    SENTINEL_CONFIG="${_SENTINEL_HOME}/.spiralsentinel/config.json"
elif [[ -d "/spiralpool/config/sentinel" ]]; then
    SENTINEL_CONFIG="/spiralpool/config/sentinel/config.json"
else
    SENTINEL_CONFIG="${_SENTINEL_HOME}/.spiralsentinel/config.json"
fi
POOL_CONFIG="/spiralpool/config/config.yaml"

# Prompt helper (styled input prompt)
prompt_input() {
    echo -ne "  ${GREEN}▸${NC} ${WHITE}${1}${NC}"
}

show_banner() {
    echo -e "${CYAN}"
    echo "╔════════════════════════════════════════════════════════════════╗"
    echo "║               SPIRAL POOL CONFIG EDITOR                        ║"
    echo "╚════════════════════════════════════════════════════════════════╝"
    echo -e "${NC}"
}

show_menu() {
    echo -e "${WHITE}What would you like to configure?${NC}"
    echo ""
    echo "  1) Discord Webhook URL"
    echo "  2) Telegram Bot Settings"
    echo "  3) XMPP Settings"
    echo "  4) Alert Settings (quiet hours, thresholds)"
    echo "  5) Report Frequency (6h, daily, off)"
    echo "  6) Currency Preference"
    echo "  7) Alert Theme (cyberpunk/professional)"
    echo "  8) Power Cost Settings"
    echo "  9) Miner Nicknames"
    echo "  10) View Current Config"
    echo "  11) Exit"
    echo ""
}

read_config() {
    if [[ -f "$SENTINEL_CONFIG" ]]; then
        cat "$SENTINEL_CONFIG"
    else
        echo "{}"
    fi
}

update_config() {
    local key="$1"
    local value="$2"
    local is_string="${3:-true}"

    mkdir -p "$(dirname "$SENTINEL_CONFIG")"

    if [[ ! -f "$SENTINEL_CONFIG" ]]; then
        echo "{}" > "$SENTINEL_CONFIG"
    fi

    CONFIG_PATH="$SENTINEL_CONFIG" KEY="$key" VALUE="$value" IS_STRING="$is_string" \
    python3 -c "
import json, os
config_path = os.environ['CONFIG_PATH']
key = os.environ['KEY']
value = os.environ['VALUE']
is_string = os.environ['IS_STRING']
with open(config_path, 'r') as f:
    config = json.load(f)
if is_string == 'true':
    config[key] = value
else:
    config[key] = json.loads(value)
with open(config_path, 'w') as f:
    json.dump(config, f, indent=2)
"
}

get_config_value() {
    local key="$1"
    local default="$2"
    CONFIG_PATH="$SENTINEL_CONFIG" KEY="$key" DEFAULT="$default" \
    python3 -c "
import json, os
config_path = os.environ['CONFIG_PATH']
key = os.environ['KEY']
default = os.environ['DEFAULT']
try:
    with open(config_path, 'r') as f:
        config = json.load(f)
    print(config.get(key, default))
except:
    print(default)
" 2>/dev/null
}

config_discord() {
    echo ""
    echo -e "${WHITE}Discord Webhook Configuration${NC}"
    echo -e "${DIM}Current: $(get_config_value 'discord_webhook_url' 'Not set')${NC}"
    echo ""
    prompt_input "Enter Discord Webhook URL (or 'clear' to remove): "; read webhook

    if [[ "$webhook" == "clear" ]]; then
        update_config "discord_webhook_url" ""
        echo -e "${GREEN}✓ Discord webhook cleared${NC}"
    elif [[ "$webhook" =~ ^https://discord\.com/api/webhooks/ ]]; then
        update_config "discord_webhook_url" "$webhook"
        echo -e "${GREEN}✓ Discord webhook updated${NC}"
    elif [[ -n "$webhook" ]]; then
        echo -e "${RED}Invalid webhook URL. Must start with https://discord.com/api/webhooks/${NC}"
    fi
}

config_telegram() {
    echo ""
    echo -e "${WHITE}Telegram Bot Configuration${NC}"
    echo -e "${DIM}Current Token: $(get_config_value 'telegram_bot_token' 'Not set' | head -c 20)...${NC}"
    echo -e "${DIM}Current Chat ID: $(get_config_value 'telegram_chat_id' 'Not set')${NC}"
    echo ""

    prompt_input "Enter Telegram Bot Token (from @BotFather, or 'skip'): "; read token
    if [[ "$token" != "skip" ]] && [[ -n "$token" ]]; then
        update_config "telegram_bot_token" "$token"
        echo -e "${GREEN}✓ Bot token updated${NC}"
    fi

    prompt_input "Enter Telegram Chat ID (or 'skip'): "; read chat_id
    if [[ "$chat_id" != "skip" ]] && [[ -n "$chat_id" ]]; then
        update_config "telegram_chat_id" "$chat_id"
        echo -e "${GREEN}✓ Chat ID updated${NC}"
    fi

    prompt_input "Enable Telegram notifications? (y/n): "; read enable
    if [[ "$enable" =~ ^[Yy] ]]; then
        update_config "telegram_enabled" "true" "false"
        echo -e "${GREEN}✓ Telegram enabled${NC}"
    else
        update_config "telegram_enabled" "false" "false"
        echo -e "${YELLOW}Telegram disabled${NC}"
    fi
}

config_xmpp() {
    echo ""
    echo -e "${WHITE}XMPP Settings${NC}"
    echo -e "${DIM}Current JID: $(get_config_value 'xmpp_jid' 'Not set')${NC}"
    echo -e "${DIM}Current Recipient: $(get_config_value 'xmpp_recipient' 'Not set')${NC}"
    echo ""

    prompt_input "Enter XMPP Bot JID (or 'clear' to remove, 'skip' to keep): "; read jid
    if [[ "$jid" == "clear" ]]; then
        update_config "xmpp_jid" ""
        update_config "xmpp_password" ""
        update_config "xmpp_recipient" ""
        update_config "xmpp_enabled" "false" "false"
        echo -e "${GREEN}✓ XMPP settings cleared${NC}"
        return
    elif [[ "$jid" != "skip" ]] && [[ -n "$jid" ]]; then
        update_config "xmpp_jid" "$jid"
        echo -e "${GREEN}✓ JID updated${NC}"
    fi

    prompt_input "Enter XMPP Bot Password (or 'skip'): "; read -s xmpp_pass; echo ""
    if [[ "$xmpp_pass" != "skip" ]] && [[ -n "$xmpp_pass" ]]; then
        update_config "xmpp_password" "$xmpp_pass"
        echo -e "${GREEN}✓ Password updated${NC}"
    fi

    prompt_input "Enter Recipient JID (or 'skip'): "; read recipient
    if [[ "$recipient" != "skip" ]] && [[ -n "$recipient" ]]; then
        update_config "xmpp_recipient" "$recipient"
        echo -e "${GREEN}✓ Recipient updated${NC}"
    fi

    prompt_input "Is recipient a MUC room? (y/n/skip): "; read muc
    if [[ "$muc" =~ ^[Yy] ]]; then
        update_config "xmpp_muc" "true" "false"
        echo -e "${GREEN}✓ MUC mode enabled${NC}"
    elif [[ "$muc" =~ ^[Nn] ]]; then
        update_config "xmpp_muc" "false" "false"
        echo -e "${GREEN}✓ MUC mode disabled${NC}"
    fi

    prompt_input "Enable XMPP notifications? (y/n): "; read enable
    if [[ "$enable" =~ ^[Yy] ]]; then
        update_config "xmpp_enabled" "true" "false"
        echo -e "${GREEN}✓ XMPP enabled${NC}"
    else
        update_config "xmpp_enabled" "false" "false"
        echo -e "${YELLOW}XMPP disabled${NC}"
    fi
}

config_alerts() {
    echo ""
    echo -e "${WHITE}Alert Settings${NC}"
    echo ""

    echo "Quiet Hours (suppress non-critical alerts):"
    echo -e "${DIM}Current: $(get_config_value 'quiet_hours_start' '22'):00 - $(get_config_value 'quiet_hours_end' '6'):00${NC}"
    prompt_input "Start hour (0-23, or 'skip'): "; read start
    if [[ "$start" != "skip" ]] && [[ "$start" =~ ^[0-9]+$ ]]; then
        update_config "quiet_hours_start" "$start" "false"
    fi
    prompt_input "End hour (0-23, or 'skip'): "; read end
    if [[ "$end" != "skip" ]] && [[ "$end" =~ ^[0-9]+$ ]]; then
        update_config "quiet_hours_end" "$end" "false"
    fi

    echo ""
    echo "Temperature Thresholds:"
    echo -e "${DIM}Current Warning: $(get_config_value 'temp_warning' '75')°C | Critical: $(get_config_value 'temp_critical' '85')°C${NC}"
    prompt_input "Warning temp °C (or 'skip'): "; read temp_warn
    if [[ "$temp_warn" != "skip" ]] && [[ "$temp_warn" =~ ^[0-9]+$ ]]; then
        update_config "temp_warning" "$temp_warn" "false"
    fi
    prompt_input "Critical temp °C (or 'skip'): "; read temp_crit
    if [[ "$temp_crit" != "skip" ]] && [[ "$temp_crit" =~ ^[0-9]+$ ]]; then
        update_config "temp_critical" "$temp_crit" "false"
    fi

    echo -e "${GREEN}✓ Alert settings updated${NC}"
}

config_reports() {
    echo ""
    echo -e "${WHITE}Report Frequency${NC}"
    echo -e "${DIM}Current: $(get_config_value 'report_frequency' '6h')${NC}"
    echo ""
    echo "  1) 6h   - Reports 4x daily (06:00, 12:00, 18:00, 21:55)"
    echo "  2) daily - Single daily digest"
    echo "  3) off   - Disable scheduled reports (alerts still work)"
    echo ""
    prompt_input "Select (1/2/3): "; read choice

    case "$choice" in
        1) update_config "report_frequency" "6h"; echo -e "${GREEN}✓ Set to 6-hour reports${NC}" ;;
        2) update_config "report_frequency" "daily"; echo -e "${GREEN}✓ Set to daily reports${NC}" ;;
        3) update_config "report_frequency" "off"; echo -e "${YELLOW}Reports disabled${NC}" ;;
    esac
}

config_currency() {
    echo ""
    echo -e "${WHITE}Reporting Currency Preference${NC}"
    echo -e "${DIM}Current: $(get_config_value 'report_currency' 'USD')${NC}"
    echo ""
    echo "  1) CAD 🍁    2) USD 🦅    3) EUR 🌐    4) GBP 🌐    5) JPY 🌐"
    echo "  6) AUD 🌐    7) CHF 🌐    8) CNY 🌐    9) NZD 🌐   10) SEK 🌐"
