config_power() {
    echo ""
    echo -e "${WHITE}Power Cost Settings${NC}"
    echo -e "${DIM}Current Rate: $(get_config_value 'power_rate_kwh' '0.12')/kWh${NC}"
    echo -e "${DIM}Current Currency: $(get_config_value 'power_currency' 'CAD')${NC}"
    echo ""
    echo "Change currency? (Enter to keep current)"
    echo "  1) CAD 🍁    2) USD 🦅    3) EUR 🌐    4) GBP 🌐    5) JPY 🌐"
    echo "  6) AUD 🌐    7) CHF 🌐    8) CNY 🌐    9) NZD 🌐   10) SEK 🌐"
    echo ""
    prompt_input "Select currency [1-10] (Enter to skip): "; read cur_choice

    if [[ -n "$cur_choice" ]]; then
        local -a CODES=("CAD" "USD" "EUR" "GBP" "JPY" "AUD" "CHF" "CNY" "NZD" "SEK")
        local -a SYMS=("\$" "\$" "€" "£" "¥" "\$" "Fr." "¥" "\$" "kr")
        local idx=$(( cur_choice - 1 ))
        if [[ $idx -ge 0 && $idx -lt 10 ]]; then
            update_config "power_currency" "${CODES[$idx]}"
            echo -e "${GREEN}✓ Power currency: ${CODES[$idx]}${NC}"
        fi
    fi

    echo ""
