config_nicknames() {
    echo ""
    echo -e "${WHITE}Miner Nicknames${NC}"
    echo -e "${DIM}Assign friendly names to miners in your database${NC}"
    echo ""

    # Shared location - accessible by both admin and dashboard service
    MINER_DB="/spiralpool/data/miners.json"
    local db_dir
    db_dir="$(dirname "$MINER_DB")"
    if [[ ! -d "$db_dir" ]]; then
        sudo mkdir -p "$db_dir" 2>/dev/null
        sudo chown "$POOL_USER:$POOL_USER" "$db_dir" 2>/dev/null || sudo chown "$USER:$USER" "$db_dir"
        sudo chmod 775 "$db_dir"
    fi

    # Check if miner database exists
    if [[ ! -f "$MINER_DB" ]] || ! python3 -c "import json; d=json.load(open('$MINER_DB')); exit(0 if d.get('miners') else 1)" 2>/dev/null; then
        echo -e "${YELLOW}No miners in database.${NC}"
        echo ""
        echo "To add miners, first run a network scan:"
        echo -e "  ${WHITE}spiralpool-scan${NC}"
        echo ""
        echo "Or manually add a miner:"
        echo -e "  ${WHITE}spiralpool-scan --add 192.168.1.100${NC}"
        echo ""
        prompt_input "Press Enter to continue..."; read
        return
    fi

    echo "Current miners:"
    python3 -c "
import json
try:
    with open('$MINER_DB', 'r') as f:
        db = json.load(f)
    miners = db.get('miners', {})
    if miners:
        for ip, info in sorted(miners.items()):
            nickname = info.get('nickname', '')
            mtype = info.get('type', 'unknown')
            if nickname:
                print(f'  {ip} ({mtype}) -> \"{nickname}\"')
            else:
                print(f'  {ip} ({mtype}) -> (no nickname)')
    else:
        print('  (no miners in database)')
except Exception as e:
    print(f'  Error: {e}')
"
    echo ""
    echo "Options:"
    echo "  1) Set/Update nickname for a miner"
    echo "  2) Clear nickname"
    echo "  3) Scan network for new miners"
    echo "  4) Back to main menu"
    echo ""
    prompt_input "Select: "; read choice

    case "$choice" in
        1)
            prompt_input "Miner IP address: "; read ip
            # Check if miner exists
            if ! MINER_DB="$MINER_DB" MINER_IP="$ip" python3 -c "
import json, os, sys
with open(os.environ['MINER_DB'], 'r') as f:
    db = json.load(f)
sys.exit(0 if os.environ['MINER_IP'] in db.get('miners', {}) else 1)
" 2>/dev/null; then
                echo -e "${YELLOW}Miner $ip not in database. Add it first with: spiralpool-scan --add $ip${NC}"
                return
            fi
            prompt_input "Nickname: "; read nickname
            if [[ -n "$ip" ]] && [[ -n "$nickname" ]]; then
                local tmp_nick="/tmp/miner_nick_$$_$(date +%s).json"
                MINER_DB="$MINER_DB" MINER_IP="$ip" MINER_NICK="$nickname" TMP_FILE="$tmp_nick" python3 -c "
import json, os, sys
db_file = os.environ['MINER_DB']
ip = os.environ['MINER_IP']
nickname = os.environ['MINER_NICK']
tmp_file = os.environ['TMP_FILE']
with open(db_file, 'r') as f:
    db = json.load(f)
if ip in db.get('miners', {}):
    db['miners'][ip]['nickname'] = nickname
    with open(tmp_file, 'w') as f:
        json.dump(db, f, indent=2)
else:
    sys.exit(1)
"
                if [[ -f "$tmp_nick" ]]; then
                    if ! mv -f "$tmp_nick" "$MINER_DB" 2>/dev/null; then
                        sudo mv -f "$tmp_nick" "$MINER_DB"
                    fi
                    sudo chown "$POOL_USER:$POOL_USER" "$MINER_DB" 2>/dev/null || sudo chown "$USER:$USER" "$MINER_DB"
                    sudo chmod 664 "$MINER_DB" 2>/dev/null
                    echo -e "${GREEN}✓ Set $ip -> $nickname${NC}"
                else
                    echo -e "${RED}✗ Failed to set nickname${NC}"
                fi
            fi
            ;;
        2)
            prompt_input "IP to clear nickname: "; read ip
            local tmp_clear="/tmp/miner_clear_$$_$(date +%s).json"
            MINER_DB="$MINER_DB" MINER_IP="$ip" TMP_FILE="$tmp_clear" python3 -c "
import json, os, sys
db_file = os.environ['MINER_DB']
ip = os.environ['MINER_IP']
tmp_file = os.environ['TMP_FILE']
with open(db_file, 'r') as f:
    db = json.load(f)
if ip in db.get('miners', {}):
    db['miners'][ip].pop('nickname', None)
    with open(tmp_file, 'w') as f:
        json.dump(db, f, indent=2)
else:
    sys.exit(1)
"
            if [[ -f "$tmp_clear" ]]; then
                if ! mv -f "$tmp_clear" "$MINER_DB" 2>/dev/null; then
                    sudo mv -f "$tmp_clear" "$MINER_DB"
                fi
                sudo chown "$POOL_USER:$POOL_USER" "$MINER_DB" 2>/dev/null || sudo chown "$USER:$USER" "$MINER_DB"
                sudo chmod 664 "$MINER_DB" 2>/dev/null
                echo -e "${GREEN}✓ Nickname cleared${NC}"
            else
                echo -e "${RED}✗ Failed to clear nickname (miner not found?)${NC}"
            fi
            ;;
        3)
            echo ""
            spiralpool-scan || echo -e "${YELLOW}Run: spiralpool-scan${NC}"
            ;;
    esac
}

