CONFIGEOF

    # Network miner scanner
    sudo tee /usr/local/bin/spiralpool-scan > /dev/null << 'SCANEOF'
#!/bin/bash
#
# Spiral Pool Miner Scanner - Discover mining devices on your network
#

# Colors
GREEN='\033[0;32m'
RED='\033[0;31m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
WHITE='\033[1;37m'
MAGENTA='\033[0;35m'
DIM='\033[2m'
NC='\033[0m'

# Prompt helper (styled input prompt)
prompt_input() {
    echo -ne "  ${GREEN}▸${NC} ${WHITE}${1}${NC}"
}

# Standard pool service account (matches install.sh)
POOL_USER="spiraluser"

# Shared location - accessible by both admin user running this script
# and the $POOL_USER service running dashboard/sentinel
MINER_DB="/spiralpool/data/miners.json"

# Miner detection ports
AXEOS_PORT=80       # BitAxe, NerdQAxe (HTTP API)
CGMINER_PORT=4028   # Antminer, Whatsminer, Avalon, Innosilicon

show_banner() {
    echo -e "${CYAN}"
    echo "+================================================================+"
    echo "|             SPIRAL POOL MINER SCANNER                          |"
    echo "+================================================================+"
    echo -e "${NC}"
}

show_usage() {
    echo ""
    echo -e "${WHITE}Usage:${NC}"
    echo "  spiralpool-scan                    - Scan local subnet for miners"
    echo "  spiralpool-scan 192.168.1.0/24     - Scan specific subnet"
    echo "  spiralpool-scan --add 192.168.1.50 - Manually add a miner"
    echo "  spiralpool-scan --list             - List all known miners"
    echo "  spiralpool-scan --remove 192.168.1.50 - Remove a miner"
    echo "  spiralpool-scan --nickname 192.168.1.50 'My BitAxe' - Set nickname"
    echo ""
}

get_local_subnet() {
    # Get the local subnet (e.g., 192.168.1.0/24)
    local ip=$(ip -4 addr show | grep -oP '(?<=inet\s)192\.168\.\d+\.\d+' | head -1)
    if [[ -z "$ip" ]]; then
        ip=$(ip -4 addr show | grep -oP '(?<=inet\s)10\.\d+\.\d+\.\d+' | head -1)
    fi
    if [[ -z "$ip" ]]; then
        ip=$(ip -4 addr show | grep -oP '(?<=inet\s)172\.(1[6-9]|2[0-9]|3[0-1])\.\d+\.\d+' | head -1)
    fi
    if [[ -n "$ip" ]]; then
        echo "${ip%.*}.0/24"
    else
        echo ""
    fi
}

init_database() {
    local db_dir
    db_dir="$(dirname "$MINER_DB")"

    # Create directory with sudo if needed (owned by spiraluser for dashboard access)
    # Use sudo -n (non-interactive) to avoid unexpected password prompts during scan
    if [[ ! -d "$db_dir" ]]; then
        if ! mkdir -p "$db_dir" 2>/dev/null; then
            if ! sudo -n mkdir -p "$db_dir" 2>/dev/null; then
                echo "ERROR: Failed to create miner database directory: $db_dir" >&2
                return 1
            fi
            sudo -n chown "$POOL_USER:$POOL_USER" "$db_dir" 2>/dev/null || sudo -n chown "$USER:$USER" "$db_dir" 2>/dev/null || true
            sudo -n chmod 775 "$db_dir" 2>/dev/null || true
        fi
    fi

    # Initialize database file if it doesn't exist
    if [[ ! -f "$MINER_DB" ]]; then
        local init_json='{
  "miners": {},
  "by_type": {
    "nmaxe": [],
    "nerdqaxe": [],
    "axeos": [],
    "qaxe": [],
    "qaxeplus": [],
    "luckyminer": [],
    "jingleminer": [],
    "zyber": [],
    "esp32miner": [],
    "avalon": [],
    "antminer": [],
    "antminer_scrypt": [],
    "whatsminer": [],
    "innosilicon": [],
    "goldshell": [],
    "hammer": [],
    "futurebit": [],
    "canaan": [],
    "ebang": [],
    "gekkoscience": [],
    "ipollo": [],
    "epic": [],
    "elphapex": [],
    "braiins": [],
    "vnish": [],
    "luxos": []
  },
  "last_scan": null
}'
        if ! echo "$init_json" > "$MINER_DB" 2>/dev/null; then
            if ! echo "$init_json" | sudo -n tee "$MINER_DB" > /dev/null 2>/dev/null; then
                echo "ERROR: Failed to initialize miner database" >&2
                return 1
            fi
            sudo -n chown "$POOL_USER:$POOL_USER" "$MINER_DB" 2>/dev/null || sudo -n chown "$USER:$USER" "$MINER_DB" 2>/dev/null || true
            sudo -n chmod 664 "$MINER_DB" 2>/dev/null || true
        fi
    fi
}

detect_miner_type() {
    local ip=$1
    local timeout=2

    # Try CGMiner API FIRST (port 4028) - used by Antminer, Whatsminer, Avalon, Innosilicon
    # Check this before HTTP because some CGMiner devices also respond on port 80
    # CGMiner uses JSON format: {"command":"version"}
    local cgminer_response=$(printf '{"command":"version"}' | timeout $timeout nc -w $timeout $ip $CGMINER_PORT 2>/dev/null | tr -d '\0')

    if [[ -n "$cgminer_response" ]] && echo "$cgminer_response" | grep -q "STATUS"; then
        # Valid CGMiner response - detect specific miner type
        # Canaan AvalonMiner A12/A13/A14 series (check BEFORE generic Avalon)
        if echo "$cgminer_response" | grep -qi "canaan\|AvalonMiner"; then
            echo "canaan"
            return 0
        # Avalon Nano 3 identifies as "Avalon Nano3s" or similar in version
        elif echo "$cgminer_response" | grep -qi "avalon\|Nano3"; then
            echo "avalon"
            return 0
        # FutureBit Apollo uses BFGMiner (CGMiner-compatible)
        elif echo "$cgminer_response" | grep -qi "futurebit\|apollo\|bfgminer"; then
            echo "futurebit"
            return 0
        # Antminer L-series (Scrypt) - check for L3, L7, L9, etc.
        elif echo "$cgminer_response" | grep -qiE "antminer.*(L[0-9]|scrypt)|bitmain.*L[0-9]"; then
            echo "antminer_scrypt"
            return 0
        elif echo "$cgminer_response" | grep -qi "antminer\|bitmain"; then
            echo "antminer"
            return 0
        elif echo "$cgminer_response" | grep -qi "whatsminer\|microbt"; then
            echo "whatsminer"
            return 0
        elif echo "$cgminer_response" | grep -qi "innosilicon"; then
            echo "innosilicon"
            return 0
        elif echo "$cgminer_response" | grep -qi "goldshell"; then
            echo "goldshell"
            return 0
        elif echo "$cgminer_response" | grep -qi "ebang\|ebit"; then
            echo "ebang"
            return 0
        elif echo "$cgminer_response" | grep -qi "gekkoscience\|compac\|newpac"; then
            echo "gekkoscience"
            return 0
        elif echo "$cgminer_response" | grep -qi "ipollo"; then
            echo "ipollo"
            return 0
        # NOTE: ePIC BlockMiner uses HTTP REST on port 4028, not CGMiner TCP — detected in HTTP section above
        elif echo "$cgminer_response" | grep -qi "elphapex\|DG1\|DG.Home"; then
            echo "elphapex"
            return 0
        else
            # Generic CGMiner device
            echo "avalon"
            return 0
        fi
    fi

    # Try AxeOS/BitAxe HTTP API (port 80) - only if CGMiner didn't match
    local axeos_response=$(curl -s --connect-timeout $timeout "http://${ip}/api/system/info" 2>/dev/null)
    if [[ -n "$axeos_response" ]]; then
        # Validate it's actual AxeOS JSON (must have hostname or ASICModel field)
        if echo "$axeos_response" | grep -q '"hostname"\|"ASICModel"\|"hashRate"'; then
            # Check device types in order of specificity (most specific first)
            # 1. NerdOctaxe (check FIRST - contains "axe" substring)
            if echo "$axeos_response" | grep -qi "nerdoctaxe\|nerdoctaxe\|octaxe"; then
                echo "nerdqaxe"
                return 0
            # 2. NerdQAxe/NerdAxe variants (check before "qaxe" to avoid substring match)
            elif echo "$axeos_response" | grep -qi "nerdqaxe\|nerdaxe\|nerd-qaxe\|nerd-axe"; then
                echo "nerdqaxe"
                return 0
            # 3. QAxe/QAxe+ (must NOT contain "nerd" to avoid collision)
            elif echo "$axeos_response" | grep -qi "qaxe" && ! echo "$axeos_response" | grep -qi "nerd"; then
                if echo "$axeos_response" | grep -qi "qaxe+\|qaxeplus\|qaxe-plus"; then
                    echo "qaxeplus"
                    return 0
                else
                    echo "qaxe"
                    return 0
                fi
            # 4. Lucky Miner LV06/LV07/LV08
            elif echo "$axeos_response" | grep -qi "lucky\|lv06\|lv07\|lv08"; then
                echo "luckyminer"
                return 0
            # 5. Jingle Miner BTC Solo Pro/Lite
            elif echo "$axeos_response" | grep -qi "jingle\|jingleminer\|btc.solo"; then
                echo "jingleminer"
                return 0
            # 6. Zyber TinyChipHub
            elif echo "$axeos_response" | grep -qi "zyber\|tinychip"; then
                echo "zyber"
                return 0
            # 7. Hammer/Heatbit (Scrypt miners)
            elif echo "$axeos_response" | grep -qi "hammer\|heatbit\|plebsource"; then
                echo "hammer"
                return 0
            # 8. ESP32 Miner
            elif echo "$axeos_response" | grep -qi "esp32miner\|nerd-miner\|nerd_miner"; then
                echo "esp32miner"
                return 0
            # 9. NMaxe/BitAxe (generic AxeOS family)
            elif echo "$axeos_response" | grep -qi "nmaxe\|bitaxe\|supra\|ultra\|gamma\|hex"; then
                echo "nmaxe"
                return 0
            else
                # Generic AxeOS device
                echo "axeos"
                return 0
            fi
        fi
    fi

    # Try Goldshell HTTP REST API (port 80, different endpoint than AxeOS)
    # Goldshell Mini DOGE/LT5/KD6 use /mcb/cgminer?cgminercmd=summary — NOT /api/system/info
    local goldshell_response=$(curl -s --connect-timeout $timeout "http://${ip}/mcb/cgminer?cgminercmd=summary" 2>/dev/null)
    if [[ -n "$goldshell_response" ]] && echo "$goldshell_response" | grep -q '"SUMMARY"\|"STATUS"'; then
        echo "goldshell"
        return 0
    fi

    # Try ePIC BlockMiner HTTP REST API on port 4028 (NOT CGMiner TCP — ePIC speaks HTTP)
    local epic_response=$(curl -s --connect-timeout $timeout -u root:letmein "http://${ip}:4028/summary" 2>/dev/null)
    if [[ -n "$epic_response" ]] && echo "$epic_response" | grep -qi "Mining\|BlockMiner\|ePIC"; then
        echo "epic"
        return 0
    fi

    # Try CGMiner stats as fallback (some miners only respond to stats, not version)
    local cgminer_stats=$(printf '{"command":"stats"}' | timeout $timeout nc -w $timeout $ip $CGMINER_PORT 2>/dev/null | tr -d '\0')
    if [[ -n "$cgminer_stats" ]] && echo "$cgminer_stats" | grep -q "STATUS"; then
        # Got a valid CGMiner stats response
        if echo "$cgminer_stats" | grep -qi "canaan\|AvalonMiner"; then
            echo "canaan"
            return 0
        elif echo "$cgminer_stats" | grep -qi "avalon\|Nano"; then
            echo "avalon"
            return 0
        elif echo "$cgminer_stats" | grep -qiE "antminer.*(L[0-9]|scrypt)|bitmain.*L[0-9]"; then
            echo "antminer_scrypt"
            return 0
        elif echo "$cgminer_stats" | grep -qi "antminer\|bitmain"; then
            echo "antminer"
            return 0
        elif echo "$cgminer_stats" | grep -qi "whatsminer\|microbt"; then
            echo "whatsminer"
            return 0
        elif echo "$cgminer_stats" | grep -qi "innosilicon"; then
            echo "innosilicon"
            return 0
        elif echo "$cgminer_stats" | grep -qi "goldshell"; then
            echo "goldshell"
            return 0
        elif echo "$cgminer_stats" | grep -qi "futurebit\|apollo\|bfgminer"; then
            echo "futurebit"
            return 0
        elif echo "$cgminer_stats" | grep -qi "ebang\|ebit"; then
            echo "ebang"
            return 0
        elif echo "$cgminer_stats" | grep -qi "gekkoscience\|compac\|newpac"; then
            echo "gekkoscience"
            return 0
        elif echo "$cgminer_stats" | grep -qi "ipollo"; then
            echo "ipollo"
            return 0
        # NOTE: ePIC detected in HTTP section above — does not respond to CGMiner TCP
        elif echo "$cgminer_stats" | grep -qi "elphapex\|DG1\|DG.Home"; then
            echo "elphapex"
            return 0
        else
            # Generic CGMiner device
            echo "avalon"
            return 0
        fi
    fi

    echo ""
    return 1
}

get_miner_info() {
    local ip=$1
    local mtype=$2
    local timeout=3

    case "$mtype" in
        nmaxe|nerdqaxe|axeos|hammer|qaxe|qaxeplus|luckyminer|jingleminer|zyber|esp32miner)
            # AxeOS HTTP API
            local info=$(curl -s --connect-timeout $timeout "http://${ip}/api/system/info" 2>/dev/null)
            if [[ -n "$info" ]]; then
                local hostname=$(echo "$info" | python3 -c "import sys,json; print(json.load(sys.stdin).get('hostname',''))" 2>/dev/null)
                local hashrate=$(echo "$info" | python3 -c "import sys,json; print(json.load(sys.stdin).get('hashRate',0))" 2>/dev/null)
                echo "${hostname:-Unknown}|${hashrate:-0} GH/s"
            fi
            ;;
        goldshell)
            # Goldshell HTTP API
            local info=$(curl -s --connect-timeout $timeout "http://${ip}/mcb/cgminer?cgminercmd=devs" 2>/dev/null)
            if [[ -n "$info" ]]; then
                local hashrate=$(echo "$info" | python3 -c "
import sys, json
try:
    data = json.load(sys.stdin)
    devs = data.get('data', {}).get('DEVS', [])
    total_mhs = sum(float(d.get('MHS 5s', 0)) for d in devs)
    if total_mhs > 1000:
        print(f'{total_mhs/1000:.2f} GH/s')
    else:
        print(f'{total_mhs:.2f} MH/s')
except:
    print('Active')
" 2>/dev/null)
                echo "Goldshell|${hashrate:-Active}"
            else
                echo "Goldshell|Offline"
            fi
            ;;
        epic)
            # ePIC BlockMiner uses HTTP REST on port 4028 (NOT CGMiner TCP)
            local epic_info=$(curl -s --connect-timeout $timeout -u root:letmein "http://${ip}:4028/summary" 2>/dev/null)
            if [[ -n "$epic_info" ]]; then
                local hashrate=$(echo "$epic_info" | python3 -c "
import sys, json
try:
    data = json.load(sys.stdin)
    mining = data.get('Mining', {})
    ghs = float(mining.get('Speed(GHS)', 0) or 0)
    if ghs > 1000:
        print(f'{ghs/1000:.2f} TH/s')
    else:
        print(f'{ghs:.2f} GH/s')
except:
    print('Active')
" 2>/dev/null)
                echo "ePIC BlockMiner|${hashrate:-Active}"
            else
                echo "ePIC BlockMiner|Offline"
            fi
            ;;
        antminer|whatsminer|avalon|innosilicon|antminer_scrypt|futurebit|ebang|canaan|gekkoscience|ipollo|elphapex|luxos)
            # Get summary info from CGMiner API
            local summary=$(printf '{"command":"summary"}' | timeout $timeout nc -w $timeout $ip $CGMINER_PORT 2>/dev/null | tr -d '\0')
            if [[ -n "$summary" ]]; then
                # Try to extract hashrate (MHS or GHS)
                local mhs=$(echo "$summary" | python3 -c "
import sys, json, re
try:
    data = sys.stdin.read().replace('\x00', '')
    data = re.sub(r'^[^{]*', '', data)
    idx = data.rfind('}')
    if idx >= 0:
        data = data[:idx+1]
    j = json.loads(data)
    s = j.get('SUMMARY', [{}])[0]
    ghs = s.get('GHS av', 0) or s.get('GHS 5s', 0)
    mhs = s.get('MHS av', 0) or s.get('MHS 5s', 0)
    if ghs and float(ghs) > 0:
        g = float(ghs)
        print(f'{g/1000:.2f} TH/s' if g >= 1000 else f'{g:.2f} GH/s')
    elif mhs and float(mhs) > 0:
        g = float(mhs) / 1000
        print(f'{g/1000:.2f} TH/s' if g >= 1000 else f'{g:.2f} GH/s')
    else:
        print('Active')
except:
    print('Active')
" 2>/dev/null)
                # Get version for device name
                local version=$(printf '{"command":"version"}' | timeout $timeout nc -w $timeout $ip $CGMINER_PORT 2>/dev/null | tr -d '\0')
                local device_name=$(echo "$version" | python3 -c "
import sys, json, re
try:
    data = sys.stdin.read().replace('\x00', '')
    data = re.sub(r'^[^{]*', '', data)
    idx = data.rfind('}')
    if idx >= 0:
        data = data[:idx+1]
    j = json.loads(data)
    v = j.get('VERSION', [{}])[0]
    name = v.get('Type', '') or v.get('PROD', '') or v.get('Miner', '') or v.get('MODEL', '') or v.get('CGMiner', 'CGMiner')
    print(name[:20] if name else 'CGMiner')
except:
    print('CGMiner')
" 2>/dev/null)
                echo "${device_name:-CGMiner}|${mhs:-Active}"
            else
                echo "CGMiner Device|Offline"
            fi
            ;;
    esac
}

add_miner() {
    local ip=$1
    local mtype=$2
    local nickname=$3

    init_database

    # Write to temp file first, then move with sudo if needed
    local tmp_file="/tmp/miner_add_$$_$(date +%s).json"

    # Export variables for Python (uses environment variables, not stdin)
    MINER_DB="$MINER_DB" TMP_FILE="$tmp_file" MINER_IP="$ip" MINER_TYPE="$mtype" MINER_NICKNAME="$nickname" \
    python3 << 'ADDMINER'
import json
import sys
from datetime import datetime, timezone
import os

db_file = os.environ.get('MINER_DB', '')
tmp_file = os.environ.get('TMP_FILE', '')
ip = os.environ.get('MINER_IP', '')
mtype = os.environ.get('MINER_TYPE', '')
nickname = os.environ.get('MINER_NICKNAME', '')

try:
    with open(db_file, 'r') as f:
        db = json.load(f)
except Exception as e:
    print(f"Warning: Could not read database ({e}), starting fresh", file=sys.stderr)
    db = {"miners": {}, "by_type": {"nmaxe":[],"nerdqaxe":[],"axeos":[],"qaxe":[],"qaxeplus":[],"luckyminer":[],"jingleminer":[],"zyber":[],"esp32miner":[],"avalon":[],"antminer":[],"antminer_scrypt":[],"whatsminer":[],"innosilicon":[],"goldshell":[],"hammer":[],"futurebit":[],"canaan":[],"ebang":[],"gekkoscience":[],"ipollo":[],"epic":[],"elphapex":[],"braiins":[],"vnish":[],"luxos":[]}}

# Add to miners dict
if ip not in db.get("miners", {}):
    db.setdefault("miners", {})[ip] = {}

db["miners"][ip]["type"] = mtype
db["miners"][ip]["added"] = datetime.now(timezone.utc).isoformat().replace('+00:00', 'Z')
if nickname:
    db["miners"][ip]["nickname"] = nickname

# Add to by_type list
if mtype not in db.get("by_type", {}):
    db.setdefault("by_type", {})[mtype] = []
if ip not in db["by_type"][mtype]:
    db["by_type"][mtype].append(ip)

# Write to temp file (always writable)
try:
    with open(tmp_file, 'w') as f:
        json.dump(db, f, indent=2)
except Exception as e:
    print(f"ERROR: {e}", file=sys.stderr)
    sys.exit(1)
ADDMINER

    # Move temp file to database location (use sudo if needed)
    # Use sudo -n (non-interactive) to avoid unexpected password prompts during scan
    if [[ -f "$tmp_file" ]]; then
        if ! mv -f "$tmp_file" "$MINER_DB" 2>/dev/null; then
            if ! sudo -n mv -f "$tmp_file" "$MINER_DB" 2>/dev/null; then
                echo "ERROR: Failed to save miner to database (sudo expired)" >&2
                rm -f "$tmp_file" 2>/dev/null
                return 1
            fi
        fi
        # Always fix permissions so dashboard (spiraluser) can read/write
        sudo -n chown "$POOL_USER:$POOL_USER" "$MINER_DB" 2>/dev/null || sudo -n chown "$USER:$USER" "$MINER_DB" 2>/dev/null || true
        sudo -n chmod 664 "$MINER_DB" 2>/dev/null || true
    else
        echo "ERROR: Python failed to create temp miner file" >&2
        return 1
    fi
}

remove_miner() {
    local ip=$1
    local tmp_file="/tmp/miner_remove_$$_$(date +%s).json"

    MINER_DB="$MINER_DB" tmp_file="$tmp_file" ip="$ip" python3 << 'REMOVEMINER'
import json, sys, os

db_file = os.environ["MINER_DB"]
tmp_file = os.environ["tmp_file"]
ip = os.environ["ip"]

try:
    with open(db_file, 'r') as f:
        db = json.load(f)
except:
    print("No miner database found")
    sys.exit(1)

# Remove from miners dict
if ip in db.get("miners", {}):
    del db["miners"][ip]
    print(f"Removed {ip} from miners")
else:
    print(f"{ip} not found in database")
    sys.exit(1)

# Remove from by_type lists
for mtype, ips in db.get("by_type", {}).items():
    if ip in ips:
        ips.remove(ip)

try:
    with open(tmp_file, 'w') as f:
        json.dump(db, f, indent=2)
except Exception as e:
    print(f"ERROR: {e}", file=sys.stderr)
    sys.exit(1)
REMOVEMINER

    # Move temp file to database location (use sudo if needed)
    if [[ -f "$tmp_file" ]]; then
        if ! mv -f "$tmp_file" "$MINER_DB" 2>/dev/null; then
            if ! sudo mv -f "$tmp_file" "$MINER_DB"; then
                echo "ERROR: Failed to update miner database" >&2
                rm -f "$tmp_file" 2>/dev/null
                return 1
            fi
        fi
        # Always fix permissions so dashboard (spiraluser) can read/write
        sudo chown "$POOL_USER:$POOL_USER" "$MINER_DB" 2>/dev/null || sudo chown "$USER:$USER" "$MINER_DB"
        sudo chmod 664 "$MINER_DB" 2>/dev/null
    else
        echo "ERROR: Python failed to create temp file for removal" >&2
        return 1
    fi
}

set_nickname() {
    local ip=$1
    local nickname=$2
    local tmp_file="/tmp/miner_nick_$$_$(date +%s).json"

    MINER_DB="$MINER_DB" tmp_file="$tmp_file" ip="$ip" nickname="$nickname" python3 << 'SETNICK'
import json, sys, os

db_file = os.environ["MINER_DB"]
tmp_file = os.environ["tmp_file"]
ip = os.environ["ip"]
nickname = os.environ["nickname"]

try:
    with open(db_file, 'r') as f:
        db = json.load(f)
except:
    print("No miner database found. Run spiralpool-scan first.")
    sys.exit(1)

if ip not in db.get("miners", {}):
    print(f"Miner {ip} not in database. Add it first with: spiralpool-scan --add {ip}")
    sys.exit(1)

db["miners"][ip]["nickname"] = nickname

try:
    with open(tmp_file, 'w') as f:
        json.dump(db, f, indent=2)
    print(f"Set nickname for {ip}: {nickname}")
except Exception as e:
    print(f"ERROR: {e}", file=sys.stderr)
    sys.exit(1)
SETNICK

    # Move temp file to database location (use sudo if needed)
    if [[ -f "$tmp_file" ]]; then
        if ! mv -f "$tmp_file" "$MINER_DB" 2>/dev/null; then
            if ! sudo mv -f "$tmp_file" "$MINER_DB"; then
                echo "ERROR: Failed to update nickname in database" >&2
                rm -f "$tmp_file" 2>/dev/null
                return 1
            fi
        fi
        # Always fix permissions so dashboard (spiraluser) can read/write
        sudo chown "$POOL_USER:$POOL_USER" "$MINER_DB" 2>/dev/null || sudo chown "$USER:$USER" "$MINER_DB"
        sudo chmod 664 "$MINER_DB" 2>/dev/null
    else
        echo "ERROR: Python failed to create temp file for nickname" >&2
        return 1
    fi
}

list_miners() {
    echo ""
    echo -e "${WHITE}Known Miners:${NC}"
    echo ""

    if [[ ! -f "$MINER_DB" ]]; then
        echo -e "  ${DIM}No miners configured. Run: spiralpool-scan${NC}"
        return
    fi

    MINER_DB="$MINER_DB" python3 << 'LISTMINERS'
import json
import os

db_file = os.environ.get('MINER_DB', '')
try:
    with open(db_file, 'r') as f:
        db = json.load(f)
except:
    print("  No miner database found")
    exit(0)

miners = db.get("miners", {})
if not miners:
    print("  No miners in database. Run: spiralpool-scan")
    exit(0)

type_icons = {
    "nmaxe": "⛏️ ",
    "nerdqaxe": "🎮",
    "antminer": "🔲",
    "whatsminer": "📦",
    "avalon": "🏔️ ",
    "innosilicon": "💎"
}

for ip, info in sorted(miners.items()):
    mtype = info.get("type", "unknown")
    nickname = info.get("nickname", "")
    icon = type_icons.get(mtype, "❓")

    display = f"  {icon} {ip}"
    if nickname:
        display += f" ({nickname})"
    display += f" - {mtype}"
    print(display)
LISTMINERS
    echo ""
}

scan_network() {
    local subnet=$1
    local auto_mode="${2:-}"

    if [[ -z "$subnet" ]]; then
        subnet=$(get_local_subnet)
    fi

    if [[ -z "$subnet" ]]; then
        echo -e "${RED}Could not detect local subnet. Please specify: spiralpool-scan 192.168.1.0/24${NC}"
        exit 1
    fi

    echo -e "${WHITE}Scanning:${NC} $subnet"
    echo ""

    echo -e "${WHITE}Select scan speed:${NC}"
    echo -e "  ${GREEN}1)${NC} Fast scan     ${DIM}(~1-2 min, may miss slow devices)${NC}"
    echo -e "  ${YELLOW}2)${NC} Thorough scan ${DIM}(~4-5 min, catches most devices)${NC} ${WHITE}[Recommended]${NC}"
    echo ""
    prompt_input "Choice [2]: "; read scan_choice
    scan_choice="${scan_choice:-2}"

    local SCAN_TIMEOUT=3
    case "$scan_choice" in
        1) SCAN_TIMEOUT=0.5; echo -e "${GREEN}Using fast scan (0.5s timeout)${NC}" ;;
        *) SCAN_TIMEOUT=3; echo -e "${YELLOW}Using thorough scan (3s timeout)${NC}" ;;
    esac
    echo ""

    # Cache sudo credentials before scan starts — avoids password prompts mid-scan
    sudo -v 2>/dev/null || true

    init_database

    local found=0
    local base_ip="${subnet%.*}"

    # Progress tracking
    local total=254
    local current=0

    echo -ne "  Progress: [                    ] 0%\r"

    for i in $(seq 1 254); do
        local ip="${base_ip}.$i"

        current=$((current + 1))
        local pct=$((current * 100 / total))
        local bars=$((pct / 5))
        local bar=$(printf '%*s' "$bars" | tr ' ' '=')
        local space=$(printf '%*s' "$((20 - bars))")
        echo -ne "  Progress: [${bar}${space}] ${pct}%\r"

        # Port check - run all checks in parallel for speed
        # Create temp files to track results
        local tmp_result="/tmp/scan_${ip//\./_}"
        rm -f "${tmp_result}"_* 2>/dev/null

        # Launch all port checks in parallel (user-selected timeout, run simultaneously)
        # Note: </dev/null prevents background jobs from consuming stdin (which causes hangs)
        (timeout $SCAN_TIMEOUT bash -c "echo >/dev/tcp/$ip/80" 2>/dev/null && touch "${tmp_result}_80") </dev/null &
        (timeout $SCAN_TIMEOUT bash -c "echo >/dev/tcp/$ip/4028" 2>/dev/null && touch "${tmp_result}_4028") </dev/null &
        (timeout $SCAN_TIMEOUT bash -c "echo >/dev/tcp/$ip/4029" 2>/dev/null && touch "${tmp_result}_4029") </dev/null &
        (timeout $SCAN_TIMEOUT bash -c "echo >/dev/tcp/$ip/8080" 2>/dev/null && touch "${tmp_result}_8080") </dev/null &

        # Wait for all parallel checks
        wait

        # Check results
        local has_axeos=false
        local has_cgminer=false
        local has_alt_port=false

        [[ -f "${tmp_result}_80" ]] && has_axeos=true
        [[ -f "${tmp_result}_4028" ]] && has_cgminer=true
        [[ -f "${tmp_result}_4029" ]] && has_cgminer=true
        [[ -f "${tmp_result}_8080" ]] && has_alt_port=true

        # Cleanup temp files
        rm -f "${tmp_result}"_* 2>/dev/null

        if $has_axeos || $has_cgminer || $has_alt_port; then
            # Skip IPs already in database to avoid duplicate reporting
            if python3 -c "import json; db=json.load(open('$MINER_DB')); exit(0 if '$ip' in db.get('miners',{}) else 1)" 2>/dev/null; then
                continue
            fi

            # Redirect stdin from /dev/null to prevent nc from consuming terminal input
            local mtype=""
            local info=""
            {
                mtype=$(detect_miner_type "$ip")
                if [[ -n "$mtype" ]]; then
                    info=$(get_miner_info "$ip" "$mtype")
                fi
            } < /dev/null
            if [[ -n "$mtype" ]]; then
                echo -e "\n  ${GREEN}✓${NC} Found: ${WHITE}$ip${NC} - ${CYAN}$mtype${NC} ${DIM}($info)${NC}"
                if add_miner "$ip" "$mtype" "" < /dev/null; then
                    found=$((found + 1))
                else
                    echo -e "  ${RED}✗${NC} ${DIM}Failed to save to database${NC}"
                fi
            fi
        fi
    done

    echo -e "\n"
    echo -e "${WHITE}Scan Complete!${NC}"
    echo -e "  Found: ${GREEN}$found${NC} new miners"
    echo ""

    if [[ $found -gt 0 ]]; then
        echo -e "${YELLOW}Tip:${NC} Set nicknames with: spiralpool-scan --nickname <IP> 'Friendly Name'"
        echo ""
    fi

    # Update last scan time — use sudo -n (non-interactive) to avoid unexpected password prompts
    # If sudo cache expired during a long scan, silently skip the timestamp update rather than
    # prompting the user with no context about what the password is for
    local scan_tmp="/tmp/miner_scan_ts_$$_$(date +%s).json"
    local scan_ts
    scan_ts=$(date -u +%Y-%m-%dT%H:%M:%SZ)
    python3 -c "
import json, sys
try:
    db = json.load(sys.stdin)
    db['last_scan'] = '$scan_ts'
    json.dump(db, sys.stdout, indent=2)
except Exception as e:
    print(f'Warning: Could not update scan timestamp: {e}', file=sys.stderr)
    sys.exit(1)
" < "$MINER_DB" > "$scan_tmp" 2>/dev/null
    if [[ -f "$scan_tmp" ]]; then
        if ! mv -f "$scan_tmp" "$MINER_DB" 2>/dev/null; then
            sudo -n mv -f "$scan_tmp" "$MINER_DB" 2>/dev/null || rm -f "$scan_tmp" 2>/dev/null
        fi
        sudo -n chown "$POOL_USER:$POOL_USER" "$MINER_DB" 2>/dev/null || true
        sudo -n chmod 664 "$MINER_DB" 2>/dev/null || true
    fi

    if [[ "$auto_mode" != "auto" ]]; then
        echo -e "${DIM}────────────────────────────────────────────────────────────────${NC}"
        echo ""
        echo -e "${CYAN}Note:${NC} Some ESP32-based miners may not be auto-detected due to limited"
        echo -e "      network APIs. Add them manually with:"
        echo -e "      ${WHITE}spiralpool-scan --add <IP>${NC} and select 'esp32' type"
        echo ""
        echo -e "${CYAN}Note:${NC} Scans are additive — old miners are NOT automatically removed."
        echo -e "      To remove a miner that is no longer on the network:"
        echo -e "      ${WHITE}spiralpool-scan --remove <IP>${NC}"
        echo -e "      To clear all miners and start fresh: ${WHITE}spiralpool-scan --reset${NC}"
        echo -e "${DIM}────────────────────────────────────────────────────────────────${NC}"
        echo ""
    fi

    # Ask user if they want to rescan for missed miners (skip in auto mode)
    if [[ "$auto_mode" == "auto" ]]; then
        rescan_choice="1"
    else
        echo -e "${YELLOW}Did we miss any miners?${NC}"
        echo -e "  ${GREEN}1)${NC} No, all miners found - continue"
        echo -e "  ${WHITE}2)${NC} Yes, rescan with longer timeout (catches slow/distant miners)"
        echo -e "  ${DIM}3)${NC} Skip - I'll add missing miners manually later"
        echo ""
        prompt_input "Choice [1-3] (default: 1): "; read rescan_choice
    fi

    case "${rescan_choice:-1}" in
        2)
            echo ""
            echo -e "${CYAN}Running deep scan with 3s timeout per device...${NC}"
            echo -e "${DIM}This may take 4-5 minutes but catches slow-responding miners${NC}"
            echo ""
            rescan_with_longer_timeout "$subnet" "$found"
            ;;
        3)
            echo ""
            echo -e "${DIM}Tip: Add missing miners with: spiralpool-scan --add <IP>${NC}"
            echo ""
            ;;
        *)
            echo ""
            echo -e "${GREEN}All miners detected.${NC}"
            echo ""
            ;;
    esac
}

# Deep rescan for slow-responding miners
rescan_with_longer_timeout() {
    local subnet=$1
    local prev_found=$2
    local base_ip="${subnet%.*}"
    local new_found=0
    local confirmed=0

    # Build list of already-known IPs from database for reliable checking
    # Store in a temporary file for reliable grep-based lookup
    local known_ips_file="/tmp/known_miners_$$"
    if [[ -f "$MINER_DB" ]]; then
        # Try direct read first, fall back to sudo cat if permission denied
        if python3 -c "import json; db=json.load(open('$MINER_DB')); print('\n'.join(db.get('miners',{}).keys()))" > "$known_ips_file" 2>/dev/null; then
            : # Success
        elif sudo cat "$MINER_DB" 2>/dev/null | python3 -c "import json,sys; db=json.load(sys.stdin); print('\n'.join(db.get('miners',{}).keys()))" > "$known_ips_file" 2>/dev/null; then
            : # Success with sudo
        else
            echo "" > "$known_ips_file"
        fi
    else
        echo "" > "$known_ips_file"
    fi

    # Debug: show how many known IPs we found
    local known_count=$(wc -l < "$known_ips_file" 2>/dev/null | tr -d ' ')
    [[ "$known_count" -gt 0 ]] && echo -e "  ${DIM}(Checking against $known_count known miners from fast scan)${NC}"

    # Refresh sudo credentials — may have expired during fast scan
    sudo -v 2>/dev/null || true

    echo -ne "  Deep scan: [                    ] 0%\r"

    for i in $(seq 1 254); do
        local ip="${base_ip}.$i"

        local pct=$((i * 100 / 254))
        local bars=$((pct / 5))
        local bar=$(printf '%*s' "$bars" | tr ' ' '=')
        local space=$(printf '%*s' "$((20 - bars))")
        echo -ne "  Deep scan: [${bar}${space}] ${pct}%\r"

        # Check if IP is already known (exact line match in file)
        local already_known=false
        if grep -qxF "$ip" "$known_ips_file" 2>/dev/null; then
            already_known=true
        fi

        # Deep scan: 3s timeout per port, run in parallel for speed
        local tmp_result="/tmp/deepscan_${ip//\./_}"
        rm -f "${tmp_result}"_* 2>/dev/null

        # Check all common miner ports in parallel with 3s timeout
        # Note: </dev/null prevents background jobs from consuming stdin (which causes hangs)
        for port in 80 4028 4029 8080 443; do
            (timeout 3 bash -c "echo >/dev/tcp/$ip/$port" 2>/dev/null && touch "${tmp_result}_${port}") </dev/null &
        done
        wait

        local has_port=false
        for port in 80 4028 4029 8080 443; do
            if [[ -f "${tmp_result}_${port}" ]]; then
                has_port=true
                break
            fi
        done
        rm -f "${tmp_result}"_* 2>/dev/null

        if $has_port; then
            # Redirect stdin from /dev/null to prevent nc from consuming terminal input
            local mtype=""
            local info=""
            {
                mtype=$(detect_miner_type "$ip")
                if [[ -n "$mtype" ]]; then
                    info=$(get_miner_info "$ip" "$mtype")
                fi
            } < /dev/null
            if [[ -n "$mtype" ]]; then
                if $already_known; then
                    echo -e "\n  ${DIM}✓${NC} ${DIM}Confirmed:${NC} ${WHITE}$ip${NC} - ${CYAN}$mtype${NC} ${DIM}($info)${NC}"
                    confirmed=$((confirmed + 1))
                else
                    echo -e "\n  ${GREEN}✓${NC} ${YELLOW}NEW:${NC} ${WHITE}$ip${NC} - ${CYAN}$mtype${NC} ${DIM}($info)${NC}"
                    if add_miner "$ip" "$mtype" "" < /dev/null; then
                        new_found=$((new_found + 1))
                    else
                        echo -e "  ${RED}✗${NC} ${DIM}Failed to save to database${NC}"
                    fi
                fi
            fi
        fi
    done

    # Cleanup temp file
    rm -f "$known_ips_file" 2>/dev/null

    echo -e "\n"
    if [[ $new_found -gt 0 ]]; then
        echo -e "${GREEN}Deep scan found ${new_found} additional miner(s)!${NC}"
        echo -e "Total miners: ${GREEN}$((prev_found + new_found))${NC}"
    else
        if [[ $confirmed -gt 0 ]]; then
            echo -e "${GREEN}Confirmed ${confirmed} existing miner(s) still responding.${NC}"
        fi
        echo -e "${DIM}No additional miners found.${NC}"
        echo ""
        echo -e "${WHITE}If you're still missing a miner, add it manually:${NC}"
        echo -e "  ${CYAN}spiralpool-scan --add 192.168.1.XX${NC}"
    fi
    echo ""

    # Update last scan timestamp after deep scan
    if [[ $new_found -gt 0 ]] || [[ $confirmed -gt 0 ]]; then
        local scan_tmp="/tmp/miner_deepscan_ts_$$_$(date +%s).json"
        local scan_ts
        scan_ts=$(date -u +%Y-%m-%dT%H:%M:%SZ)
        python3 -c "
import json, sys
try:
    db = json.load(sys.stdin)
    db['last_scan'] = '$scan_ts'
    json.dump(db, sys.stdout, indent=2)
except Exception as e:
    print(f'Warning: Could not update scan timestamp: {e}', file=sys.stderr)
    sys.exit(1)
" < "$MINER_DB" > "$scan_tmp" 2>/dev/null
        if [[ -f "$scan_tmp" ]]; then
            if ! mv -f "$scan_tmp" "$MINER_DB" 2>/dev/null; then
                sudo -n mv -f "$scan_tmp" "$MINER_DB" 2>/dev/null || rm -f "$scan_tmp" 2>/dev/null
            fi
            sudo -n chown "$POOL_USER:$POOL_USER" "$MINER_DB" 2>/dev/null || true
            sudo -n chmod 664 "$MINER_DB" 2>/dev/null || true
        fi
    fi
}

# Main
show_banner

case "${1:-}" in
    ""|"-h"|"--help"|"help")
        if [[ -z "$1" ]]; then
            # No args - do a scan
            scan_network ""
        else
            show_usage
        fi
        ;;
    "--auto")
        # Non-interactive mode (called from install.sh) — thorough scan, no prompts
        scan_network "" "auto"
        ;;
    "--list"|"-l"|"list")
        list_miners
        ;;
    "--add"|"-a"|"add")
        if [[ -z "$2" ]]; then
            echo -e "${RED}Please specify IP address${NC}"
            exit 1
        fi
        mtype=$(detect_miner_type "$2")
        if [[ -z "$mtype" ]]; then
            echo -e "${YELLOW}Could not auto-detect miner type. Please specify:${NC}"
            echo ""
            echo -e "  ${GREEN}AxeOS HTTP API devices:${NC}"
            echo "   1) nmaxe (BitAxe/NMaxe/AxeOS)"
            echo "   2) nerdqaxe (NerdQAxe++/NerdAxe/NerdOctaxe)"
            echo "   3) luckyminer (Lucky Miner LV06/LV07/LV08)"
            echo "   4) jingleminer (Jingle Miner BTC Solo Pro/Lite)"
            echo "   5) zyber (Zyber 8G/8GP/8S TinyChipHub)"
            echo "   6) hammer (PlebSource Hammer Miner)"
            echo "   7) esp32miner (ESP32 Miners)"
            echo ""
            echo -e "  ${GREEN}CGMiner API devices (port 4028):${NC}"
            echo "   8) antminer (Bitmain S19/S21/T21)"
            echo "   9) antminer_scrypt (Bitmain L3+/L7/L9)"
            echo "  10) whatsminer (MicroBT M30/M50/M60)"
            echo "  11) avalon (Avalon Nano 2/3/3S)"
            echo "  12) canaan (Canaan AvalonMiner A12-A16)"
            echo "  13) innosilicon (Innosilicon A10/A11/T3)"
            echo "  14) futurebit (FutureBit Apollo/Apollo II)"
            echo "  15) goldshell (Goldshell KD6/LT5/Mini DOGE)"
            echo "  16) ebang (Ebang Ebit E9-E12+)"
            echo "  17) gekkoscience (GekkoScience Compac F/NewPac/R606)"
            echo "  18) ipollo (iPollo V1/V1 Mini/G1)"
            echo "  19) epic (ePIC BlockMiner)"
            echo "  20) elphapex (Elphapex DG1/DG Home)"
            echo ""
            echo -e "  ${GREEN}Custom firmware (manual config):${NC}"
            echo "  21) braiins (BraiinsOS/BOS+ on Antminers)"
            echo "  22) vnish (Vnish firmware on Antminers)"
            echo "  23) luxos (LuxOS firmware on Antminers)"
            echo ""
            prompt_input "Select (1-23): "; read choice
            case "$choice" in
                1) mtype="nmaxe" ;;
                2) mtype="nerdqaxe" ;;
                3) mtype="luckyminer" ;;
                4) mtype="jingleminer" ;;
                5) mtype="zyber" ;;
                6) mtype="hammer" ;;
                7) mtype="esp32miner" ;;
                8) mtype="antminer" ;;
                9) mtype="antminer_scrypt" ;;
                10) mtype="whatsminer" ;;
                11) mtype="avalon" ;;
                12) mtype="canaan" ;;
                13) mtype="innosilicon" ;;
                14) mtype="futurebit" ;;
                15) mtype="goldshell" ;;
                16) mtype="ebang" ;;
                17) mtype="gekkoscience" ;;
                18) mtype="ipollo" ;;
                19) mtype="epic" ;;
                20) mtype="elphapex" ;;
                21) mtype="braiins" ;;
                22) mtype="vnish" ;;
                23) mtype="luxos" ;;
                *) echo "Invalid choice"; exit 1 ;;
            esac
        fi
        # For ESP32 miners, prompt for worker name (required for pool stats tracking)
        nickname="${3:-}"
        if [[ "$mtype" == "esp32miner" && -z "$nickname" ]]; then
            echo ""
            echo -e "${YELLOW}ESP32 miners have no HTTP API - stats come from the pool.${NC}"
            echo -e "Enter the ${WHITE}worker name${NC} this device uses when mining."
            echo -e "${DIM}(This is the name after your wallet address, e.g., ADDRESS.${WHITE}MyESP32${NC}${DIM})${NC}"
            prompt_input "Worker name: "; read nickname
            if [[ -z "$nickname" ]]; then
                echo -e "${YELLOW}Warning: Without a worker name, pool stats won't be available.${NC}"
            fi
        fi
        add_miner "$2" "$mtype" "$nickname"
        if [[ $? -eq 0 ]]; then
            echo ""
            echo -e "  ${GREEN}✓${NC} Added ${WHITE}${mtype}${NC} at ${WHITE}${2}${NC}${nickname:+ (${nickname})} to miner database"
            echo -e "  ${DIM}Sentinel will detect it on the next monitoring cycle${NC}"
        else
            echo ""
            echo -e "  ${RED}✗${NC} Failed to add miner"
        fi
        ;;
    "--remove"|"-r"|"remove")
        if [[ -z "$2" ]]; then
            echo -e "${RED}Please specify IP address${NC}"
            exit 1
        fi
        remove_miner "$2"
        ;;
    "--nickname"|"-n"|"nickname")
        if [[ -z "$2" ]] || [[ -z "$3" ]]; then
            echo -e "${RED}Usage: spiralpool-scan --nickname <IP> 'Nickname'${NC}"
            exit 1
        fi
        set_nickname "$2" "$3"
        ;;
    *)
        # Assume it's a subnet to scan
        if [[ "$1" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+(/[0-9]+)?$ ]]; then
            scan_network "$1"
        else
            echo -e "${RED}Unknown option: $1${NC}"
            show_usage
            exit 1
        fi
        ;;
esac
SCANEOF

    # Live dashboard watch command
    sudo tee /usr/local/bin/spiralpool-watch > /dev/null << 'WATCHEOF'
#!/bin/bash
#
# Spiral Pool Live Dashboard - Real-time mining monitor
# Like htop, but for your mining pool
#

# Colors
GREEN='\033[0;32m'
RED='\033[0;31m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
WHITE='\033[1;37m'
MAGENTA='\033[0;35m'
DIM='\033[2m'
NC='\033[0m'
BOLD='\033[1m'

POOL_API="http://localhost:4000"
REFRESH_INTERVAL=${1:-10}

# Cleanup on exit
cleanup() {
    tput cnorm  # Show cursor
    clear
    echo "Dashboard closed."
    exit 0
}
trap cleanup EXIT INT TERM

format_hashrate() {
    local h=$1
    # Guard against empty/non-numeric input
    if [[ -z "$h" ]] || ! echo "$h" | grep -qE '^[0-9.]+$'; then
        echo "0 H/s"
        return
    fi
    if (( $(echo "$h >= 1000000000000000" | bc -l 2>/dev/null) )); then
        echo "$(echo "scale=2; $h / 1000000000000000" | bc) PH/s"
    elif (( $(echo "$h >= 1000000000000" | bc -l 2>/dev/null) )); then
        echo "$(echo "scale=2; $h / 1000000000000" | bc) TH/s"
    elif (( $(echo "$h >= 1000000000" | bc -l 2>/dev/null) )); then
        echo "$(echo "scale=2; $h / 1000000000" | bc) GH/s"
    elif (( $(echo "$h >= 1000000" | bc -l 2>/dev/null) )); then
        echo "$(echo "scale=2; $h / 1000000" | bc) MH/s"
    else
        echo "${h} H/s"
    fi
}

format_time() {
    local secs=$1
    local days=$((secs / 86400))
    local hours=$(( (secs % 86400) / 3600 ))
    local mins=$(( (secs % 3600) / 60 ))
    if [[ $days -gt 0 ]]; then
        echo "${days}d ${hours}h ${mins}m"
    elif [[ $hours -gt 0 ]]; then
        echo "${hours}h ${mins}m"
    else
        echo "${mins}m"
    fi
}

draw_dashboard() {
    local pool_data=$(curl -s "${POOL_API}/api/pools" 2>/dev/null)

    if [[ -z "$pool_data" ]] || ! echo "$pool_data" | python3 -c "import sys,json; json.load(sys.stdin)" 2>/dev/null; then
        echo -e "${RED}Pool API not available${NC}"
        return
    fi

    # Parse ALL pools — one tab-separated line per pool
    # Format: SYMBOL\tHASHRATE\tMINERS\tBLOCKS\tEFFORT\tNET_HASH\tNET_DIFF\tHEIGHT\tREWARD\tPOOL_ID
    POOL_LINES=$(echo "$pool_data" | python3 -c "
import sys, json
try:
    # Per-algo block times in seconds (fallback for network hashrate computation)
    BT = {'DGB':75,'DGB-SCRYPT':75,'BTC':600,'BCH':600,'BC2':600,'NMC':600,
          'SYS':150,'XMY':60,'FBTC':30,'LTC':150,'DOGE':60,'PEP':60,'CAT':600}
    data = json.load(sys.stdin)
    for pool in data.get('pools', []):
        coin = pool.get('coin', {})
        symbol = coin.get('type', 'UNKNOWN').upper()
        ps = pool.get('poolStats', {})
        hashrate = ps.get('poolHashrate', 0)
        miners = ps.get('connectedMiners', 0)
        blocks = ps.get('blocksFound', 0)
        effort = ps.get('poolEffort', 0)
        net_diff = ps.get('networkDifficulty', 0)
        net_hash = ps.get('networkHashrate', 0)
        if net_hash == 0 and net_diff > 0:
            bt = BT.get(symbol, 600)
            net_hash = net_diff * (2**32) / bt if bt > 0 else 0
        height = ps.get('blockHeight', 0)
        reward = ps.get('blockReward', 0)
        pool_id = pool.get('id', '')
        print(f'{symbol}\t{hashrate}\t{miners}\t{blocks}\t{effort}\t{net_hash}\t{net_diff}\t{height}\t{reward}\t{pool_id}')
except:
    pass
" 2>/dev/null)

    if [[ -z "$POOL_LINES" ]]; then
        echo -e "${RED}No pool data available${NC}"
        return
    fi

    POOL_COUNT=$(echo "$POOL_LINES" | grep -c . || echo 0)

    # Read first pool for primary/single display
    IFS=$'\t' read -r COIN_SYM HASHRATE MINERS BLOCKS EFFORT NETWORK_HASH NETWORK_DIFF BLOCK_HEIGHT REWARD POOL_ID <<< "$(echo "$POOL_LINES" | head -1)"

    POOL_HR=$(format_hashrate "$HASHRATE")
    NET_HR=$(format_hashrate "$NETWORK_HASH")

    # Calculate pool share
    POOL_SHARE="0.0000"
    if (( $(echo "$NETWORK_HASH > 0" | bc -l 2>/dev/null) )); then
        POOL_SHARE=$(echo "scale=4; ($HASHRATE / $NETWORK_HASH) * 100" | bc 2>/dev/null || echo "0.0000")
    fi

    # Calculate estimated time to block (handle ∞ safely)
    EST_DAYS_FMT="N/A"
    if (( $(echo "$POOL_SHARE > 0" | bc -l 2>/dev/null) )); then
        EST_DAYS_RAW=$(echo "scale=1; (100 / $POOL_SHARE) * 10 / 1440" | bc 2>/dev/null)
        if [[ -n "$EST_DAYS_RAW" ]] && [[ "$EST_DAYS_RAW" != "0" ]]; then
            EST_DAYS_FMT="~${EST_DAYS_RAW} days"
        fi
    fi

    # Get service uptime
    UPTIME=""
    if systemctl is-active spiralstratum &>/dev/null; then
        UPTIME_TS=$(systemctl show spiralstratum --property=ActiveEnterTimestamp --value 2>/dev/null | xargs -I{} date -d {} +%s 2>/dev/null)
        if [[ -n "$UPTIME_TS" ]]; then
            NOW=$(date +%s)
            SECS=$((NOW - UPTIME_TS))
            UPTIME=$(format_time $SECS)
        fi
    fi

    # Clear and draw
    clear

    echo -e "${CYAN}╔══════════════════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${CYAN}║${NC}                          ${WHITE}${BOLD}SPIRAL POOL LIVE DASHBOARD${NC}                          ${CYAN}║${NC}"

    if [[ "$POOL_COUNT" -gt 1 ]]; then
        # ═══════════════════════════════════════════════════════════════════════
        # MULTI-POOL TABLE VIEW
        # ═══════════════════════════════════════════════════════════════════════
        echo -e "${CYAN}╠══════════════════════════════════════════════════════════════════════════════╣${NC}"
        echo -e "${CYAN}║${NC}  ${WHITE}COIN    HASHRATE        MINERS  BLOCKS  EFFORT    NETWORK HASH${NC}              ${CYAN}║${NC}"
        echo -e "${CYAN}╠──────────────────────────────────────────────────────────────────────────────╣${NC}"

        TOTAL_MINERS=0
        TOTAL_BLOCKS=0
        while IFS=$'\t' read -r P_SYM P_HR P_MIN P_BLK P_EFF P_NET P_DIFF P_HGT P_RWD P_PID; do
            [[ -z "$P_SYM" ]] && continue
            P_HR_FMT=$(format_hashrate "$P_HR")
            P_NET_FMT=$(format_hashrate "$P_NET")
            P_EFF_FMT=$(printf "%.1f%%" "$P_EFF" 2>/dev/null || echo "0.0%")
            TOTAL_MINERS=$((TOTAL_MINERS + P_MIN))
            TOTAL_BLOCKS=$((TOTAL_BLOCKS + P_BLK))

            # Coin emoji
            case "${P_SYM,,}" in
                dgb) P_EMO="💎" ;; btc) P_EMO="🟠" ;; bch) P_EMO="🟢" ;; bc2) P_EMO="🔵" ;;
                nmc) P_EMO="🔶" ;; sys) P_EMO="🔷" ;; xmy) P_EMO="🔴" ;; fbtc) P_EMO="🔶" ;; qbx) P_EMO="⚛️" ;;
                ltc) P_EMO="⚪" ;; doge) P_EMO="🐕" ;; pep) P_EMO="🐸" ;; cat) P_EMO="🐱" ;;
                *) P_EMO="•" ;;
            esac

            SYM_P=$(printf "%-5s" "$P_SYM")
            HR_P=$(printf "%-15s" "$P_HR_FMT")
            MIN_P=$(printf "%-7s" "$P_MIN")
            BLK_P=$(printf "%-7s" "$P_BLK")
            EFF_P=$(printf "%-9s" "$P_EFF_FMT")
            NET_P=$(printf "%-14s" "$P_NET_FMT")
            echo -e "${CYAN}║${NC}  ${P_EMO} ${GREEN}${SYM_P}${NC} ${WHITE}${HR_P}${NC} ${CYAN}${MIN_P}${NC} ${MAGENTA}${BLK_P}${NC} ${YELLOW}${EFF_P}${NC} ${DIM}${NET_P}${NC}           ${CYAN}║${NC}"
        done <<< "$POOL_LINES"

        # Totals row
        echo -e "${CYAN}╠──────────────────────────────────────────────────────────────────────────────╣${NC}"
        TOT_LABEL=$(printf "%-6s" "TOTAL")
        TOT_MIN=$(printf "%-7s" "$TOTAL_MINERS")
        TOT_BLK=$(printf "%-7s" "$TOTAL_BLOCKS")
        echo -e "${CYAN}║${NC}    ${WHITE}${TOT_LABEL}${NC} ${DIM}                ${NC} ${WHITE}${TOT_MIN}${NC} ${WHITE}${TOT_BLK}${NC}                                   ${CYAN}║${NC}"

    else
        # ═══════════════════════════════════════════════════════════════════════
        # SINGLE-POOL DETAILED VIEW
        # ═══════════════════════════════════════════════════════════════════════
        echo -e "${CYAN}╠══════════════════════════════════════════════════════════════════════════════╣${NC}"
        echo -e "${CYAN}║${NC}  ${WHITE}${COIN_SYM} POOL STATUS${NC}                    ${CYAN}│${NC}  ${WHITE}${COIN_SYM} NETWORK STATUS${NC}               ${CYAN}║${NC}"
        echo -e "${CYAN}╠══════════════════════════════════════════════════════════════════════════════╣${NC}"

        POOL_HR_PAD=$(printf "%-22s" "$POOL_HR")
        NET_HR_PAD=$(printf "%-22s" "$NET_HR")
        echo -e "${CYAN}║${NC}  ${WHITE}Hashrate:${NC}    ${GREEN}${POOL_HR_PAD}${NC} ${CYAN}│${NC}  ${WHITE}Net Hash:${NC}  ${CYAN}${NET_HR_PAD}${NC}    ${CYAN}║${NC}"

        MINERS_PAD=$(printf "%-22s" "$MINERS connected")
        BLOCK_PAD=$(printf "%-22s" "#$BLOCK_HEIGHT")
        echo -e "${CYAN}║${NC}  ${WHITE}Miners:${NC}      ${CYAN}${MINERS_PAD}${NC} ${CYAN}│${NC}  ${WHITE}Block:${NC}     ${DIM}${BLOCK_PAD}${NC}    ${CYAN}║${NC}"

        BLOCKS_PAD=$(printf "%-22s" "$BLOCKS found")
        REWARD_FMT=$(printf "%.2f" "$REWARD" 2>/dev/null || echo "0.00")
        # Strip trailing zeros after decimal: 726.00 -> 726, 3.12 -> 3.12
        REWARD_FMT=$(echo "$REWARD_FMT" | sed 's/\.00$//; s/0$//')
        REWARD_PAD=$(printf "%-22s" "${REWARD_FMT} ${COIN_SYM}")
        echo -e "${CYAN}║${NC}  ${WHITE}Blocks:${NC}      ${MAGENTA}${BLOCKS_PAD}${NC} ${CYAN}│${NC}  ${WHITE}Reward:${NC}    ${YELLOW}${REWARD_PAD}${NC}    ${CYAN}║${NC}"

        SHARE_PAD=$(printf "%-22s" "${POOL_SHARE}% of network")
        DIFF_VAL=$(printf "%.2fG" "$(echo "$NETWORK_DIFF / 1000000000" | bc -l 2>/dev/null || echo 0)")
        DIFF_PAD=$(printf "%-22s" "$DIFF_VAL")
        echo -e "${CYAN}║${NC}  ${WHITE}Share:${NC}       ${YELLOW}${SHARE_PAD}${NC} ${CYAN}│${NC}  ${WHITE}Diff:${NC}      ${DIM}${DIFF_PAD}${NC}    ${CYAN}║${NC}"
    fi

    echo -e "${CYAN}╠══════════════════════════════════════════════════════════════════════════════╣${NC}"

    # Effort bar (uses first/primary pool)
    EFFORT_INT=$(printf "%.0f" "$EFFORT" 2>/dev/null || echo 0)
    if [[ $EFFORT_INT -lt 100 ]]; then
        EFFORT_COLOR="${GREEN}"
        EFFORT_LABEL="Lucky!"
    elif [[ $EFFORT_INT -lt 200 ]]; then
        EFFORT_COLOR="${YELLOW}"
        EFFORT_LABEL="Normal"
    else
        EFFORT_COLOR="${RED}"
        EFFORT_LABEL="Unlucky"
    fi

    BAR_LEN=40
    FILL_LEN=$(( (EFFORT_INT > 300 ? 300 : EFFORT_INT) * BAR_LEN / 300 ))
    [[ $FILL_LEN -lt 1 ]] && FILL_LEN=1
    BAR=$(printf '█%.0s' $(seq 1 $FILL_LEN))
    EMPTY=$(printf '░%.0s' $(seq 1 $((BAR_LEN - FILL_LEN))))

    EFFORT_PCT=$(printf "%.1f%%" "$EFFORT" 2>/dev/null || echo "0.0%")
    EFFORT_CONTENT_LEN=$((10 + 40 + 1 + ${#EFFORT_PCT} + 2 + ${#EFFORT_LABEL} + 1))
    EFFORT_PAD_LEN=$((77 - EFFORT_CONTENT_LEN))
    [[ $EFFORT_PAD_LEN -lt 0 ]] && EFFORT_PAD_LEN=0
    EFFORT_PAD=$(printf '%*s' "$EFFORT_PAD_LEN" '')
    echo -e "${CYAN}║${NC}  ${WHITE}Effort:${NC} ${EFFORT_COLOR}${BAR}${EMPTY}${NC} ${EFFORT_COLOR}${EFFORT_PCT}${NC} ${DIM}(${EFFORT_LABEL})${NC}${EFFORT_PAD} ${CYAN}║${NC}"

    EST_CONTENT_LEN=$((22 + ${#EST_DAYS_FMT}))
    EST_PAD_LEN=$((77 - EST_CONTENT_LEN))
    [[ $EST_PAD_LEN -lt 0 ]] && EST_PAD_LEN=0
    EST_PAD=$(printf '%*s' "$EST_PAD_LEN" '')
    echo -e "${CYAN}║${NC}  ${WHITE}Est. Time to Block:${NC} ${CYAN}${EST_DAYS_FMT}${NC}${EST_PAD} ${CYAN}║${NC}"

    echo -e "${CYAN}╠══════════════════════════════════════════════════════════════════════════════╣${NC}"

    # Services status — detect all installed daemons
    echo -e "${CYAN}║${NC}  ${WHITE}SERVICES:${NC}                                                                   ${CYAN}║${NC}"

    for svc in spiralstratum digibyted bitcoind bitcoind-bch bitcoiniid litecoind dogecoind pepecoind catcoind namecoind syscoind myriadcoind fractald spiralsentinel spiraldash; do
        if systemctl is-active --quiet "$svc" 2>/dev/null; then
            STATUS_TEXT="running"
            STATUS_ICON="${GREEN}●${NC}"
        elif systemctl is-enabled --quiet "$svc" 2>/dev/null; then
            STATUS_TEXT="stopped"
            STATUS_ICON="${YELLOW}○${NC}"
        else
            continue
        fi

        case "$svc" in
            spiralstratum) NAME="Stratum Pool" ;;
            digibyted) NAME="DigiByte Node" ;;
            bitcoind) NAME="Bitcoin Node" ;;
            bitcoind-bch) NAME="BCH Node" ;;
            bitcoiniid) NAME="BC2 Node" ;;
            litecoind) NAME="Litecoin Node" ;;
            dogecoind) NAME="Dogecoin Node" ;;
            pepecoind) NAME="PepeCoin Node" ;;
            catcoind) NAME="Catcoin Node" ;;
            namecoind) NAME="Namecoin Node" ;;
            syscoind) NAME="Syscoin Node" ;;
            myriadcoind) NAME="Myriad Node" ;;
            fractald) NAME="Fractal Node" ;;
            spiralsentinel) NAME="Sentinel" ;;
            spiraldash) NAME="Dashboard" ;;
        esac
        NAME_PAD=$(printf "%-14s" "$NAME")
        STATUS_PAD=$(printf "%-57s" "$STATUS_TEXT")
        echo -e "${CYAN}║${NC}    ${NAME_PAD} ${STATUS_ICON} ${STATUS_PAD}${CYAN}║${NC}"
    done

    echo -e "${CYAN}╠══════════════════════════════════════════════════════════════════════════════╣${NC}"
    UPTIME_VAL=$(printf "%-14s" "${UPTIME:-N/A}")
    TIME_VAL=$(printf "%-8s" "$(date '+%H:%M:%S')")
    echo -e "${CYAN}║${NC}  ${DIM}Uptime: ${UPTIME_VAL}  Updated: ${TIME_VAL}  [q=quit]${NC}                         ${CYAN}║${NC}"
    echo -e "${CYAN}╚══════════════════════════════════════════════════════════════════════════════╝${NC}"
}

# Main loop
tput civis  # Hide cursor
echo -e "${CYAN}Starting Spiral Pool Live Dashboard (refresh: ${REFRESH_INTERVAL}s)...${NC}"
echo "Press 'q' to quit"
sleep 1

while true; do
    draw_dashboard

    # Non-blocking read with timeout
    read -t "$REFRESH_INTERVAL" -n 1 key 2>/dev/null
    if [[ "$key" == "q" ]] || [[ "$key" == "Q" ]]; then
        cleanup
    fi
done
WATCHEOF

    # CSV export command
    sudo tee /usr/local/bin/spiralpool-export > /dev/null << 'EXPORTEOF'
#!/bin/bash
#
# Spiral Pool CSV Exporter - Export mining history for tax/records
#

# Colors
GREEN='\033[0;32m'
RED='\033[0;31m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
WHITE='\033[1;37m'
NC='\033[0m'
DIM='\033[2m'

# Detect Sentinel data directory: check service user first (handles sudo correctly)
# Under sudo, $HOME is /root — always prefer the actual service user's directory
SENTINEL_DIR=""
SENTINEL_USER=$(systemctl show spiralsentinel --property=User --value 2>/dev/null)
SENTINEL_USER="${SENTINEL_USER:-spiraluser}"
SENTINEL_HOME=$(getent passwd "$SENTINEL_USER" 2>/dev/null | cut -d: -f6)
SENTINEL_HOME="${SENTINEL_HOME:-/home/spiraluser}"
if [[ -d "${SENTINEL_HOME}/.spiralsentinel" ]]; then
    SENTINEL_DIR="${SENTINEL_HOME}/.spiralsentinel"
elif [[ -d "/spiralpool/config/sentinel" ]]; then
    SENTINEL_DIR="/spiralpool/config/sentinel"
fi
# Final fallback
SENTINEL_DIR="${SENTINEL_DIR:-${SENTINEL_HOME}/.spiralsentinel}"
HISTORY_FILE="$SENTINEL_DIR/history.json"
STATE_FILE="$SENTINEL_DIR/state.json"
OUTPUT_DIR="$HOME"

# Detect coin symbol from pool API (fallback to generic)
COIN_SYM=$(curl -s http://localhost:4000/api/pools 2>/dev/null | python3 -c "
import sys, json
try:
    d = json.load(sys.stdin)
    print(d.get('pools',[{}])[0].get('coin',{}).get('type','COIN').upper())
except:
    print('COIN')
" 2>/dev/null || echo "COIN")

show_usage() {
    echo ""
    echo -e "${CYAN}Spiral Pool CSV Exporter${NC}"
    echo ""
    echo "Usage: spiralpool-export [output_directory] [options]"
    echo ""
    echo "Options:"
    echo "  blocks      Export blocks found history"
    echo "  earnings    Export earnings summary"
    echo "  all         Export all data (default)"
    echo ""
    echo "Examples:"
    echo "  spiralpool-export                    # Export all to home dir"
    echo "  spiralpool-export /tmp blocks        # Export blocks to /tmp"
    echo "  spiralpool-export . earnings         # Export earnings to current dir"
    echo ""
}

# Parse arguments
EXPORT_TYPE="all"
for arg in "$@"; do
    case "$arg" in
        blocks|earnings|all)
            EXPORT_TYPE="$arg"
            ;;
        -h|--help|help)
            show_usage
            exit 0
            ;;
        *)
            if [[ -d "$arg" ]]; then
                OUTPUT_DIR="$arg"
            fi
            ;;
    esac
done

# Verify data exists
if [[ ! -f "$HISTORY_FILE" ]] && [[ ! -f "$STATE_FILE" ]]; then
    echo -e "${YELLOW}No mining history found.${NC}"
    echo "History is recorded by Spiral Sentinel after blocks are found."
    echo ""
    echo "Data locations checked:"
    echo "  $HISTORY_FILE"
    echo "  $STATE_FILE"
    exit 1
fi

TIMESTAMP=$(date '+%Y%m%d_%H%M%S')

export_blocks() {
    local outfile="$OUTPUT_DIR/spiralpool_blocks_${TIMESTAMP}.csv"

    echo -e "${WHITE}Exporting blocks...${NC}"

    # Create CSV header
    echo "Block Number,Date,Time,Reward ($COIN_SYM),Finder IP,Finder Name,Effort %,Confirmation Status" > "$outfile"

    # Extract blocks from history
    python3 << PYEOF
import json
import os
from datetime import datetime

history_file = "$HISTORY_FILE"
state_file = "$STATE_FILE"
outfile = "$outfile"

blocks = []

# Try history file first
if os.path.exists(history_file):
    try:
        with open(history_file, 'r') as f:
            data = json.load(f)
            blocks.extend(data.get('blocks', []))
    except:
        pass

# Also check state file for recent blocks
if os.path.exists(state_file):
    try:
        with open(state_file, 'r') as f:
            data = json.load(f)
            for b in data.get('recent_blocks', []):
                if b not in blocks:
                    blocks.append(b)
    except:
        pass

# Sort by timestamp
blocks.sort(key=lambda x: x.get('timestamp', x.get('time', '')), reverse=True)

# Write to CSV
with open(outfile, 'a') as f:
    for block in blocks:
        block_num = block.get('height', block.get('blockNumber', 'N/A'))
        ts = block.get('timestamp', block.get('time', ''))

        # Parse timestamp
        if ts:
            try:
                if isinstance(ts, (int, float)):
                    dt = datetime.fromtimestamp(ts)
                else:
                    dt = datetime.fromisoformat(ts.replace('Z', '+00:00'))
                date_str = dt.strftime('%Y-%m-%d')
                time_str = dt.strftime('%H:%M:%S')
            except:
                date_str = str(ts)[:10]
                time_str = str(ts)[11:19] if len(str(ts)) > 11 else ''
        else:
            date_str = 'Unknown'
            time_str = ''

        reward = block.get('reward', block.get('value', 0))
        finder_ip = block.get('finder', block.get('miner', 'Unknown'))
        finder_name = block.get('finder_name', block.get('minerName', ''))
        effort = block.get('effort', 0)
        status = block.get('status', 'confirmed')

        f.write(f'{block_num},{date_str},{time_str},{reward},{finder_ip},{finder_name},{effort},{status}\n')

print(f"Exported {len(blocks)} blocks")
PYEOF

    echo -e "${GREEN}✓${NC} Blocks exported to: $outfile"
}

export_earnings() {
    local outfile="$OUTPUT_DIR/spiralpool_earnings_${TIMESTAMP}.csv"

    echo -e "${WHITE}Exporting earnings summary...${NC}"

    # Create CSV
    python3 << PYEOF
import json
import os
from datetime import datetime
from collections import defaultdict

history_file = "$HISTORY_FILE"
state_file = "$STATE_FILE"
outfile = "$outfile"

blocks = []

# Load blocks
if os.path.exists(history_file):
    try:
        with open(history_file, 'r') as f:
            blocks.extend(json.load(f).get('blocks', []))
    except:
        pass

if os.path.exists(state_file):
    try:
        with open(state_file, 'r') as f:
            for b in json.load(f).get('recent_blocks', []):
                if b not in blocks:
                    blocks.append(b)
    except:
        pass

# Group by month
coin_sym = "$COIN_SYM"
monthly = defaultdict(lambda: {'blocks': 0, 'reward': 0})

for block in blocks:
    ts = block.get('timestamp', block.get('time', ''))
    reward = float(block.get('reward', block.get('value', 0)) or 0)

    try:
        if isinstance(ts, (int, float)):
            dt = datetime.fromtimestamp(ts)
        else:
            dt = datetime.fromisoformat(str(ts).replace('Z', '+00:00'))
        month_key = dt.strftime('%Y-%m')
    except:
        month_key = 'Unknown'

    monthly[month_key]['blocks'] += 1
    monthly[month_key]['reward'] += reward

# Write CSV
with open(outfile, 'w') as f:
    f.write(f'Month,Blocks Found,Total {coin_sym},Avg Reward\n')

    total_blocks = 0
    total_reward = 0

    for month in sorted(monthly.keys(), reverse=True):
        data = monthly[month]
        avg = data['reward'] / data['blocks'] if data['blocks'] > 0 else 0
        f.write(f"{month},{data['blocks']},{data['reward']:.8f},{avg:.8f}\n")
        total_blocks += data['blocks']
        total_reward += data['reward']

    f.write(f"\nTOTAL,{total_blocks},{total_reward:.8f},\n")

print(f"Exported earnings for {len(monthly)} months")
print(f"Total: {total_blocks} blocks, {total_reward:.8f} {coin_sym}")
PYEOF

    echo -e "${GREEN}✓${NC} Earnings exported to: $outfile"
}

echo ""
echo -e "${CYAN}╔════════════════════════════════════════════════════════════════╗${NC}"
echo -e "${CYAN}║${NC}${WHITE}                    SPIRAL POOL CSV EXPORTER                    ${NC}${CYAN}║${NC}"
echo -e "${CYAN}╚════════════════════════════════════════════════════════════════╝${NC}"
echo ""

case "$EXPORT_TYPE" in
    blocks)
        export_blocks
        ;;
    earnings)
        export_earnings
        ;;
    all)
        export_blocks
        echo ""
        export_earnings
        ;;
esac

echo ""
echo -e "${DIM}Files saved to: $OUTPUT_DIR${NC}"
echo ""
EXPORTEOF

    sudo chmod +x /usr/local/bin/spiralpool-{status,logs,restart,sync,wallet,backup,restore,pause,stats,test,config,scan,watch,export}

    # Create scripts directory for additional utilities
    sudo mkdir -p /spiralpool/scripts
    sudo chown "$POOL_USER:$POOL_USER" /spiralpool/scripts 2>/dev/null || true
    sudo chmod 775 /spiralpool/scripts

    # Create data directory for miner database (used by spiralpool-scan and Sentinel)
    sudo mkdir -p /spiralpool/data
    sudo chown "$POOL_USER:$POOL_USER" /spiralpool/data 2>/dev/null || true
    sudo chmod 775 /spiralpool/data

    # Create logs directory
    sudo mkdir -p /spiralpool/logs
    sudo chown "$POOL_USER:$POOL_USER" /spiralpool/logs 2>/dev/null || true
    sudo chmod 775 /spiralpool/logs

    # Create backups directory
    sudo mkdir -p /spiralpool/backups
    sudo chown "$POOL_USER:$POOL_USER" /spiralpool/backups 2>/dev/null || true
    sudo chmod 775 /spiralpool/backups

    # Determine scripts source directory (scripts/ or scripts/linux/)
    local SCRIPTS_SRC="${SCRIPT_DIR}/scripts/linux"
    if [[ ! -d "$SCRIPTS_SRC" ]]; then
        SCRIPTS_SRC="${SCRIPT_DIR}/scripts"
    fi

    # Copy update checker script
    if [[ -f "${SCRIPTS_SRC}/update-checker.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/update-checker.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/update-checker.sh"
        sudo ln -sf "${INSTALL_DIR}/scripts/update-checker.sh" /usr/local/bin/spiralpool-update
    fi

    # Copy maintenance mode script
    if [[ -f "${SCRIPTS_SRC}/maintenance-mode.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/maintenance-mode.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/maintenance-mode.sh"
        sudo ln -sf "${INSTALL_DIR}/scripts/maintenance-mode.sh" /usr/local/bin/spiralpool-maintenance
    fi

    # Copy HA service control script (manages Sentinel/Dashboard based on HA role)
    if [[ -f "${SCRIPTS_SRC}/ha-service-control.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/ha-service-control.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/ha-service-control.sh"
        sudo ln -sf "${INSTALL_DIR}/scripts/ha-service-control.sh" /usr/local/bin/spiralpool-ha-service
    fi

    # Copy HA role watcher script (monitors role changes and triggers service control)
    if [[ -f "${SCRIPTS_SRC}/ha-role-watcher.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/ha-role-watcher.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/ha-role-watcher.sh"
    fi

    # Copy etcd quorum recovery script (automatic failover for HA clusters)
    if [[ -f "${SCRIPTS_SRC}/etcd-quorum-recover.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/etcd-quorum-recover.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/etcd-quorum-recover.sh"
        sudo ln -sf "${INSTALL_DIR}/scripts/etcd-quorum-recover.sh" /usr/local/bin/spiralpool-etcd-recover
    fi

    # Copy Patroni force bootstrap script (nuclear recovery for WAL corruption / diverged timelines)
    if [[ -f "${SCRIPTS_SRC}/patroni-force-bootstrap.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/patroni-force-bootstrap.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/patroni-force-bootstrap.sh"
        sudo ln -sf "${INSTALL_DIR}/scripts/patroni-force-bootstrap.sh" /usr/local/bin/spiralpool-patroni-bootstrap
    fi

    # Copy etcd cluster rejoin script (returning node rejoins cluster after failback)
    if [[ -f "${SCRIPTS_SRC}/etcd-cluster-rejoin.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/etcd-cluster-rejoin.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/etcd-cluster-rejoin.sh"
    fi

    # Copy HA failback orchestrator (automatic return to preferred primary)
    if [[ -f "${SCRIPTS_SRC}/ha-failback.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/ha-failback.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/ha-failback.sh"
    fi

    # Copy HA add peer script (called remotely when a new node joins the cluster)
    if [[ -f "${SCRIPTS_SRC}/ha-add-peer.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/ha-add-peer.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/ha-add-peer.sh"
    fi

    # Copy HA validation script (comprehensive HA testing)
    if [[ -f "${SCRIPTS_SRC}/ha-validate.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/ha-validate.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/ha-validate.sh"
        sudo ln -sf "${INSTALL_DIR}/scripts/ha-validate.sh" /usr/local/bin/spiralpool-ha-validate
    fi

    # Copy spiralctl control utility (in scripts/, not scripts/linux/)
    if [[ -f "${SCRIPT_DIR}/scripts/spiralctl.sh" ]]; then
        sudo cp "${SCRIPT_DIR}/scripts/spiralctl.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/spiralctl.sh"
        sudo ln -sf "${INSTALL_DIR}/scripts/spiralctl.sh" /usr/local/bin/spiralctl
        log_success "Installed spiralctl"
    fi


    # Copy pool-mode script
    if [[ -f "${SCRIPTS_SRC}/pool-mode.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/pool-mode.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/pool-mode.sh"
    fi

    # Copy block celebration script (Avalon LED flash on block found)
    if [[ -f "${SCRIPTS_SRC}/block-celebrate.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/block-celebrate.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/block-celebrate.sh"
        log_success "Installed block-celebrate.sh (Avalon LED celebration)"
    fi

    # Copy HA replication scripts
    if [[ -f "${SCRIPTS_SRC}/ha-replicate.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/ha-replicate.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/ha-replicate.sh"
        log_success "Installed ha-replicate.sh (HA cold-standby replication)"
    fi

    # Copy blockchain export/restore scripts
    if [[ -f "${SCRIPTS_SRC}/blockchain-export.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/blockchain-export.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/blockchain-export.sh"
        sudo ln -sf "${INSTALL_DIR}/scripts/blockchain-export.sh" /usr/local/bin/spiralpool-chain-export
        log_success "Installed blockchain-export.sh"
    fi

    if [[ -f "${SCRIPTS_SRC}/blockchain-restore.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/blockchain-restore.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/blockchain-restore.sh"
        sudo ln -sf "${INSTALL_DIR}/scripts/blockchain-restore.sh" /usr/local/bin/spiralpool-chain-restore
        log_success "Installed blockchain-restore.sh"
    fi

    if [[ -f "${SCRIPTS_SRC}/ha-setup-ssh.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/ha-setup-ssh.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/ha-setup-ssh.sh"
    fi

    if [[ -f "${SCRIPTS_SRC}/install-patroni.sh" ]]; then
        sudo cp "${SCRIPTS_SRC}/install-patroni.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/install-patroni.sh"
    fi

    # Copy upgrade script
    if [[ -f "${SCRIPT_DIR}/upgrade.sh" ]]; then
        sudo cp "${SCRIPT_DIR}/upgrade.sh" "${INSTALL_DIR}/"
        sudo chmod +x "${INSTALL_DIR}/upgrade.sh"
        log_success "Installed upgrade.sh"
    fi

    log_success "Helper scripts created"
}

# ═══════════════════════════════════════════════════════════════════════════════
# UPDATE CHECKER CONFIGURATION
# ═══════════════════════════════════════════════════════════════════════════════

setup_update_checker() {
    log_step "Configuring Update Checker"

    # Create config directory
    sudo mkdir -p /spiralpool/config

    # Set notification flags BEFORE writing the config file
    if [[ -n "${DISCORD_WEBHOOK:-}" ]]; then
        NOTIFY_DISCORD=true
    fi
    if [[ -n "${TELEGRAM_BOT_TOKEN:-}" ]] && [[ -n "${TELEGRAM_CHAT_ID:-}" ]]; then
        NOTIFY_TELEGRAM=true
    fi

    # Save update settings
    sudo tee /spiralpool/config/update-settings.conf > /dev/null << EOF
# Spiral Pool Update Settings
# Generated on $(date)

# Update mode: "auto", "notify", or "disabled"
UPDATE_MODE="${UPDATE_MODE:-notify}"

# Check interval: "hourly", "daily", "weekly"
CHECK_INTERVAL="daily"

# Discord notifications (reuse from Sentinel if configured)
NOTIFY_DISCORD=${NOTIFY_DISCORD:-false}
DISCORD_WEBHOOK="${DISCORD_WEBHOOK:-}"

# Telegram notifications (reuse from Sentinel if configured)
NOTIFY_TELEGRAM=${NOTIFY_TELEGRAM:-false}
TELEGRAM_BOT_TOKEN="${TELEGRAM_BOT_TOKEN:-}"
TELEGRAM_CHAT_ID="${TELEGRAM_CHAT_ID:-}"

# Last check timestamp
LAST_CHECK="$(date +%s)"

# Last notified version
LAST_NOTIFIED_VERSION=""
EOF

    # Owned by POOL_USER — update-checker.sh runs as spiraluser and needs read+write
    # (save_settings() atomically replaces this file via mv)
    sudo chmod 600 /spiralpool/config/update-settings.conf
    sudo chown "$POOL_USER:$POOL_USER" /spiralpool/config/update-settings.conf

    # Enable periodic update checking via cron (runs as POOL_USER)
    # update-checker.sh runs as spiraluser: owns /spiralpool/logs, /spiralpool/config,
    # /run/spiralpool (via tmpfiles.d). Cron entry goes to spiraluser's crontab.
    # Auto-update mode uses sudo for upgrade.sh (sudoers entry below).
    sudo -u "$POOL_USER" ${INSTALL_DIR}/scripts/update-checker.sh enable

    log_success "Update checker configured (mode: ${UPDATE_MODE:-notify})"
}

# ═══════════════════════════════════════════════════════════════════════════════
# HA BLOCKCHAIN REPLICATION
# ═══════════════════════════════════════════════════════════════════════════════

# Execute blockchain replication based on pre-collected user choices
ask_blockchain_rsync() {
    # HA Backup Mode: Automatically offer replication from primary
    local ha_primary="${HA_PRIMARY_IP:-$HA_PEER_IP}"

    # Early-deploy ha-replicate.sh so it's available for replication
    # (create_helper_scripts runs later in main(), but we need it now)
    local SCRIPTS_SRC_EARLY="${SCRIPT_DIR}/scripts/linux"
    [[ ! -d "$SCRIPTS_SRC_EARLY" ]] && SCRIPTS_SRC_EARLY="${SCRIPT_DIR}/scripts"
    if [[ -f "${SCRIPTS_SRC_EARLY}/ha-replicate.sh" ]] && [[ ! -f "${INSTALL_DIR}/scripts/ha-replicate.sh" ]]; then
        sudo mkdir -p "${INSTALL_DIR}/scripts"
        sudo cp "${SCRIPTS_SRC_EARLY}/ha-replicate.sh" "${INSTALL_DIR}/scripts/"
        sudo chmod +x "${INSTALL_DIR}/scripts/ha-replicate.sh"
    fi

    # Determine correct PostgreSQL service name (version-aware, Patroni-aware)
    local pg_service_name="postgresql@${POSTGRES_VERSION}-main"
    if [[ "$PATRONI_ENABLED" == "true" ]] && [[ "$HA_ENABLED" == "true" ]]; then
        pg_service_name="patroni"
    fi
    # Re-verify SSH if variable says not ready (same stale-checkpoint fix as copy_binaries_from_primary)
    if [[ "$HA_MODE" == "ha-backup" ]] && [[ -n "$ha_primary" ]] && [[ "$HA_SSH_READY" != "true" ]]; then
        local rsync_ssh_key="/home/${POOL_USER}/.ssh/id_ed25519"
        local rsync_ssh_known_hosts="/home/${POOL_USER}/.ssh/known_hosts"
        local rsync_ssh_opts="-o StrictHostKeyChecking=accept-new -o ConnectTimeout=10 -o BatchMode=yes"
        [[ -f "$rsync_ssh_key" ]] && rsync_ssh_opts="$rsync_ssh_opts -i $rsync_ssh_key"
        [[ -f "$rsync_ssh_known_hosts" ]] && rsync_ssh_opts="$rsync_ssh_opts -o UserKnownHostsFile=$rsync_ssh_known_hosts"
        local rsync_ssh_test=""
        if rsync_ssh_test=$(sudo -u "$POOL_USER" ssh $rsync_ssh_opts "${POOL_USER}@${ha_primary}" "echo 'SSH_OK'" 2>&1); then
            log "HA SSH connectivity verified for replication (recovering from stale HA_SSH_READY=false)"
            HA_SSH_READY=true
        else
            log_warn "SSH re-verify to primary (${ha_primary}) failed: ${rsync_ssh_test}"
        fi
    fi

    if [[ "$HA_MODE" == "ha-backup" ]] && [[ -n "$ha_primary" ]] && [[ "$HA_SSH_READY" == "true" ]]; then
        # User chose network sync instead of primary replication
        if [[ "${HA_REPLICATE_FROM_PRIMARY:-}" == "false" ]]; then
            log "Skipping blockchain replication — user chose network sync"
            return 0
        fi

        # Skip replication if primary doesn't have any of the selected coins
        # (copy_binaries_from_primary tracks this — if it never found binaries,
        # there's no blockchain data to replicate either)
        if [[ "${HA_PRIMARY_COIN_COUNT:-0}" -eq 0 ]]; then
            log "Primary node does not have any of the selected coins installed — skipping blockchain replication"
            return 0
        fi

        echo ""
        echo -e "  ${GREEN}HA Backup: Replicating blockchain data from primary (${ha_primary})${NC}"
        echo -e "  ${DIM}Blockchain daemons will be stopped during data copy and restarted after.${NC}"
        echo -e "  ${DIM}The primary node will continue running normally.${NC}"
        echo ""

        log "Starting blockchain replication from primary node (${ha_primary})..."
        log_warn "Services on this node will be temporarily stopped during sync."

        local ha_replicate_script="${INSTALL_DIR}/scripts/ha-replicate.sh"
        if [[ -f "$ha_replicate_script" ]]; then
            if sudo "$ha_replicate_script" --mode blockchain --source "$ha_primary" --execute --yes; then
                log_success "Blockchain replication from primary completed successfully!"
                echo ""
                echo -e "  ${CYAN}ℹ${NC}  ${WHITE}Wallet addresses:${NC} If the primary node has already generated"
                echo -e "     wallets, this backup will automatically reuse the same addresses."
                echo -e "     Both nodes will share identical wallet configurations."
                echo ""

                # Verify services were restarted
                log "Verifying services are running..."
                local services_ok=true
                for service in bitcoind bitcoind-bch litecoind dogecoind digibyted bitcoiniid pepecoind catcoind namecoind syscoind myriadcoind fractald $pg_service_name; do
                    if systemctl list-unit-files | grep -q "^${service}.service\|^${service}@"; then
                        if systemctl is-active --quiet "$service"; then
                            log_success "${service} is running"
                        else
                            log_warn "${service} is not running, attempting to start..."
                            sudo systemctl start "$service" 2>/dev/null || true
                            sleep 2
                            if systemctl is-active --quiet "$service"; then
                                log_success "${service} started successfully"
                            else
                                services_ok=false
                            fi
                        fi
                    fi
                done

                if [[ "$services_ok" == "true" ]]; then
                    log_success "All services are running"
                else
                    log_warn "Some services may need manual attention"
                fi
            else
                log_error "Replication failed. Check logs for details."
                log_warn "Attempting to restart any stopped services..."

                # Try to restart services
                for service in bitcoind bitcoind-bch litecoind dogecoind digibyted bitcoiniid pepecoind catcoind namecoind syscoind myriadcoind fractald $pg_service_name; do
                    if systemctl list-unit-files | grep -q "^${service}.service\|^${service}@"; then
                        sudo systemctl start "$service" 2>/dev/null || true
                    fi
                done

                log_warn "Falling back to network sync."
            fi
        else
            log_error "HA replication script not found: $ha_replicate_script"
            log_warn "Falling back to network sync."
        fi
        return 0
    fi

    # Standard mode: use pre-collected choices from configuration phase
    if [[ "$BLOCKCHAIN_SYNC_CHOICE" != "2" ]] || [[ -z "$SYNC_SOURCE_NODE" ]]; then
        log "Using network sync (P2P blockchain download)"
        return
    fi

    # User chose option 2 (copy from another node) during configuration
    local source_node="$SYNC_SOURCE_NODE"
    local ssh_username="${SYNC_SSH_USER:-$POOL_USER}"

    # Skip replication if source node didn't have any of the selected coins
    # (copy_binaries_from_primary tracks this — if it never found binaries,
    # there's no blockchain data to replicate either)
    if [[ "${HA_PRIMARY_COIN_COUNT:-0}" -eq 0 ]]; then
        log "No coins found on source node during binary copy — skipping blockchain replication"
        return
    fi

    # SSH was already set up before coin installs (main() pre-coin SSH block).
    # Only attempt SSH setup here as fallback (e.g., checkpoint resume scenario).
    if [[ "${SOURCE_SSH_READY:-}" == "true" ]]; then
        log "SSH to ${source_node} already verified — proceeding with blockchain replication"
    else
        # Test SSH connection and set up keys if needed
        echo ""
        log "Testing SSH connection to ${ssh_username}@${source_node}..."

        local ssh_dir="/home/${ssh_username}/.ssh"
        local ssh_key_path="${ssh_dir}/id_ed25519"

        if ssh -i "$ssh_key_path" -o BatchMode=yes -o ConnectTimeout=10 -o StrictHostKeyChecking=accept-new \
            -o UserKnownHostsFile="${ssh_dir}/known_hosts" "${ssh_username}@${source_node}" "echo 'SSH OK'" &>/dev/null; then
            log_success "SSH connection successful"
        else
            log_warn "SSH key not yet authorized on ${source_node}"
            echo ""
            echo -e "  ${WHITE}Automatic SSH key setup${NC}"
            echo -e "  To copy blockchain data, this node needs SSH access to the source node."
            echo -e "  Enter the password for ${CYAN}${ssh_username}@${source_node}${NC} to authorize access."
            echo ""
            echo -e "  ${DIM}(This is a one-time setup - future connections will use the SSH key)${NC}"
            echo ""

            # Ensure sshpass is installed
            if ! command -v sshpass &>/dev/null; then
                log "Installing sshpass for automated SSH key setup..."
                sudo apt-get update -qq
                sudo apt-get install -y -qq sshpass
            fi

            # Ensure SSH directory exists with correct ownership
            if [[ ! -d "$ssh_dir" ]]; then
                sudo -u "$ssh_username" mkdir -p "$ssh_dir" 2>/dev/null || mkdir -p "$ssh_dir"
            fi
            sudo chown "${ssh_username}:${ssh_username}" "$ssh_dir" 2>/dev/null || true
            chmod 700 "$ssh_dir"

            # Check if key exists
            if [[ -f "$ssh_key_path" ]]; then
                sudo chown "${ssh_username}:${ssh_username}" "$ssh_key_path" 2>/dev/null || true
                chmod 600 "$ssh_key_path"
                [[ -f "${ssh_key_path}.pub" ]] && sudo chown "${ssh_username}:${ssh_username}" "${ssh_key_path}.pub" 2>/dev/null || true && chmod 644 "${ssh_key_path}.pub"
                log "Using existing SSH key: $ssh_key_path"
            else
                log "Generating SSH key for ${ssh_username}..."
                sudo -u "$ssh_username" ssh-keygen -t ed25519 -f "$ssh_key_path" -N "" -C "spiralpool-replication" -q 2>/dev/null \
                    || ssh-keygen -t ed25519 -f "$ssh_key_path" -N "" -C "spiralpool-replication" -q
                sudo chown "${ssh_username}:${ssh_username}" "$ssh_key_path" "${ssh_key_path}.pub" 2>/dev/null || true
                log_success "SSH key generated"
            fi

            # Ask for password and copy key
            read -sp "  Password for ${ssh_username}@${source_node}: " source_password
            echo ""

            if [[ -z "$source_password" ]]; then
                log_warn "No password provided. Falling back to network sync."
                return
            fi

            echo ""
            log "Copying SSH key to ${source_node}..."

            # Copy the key using sshpass (-e reads from SSHPASS env var, avoids exposing password in process list)
            if SSHPASS="$source_password" sshpass -e ssh-copy-id \
                -o StrictHostKeyChecking=accept-new \
                -o ConnectTimeout=15 \
                -i "${ssh_key_path}.pub" \
                "${ssh_username}@${source_node}" &>/dev/null; then

                # Verify SSH access works now
                # BUG FIX (M10): Add StrictHostKeyChecking=accept-new. ssh-copy-id above
                # wrote the host key to root's known_hosts (runs as root, no sudo -u).
                # The verification here uses UserKnownHostsFile (user's known_hosts) which
                # doesn't have the key yet. Without accept-new, BatchMode rejects the unknown host.
                if ssh -i "$ssh_key_path" -o BatchMode=yes -o ConnectTimeout=10 \
                    -o StrictHostKeyChecking=accept-new \
                    -o UserKnownHostsFile="${ssh_dir}/known_hosts" "${ssh_username}@${source_node}" "echo 'SSH OK'" &>/dev/null; then
                    log_success "SSH key successfully deployed to ${source_node}"
                else
                    log_error "SSH key was copied but connection still fails"
                    log_error "Check if ${ssh_username} user exists on ${source_node}"
                    log_warn "Falling back to network sync."
                    unset source_password 2>/dev/null
                    return
                fi
            else
                log_error "Failed to copy SSH key to ${source_node}"
                log_error "Possible causes:"
                log_error "  • Incorrect password"
                log_error "  • User '${ssh_username}' doesn't exist on ${source_node}"
                log_error "  • SSH password authentication disabled on ${source_node}"
                log_error "  • Network/firewall blocking SSH"
                echo ""
                log_warn "Falling back to network sync."
                unset source_password 2>/dev/null
                return
            fi

            # Clear password from memory immediately after key deployment
            unset source_password 2>/dev/null
        fi
    fi

    # Proceed with replication (user already confirmed during configuration)
    log "Starting blockchain replication from ${source_node}..."
    log_warn "Services on this node will be temporarily stopped during sync."

    # Check if ha-replicate.sh exists
    local ha_replicate_script="${INSTALL_DIR}/scripts/ha-replicate.sh"
    if [[ -f "$ha_replicate_script" ]]; then
        # Run replication (ha-replicate.sh handles stopping/starting services)
        if sudo "$ha_replicate_script" --mode blockchain --source "$source_node" --ssh-user "$ssh_username" --execute --yes; then
            log_success "Blockchain replication completed successfully!"
            log "Blockchain data copied from ${source_node}"

            # Verify services were restarted by ha-replicate.sh
            log "Verifying blockchain services are running..."
            local services_ok=true
            # All supported blockchain daemon services
            for service in bitcoind bitcoind-bch litecoind dogecoind digibyted bitcoiniid pepecoind catcoind namecoind syscoind myriadcoind fractald; do
                if systemctl list-unit-files | grep -q "^${service}.service"; then
                    if systemctl is-active --quiet "$service"; then
                        log_success "${service} is running"
                    else
                        log_warn "${service} is not running, attempting to start..."
                        sudo systemctl start "$service" 2>/dev/null || true
                        sleep 2
                        if systemctl is-active --quiet "$service"; then
                            log_success "${service} started successfully"
                        else
                            log_error "${service} failed to start - check logs: journalctl -u ${service}"
                            services_ok=false
                        fi
                    fi
                fi
            done

            if [[ "$services_ok" == "true" ]]; then
                log_success "All blockchain services are running"
            else
                log_warn "Some services may need manual attention"
            fi
        else
            log_error "Blockchain replication failed. Check logs for details."
            log_warn "Attempting to restart any stopped services..."

            # Try to restart services that may have been stopped
            for service in bitcoind bitcoind-bch litecoind dogecoind digibyted bitcoiniid pepecoind catcoind namecoind syscoind myriadcoind fractald; do
                if systemctl list-unit-files | grep -q "^${service}.service"; then
                    sudo systemctl start "$service" 2>/dev/null || true
                fi
            done

            log_warn "Falling back to network sync."
        fi
    else
        log_error "HA replication script not found: $ha_replicate_script"
        log_warn "Falling back to network sync."
    fi
}

# ═══════════════════════════════════════════════════════════════════════════════
# AUTOMATED DATABASE BACKUP SCHEDULING
# ═══════════════════════════════════════════════════════════════════════════════

# Global flag for automated backups (default: disabled)
ENABLE_AUTO_BACKUPS=false

# Set up automated daily backups (choice was made during configuration)
ask_automated_backups() {
    if [[ "$ENABLE_AUTO_BACKUPS" == "true" ]]; then
        setup_automated_backups
    else
        log "Automated backups skipped (to enable later: spiralpool-backup --schedule enable)"
    fi
}

setup_automated_backups() {
    log_step "Setting Up Automated Database Backups"

    local BACKUP_DIR="${INSTALL_DIR}/backups"
    local BACKUP_SCRIPT="${INSTALL_DIR}/scripts/daily-backup.sh"

    # Create backup directory with secure permissions
    sudo mkdir -p "$BACKUP_DIR"
    sudo chown "$POOL_USER:$POOL_USER" "$BACKUP_DIR"
    sudo chmod 700 "$BACKUP_DIR"

    # Create daily backup script
    sudo tee "$BACKUP_SCRIPT" > /dev/null << 'DAILYBACKUPEOF'
#!/bin/bash
# ═══════════════════════════════════════════════════════════════════════════════
# SPIRAL POOL - AUTOMATED DAILY BACKUP
# ═══════════════════════════════════════════════════════════════════════════════
# This script is run automatically via cron to create daily database backups.
# Backups are stored in /spiralpool/backups/ with automatic rotation.

set -o pipefail

# Configuration
BACKUP_DIR="/spiralpool/backups"
RETENTION_DAYS=30
DB_NAME="spiralstratum"
LOG_FILE="/spiralpool/logs/backup.log"
TIMESTAMP=$(date +%Y%m%d_%H%M%S)
BACKUP_NAME="daily-${TIMESTAMP}"
BACKUP_PATH="${BACKUP_DIR}/${BACKUP_NAME}"

# Logging
log() { echo "[$(date '+%Y-%m-%d %H:%M:%S')] $1" | tee -a "$LOG_FILE"; }
log_error() { echo "[$(date '+%Y-%m-%d %H:%M:%S')] ERROR: $1" | tee -a "$LOG_FILE" >&2; }

# Ensure log directory exists
mkdir -p "$(dirname "$LOG_FILE")"

log "Starting daily backup..."

# Check PostgreSQL is running (Patroni manages PG in HA mode)
db_service="postgresql"
if systemctl is-enabled --quiet "patroni" 2>/dev/null; then
    db_service="patroni"
fi
if ! systemctl is-active --quiet "$db_service" 2>/dev/null; then
    log_error "$db_service is not running - backup failed"
    exit 1
fi

# Create backup directory
(umask 077 && mkdir -p "${BACKUP_PATH}")

# Backup database
log "Creating database dump..."
if sudo -u postgres pg_dump "$DB_NAME" > "${BACKUP_PATH}/database.sql" 2>/dev/null; then
    gzip "${BACKUP_PATH}/database.sql"
    BACKUP_SIZE=$(du -h "${BACKUP_PATH}/database.sql.gz" | cut -f1)
    log "Database backup created: ${BACKUP_SIZE}"
else
    log_error "Database backup failed!"
    rm -rf "${BACKUP_PATH}"
    exit 1
fi

# Backup config files (critical for recovery)
cp /spiralpool/config/config.yaml "${BACKUP_PATH}/" 2>/dev/null || true
log "Config files backed up"

# Create backup manifest
cat > "${BACKUP_PATH}/manifest.txt" << EOF
Spiral Pool Daily Backup
========================
Created: $(date)
Type: Scheduled daily backup
Database: ${DB_NAME}
Hostname: $(hostname)
EOF

# Set secure permissions
chmod -R 600 "${BACKUP_PATH}"/*
chmod 700 "${BACKUP_PATH}"

log "Backup complete: ${BACKUP_PATH}"

# Rotate old backups (keep last RETENTION_DAYS days)
log "Rotating old backups (keeping ${RETENTION_DAYS} days)..."
find "${BACKUP_DIR}" -maxdepth 1 -type d -name "daily-*" -mtime +${RETENTION_DAYS} -exec rm -rf {} \; 2>/dev/null

# Count remaining backups
BACKUP_COUNT=$(find "${BACKUP_DIR}" -maxdepth 1 -type d -name "daily-*" | wc -l)
log "Total backups: ${BACKUP_COUNT}"

log "Daily backup completed successfully"
DAILYBACKUPEOF

    sudo chmod +x "$BACKUP_SCRIPT"
    sudo chown root:root "$BACKUP_SCRIPT"

    # Set up cron job for daily backups at 2 AM
    # Using /etc/cron.d/ for system-level cron (more reliable than user crontab)
    sudo tee /etc/cron.d/spiralpool-backup > /dev/null << CRONEOF
# Spiral Pool - Automated Daily Database Backup
# Runs at 2:00 AM daily to minimize impact on mining operations
# Script logs to /spiralpool/logs/backup.log via tee

SHELL=/bin/bash
PATH=/usr/local/sbin:/usr/local/bin:/sbin:/bin:/usr/sbin:/usr/bin

# Daily backup at 2:00 AM (script handles its own logging via tee)
0 2 * * * root ${BACKUP_SCRIPT} > /dev/null 2>&1
CRONEOF

    sudo chmod 644 /etc/cron.d/spiralpool-backup

    # Create initial backup immediately
    log "Creating initial backup..."
    sudo "$BACKUP_SCRIPT" > /dev/null 2>&1 || true

    log_success "Automated daily backups configured"
    log "  - Backup script: ${BACKUP_SCRIPT}"
    log "  - Backup location: ${BACKUP_DIR}"
    log "  - Schedule: Daily at 2:00 AM"
    log "  - Retention: ${RETENTION_DAYS:-30} days"
}

# ═══════════════════════════════════════════════════════════════════════════════
# BLOCKCHAIN SYNC FUNCTIONS (Multi-Coin Support)
# ═══════════════════════════════════════════════════════════════════════════════

# Get CLI command and config path for a specific coin
get_coin_cli_info() {
    local coin="$1"
    case "$coin" in
        DGB|dgb|digibyte)
            echo "digibyte-cli|$(get_blockchain_dir dgb)/digibyte.conf"
            ;;
        BTC|btc|bitcoin)
            echo "bitcoin-cli|$(get_blockchain_dir btc)/bitcoin.conf"
            ;;
        BCH|bch|bitcoincash)
            echo "bitcoin-cli-bch|$(get_blockchain_dir bch)/bitcoin.conf"
            ;;
        BC2|bc2|bitcoinii)
            # Bitcoin II uses capital "II" in binary names, but we created lowercase symlinks
            echo "bitcoinii-cli|$(get_blockchain_dir bc2)/bitcoinii.conf"
            ;;
        LTC|ltc|litecoin)
            echo "litecoin-cli|$(get_blockchain_dir ltc)/litecoin.conf"
            ;;
        DOGE|doge|dogecoin)
            echo "dogecoin-cli|$(get_blockchain_dir doge)/dogecoin.conf"
            ;;
        DGB_SCRYPT|dgb_scrypt)
            # DGB-Scrypt uses the same daemon as DGB SHA-256d
            echo "digibyte-cli|$(get_blockchain_dir dgb)/digibyte.conf"
            ;;
        PEP|pep|pepecoin)
            echo "pepecoin-cli|$(get_blockchain_dir pep)/pepecoin.conf"
            ;;
        CAT|cat|catcoin)
            echo "catcoin-cli|$(get_blockchain_dir cat)/catcoin.conf"
            ;;
        NMC|nmc|namecoin)
            echo "namecoin-cli|$(get_blockchain_dir nmc)/namecoin.conf"
            ;;
        SYS|sys|syscoin)
            echo "syscoin-cli|$(get_blockchain_dir sys)/syscoin.conf"
            ;;
        XMY|xmy|myriadcoin)
            echo "myriadcoin-cli|$(get_blockchain_dir xmy)/myriadcoin.conf"
            ;;
        FBTC|fbtc|fractal)
            echo "fractal-cli|$(get_blockchain_dir fbtc)/fractal.conf"
            ;;
        QBX|qbx|qbitx)
            echo "qbitx-cli|$(get_blockchain_dir qbx)/qbitx.conf"
            ;;
        *)
            echo ""
            ;;
    esac
}

# Check if a specific coin's blockchain is synced
# Usage: check_coin_sync DGB|BTC|BCH
# Returns 0 if synced (progress >= 0.9999), 1 if still syncing
check_coin_sync() {
    local coin="${1:-DGB}"
    local cli_info=$(get_coin_cli_info "$coin")

    if [[ -z "$cli_info" ]]; then
        return 1
    fi

    local cli_cmd=$(echo "$cli_info" | cut -d'|' -f1)
    local conf_path=$(echo "$cli_info" | cut -d'|' -f2)

    local progress
    progress=$($cli_cmd -conf="$conf_path" getblockchaininfo 2>/dev/null | grep -o '"verificationprogress":[^,]*' | cut -d: -f2 | tr -d ' ')

    # Validate progress is a number
    if [[ -z "$progress" ]] || ! [[ "$progress" =~ ^[0-9.]+$ ]]; then
        return 1  # Can't get progress, assume not synced
    fi

    # Use awk for floating point comparison (more reliable than bc)
    if echo "$progress" | awk '{exit ($1 >= 0.9999) ? 0 : 1}'; then
        return 0  # Synced
    fi

    return 1  # Still syncing
}

# Get sync progress for a specific coin
# Usage: get_coin_sync_progress DGB|BTC|BCH
get_coin_sync_progress() {
    local coin="${1:-DGB}"
    local cli_info=$(get_coin_cli_info "$coin")

    if [[ -z "$cli_info" ]]; then
        echo "unknown"
        return
    fi

    local cli_cmd=$(echo "$cli_info" | cut -d'|' -f1)
    local conf_path=$(echo "$cli_info" | cut -d'|' -f2)

    local info
    info=$($cli_cmd -conf="$conf_path" getblockchaininfo 2>/dev/null)

    if [[ -z "$info" ]]; then
        echo "unknown"
        return
    fi

    local progress=$(echo "$info" | grep -o '"verificationprogress":[^,]*' | cut -d: -f2)
    local blocks=$(echo "$info" | grep -o '"blocks":[^,]*' | cut -d: -f2)
    local headers=$(echo "$info" | grep -o '"headers":[^,]*' | cut -d: -f2)

    if [[ -n "$progress" ]] && [[ "$progress" =~ ^[0-9.]+$ ]]; then
        # Convert to percentage using awk (more reliable than bc)
        local pct=$(echo "$progress" | awk '{printf "%.0f", $1 * 100}' 2>/dev/null)
        echo "${pct:-0}% (${blocks:-0}/${headers:-0} blocks)"
    else
        echo "initializing..."
    fi
}

# Legacy wrapper — checks all enabled coins (not just DGB)
# Falls back to DGB-only if ENABLE_* vars aren't set (backwards compatibility)
check_blockchain_sync() {
    # If any ENABLE_* vars are set, use the full multi-coin check
    if [[ -n "${ENABLE_DGB:-}" ]] || [[ -n "${ENABLE_BTC:-}" ]]; then
        check_all_coins_sync
    else
        check_coin_sync "DGB"
    fi
}

get_sync_progress() {
    get_coin_sync_progress "DGB"
}

# Check all enabled coins sync status
check_all_coins_sync() {
    local all_synced=true

    # SHA-256d coins
    if [[ "$ENABLE_DGB" == "true" ]]; then
        if ! check_coin_sync "DGB"; then
            all_synced=false
        fi
    fi

    if [[ "$ENABLE_BTC" == "true" ]]; then
        if ! check_coin_sync "BTC"; then
            all_synced=false
        fi
    fi

    if [[ "$ENABLE_BCH" == "true" ]]; then
        if ! check_coin_sync "BCH"; then
            all_synced=false
        fi
    fi

    if [[ "$ENABLE_BC2" == "true" ]]; then
        if ! check_coin_sync "BC2"; then
            all_synced=false
        fi
    fi

    # Scrypt coins
    if [[ "$ENABLE_LTC" == "true" ]]; then
        if ! check_coin_sync "LTC"; then
            all_synced=false
        fi
    fi

    if [[ "$ENABLE_DOGE" == "true" ]]; then
        if ! check_coin_sync "DOGE"; then
            all_synced=false
        fi
    fi

    # DGB-Scrypt uses same daemon as DGB, already checked above
    # No separate check needed

    # PepeCoin (Scrypt)
    if [[ "$ENABLE_PEP" == "true" ]]; then
        if ! check_coin_sync "PEP"; then
            all_synced=false
        fi
    fi

    # Catcoin (Scrypt)
    if [[ "$ENABLE_CAT" == "true" ]]; then
        if ! check_coin_sync "CAT"; then
            all_synced=false
        fi
    fi

    # SHA-256d AuxPoW coins (merge-mined)
    if [[ "$ENABLE_NMC" == "true" ]]; then
        if ! check_coin_sync "NMC"; then
            all_synced=false
        fi
    fi

    if [[ "$ENABLE_SYS" == "true" ]]; then
        if ! check_coin_sync "SYS"; then
            all_synced=false
        fi
    fi

    if [[ "$ENABLE_XMY" == "true" ]]; then
        if ! check_coin_sync "XMY"; then
            all_synced=false
        fi
    fi

    if [[ "$ENABLE_FBTC" == "true" ]]; then
        if ! check_coin_sync "FBTC"; then
            all_synced=false
        fi
    fi

    if [[ "$ENABLE_QBX" == "true" ]]; then
        if ! check_coin_sync "QBX"; then
            all_synced=false
        fi
    fi

    if [[ "$all_synced" == "true" ]]; then
        return 0
    fi
    return 1
}

# Display sync status for all enabled coins
show_all_coins_sync_status() {
    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo -e "${WHITE}                    BLOCKCHAIN SYNC STATUS                            ${NC}"
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
    echo ""

    # SHA-256d Coins
    local sha256d_shown=false

    if [[ "$ENABLE_DGB" == "true" ]]; then
        if [[ "$sha256d_shown" == "false" ]]; then
            echo -e "  ${YELLOW}SHA-256d:${NC}"
            sha256d_shown=true
        fi
        local dgb_progress=$(get_coin_sync_progress "DGB")
        if check_coin_sync "DGB"; then
            echo -e "    💎 ${WHITE}DigiByte:${NC}      ${GREEN}✓ Synced${NC} ($dgb_progress)"
        else
            echo -e "    💎 ${WHITE}DigiByte:${NC}      ${YELLOW}⏳ Syncing${NC} - $dgb_progress"
        fi
    fi

    if [[ "$ENABLE_BTC" == "true" ]]; then
        if [[ "$sha256d_shown" == "false" ]]; then
            echo -e "  ${YELLOW}SHA-256d:${NC}"
            sha256d_shown=true
        fi
        local btc_progress=$(get_coin_sync_progress "BTC")
        if check_coin_sync "BTC"; then
            echo -e "    🟠 ${WHITE}Bitcoin:${NC}       ${GREEN}✓ Synced${NC} ($btc_progress)"
        else
            echo -e "    🟠 ${WHITE}Bitcoin:${NC}       ${YELLOW}⏳ Syncing${NC} - $btc_progress"
        fi
    fi

    if [[ "$ENABLE_BCH" == "true" ]]; then
        if [[ "$sha256d_shown" == "false" ]]; then
            echo -e "  ${YELLOW}SHA-256d:${NC}"
            sha256d_shown=true
        fi
        local bch_progress=$(get_coin_sync_progress "BCH")
        if check_coin_sync "BCH"; then
            echo -e "    🟢 ${WHITE}Bitcoin Cash:${NC}  ${GREEN}✓ Synced${NC} ($bch_progress)"
        else
            echo -e "    🟢 ${WHITE}Bitcoin Cash:${NC}  ${YELLOW}⏳ Syncing${NC} - $bch_progress"
        fi
    fi

    if [[ "$ENABLE_BC2" == "true" ]]; then
        if [[ "$sha256d_shown" == "false" ]]; then
            echo -e "  ${YELLOW}SHA-256d:${NC}"
            sha256d_shown=true
        fi
        local bc2_progress=$(get_coin_sync_progress "BC2")
        if check_coin_sync "BC2"; then
            echo -e "    🔷 ${WHITE}Bitcoin II:${NC}    ${GREEN}✓ Synced${NC} ($bc2_progress)"
        else
            echo -e "    🔷 ${WHITE}Bitcoin II:${NC}    ${YELLOW}⏳ Syncing${NC} - $bc2_progress"
        fi
    fi

    # SHA-256d AuxPoW coins (merge-mined with Bitcoin)
    if [[ "$ENABLE_NMC" == "true" ]]; then
        if [[ "$sha256d_shown" == "false" ]]; then
            echo -e "  ${YELLOW}SHA-256d:${NC}"
            sha256d_shown=true
        fi
        local nmc_progress=$(get_coin_sync_progress "NMC")
        if check_coin_sync "NMC"; then
            echo -e "    🔵 ${WHITE}Namecoin:${NC}      ${GREEN}✓ Synced${NC} ($nmc_progress)"
        else
            echo -e "    🔵 ${WHITE}Namecoin:${NC}      ${YELLOW}⏳ Syncing${NC} - $nmc_progress"
        fi
    fi

    if [[ "$ENABLE_SYS" == "true" ]]; then
        if [[ "$sha256d_shown" == "false" ]]; then
            echo -e "  ${YELLOW}SHA-256d:${NC}"
            sha256d_shown=true
        fi
        local sys_progress=$(get_coin_sync_progress "SYS")
        if check_coin_sync "SYS"; then
            echo -e "    🟣 ${WHITE}Syscoin:${NC}       ${GREEN}✓ Synced${NC} ($sys_progress)"
        else
            echo -e "    🟣 ${WHITE}Syscoin:${NC}       ${YELLOW}⏳ Syncing${NC} - $sys_progress"
        fi
    fi

    if [[ "$ENABLE_XMY" == "true" ]]; then
        if [[ "$sha256d_shown" == "false" ]]; then
            echo -e "  ${YELLOW}SHA-256d:${NC}"
            sha256d_shown=true
        fi
        local xmy_progress=$(get_coin_sync_progress "XMY")
        if check_coin_sync "XMY"; then
            echo -e "    🟤 ${WHITE}Myriadcoin:${NC}    ${GREEN}✓ Synced${NC} ($xmy_progress)"
        else
            echo -e "    🟤 ${WHITE}Myriadcoin:${NC}    ${YELLOW}⏳ Syncing${NC} - $xmy_progress"
        fi
    fi

    if [[ "$ENABLE_FBTC" == "true" ]]; then
        if [[ "$sha256d_shown" == "false" ]]; then
            echo -e "  ${YELLOW}SHA-256d:${NC}"
            sha256d_shown=true
        fi
        local fbtc_progress=$(get_coin_sync_progress "FBTC")
        if check_coin_sync "FBTC"; then
            echo -e "    🟡 ${WHITE}Fractal BTC:${NC}   ${GREEN}✓ Synced${NC} ($fbtc_progress)"
        else
            echo -e "    🟡 ${WHITE}Fractal BTC:${NC}   ${YELLOW}⏳ Syncing${NC} - $fbtc_progress"
        fi
    fi

    if [[ "$ENABLE_QBX" == "true" ]]; then
        if [[ "$sha256d_shown" == "false" ]]; then
            echo -e "  ${YELLOW}SHA-256d:${NC}"
            sha256d_shown=true
        fi
        local qbx_progress=$(get_coin_sync_progress "QBX")
        if check_coin_sync "QBX"; then
            echo -e "    ⚛️ ${WHITE}Q-BitX:${NC}        ${GREEN}✓ Synced${NC} ($qbx_progress)"
        else
            echo -e "    ⚛️ ${WHITE}Q-BitX:${NC}        ${YELLOW}⏳ Syncing${NC} - $qbx_progress"
        fi
    fi

    # Scrypt Coins
    local scrypt_shown=false

    if [[ "$ENABLE_LTC" == "true" ]]; then
        if [[ "$scrypt_shown" == "false" ]]; then
            echo ""
            echo -e "  ${YELLOW}Scrypt:${NC}"
            scrypt_shown=true
        fi
        local ltc_progress=$(get_coin_sync_progress "LTC")
        if check_coin_sync "LTC"; then
            echo -e "    🪙 ${WHITE}Litecoin:${NC}      ${GREEN}✓ Synced${NC} ($ltc_progress)"
        else
            echo -e "    🪙 ${WHITE}Litecoin:${NC}      ${YELLOW}⏳ Syncing${NC} - $ltc_progress"
        fi
    fi

    if [[ "$ENABLE_DOGE" == "true" ]]; then
        if [[ "$scrypt_shown" == "false" ]]; then
            echo ""
            echo -e "  ${YELLOW}Scrypt:${NC}"
            scrypt_shown=true
        fi
        local doge_progress=$(get_coin_sync_progress "DOGE")
        if check_coin_sync "DOGE"; then
            echo -e "    🐕 ${WHITE}Dogecoin:${NC}      ${GREEN}✓ Synced${NC} ($doge_progress)"
        else
            echo -e "    🐕 ${WHITE}Dogecoin:${NC}      ${YELLOW}⏳ Syncing${NC} - $doge_progress"
        fi
    fi

    if [[ "$ENABLE_PEP" == "true" ]]; then
        if [[ "$scrypt_shown" == "false" ]]; then
            echo ""
            echo -e "  ${YELLOW}Scrypt:${NC}"
            scrypt_shown=true
        fi
        local pep_progress=$(get_coin_sync_progress "PEP")
        if check_coin_sync "PEP"; then
            echo -e "    🐸 ${WHITE}PepeCoin:${NC}      ${GREEN}✓ Synced${NC} ($pep_progress)"
        else
            echo -e "    🐸 ${WHITE}PepeCoin:${NC}      ${YELLOW}⏳ Syncing${NC} - $pep_progress"
        fi
    fi

    if [[ "$ENABLE_CAT" == "true" ]]; then
        if [[ "$scrypt_shown" == "false" ]]; then
            echo ""
            echo -e "  ${YELLOW}Scrypt:${NC}"
            scrypt_shown=true
        fi
        local cat_progress=$(get_coin_sync_progress "CAT")
        if check_coin_sync "CAT"; then
            echo -e "    🐱 ${WHITE}Catcoin:${NC}       ${GREEN}✓ Synced${NC} ($cat_progress)"
        else
            echo -e "    🐱 ${WHITE}Catcoin:${NC}       ${YELLOW}⏳ Syncing${NC} - $cat_progress"
        fi
    fi

    if [[ "$ENABLE_DGB_SCRYPT" == "true" ]]; then
        if [[ "$scrypt_shown" == "false" ]]; then
            echo ""
            echo -e "  ${YELLOW}Scrypt:${NC}"
            scrypt_shown=true
        fi
        # DGB-Scrypt uses the same daemon as DGB
        local dgb_scrypt_progress=$(get_coin_sync_progress "DGB")
        if check_coin_sync "DGB"; then
            echo -e "    💎 ${WHITE}DGB-Scrypt:${NC}    ${GREEN}✓ Synced${NC} ($dgb_scrypt_progress)"
        else
            echo -e "    💎 ${WHITE}DGB-Scrypt:${NC}    ${YELLOW}⏳ Syncing${NC} - $dgb_scrypt_progress"
        fi
    fi

    echo ""
    echo -e "${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${NC}"
}

create_sync_monitor() {
    # Create a multi-coin sync monitor script
    sudo tee "$INSTALL_DIR/bin/sync-monitor.sh" > /dev/null << 'SYNCEOF'
#!/bin/bash
#
# Spiral Pool Multi-Coin Blockchain Sync Monitor
# Waits for ALL enabled blockchains to sync before enabling the stratum pool
#

INSTALL_DIR="/spiralpool"
LOG_FILE="$INSTALL_DIR/logs/sync-monitor.log"
CHECK_INTERVAL=60

# Read enabled coins and multi-disk config
# SECURITY: Use safe parsing instead of source to prevent code injection
CONFIG_FILE="$INSTALL_DIR/config/coins.env"
MULTI_DISK_CONFIGURED="false"; CHAIN_MOUNT_POINT=""
if [[ -f "$CONFIG_FILE" ]] && [[ ! -L "$CONFIG_FILE" ]]; then
    MULTI_DISK_CONFIGURED=$(grep -oP '^MULTI_DISK_CONFIGURED=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "false")
    CHAIN_MOUNT_POINT=$(grep -oP '^CHAIN_MOUNT_POINT=\K\S+$' "$CONFIG_FILE" 2>/dev/null || echo "")
    # Only extract known boolean variables using grep
    # SHA-256d coins
    ENABLE_DGB=$(grep -oP '^ENABLE_DGB=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    ENABLE_BTC=$(grep -oP '^ENABLE_BTC=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    ENABLE_BCH=$(grep -oP '^ENABLE_BCH=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    ENABLE_BC2=$(grep -oP '^ENABLE_BC2=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    # SHA-256d AuxPoW coins (merge-mineable with Bitcoin)
    ENABLE_NMC=$(grep -oP '^ENABLE_NMC=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    ENABLE_SYS=$(grep -oP '^ENABLE_SYS=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    ENABLE_XMY=$(grep -oP '^ENABLE_XMY=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    ENABLE_FBTC=$(grep -oP '^ENABLE_FBTC=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    ENABLE_QBX=$(grep -oP '^ENABLE_QBX=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    # Scrypt coins
    ENABLE_LTC=$(grep -oP '^ENABLE_LTC=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    ENABLE_DOGE=$(grep -oP '^ENABLE_DOGE=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    ENABLE_DGB_SCRYPT=$(grep -oP '^ENABLE_DGB_SCRYPT=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    ENABLE_PEP=$(grep -oP '^ENABLE_PEP=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
    ENABLE_CAT=$(grep -oP '^ENABLE_CAT=\K(true|false)$' "$CONFIG_FILE" 2>/dev/null || echo "")
fi

# Default to false - coins must be explicitly enabled in config
ENABLE_DGB="${ENABLE_DGB:-false}"
ENABLE_BTC="${ENABLE_BTC:-false}"
ENABLE_BCH="${ENABLE_BCH:-false}"
ENABLE_BC2="${ENABLE_BC2:-false}"
# SHA-256d AuxPoW coins
ENABLE_NMC="${ENABLE_NMC:-false}"
ENABLE_SYS="${ENABLE_SYS:-false}"
ENABLE_XMY="${ENABLE_XMY:-false}"
ENABLE_FBTC="${ENABLE_FBTC:-false}"
ENABLE_QBX="${ENABLE_QBX:-false}"
# Scrypt coins
ENABLE_LTC="${ENABLE_LTC:-false}"
ENABLE_DOGE="${ENABLE_DOGE:-false}"
ENABLE_DGB_SCRYPT="${ENABLE_DGB_SCRYPT:-false}"
ENABLE_PEP="${ENABLE_PEP:-false}"
ENABLE_CAT="${ENABLE_CAT:-false}"

log() { echo "[$(date '+%Y-%m-%d %H:%M:%S')] $1" | tee -a "$LOG_FILE"; }
get_blockchain_dir() { local c="$1"; if [[ "$MULTI_DISK_CONFIGURED" == "true" && -n "$CHAIN_MOUNT_POINT" && -d "$CHAIN_MOUNT_POINT" ]]; then echo "$CHAIN_MOUNT_POINT/$c"; else echo "$INSTALL_DIR/$c"; fi; }

# Get CLI command for a coin
get_cli_cmd() {
    local coin="$1"
    case "$coin" in
        # SHA-256d coins
        DGB) echo "digibyte-cli -conf=$(get_blockchain_dir dgb)/digibyte.conf" ;;
        BTC) echo "bitcoin-cli -conf=$(get_blockchain_dir btc)/bitcoin.conf" ;;
        BCH) echo "bitcoin-cli-bch -conf=$(get_blockchain_dir bch)/bitcoin.conf" ;;
        BC2) echo "bitcoinii-cli -conf=$(get_blockchain_dir bc2)/bitcoinii.conf" ;;
        # SHA-256d AuxPoW coins (merge-mineable with Bitcoin)
        NMC) echo "namecoin-cli -conf=$(get_blockchain_dir nmc)/namecoin.conf" ;;
        SYS) echo "syscoin-cli -conf=$(get_blockchain_dir sys)/syscoin.conf" ;;
        XMY) echo "myriadcoin-cli -conf=$(get_blockchain_dir xmy)/myriadcoin.conf" ;;
        FBTC) echo "fractal-cli -conf=$(get_blockchain_dir fbtc)/fractal.conf" ;;
        QBX) echo "qbitx-cli -conf=$(get_blockchain_dir qbx)/qbitx.conf" ;;
        # Scrypt coins
        LTC) echo "litecoin-cli -conf=$(get_blockchain_dir ltc)/litecoin.conf" ;;
        DOGE) echo "dogecoin-cli -conf=$(get_blockchain_dir doge)/dogecoin.conf" ;;
        PEP) echo "pepecoin-cli -conf=$(get_blockchain_dir pep)/pepecoin.conf" ;;
        CAT) echo "catcoin-cli -conf=$(get_blockchain_dir cat)/catcoin.conf" ;;
        DGB_SCRYPT) echo "digibyte-cli -conf=$(get_blockchain_dir dgb)/digibyte.conf" ;;
    esac
}

# Get coin display name
get_coin_name() {
    local coin="$1"
    case "$coin" in
        DGB) echo "DigiByte" ;;
        BTC) echo "Bitcoin" ;;
        BCH) echo "Bitcoin Cash" ;;
        BC2) echo "Bitcoin II" ;;
        # SHA-256d AuxPoW coins
        NMC) echo "Namecoin" ;;
        SYS) echo "Syscoin" ;;
        XMY) echo "Myriad" ;;
        FBTC) echo "Fractal Bitcoin" ;;
        # Scrypt coins
        LTC) echo "Litecoin" ;;
        DOGE) echo "Dogecoin" ;;
        PEP) echo "PepeCoin" ;;
        CAT) echo "Catcoin" ;;
        DGB_SCRYPT) echo "DGB-Scrypt" ;;
    esac
}

# Check if a specific coin is synced
is_coin_synced() {
    local coin="$1"
    local cli_cmd=$(get_cli_cmd "$coin")
    local info progress ibd

    info=$($cli_cmd getblockchaininfo 2>/dev/null)
    [[ -z "$info" ]] && return 1

    # Primary check: initialblockdownload=false is authoritative (works for BC2 and all chains)
    ibd=$(echo "$info" | grep -o '"initialblockdownload":[^,]*' | cut -d: -f2 | tr -d ' ')
    [[ "$ibd" == "false" ]] && return 0

    # Fallback: verificationprogress >= 0.9999 for older daemons
    progress=$(echo "$info" | grep -o '"verificationprogress":[^,]*' | cut -d: -f2)
    [[ -z "$progress" ]] && return 1
    echo "$progress" | awk '{exit ($1 >= 0.9999) ? 0 : 1}'
}

# Get sync progress for a coin
get_coin_progress() {
    local coin="$1"
    local cli_cmd=$(get_cli_cmd "$coin")
    local info=$($cli_cmd getblockchaininfo 2>/dev/null)
    local progress=$(echo "$info" | grep -o '"verificationprogress":[^,]*' | cut -d: -f2)
    local blocks=$(echo "$info" | grep -o '"blocks":[^,]*' | cut -d: -f2)
    local headers=$(echo "$info" | grep -o '"headers":[^,]*' | cut -d: -f2)

    if [[ -n "$progress" ]] && [[ -n "$headers" ]] && [[ "$headers" != "0" ]]; then
        local pct=$(echo "$progress" | awk '{printf "%.2f", $1 * 100}')
        echo "$pct% ($blocks/$headers blocks)"
    else
        echo "waiting for peers..."
    fi
}

# Check if all enabled coins are synced
all_synced() {
    # SHA-256d coins
    if [[ "$ENABLE_DGB" == "true" ]] && ! is_coin_synced "DGB"; then return 1; fi
    if [[ "$ENABLE_BTC" == "true" ]] && ! is_coin_synced "BTC"; then return 1; fi
    if [[ "$ENABLE_BCH" == "true" ]] && ! is_coin_synced "BCH"; then return 1; fi
    if [[ "$ENABLE_BC2" == "true" ]] && ! is_coin_synced "BC2"; then return 1; fi
    # SHA-256d AuxPoW coins (merge-mineable with Bitcoin)
    if [[ "$ENABLE_NMC" == "true" ]] && ! is_coin_synced "NMC"; then return 1; fi
    if [[ "$ENABLE_SYS" == "true" ]] && ! is_coin_synced "SYS"; then return 1; fi
    if [[ "$ENABLE_XMY" == "true" ]] && ! is_coin_synced "XMY"; then return 1; fi
    if [[ "$ENABLE_FBTC" == "true" ]] && ! is_coin_synced "FBTC"; then return 1; fi
    if [[ "$ENABLE_QBX" == "true" ]] && ! is_coin_synced "QBX"; then return 1; fi
    # Scrypt coins
    if [[ "$ENABLE_LTC" == "true" ]] && ! is_coin_synced "LTC"; then return 1; fi
    if [[ "$ENABLE_DOGE" == "true" ]] && ! is_coin_synced "DOGE"; then return 1; fi
    if [[ "$ENABLE_PEP" == "true" ]] && ! is_coin_synced "PEP"; then return 1; fi
    if [[ "$ENABLE_CAT" == "true" ]] && ! is_coin_synced "CAT"; then return 1; fi
    # DGB_SCRYPT uses same daemon as DGB, already checked
    return 0
}

# Wait for a daemon to be responsive
wait_for_daemon() {
    local coin="$1"
    local cli_cmd=$(get_cli_cmd "$coin")
    local name=$(get_coin_name "$coin")
    local wait_count=0

    while ! $cli_cmd getblockchaininfo &>/dev/null; do
        if [[ $wait_count -ge 60 ]]; then
            log "WARNING: $name daemon not responding after 5 minutes"
            wait_count=0
        fi
        sleep 5
        wait_count=$((wait_count + 1))
    done
    log "$name daemon is responsive"
}

log "================================================"
log "Spiral Pool Multi-Coin Sync Monitor Started"
log "================================================"

# List enabled coins
enabled_coins=""
# SHA-256d
[[ "$ENABLE_DGB" == "true" ]] && enabled_coins="${enabled_coins}DGB "
[[ "$ENABLE_BTC" == "true" ]] && enabled_coins="${enabled_coins}BTC "
[[ "$ENABLE_BCH" == "true" ]] && enabled_coins="${enabled_coins}BCH "
[[ "$ENABLE_BC2" == "true" ]] && enabled_coins="${enabled_coins}BC2 "
[[ "$ENABLE_NMC" == "true" ]] && enabled_coins="${enabled_coins}NMC "
[[ "$ENABLE_SYS" == "true" ]] && enabled_coins="${enabled_coins}SYS "
[[ "$ENABLE_XMY" == "true" ]] && enabled_coins="${enabled_coins}XMY "
[[ "$ENABLE_FBTC" == "true" ]] && enabled_coins="${enabled_coins}FBTC "
[[ "$ENABLE_QBX" == "true" ]] && enabled_coins="${enabled_coins}QBX "
# Scrypt
[[ "$ENABLE_LTC" == "true" ]] && enabled_coins="${enabled_coins}LTC "
[[ "$ENABLE_DOGE" == "true" ]] && enabled_coins="${enabled_coins}DOGE "
[[ "$ENABLE_DGB_SCRYPT" == "true" ]] && enabled_coins="${enabled_coins}DGB_SCRYPT "
[[ "$ENABLE_PEP" == "true" ]] && enabled_coins="${enabled_coins}PEP "
[[ "$ENABLE_CAT" == "true" ]] && enabled_coins="${enabled_coins}CAT "
log "Enabled coins: $enabled_coins"

# Wait for all enabled daemons to be responsive
# SHA-256d
[[ "$ENABLE_DGB" == "true" ]] && wait_for_daemon "DGB"
[[ "$ENABLE_BTC" == "true" ]] && wait_for_daemon "BTC"
[[ "$ENABLE_BCH" == "true" ]] && wait_for_daemon "BCH"
[[ "$ENABLE_BC2" == "true" ]] && wait_for_daemon "BC2"
[[ "$ENABLE_NMC" == "true" ]] && wait_for_daemon "NMC"
[[ "$ENABLE_SYS" == "true" ]] && wait_for_daemon "SYS"
[[ "$ENABLE_XMY" == "true" ]] && wait_for_daemon "XMY"
[[ "$ENABLE_FBTC" == "true" ]] && wait_for_daemon "FBTC"
[[ "$ENABLE_QBX" == "true" ]] && wait_for_daemon "QBX"
# Scrypt
[[ "$ENABLE_LTC" == "true" ]] && wait_for_daemon "LTC"
[[ "$ENABLE_DOGE" == "true" ]] && wait_for_daemon "DOGE"
[[ "$ENABLE_PEP" == "true" ]] && wait_for_daemon "PEP"
[[ "$ENABLE_CAT" == "true" ]] && wait_for_daemon "CAT"
# DGB_SCRYPT uses same daemon as DGB, already waited

log "All daemons responsive, monitoring sync progress..."

# Track last progress for each coin to avoid log spam
declare -A LAST_PROGRESS

# Monitor sync progress for all coins (alphabetically ordered)
while ! all_synced; do
    # Log progress for each coin (SHA-256d and Scrypt)
    for coin in BC2 BCH BTC CAT DGB DGB_SCRYPT DOGE FBTC LTC NMC PEP QBX SYS XMY; do
        case "$coin" in
            BC2) [[ "$ENABLE_BC2" != "true" ]] && continue ;;
            BCH) [[ "$ENABLE_BCH" != "true" ]] && continue ;;
            BTC) [[ "$ENABLE_BTC" != "true" ]] && continue ;;
            CAT) [[ "$ENABLE_CAT" != "true" ]] && continue ;;
            DGB) [[ "$ENABLE_DGB" != "true" ]] && continue ;;
            DGB_SCRYPT) [[ "$ENABLE_DGB_SCRYPT" != "true" ]] && continue ;;
            DOGE) [[ "$ENABLE_DOGE" != "true" ]] && continue ;;
            FBTC) [[ "$ENABLE_FBTC" != "true" ]] && continue ;;
            LTC) [[ "$ENABLE_LTC" != "true" ]] && continue ;;
            NMC) [[ "$ENABLE_NMC" != "true" ]] && continue ;;
            QBX) [[ "$ENABLE_QBX" != "true" ]] && continue ;;
            SYS) [[ "$ENABLE_SYS" != "true" ]] && continue ;;
            XMY) [[ "$ENABLE_XMY" != "true" ]] && continue ;;
            PEP) [[ "$ENABLE_PEP" != "true" ]] && continue ;;
        esac

        current=$(get_coin_progress "$coin")
        if [[ "$current" != "${LAST_PROGRESS[$coin]}" ]]; then
            name=$(get_coin_name "$coin")
            if is_coin_synced "$coin"; then
                log "$name: SYNCED"
            else
                log "$name: $current"
            fi
            LAST_PROGRESS[$coin]="$current"
        fi
    done

    sleep $CHECK_INTERVAL
done

log "================================================"
log "ALL BLOCKCHAINS SYNC COMPLETE!"
log "================================================"

# ═══════════════════════════════════════════════════════════════════════
# AUTO-GENERATE WALLETS IF ANY COIN HAS PENDING_GENERATION
# This ensures wallets are created even when user isn't watching
# ═══════════════════════════════════════════════════════════════════════
CONFIG_YAML="$INSTALL_DIR/config/config.yaml"
if [[ -f "$CONFIG_YAML" ]] && grep -q "PENDING_GENERATION" "$CONFIG_YAML" 2>/dev/null; then
    log "Detected PENDING_GENERATION addresses - generating wallets..."

    # Detect the pool user for running wallet generation
    POOL_USER="${POOL_USER:-}"
    for svc in spiralstratum digibyted bitcoind bitcoind-bch bitcoiniid litecoind dogecoind pepecoind catcoind namecoind syscoind myriadcoind fractald; do
        if [[ -f "/etc/systemd/system/${svc}.service" ]]; then
            POOL_USER=$(grep -oP '^User=\K[a-z_][a-z0-9_-]*' "/etc/systemd/system/${svc}.service" 2>/dev/null | head -1)
            [[ -n "$POOL_USER" ]] && [[ "$POOL_USER" != "root" ]] && break
            POOL_USER=""
        fi
    done
    # Fallback to spiraluser if detection failed
    [[ -z "$POOL_USER" ]] && POOL_USER="spiraluser"

    # Parse config.yaml to find coins needing wallet generation
    WALLETS_TO_GENERATE=()
    current_coin=""
    while IFS= read -r line; do
        # Multi-coin format: symbol: "DGB"
        if [[ "$line" =~ symbol:[[:space:]]*\"?([A-Za-z0-9-]+)\"? ]]; then
            current_coin="${BASH_REMATCH[1]}"
        # Single-coin format: coin: "digibyte"
        elif [[ "$line" =~ ^[[:space:]]*coin:[[:space:]]*\"?([A-Za-z0-9-]+)\"? ]]; then
            coin_type="${BASH_REMATCH[1]}"
            case "$coin_type" in
                digibyte) current_coin="DGB" ;;
                bitcoin) current_coin="BTC" ;;
                bitcoincash) current_coin="BCH" ;;
                bitcoinii) current_coin="BC2" ;;
                namecoin) current_coin="NMC" ;;
                syscoin) current_coin="SYS" ;;
                myriadcoin) current_coin="XMY" ;;
                fractalbitcoin|fractal) current_coin="FBTC" ;;
                litecoin) current_coin="LTC" ;;
                dogecoin) current_coin="DOGE" ;;
                pepecoin) current_coin="PEP" ;;
                catcoin) current_coin="CAT" ;;
                digibyte-scrypt) current_coin="DGB-SCRYPT" ;;
                *) current_coin="$coin_type" ;;
            esac
        elif [[ "$line" =~ address:[[:space:]]*\"?PENDING_GENERATION\"? ]] && [[ -n "$current_coin" ]]; then
            WALLETS_TO_GENERATE+=("$current_coin")
            current_coin=""
        fi
    done < "$CONFIG_YAML"

    for wallet_coin in "${WALLETS_TO_GENERATE[@]}"; do
        coin_lower="${wallet_coin,,}"
        # Normalize coin name for spiralpool-wallet CLI
        case "$coin_lower" in
            dgb|digibyte) coin_lower="dgb" ;;
            btc|bitcoin) coin_lower="btc" ;;
            bch|bitcoincash) coin_lower="bch" ;;
            bc2|bitcoinii|bitcoin2) coin_lower="bc2" ;;
            nmc|namecoin) coin_lower="nmc" ;;
            sys|syscoin) coin_lower="sys" ;;
            xmy|myriadcoin) coin_lower="xmy" ;;
            fbtc|fractalbitcoin|fractal) coin_lower="fbtc" ;;
            qbx|qbitx) coin_lower="qbx" ;;
            ltc|litecoin) coin_lower="ltc" ;;
            doge|dogecoin) coin_lower="doge" ;;
            pep|pepecoin) coin_lower="pep" ;;
            cat|catcoin) coin_lower="cat" ;;
            dgb-scrypt|digibyte-scrypt) coin_lower="dgb" ;;
        esac

        log "Generating ${wallet_coin} wallet..."
        pending_before=$(grep -c "PENDING_GENERATION" "$CONFIG_YAML" 2>/dev/null || echo 0)
        # Run as pool user if detected, otherwise as current user
        if [[ -n "$POOL_USER" ]]; then
            sudo -u "$POOL_USER" spiralpool-wallet --coin "$coin_lower" --auto 2>&1 | tee -a "$LOG_FILE" || true
        else
            spiralpool-wallet --coin "$coin_lower" --auto 2>&1 | tee -a "$LOG_FILE" || true
        fi

        # Verify this specific coin's wallet was generated (count decreased)
        pending_after=$(grep -c "PENDING_GENERATION" "$CONFIG_YAML" 2>/dev/null || echo 0)
        if [[ "$pending_after" -ge "$pending_before" ]]; then
            log "WARNING: ${wallet_coin} wallet generation failed."
            log ""
            log "  To set the ${wallet_coin} address manually:"
            log ""
            log "  1. Generate a ${wallet_coin} address using the official wallet software"
            log "     (download from the coin's website) or a hardware wallet (Ledger, Trezor)."
            log "     You MUST use a wallet where you control the private keys."
            log ""
            log "     WARNING: Do NOT use exchange addresses (Binance, Coinbase, Kraken, etc.)"
            log "     Exchange deposits often require a memo, tag, or note to credit your"
            log "     account. Pool payouts CANNOT include memos/tags. Funds sent to exchange"
            log "     addresses without proper identification may be permanently LOST."
            log ""
            log "  2. Run this command (replace YOUR_ADDRESS with your actual address):"
            log ""
            log "     sudo sed -i '/symbol:.*\"${wallet_coin}\"/,/address:/{s|address:.*|address: \"YOUR_ADDRESS\"|}' /spiralpool/config/config.yaml"
            log ""
            log "  3. Restart all pool services:"
            log ""
            log "     sudo systemctl restart spiralstratum spiralsentinel spiraldash spiralpool-health"
            log ""
            log "  If running HA: repeat steps 2-3 on all peer nodes, or copy the updated"
            log "  config.yaml to each peer and restart services on each node."
            log ""
            log "  Or run wallet setup interactively: spiralpool-wallet --coin ${wallet_coin,,}"
        else
            log "${wallet_coin} wallet generated successfully"
        fi
    done
else
    log "No pending wallet generation needed"
fi

# Enable and start the stratum pool
log "Enabling Spiral Stratum pool..."
systemctl enable spiralstratum
systemctl restart spiralstratum

if systemctl is-active --quiet spiralstratum; then
    log "Spiral Stratum is now ONLINE and ready for miners!"
else
    log "WARNING: Failed to start Spiral Stratum - check logs"
fi

log "Sync monitor completed successfully"
SYNCEOF

    sudo chmod +x "$INSTALL_DIR/bin/sync-monitor.sh"
    sudo chown "$POOL_USER:$POOL_USER" "$INSTALL_DIR/bin/sync-monitor.sh"

    # Save enabled coins config for sync monitor to read
    sudo tee "$INSTALL_DIR/config/coins.env" > /dev/null << EOF
# Enabled coins configuration (auto-generated by installer)
COIN_MODE=$COIN_MODE
# Multi-disk storage configuration
MULTI_DISK_CONFIGURED=$MULTI_DISK_CONFIGURED
CHAIN_MOUNT_POINT=$CHAIN_MOUNT_POINT
# SHA-256d coins
ENABLE_DGB=$ENABLE_DGB
ENABLE_BTC=$ENABLE_BTC
ENABLE_BCH=$ENABLE_BCH
ENABLE_BC2=$ENABLE_BC2
# Scrypt coins
ENABLE_LTC=$ENABLE_LTC
ENABLE_DOGE=$ENABLE_DOGE
ENABLE_PEP=$ENABLE_PEP
ENABLE_CAT=$ENABLE_CAT
ENABLE_DGB_SCRYPT=$ENABLE_DGB_SCRYPT
# Aux chain coins (merge mining)
ENABLE_NMC=$ENABLE_NMC
ENABLE_SYS=$ENABLE_SYS
ENABLE_XMY=$ENABLE_XMY
ENABLE_FBTC=$ENABLE_FBTC
ENABLE_QBX=$ENABLE_QBX
QBX_RPC_PASSWORD=$QBX_RPC_PASSWORD
QBX_POOL_ADDRESS=$QBX_POOL_ADDRESS
# Stratum ports (single-coin mode uses these, multi-coin uses predefined per-coin ports)
STRATUM_PORT=$STRATUM_PORT
STRATUM_V2_PORT=$STRATUM_V2_PORT
# Enhanced Stratum (V2) — enables encrypted binary protocol + TLS for V1
ENABLE_V2_STRATUM=true
EOF
    sudo chown "$POOL_USER:$POOL_USER" "$INSTALL_DIR/config/coins.env"

    # Create systemd service for sync monitor with dependencies on enabled nodes
    local after_deps="network.target"
    local requires_deps=""

    # SHA-256d coin services
    [[ "$ENABLE_DGB" == "true" ]] && after_deps="$after_deps digibyted.service" && requires_deps="digibyted.service"
    [[ "$ENABLE_BTC" == "true" ]] && after_deps="$after_deps bitcoind.service" && requires_deps="$requires_deps bitcoind.service"
    [[ "$ENABLE_BCH" == "true" ]] && after_deps="$after_deps bitcoind-bch.service" && requires_deps="$requires_deps bitcoind-bch.service"
    [[ "$ENABLE_BC2" == "true" ]] && after_deps="$after_deps bitcoiniid.service" && requires_deps="$requires_deps bitcoiniid.service"
    # Scrypt coin services
    [[ "$ENABLE_LTC" == "true" ]] && after_deps="$after_deps litecoind.service" && requires_deps="$requires_deps litecoind.service"
    [[ "$ENABLE_DOGE" == "true" ]] && after_deps="$after_deps dogecoind.service" && requires_deps="$requires_deps dogecoind.service"
    [[ "$ENABLE_PEP" == "true" ]] && after_deps="$after_deps pepecoind.service" && requires_deps="$requires_deps pepecoind.service"
    [[ "$ENABLE_CAT" == "true" ]] && after_deps="$after_deps catcoind.service" && requires_deps="$requires_deps catcoind.service"
    # Aux chain services (merge mining)
    [[ "$ENABLE_NMC" == "true" ]] && after_deps="$after_deps namecoind.service" && requires_deps="$requires_deps namecoind.service"
    [[ "$ENABLE_SYS" == "true" ]] && after_deps="$after_deps syscoind.service" && requires_deps="$requires_deps syscoind.service"
    [[ "$ENABLE_XMY" == "true" ]] && after_deps="$after_deps myriadcoind.service" && requires_deps="$requires_deps myriadcoind.service"
    [[ "$ENABLE_FBTC" == "true" ]] && after_deps="$after_deps fractald.service" && requires_deps="$requires_deps fractald.service"
    [[ "$ENABLE_QBX" == "true" ]] && after_deps="$after_deps qbitxd.service" && requires_deps="$requires_deps qbitxd.service"
    # DGB_SCRYPT uses same daemon as DGB, already added above

    sudo tee /etc/systemd/system/spiralpool-sync.service > /dev/null << EOF
[Unit]
Description=Spiral Pool Multi-Coin Blockchain Sync Monitor
After=$after_deps
Requires=$requires_deps

[Service]
Type=oneshot
User=root
ExecStart=$INSTALL_DIR/bin/sync-monitor.sh
RemainAfterExit=yes
TimeoutStartSec=infinity

[Install]
WantedBy=multi-user.target
EOF

    sudo systemctl daemon-reload || true
    log_success "Multi-coin sync monitor created"
}

# ═══════════════════════════════════════════════════════════════════════════════
# START SERVICES
# ═══════════════════════════════════════════════════════════════════════════════

start_services() {
    log_step "Starting Services"

    # Helper to safely start a service
    start_service_if_exists() {
        local svc="$1"
        if [[ -f "/etc/systemd/system/${svc}.service" ]]; then
            if systemctl is-enabled --quiet "$svc" 2>/dev/null; then
                log "Starting $svc..."
                sudo systemctl start "$svc" || log_warn "Failed to start $svc"
            else
                log "$svc is not enabled, skipping..."
            fi
        fi
    }

    # Helper to wait for a daemon to be responsive
    wait_for_daemon() {
        local coin="$1"
        local cli_info=$(get_coin_cli_info "$coin")
        local cli_cmd=$(echo "$cli_info" | cut -d'|' -f1)
        local conf_path=$(echo "$cli_info" | cut -d'|' -f2)
        local wait_count=0

        while ! $cli_cmd -conf="$conf_path" getblockchaininfo &>/dev/null; do
            sleep 2
            wait_count=$((wait_count + 1))
            if [[ $wait_count -ge 30 ]]; then
                log_warn "Daemon will start in background, this is normal behaviour."
                break
            fi
        done
    }

    # Start enabled blockchain daemons
    # SHA-256d coins
    if [[ "$ENABLE_DGB" == "true" ]]; then
        log "Starting DigiByte Core..."
        sudo systemctl start digibyted || log_warn "Failed to start digibyted"
        sleep 3
        wait_for_daemon "DGB"
    fi

    if [[ "$ENABLE_BTC" == "true" ]]; then
        log "Starting Bitcoin Knots..."
        sudo systemctl start bitcoind || log_warn "Failed to start bitcoind"
        sleep 3
        wait_for_daemon "BTC"
    fi

    if [[ "$ENABLE_BCH" == "true" ]]; then
        log "Starting Bitcoin Cash Node..."
        sudo systemctl start bitcoind-bch || log_warn "Failed to start bitcoind-bch"
        sleep 3
        wait_for_daemon "BCH"
    fi

    if [[ "$ENABLE_BC2" == "true" ]]; then
        log "Starting Bitcoin II Core..."
        sudo systemctl start bitcoiniid || log_warn "Failed to start bitcoiniid"
        sleep 3
        wait_for_daemon "BC2"
    fi

    # Scrypt coins
    if [[ "$ENABLE_LTC" == "true" ]]; then
        log "Starting Litecoin Core..."
        sudo systemctl start litecoind || log_warn "Failed to start litecoind"
        sleep 3
        wait_for_daemon "LTC"
    fi

    if [[ "$ENABLE_DOGE" == "true" ]]; then
        log "Starting Dogecoin Core..."
        sudo systemctl start dogecoind || log_warn "Failed to start dogecoind"
        sleep 3
        wait_for_daemon "DOGE"
    fi

    if [[ "$ENABLE_PEP" == "true" ]]; then
        log "Starting PepeCoin Core..."
        sudo systemctl start pepecoind || log_warn "Failed to start pepecoind"
        sleep 3
        wait_for_daemon "PEP"
    fi

    if [[ "$ENABLE_CAT" == "true" ]]; then
        log "Starting Catcoin Core..."
        sudo systemctl start catcoind || log_warn "Failed to start catcoind"
        sleep 3
        wait_for_daemon "CAT"
    fi

    # Aux chain daemons (merge mining)
    if [[ "$ENABLE_NMC" == "true" ]]; then
        log "Starting Namecoin Core..."
        sudo systemctl start namecoind || log_warn "Failed to start namecoind"
        sleep 3
        wait_for_daemon "NMC"
    fi

    if [[ "$ENABLE_SYS" == "true" ]]; then
        log "Starting Syscoin Core..."
        sudo systemctl start syscoind || log_warn "Failed to start syscoind"
        sleep 3
        wait_for_daemon "SYS"
    fi

    if [[ "$ENABLE_XMY" == "true" ]]; then
        log "Starting Myriadcoin Core..."
        sudo systemctl start myriadcoind || log_warn "Failed to start myriadcoind"
        sleep 3
        wait_for_daemon "XMY"
    fi

    if [[ "$ENABLE_FBTC" == "true" ]]; then
        log "Starting Fractal Bitcoin..."
        sudo systemctl start fractald || log_warn "Failed to start fractald"
        sleep 3
        wait_for_daemon "FBTC"
    fi

    if [[ "$ENABLE_QBX" == "true" ]]; then
        log "Starting Q-BitX..."
        sudo systemctl start qbitxd || log_warn "Failed to start qbitxd"
        sleep 3
        wait_for_daemon "QBX"
    fi

    # Note: DGB-Scrypt uses the same daemon as DGB, no separate start needed

    # Check if all enabled blockchains are synced
    if check_all_coins_sync; then
        log_success "All blockchains are synced!"
        log "Starting Spiral Stratum..."
        sudo systemctl enable spiralstratum || log_warn "Failed to enable spiralstratum"
        sudo systemctl start spiralstratum || log_warn "Failed to start spiralstratum"
        sleep 3
    else
        # Show sync status for all enabled coins
        show_all_coins_sync_status

        # Enable sync monitor to auto-start stratum when ready
        # NOTE: spiralpool-sync is Type=oneshot with TimeoutStartSec=infinity,
        # so systemctl start blocks until all chains are synced. We must prompt
        # the user BEFORE starting the service, not after.
        log "Spiral Stratum will start automatically when sync completes"

        echo ""
        echo -e "${WHITE}The pool will automatically start once the blockchain finishes syncing.${NC}"
        echo ""

        # Watch sync choice was already made during configuration phase
        # Start sync monitor (this blocks until all chains are synced)
        log "Enabling sync monitor (will start pool when all blockchains are synced)..."
        sudo systemctl enable spiralpool-sync || true
        sudo systemctl start --no-block spiralpool-sync > /dev/null 2>&1

        # Don't enable stratum yet - sync monitor will do it
    fi

    # Health monitor is ALWAYS started (critical for autonomous operation)
    log "Starting health monitor..."
    sudo systemctl start spiralpool-health || log_warn "Failed to start health monitor"

    # Full mode starts optional extras (these can run during sync)
    if [[ "$INSTALL_MODE" == "full" ]]; then
        # HA Mode: Use role-aware service control
        if [[ "$HA_ENABLED" == "true" ]]; then
            log "HA Mode: Checking node role before starting services..."

            # Create HA enabled marker (for watcher service ConditionPathExists)
            sudo touch "$INSTALL_DIR/config/ha-enabled"
            sudo chown "$POOL_USER:$POOL_USER" "$INSTALL_DIR/config/ha-enabled"

            # Write ha-mode file (used by ha-role-watcher for automatic failback)
            echo "$HA_MODE" | sudo tee "$INSTALL_DIR/config/ha-mode" > /dev/null
            sudo chown "$POOL_USER:$POOL_USER" "$INSTALL_DIR/config/ha-mode"

            # Install and start the HA role watcher service
            if [[ -f "${SCRIPT_DIR}/scripts/linux/systemd/spiralpool-ha-watcher.service" ]]; then
                sudo cp "${SCRIPT_DIR}/scripts/linux/systemd/spiralpool-ha-watcher.service" /etc/systemd/system/
                sudo sed -i "s|{{INSTALL_DIR}}|$INSTALL_DIR|g" /etc/systemd/system/spiralpool-ha-watcher.service
                sudo sed -i "s|{{POOL_USER}}|$POOL_USER|g" /etc/systemd/system/spiralpool-ha-watcher.service
                sudo systemctl daemon-reload || true
                sudo systemctl enable spiralpool-ha-watcher || true
                sudo systemctl start spiralpool-ha-watcher || log_warn "Failed to start HA watcher"
                log_success "HA role watcher service started"
            fi

            # Use auto-detection to start services based on actual HA role.
            # SKIP on backup: stratum may not have initialized its VIP API yet
            # (or may not be running at all if blockchain is still syncing).
            # Without a VIP API response, auto-detect returns "STANDALONE" and
            # incorrectly starts sentinel+dashboard on backup. The ha-watcher
            # service handles role detection continuously and will start services
            # if/when this node becomes MASTER.
            if [[ "$HA_MODE" == "ha-backup" ]]; then
                log "HA backup: sentinel/dashboard will start via ha-role-watcher on failover"
            elif [[ -x "/usr/local/bin/spiralpool-ha-service" ]]; then
                log "Running HA service auto-detection..."
                /usr/local/bin/spiralpool-ha-service auto "Installation complete" || true
            else
                log_warn "HA service control script not found, falling back to direct start"
                start_service_if_exists "spiraldash"
                if [[ -n "$DISCORD_WEBHOOK" ]] || [[ -n "$TELEGRAM_BOT_TOKEN" ]] || [[ -n "$XMPP_JID" ]]; then
                    start_service_if_exists "spiralsentinel"
                fi
            fi
        else
            # Non-HA Mode: Start services directly
            start_service_if_exists "spiraldash"

            # Start Sentinel only if notifications were configured
            if [[ -n "$DISCORD_WEBHOOK" ]] || [[ -n "$TELEGRAM_BOT_TOKEN" ]] || [[ -n "$XMPP_JID" ]]; then
                start_service_if_exists "spiralsentinel"
            fi
        fi
    fi

    log_success "Services started"
    mark_progress "services"
    log ""
    log "Self-healing health monitor is active and will:"
    log "  - Auto-restart crashed services"
    log "  - Monitor disk space and memory"
    log "  - Start stratum when all blockchains sync"
}

