            else
                echo -e "  ${GREEN}✓${NC} Spiral Sentinel is running"
            fi
            [[ -n "$DISCORD_WEBHOOK" ]] && echo -e "    ${GREEN}✓${NC} Discord notifications enabled"
            [[ -n "$TELEGRAM_BOT_TOKEN" ]] && echo -e "    ${GREEN}✓${NC} Telegram notifications enabled"
